gameforge.collect_quest_lv40._60_say = "Je veux en savoir plus \224 propos de la soci\233t\233[ENTER]secr\232te dans la Vall\233e de Seungryong. Je crois[ENTER]que les membres d\233tiennent des informations[ENTER]concernant cette magie ancienne; je suis tout[ENTER]particuli\232rement int\233ress\233 par les Livres[ENTER]Mal\233fiques qu'ils ont cr\233\233s. Je pense qu'ils sont[ENTER]la pi\232ce manquante de mes recherches. "
gameforge.collect_quest_lv40._70_say = "S'il vous plait apportez-moi ces livres ! Et[ENTER]assurez-vous bien qu'ils sont en bon \233tat -[ENTER]certains d'entre eux sont trop us\233s et[ENTER]illisibles. Je ne peux rien faire de ce genre de[ENTER]livres. Il me faut 15 Livres Mal\233fiques pour[ENTER]mener \224 bien mes recherches. Apportez les moi un[ENTER]par un afin que je les \233tudie individuellement. "
gameforge.collect_quest_lv40._80_sayTitle = "La magie d'antan "
gameforge.collect_quest_lv40._90_say = "Le biologiste Chaegirab, l'apprenti d'Uriel, fait[ENTER]des recherches sur une magie tr\232s ancienne.[ENTER]Dans la Vall\233e de Seungryong, il y a 15 livres[ENTER]provenant d'une collection de Livres Mal\233fiques.[ENTER]Trouvez ces livres, et apportez les \224 Chaegirab[ENTER]un par un. Vous pouvez en trouver sur les[ENTER]Bourreaux funestes et les Hauts Tourmenteurs. "
