gameforge.collect_quest_lv92._070_say = "Actuellement, je suis \224 la recherche de Joyaux de[ENTER]Cruaut\233 de qualit\233 irr\233prochable - de magnifiques[ENTER]pierres pr\233cieuses qu'on ne trouve que dans les[ENTER]profondeurs des montagnes. Ces diamants tr\232s[ENTER]sp\233ciaux ont \233t\233 durant des ann\233es sous[ENTER]l'influence des pouvoirs mal\233fiques du Dieu[ENTER]Beran-Setaou et ont absorb\233 une minuscule partie[ENTER]de son \233nergie. J'ai besoin de 10 Joyaux en[ENTER]parfait \233tat. Bonne chance et \224 bient\244t ! "
gameforge.collect_quest_lv92._080_say_title = "Joyaux pour Seon-Pyeong "
gameforge.collect_quest_lv92._090_say = "Seon-Pyeong, le forgeron d'armes et chercheur a[ENTER]besoin de 10 Joyaux de Cruaut\233 pour ses[ENTER]recherches. Apportez-les lui un par un, afin[ENTER]qu'il puisse les \233tudier individuellement.[ENTER]Vous les trouverez en tuant des Golems de Glace[ENTER]d'enfer ainsi que des Hommes de Glace d'enfer. "
gameforge.collect_quest_lv92._100_sayReward = "Vous avez d\233j\224 apport\233 %s Joyau(x). "
gameforge.collect_quest_lv92._110_say = "Vous ne pouvez pas encore utiliser l'\233lixir du[ENTER]Chercheur. "
gameforge.collect_quest_lv92._120_say = "Vous avez d\233j\224 utilis\233 un \233lixir ! "
gameforge.collect_quest_lv92._130_say = "Vous pourrez utiliser un \233lixir d\232s que vous[ENTER]aurez trouv\233 un Joyau. "
gameforge.collect_quest_lv92._140_send_letter = "Joyau trouv\233 "
gameforge.collect_quest_lv92._145_npcChat = "Joyaux pour la recherche "
gameforge.collect_quest_lv92._150_say = "Vous ici ? Je suis d\233sol\233 mais je n'ai pas[ENTER]termin\233 d'\233tudier le dernier Joyau que vous[ENTER]m'avez apport\233. Repassez plus tard ! "
gameforge.collect_quest_lv92._160_say = "Vous n'avez encore rien trouv\233 ? Je suis d\233sol\233,[ENTER]mais que faites-vous l\224 alors ? Allez,[ENTER]d\233p\234chez-vous un peu ! Revenez me voir quand vous[ENTER]avez un joyau \224 m'apporter ! "
gameforge.collect_quest_lv92._170_say = "Vous avez trouv\233 un joyau ? Fantastique ![ENTER]Attendez un moment que je m'assure de sa qualit\233[ENTER]... "
gameforge.collect_quest_lv92._180_say = "C'est magnifique. Ce Joyau est sans aucun doute[ENTER]un des plus beaux que j'ai vu jusqu'ici. Merci[ENTER]beaucoup ! "
gameforge.collect_quest_lv92._190_say = "Mais comme vous le savez, il m'en faut encore %s[ENTER]de cette qualit\233. Laissez-moi un peu de temps[ENTER]pour l'examiner. Vous pourrez alors m'en apporter[ENTER]une autre. "
gameforge.collect_quest_lv92._200_say = "Bonne chance ! "
gameforge.collect_quest_lv92._210_say = "C'\233tait le dernier Joyau, vous m'avez apport\233 les[ENTER]10 dont j'avais besoin. Je vous en suis[ENTER]r\233ellement reconnaissant... et votre r\233compense[ENTER]sera \224 la hauteur de votre aide. Choisissez[ENTER]maintenant ! "
gameforge.collect_quest_lv92._220_1_select = "+1000 Points de vie "
gameforge.collect_quest_lv92._220_2_select = "D\233fense +120 "
gameforge.collect_quest_lv92._220_3_select = "Attaque +51 "
gameforge.collect_quest_lv92._230_say = "Hum ... Ce joyau provient vraiment de la grotte[ENTER]de l'Exil ? Il est certes tr\232s beau mais il n'a[ENTER]pas de flamme int\233rieure. Je crains de ne pas[ENTER]pouvoir l'utiliser. Je vais tout de m\234me[ENTER]l'examiner un peu plus pr\233cis\233ment, mais essayez[ENTER]plut\244t d'en trouver un autre pendant ce temps,[ENTER]d'accord ? "
