gameforge.couple_ring._10_npcChat = "La vengeance du marchand de bagues "
gameforge.couple_ring._110_sayReward = "La vieille Dame vous a demand\233 de l'aide : Votre[ENTER]ami le vendeur de bagues a \233t\233 assassin\233 par les[ENTER]Jin-Hees, l\146\233lite du Serment blanc.[ENTER]Vengez-le en tuant 30 Jin-Hees. "
gameforge.couple_ring._120_sayReward = "Nombre de Jin-Hees restant: %s "
