gameforge.couple_ring._140_say = "La famille du marchand de bagues veut venger sa[ENTER]mort! Si vous pouvez les aider et att\233nuer leur[ENTER]peine, faites-le. "
gameforge.couple_ring._150_say = "Dommage que vous ne souhaitiez pas venger la mort[ENTER]du marchand de bagues. Hum, bien s\251r vous tenez \224[ENTER]votre propre vie. Comme vous voulez. Chaque vie a[ENTER]sa propre valeur. "
