gameforge.couple_ring._170_select = "Je vais r\233essayer. "
gameforge.couple_ring._180_say = "Les pierres pr\233cieuses ne m'int\233ressent pas. Je[ENTER]veux juste que la mort du marchand de bagues soit[ENTER]veng\233e, pour sa famille. Je vous remercie d'\234tre[ENTER]revenu sur votre d\233cision et d'accepter de[ENTER]remplir cette mission. "
