gameforge.couple_ring._220_npcChat = "Vous avez tu\233 30 Jin-Hees ! "
gameforge.couple_ring._230_say = "Vous avez vaincu tous les Jin-Hees, bravo ! Le[ENTER]marchand de bagues va pouvoir maintenant reposer[ENTER]en paix. Voici l'anneau de couple qu'il m'avait[ENTER]confi\233.[ENTER]Il est \224 vous, en r\233compense pour avoir veng\233 sa[ENTER]mort. Je suis s\251re qu'il l'aurait voulu ainsi. "
