gameforge.couple_ring._250_sayItem = "Anneau de couple "
gameforge.couple_ring._255_sayItem = "Cet anneau symbolise un mariage imminent. "
gameforge.couple_ring._30_say = "Vous \234tes maintenant l'un des guerriers de cet[ENTER]empire. Si seulement je savais comment vous[ENTER]pourriez vous servir de vos nouvelles[ENTER]comp\233tences. Avez-vous jamais entendu parler des[ENTER]Jin-Hee ? C'est un groupe de dangereuses[ENTER]guerri\232res \233lites. L'une d'entre elles a tu\233 le[ENTER]bijoutier de notre village. Ce marchand \233tait non[ENTER]seulement un bon ami, mais aussi un homme tr\232s[ENTER]honn\234te qui vendait des alliances aux jeunes[ENTER]couples ayant l'intention de se marier.[ENTER]\202tes-vous pr\234t \224 venger sa mort ? Pour se faire,[ENTER]vous devrez tuer 30 Jin-Hee... "
gameforge.couple_ring._40_select = "Je vengerai le vendeur de bagues. "
gameforge.couple_ring._50_select = "Non, les Jin-Hees sont trop redoutables. "
gameforge.couple_ring._60_say = "C'est une d\233cision tr\232s honorable et courageuse ![ENTER]Souvenez-vous - vous devez tuer 30 Jin-Hee.[ENTER]Faites attention, ils sont habiles et tr\232s forts[ENTER]pour se dissimuler ! "
gameforge.couple_ring._70_say = "Hmm, quel dommage. Enfin c'est vous qui d\233cidez.[ENTER]Il est vrai que le courage aveugle m\232ne \224 une[ENTER]mort certaine. Faites attention \224 vous! "
gameforge.couple_ring._75_say = "Nombre de Jin-Hees restantes "
gameforge.couple_ring._80_sayTitle = "Vous avez vaincu toutes les Jin Hees "
