gameforge.dragon_soul = {}
gameforge.dragon_soul._010_sayTitle = "Fragment de pierre-dragon "
gameforge.dragon_soul._020_say = "Vous tenez en main un fragment de pierre[ENTER]pr\233cieuse. Il brille d'une lueur \233nigmatique, et[ENTER]vous sentez sa force vous gagner.[ENTER]Quelle est cette pierre\160? Apportez ce fragment \224[ENTER]l'alchimiste, il devrait pouvoir vous le dire. "
gameforge.dragon_soul._030_npcChat = "Fragment de pierre-dragon "
gameforge.dragon_soul._040_say = "C'est un fragment de pierre-dragon, un cristal[ENTER]rarissime de grande valeur au pouvoir immense. On[ENTER]raconte que ces pierres sont les \226mes de dragons.[ENTER]Comme ce fragment est beau\160![ENTER]Percevez-vous sa force vous parcourir quand vous[ENTER]le prenez\160?[ENTER]Apportez-m'en 10 en tout et je pourrai les[ENTER]transmuer en une pierre-dragon enti\232re. "
gameforge.dragon_soul._050_npcChat = "Transmutation en pierre-dragon "
gameforge.dragon_soul._060_say = "Pas si vite, l'ami\160! Il me faut 10 fragments pour[ENTER]pouvoir les transmuter en une pierre-dragon.[ENTER]Continuez \224 chercher\160! "
gameforge.dragon_soul._070_say = "Ah, vous avez trouv\233 dix fragments de[ENTER]pierre-dragon, tr\232s bien ! Attendez un instant.[ENTER]...[ENTER]\199a y est\160! Comme c'est \233trange... la[ENTER]transmutation a donn\233 ce qu'on appelle un \171\160Cor[ENTER]Draconis\160\187, un c\156ur de dragon cristallin qui[ENTER]enveloppe et prot\232ge une pierre-dragon.[ENTER]Brisez-le pour d\233couvrir laquelle. Elle sera[ENTER]alors plac\233e directement dans votre inventaire[ENTER]d'alchimie des pierres-dragons. Saviez-vous que[ENTER]vous pouvez raffiner davantage encore les[ENTER]pierres-dragons\160? "
gameforge.dragon_soul._080_say = "Vous voulez un autre Cor Draconis\160? Ouh, mais[ENTER]c'est que je ne suis plus tout jeune. Et puis la[ENTER]fabrication d'un objet aussi complexe demande[ENTER]beaucoup de forces.[ENTER]Pour vous, je veux bien essayer. Mais je[ENTER]n'arriverai pas \224 en transmuter plus de dix par[ENTER]jour, m\234me avec la meilleure volont\233 du monde\160! "
gameforge.dragon_soul._090_say = "\199a suffit pour aujourd'hui, je ne peux tout[ENTER]simplement pas transmuter plus de dix Cor[ENTER]Draconis par jour. Je suis \233puis\233, je dois me[ENTER]reposer.[ENTER]Revenez demain. "
gameforge.dragon_soul._100_npcChat = "Voir le magasin "
gameforge.dragon_soul._1010_sendLetter = "Arriv\233e du fragment de pierre-dragon "
gameforge.dragon_soul._1020_say = "Le plus grand alchimiste du royaume en mati\232re de[ENTER]minerais vous cherche. Allez vite le voir\160! "
gameforge.dragon_soul._1030_npcChat = "Un fragment de pierre-dragon ?! "
gameforge.dragon_soul._1040_say = "Ah, vous voil\224\160! J'ai d\233couvert quelque chose de[ENTER]surprenant\160: un fragment de pierre-dragon\160! Une[ENTER]pierre-dragon est un cristal rarissime de grande[ENTER]valeur au pouvoir immense. On raconte que ces[ENTER]pierres sont les \226mes de dragons. Regardez comme[ENTER]c'est beau ! Je vous accorde le pouvoir de l'\156il[ENTER]du Dragon pour que vous puissiez retrouver ces[ENTER]fragments. Rapportez-moi 10 fragments de[ENTER]pierre-dragon et je pourrai les transmuer en une[ENTER]pierre compl\232te. "
gameforge.dragon_soul._1050_sendLetter = "R\233cup\233rer des fragments de pierre-dragon "
gameforge.dragon_soul._1060_say = "Rapporte 10 pierres-dragons \224 l'alchimiste. "
gameforge.dragon_soul._1070_say = "Ah, parfait\160! Vous avez trouv\233 dix fragments de[ENTER]pierre-dragon. Attendez un instant\133 Incroyable\160![ENTER]la transmutation a donn\233 ce qu'on appelle un \171[ENTER]Cor Draconis \187, un c\156ur de dragon cristallin qui[ENTER]enveloppe et prot\232ge une pierre-dragon. Si vous[ENTER]le brisez, la pierre-dragon qui se trouve \224[ENTER]l'int\233rieur sera plac\233e directement dans votre[ENTER]inventaire de l'alchimie des pierres-dragons.[ENTER]Pour pouvoir trouver et transmuter les fragments,[ENTER]il vous faut le pouvoir de l'\156il du dragon. Je[ENTER]peux vous l'accorder une fois par jour.[ENTER]Vous pourrez aussi transmuter vous-m\234me des[ENTER]fragments de pierre-dragon\160! Aujourd'hui je vous[ENTER]en ai d\233j\224 fabriqu\233 une, vous pourrez faire les[ENTER]%d autres vous-m\234me. "
gameforge.dragon_soul._1080_say = "Eh, ne perdez pas de temps\160! Partez plut\244t[ENTER]chercher des fragments de pierre-dragon\160! "
gameforge.dragon_soul._1090_sendLetter = "Pouvoir de l'\156il du Dragon "
gameforge.dragon_soul._1100_say = "Pouvoir de l'\156il du Dragon restant\160: %d "
gameforge.dragon_soul._110_say = "Choisissez. "
gameforge.dragon_soul._1110_notice = "Es gibt keine Drachensteinsplitter mehr. "
gameforge.dragon_soul._1120_npcChat = "Accordez-moi le pouvoir de l'\156il du Dragon "
gameforge.dragon_soul._1130_say = "Bonjour\160! Je vous ai d\233j\224 accord\233 le pouvoir de[ENTER]l'\156il du Dragon aujourd'hui, et je suis \224 bout de[ENTER]forces. Je ne peux r\233aliser ce rituel qu'une fois[ENTER]par jour. Revenez demain\160! "
gameforge.dragon_soul._1140_say = "Bonjour\160! Je parie que vous \234tes ici pour le[ENTER]pouvoir de l'\156il du Dragon, je me trompe\160? Bon,[ENTER]le voil\224... Bonne chance dans vos recherches\160![ENTER]J'esp\232re que vous trouverez suffisamment de[ENTER]fragments que pour transmuer dix[ENTER]pierres-dragons\160! "
