gameforge.energy_system._001_npcChat = "Une nouvelle technique\160! "
gameforge.energy_system._010_say = "J'ai r\233ussi\160![ENTER]J'ai enfin pu d\233velopper une technique[ENTER]r\233volutionnaire.[ENTER]Je suis maintenant capable de bricoler des objets[ENTER]pour en tirer de l'\233nergie pure. Je suis un[ENTER]g\233nie\160! "
gameforge.energy_system._020_say = "En d\233truisant un objet avec cette technique, on[ENTER]obtient des fragments d'\233nergie. Avec 30 d'entre[ENTER]eux, on peut reconstituer un cristal d'\233nergie\160![ENTER]De l'\233nergie pure captur\233e dans une pierre[ENTER]pr\233cieuse. Cette force se r\233pandra dans tout[ENTER]votre \233quipement. Cela vous int\233resse\160? "
gameforge.energy_system._030_say = "Apportez-moi des objets que vous trouverez au[ENTER]cours de vos aventures, comme des armes, des[ENTER]bijoux et des v\234tements. Je les transformerai en[ENTER]fragments d'\233nergie. Cette technique va[ENTER]influencer l'avenir de notre nation. Nous serons[ENTER]invincibles\160! "
gameforge.energy_system._035_npcChat = "Extraire des fragments d'\233nergie "
gameforge.energy_system._040_say = "\199a a fonctionn\233\160? Avez-vous obtenu des fragments[ENTER]d'\233nergie\160? Apportez-moi plus d'objets et je les[ENTER]d\233monterai \224 l'aide de l'alchimie. Ma technique[ENTER]n'est pas encore tout \224 fait au point, c'est[ENTER]pourquoi je ne peux pas vous dire exactement[ENTER]combien de fragments vous obtiendrez. "
gameforge.energy_system._050_say = "Il y a toutefois une condition\160: votre niveau[ENTER]ainsi que celui de l'objet doivent \234tre \233gaux ou[ENTER]sup\233rieurs \224 35.[ENTER]Bon, voyons voir... "
gameforge.energy_system._060_say = "Vous n'\234tes pas encore assez puissant\160! Revenez[ENTER]me voir quand vous aurez atteint le niveau 35. "
gameforge.energy_system._070_say = "Ah, parfait\160! Vous \234tes fort et exp\233riment\233.[ENTER]Donnez-moi l'objet que je dois transformer. "
gameforge.energy_system._080_say = "Vous n'\234tes pas encore assez puissant pour[ENTER]ma\238triser la force contenue dans les fragments[ENTER]d'\233nergie. Revenez quand vous aurez atteint le[ENTER]niveau 35. "
gameforge.energy_system._090_say = "Je ne peux pas utiliser ma technique avec cet[ENTER]objet. Apportez-moi autre chose. "
gameforge.energy_system._100_say = "Cet objet n'a pas assez d'\233nergie.[ENTER]Apportez-m'en un de niveau 35 minimum, faute de[ENTER]quoi ma technique ne servira \224 rien. "
gameforge.energy_system._110_say = "Dois-je d\233truire cet objet\160? "
gameforge.energy_system._120_select = "Oui\160! "
gameforge.energy_system._130_select = "Non, pas encore\160! "
