gameforge.energy_system._150_say = "Extraordinaire\160! J'ai pu extraire %d fragments[ENTER]d'\233nergie. Tenez. "
gameforge.energy_system._160_npcChat = "Fabriquer un cristal d'\233nergie "
gameforge.energy_system._170_say = "Vous avez d\233j\224 \233puis\233 vos r\233serves d'\233nergie\160?[ENTER]Vous ne devriez pas travailler si dur et risquer[ENTER]votre vie inutilement. Pour fabriquer un cristal[ENTER]d'\233nergie, il me faut %d cristaux d'\233nergie. "
