gameforge.find_brother_article._160_say = "Vous voulez abandonner la recherche ? Je ne[ENTER]demande pas tant que \231a ... J'aimerais tellement[ENTER]avoir un souvenir concret de mon fr\232re.[ENTER]Aidez-moi s'il vous pla\238t ! "
gameforge.find_brother_article._170_select = "Abandonner "
gameforge.find_brother_article._180_sayReward = "Il est presque impossible de refuser la demande[ENTER]de cette jeune femme. Se battre contre 100[ENTER]membres du Gang de Vent Noir semble \234tre en[ENTER]comparaison beaucoup plus facile. "
gameforge.find_brother_article._190_say = "Je suis d\233sol\233. Je comprends votre douleur mais[ENTER]le Clan du Vent Noir est trop fort pour moi. Je[ENTER]pense que vous devriez trouver quelqu'un de plus[ENTER]qualifi\233 pour cette mission. "
