gameforge.find_brother_article._205_sayReward = "La jeune fille sort un objet pr\233cieusement[ENTER]envelopp\233 dans un paquet - une \233p\233e.[ENTER]Au vu des gravures sur le pommeau, vous pensez[ENTER]qu'elle doit \234tre tr\232s pr\233cieuse. "
gameforge.find_brother_article._20_sayTitle = "Mirine: "
