gameforge.find_brother_article._220_say = "Ce n'est pas pour la r\233compense mais je vais[ENTER]relever le d\233fi. "
gameforge.find_brother_article._230_say = "Personne n'est revenu et ils sont peut-\234tre tous[ENTER]morts. Une vie est plus importante que n'importe[ENTER]quel souvenir. Inutile de sacrifier d'autres[ENTER]vies. Adieu ! "
gameforge.find_brother_article._240_npcChat = "J'ai trouv\233 l'uniforme noir ! "
gameforge.find_brother_article._250_say = "Je vous remercie. Il portait toujours cet[ENTER]uniforme. Il n'a jamais voulu porter autre chose.[ENTER]Tenez, prenez ceci c'est ma plus pr\233cieuse[ENTER]possession et je n'en ai pas besoin.[ENTER]Prenez-la, s'il vous pla\238t ! "
gameforge.find_brother_article._260_sayReward = "R\233compense de Mirine accept\233e "
gameforge.find_brother_article._270_sendLetter = "La r\233compense de Mirine "
