gameforge.find_brother_article._290_say = "c'est une arme magnifique mais elle est cass\233e en[ENTER]deux.[ENTER]Il serait trop dommage de jeter cette \156uvre[ENTER]d'art. Je devrais porter cette lame au forgeron[ENTER]pour qu'il la r\233pare. "
gameforge.find_brother_article._300_sayReward = "Vous avez gagn\233 une \233p\233e cass\233e. Amenez-la au[ENTER]forgeron pour la faire r\233parer. "
gameforge.find_brother_article._30_say = "Je suis d\233sol\233e, je ne vous ai pas entendu[ENTER]arriver. J'\233tais en train de penser \224 mon pauvre[ENTER]fr\232re. Mais, qui \234tes-vous ? "
gameforge.find_brother_article._310_sendLetter = "Retournez voir le forgeron. "
gameforge.find_brother_article._320_say = "Mirine \233tait tellement contente de votre aide[ENTER]qu'elle vous a offert son bien le plus pr\233cieux\160:[ENTER]une magnifique \233p\233e malheureusement bris\233e.[ENTER]Ayant remarqu\233 au premier coup d'\156il qu'il s'agit[ENTER]d'une arme de valeur, vous prenez la d\233cision de[ENTER]la faire r\233parer. "
gameforge.find_brother_article._330_targetVid = "La r\233paration de l'\233p\233e "
gameforge.find_brother_article._340_npcChat = "Pouvez-vous r\233parer cette \233p\233e ? "
gameforge.find_brother_article._350_say = "Oh! Quelle \233p\233e magnifique! Elle appartenait \224[ENTER]Mirine, n'est-ce pas ? Quel acte courageux! Vous[ENTER]\234tes un homme juste, et pour cela je ne vous[ENTER]ferai rien payer pour la r\233paration.[ENTER]Attendez un moment ... "
gameforge.find_brother_article._360_say = "Tenez, prenez ceci mon noble ami, la lame est[ENTER]comme neuve. Une arme tr\232s noble, c'est sur.[ENTER]Prenez-la mon ami. "
gameforge.find_brother_article._370_sayReward = "Vous recevez une \233p\233e en argent +3 "
gameforge.find_brother_article._380_sayReward = "Le forgeron vous remet une \201p\233e aux orchid\233es+2. "
gameforge.find_brother_article._390_sayReward = "Le forgeron vous remet une \201p\233e b\226tarde+2 "
gameforge.find_brother_article._400_sayReward = "Le forgeron vous remet un Glaive barbare+2 "
gameforge.find_brother_article._40_say = "Je passais par l\224 et je vous ai vue pleurer.[ENTER]Tenez, prenez ce mouchoir. "
gameforge.find_brother_article._50_say = "Oh, je ne me suis pas rendu compte que quelqu'un[ENTER]m'observait... Mon nom est Mirine. Peut-\234tre[ENTER]pourriez-vous m'aider ? Mon grand fr\232re est mort.[ENTER]Il \233tait parti chercher des m\233dicaments ...[ENTER]Les seules choses qui me restent de lui sont son[ENTER]uniforme et sa tombe. "
gameforge.find_brother_article._60_sayTitle = "Mirine: "
gameforge.find_brother_article._70_say = "En rentrant chez moi, le Gang du Vent Noir est[ENTER]apparu - un des groupes tristement c\233l\232bres[ENTER]d'assassins sans foi ni loi. J'ai d\251 les fuir et[ENTER]ai perdu un souvenir donn\233 par mon fr\232re.[ENTER]Retourner le chercher m'effraie beaucoup.[ENTER]Pourriez-vous le faire pour moi ? "
gameforge.find_brother_article._80_sayReward = "Ayez un peu de compassion pour cette jeune fille[ENTER]et aidez-la \224 retrouver le vieil uniforme noir[ENTER]us\233 qui appartenait \224 son fr\232re. "
