gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "Fant\244me d'un Sura : "
gameforge.ghost_story._020_npcChat = "\202tes-vous un fant\244me ? "
gameforge.ghost_story._030_say = "Non je suis votre grand-m\232re ... Bien entendu que[ENTER]je suis un fant\244me ! Vous avez eu un accident de[ENTER]poussette ou quoi ? "
gameforge.ghost_story._040_npcChat = "Au secours, un fant\244me ! "
gameforge.ghost_story._050_say = "Regardez-moi ce guerrier sans peur ! Bouh ! "
gameforge.ghost_story._060_npcChat = "Vous \234tes qui? "
gameforge.ghost_story._070_say = "Je me nomme Akuma. On dit qu'autrefois, j'\233tais[ENTER]l'un des plus grands guerriers de mon \233poque.[ENTER]Moi-m\234me, je l'ai cru ! Mais regardez-moi ...[ENTER]Regardez ce qu'il reste de moi apr\232s avoir trouv\233[ENTER]cette fameuse grotte ... et y avoir \233t\233 terrass\233. "
gameforge.ghost_story._080_npcChat = "Connaissez-vous l'histoire de ce lieu ? "
gameforge.ghost_story._090_say = "Oh oui, je sais bien ce qu'il s'est pass\233 \224[ENTER]l'\233poque. Tout au long de ma vie, j'ai fait des[ENTER]recherches sur la grotte et comment la trouver.[ENTER]Et apr\232s ma mort, j'ai eu largement le temps de[ENTER]compl\233ter mes connaissances. Demandez-moi[ENTER]simplement ce qui vous int\233resse ! "
gameforge.ghost_story._100_npcChat = "Qu'est ce que c'est que ce portail ? "
gameforge.ghost_story._110_say = "Ce portail m\232ne dans l'antre du dragon t\233n\233breux,[ENTER]Beran-Setaou, le Dieu d\233chu. Il faut une cl\233[ENTER]magique pour l'activer, que seuls les chefs des[ENTER]troupes de Beran-Setaou re\231oivent... "
gameforge.ghost_story._120_npcChat = "Les trois Dieux "
gameforge.ghost_story._130_say = "La fratrie divine \233tait autrefois le pilier de[ENTER]toute existence.[ENTER]Bahar-Taraji, D\233esse de la cr\233ation, \233tait la[ENTER]plus jeunes des trois. Sa t\226che \233tait la cr\233ation[ENTER]des choses nouvelles : O\249 qu'elle aille,[ENTER]fleurissait la v\233g\233tation sur sa trace, une[ENTER]v\233ritable explosion de vie. "
gameforge.ghost_story._140_say = "Le plus vieux des fr\232res \233tait Beran-Setaou. Il[ENTER]\233tait responsable de la fin et de la dissolution.[ENTER]Lorsque quelque chose approchait de la fin de son[ENTER]cycle de vie, il s\233parait l'\226me du corps et[ENTER]accompagnait l'\226me vers l'au-del\224.[ENTER]Ainsi on pouvait assister \224 un cycle n\233cessaire \224[ENTER]toute forme de vie. "
gameforge.ghost_story._150_say = "Pour finir, parlons du fr\232re cadet,[ENTER]Baljit-Elvedin. Il \233tait le dieu charg\233 de[ENTER]l'\233quilibre et se pla\231ait souvent dans le r\244le de[ENTER]l'interm\233diaire entre sa s\156ur et son fr\232re et[ENTER]s'assurait de la continuit\233 du cycle de la vie.[ENTER]Le passage des saisons faisait par exemple partie[ENTER]des t\226ches. "
gameforge.ghost_story._160_npcChat = "La Rupture "
gameforge.ghost_story._170_say = "Les humains adoraient ces 3 dieux et les[ENTER]imploraient lorsque les temps \233taient durs. Mais[ENTER]\224 cause de leur vision \224 court terme des choses,[ENTER]ils craignaient mais respectaient moins[ENTER]Beran-Setaou, ne comprenant pas que comme la[ENTER]lumi\232re \224 besoin de l'ombre pour \234tre r\233v\233l\233e, la[ENTER]destruction est le pendant n\233cessaire \224 la[ENTER]cr\233ation. "
gameforge.ghost_story._180_say = "Pendant tr\232s longtemps, le Dieu sut ignorer ce[ENTER]comportement, mais au fils des si\232cles, il devint[ENTER]de plus en plus jaloux et sa jalousie finit par[ENTER]se transformer en Haine. Il la canalisa d'abord[ENTER]en direction des humains en leur apportant[ENTER]guerres, famines et maladies. Mais cela ne fit[ENTER]qu'empirer les sentiments que les humains avaient[ENTER]\224 son \233gard et ils se tourn\232rent toujours plus[ENTER]vers Bahar-Taraji, la d\233esse de la cr\233ation et la[ENTER]vie. Ainsi se cr\233a un cercle vicieux, o\249 la[ENTER]situation ne faisait que s'empirer. "
gameforge.ghost_story._190_say = "Lorsque la col\232re du Dieu devint si grande qu'il[ENTER]ne pouvait plus la contenir, l'inimaginable se[ENTER]produisit : Il tua sa s\156ur, la pr\233f\233r\233e des[ENTER]humains. Il n'eut m\234me pas besoin de pr\233paration[ENTER]ou de pi\232ge, car ce jour l\224, quand il la[ENTER]rencontra, elle s\146avan\231a vers lui en toute[ENTER]confiance et candeur. Il croisa son regard rempli[ENTER]d'amour fraternel mais ne faiblit pas et la tua[ENTER]en un seul coup. "
gameforge.ghost_story._200_npcChat = "Les cons\233quences "
gameforge.ghost_story._210_say = "La mort de Bahar-Tarajis eut des cons\233quences[ENTER]terribles, autant dans le monde des Dieux que[ENTER]dans celui des humains : l'hiver s'installa et[ENTER]resta, des ann\233es durant, tuant \233norm\233ment de[ENTER]cr\233ature, sur terre comme en mer. La terre gela[ENTER]tellement fort que cela en fendit les pierres et[ENTER]tua m\234me les plus r\233sistants et les plus anciens[ENTER]des arbres. "
gameforge.ghost_story._220_say = "Les jeunes humains et les b\234tes moururent, et[ENTER]quand le redoux arriva, le nombre de naissance[ENTER]\233tait au plus bas. La terre d\233vast\233e ne pouvait[ENTER]plus fournir assez de nourriture aux adultes, il[ENTER]n'\233tait donc pas question pour eux de se[ENTER]reproduire. L'espoir \233tait mort en m\234me tant que[ENTER]la vie et tous deux mirent des ann\233es \224 se[ENTER]r\233g\233n\233rer. "
gameforge.ghost_story._230_say = "Les dieux aussi souffrirent, m\234me si le temps[ENTER]n'\233tait pas compt\233 comme pour les humains.[ENTER]Beran-Setaou rechercha la solitude d\232s qu'il se[ENTER]rendit compte de l'acte qu'il avait commis. Son[ENTER]c\156ur passait sans arr\234t du sentiment de remord \224[ENTER]celui de satisfaction, et celle-ci finit par[ENTER]l'emporter. Son c\156ur gela d\233finitivement et le[ENTER]Dieu de la dissolution se transforma en Dieu de[ENTER]la glace, du froid, de la haine et de la peur. "
gameforge.ghost_story._240_npcChat = "Le combat "
gameforge.ghost_story._250_say = "Baljit-Elvedin, dieu de la protection, porta[ENTER]longtemps le deuil de sa s\156ur. Lorsqu'il put[ENTER]enfin s'extraire des griffes paralysantes de la[ENTER]peine qu'il \233prouvait, il se lan\231a \224 la recherche[ENTER]de son fr\232re. Mais en chemin, il remarqua qu'en[ENTER]d\233pit de sa peine et de sa ranc\156ur, le[ENTER]d\233s\233quilibre qui r\233gnait ne laissait aucune[ENTER]chance \224 la vie de s'\233panouir. "
gameforge.ghost_story._260_say = "Il suivit les traces de son fr\232re, et finit par[ENTER]le trouver, apr\232s de longues ann\233es, dans une[ENTER]grotte de glace ou r\233gnaient solitude et haine,[ENTER]bannissant toute forme de vie. Baljit-Elvedin fit[ENTER]ce qu'il savait \234tre sa seule option, m\234me si[ENTER]cela lui brisait le c\156ur : Il provoqua son fr\232re[ENTER]en duel. Celui-ci avait depuis si longtemps[ENTER]oubli\233 ses remords et la notion m\234me d'amour[ENTER]qu'il n'h\233sita pas une seconde ... "
gameforge.ghost_story._270_say = "Les l\233gendes rapportent un combat titanesque, au[ENTER]del\224 de toute imagination humaine, qui fut[ENTER]finalement gagn\233 par Baljit-Elvedin. Cependant,[ENTER]en concordance avec ses valeurs \233thiques, il[ENTER]d\233cida de ne pas tuer son fr\232re, mais de lui[ENTER]prendre ses pouvoirs et de l'enfermer dans cette[ENTER]grotte. C'est ainsi que Beran-Setaou en vint \224[ENTER]devoir passer sa vie dans cette grotte, en[ENTER]compagnie des cr\233atures qu'il cr\233a au cours des[ENTER]si\232cles. "
gameforge.ghost_story._280_npcChat = "J'en ai entendu assez. "
gameforge.ghost_story._290_say = "Je vous souhaite un autre destin que celui qui[ENTER]fut le mien. Bonne chance ! "
gameforge.ghost_story._300_sayTitle = "Fant\244me d'un guerrier : "
gameforge.ghost_story._310_npcChat = "Pourquoi \234tes-vous transparent ? "
gameforge.ghost_story._320_say = "Qu'est-ce que vous croyez ? Je suis un fant\244me[ENTER]enferm\233 dans la roche depuis des mill\233naires... "
gameforge.ghost_story._330_say = "Au secours, un fant\244me ! "
gameforge.ghost_story._340_say = "En effet, un fant\244me ! Si je t'attrape, je te[ENTER]mange ! "
gameforge.ghost_story._350_npcChat = "Vous \234tes qui? "
gameforge.ghost_story._360_say = "J'\233tais un mercenaire, un homme du commun. Mes[ENTER]parents \233taient des paysans, mais je ne voulait[ENTER]pas passer ma vie \224 cultiver le m\234me champ, donc[ENTER]j'ai choisi de m'engager. C'\233tait tr\232s dur et[ENTER]sanglant, mais je ne regrette pas. Mais un jour[ENTER]j'en ai eu assez de suivre au doigt et \224 l\146\156il[ENTER]les directives de nobles arrogants et j'ai[ENTER]d\233sert\233. C'est un malheureux hasard qui m'a[ENTER]conduit dans ce lieu lugubre. "
gameforge.ghost_story._370_npcChat = "Connaissez-vous l'histoire de la grotte ? "
gameforge.ghost_story._380_say = "Non, je n'en sais rien, je n'ai que jou\233 de[ENTER]malchance. Apr\232s avoir d\233sert\233, j'ai voulu aller[ENTER]me cacher dans les montagnes et j'ai trouv\233 cette[ENTER]grotte. D\232s le d\233but, elle ne m'inspirait pas[ENTER]confiance, mais elle \233tait bien plac\233e et loin de[ENTER]tout. Quelques jours plus tard, j'ai \233t\233 le[ENTER]t\233moin et la victime d'un combat incroyable.[ENTER]Si vous voulez, je peux vous le raconter. "
gameforge.ghost_story._390_npcChat = "Le d\233but du combat "
gameforge.ghost_story._400_say = "Un jour, alors que j'\233tais en train de r\233colter[ENTER]des racines \224 flanc de montagne, sans[ENTER]avertissement, un grand dragon argent\233 est[ENTER]descendu des cieux pr\233s de moi. Je pensait qu'il[ENTER]allait m'attraper pour me manger, mais je ne[ENTER]semblait pas \234tre l\224 pour moi : Son attention[ENTER]\233tait compl\232tement capt\233e par l'entr\233e de la[ENTER]grotte. Sans baisser de vitesse, il s'est[ENTER]engouffr\233 dans cette minuscule entr\233e. "
gameforge.ghost_story._410_say = "Un instant qui m'a sembl\233 durer une \233ternit\233, le[ENTER]calme avant la temp\234te a continu\233 \224 r\233gner. Mon[ENTER]\233quipement complet \233tait dans la grotte mais je[ENTER]n'avais en aucun cas envie de rencontrer le[ENTER]dragon ! Puis la terre s'est mise \224 trembler et[ENTER]j'ai pu entendre des rugissements terrifiants[ENTER]sortir des entrailles de la terre, mais ces[ENTER]rugissements ne provenaient pas d'un mais de DEUX[ENTER]dragons ! Peu apr\232s j'ai pu voir les deux[ENTER]reptiles volants sortir de la grotte. D'abord un[ENTER]argent\233 puis un autre bleut\233. "
gameforge.ghost_story._420_say = "Les deux dragons ont commenc\233 \224 se battre d'un[ENTER]fa\231on qui me serait difficile \224 d\233crire. Il se[ENTER]griffaient les flancs, s'accrochaient l'un \224[ENTER]l'autre, plantaient leur crocs gigantesques dans[ENTER]leurs longs cous ... Un pluie de sang me tombait[ENTER]dessus, mais aucun des deux ne semblait vouloir[ENTER]abandonner. "
gameforge.ghost_story._430_npcChat = "La fin du combat "
gameforge.ghost_story._440_say = "Les deux dragons ont gliss\233 sur le haut des[ENTER]montagnes, faisant chuter par l\224 m\234me la cime,[ENTER]d\233capitant pour ainsi dire la montagne. Des[ENTER]\233clairs br\251laient r\233guli\232rement le museau du[ENTER]dragon bleut\233 alors que le dragon argent\233 devait[ENTER]subir incessamment la morsure d'une gr\234le grosse[ENTER]comme le poing, mais pointue comme lances. La[ENTER]couche de glace accumul\233e au cours des ann\233es[ENTER]pr\233c\233dentes de glaciation commen\231ait \224 fondre[ENTER]sous leur assauts et provoquait des coul\233es de[ENTER]boue. Paralys\233 par la peur, je me suis cach\233 dans[ENTER]une anfractuosit\233 de la roche, incapable de[ENTER]quitter ce spectacle des yeux. "
gameforge.ghost_story._450_say = "Apr\232s quelques heures de combat. leur forces ont[ENTER]commenc\233 \224 faiblir. J'ai alors saisi[ENTER]l'opportunit\233 qui s'offrait \224 moi et j'ai couru[ENTER]vers la grotte pour r\233cup\233rer mes affaires.[ENTER]C'est ce qui a entra\238n\233 mon terrible destin.[ENTER]J'\233tais d\233j\224 en train de revenir quand les[ENTER]dragons sont revenus devant l'entr\233e de la[ENTER]grotte, le dragon bleut\233 semblait tr\232s bless\233 et[ENTER]en train de battre en retraite vers la grotte. "
gameforge.ghost_story._460_say = "Juste avant qu'il ne disparaisse dans la grotte,[ENTER]l'argent\233 l'a rattrap\233, et il s'est pass\233 quelque[ENTER]chose de tr\232s inhabituel. L'air s'est mis \224[ENTER]scintiller, puis ce scintillement s'est[ENTER]transform\233 en brise, qui s'est lui-m\234me[ENTER]transform\233 en tourbillon d'\233nergie dans lequel,[ENTER]hurlant et se d\233battant, le dragon bleut\233[ENTER]semblait crier de douleur et de col\232re. Il[ENTER]semblait r\233tr\233cir et son grondement se r\233duire,[ENTER]jusqu'\224 ce que ses \233cailles perdent leur couleur,[ENTER]devenant ternes et \233mouss\233es... "
gameforge.ghost_story._470_say = "Finalement le dragon argent\233 abandonna l'autre[ENTER]dans la grotte. Le perdant du duel a alors[ENTER]utilis\233 ses derni\232res forces pour se cacher dans[ENTER]l'obscurit\233 au c\156ur de la montagne. L'argent\233[ENTER]lan\231a alors une temp\234te de magie qui a scell\233[ENTER]avec une barri\232re d'\233nergie magique qui a fait en[ENTER]partie s'effondrer la montagne. Le dragon des[ENTER]t\233n\232bres et moi \233tions pi\233g\233s au sein de la[ENTER]montagne, damn\233s \224 mourir de faim ... "
gameforge.ghost_story._480_npcChat = "J'en ai entendu assez. "
gameforge.ghost_story._490_say = "Merci de m'avoir \233cout\233, les derniers mill\233naires[ENTER]ont \233t\233 un peu ennuyeux ... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Avant d'\233chapper au Vent noir, j'ai r\233ussi \224[ENTER]d\233couvrir o\249 ils cachent leur or! Ils ont une[ENTER]montagne de lingots d'or! Ils ne remarqueraient[ENTER]pas si quelques-uns venaient \224 manquer. Ils sont[ENTER]tellement niais. Si vous me payez un bon prix[ENTER]j'irai chercher des lingots d'or pour vous.[ENTER]Mais je ne peux ramener qu'un lingot \224 la fois ! "
gameforge.goldbar._104_say = "Temps "
gameforge.goldbar._108_say = "minute(s) "
gameforge.goldbar._10_npcChat = "Une victime du Clan du Vent Noir "
gameforge.goldbar._110_say = "Cela prend environ %s %s pour ramener un lingot[ENTER]d'or. "
gameforge.goldbar._120_say = "Dites-moi si vous \234tes int\233ress\233. "
gameforge.goldbar._130_say = "Vraiment? March\233 conclu alors? Vous n'avez qu'\224[ENTER]me le demander et je vais vous en chercher un! "
gameforge.goldbar._140_npcChat = "Je voudrais acheter un lingot d'or. "
gameforge.goldbar._150_say = "De quoi me parlez-vous? Je ne suis au courant de[ENTER]rien. "
gameforge.goldbar._160_say = "Comment ? Vous voulez acheter des lingots d'or?[ENTER]Non, pas pour l'instant. Le Vent Noir me semble[ENTER]m\233fiant en ce moment. Je risque ma peau si je ne[ENTER]fais pas attention! J'essayerai lorsque la[ENTER]situation se sera un peu calm\233e! "
gameforge.goldbar._170_sayReward = "Vous ne pouvez pas acheter de lingots d'or pour[ENTER]l'instant. "
gameforge.goldbar._180_say = "Je n'ai pas encore eu l'occasion d'aller chercher[ENTER]un lingot d'or. "
gameforge.goldbar._190_say = "Nous devons attendre %s %s "
gameforge.goldbar._200_say = "Je vous ai ramen\233 un lingot d'or.[ENTER]Il co\251te 2,2 Millions de Yangs. Les 200 000 Yangs[ENTER]sont mon salaire en quelque sorte.[ENTER]Alors ? Voulez-vous l'acheter? "
gameforge.goldbar._20_sayTitle = "Balso le tra\238tre : "
gameforge.goldbar._210_say = "Voil\224 : un lingot d'or ! Sage d\233cision! Quand on[ENTER]a des Yangs, il faut les placer. "
gameforge.goldbar._220_say = "Vous n'avez pas assez de Yangs! Il co\251te 2,2[ENTER]millions de Yangs. "
gameforge.goldbar._230_say = "Pourquoi venez-vous ici si c'est pour ne rien[ENTER]acheter? Vous me faites perdre mon temps;[ENTER]allez-vous en. "
gameforge.goldbar._240_npcChat = "GM: R\233initialiser le temps de vente du lingot. "
gameforge.goldbar._250_say = "Le temps de vente du lingot d'or a \233t\233[ENTER]r\233initialis\233. "
gameforge.goldbar._260_npcChat = "Vendre un lingot d'or. "
gameforge.goldbar._270_say = "De quoi me parlez-vous? Je ne suis au courant de[ENTER]rien. "
gameforge.goldbar._280_say = "Comment? Vous voulez vendre un lingot d'or? Vous[ENTER]ne savez donc pas? Les guerriers du Vent Noir[ENTER]sont devenus tr\232s m\233fiants! Si vous vendez le[ENTER]lingot maintenant, vous n'aurez plus tr\232s[ENTER]longtemps \224 vivre. Laissez-le o\249 il est et[ENTER]cachez-le bien. "
gameforge.goldbar._290_sayReward = "Vous ne pouvez pas vendre de lingot d'or pour[ENTER]l'instant. "
gameforge.goldbar._300_say = "Si vous voulez rapporter le lingot d'or, "
gameforge.goldbar._30_say = "Quoi? Une victime du Vent noir? Ha, ha, ha! Vous[ENTER]\234tes encore un enfant. O\249 avez-vous entendu[ENTER]parler de cela? Partez et allez jouer avec chiens[ENTER]errants. "
gameforge.goldbar._310_say = "vous devez attendre environ %s %s. "
gameforge.goldbar._320_say = "Vous n'avez pas de lingots d'or. Si vous me[ENTER]donnez des lingots d'or je vous donnerai des[ENTER]Yangs. "
gameforge.goldbar._330_say = "Hein ? Vous voulez me rendre le lingot ? Mais[ENTER]pourquoi me l'avoir achet\233 si c'est pour me le[ENTER]rendre ? Enfin, si c'est ce que vous voulez, je[ENTER]veux bien le reprendre. Le Vent Noir veille je ne[ENTER]vais pas pouvoir faire \231a tr\232s souvent.[ENTER]Voulez-vous vraiment que je le reprenne ? "
gameforge.goldbar._340_select = "Revendre "
gameforge.goldbar._350_select = "Ne pas revendre "
gameforge.goldbar._360_say = "Voici vos Yangs. Zut! Maintenant il faut que je[ENTER]le ram\232ne! "
gameforge.goldbar._370_say = "Avez-vous des lingots d'or? Je suis tr\232s occup\233.[ENTER]Ne venez pas me d\233ranger si vous n'avez pas[ENTER]l'intention de commercer. "
gameforge.goldbar._40_sayReward = "La qu\234te de la victime du Vent Noir n'est[ENTER]disponible qu'aux personnages disposant d'un[ENTER]niveau sup\233rieur ou \233gal \224 30. "
gameforge.goldbar._50_say = "Faites attention! Les guerriers du Vent Noir sont[ENTER]m\233fiants en ce moment. Il vaut mieux ne pas faire[ENTER]de vagues. Adieu. "
gameforge.goldbar._60_sayReward = "La qu\234te de la victime du Vent Noir n'est pas[ENTER]disponible pour l'instant. "
gameforge.goldbar._70_say = "Chut! Il pourrait y avoir des guerriers du Vent[ENTER]noir cach\233s dans les parages. O\249 avez-vous[ENTER]entendu parler de cela? Non, ce n'est pas grave,[ENTER]ce n'est pas tr\232s important Vous savez ce qu'il[ENTER]se passe ? "
gameforge.goldbar._80_select = "Non, pas vraiment. "
