gameforge.heavens_cave_keyquest = {}
gameforge.heavens_cave_keyquest._010_target = "Seon-Hae "
gameforge.heavens_cave_keyquest._020_npcChat = "Dans la grotte "
gameforge.heavens_cave_keyquest._030_say = "Il faudra bien m'\233couter, mon ami. Je ne[ENTER]raconterai cette histoire qu'une fois... "
gameforge.heavens_cave_keyquest._040_say = "Il faudra bien m'\233couter, mon amie. Je ne[ENTER]raconterai cette histoire qu'une fois... "
gameforge.heavens_cave_keyquest._050_say = "Nous ne v\233n\233rons de nos jours que le Dieu Dragon,[ENTER]mais cela n'a pas toujours \233t\233 le cas. Trois[ENTER]dieux r\233gnaient jadis sur les cieux. Mais[ENTER]Bahar-Taraji, la d\233esse cr\233atrice, fut tu\233e par[ENTER]son fr\232re Beran-Setaou, qui \233tait rong\233 par une[ENTER]jalousie incontr\244lable. Le troisi\232me dieu -[ENTER]Baljit-Elvedin, qu'on conna\238t aujourd'hui sous le[ENTER]nom du Dieu Dragon - a sombr\233 longtemps dans la[ENTER]tristesse. "
gameforge.heavens_cave_keyquest._060_say = "Une bataille a \233clat\233 entre les deux fr\232res, et[ENTER]le Dieu Dragon fut le gagnant. La rumeur dit que[ENTER]les traces de la bataille peuvent toujours \234tre[ENTER]trouv\233es sur le lieu de leur altercation.[ENTER]Beran-Setaou a \233t\233 enferm\233 dans une caverne apr\232s[ENTER]sa d\233faite, qui fut alors connue sous le nom de[ENTER]Grotte de l'Exil. "
gameforge.heavens_cave_keyquest._070_say = "Cette grotte est scell\233e et gard\233e par les[ENTER]membres de l'ordre de Baljit-Elvedin. Vous devez[ENTER]remettre une Pierre de Sang afin d'avoir la[ENTER]permission d'y entrer. Je sais comment fabriquer[ENTER]ces pierres, mais ce n'est pas facile. "
gameforge.heavens_cave_keyquest._080_say = "Tout a commenc\233 lorsque le Dieu Dragon a pleur\233[ENTER]sa s\156ur \224 chaudes larmes, qui sont alors devenues[ENTER]des pierres tombant sur la terre. Vous pouvez[ENTER]toujours les trouver \224 Doyyumhwan aujourd'hui.[ENTER]Obtenez sept de ces larmes et quatre Obsidiennes[ENTER]se trouvant sur des Flammes, et apportez-les moi. "
gameforge.heavens_cave_keyquest._090_say_reward = "Trouvez 7 Larmes P\233trifi\233es et 4 Obsidiennes \224[ENTER]Doyyumhwan. "
gameforge.heavens_cave_keyquest._100_say = "Vous avez besoin d'une autre pierre de sang pour[ENTER]passer les gardiens de l'ordre? Trouvez encore[ENTER]sept larmes p\233trifi\233es et quatre obsidiennes dans[ENTER]la Terre de Feu de Doyyumhwan. "
gameforge.heavens_cave_keyquest._110_say = "Vous avez besoin d'une autre pierre de sang?[ENTER]Vous devriez attendre. Ce Koe-Pung n'est pas[ENTER]l'homme le plus intelligent du monde, mais il se[ENTER]pourrait quand m\234me qu'il remarque que vous ne[ENTER]faites pas parti de son ordre. "
gameforge.heavens_cave_keyquest._120_say = "Quelques heures, je dirais: %s "
gameforge.heavens_cave_keyquest._130_say = "Une heure et %s minutes. "
gameforge.heavens_cave_keyquest._140_say = "Attendez encore %s minutes. "
