gameforge.heavens_cave_keyquest._160_say = "Une des larmes p\233trifi\233es du Dieu Dragon a[ENTER]atterri ici. "
gameforge.heavens_cave_keyquest._170_1_select = "Ramassez la larme "
gameforge.heavens_cave_keyquest._170_2_select = "Continuer de chercher des Larmes ici. "
gameforge.heavens_cave_keyquest._170_3_select = "Ne rien faire "
gameforge.heavens_cave_keyquest._180_say = "Vous obtenez une larme p\233trifi\233e. "
gameforge.heavens_cave_keyquest._190_say_title = "Larme p\233trifi\233e "
gameforge.heavens_cave_keyquest._200_say = "Vous tentez votre chance d'obtenir plus de larmes[ENTER]et vous trouvez: %s "
gameforge.heavens_cave_keyquest._210_say = "Les cr\233atures des environs commencent \224 faire[ENTER]attention \224 vous ! "
gameforge.heavens_cave_keyquest._220_say = "Rendez-vous \224 Doyyumhwan et trouvez les larmes[ENTER]p\233trifi\233es de Baljit-Elvedin, le Dieu Dragon.[ENTER]Ramenez aussi de l'obsidienne, en tuant des[ENTER]Flammes. "
gameforge.heavens_cave_keyquest._230_say = "Larmes p\233trifi\233es n\233cessaires: %s "
gameforge.heavens_cave_keyquest._240_say = "Obsidiennes n\233cessaires: %s "
gameforge.heavens_cave_keyquest._250_notice = "Vous avez trouv\233 assez de larmes p\233trifi\233es! "
gameforge.heavens_cave_keyquest._260_notice = "Vous avez trouv\233 de l'obsidienne pr\232s de cette[ENTER]flamme! "
gameforge.heavens_cave_keyquest._270_notice = "Vous avez trouv\233 toutes les obsidiennes[ENTER]n\233cessaires! "
gameforge.heavens_cave_keyquest._280_say = "Retournez chez Seon-Hae avec les larmes[ENTER]p\233trifi\233es et les obsidiennes. "
gameforge.heavens_cave_keyquest._290_say = "Seon-Hae se trouve dans: %s "
gameforge.heavens_cave_keyquest._300_say = "Les larmes de Baljit-Elvedin! Je vais les[ENTER]retourner \224 leur \233tat liquide et les encuver dans[ENTER]l'obsidienne. Leur pouvoir vous permettra[ENTER]d'appeler la d\233esse Bahar-Taraji! "
gameforge.heavens_cave_keyquest._310_say = "Son esprit survole toujours le monde. Si vous[ENTER]portez les larmes, elle vous parlera. Cherchez-la[ENTER]dans le Bois Rouge de Lungsam. "
gameforge.heavens_cave_keyquest._320_say = "Tenez, prenez ce vase et cherchez la voix de[ENTER]Bahar-Taraji. "
gameforge.heavens_cave_keyquest._330_say = "Cherchez la voix de Bahar-Taraji dans le Bois[ENTER]Rouge de Lungsam. M\234me si vous n'arrivez pas \224[ENTER]voir l'esprit de la d\233esse, vous allez remarquer[ENTER]sa pr\233sence. "
gameforge.heavens_cave_keyquest._335_say = "Un l\233ger chuchotement sembla siffler \224 travers le[ENTER]vent : Partez dans un lieu plus s\251r... Nous ne[ENTER]pouvons parler ici...[ENTER]Cliquez sur le parchemin de qu\234te pour parler au[ENTER]fant\244me. "
gameforge.heavens_cave_keyquest._340_say = "Dans le vent se fait entendre la voix de[ENTER]Bahar-Taraji, la d\233esse assassin\233e... "
gameforge.heavens_cave_keyquest._350_say = "Les larmes de mon fr\232re... il a tant souffert de[ENTER]ma mort. Mais il ne pouvait pas punir[ENTER]Beran-Setaou. "
gameforge.heavens_cave_keyquest._360_say = "Il ne pouvait pas combattre contre son propre[ENTER]fr\232re - Beran-Setaou, le destructeur, craint par[ENTER]les hommes. "
gameforge.heavens_cave_keyquest._370_say = "Mais vous... qui \234tes vous? Vous \234tes diff\233rent.[ENTER]Vous n'avez pas peur de lui! Au contraire, je[ENTER]vois que vous cherchez le combat. "
gameforge.heavens_cave_keyquest._380_say = "%s! Prenez cette goutte de mon sang. Formez \224[ENTER]partir de cette goutte une pierre de sang et[ENTER]punissez Beran-Setaou pour ce qu'il m'a fait.[ENTER]Le chemin jusqu'\224 la Grotte de l'Exil n'est plus[ENTER]bien long. "
gameforge.heavens_cave_keyquest._390_say = "Dans le vent se fait entendre la voix de[ENTER]Bahar-Taraji, la d\233esse assassin\233e... "
gameforge.heavens_cave_keyquest._400_say = "%s! Je vous reconnais! "
gameforge.heavens_cave_keyquest._410_say = "Vous m'apportez les larmes de mon fr\232re pour me[ENTER]r\233conforter. Vous recevrez en r\233compense une[ENTER]goutte de mon sang, afin que vous puissiez[ENTER]continuer votre combat. "
gameforge.heavens_cave_keyquest._420_say = "Rapportez le sang de Bahar-Taraji \224 Seon-Hae. "
gameforge.heavens_cave_keyquest._430_say = "Une lueur appara\238t dans les yeux de Seon-Hae[ENTER]lorsqu'il accepte la goutte de sang... "
gameforge.heavens_cave_keyquest._440_say = "Le sang d'une vraie d\233esse! Il faut que je le[ENTER]transforme rapidement en pierre de sang, avant[ENTER]qu'il ne s'ass\232che. "
gameforge.heavens_cave_keyquest._450_say = "Le garde Koe-Pung vous laissera utiliser le[ENTER]portail qui m\232ne \224 la Grotte de l'Exil si vous[ENTER]avez une Pierre de Sang sur vous. Cependant, cela[ENTER]ne fonctionnera qu'une seule fois. Si vous avez[ENTER]besoin de plus de pierres de sang, revenez alors[ENTER]me voir. Malheureusement je ne peux seulement[ENTER]produire qu'une Pierre de Sang par jour, afin de[ENTER]ne pas attirer la col\232re de l'Ordre. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae peut vous fournir plus de Pierres de[ENTER]Sang, mais une seule par jour peut \234tre utilis\233e. "
gameforge.heavens_cave_keyquest._470_say = "Encore une fois, je vais transformer le sang de[ENTER]Bahar-Taraji en une pierre de sang. Puisse-t-elle[ENTER]vous \234tre utile. "
gameforge.heavens_cave_keyquest._480_say_reward = "Je ne pourrai vous fabriquer une pierre de sang[ENTER]qu'une fois par jour. Si je le faisais plus[ENTER]souvent, Koe-Pung se poserait des questions. "
