gameforge.horse_guard._10_npcChat = "Informations sur les chevaux "
gameforge.horse_guard._20_say = "Pour d\233buter une qu\234te \233questre vous avez besoin[ENTER]d'une m\233daille \233questre. Vous en trouverez une[ENTER]dans le Donjon des Singes. "
gameforge.horse_guard._30_say = "Les chevaux ont 3 niveaux de d\233veloppement : pour[ENTER]d\233butants, pour cavaliers avanc\233s et pour[ENTER]cavaliers exp\233riment\233s. Pour changer de niveau[ENTER]vous devez passer un test de comp\233tence. "
gameforge.horse_guard._40_say = "Les chevaux ont besoin d'une nourriture[ENTER]diff\233rente selon leur niveau de d\233veloppement.[ENTER]Les chevaux pour d\233butants ne mangent que du[ENTER]foin, les chevaux pour cavaliers avanc\233s[ENTER]uniquement des carottes et les chevaux pour les[ENTER]cavaliers les plus exp\233riment\233s mangent du[ENTER]ginseng rouge.[ENTER]On pourrait croire qu'ils sont plus compliqu\233s[ENTER]que nous. "
gameforge.horse_guard._50_say = "Quand le cheval est en bonne sant\233, il est[ENTER]affich\233 en vert, quand il a faim en jaune et[ENTER]quand il est affam\233, il s'affiche en rouge. Pour[ENTER]repasser du rouge ou du jaune au vert, vous devez[ENTER]nourrir votre cheval. Votre cheval pourrait en[ENTER]mourir, donc soyez s\233rieux. "
gameforge.horse_guard._60_say = "Lorsque vous montez \224 cheval, sa fatigue augmente[ENTER]et sa sant\233 diminue. Vous ne pouvez pas monter[ENTER]sur un cheval en mauvaise sant\233. C'est pour cela[ENTER]que vous devez faire une pause de temps en temps. "
gameforge.horse_guard._70_say = "Il y a des rumeurs selon lesquelles on pourrait[ENTER]ressusciter un cheval mort avec de l'herbe des[ENTER]singes. Cette herbe est surveill\233e par les singes[ENTER]et est tr\232s dure \224 obtenir. On dit que s'ils vous[ENTER]font prisonnier, ils vous jettent un sort et vous[ENTER]transforment en singe. "
gameforge.horse_guard._80_say = "Il y a diff\233rents niveaux d'\233quitation et vous[ENTER]pourrez aussi d\233velopper le niveau de votre[ENTER]cheval pour qu'il devienne plus fort. Seule une[ENTER]personne avec une m\233daille \233questre peut se[ENTER]servir d'un cheval. "
