gameforge.horse_upgrade2._50_say = "Si vous voulez am\233liorer votre cheval, vous devez[ENTER]r\233ussir une \233preuve. Comme la fois pr\233c\233dente, il[ENTER]vous faut une m\233daille \233questre pour pouvoir[ENTER]passer l'\233preuve. Vous pourrez la trouver au[ENTER]Donjon des Singes. Bien s\251r, les singes ne vous[ENTER]laisseront pas la prendre sans combat... "
