gameforge.locale.bookworm.accept_ask = "Soon: Pourquoi \234tes-vous encore ici?[ENTER]Vous avez accept\233 la t\226che, alors d\233p\234chez-vous[ENTER]et faites votre travail. Premier arriv\233, premier[ENTER]servi. D\233p\234chez-vous! "
