gameforge.locale.bookworm.accept_failure_say_1 = "Retournez au village. "
gameforge.locale.bookworm.accept_failure_say_2 = "Quoi que je fasse, je n'arrive pas \224 trouver le[ENTER]livre de Milgyo. Je devrais retourner au village[ENTER]mais que vais-je dire \224 Soon? "
gameforge.locale.bookworm.accept_success_info_label = "Allez chercher le livre de Milgyo pour Soon. "
gameforge.locale.bookworm.accept_success_info_text_1 = "Allez chercher le livre de Milgyo pour Soon. "
gameforge.locale.bookworm.accept_success_info_text_2 = "Retournez au village, donnez le livre \224 Soon et[ENTER]obtenez votre r\233compense. "
gameforge.locale.bookworm.accept_success_say_1 = "Voil\224 le livre de Milgyo! "
gameforge.locale.bookworm.accept_success_say_2 = "Voil\224 le livre de Milgyo! Apportez au village[ENTER]l'apporter \224 Soon. "
gameforge.locale.bookworm.aranyeo_complete_say = "Aranyo: Quel imb\233cile a ramen\233 cet \233trange livre[ENTER]\224 mon mari? Il passe ses journ\233es \224 le contempler[ENTER]pour y apprendre des chants \233tranges. Il ne fait[ENTER]plus rien! Je vais lui casser la figure si je[ENTER]mets la main sur lui! "
gameforge.locale.bookworm.aranyeo_complete_say2 = "Aranyo: Qu'est-ce qui ne va pas? Pourquoi cette[ENTER]sueur froide? "
gameforge.locale.bookworm.aranyeo_start_say = "Aranyo: O\249 est-il pass\233? Il me saoule! Il perd[ENTER]son temps \224 lire, sans jamais gagner le moindre[ENTER]yang! Il n'a m\234me pas honte d'agir ainsi devant[ENTER]les enfants! "
gameforge.locale.bookworm.aranyeo_start_say2 = "Aranyo: Est-ce que les livres mettent le pain sur[ENTER]la table ou les v\234tements sur votre dos? Je vais[ENTER]lui briser les os si je le trouve ! "
gameforge.locale.bookworm.aranyeo_talk = "Parler. "
gameforge.locale.bookworm.complete_say = "Soon: Oooh! Je le vois! Oui je le vois! Je vois[ENTER]le nouveau monde! "
gameforge.locale.bookworm.do_you_find_the_book = "Avez-vous trouv\233 le livre de Milgyo? "
gameforge.locale.bookworm.do_you_mean_this_book = "C'est le livre? "
gameforge.locale.bookworm.etc_shop_start_say = "Il est venu hier. Ce qu'il cherchait ? Le livre[ENTER]de Milgyo ou quelque chose de ce genre.[ENTER]Il n'avait pas d'argent mais continuait \224[ENTER]insister quand m\234me.[ENTER]Milgyo a peut-\234tre un rapport avec ce type brutal[ENTER]de la vall\233e de Seungryong. Aucune id\233e de la[ENTER]raison pour laquelle il s'int\233resse \224 un dingue[ENTER]pareil tout \224 coup! "
gameforge.locale.bookworm.etc_shop_start_say2 = "La marchande\160: On ne peut qu'\234tre d\233sol\233 pour[ENTER]Aranyo. Pourquoi s'inflige-t-elle cela\160? *soupir* "
gameforge.locale.bookworm.etc_shop_talk_about_bookworm = "\192 propos de Soon le rat de biblioth\232que. "
gameforge.locale.bookworm.order_accept = "D'accord! Je vais vous le trouver! "
gameforge.locale.bookworm.order_accept_answer = "Soon: Merci! Je compte sur vous. "
gameforge.locale.bookworm.order_find_book_label = "Tuez le disciple de Milgyo! "
gameforge.locale.bookworm.order_find_book_text_1 = "Tuez le disciple de Milgyo! "
gameforge.locale.bookworm.order_find_book_text_2 = "Prenez au disciple le livre de Milgyo. "
gameforge.locale.bookworm.order_refuse = "Ce devrait \234tre assez difficile. "
gameforge.locale.bookworm.order_refuse_answer = "Soon: Pourquoi n'essayez-vous pas? Je suis s\251r[ENTER]que vous y arriverez! "
gameforge.locale.bookworm.order_say1 = "Soon: Voulez-vous que je vous dise? Je ne peux[ENTER]pas vraiment me vanter d'avoir lu tous les livres[ENTER]existants. En ce moment j'\233tudie des textes[ENTER]sacr\233s \233crits par des saints. Il para\238t qu'on[ENTER]peut trouver des informations secr\232tes sur le[ENTER]moyen de devenir un saint dans le livre de[ENTER]Milgyo. "
gameforge.locale.bookworm.order_say2 = "Soon: Je veux avoir ce livre pour le lire! Qu'en[ENTER]pensez-vous? Pourriez-vous me le rapporter? Si[ENTER]vous me le procurez je vous r\233compenserai. M\234me[ENTER]si je dois vendre ma maison pour cela! "
gameforge.locale.bookworm.order_too_late = "Soon: Quelqu'un d'autre m'a d\233j\224 apport\233 le livre[ENTER]de Milgyo. Vous n'avez plus besoin de vous en[ENTER]occuper. "
gameforge.locale.bookworm.start_find_bookworm_label = "Allez voir Soon. "
gameforge.locale.bookworm.start_find_bookworm_text_1 = "Allez voir Soon. "
gameforge.locale.bookworm.start_find_bookworm_text_2 = "Allez voir Soon et parlez-lui du livre de Milgyo. "
gameforge.locale.bookworm.start_say = "Voyez-vous la sagesse contenue dans cette lettre?[ENTER]Les mots forment des phrases et c'est ainsi qu'on[ENTER]\233crit une histoire. Cela demande de l'habitude[ENTER]car tout le monde n'aime pas \231a. "
gameforge.locale.bookworm.start_say2 = "Plus on en a, plus on en veut.[ENTER]Le savoir c'est la joie.[ENTER]Ah, si seulement je pouvais passer ma vie \224[ENTER]lire... "
gameforge.locale.bookworm.success_thanks = "Soon: Oh! C'est bien cela! Je vais me d\233lecter \224[ENTER]le lire. "
gameforge.locale.bookworm.talk = "Parler. "
