gameforge.locale.forked_condition = "Nous devons trouver le gardien du portail, avant[ENTER]qu'un des autres empires ne le fasse.[ENTER]Montrons notre puissance et agrandissons notre[ENTER]territoire\160! "
gameforge.locale.forked_condition2 = "Maintenant il ne nous reste plus qu'\224 \233liminer[ENTER]ceux qui violent le territoire sacr\233. A[ENTER]l'attaque! "
gameforge.locale.forked_enter = "Entrer "
gameforge.locale.forked_kill_boss = "Je suis Thorr Sarch! Ahhhhh! Que pouvez-vous[ENTER]contre moi ?[ENTER]Je ne suis pas mort, je reviendrai \224 la vie ! Des[ENTER]l\233gions enti\232res de guerriers me suivront ![ENTER]Vous avez termin\233 la bataille des empires.[ENTER]Tout le monde est transport\233 au village. "
gameforge.locale.forked_man_chat = "Participer \224 la bataille des Empires "
gameforge.locale.forked_man_say = "Une nouvelle aire de bataille a \233t\233 d\233couverte.[ENTER]Elle peut connecter tout les empires. Elle est[ENTER]envahie de monstres, l'empire a besoin de votre[ENTER]aide! Pouvez-vous les affronter? Battez tout vos[ENTER]ennemis pour retrouver la paix dans notre empire. "
gameforge.locale.forked_man_say_cant = "Hey ! Une nouvelle r\233gion a \233t\233 d\233couverte. Il se[ENTER]peut qu'elle soit une connexion entre tous les[ENTER]empires. D\232s que la recherche sera termin\233e, vous[ENTER]pourrez entrer dans cette r\233gion. "
gameforge.locale.forked_no_enter = "Ne pas entrer. "
gameforge.locale.forked_open_gate = "La porte qui \233tait rest\233e close jusqu'\224[ENTER]maintenant s'est ouverte.[ENTER]Allons sur le territoire sacr\233! Nous allons les[ENTER]conqu\233rir! \192 l'attaque![ENTER]Tout le monde va \234tre t\233l\233port\233 sur les lieux. "
gameforge.locale.forked_rule = "R\232gles pour participer \224 une bataille des[ENTER]empires\160:[ENTER]1. Tous ceux qui meurent \224 cet endroit sont[ENTER]t\233l\233port\233s au village, mais peut-\234tre[ENTER]imm\233diatement renvoy\233 au combat par le Ma\238tre[ENTER]d'Armes.[ENTER]2. Une fois que le territoire sacr\233 est[ENTER]accessible, il n'est plus possible d'entrer ici.[ENTER]3. Pour gagner acc\232s au territoire sacr\233, la cl\233[ENTER]correspondante doit \234tre trouv\233e. "
gameforge.locale.forked_rule_sungzi = "R\232gles d'une bataille des empires :[ENTER]1. L'empire avec le plus bas nombre de victoire[ENTER]contre un autre empire est \233limin\233 en premier.[ENTER]2. Des monstres vont appara\238tre. Le premier[ENTER]empire qui d\233truit un nombre d\233termin\233 de[ENTER]monstres gagne.[ENTER]3. Si le renard Neuf-Queues est tu\233 apr\232s ceci,[ENTER]la bataille est termin\233e.[ENTER]4. Il est impossible d'obtenir des objets durant[ENTER]la bataille.[ENTER]5. Qui meurt trois fois dans le territoire sacr\233[ENTER]est renvoy\233 au village et ne peut plus participer[ENTER]\224 la bataille des empires. "
gameforge.locale.fortune_words_1_body = "Ciel\160! La Fortune vous sourit\160! Sentez-la flotter[ENTER]autour de vous, vous parcourir le corps\160! Vous[ENTER]avez aujourd'hui \171\160une chance extraordinaire\160\187\160![ENTER]Remerciez l'harmonie du Chi qui vous entoure car[ENTER]quelque chose d'heureux va vous arriver[ENTER]aujourd'hui\160! "
gameforge.locale.fortune_words_1_title = "Tr\232s grande chance\160! "
gameforge.locale.fortune_words_2_body = "La chance est avec vous\160! Il est dit ce que vous[ENTER]donnez vous sera rendu. Vous avez aujourd'hui[ENTER]\171\160une chance m\233morable\160\187\160! Pers\233v\233rez un peu et[ENTER]vous serez r\233compens\233 de vos efforts \160! "
gameforge.locale.fortune_words_2_title = "Une chance impressionnante\160! "
gameforge.locale.fortune_words_3_body = "Pas mal\160! Vous avez aujourd'hui \171\160de la chance\160\187.[ENTER]Votre journ\233e se passera mieux, mais ne vous[ENTER]attendez pas non plus \224 trop de cadeaux du[ENTER]destin. "
gameforge.locale.fortune_words_3_title = "Un peu de chance. "
gameforge.locale.fortune_words_4_body = "Rien de bon, mais rien de mauvais\160! Pour[ENTER]aujourd'hui je peux vous pr\233dire une journ\233e de[ENTER]\171\160chance normale\160\187. Cela ne vous sera pas d'une[ENTER]grande aide mais c'est toujours mieux qu'une[ENTER]journ\233e de poisse... "
gameforge.locale.fortune_words_4_title = "Fortune normale. "
gameforge.locale.fortune_words_5_body = "Vous n'\234tes pas vraiment chanceux. Si vous lancez[ENTER]un filet aujourd'hui, vous n'attraperez pas[ENTER]beaucoup de poissons, mais ne mourrez pas de faim[ENTER]non plus. Aujourd'hui, vous n'avez \171\160pas de[ENTER]chance\160\187\160! Mais c'est bon d'y \234tre pr\233par\233. Si[ENTER]vous voulez, je vous \233cris un talisman qui[ENTER]\233loignera cette malchance. Voulez-vous acheter un[ENTER]talisman\160? "
gameforge.locale.fortune_words_5_title = "Une partie de malchance. "
gameforge.locale.fortune_words_6_body = "Aujourd'hui est un mauvais jour. Un jour o\249 faire[ENTER]votre maximum ne vous rapporte rien.[ENTER]Aujourd'hui vous \234tes \171\160malchanceux\160\187\160! Vous[ENTER]devez \234tre attentif \224 toutes les mauvaises[ENTER]choses. Si vous le voulez, je vous \233crirai un[ENTER]Charme Karma qui augmentera votre chance et[ENTER]rendra votre journ\233e un peu meilleure.[ENTER]Voulez-vous acheter ce talisman sp\233cial\160? "
gameforge.locale.fortune_words_6_title = "Malchance. "
gameforge.locale.fortune_words_7_body = "C'est le plus mauvais jour de votre vie. Tous les[ENTER]dieux au paradis et sur terre se d\233cha\238nent sur[ENTER]vous. Rien ne fonctionnera... Si vous voulez[ENTER]faire du feu, il pleuvra. Si vous avez soif, le[ENTER]soleil vous assommera un peu plus. Vous[ENTER]travaillerez aussi durement que les autres, mais[ENTER]cela ne vous rapportera rien. \171\160Malchance[ENTER]extr\234me\160\187. Vous devrez endurer beaucoup de[ENTER]choses.[ENTER]Ce talisman vous aidera \224 surmonter ces[ENTER]difficult\233s. Voulez-vous acheter un talisman\160? "
gameforge.locale.fortune_words_7_title = "Malchance extr\234me. "
