gameforge.locale.monster_chat = {}
gameforge.locale.monster_chat_1001_1 = "Haha, tout le monde mourra! Kayaaaa! "
gameforge.locale.monster_chat_1001_2 = "En tout petits morceaux .... "
gameforge.locale.monster_chat_1001_3 = "Hehehehe "
gameforge.locale.monster_chat_1001_4 = "Kukieh! Meurs! Haha. "
gameforge.locale.monster_chat_1001_5 = "hehehe "
gameforge.locale.monster_chat_1001_6 = "T'as une sale t\234te, d\233form\233e par la peur! H\233h\233h\233. "
gameforge.locale.monster_chat_1002_1 = "Haha! "
gameforge.locale.monster_chat_1002_2 = "Porcs! "
gameforge.locale.monster_chat_1002_3 = "Ils me tapent vraiment sur les nerfs. "
gameforge.locale.monster_chat_1002_4 = {}
gameforge.locale.monster_chat_1002_5 = "Leur sang coule, h\233h\233. "
gameforge.locale.monster_chat_1003_1 = "H\233h\233! (rire tonitruant) "
gameforge.locale.monster_chat_1003_2 = "La lance est plus forte que l'\233p\233e, hein? "
gameforge.locale.monster_chat_1003_3 = "H\233, ne pars pas! Viens par l\224! "
gameforge.locale.monster_chat_1003_4 = "Ta seule vue me fais saliver... "
gameforge.locale.monster_chat_1003_5 = "Tu me cherches! "
gameforge.locale.monster_chat_1003_6 = "Tu vas mouriiiiiiir! "
gameforge.locale.monster_chat_1004_1 = "Tuer, tuuuuer, tuuuuuuuuuer! "
gameforge.locale.monster_chat_1004_2 = "De jolis \233chantillons sont arriv\233s. "
gameforge.locale.monster_chat_1004_3 = "On va bien s'amuser! "
gameforge.locale.monster_chat_1004_4 = "Pas tout de suite, ne meurs pas trop vite, attends! H\233h\233h\233. "
gameforge.locale.monster_chat_1004_5 = "Alors que t'arrive-t-il? Tes mains tremblent! "
gameforge.locale.monster_chat_1004_6 = "Courageux de venir nous voir, n'aie pas peur. "
gameforge.locale.monster_chat_1035_1 = "J'aurai ma vengeance avant de mourir. "
gameforge.locale.monster_chat_1035_2 = "Vas y, tout doucement... "
gameforge.locale.monster_chat_1035_3 = "Tu es notre joie. "
gameforge.locale.monster_chat_1035_4 = "Ton corps tremble de peur. (Rire) "
gameforge.locale.monster_chat_1035_5 = "Tu as peur, hein? (Rire) "
gameforge.locale.monster_chat_1035_6 = "Je pense qu'il est temps de te d\233lester de quelques parties de ton corps. "
gameforge.locale.monster_chat_1036_1 = "Avec qui veux-tu aller en enfer? "
gameforge.locale.monster_chat_1036_2 = "Sales chiens! Je vais vous rendre fous! "
gameforge.locale.monster_chat_1036_3 = "(Rire) "
gameforge.locale.monster_chat_1036_4 = "Vends ton \226me si tu veux sauver ta vie. "
gameforge.locale.monster_chat_1036_5 = {}
gameforge.locale.monster_chat_1036_6 = "Tu vois trouble, tu ne distingues m\234me plus ta gauche de ta droite (Rire). "
gameforge.locale.monster_chat_1037_1 = "Pourquoi ne pas errer ainsi pour toujours? "
gameforge.locale.monster_chat_1037_2 = "Quoi? Tu as peur du noir? "
gameforge.locale.monster_chat_1037_3 = "Bienvenue en enfer (rire). "
gameforge.locale.monster_chat_1037_4 = "Mais oui, mais oui. Tu peux crier! "
gameforge.locale.monster_chat_1037_5 = "(Rire) Ce n'est pas comme \231a que tu me tueras. "
gameforge.locale.monster_chat_1037_6 = "Ouiiiii, voil\224 qui est mieux! "
gameforge.locale.monster_chat_1038_1 = "C'est ici l'enfer "
gameforge.locale.monster_chat_1038_2 = "Bienvenue en enfer. "
gameforge.locale.monster_chat_1038_3 = "Si tu pouvais mourir lentement... "
gameforge.locale.monster_chat_1038_4 = "\199a n'a pas de sens de m'attaquer! (Rire) "
gameforge.locale.monster_chat_1038_5 = {}
gameforge.locale.monster_chat_1038_6 = "Ce n'est pas bien de mourir rapidement, nous voulons nous amuser avec vous... "
gameforge.locale.monster_chat_1039_1 = "Jusqu'\224 ce qu'un autre arrive... "
gameforge.locale.monster_chat_1039_2 = "Tu crois vraiment pouvoir nous \233chapper? "
gameforge.locale.monster_chat_1039_3 = "Ici tout est effrayant, tr\232s effrayant. "
gameforge.locale.monster_chat_1039_4 = "Bienvenue chez nous (Rire) "
gameforge.locale.monster_chat_1039_5 = "Tu vois? Tu l'as rat\233... "
gameforge.locale.monster_chat_1039_6 = "Hmm, si frais... "
gameforge.locale.monster_chat_1040_1 = "Nous voyons tes moindres mouvements. "
gameforge.locale.monster_chat_1040_2 = "Vas-y doucement. "
gameforge.locale.monster_chat_1040_3 = "Si tu touches quelqu'un tu es mort. (rire) "
gameforge.locale.monster_chat_1040_4 = "Tu l'entends ma cloche ??? Ce sera la derni\232re chose que tu entendras !!! "
gameforge.locale.monster_chat_1040_5 = "Si cette blessure continue de saigner \231a deviendra dangereux pour toi... "
gameforge.locale.monster_chat_1040_6 = "Oui! Allez, bats-toi! (rire) "
gameforge.locale.monster_chat_1041_1 = "(Rire)(Rire)(Rire) "
gameforge.locale.monster_chat_1041_2 = "Les nouveaux corps sont l\224. "
gameforge.locale.monster_chat_1041_3 = "Oui, il est temps d'entrer dans un nouveau corps. "
gameforge.locale.monster_chat_1041_4 = "Nous ressuscitons. Nous ne mourons jamais! "
gameforge.locale.monster_chat_1041_5 = "C'est inutile de nous attaquer. (Rire) "
gameforge.locale.monster_chat_1041_6 = "De quoi mourras-tu? d'\233puisement ou de tes blessures? "
gameforge.locale.monster_chat_1091_1 = "Qui peut voler et attaquer mieux que moi? "
gameforge.locale.monster_chat_1091_2 = "Tu peux devenir comme moi. "
gameforge.locale.monster_chat_1091_3 = "Ne veux-tu pas devenir pareil \224 moi? "
gameforge.locale.monster_chat_1091_4 = "Tu es \224 moi corps et \226me! (rire) "
gameforge.locale.monster_chat_1091_5 = "Fatigu\233? Tes jambes tremblent... "
gameforge.locale.monster_chat_1091_6 = "Combien de temps crois-tu pouvoir r\233sister? (rire) "
gameforge.locale.monster_chat_1093_1 = "Qui aurait cru qu'il y a pire que la mort? "
gameforge.locale.monster_chat_1093_2 = "Bienvenue. "
gameforge.locale.monster_chat_1093_3 = "Tu seras ma proie! "
gameforge.locale.monster_chat_1093_4 = "Je d\233vorerai ton corps et ton \226me avec! "
gameforge.locale.monster_chat_1093_5 = "Combien de temps r\233sisteras-tu? Hein? "
gameforge.locale.monster_chat_1093_6 = "La mort rit dans ton dos. (rire) "
gameforge.locale.monster_chat_11000_1 = "Tous ceux qui sont inquiets pour leur d\233veloppement devraient \233couter! "
gameforge.locale.monster_chat_11000_10 = "Si vous voulez contr\244ler le pouvoir de la Nature et de la foudre, choisissez l'apprentissage des Soins! "
gameforge.locale.monster_chat_11000_11 = "Chaque guerrier combat diff\233remment. L'important est d'endurcir votre corps! "
gameforge.locale.monster_chat_11000_12 = "Le point fort d'un Sura est la magie. Travaillez votre intelligence et votre rapidit\233, sans n\233gliger votre force\160! "
gameforge.locale.monster_chat_11000_13 = "Utilisez les comp\233tences de Ninja! Concentrez-vous sur la vitesse et la force de votre corps! "
gameforge.locale.monster_chat_11000_14 = "Les Chamanes utilisent la r\233g\233n\233ration, l'assistance et les sorts \224 distance, pour lesquels l'intelligence est indispensable\160! "
gameforge.locale.monster_chat_11000_15 = "N'oubliez pas votre apprentissage! "
gameforge.locale.monster_chat_11000_16 = "Suivez un apprentissage pour augmenter vos comp\233tences! "
gameforge.locale.monster_chat_11000_17 = "Comp\233tences? Vous pouvez vous \233lever au rang de ma\238tre, attribu\233 al\233atoirement entre les niveaux 17 et 21! "
gameforge.locale.monster_chat_11000_18 = "Vous voulez devenir un grand ma\238tre? Vous aurez donc besoin d'un livre de comp\233tence particulier ! "
gameforge.locale.monster_chat_11000_19 = "D\232s que vous aurez lu le livre de comp\233tence, il dispara\238tra ! "
gameforge.locale.monster_chat_11000_2 = "Guerriers jusqu'au niveau 5, \233coutez-moi ! "
gameforge.locale.monster_chat_11000_20 = "Vous voulez lire un autre livre de comp\233tence ? Attendez une journ\233e ! "
gameforge.locale.monster_chat_11000_21 = "Augmentez votre intelligence pour am\233liorer vos comp\233tences de Sura ! "
gameforge.locale.monster_chat_11000_22 = "Utilisez les grands pouvoirs d'un Sura en combat! "
gameforge.locale.monster_chat_11000_23 = "Vous savez o\249 se trouve le temple de la secte secr\232te ? Dans la vall\233e de Seungryong ! "
gameforge.locale.monster_chat_11000_24 = "Les caves aux araign\233es ont r\233apparu. Elles sont dans le d\233sert de Yongbi. "
gameforge.locale.monster_chat_11000_25 = "Accomplissez des qu\234tes et utilisez vos r\233compenses pour faire des am\233liorations ! "
gameforge.locale.monster_chat_11000_26 = "P\234cher? \199a me parait bien! Vous \234tes-vous d\233j\224 procur\233 une canne et des app\226ts chez un p\234cheur? "
gameforge.locale.monster_chat_11000_27 = "Vous voulez avoir quelque chose de plus dur \224 chasser? Cherchez un portail! Allez dans un terrain de chasse appropri\233 \224 votre niveau! "
gameforge.locale.monster_chat_11000_28 = "Prenez garde aux ennemis des autres empires. On ne sait jamais quand ils s'appr\234tent \224 vous poignarder dans le dos. "
gameforge.locale.monster_chat_11000_29 = "Voulez-vous r\233initialiser vos comp\233tences? Allez voir la Vieille dame. N'oubliez pas d'apporter assez de yangs! "
gameforge.locale.monster_chat_11000_3 = "Allez voir l'instructeur de combat au corps \224 corps si vous voulez \234tre connu comme un guerrier puissant en attaque! "
gameforge.locale.monster_chat_11000_30 = "Visez le niveau de Ma\238tre parfait, il n'y a que comme \231a que vous deviendrez un v\233ritable h\233ros! "
gameforge.locale.monster_chat_11000_31 = "Si vous voulez aller vers une autre ville ou un autre champ de bataille, cherchez les vieillards sur le continent. "
gameforge.locale.monster_chat_11000_4 = "Si vous voulez \234tre puissant dans les comp\233tences de guerrier, choisissez l'apprentissage mental! "
gameforge.locale.monster_chat_11000_5 = "Si vous voulez devenir un Sura sachant manier l'\233p\233e magique, choisissez l'apprentissage des armes magiques! "
gameforge.locale.monster_chat_11000_6 = "Choisissez la magie noire si vous voulez ma\238triser l'utilisation des sorts! "
gameforge.locale.monster_chat_11000_7 = "L'entrainement \224 l'arc est r\233serv\233 aux ninjas de niveau 5 et plus. "
gameforge.locale.monster_chat_11000_8 = "Si vous voulez devenir un Ninja secret, choisissez l'apprentissage du combat au corps \224 corps! "
gameforge.locale.monster_chat_11000_9 = "Si vous voulez devenir un guerrier de la force du Dragon, choisissez la doctrine du Dieu dragon! "
