gameforge.locale.monster_chat_1105_1 = "L'\233tat de glace est bon. "
gameforge.locale.monster_chat_1105_2 = "Le mont Sohan est s\251rement le mieux. "
gameforge.locale.monster_chat_1105_3 = "Quel temps magnifique. "
gameforge.locale.monster_chat_1105_4 = "Tu seras exactement comme moi. "
gameforge.locale.monster_chat_1105_5 = "Tu peux vivre pour toujours, du moins jusqu'\224 ce que la glace fonde. "
gameforge.locale.monster_chat_1105_6 = "Combien de temps \231a prendra avant que tu ne deviennes de glace? "
gameforge.locale.monster_chat_1106_1 = "Des humains... ici?! "
gameforge.locale.monster_chat_1106_2 = "Fatigu\233... mais assez r\233veill\233 pour toi... "
gameforge.locale.monster_chat_1106_3 = "Quelqu'un ici, sur ma colline?  "
gameforge.locale.monster_chat_1106_4 = "Tu n'as rien \224 faire ici! "
gameforge.locale.monster_chat_1106_5 = "Tu ferais mieux de retourner sur tes pas! "
gameforge.locale.monster_chat_1106_6 = "Etranger... tu te sens si seul? "
gameforge.locale.monster_chat_1191_1 = "Voyons si de beaux hommes passent par ici. "
gameforge.locale.monster_chat_1191_2 = "Si froid...si seule...ou est mon futur mari? "
gameforge.locale.monster_chat_1191_3 = "Devrais-je y travailler? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Quelque chose manque. Je ne suis pas amus\233. "
gameforge.locale.monster_chat_1191_6 = "Je vais mettre un terme a tes souffrances! "
gameforge.locale.monster_chat_1301_1 = "Un dragon\160! "
gameforge.locale.monster_chat_1301_2 = "Ta peau p\226le va devenir encore plus p\226le dans quelques minutes. "
gameforge.locale.monster_chat_1301_3 = "Tu veux me d\233fier\160? Pas de souci\160! "
gameforge.locale.monster_chat_1301_4 = "Tu m'attaques\160? C\244ah\160! Tu n'y survivras pas\160! "
gameforge.locale.monster_chat_1301_5 = "Quel humain faible, faible\160! "
gameforge.locale.monster_chat_1301_6 = "Voyons comment tu encaisses\160! "
gameforge.locale.monster_chat_1302_1 = "T'en tirer\160? N'y pense m\234me pas. "
gameforge.locale.monster_chat_1302_2 = "Bien... Approche... C\244ah\160! "
gameforge.locale.monster_chat_1302_3 = "L'\233p\233e tremble dans ma main. C\244ah\160! "
gameforge.locale.monster_chat_1302_4 = "Tu ne survivras pas \224 cette rencontre\160! "
gameforge.locale.monster_chat_1302_5 = "Voici mon \233p\233e\160! "
gameforge.locale.monster_chat_1302_6 = "Douloureux, n'est-ce pas? (rire) "
gameforge.locale.monster_chat_1303_1 = "M\234me l'herbe sur laquelle tu as march\233 par m\233garde peut te tuer. "
gameforge.locale.monster_chat_1303_2 = "Fais attention \224 l'herbe. "
gameforge.locale.monster_chat_1303_3 = "Bien. Viens \224 moi. (rire) "
gameforge.locale.monster_chat_1303_4 = "Esp\232ce de chien! Puisque tu es venu je vais te tuer maintenant. "
gameforge.locale.monster_chat_1303_5 = "Meurs! Meurs! "
gameforge.locale.monster_chat_1303_6 = "Regrettes-tu d'\234tre venu? "
gameforge.locale.monster_chat_1305_1 = "Qui pourra me vaincre? "
gameforge.locale.monster_chat_1305_2 = "Toi? Tu veux te battre? "
gameforge.locale.monster_chat_1305_3 = "Viens ici si tu veux! "
gameforge.locale.monster_chat_1305_4 = "Faisons cela comme il faut! Ne t'en vas pas! "
gameforge.locale.monster_chat_1305_5 = "Comment trouves-tu mon \233p\233e? "
gameforge.locale.monster_chat_1305_6 = "Tu as peur? (rire) "
gameforge.locale.monster_chat_1901_1 = "Je pense que tu vas mourir aujourd'hui. "
gameforge.locale.monster_chat_1901_2 = "Je t'aime bien, toi... "
gameforge.locale.monster_chat_1901_3 = "Alors qu'en penses-tu? Ma ch\232re distraction... "
gameforge.locale.monster_chat_1901_4 = "H\233! Fais \231a bien et ne t'enfuis pas comme un poltron. "
gameforge.locale.monster_chat_1901_5 = "D\233j\224 en mon pouvoir? Hmmm? "
gameforge.locale.monster_chat_1901_6 = "Tu ne veux pas hurler un peu? (rire) "
gameforge.locale.monster_chat_20001_1 = "Vous semblez nerveux... Ne vous inqui\233tez pas, \231a ne risque pas exploser. "
gameforge.locale.monster_chat_20001_2 = "Parfois, j'ai juste envie d'une promenade. "
gameforge.locale.monster_chat_20001_3 = "Je m'ennuie tellement. M\234me mes petits-enfants ne viennent plus me rendre visite. "
gameforge.locale.monster_chat_20001_4 = "Quant on devient vieux on a besoin des autres. "
gameforge.locale.monster_chat_20001_5 = "Mes belles ann\233es sont derri\232re moi. "
gameforge.locale.monster_chat_20002_1 = "Le soleil est si chaud. "
gameforge.locale.monster_chat_20002_2 = "Temps magnifique pour s\233cher un linge mouill\233, n'est-ce pas? "
gameforge.locale.monster_chat_20002_3 = "O\249 est mon bon \224 rien de mari? "
gameforge.locale.monster_chat_20002_4 = "Il se fait appeler p\232re et n'a m\234me pas honte face \224 ses enfants. "
gameforge.locale.monster_chat_20002_5 = "Les livres sont des livres. Il ne gagne pas d'argent. Il ne fait que lire. "
gameforge.locale.monster_chat_20003_1 = "Oooh, doudou, b\233b\233. Tu as bien dormi? "
gameforge.locale.monster_chat_20003_2 = "Tu souris comme un petit ange. "
gameforge.locale.monster_chat_20003_3 = "Maman est si contente que tu sois en bonne sant\233. "
gameforge.locale.monster_chat_20003_4 = "Tu veux qu'on s'occupe de toi? Tu as faim? "
gameforge.locale.monster_chat_20003_5 = "Bon petit... Dors mon b\233b\233, dors. "
gameforge.locale.monster_chat_20004_1 = "La routine. "
gameforge.locale.monster_chat_20004_2 = "O\249 vais-je trouver \224 manger aujourd'hui? "
gameforge.locale.monster_chat_20004_3 = "Ces gens en arme sont si ennuyeux. "
gameforge.locale.monster_chat_20004_4 = "Voyons voir. Peut-\234tre devrais-je aller au restaurant d'Octavio. "
gameforge.locale.monster_chat_20004_5 = "Oh, au fait, on dirait que les guerres sont finies... "
gameforge.locale.monster_chat_20005_1 = "L'esprit du Ma\238tre-potier coule jusqu'au bout de ses doigts. "
gameforge.locale.monster_chat_20005_2 = "Depuis que le chaos a envahi le pays, il y a des combattants partout. "
gameforge.locale.monster_chat_20005_3 = "Tout le monde veut se battre. "
gameforge.locale.monster_chat_20005_4 = "Je prie pour un monde calme et paisible. "
gameforge.locale.monster_chat_20005_5 = "H\233, vous l\224, prenez une minute pour vous relaxer et r\233fl\233chir... "
gameforge.locale.monster_chat_20006_1 = "Oh ciel, que dois-je faire? "
gameforge.locale.monster_chat_20006_2 = "Je ne trouve pas la moindre trace de mon fr\232re pourtant il a promis d'\234tre l\224. "
gameforge.locale.monster_chat_20006_3 = "Je ne vois que des porteurs d'\233p\233e partout. "
gameforge.locale.monster_chat_20006_4 = "Mon fr\232re me manque. "
gameforge.locale.monster_chat_20006_5 = "Personne n'a vu mon fr\232re? "
gameforge.locale.monster_chat_20007_1 = "Hm, c'est vraiment de la viande fraiche! "
gameforge.locale.monster_chat_20007_2 = "C'est bien que les gens mangent plus de viande maintenant. "
gameforge.locale.monster_chat_20007_3 = "Les affaires vont bien mais la viande est toujours rare. "
gameforge.locale.monster_chat_20007_4 = "Quand est-ce que la viande que nous avons command\233e arrivera? "
gameforge.locale.monster_chat_20007_5 = "Si \231a n'arrive pas \224 temps, il nous faudra partir chasser. "
gameforge.locale.monster_chat_20008_1 = "J'esp\232re que les clients viendront en masse quand les beaux jours reviendront. "
gameforge.locale.monster_chat_20008_2 = "Le chien paresseux viendra s\251rement bient\244t r\233clamer \224 manger. "
gameforge.locale.monster_chat_20008_3 = "Oh mon dieu, quel pauvre homme! "
gameforge.locale.monster_chat_20008_4 = "Il \233tait un grand guerrier autrefois. "
gameforge.locale.monster_chat_20008_5 = "Je me demande pourquoi il ne combat plus. "
gameforge.locale.monster_chat_20009_1 = "Les jeunes sont vraiment fougueux, ils rayonnent de vitalit\233. "
gameforge.locale.monster_chat_20009_2 = "Les guerriers ont bien plus fi\232re allure quand ils portent leurs armes. "
gameforge.locale.monster_chat_20009_3 = "Cet esprit meurtrier, tout le monde l'a \224 pr\233sent. "
gameforge.locale.monster_chat_20009_4 = "Domine ton c\156ur, concentre-toi profond\233ment et calme ton esprit. "
gameforge.locale.monster_chat_20009_5 = "Il existe une recette infaillible pour le bonheur, mais il faut se tenir \224 de strictes r\232gles. "
gameforge.locale.monster_chat_20010_1 = "Je t'ai apport\233 un objet pr\233cieux! "
gameforge.locale.monster_chat_20010_2 = "Marchandises Exotiques ! Pi\232ces rares et belles ! "
gameforge.locale.monster_chat_20010_3 = "Venez, venez tous! "
gameforge.locale.monster_chat_20010_4 = "Venez, venez acheter! Vous n'aurez plus d'occasion comme celle l\224! "
gameforge.locale.monster_chat_20010_5 = "Argh, pourquoi y a-t-il autant de voleurs par ici? "
gameforge.locale.monster_chat_20011_1 = "Tout est si sec ces temps-ci... "
gameforge.locale.monster_chat_20011_2 = "La r\233colte de grain n'est plus ce qu'elle \233tait avant. "
gameforge.locale.monster_chat_20011_3 = "Pourquoi les r\233coltes sont-elles moins bonnes qu'avant? "
gameforge.locale.monster_chat_20011_4 = "Le grain est cassant et a un go\251t de pourriture. "
gameforge.locale.monster_chat_20011_5 = "C'est mauvais signe. L'agriculture est la base de notre vie. "
gameforge.locale.monster_chat_20012_1 = "G\226teaux de riz! D\233licieux g\226teaux de riz!! "
gameforge.locale.monster_chat_20012_2 = "Achetez mes g\226teaux de riz sucr\233s! "
gameforge.locale.monster_chat_20012_3 = "C'est vrai, les affaires se portent plut\244t mal. "
gameforge.locale.monster_chat_20012_4 = "Je devrais peut-\234tre tenter ma chance dans une autre ville. "
gameforge.locale.monster_chat_20012_5 = "Mais il y a tellement de tigres... "
gameforge.locale.monster_chat_20013_1 = "Les jours comme aujourd'hui, la meilleure chose qui puisse t'arriver c'est d'\234tre sur un bateau. "
gameforge.locale.monster_chat_20013_2 = "Temps id\233al pour p\234cher! "
gameforge.locale.monster_chat_20013_3 = "Encore un petit n\156ud... Aucun poisson ne m'arrachera cet hame\231on ! "
gameforge.locale.monster_chat_20013_4 = "Ce satan\233 ours a d\233truit ma canne \224 p\234che! "
gameforge.locale.monster_chat_20013_5 = "Je devrais vraiment ramander mes filets. "
gameforge.locale.monster_chat_20014_1 = "Huh! "
gameforge.locale.monster_chat_20014_2 = "Pas d'inqui\233tude, c'est ma fa\231on d'\234tre. "
gameforge.locale.monster_chat_20014_3 = "Haaaaa! "
gameforge.locale.monster_chat_20014_4 = "Que faire pour qu'il... Oh...qu'est-ce que je viens de vous dire ? "
gameforge.locale.monster_chat_20014_5 = "Je ne peux pas du tout \234tre courageux. "
gameforge.locale.monster_chat_20015_1 = "Cette hache m'a toujours bien servi pendant ces 20 derni\232res ann\233es. "
gameforge.locale.monster_chat_20015_2 = "Toujours tranchante, mais peut-\234tre plus autant qu'avant. "
gameforge.locale.monster_chat_20015_3 = "Je veux la renforcer pour continuer \224 l'utiliser. "
gameforge.locale.monster_chat_20015_4 = "Mais j'ai besoin de pierres pleines de min\233raux pour cela "
gameforge.locale.monster_chat_20015_5 = "Mais o\249 pourrai-je les trouver? "
gameforge.locale.monster_chat_20016_1 = "Les clients viennent en masse. "
gameforge.locale.monster_chat_20016_2 = "Esp\233rons que je puisse finir \224 temps. "
gameforge.locale.monster_chat_20016_3 = "Je tape sur l'enclume, ne me tapez pas sur les nerfs ! "
gameforge.locale.monster_chat_20016_4 = "Voil\224 le bruit que doit faire un marteau ! "
gameforge.locale.monster_chat_20016_5 = "Quelle chaleur dans cette forge. "
gameforge.locale.monster_chat_20017_1 = "Je ne me sens pas de jouer d'un instrument. "
gameforge.locale.monster_chat_20017_2 = "Mon instrument est dans un bien sale \233tat. "
gameforge.locale.monster_chat_20017_3 = "Peut-\234tre devrais-je acheter un nouvel instrument ? "
gameforge.locale.monster_chat_20017_4 = "Mon instrument est certes vieux et us\233... Mais que voulez-vous, j'aime les antiquit\233s ! "
gameforge.locale.monster_chat_20017_5 = "Il faut que je trouve rapidement des cordes pour remplacer celles qui ont cass\233... "
gameforge.locale.monster_chat_20018_1 = "Je suis si occup\233! "
gameforge.locale.monster_chat_20018_2 = "Chaque jour de nouveaux bless\233s arrivent. "
gameforge.locale.monster_chat_20018_3 = "Pas le temps de sortir et voir des gens! "
gameforge.locale.monster_chat_20018_4 = "Et les m\233dicaments commencent \224 manquer. "
gameforge.locale.monster_chat_20018_5 = "Je voudrais bien trouver quelqu'un pour ramener les ingr\233dients pour fabriquer de nouveaux rem\232des. "
gameforge.locale.monster_chat_20019_1 = "Depuis trente ans, je parcours les montagnes avec mon arc. "
gameforge.locale.monster_chat_20019_2 = "C'est comme \231a que j'ai pu nourrir ma femme et \233lever trois enfants. "
gameforge.locale.monster_chat_20019_3 = "Ce n'est pas une vie facile mais \231a en vaut la peine. "
gameforge.locale.monster_chat_20019_4 = "Mais maintenant la corde de mon arc est cass\233e et je ne peux plus chasser pour nourrir ma famille. "
gameforge.locale.monster_chat_20019_5 = "Si je ne peux pas r\233parer mon arc il faudra que j'arr\234te. "
gameforge.locale.monster_chat_20020_1 = "H\233, qu'est-ce que vous regardez comme \231a?? "
gameforge.locale.monster_chat_20020_2 = "Allez vous-en! "
gameforge.locale.monster_chat_20020_3 = "Oh, combien de temps devrais-je rester cach\233? "
gameforge.locale.monster_chat_20020_4 = "Vais-je mourir au milieu de nulle part, oubli\233 de tous? "
gameforge.locale.monster_chat_20020_5 = "Aaaah, j'esp\232re tellement l'aide de quelqu'un... "
gameforge.locale.monster_chat_20021_1 = "Ce jour prendra fin comme tous les autres. "
gameforge.locale.monster_chat_20021_2 = "Que vais-je faire \224 pr\233sent hein? "
gameforge.locale.monster_chat_20021_3 = "Je n'aurais jamais cru que \231a finirait ainsi. "
gameforge.locale.monster_chat_20021_4 = "Non! Il ne peut pas \234tre le seul \224 avoir fini comme \231a! "
gameforge.locale.monster_chat_20021_5 = "J'esp\232re qu'il sera veng\233! "
gameforge.locale.monster_chat_20022_1 = "Encore un jour formidable! "
gameforge.locale.monster_chat_20022_2 = "Le mari de Ariyoung a disparu. "
gameforge.locale.monster_chat_20022_3 = "Je voulais aider mais cette obstination... "
gameforge.locale.monster_chat_20022_4 = "Si elle m'avait \233pous\233, elle n'aurait pas eu une vie aussi ennuyeuse. "
gameforge.locale.monster_chat_20022_5 = "Je n'ai pas su lui montrer mes sentiments... "
gameforge.locale.monster_chat_20023_1 = "Oh non! Que faire si ma femme apprend \231a? "
gameforge.locale.monster_chat_20023_2 = "Si seulement je pouvais vivre de la lecture de mes livres! "
gameforge.locale.monster_chat_20023_3 = "Les livres sont si myst\233rieux. "
gameforge.locale.monster_chat_20023_4 = "Je ne pourrais pas vivre comme \231a \233ternellement mais... "
gameforge.locale.monster_chat_20023_5 = "J'aimerais pouvoir faire quelque chose pour ma femme mais... "
gameforge.locale.monster_chat_20024_1 = "Allez, allez! Bouge un peu mieux que \231a! "
gameforge.locale.monster_chat_20024_2 = "Qu'est-ce que tu fais? Tu ne peux pas te d\233p\234cher un peu? "
gameforge.locale.monster_chat_20024_3 = "Imaginez-vous comment un guerrier manie son \233p\233e et faites pareil ! "
gameforge.locale.monster_chat_20024_4 = "O\249 est cet imb\233cile? O\249 est-il maintenant? "
gameforge.locale.monster_chat_20024_5 = "Chien! Tu n'est pas un homme. Ha! "
gameforge.locale.monster_chat_2091_1 = "Coupons, coupons... Cheveux et cous ! "
gameforge.locale.monster_chat_2091_2 = "J'ai la solution \224 vos probl\232mes de fatigue : Le sommeil \233ternel ! "
gameforge.locale.monster_chat_2091_3 = "Respirez profond\233ment. Ne vous inqui\233tez pas, ce n'est que du poison ! "
gameforge.locale.monster_chat_2091_4 = "Je ne vais laisser que votre visage intact ! Cela fera une belle d\233coration... "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Une fois enroul\233s dans ma toile, vous ferez un app\233tissant petit-four pour plus tard. "
gameforge.locale.monster_chat_2092_1 = "Je ne peux plus supporter les caprices de ma femme. "
gameforge.locale.monster_chat_2092_2 = "Pourquoi je ne peux pas dormir? "
gameforge.locale.monster_chat_2092_3 = "Oh, on dirait que quelqu'un est pris dans la toile d'araign\233e. "
gameforge.locale.monster_chat_2092_4 = "Je suis plut\244t pacifique, mais si quelqu'un m'attaque il le regrette tr\232s vite. "
gameforge.locale.monster_chat_2092_5 = "Ouiiiii, donne tout ce que tu as! "
gameforge.locale.monster_chat_2092_6 = "Personne ne peut me vaincre ! "
gameforge.locale.monster_chat_2104_1 = "Pourquoi les humains sont ils aussi humides \224 l'int\233rieur ? \199a fait rouiller mon \233p\233e ! "
gameforge.locale.monster_chat_2104_2 = "Le poison dans ton dard caudal a-t-il s\233ch\233 ? "
gameforge.locale.monster_chat_2104_3 = "Alors, et ce combat? "
gameforge.locale.monster_chat_2104_4 = "D\233j\224 \233puis\233 par la chaleur? "
gameforge.locale.monster_chat_2104_5 = "J'aime abandonner les gens dans le d\233sert. "
gameforge.locale.monster_chat_2104_6 = "Pauvre de toi, enterr\233 ainsi dans le d\233sert. "
gameforge.locale.monster_chat_2105_1 = "Je vais partager un secret avec toi - je d\233teste la poussi\232re. "
gameforge.locale.monster_chat_2105_2 = "Il fait tr\232s chaud, n'est-ce pas? "
gameforge.locale.monster_chat_2105_3 = "Cet endroit est dangereux. "
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "Je te toucherai entre les deux yeux. "
gameforge.locale.monster_chat_2106_1 = "(soupir) Quelque chose \224 attraper aujourd'hui? (soupir) "
gameforge.locale.monster_chat_2106_2 = "Oooh oui, voil\224 quelque chose \224 chasser.(rire) "
gameforge.locale.monster_chat_2106_3 = "(Rire) J'aime \231a, j'aime beaucoup \231a! "
gameforge.locale.monster_chat_2106_4 = "Celui-l\224 est bien gras. Il est pour moi ! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "J'aime l'odeur du sang. "
gameforge.locale.monster_chat_2107_1 = "(soupir) Il n'y a pas grand chose \224 faire ces temps-ci.(soupir) "
gameforge.locale.monster_chat_2107_2 = "H\233, ceux-l\224 sont vraiment gras! "
gameforge.locale.monster_chat_2107_3 = "Le Chef appr\233ciera... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "Bougeons un peu nos jambes. "
gameforge.locale.monster_chat_2107_6 = "Et voil\224 la fl\232che! "
gameforge.locale.monster_chat_2108_1 = "Si j'en attrape un, je... "
gameforge.locale.monster_chat_2108_2 = "H\233, pourquoi regardes-tu derri\232re toi? "
gameforge.locale.monster_chat_2108_3 = "Tu penses pouvoir me battre facilement? Hein? "
gameforge.locale.monster_chat_2108_4 = "Pas de chance pour toi de me rencontrer dans le d\233sert! "
gameforge.locale.monster_chat_2108_5 = "Ah, cette sensation, je ne m'en lasserai jamais! "
gameforge.locale.monster_chat_2108_6 = "Merci! "
gameforge.locale.monster_chat_2191_1 = "\199a sent l'humain - tellement d\233licieux! "
gameforge.locale.monster_chat_2191_2 = "Bien. Viens par ici, viens... "
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "\199a fait plaisir de rencontrer quelqu'un dans le d\233sert! "
gameforge.locale.monster_chat_2191_5 = "Arr\234te de bouger! Kkkkkk! "
gameforge.locale.monster_chat_2191_6 = "Un petit morceau pour commencer... "
gameforge.locale.monster_chat_2202_1 = "Je ne vois vraiment pas pourquoi \231a il fait si chaud. "
gameforge.locale.monster_chat_2202_2 = "Si seulement il y avait quelque chose de frais... "
gameforge.locale.monster_chat_2202_3 = "Je pourrais peut-\234tre me rafraichir avec leur sang. "
gameforge.locale.monster_chat_2202_4 = "J'ai chaud, chaud! Leur sang me rafra\238chira. "
gameforge.locale.monster_chat_2202_5 = "Donne-moi ton sang! "
gameforge.locale.monster_chat_2202_6 = "Deviens comme moi! "
gameforge.locale.monster_chat_2204_1 = "Personne n'entrera tant que je serai ici! "
gameforge.locale.monster_chat_2204_2 = "Je ne sais pas pourquoi mais tu commences \224 m'ennuyer. "
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Kwuuh, sais-tu o\249 tu es? "
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "Si maigre! (Rire) "
gameforge.locale.monster_chat_2205_1 = "Une \233p\233e n'est utile que dans les mains d'un guerrier. "
gameforge.locale.monster_chat_2205_2 = "Garde ton \233p\233e \224 la main. "
gameforge.locale.monster_chat_2205_3 = "La guerre se pr\233pare. "
gameforge.locale.monster_chat_2205_4 = "Maintenant c'est un combat \224 mort! "
gameforge.locale.monster_chat_2205_5 = "Tu veux continuer \224 r\233sister \224 la mort? "
gameforge.locale.monster_chat_2205_6 = "Oui, ne meurs pas trop vite. "
gameforge.locale.monster_chat_2206_1 = "C'est si bon de nager dans la lave. "
gameforge.locale.monster_chat_2206_2 = "J'aime me rafraichir dans un bain de lave. "
gameforge.locale.monster_chat_2206_3 = "Mais la lave n'est plus ce qu'elle \233tait... "
gameforge.locale.monster_chat_2206_4 = "Fils de chien! Tu m'as d\233rang\233! "
gameforge.locale.monster_chat_2206_5 = "Ne d\233range pas mon intimit\233. "
gameforge.locale.monster_chat_2206_6 = "Sinon tu le regretteras... "
gameforge.locale.monster_chat_2291_1 = "Beau temps. Ce serait tellement bien de pouvoir simplement dormir. "
gameforge.locale.monster_chat_2291_2 = "Rien n'est comparable au pays de Doyyumhwan. "
gameforge.locale.monster_chat_2291_3 = "Pourquoi n'irais-je pas dormir? "
gameforge.locale.monster_chat_2291_4 = "Tu m'as d\233rang\233. "
gameforge.locale.monster_chat_2291_5 = "Tu sembles regretter de m'avoir d\233rang\233. "
gameforge.locale.monster_chat_2291_6 = "Trop tard pour fuir. Et \231a ne servirait \224 rien. "
gameforge.locale.monster_chat_301_1 = "Je m'ennuie tellement. N'y a-t-il rien d'int\233ressant \224 faire? "
gameforge.locale.monster_chat_301_2 = "Il y a deux jours, un petite fille a \233t\233 mang\233e par des b\234tes sauvages, dans les environs. "
gameforge.locale.monster_chat_301_3 = "Les animaux sauvages deviennent de plus en plus agressifs. Nous devrions en tuer autant que possible. "
gameforge.locale.monster_chat_301_4 = "Pas de probl\232me ! H\233h\233, \234tre bien de sa personne ne suffit pas. "
gameforge.locale.monster_chat_301_5 = "Veux-tu cette \233p\233e ? Nous ne plaisantons pas. "
gameforge.locale.monster_chat_302_1 = "H\233 ! Voil\224 un beau gar\231on! "
gameforge.locale.monster_chat_302_2 = "Je fais un r\233gime, vous savez. "
gameforge.locale.monster_chat_302_3 = "J'ai envie d'aller faire des courses. "
gameforge.locale.monster_chat_302_4 = "C'\233tait ma fl\232che! "
gameforge.locale.monster_chat_302_5 = "Tu la vois? Elle vise ton c\156ur. "
gameforge.locale.monster_chat_302_6 = "Oh ! En plein dans le mille! "
gameforge.locale.monster_chat_303_1 = "Nos enfants sont devenus trop paresseux maintenant. "
gameforge.locale.monster_chat_303_2 = "Que se passerait-il si les soldats venaient ici ? "
gameforge.locale.monster_chat_303_3 = "Pourquoi me regardes-tu comme \231a? "
gameforge.locale.monster_chat_303_4 = "Oh, mon dieu, quel poltron! "
gameforge.locale.monster_chat_303_5 = "N'en prends pas trop \224 ton aise. "
gameforge.locale.monster_chat_303_6 = "Ce combat sera plus difficile que je ne le pensais. "
gameforge.locale.monster_chat_304_1 = "Vous les femmes vous \234tes venues apr\232s que vos maris vous aient laiss\233 tomber mais vous avez toujours besoin d'hommes. "
gameforge.locale.monster_chat_304_2 = "Il n'existe pas d'hommes bien. "
gameforge.locale.monster_chat_304_3 = "Vous me tapez sur les nerfs. "
gameforge.locale.monster_chat_304_4 = "Quel effet \231a fait? Tu ne vois pas que la mort vous regarde? "
gameforge.locale.monster_chat_304_5 = "Oh, non ! Tu abandonnes d\233j\224? "
gameforge.locale.monster_chat_304_6 = "La souffrance vient vite. "
gameforge.locale.monster_chat_305_1 = "H\233! Cette \233p\233e a l'air fantastique. "
gameforge.locale.monster_chat_305_2 = "Sois plus tenace et augmente ta puissance! "
gameforge.locale.monster_chat_305_3 = "Tu penses pouvoir devenir aussi fort que moi? "
gameforge.locale.monster_chat_305_4 = "Ok. Passons aux choses s\233rieuses. "
gameforge.locale.monster_chat_305_5 = "Oh mon dieu! Je ne suis qu'une faible femme! "
gameforge.locale.monster_chat_305_6 = "Tu as l'air fatigu\233. Pourquoi ne pas abandonner? H\233h\233. "
gameforge.locale.monster_chat_306_1 = "Que va faire Serangyi aujourd'hui, hm? "
gameforge.locale.monster_chat_306_2 = "Je m'ennuie tellement... Joue avec moi! "
gameforge.locale.monster_chat_306_3 = "Je dois dire que je pr\233f\232re les Suras. "
gameforge.locale.monster_chat_306_4 = "H\233 ! Pourquoi pas un combat? "
gameforge.locale.monster_chat_306_5 = "Ne me sous-estime pas sous pr\233texte que je suis une femme! "
gameforge.locale.monster_chat_306_6 = "La souffrance n'est que passag\232re. "
gameforge.locale.monster_chat_307_1 = "Je veux quitter cet endroit \224 tout prix. "
gameforge.locale.monster_chat_307_2 = "Comment sont s\233curis\233es les habitations des membres individuels ? "
gameforge.locale.monster_chat_307_3 = "Taisez-vous les filles! "
gameforge.locale.monster_chat_307_4 = "Je te vaincrai en un seul coup. "
gameforge.locale.monster_chat_307_5 = "Ne pense m\234me pas \224 t'enfuir! "
gameforge.locale.monster_chat_307_6 = "Bon, on commence? "
gameforge.locale.monster_chat_394_1 = "N'oubliez pas : tous les hommes sont des ennemis. "
gameforge.locale.monster_chat_394_2 = "Si une personne a un visage agr\233able, nous pouvons \234tre moins m\233chantes. "
gameforge.locale.monster_chat_394_3 = "Quoi? Tu veux te battre? "
gameforge.locale.monster_chat_394_4 = "\199a ne prendra pas longtemps mais \231a va faire mal. "
gameforge.locale.monster_chat_394_5 = "Oh, tu sembles vraiment souffrir. "
gameforge.locale.monster_chat_394_6 = "Adieu, va en enfer! "
gameforge.locale.monster_chat_401_1 = "Alors, que fais-tu dans le Serment Blanc? "
gameforge.locale.monster_chat_401_2 = "O\249 vas-tu? "
gameforge.locale.monster_chat_401_3 = "H\233, tu veux te battre? "
gameforge.locale.monster_chat_401_4 = "H\233h\233, tu esquives mes coups. "
gameforge.locale.monster_chat_401_5 = "Tu penses pouvoir m'\233chapper? "
gameforge.locale.monster_chat_401_6 = "Prends \231a! "
gameforge.locale.monster_chat_402_1 = "Dieu que je suis fatigu\233 ! "
gameforge.locale.monster_chat_402_2 = "H\233, belle armure! Elle a co\251t\233 combien? "
gameforge.locale.monster_chat_402_3 = "Mais le temps est au beau. "
gameforge.locale.monster_chat_402_4 = "Oh, tu t'es beaucoup entra\238n\233, tr\232s bien ! "
gameforge.locale.monster_chat_402_5 = "Que penses-tu de mes capacit\233s? Pas mal hein? "
gameforge.locale.monster_chat_402_6 = "Quoi? bien sur, c'est cette vitesse incroyable! "
gameforge.locale.monster_chat_403_1 = "Pourquoi n'irais-je pas chasser? "
gameforge.locale.monster_chat_403_2 = "Personne n'attaque notre village aujourd'hui. "
gameforge.locale.monster_chat_403_3 = "SI tu veux te battre alors bats-toi, sale chien! "
gameforge.locale.monster_chat_403_4 = "H\233h\233, tu n'es qu'un d\233butant. "
gameforge.locale.monster_chat_403_5 = "Que devrais-je viser en premier, ton bras ou ta jambe? "
gameforge.locale.monster_chat_403_6 = "Et voici ma fl\232che! "
gameforge.locale.monster_chat_404_1 = "Je dois aller au village m'entra\238ner bient\244t. "
gameforge.locale.monster_chat_404_2 = "Je me sens plut\244t rouill\233. "
gameforge.locale.monster_chat_404_3 = "Qu'est-ce qu'on mange ce soir? "
gameforge.locale.monster_chat_404_4 = "Je surveille, alors crie tant que tu veux. "
gameforge.locale.monster_chat_404_5 = "Tu as attendu trop longtemps? Commence par faire tournoyer ton \233p\233e! "
gameforge.locale.monster_chat_404_6 = "L'\233p\233e semble int\233ressante! "
gameforge.locale.monster_chat_405_1 = "Cette \233p\233e est pr\234te! "
gameforge.locale.monster_chat_405_2 = "Voyons qui sera tu\233 le premier par cette \233p\233e. "
gameforge.locale.monster_chat_405_3 = "H\233, qu'est-ce que tu regarde comme \231a? "
gameforge.locale.monster_chat_405_4 = "D'abord le ventre! "
gameforge.locale.monster_chat_405_5 = "Tu vas servir de fourreau \224 mon \233p\233e. "
gameforge.locale.monster_chat_405_6 = "Tu vas servir de fourreau \224 mon \233p\233e. "
gameforge.locale.monster_chat_406_1 = "Je suis affam\233. "
gameforge.locale.monster_chat_406_2 = "Y a-t-il quelque chose \224 manger? "
gameforge.locale.monster_chat_406_3 = "Pourquoi ai-je encore faim apr\232s toute cette nourriture? "
gameforge.locale.monster_chat_406_4 = "Aaargh, meurs! "
gameforge.locale.monster_chat_406_5 = "Mon estomac d\233cidera de l'issue de ce combat! "
gameforge.locale.monster_chat_406_6 = "C'est un choix entre le paradis et l'enfer! "
gameforge.locale.monster_chat_491_1 = "Je n'en peux plus! Mon corps me d\233mange. "
gameforge.locale.monster_chat_491_2 = "Oh oui, il y a quelques porcs. "
gameforge.locale.monster_chat_491_3 = "Par terre? "
gameforge.locale.monster_chat_491_4 = "Un seul coup me suffira pour en finir avec toi. "
gameforge.locale.monster_chat_491_5 = "Ce me fera un beau souvenir ! "
gameforge.locale.monster_chat_491_6 = "Meurs! "
gameforge.locale.monster_chat_492_1 = "Mon corps s'est ramolli. "
gameforge.locale.monster_chat_492_2 = "Pourquoi est-ce que je ne m'entra\238ne plus? "
gameforge.locale.monster_chat_492_3 = "Tu as peur hein? "
gameforge.locale.monster_chat_492_4 = "Ah, une nouvelle victime pour mon \233p\233e tournoyante. "
gameforge.locale.monster_chat_492_5 = "Pouvez-vous voir ma force d'attaque ? Non ? Crevez ! "
gameforge.locale.monster_chat_492_6 = "M\234me la plus petite entaille n'est pas bonne pour la sant\233, tu sais? "
gameforge.locale.monster_chat_493_1 = "C'est si inconfortable d'avoir une telle main! "
gameforge.locale.monster_chat_493_2 = "Qu'est-ce que tu regardes? Tu n'a jamais vu une main comme celle-l\224? "
gameforge.locale.monster_chat_493_3 = "Vous me tapez tous sur les nerfs. "
gameforge.locale.monster_chat_493_4 = "Tu veux que je te mette une racl\233e? Sinon, sauve-toi. Compris? "
gameforge.locale.monster_chat_493_5 = "Je vais te montrer mon meilleur coup! "
gameforge.locale.monster_chat_493_6 = "Je sais que tu regardes ma main! "
gameforge.locale.monster_chat_494_1 = "H\233 toi, si tu veux te battre, viens ici! "
gameforge.locale.monster_chat_494_2 = "Je pense que je suis plut\244t \233poustouflant. "
gameforge.locale.monster_chat_494_3 = "Pourquoi est-ce qu'on n'organise pas quelque chose? "
gameforge.locale.monster_chat_494_4 = "Non, tu n'as pas le droit de partir, encore. Bats-toi! "
gameforge.locale.monster_chat_494_5 = "Tiens, voil\224! "
gameforge.locale.monster_chat_494_6 = "Tu es presque mort! "
gameforge.locale.monster_chat_501_1 = "Joue avec moi! Ne t'en vas pas! "
gameforge.locale.monster_chat_501_2 = "Je pourrais faire de beaux bijoux avec vos os ! "
gameforge.locale.monster_chat_501_3 = "Nous ne nous sommes pas encore entra\238n\233s. "
gameforge.locale.monster_chat_501_4 = "Quelle armure fantastique! Je la veux. "
gameforge.locale.monster_chat_501_5 = "\192 partir de maintenant tu vas avoir du mal \224 ignorer mes attaques. "
gameforge.locale.monster_chat_501_6 = "H\233h\233, surpris? "
gameforge.locale.monster_chat_502_1 = "La beaut\233 ne fait pas tout. "
gameforge.locale.monster_chat_502_2 = "Ne regarde pas b\234tement, bats-toi! "
gameforge.locale.monster_chat_502_3 = "Je n'aime pas ta fa\231on de me regarder. Bats-toi! "
gameforge.locale.monster_chat_502_4 = "C'est un honneur de mourir par mon \233p\233e! "
gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "Tr\232s bien\160! "
gameforge.locale.monster_chat_503_1 = "H\233 l\224, ne touche pas! "
gameforge.locale.monster_chat_503_2 = "On dirait que la corde de mon arc est coup\233e. "
gameforge.locale.monster_chat_503_3 = "Minces, ces idiots \233taient ici. "
gameforge.locale.monster_chat_503_4 = "Pas mal. Mais tu mourras quand m\234me! "
gameforge.locale.monster_chat_503_5 = "Tu es d'accord? Parfait! "
gameforge.locale.monster_chat_503_6 = "Voil\224 la fl\232che! "
gameforge.locale.monster_chat_504_1 = "Venez tous par ici! "
gameforge.locale.monster_chat_504_2 = "La, lala, j'en chante une belle chanson... "
gameforge.locale.monster_chat_504_3 = "Quel temps magnifique! "
gameforge.locale.monster_chat_504_4 = {}
gameforge.locale.monster_chat_504_5 = "Ton d\233sir de combattre me fait plaisir! "
gameforge.locale.monster_chat_504_6 = "Allez ! Tous par ici ! Je vous attends ! "
gameforge.locale.monster_chat_601_1 = "J'ai tr\232s faim! "
gameforge.locale.monster_chat_601_2 = "J'ai envie de manger des fruits. "
gameforge.locale.monster_chat_601_3 = "Bien, aussi utile qu'un poisson. \192 l'attaque ! "
gameforge.locale.monster_chat_601_4 = "Ne t'enfuis pas! Reste ici! "
gameforge.locale.monster_chat_601_5 = "J'ai gagn\233. C'est \233vident! "
gameforge.locale.monster_chat_601_6 = "Tu vois? Rat\233! "
gameforge.locale.monster_chat_601_7 = "Tu devrais faire attention, ah ah ! "
gameforge.locale.monster_chat_602_1 = "O\249 suis-je? "
gameforge.locale.monster_chat_602_2 = "Beau temps. "
gameforge.locale.monster_chat_602_3 = "Tu es venu me traquer? N'importe quoi! "
gameforge.locale.monster_chat_602_4 = "Tu es ma proie. "
gameforge.locale.monster_chat_602_5 = "Quel supplice, hein? Je vais t'achever rapidement. "
gameforge.locale.monster_chat_602_6 = "Regarde comme je suis fort : je peux balancer cette \233norme batte ! "
gameforge.locale.monster_chat_603_1 = "Rasoir! "
gameforge.locale.monster_chat_603_2 = "Mon corps entier me d\233mange. "
gameforge.locale.monster_chat_603_3 = "Qui que ce soit, allez-y. "
gameforge.locale.monster_chat_603_4 = "Tu m'as touch\233 le premier? Tu ne vas pas faire long feu ici! "
gameforge.locale.monster_chat_603_5 = "Une fois entr\233, impossible d'en sortir. Aucune \233chappatoire possible! "
gameforge.locale.monster_chat_603_6 = "Ce sera mon dernier coup. Je vais t'achever! "
gameforge.locale.monster_chat_604_1 = "J'ai fabriqu\233 un poison au go\251t sensationnel. Vous voulez y go\251ter ? "
gameforge.locale.monster_chat_604_2 = "Je veux voir comment il marche! Prends \231a ! "
gameforge.locale.monster_chat_604_3 = "H\233 toi, tu veux \234tre mon cobaye?! "
gameforge.locale.monster_chat_604_4 = "Je vais t'empoisonner! "
gameforge.locale.monster_chat_604_5 = "Oh, tr\232s bien, un cobaye! "
gameforge.locale.monster_chat_604_6 = "Ce n'est pas marrant si tu abandonnes aussi vite!! D\233fends toi mauviette ! "
gameforge.locale.monster_chat_631_1 = "Un instant, je cherche quelque chose \224 chasser! "
gameforge.locale.monster_chat_631_2 = "\199a ne marche pas si tu es trop lent! "
gameforge.locale.monster_chat_631_3 = "J'ai si faim! "
gameforge.locale.monster_chat_631_4 = "C'est bien, j'ai trouv\233 quelque chose \224 chasser! "
gameforge.locale.monster_chat_631_5 = "N'esp\232re pas survivre ! "
gameforge.locale.monster_chat_631_6 = "Je vais t'apprendre ce que souffrir veut dire ! "
gameforge.locale.monster_chat_632_1 = "Je m'ennuiiiiiiiiiie !! "
gameforge.locale.monster_chat_632_2 = "Y'a quelque chose qui puisse servir d'app\226t? "
gameforge.locale.monster_chat_632_3 = "Viens te battre si tu l'oses! "
gameforge.locale.monster_chat_632_4 = "Si tu es un guerrier, prouve-le moi ! "
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "Fuis et regagne le village si tu tiens \224 la vie! "
gameforge.locale.monster_chat_633_1 = "C'est douloureux d'\234tre affam\233. "
gameforge.locale.monster_chat_633_2 = "Oh, ils se dirigent droit sur nous! "
gameforge.locale.monster_chat_633_3 = "Que dirais-tu d'un duel? "
gameforge.locale.monster_chat_633_4 = "Ne me compare pas \224 ces fils de chiens! "
gameforge.locale.monster_chat_633_5 = "Voil\224 un coup rapide comme l'\233clair ! "
gameforge.locale.monster_chat_633_6 = "Celui qui fuit n'est pas un vrai guerrier ! "
gameforge.locale.monster_chat_634_1 = "Cette fois-ci le poison devrait \234tre plus efficace! "
gameforge.locale.monster_chat_634_2 = "Quand on a faim, les chauve-souris ont tr\232s bon go\251t. "
gameforge.locale.monster_chat_634_3 = "\199a te dit de te battre? "
gameforge.locale.monster_chat_634_4 = "Si tu es infect\233 par mon poison, il n'existe aucun rem\232de. "
gameforge.locale.monster_chat_634_5 = "Ma magie br\251lera tout, ah ah ah ! "
gameforge.locale.monster_chat_634_6 = "Br\251le! Haha! "
gameforge.locale.monster_chat_635_1 = "N'oublie jamais d'aff\251ter ton \233p\233e! Il y a toujours un autre combat qui t'attend. "
gameforge.locale.monster_chat_635_2 = "Panne? "
gameforge.locale.monster_chat_635_3 = "Meurs, comme \231a tu pourras te r\233veiller en enfer ! "
gameforge.locale.monster_chat_635_4 = "Me vaincre? Vraiment? "
gameforge.locale.monster_chat_635_5 = "Bats-toi comme un guerrier! (vlan) "
gameforge.locale.monster_chat_635_6 = "Encore un petit peu. "
gameforge.locale.monster_chat_636_1 = "J'ai envie d'un bon combat. "
gameforge.locale.monster_chat_636_2 = "C'est amusant de se battre. (rire) "
gameforge.locale.monster_chat_636_3 = "Je voudrais passer ma vie \224 me battre! "
gameforge.locale.monster_chat_636_4 = "Ah c'est bon ! Essaie encore ! "
gameforge.locale.monster_chat_636_5 = "Regarde bien mon \233p\233e ! "
gameforge.locale.monster_chat_636_6 = "Tu vas regretter de m'avoir touch\233! "
gameforge.locale.monster_chat_636_7 = "Quelle faiblesse! Ridicule ! "
gameforge.locale.monster_chat_637_1 = "Je ne veux pas \234tre d\233rang\233. "
gameforge.locale.monster_chat_637_2 = "Va te coucher. Pour toujours ! "
gameforge.locale.monster_chat_637_3 = "Toujours pas endormi? "
gameforge.locale.monster_chat_637_4 = "Il y a beaucoup \224 faire ! Allons-y ! "
gameforge.locale.monster_chat_637_5 = "Ne sois pas \233tonn\233 de ma puissance! "
gameforge.locale.monster_chat_637_6 = "Je vais te pulv\233riser! "
gameforge.locale.monster_chat_691_1 = "J'aime avoir un adversaire \224 la hauteur ! "
gameforge.locale.monster_chat_691_2 = "Quoi? De quoi j'ai l'air? "
gameforge.locale.monster_chat_691_3 = "Ne me comparez pas \224 ce d\233butant! "
gameforge.locale.monster_chat_691_4 = "Toi, je ne t'aime pas, lui non plus ne t'aime pas ! "
gameforge.locale.monster_chat_691_5 = "Battons-nous. "
gameforge.locale.monster_chat_691_6 = "Jusqu'\224 la mort! "
gameforge.locale.monster_chat_701_1 = "Regarde, un papillon ! Comme il est mignon ! "
gameforge.locale.monster_chat_701_2 = "Ne voyez-vous pas la v\233rit\233 du ciel et de la terre? "
gameforge.locale.monster_chat_701_3 = "Apr\232s, il sera trop tard pour croire. Convertissez-vous maintenant! "
gameforge.locale.monster_chat_701_4 = "Embrassez la doctrine des mystiques! "
gameforge.locale.monster_chat_701_5 = "Ceux qui doutent p\233riront! "
gameforge.locale.monster_chat_701_6 = "Que la mort vous \233claire! "
gameforge.locale.monster_chat_702_1 = "La v\233rit\233 mystique ne peut \234tre r\233v\233l\233e qu'en comprenant l'ordre de toute chose sur la terre comme dans le ciel. "
gameforge.locale.monster_chat_702_2 = "La philosophie mystique est l'ordre cosmique! "
gameforge.locale.monster_chat_702_3 = "V\233rit\233 mystique; v\233rit\233 du Dieu Tigre; Sabaha Sabaha. "
gameforge.locale.monster_chat_702_4 = "Tu oses douter de la v\233rit\233 du ciel et de la terre? "
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "Voici mon \233p\233e\160! "
gameforge.locale.monster_chat_703_1 = "Quand la v\233rit\233 du Dieu Tigre sera chant\233e pour les si\232cles des si\232cles, toute souffrance dispara\238tra. "
gameforge.locale.monster_chat_703_2 = "La v\233rit\233 mystique ne peut \234tre r\233v\233l\233e qu'en comprenant l'ordre de toute chose sur la terre comme dans le ciel. "
gameforge.locale.monster_chat_703_3 = "Sabaha Sabaha. Accorde-nous la connaissance! "
gameforge.locale.monster_chat_703_4 = "Ne doute pas! "
gameforge.locale.monster_chat_703_5 = "Que la foudre des cieux s'abatte sur toi! "
gameforge.locale.monster_chat_703_6 = "La frappe du Jugement! "
gameforge.locale.monster_chat_704_1 = "La v\233rit\233 mystique ne peut \234tre r\233v\233l\233e qu'en comprenant l'ordre de toute chose sur la terre comme dans le ciel. "
gameforge.locale.monster_chat_704_2 = "V\233rit\233 mystique; v\233rit\233 du Dieu Tigre; Sabaha Sabaha. "
gameforge.locale.monster_chat_704_3 = "Tu penses que je suis un clown ? Plus pour longtemps ! "
gameforge.locale.monster_chat_704_4 = "Le chef de cette secte est un saint et il est sup\233rieur \224 tous les \234tres vivants\160! "
gameforge.locale.monster_chat_704_5 = "Que les flammes de l'enfer t'emportent! "
gameforge.locale.monster_chat_704_6 = "Tu n'as jamais rien vu d'aussi gros avant n'est-ce pas ? "
gameforge.locale.monster_chat_705_1 = "V\233rit\233 mystique; v\233rit\233 du Dieu Tigre; Sabaha Sabaha. "
gameforge.locale.monster_chat_705_2 = "La v\233rit\233 mystique ne peut \234tre r\233v\233l\233e qu'en comprenant l'ordre de toute chose sur la terre comme dans le ciel. "
gameforge.locale.monster_chat_705_3 = "Ce n'est pas parce que je suis plus petit que mon fr\232re que je vais tout supporter sans rien dire ! "
gameforge.locale.monster_chat_705_4 = "Souffrance \233ternelle et t\233n\232bres vous attendent ! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Ce n'est pas la fin. \199a sera mieux apr\232s. "
gameforge.locale.monster_chat_706_1 = "Nous demandons la paix et qu'on nous laisse tranquilles! S'il vous pla\238t! "
gameforge.locale.monster_chat_706_2 = "Si la peur domine, la v\233rit\233 du Dieu Tigre nous aidera! "
gameforge.locale.monster_chat_706_3 = "La v\233rit\233 mystique r\233v\232le l'ordre cosmique. "
gameforge.locale.monster_chat_706_4 = "Allons tous en enfer! "
gameforge.locale.monster_chat_706_5 = "Je ne te laisserai pas partir! "
gameforge.locale.monster_chat_706_6 = "Je vous donnerai tout ce que j'ai. "
gameforge.locale.monster_chat_707_1 = "Je vous en prie sauvez-nous! "
gameforge.locale.monster_chat_707_2 = "La v\233rit\233 mystique ne peut \234tre r\233v\233l\233e qu'en comprenant l'ordre de toute chose sur la terre comme dans le ciel. "
gameforge.locale.monster_chat_707_3 = "V\233rit\233 mystique; v\233rit\233 du Dieu Tigre; Sabaha Sabaha. "
gameforge.locale.monster_chat_707_4 = "(rire bruyant) Les portes de l'enfer sont grandes ouvertes. Meurs! "
gameforge.locale.monster_chat_707_5 = "Je te pr\233viens ! Ne m'oblige pas \224 utiliser le tableau ! "
gameforge.locale.monster_chat_707_6 = "Je vois ta mort, d\233j\224! "
gameforge.locale.monster_chat_791_1 = "Comment dire en peu de mots la v\233rit\233 du Dieu tigre? "
gameforge.locale.monster_chat_791_2 = "J'entends les psalmodies des fid\232les. "
gameforge.locale.monster_chat_791_3 = "C'est bien! Repends-toi et tu seras sauv\233! "
gameforge.locale.monster_chat_791_4 = "Tu souffres de la douleur \233ternelle, car tu doutes de la v\233rit\233! "
gameforge.locale.monster_chat_791_5 = "\201coute mon enseignement. "
gameforge.locale.monster_chat_791_6 = "Ne vois pas cela comme de la souffrance, mais comme un apprentissage. "
gameforge.locale.monster_chat_901_1 = "Je ne suis peut-\234tre pas beau, mais je sais m'amuser ! "
gameforge.locale.monster_chat_901_2 = "Tu dois nous rejoindre! "
gameforge.locale.monster_chat_901_3 = "Venez, venez ! "
gameforge.locale.monster_chat_901_4 = "Haaaaa !! Ah Ah ! "
gameforge.locale.monster_chat_901_5 = "\199a commence! "
gameforge.locale.monster_chat_903_1 = "C'est l'enfer ! "
gameforge.locale.monster_chat_903_2 = "Ahhhh! "
gameforge.locale.monster_chat_903_3 = "Nous ne pouvons pas le faire seuls! Non! "
gameforge.locale.monster_chat_903_4 = "Tu dois toi aussi go\251ter \224 la souffrance! "
gameforge.locale.monster_chat_903_5 = "On fait un deal ? Tu me donnes ton \226me, je te donne ma souffrance ! "
gameforge.locale.monster_chat_903_6 = "Tu connaitras bient\244t la paix \233ternelle! "
gameforge.locale.monster_chat_904_1 = "La douleur! La douleur! "
gameforge.locale.monster_chat_904_2 = "Ma poitrine... \231a br\251le! "
gameforge.locale.monster_chat_904_3 = "Pourquoi devons-nous souffrir, oh pourquoi? "
gameforge.locale.monster_chat_904_4 = "Ce n'est pas si terrible de souffrir de cette myst\233rieuse maladie. "
gameforge.locale.monster_chat_904_5 = {}
gameforge.locale.monster_chat_904_6 = "Ahhhh! "
gameforge.locale.monster_chat_905_1 = "Ahhhh! "
gameforge.locale.monster_chat_905_2 = "Je vais te tueeeeeeeeer! "
gameforge.locale.monster_chat_905_3 = "Ne te contente pas de regarder, aide moi! "
gameforge.locale.monster_chat_905_4 = "Soyons amis! "
gameforge.locale.monster_chat_905_5 = "Tu es d\233j\224 contamin\233. "
gameforge.locale.monster_chat_905_6 = "Maintenant tu es mon ami. "
gameforge.locale.monster_chat_906_1 = "Hi hi hi "
gameforge.locale.monster_chat_906_2 = "Viens sentir ma fl\232che! "
gameforge.locale.monster_chat_906_3 = "Tu es vraiment casse-pieds! "
gameforge.locale.monster_chat_906_4 = "Je vais t'infecter avec la maladie myst\233rieuse. "
gameforge.locale.monster_chat_906_5 = "\199a sent bon! "
gameforge.locale.monster_chat_906_6 = "Meurs! "
gameforge.locale.monster_chat_907_1 = "Je vais devoir trouver un autre pathog\232ne... "
gameforge.locale.monster_chat_907_2 = "(Rire) On va bien s'amuser! "
gameforge.locale.monster_chat_907_3 = "Hmm, fouet ou grappin ... ? "
gameforge.locale.monster_chat_907_4 = "Ahhhhh, ouiiiiii! "
gameforge.locale.monster_chat_907_5 = "Je vais te passer la maladie! "
gameforge.locale.monster_chat_907_6 = "La cause tenace de la myst\233rieuse maladie! "
