gameforge.locale.old_pirate.baekgo_accept_ask = "Baek-Go\160:[ENTER]Vous n'avez encore rien trouv\233\160?[ENTER]Nous devons stopper la maladie avant qu'elle ne[ENTER]s'\233tende \224 tout le village\160! D\233p\234chez-vous\160! "
