gameforge.locale.old_pirate.baekgo_accept_failure_info_text_1 = "Retournez voir Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_failure_info_text_2 = "Dites \224 Baek-Go que vous n'avez pas pu trouver le[ENTER]pathog\232ne de la maladie myst\233rieuse. "
gameforge.locale.old_pirate.baekgo_accept_failure_say_1 = "Retournez voir Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_failure_say_2 = "Je n'arrive pas \224 trouver le pathog\232ne de la[ENTER]maladie myst\233rieuse! Que vais-je dire \224 Baek-Go? "
gameforge.locale.old_pirate.baekgo_accept_success_info_label = "Apportez l'\233chantillon \224 Baek-Go "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_1 = "Apportez un \233chantillon du pathog\232ne \224 Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_2 = "Apportez un \233chantillon du pathog\232ne \224 Baek-Go et[ENTER]obtenez le m\233dicament pour le vieux pirate. "
gameforge.locale.old_pirate.baekgo_accept_success_say_1 = "J'ai un \233chantillon du pathog\232ne de la[ENTER]myst\233rieuse maladie. "
gameforge.locale.old_pirate.baekgo_accept_success_say_2 = "J'ai un \233chantillon du pathog\232ne de la[ENTER]myst\233rieuse maladie. Je dois l'apporter \224[ENTER]Baek-Go. "
gameforge.locale.old_pirate.baekgo_do_you_get_the_virus = "Je ne sais pas d'o\249 vient cette myst\233rieuse[ENTER]maladie. "
gameforge.locale.old_pirate.baekgo_iv_got_the_virus = "J'ai trouv\233 la cause de la maladie myst\233rieuse. "
gameforge.locale.old_pirate.baekgo_order_find_virus_label = "Tuez tous les infect\233s "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_1 = "Tuez tous ceux qui sont atteints de la maladie[ENTER]myst\233rieuse! "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_2 = "Tuez tous ceux qui sont atteints de la[ENTER]myst\233rieuse maladie et apportez un \233chantillon du[ENTER]pathog\232ne \224 Baek-Go. Il va confectionner le[ENTER]rem\232de pour le vieux pirate. "
gameforge.locale.old_pirate.baekgo_order_too_late = "Baek-Go :[ENTER]Quelqu'un d'autre m'a d\233j\224 apport\233 un \233chantillon[ENTER]du pathog\232ne. J'ai envoy\233 le rem\232de au vieux[ENTER]pirate. Il doit aller mieux maintenant. "
gameforge.locale.old_pirate.baekgo_start_say = "Baek-Go\160:[ENTER]Il n'a eu qu'un seul contact avec une personne[ENTER]infect\233e et sa blessure a commenc\233 \224 le d\233manger[ENTER]et \224 suppurer\160? "
gameforge.locale.old_pirate.baekgo_start_say2 = "Baek-Go\160:[ENTER]Oh, mon dieu\160! Je suis presque s\251r qu'il a \233t\233[ENTER]contamin\233 par cette maladie myst\233rieuse\160! S'il[ENTER]n'est pas trait\233 rapidement, la maladie va se[ENTER]r\233pandre dans tout le village\160! "
gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go\160:[ENTER]Il faut l'isoler pour qu'il ne contamine[ENTER]personne. Il faut aussi le traiter imm\233diatement.[ENTER]Pour \231a, il nous faut un \233chantillon du pathog\232ne[ENTER]de cette maladie myst\233rieuse. Vous pourrez en[ENTER]obtenir parmi les gens infect\233s qui vivent sur le[ENTER]mont Sohan dans le Nord. "
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go\160:[ENTER]Vous avez r\233ussi\160! Deux minutes, je vais faire le[ENTER]m\233dicament tout de suite. [DELAY value;1000][ENTER]J'\233tais press\233 donc je ne sais pas s'il va[ENTER]vraiment \234tre efficace mais il devrait au moins[ENTER]se sentir mieux. Apportez-lui le rem\232de aussi[ENTER]vite que possible. "
gameforge.locale.old_pirate.baekgo_talk = "Le Vieux Pirate m'envoie. "
gameforge.locale.old_pirate.baekgo_talk_about_old_pirate = "La maladie du vieux pirate. "
gameforge.locale.old_pirate.complete_say = "Le vieux pirate\160:[ENTER]\199a me d\233mange encore. Mais je me sens mieux[ENTER]maintenant. \199a ira comme \231a. "
gameforge.locale.old_pirate.do_you_get_the_medicine = "Je n'ai pas encore le m\233dicament. "
gameforge.locale.old_pirate.do_you_mean_this_medicine = "Voil\224 le rem\232de! "
gameforge.locale.old_pirate.etc_shop_start_say = "La marchande\160:[ENTER]Le vieux pirate\160? Bien s\251r que je le connais\160![ENTER]Vous parlez de ce gaillard qui ne fait que jurer[ENTER]et se gratter, n'est-ce pas\160? Il vient souvent[ENTER]par ici pour acheter des potions. Il a d\233pens\233[ENTER]des milliers de yangs en potion rouge. "
gameforge.locale.old_pirate.etc_shop_start_say2 = "La marchande\160:[ENTER]O\249 diantre se procure-t-il tous ces yangs\160? Il ne[ENTER]travaille m\234me pas! Je lui ai dit plusieurs fois[ENTER]d'aller voir un docteur mais il ne m'\233coute pas.[ENTER]Je lui ai dit et r\233p\233t\233 que la potion rouge est[ENTER]uniquement \224 usage externe mais il m'ignore. J'ai[ENTER]bien peur que tout ceci ne finisse mal. "
gameforge.locale.old_pirate.etc_shop_talk_about_old_pirate = "Connaissez-vous le vieux pirate ? "
gameforge.locale.old_pirate.order_accept = "Je vais vous aider "
gameforge.locale.old_pirate.order_accept_answer = "Le vieux pirate\160:[ENTER]Fantastique\160! Bonne chance\160![ENTER]Le m\233decin est s\251rement dans la ville. "
gameforge.locale.old_pirate.order_find_medicine_label = "Rem\232de pour le vieux pirate. "
gameforge.locale.old_pirate.order_find_medicine_text_1 = "Allez chercher le rem\232de pour le vieux pirate. "
gameforge.locale.old_pirate.order_find_medicine_text_2 = "Allez voir Baek-Go en ville et demandez lui le[ENTER]rem\232de pour le vieux pirate. "
gameforge.locale.old_pirate.order_refuse = "Je suis d\233sol\233, je ne peux pas. "
gameforge.locale.old_pirate.order_refuse_answer = "Le vieux pirate\160:[ENTER]Bien, dans ce cas nous n'avons plus rien \224 nous[ENTER]dire. "
gameforge.locale.old_pirate.order_say1 = "Le vieux pirate\160:[ENTER]Par tous les diables, que me veut-il celui-l\224?[ENTER]Morbleu! C'est cette m\233g\232re de marchande qui vous[ENTER]a parl\233 de moi, n'est-ce pas? Ce qu'elle vous a[ENTER]dit est vrai mais je n'ai pas le temps d'aller[ENTER]voir le docteur, j'ai tellement d'ennemis. "
gameforge.locale.old_pirate.order_say2 = "Le vieux pirate\160:[ENTER]Ces fils de chiens sont capables de me tomber[ENTER]dessus pour me poignarder n'importe quand! Mais[ENTER]ces d\233mangeaisons me rendent fou, je n'en peux[ENTER]plus! Et si vous alliez chez le docteur pour me[ENTER]chercher le rem\232de \224 ma place? Je vous[ENTER]r\233compenserais g\233n\233reusement. "
gameforge.locale.old_pirate.order_too_late = "Le vieux pirate\160:[ENTER]Quelqu'un d'autre m'a d\233j\224 rapport\233 le[ENTER]m\233dicament. D\233sol\233, \231a veut dire pas de[ENTER]r\233compense pour vous! "
gameforge.locale.old_pirate.start_find_old_pirate_label = "Allez voir le vieux pirate. "
gameforge.locale.old_pirate.start_find_old_pirate_text_1 = "Allez voir le vieux pirate. "
gameforge.locale.old_pirate.start_find_old_pirate_text_2 = "Allez voir le vieux pirate et demandez-lui[ENTER]pourquoi il ne va pas voir un docteur. "
gameforge.locale.old_pirate.start_say = "Le vieux pirate\160:[ENTER]\199a me gratte de partout! Je n'aurais jamais d\251 me[ENTER]cogner \224 ce type! Je l'ai \224 peine effleur\233![ENTER]L'endroit qu'il a touch\233 est infect\233 depuis et[ENTER]tout mon corps me d\233mange! On dirait que je suis[ENTER]en train de pourrir vivant! Le fils de chien! "
gameforge.locale.old_pirate.success_thanks = "Le vieux pirate\160:[ENTER]Hein? J'ai \233t\233 contamin\233 par la maladie[ENTER]myst\233rieuse? vous avez le rem\232de n\233cessaire ?[ENTER]Merci, merci beaucoup ! Vous me sauvez la vie ![ENTER]Je vous en suis tr\232s reconnaissant. "
gameforge.locale.old_pirate.talk = "\202tes-vous le vieux pirate ? "
gameforge.locale.old_pirate.talk_about_medicine = "Pourquoi n'allez vous pas voir un docteur? "
