gameforge.locale.questscroll5 = {}
gameforge.locale.questscroll5.mission_10_hunt = "La marche des ours affam\233s "
gameforge.locale.questscroll5.mission_10_mis = "Tuez 25 ours noirs et 25 grizzlys. "
gameforge.locale.questscroll5.mission_10_text = "Oh, s'il vous pla\238t aidez-nous. Depuis quelques[ENTER]temps un nombre grandissant de grizzlys et d'ours[ENTER]noirs d\233truisent nos ruches et nos cultures.[ENTER]Aidez-nous s'il vous pla\238t. Sans les abeilles et[ENTER]les fruits nous allons mourir de faim. Tuez ces[ENTER]b\234tes pour nous aider. "
gameforge.locale.questscroll5.mission_11_hunt = "L'Ouragan des loups bleus "
gameforge.locale.questscroll5.mission_11_mis = "Tuez 35 loups bleus et 25 loups alpha bleus. "
gameforge.locale.questscroll5.mission_11_text = "Avez-vous entendu parler de l'ouragan des loups[ENTER]bleus? \199a concerne le grabuge que les loups bleus[ENTER]ont caus\233 ces derni\232res semaines. Ils d\233truisent[ENTER]tout sur leur passage, pareils \224 un ouragan de[ENTER]fourrure et de crocs. Guerrier, peux-tu combattre[ENTER]cet ouragan? "
gameforge.locale.questscroll5.mission_12_hunt = "Chasser l'arm\233e blanche "
gameforge.locale.questscroll5.mission_12_mis = "Tuez 20 leaders du Serment Blanc. "
gameforge.locale.questscroll5.mission_12_text = "Ces derniers temps, le Serment Blanc a caus\233 pas[ENTER]mal de troubles. Ils capturent les marchands[ENTER]ambulants et attaquent les villages. S'il vous[ENTER]pla\238t arr\234tez leur arm\233e. \201liminez les membres du[ENTER]Serment Blanc et leurs leaders. "
gameforge.locale.questscroll5.mission_13_hunt = "Le Vent Noir agit\233 "
gameforge.locale.questscroll5.mission_13_mis = "Tuez 25 Jak-To et 25 To-Su du clan du Vent Noir. "
gameforge.locale.questscroll5.mission_13_text = "On dit que le gang du Vent Noir veut s'emparer de[ENTER]l'empire. Nous ferions mieux d'\233liminer leurs[ENTER]leaders avant qu'ils n'aient le temps de[ENTER]renforcer leur arm\233e. Faites-le s'il vous pla\238t,[ENTER]\233liminez leurs chefs. "
gameforge.locale.questscroll5.mission_14_hunt = "La Grande R\233volte des orcs 1 "
gameforge.locale.questscroll5.mission_14_mis = "Tuez 30 orcs intr\233pides et 30 \233claireurs orcs. "
gameforge.locale.questscroll5.mission_14_text = "Des informations secr\232tes laissent \224 penser que[ENTER]les chefs des orcs de la vall\233e de Seungryong[ENTER]dans la zone neutre ont pour ambition de se[ENTER]lancer \224 la conqu\234te du monde. Je voudrais que[ENTER]vous alliez vous renseigner \224 ce sujet, guerrier.[ENTER]Et profitez de votre pr\233sence l\224 bas pour r\233duire[ENTER]leur nombre. "
gameforge.locale.questscroll5.mission_15_hunt = "L'attaque des barbares "
gameforge.locale.questscroll5.mission_15_mis = "Tuez 30 soldats barbare et 30 minions barbare. "
gameforge.locale.questscroll5.mission_15_text = "Nous avons obtenu une information cruciale aupr\232s[ENTER]d'un espion barbare que nous avons captur\233. Les[ENTER]Barbares veulent raider l'empire. Nous devons[ENTER]attaquer avant qu'ils ne le fassent. Montrez[ENTER]votre loyaut\233 \224 votre empire. "
gameforge.locale.questscroll5.mission_16_hunt = "Brisez la Metin des T\233n\232bres "
gameforge.locale.questscroll5.mission_16_mis = "D\233truisez 3 Metin des T\233n\232bres. "
gameforge.locale.questscroll5.mission_16_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_17_hunt = "Brisez la pierre Metin Noire "
gameforge.locale.questscroll5.mission_17_mis = "D\233truisez 2 pierres Metin Noires. "
gameforge.locale.questscroll5.mission_17_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_18_hunt = "L'attaque des Se-Rangs "
gameforge.locale.questscroll5.mission_18_mis = "Tuez 10 Se-Rangs de l'arm\233e du Serment Blanc. "
gameforge.locale.questscroll5.mission_18_text = "Guerrier, nous avons de nouvelles informations[ENTER]concernant le Serment Blanc. En r\233action \224 nos[ENTER]offensives contre eux, les Se-Rangs, leaders du[ENTER]Serment Blanc ont lanc\233 une contre-offensive. Il[ENTER]faut agir contre les Se-Rangs d\232s maintenant! Ce[ENTER]n'est pas en tuant quelques fantassins que nous[ENTER]arriverons \224 quelque chose. Nous devons \233liminer[ENTER]leurs leaders si nous voulons contrer leurs[ENTER]plans. "
gameforge.locale.questscroll5.mission_19_hunt = "La Grande r\233volte des orcs 2 "
gameforge.locale.questscroll5.mission_19_mis = "Tuez 20 combattants d'\233lite orcs et 15 sorciers[ENTER]d'\233lite orcs. "
gameforge.locale.questscroll5.mission_19_text = "Des informations secr\232tes semblent montrer que[ENTER]les leaders orcs de la vall\233e de Seungryong dans[ENTER]la zone neutre veulent se lancer \224 la conqu\234te du[ENTER]monde. Je vous demande de vous renseigner \224 ce[ENTER]sujet, guerrier. Et profitez-en pour r\233duire leur[ENTER]nombre puisque vous serez sur place. "
gameforge.locale.questscroll5.mission_1_hunt = "Brisez la Metin de Combat "
gameforge.locale.questscroll5.mission_1_mis = "D\233truisez 3 Metins de Combat "
gameforge.locale.questscroll5.mission_1_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_20_hunt = "Le secret du Donjon normal des Singes 1 "
gameforge.locale.questscroll5.mission_20_mis = "Tuez 30 soldats singes et 30 singes lanceurs. "
gameforge.locale.questscroll5.mission_20_text = "L'emplacement du donjon des singes moyen a[ENTER]finalement \233t\233 trouv\233 dans le d\233sert. Normalement[ENTER]ces singes ne constituent pas une menace mais si[ENTER]ils se r\233unissent ils pourraient repr\233senter un[ENTER]danger pour notre empire. Allez au donjon des[ENTER]singes moyen et essayez de d\233couvrir ce qui s'y[ENTER]trame. "
gameforge.locale.questscroll5.mission_21_hunt = "Le secret du Donjon facile des Singes 1 "
gameforge.locale.questscroll5.mission_21_mis = "Tuez 30 singes faibles et 30 singes lanceurs[ENTER]faibles. "
gameforge.locale.questscroll5.mission_21_text = "L'emplacement du Donjon facile des Singes a[ENTER]finalement \233t\233 trouv\233. Normalement ces singes ne[ENTER]constituent pas une menace mais s'ils se[ENTER]r\233unissent ils pourraient repr\233senter un danger[ENTER]pour notre empire. Allez au donjon des singes[ENTER]facile et essayez de d\233couvrir ce qui s'y trame. "
gameforge.locale.questscroll5.mission_22_hunt = "Ils s\232ment le vent et r\233coltent la temp\234te. "
gameforge.locale.questscroll5.mission_22_mis = "Tuez 4 Chuongs du Gang du Vent Noir. "
gameforge.locale.questscroll5.mission_22_text = "Les Chuongs, leaders du Gang du Vent Noir,[ENTER]commencent \224 faire parler d'eux. Ils sont des[ENTER]ma\238tres du combat \224 l'\233p\233e et s'amusent \224 d\233fier[ENTER]des guerriers par jeu. Arr\234tez-les avant que tout[ENTER]le gang ne s'y mette. "
gameforge.locale.questscroll5.mission_23_hunt = "Brisez la Metin de Jalousie "
gameforge.locale.questscroll5.mission_23_mis = "D\233truisez 2 Metins de Jalousie "
gameforge.locale.questscroll5.mission_23_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_24_hunt = "Secret du Donjon normal des Singes 2 "
gameforge.locale.questscroll5.mission_24_mis = "Tuez 15 combattants singes et 15 g\233n\233raux singes. "
gameforge.locale.questscroll5.mission_24_text = "L'emplacement du Donjon normal des Singes a[ENTER]finalement \233t\233 trouv\233 dans le d\233sert. Normalement[ENTER]ces singes ne constituent pas une menace mais si[ENTER]ils se r\233unissent ils pourraient repr\233senter un[ENTER]danger pour notre empire.Allez au donjon des[ENTER]singes moyen et essayez de d\233couvrir ce qui s'y[ENTER]trame. "
gameforge.locale.questscroll5.mission_25_hunt = "Le secret du Donjon facile des Singes 2 "
gameforge.locale.questscroll5.mission_25_mis = "Tuez 15 singes combattants et 15 sing\233s g\233n\233raux[ENTER]faibles. "
gameforge.locale.questscroll5.mission_25_text = "L'emplacement du Donjon facile des Singes a[ENTER]finalement \233t\233 trouv\233. Normalement ces singes ne[ENTER]constituent pas une menace mais s'ils se[ENTER]r\233unissent ils pourraient repr\233senter un danger[ENTER]pour notre empire. Allez au donjon des singes[ENTER]facile et essayez de d\233couvrir ce qui s'y trame. "
