gameforge.locale.questscroll5.mission_26_mis = "D\233truisez 2 Metins des \226mes "
gameforge.locale.questscroll5.mission_26_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_27_hunt = "La col\232re de l'araign\233e 1 "
gameforge.locale.questscroll5.mission_27_mis = "Tuez 40 jeunes araign\233es. "
gameforge.locale.questscroll5.mission_27_text = "Les araign\233es qui vivaient jusqu'\224 pr\233sent[ENTER]paisiblement dans le d\233sert de Yongbi se sont[ENTER]mises \224 attaquer et tuer des voyageurs. C'est[ENTER]mauvais pour le commerce dans notre empire.[ENTER]\201liminez ces araign\233es s'il vous pla\238t. "
gameforge.locale.questscroll5.mission_28_hunt = "La col\232re de l'araign\233e 2 "
gameforge.locale.questscroll5.mission_28_mis = "Tuez 40 araign\233es venimeuses "
gameforge.locale.questscroll5.mission_28_text = "Les araign\233es qui vivaient jusqu'\224 pr\233sent[ENTER]paisiblement dans le d\233sert de Yongbi se sont[ENTER]mises \224 attaquer et tuer des voyageurs. C'est[ENTER]mauvais pour le commerce dans notre empire.[ENTER]\201liminez ces araign\233es s'il vous pla\238t. "
gameforge.locale.questscroll5.mission_29_hunt = "Les disciples des t\233n\232bres 2 "
gameforge.locale.questscroll5.mission_29_mis = "Tuez 20 combattants funestes et 25 chefs Arahan[ENTER]funestes. "
gameforge.locale.questscroll5.mission_29_text = "Nous avons finalement re\231u l'ordre d'\233liminer la[ENTER]secte la plus dangereuse de l'empire, la secte[ENTER]myst\233rieuse. Vous les trouverez dans la vall\233e de[ENTER]Seungryong. Soyez pr\233par\233, il n'est pas facile de[ENTER]les tuer. "
gameforge.locale.questscroll5.mission_2_hunt = "Brisez la Metin de Tristesse "
gameforge.locale.questscroll5.mission_2_mis = "D\233truisez 2 Metins de Tristesse "
gameforge.locale.questscroll5.mission_2_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
