gameforge.locale.questscroll5.mission_30_mis = "Tuez 30 fanatiques funestes et 30 Arahans[ENTER]funestes. "
gameforge.locale.questscroll5.mission_30_text = "Nous avons finalement re\231u l'ordre d'\233liminer la[ENTER]secte la plus dangereuse de l'empire, la secte[ENTER]myst\233rieuse. Vous les trouverez dans la vall\233e de[ENTER]Seungryong. Soyez pr\233par\233, il n'est pas facile de[ENTER]les tuer. "
