gameforge.locale.questscroll5.mission_31_mis = "Tuez 40 bourreaux funestes et 40 invocateurs[ENTER]funestes. "
gameforge.locale.questscroll5.mission_31_text = "Nous avons finalement re\231u l'ordre d'\233liminer la[ENTER]secte la plus dangereuse de l'empire, la secte[ENTER]myst\233rieuse. Vous les trouverez dans la vall\233e de[ENTER]Seungryong. Soyez pr\233par\233, il n'est pas facile de[ENTER]les tuer. "
gameforge.locale.questscroll5.mission_32_hunt = "Brisez la Metin de l'Ombre "
gameforge.locale.questscroll5.mission_32_mis = "D\233truisez 2 Metins de l'ombre "
gameforge.locale.questscroll5.mission_32_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_33_hunt = "Elles ont 8 pattes (1) "
gameforge.locale.questscroll5.mission_33_mis = "Tuez 35 jeunes araign\233es venimeuses et 35[ENTER]araign\233es mortelles. "
gameforge.locale.questscroll5.mission_33_text = "L'empire a d\233couvert tout un r\233seau de galeries[ENTER]souterraines. On pense qu'elles servent de[ENTER]repaire aux araign\233es du d\233sert de Yongbi. Il n'y[ENTER]a pas d'information fiable \224 propos de ces caves,[ENTER]nous savons seulement qu'elles sont dangereuses.[ENTER]Pourriez-vous y aller? Arr\234tez cette menace en[ENTER]d\233cimant leurs rangs. "
gameforge.locale.questscroll5.mission_34_hunt = "Elles ont 8 pattes (2) "
gameforge.locale.questscroll5.mission_34_mis = "Tuez 35 jeunes araign\233es venimeuses et 35[ENTER]araign\233es mortelles. "
gameforge.locale.questscroll5.mission_34_text = "L'empire a d\233couvert tout un r\233seau de galeries[ENTER]souterraines. On pense qu'elles servent de[ENTER]repaire aux araign\233es du d\233sert de Yongbi. Il n'y[ENTER]a pas d'information fiable \224 propos de ces caves,[ENTER]nous savons seulement qu'elles sont dangereuses.[ENTER]Pourriez-vous y aller? Arr\234tez cette menace en[ENTER]d\233cimant leurs rangs. "
gameforge.locale.questscroll5.mission_35_hunt = "Elles ont 8 pattes (3) "
gameforge.locale.questscroll5.mission_35_mis = "Tuez 35 araign\233es rouges venimeuses et 35[ENTER]araign\233es \224 griffes "
gameforge.locale.questscroll5.mission_35_text = "L'empire a d\233couvert tout un r\233seau de galeries[ENTER]souterraines. On pense qu'elles servent de[ENTER]repaire aux araign\233es du d\233sert de Yongbi. Il n'y[ENTER]a pas d'information fiable \224 propos de ces caves,[ENTER]nous savons seulement qu'elles sont dangereuses.[ENTER]Pourriez-vous y aller? Arr\234tez cette menace en[ENTER]d\233cimant leurs rangs. "
gameforge.locale.questscroll5.mission_36_hunt = "Elles ont 8 pattes (4) "
gameforge.locale.questscroll5.mission_36_mis = "Tuez 40 soldats araign\233es \233lites "
gameforge.locale.questscroll5.mission_36_text = "L'empire a d\233couvert tout un r\233seau de galeries[ENTER]souterraines. On pense qu'elles servent de[ENTER]repaire aux araign\233es du d\233sert de Yongbi. Il n'y[ENTER]a pas d'information fiable \224 propos de ces caves,[ENTER]nous savons seulement qu'elles sont dangereuses.[ENTER]Pourriez-vous y aller? Arr\234tez cette menace en[ENTER]d\233cimant leurs rangs. "
gameforge.locale.questscroll5.mission_37_hunt = "D\233truisez la Metin de Force ! "
gameforge.locale.questscroll5.mission_37_mis = "D\233truisez 2 Metins de Force "
gameforge.locale.questscroll5.mission_37_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_38_hunt = "Le fl\233au des scorpions "
gameforge.locale.questscroll5.mission_38_mis = "Tuez 30 rois scorpions et 20 jeunes hommes[ENTER]scorpions. "
gameforge.locale.questscroll5.mission_38_text = "Ces scorpions empoisonnent la vie des voyageurs[ENTER]et des marchands. C'est mauvais pour le commerce[ENTER]dans notre empire. Tuez-les. "
gameforge.locale.questscroll5.mission_39_hunt = "Compagnie de la mort 1 "
gameforge.locale.questscroll5.mission_39_mis = "Tuez 30 soldats d\233mons et 20 archers d\233mons. "
gameforge.locale.questscroll5.mission_39_text = "Connaissez-vous la Tour des d\233mons\160? Des[ENTER]Mystiques y ont invoqu\233 des \226mes errantes gr\226ce \224[ENTER]de puissants sortil\232ges et ces fant\244mes ont[ENTER]maintenant form\233 un groupe de Soldats D\233mons. Un[ENTER]Invocateur Infernal a pris le contr\244le et il se[ENTER]cache avec les d\233mons dans cette tour.[ENTER]Combattez-les et d\233couvrez leur v\233ritable force. "
gameforge.locale.questscroll5.mission_3_hunt = "L'apparition des loups gris 2 "
gameforge.locale.questscroll5.mission_3_mis = "Tuez 30 loups alpha gris "
gameforge.locale.questscroll5.mission_3_text = "Avez-vous d\233j\224 entendu parler des loups alpha[ENTER]gris? Pour la plupart ils errent sans but, mais[ENTER]ces derni\232res semaines sous l'influence du Chi[ENTER]mal\233fique ils ont commenc\233 \224 s'attaquer aux[ENTER]voyageurs imprudents. Est-il possible que vous[ENTER]\233liminiez ces loups alpha gris? Vous serez[ENTER]certainement r\233compens\233. "
gameforge.locale.questscroll5.mission_40_hunt = "La compagnie de la mort 2 "
gameforge.locale.questscroll5.mission_40_mis = "Tuez 30 lanciers d\233moniaques et 25 chamanes[ENTER]d\233moniaques. "
gameforge.locale.questscroll5.mission_40_text = "Connaissez-vous la Tour des d\233mons\160? Des[ENTER]Mystiques y ont invoqu\233 des \226mes errantes gr\226ce \224[ENTER]de puissants sortil\232ges et ces fant\244mes ont[ENTER]maintenant form\233 un groupe de Soldats D\233mons. Un[ENTER]Invocateur Infernal a pris le contr\244le et il se[ENTER]cache avec les d\233mons dans cette tour.[ENTER]Combattez-les et d\233couvrez leur v\233ritable force. "
gameforge.locale.questscroll5.mission_41_hunt = "Le secret du Donjon difficile des singes 2 "
gameforge.locale.questscroll5.mission_41_mis = "Tuez 15 puissants combattants singes et 15[ENTER]puissants g\233n\233raux singes. "
gameforge.locale.questscroll5.mission_41_text = "L'emplacement du Donjon difficile des Singes a[ENTER]enfin \233t\233 trouv\233. Normalement ces singes ne[ENTER]constituent pas une menace mais s'ils se[ENTER]rassemblent ils pourraient repr\233senter un danger[ENTER]pour notre empire. Allez au donjon des singes[ENTER]difficile et d\233couvrez ce qui s'y trame. "
gameforge.locale.questscroll5.mission_42_hunt = "La glace fondra un jour "
gameforge.locale.questscroll5.mission_42_mis = "Tuez 25 golems de glace au mont Sohan. "
gameforge.locale.questscroll5.mission_42_text = "Le mont Sohan est recouvert de glace. Bien des[ENTER]aventuriers et des guerriers y sont all\233s mais[ENTER]nul n'en est jamais revenu. D\233couvrez pourquoi et[ENTER]s'ils ont \233t\233 attaqu\233s. Peut-\234tre pourrez-vous en[ENTER]apprendre plus sur ce qui s'est pass\233 si vous y[ENTER]chassez quelques monstres. "
gameforge.locale.questscroll5.mission_43_hunt = "Le secret du Donjon difficile des Singes 1 "
gameforge.locale.questscroll5.mission_43_mis = "Tuez 30 Forts Singes Soldats et 30 Forts Singes[ENTER]Lanceurs. "
gameforge.locale.questscroll5.mission_43_text = "L'emplacement du Donjon difficile des Singes a[ENTER]enfin \233t\233 trouv\233. Normalement ces singes ne[ENTER]constituent pas une menace mais s'ils se[ENTER]rassemblent ils pourraient repr\233senter un danger[ENTER]pour notre empire. Allez au donjon des singes[ENTER]difficile et d\233couvrez ce qui s'y trame. "
gameforge.locale.questscroll5.mission_44_hunt = "Les bras droits de l'Esprit du Tigre Jaune "
gameforge.locale.questscroll5.mission_44_mis = "Tuez 30 g\233n\233raux grenouilles taureaux. "
gameforge.locale.questscroll5.mission_44_text = "L'Esprit du Tigre Jaune, Roi de tous les \234tres[ENTER]vivants sur ce continent, a derni\232rement mobilis\233[ENTER]tous les animaux autour de lui. La service de[ENTER]renseignements imp\233riale estime que c'est la[ENTER]cause de la folie des animaux. Il est vital de[ENTER]r\233duire le nombre de ces cr\233atures. \201liminez les[ENTER]bras droits du Tigre Jaune. "
gameforge.locale.questscroll5.mission_45_hunt = "Propri\233taire du mont Sohan? "
gameforge.locale.questscroll5.mission_45_mis = "Tuez 35 hommes de glace et 30 yetis. "
gameforge.locale.questscroll5.mission_45_text = "Le Renard \224 neuf-queues, ma\238tre du mont Sohan,[ENTER]est suspect\233 de rallier \224 sa cause de nombreux[ENTER]d\233mons. Avant que les effectifs ne soient trop[ENTER]importants, nous devons \233liminer les Hommes-glace[ENTER]et les Y\233tis, qui se trouvent \234tre l'\233pine[ENTER]dorsale de cette arm\233e. Aidez-nous et vous serez[ENTER]r\233compens\233. "
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki "
gameforge.locale.questscroll5.mission_46_mis = "Tuez 45 soldats grenouilles arboricoles et 35[ENTER]chefs grenouilles arboricoles. "
gameforge.locale.questscroll5.mission_46_text = "L'Esprit du Tigre Jaune est suspect\233 de comploter[ENTER]avec les monstres grenouilles arboricoles.[ENTER]\201liminez leurs forces conjointes. Si nous n'y[ENTER]prenons pas garde, ils risquent de causer de gros[ENTER]probl\232mes \224 l'empire. "
gameforge.locale.questscroll5.mission_47_hunt = "Les monstres des glaces! Leur vrai visage "
gameforge.locale.questscroll5.mission_47_mis = "D\233truisez 45 glaces enchant\233es "
gameforge.locale.questscroll5.mission_47_text = "Nous avons d\233couvert comment les monstres du Mont[ENTER]Sohan communiquent entre eux : avec l'aide des[ENTER]Glaces enchant\233es. Il est urgent d'affaiblir les[ENTER]troupes du Mont Sohan, tuez donc les Glaces[ENTER]enchant\233es. "
gameforge.locale.questscroll5.mission_48_hunt = "Le secret de la Tour des d\233mons "
gameforge.locale.questscroll5.mission_48_mis = "Tuez 45 vils lanciers d\233moniaques "
gameforge.locale.questscroll5.mission_48_text = "D'apr\232s certaines rumeurs, les vils lanciers[ENTER]d\233moniaques dans la Tour des d\233mons seraient[ENTER]invincibles. Ils se rel\232veraient des morts apr\232s[ENTER]avoir \233t\233 tu\233s. Si cette rumeur se confirme,[ENTER]alors funeste est notre avenir... Essayez d'en[ENTER]apprendre plus ! "
gameforge.locale.questscroll5.mission_49_hunt = "Les Ma\238tres de la Tour des d\233mons "
gameforge.locale.questscroll5.mission_49_mis = "Tuez 60 chamanes d\233mons. "
gameforge.locale.questscroll5.mission_49_text = "Des recherches approfondies nous ont permis de[ENTER]d\233couvrir que les soldats fant\244mes sont[ENTER]constamment ressuscit\233s. Nous devons \233liminer les[ENTER]Vils Chamanes D\233moniaques pour mettre fin \224 cela. "
gameforge.locale.questscroll5.mission_4_hunt = "Apparition des loups gris 1 "
gameforge.locale.questscroll5.mission_4_mis = "Tuez 35 loups gris "
gameforge.locale.questscroll5.mission_4_text = "Avez-vous entendu parler des loups gris? Pour la[ENTER]plupart ils errent sans but, mais ces derni\232res[ENTER]semaines sous l'influence du Chi mal\233fique ils[ENTER]ont commenc\233 \224 s'attaquer aux voyageurs[ENTER]imprudents. Est-il possible que vous \233liminiez[ENTER]ces loups gris? Vous serez r\233compens\233. "
gameforge.locale.questscroll5.mission_50_hunt = "Explorer Doyyumhwan "
gameforge.locale.questscroll5.mission_50_mis = "Tuez 45 tigres minions combattants "
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan est une zone volcanique peupl\233e de[ENTER]nombreuses b\234tes inconnues. Il nous faut explorer[ENTER]cette r\233gion. Pouvez-vous nous y aider? "
gameforge.locale.questscroll5.mission_51_hunt = "Esprit flamme ! Son identit\233 "
gameforge.locale.questscroll5.mission_51_mis = "Tuez 45 esprits flammes. "
gameforge.locale.questscroll5.mission_51_text = "Un groupe qui devait \233liminer les tigres de[ENTER]combat a \233t\233 an\233anti par des ennemis inconnus. La[ENTER]rumeur dit que ces ennemis avaient l'apparence de[ENTER]cr\233atures enflamm\233es. Aidez-nous \224 d\233couvrir la[ENTER]v\233rit\233. "
gameforge.locale.questscroll5.mission_52_hunt = "R\233duisez le nombre de tigres de combat "
gameforge.locale.questscroll5.mission_52_mis = "Tuez 60 tigres minions combattants et 40 tigres[ENTER]de combat. "
gameforge.locale.questscroll5.mission_52_text = "Maintenant que nous pouvons nous battre avec les[ENTER]monstres de feu, nous devons compl\232tement les[ENTER]\233liminer dans une grande bataille. L'arm\233e[ENTER]s'occupe d'habitude de ces missions, mais pour[ENTER]gagner nous avons besoin de techniques de combats[ENTER]plus efficaces.[ENTER]Assurez-vous s'il vous pla\238t que les Tigres de[ENTER]combat ne nous trouvent pas. "
gameforge.locale.questscroll5.mission_53_hunt = "\201tude des Flammes "
gameforge.locale.questscroll5.mission_53_mis = "Tuez 40 Flammes "
gameforge.locale.questscroll5.mission_53_text = "Les Flammes sont d'une brutalit\233 incroyable. Ils[ENTER]se repaissent de la souffrance de leurs victimes.[ENTER]Nous ne savons toujours pas comment les tuer.[ENTER]Pourriez-vous le d\233couvrir pour nous? "
gameforge.locale.questscroll5.mission_54_hunt = "Les guerriers flammes "
gameforge.locale.questscroll5.mission_54_mis = "Tuez 60 guerriers des flammes "
gameforge.locale.questscroll5.mission_54_text = "Il n'y a pas tr\232s longtemps un jeune noble qui[ENTER]s'\233tait aventur\233 dans le Doyyumhwan a \233t\233 tu\233 par[ENTER]un guerrier flamme. Si vous tuez les guerriers[ENTER]flamme vous serez r\233compens\233.[ENTER]Essayez de vous en occuper. "
gameforge.locale.questscroll5.mission_55_hunt = "Examinez les arbres fant\244mes "
gameforge.locale.questscroll5.mission_55_mis = "D\233truisez 30 arbres fant\244mes. "
gameforge.locale.questscroll5.mission_55_text = "En temps normal ils n'ont pas l'air diff\233rents[ENTER]des autres arbres \150 puis tout \224 coup ils[ENTER]attaquent animaux et \234tres humains. Leur nombre[ENTER]augmente. D\233couvrez comment nous pouvons d\233truire[ENTER]ces arbres fant\244mes. "
gameforge.locale.questscroll5.mission_56_hunt = "Le secret du Bois enchant\233 "
gameforge.locale.questscroll5.mission_56_mis = "Tuez 40 esprits de la souches et 30 dryades. "
gameforge.locale.questscroll5.mission_56_text = "Les recherches nous ont montr\233 que le Bois[ENTER]enchant\233 est peupl\233 d'esprits et de dryades. En[ENTER]les \233liminant nous pourrons stopper leur[ENTER]expansion. "
gameforge.locale.questscroll5.mission_5_hunt = "Soucis concernant les villages "
gameforge.locale.questscroll5.mission_5_mis = "Tuez 40 sangliers. "
gameforge.locale.questscroll5.mission_5_text = "Les probl\232mes des villages environnants n'ont[ENTER]fait qu'empirer ces derniers temps. Les[ENTER]sangliers, qui auparavant ne s'en prenaient[ENTER]qu'aux petits animaux des montagnes, deviennent[ENTER]soudainement agressifs.[ENTER]Ils saccagent les champs, et attaquent les[ENTER]fermiers. Pouvez-vous nous en d\233barrasser? "
gameforge.locale.questscroll5.mission_6_hunt = "\192 propos des Tigres et des Ours "
gameforge.locale.questscroll5.mission_6_mis = "Tuez 25 tigres et 30 ours "
gameforge.locale.questscroll5.mission_6_text = "Avez-vous entendu cette rumeur? Si les tigres et[ENTER]les ours ne mangent que de l'ail et des oignons[ENTER]pendant 100 jours ils peuvent se transformer en[ENTER]Tigres de Feu et en Grands Ours. Ce n'est[ENTER]probablement pas vrai mais ce serait bien de[ENTER]v\233rifier quand m\234me. Prouvez-le en tuant des[ENTER]tigres et des ours . Vous serez r\233compens\233. "
gameforge.locale.questscroll5.mission_7_hunt = "Brisez la Metin de Cupidit\233 "
gameforge.locale.questscroll5.mission_7_mis = "D\233truisez 2 Metins de Cupidit\233 "
gameforge.locale.questscroll5.mission_7_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_8_hunt = "D\233truisez la Metin de Bataille "
gameforge.locale.questscroll5.mission_8_mis = "D\233truisez 2 Metins de Bataille "
gameforge.locale.questscroll5.mission_8_text = "Depuis quelque temps, des pierres mal\233fiques sont[ENTER]tomb\233es en grande quantit\233 aux abords de la[ENTER]ville. Les recherches montrent que le chi de ces[ENTER]pierres rend les animaux fous. D\233truisez ces[ENTER]pierres, je vous en prie. Vous serez r\233compens\233 \224[ENTER]hauteur de vos efforts. "
gameforge.locale.questscroll5.mission_9_hunt = "Soucis concernant les villages 2 "
gameforge.locale.questscroll5.mission_9_mis = "Tuez 30 sangliers rouges. "
gameforge.locale.questscroll5.mission_9_text = "Cela fait un petit moment que les sangliers,[ENTER]men\233s par les sangliers rouges, attaquent les[ENTER]villages non loin de la ville. Le gouvernement a[ENTER]ordonn\233 l'extermination des sangliers rouges. Il[ENTER]est demand\233 \224 chaque guerrier de tuer 30[ENTER]sangliers rouges sauvages. S'il vous plait[ENTER]aidez-nous vous aussi. "
gameforge.locale.questscroll_10_hunt = "Les serpents \233p\233istes "
gameforge.locale.questscroll_10_mis = "Tuez les soldats mi hommes mi serpents. "
gameforge.locale.questscroll_10_text = "On ne peut les dire humains, mais ils ne sont pas[ENTER]non plus des animaux. Ils ont l'air humains mais[ENTER]leur t\234te, leur peau et leur comportement sont[ENTER]ceux de serpents venimeux. Ils vivent dans le[ENTER]d\233sert et attaquent les marchands ambulants.[ENTER][ENTER]Tuez 20 de ces cr\233atures mi hommes mi serpents.[ENTER]Si vous les tuez vous obtiendrez ceci en[ENTER]r\233compense: "
gameforge.locale.questscroll_11_hunt = "Les archers serpents "
gameforge.locale.questscroll_11_mis = "Tuez les archers mi hommes mi serpents. "
gameforge.locale.questscroll_11_text = "Leur intelligence est humaine. Ils sont sournois[ENTER]et savent utiliser des armes. Ce sont des[ENTER]archers, mi hommes mi serpents qui attaquent les[ENTER]marchands \224 distance. Beaucoup de marchands ont[ENTER]ainsi p\233ri. "
gameforge.locale.questscroll_12_hunt = "Hors la loi du D\233sert "
gameforge.locale.questscroll_12_mis = "Tuez les Hors la loi du D\233sert "
gameforge.locale.questscroll_12_text = "Il y a des \234tres mauvais dans le d\233sert de[ENTER]Yongbi. On les appelle les vagabonds du d\233sert et[ENTER]leurs crimes sont si haineux que les cieux en[ENTER]fr\233missent. Ils volent et tuent les marchands par[ENTER]plaisir. Ils ont aussi d\233truit tous les villages[ENTER]dans le d\233sert. "
gameforge.locale.questscroll_13_hunt = "Tigres de combat "
gameforge.locale.questscroll_13_mis = "Tuez les tigres de combat. "
gameforge.locale.questscroll_13_text = "Il existe des animaux appel\233s tigres de combat.[ENTER]Leur sang est fait de braises et leur corps de[ENTER]granit. Ces monstres poss\232dent une force[ENTER]incroyable et se nourrissent de lave et de feu.[ENTER]Parfois ils descendent du volcan, pour attaquer[ENTER]et d\233vorer les gens...[ENTER][ENTER]Tuez 20 de ces tigres de combat et quand ce sera[ENTER]fait vous obtiendrez ceci en r\233compense: "
gameforge.locale.questscroll_14_hunt = "Homme de guerre "
gameforge.locale.questscroll_14_mis = "Tuez l'homme de guerre "
gameforge.locale.questscroll_14_text = "Le Doyyumhwan est grand, chaud et recense un tas[ENTER]d'animaux sauvages. Ici, des guerriers de Chunjo,[ENTER]Jinno et Shinsoo se rencontrent. Des monstres[ENTER]terrifiants et puissants les attendent.[ENTER]Les Hommes de guerres sont de ceux qui contr\244lent[ENTER]le Doyyumhwan.[ENTER]Voulez-vous les affronter ? Si vous tuez 20[ENTER]Hommes de guerres, vous recevrez: "
gameforge.locale.questscroll_15_hunt = "Les guerriers Taehwa "
gameforge.locale.questscroll_15_mis = "D\233truisez les guerriers Taehwa "
gameforge.locale.questscroll_15_text = "\201coutez, vous qui pensez \234tre des guerriers[ENTER]puissants et redoutables\160! Voici le champ de[ENTER]bataille br\251lant du sang, des larmes et de la[ENTER]mort! Ici est ma demeure parmi les monstres et[ENTER]les criminels\160! Qui aura le courage de me[ENTER]d\233fier\160? Y en a-t-il un seul qui veuille[ENTER]m'affronter \224 l'\233p\233e\160?[ENTER]Si vous avez foi en vous-m\234me, venez me d\233fier\160![ENTER]Si vous arrivez \224 me battre ainsi que 12 de mes[ENTER]camarades vous recevrez la r\233compense suivante\160: "
gameforge.locale.questscroll_16_hunt = "Ours noir "
gameforge.locale.questscroll_16_mis = "Tuez les Ours noirs "
gameforge.locale.questscroll_16_text = "J'ai bien peur que ce soit la fin. Mais[ENTER]laisse-moi te dire des d\233tails sur un incident[ENTER]important... Quand tu liras cette lettre, je[ENTER]serais d\233j\224 mort ou disparu. J'ai v\233cu dans la[ENTER]vall\233e de Seungryong, o\249 j'ai collect\233 des[ENTER]plantes m\233dicinales. Mais des monstres appel\233s[ENTER]Ours noir ont commenc\233s \224 devenir fou. Ils ont[ENTER]tu\233s ma famille.[ENTER]S'il te pla\238t, venge ma famille et moi-m\234me. Si[ENTER]tu tues 25 Ours noirs, tu recevras: "
gameforge.locale.questscroll_17_hunt = "Ours noir g\233ant "
gameforge.locale.questscroll_17_mis = "Tuez les Ours noirs g\233ants "
gameforge.locale.questscroll_17_text = "Les ours ont cr\233\233s un nouveau monstre en[ENTER]s'accouplant avec des monstres encore plus[ENTER]malfaisants. Ils sont plus grands et forts que[ENTER]les Ours noir et sont terriblement vicieux. Aussi[ENTER]longtemps qu'ils seront dans la vall\233e de[ENTER]Seungryong, le peuple souffrira. Tues 20 Ours[ENTER]noir g\233ant. Si la mission est une r\233ussite, tu[ENTER]recevras : "
gameforge.locale.questscroll_18_hunt = "Les soldats atteints d'une maladie myst\233rieuse "
gameforge.locale.questscroll_18_mis = "Tuez les soldats atteints de la maladie[ENTER]myst\233rieuse "
gameforge.locale.questscroll_18_text = "Le village semble avoir \233t\233 ray\233 de la carte.[ENTER]Ceux qui souffrent de cette myst\233rieuse maladie[ENTER]attaquent ceux qui ont la malchance de passer par[ENTER]l\224. Ils s'attaquent aux colporteurs et se[ENTER]nourrissent de chair humaine. Ils sont[ENTER]extr\234mement dangereux.[ENTER][ENTER]Tuez 35 soldats souffrant de la maladie[ENTER]myst\233rieuse. Si vous r\233ussissez vous obtiendrez[ENTER]ceci en r\233compense: "
gameforge.locale.questscroll_19_hunt = "Les archers souffrants de la maladie myst\233rieuse "
gameforge.locale.questscroll_19_mis = "Tuez les archers souffrant de la maladie[ENTER]myst\233rieuse "
gameforge.locale.questscroll_19_text = "La maladie myst\233rieuse est la cause des m\233faits[ENTER]commis par ceux qui en sont atteints. Les plus[ENTER]dangereux sont les archers qui en sont atteints.[ENTER]Ils tirent des fl\232ches empoisonn\233es qui[ENTER]paralysent les voyageurs qui peuvent ainsi \234tre[ENTER]captur\233s.[ENTER]Tuez 25 archers atteints de la maladie[ENTER]myst\233rieuse. Si vous r\233ussissez, vous recevrez[ENTER]ceci en r\233compense: "
gameforge.locale.questscroll_1_hunt = "Ours maudit "
gameforge.locale.questscroll_1_mis = "Tuez 25 Ours maudits "
gameforge.locale.questscroll_1_text = "Les Ours de feu r\244dent souvent pr\232s des villes.[ENTER]Ils parcourent les prairies et les larges routes[ENTER]des humains. De plus en plus de gens en sont[ENTER]victimes. Beaucoup de personnes ont \233t\233 tu\233es.[ENTER][ENTER]Chassez ces ours de feu. D\232s que vous en aurez[ENTER]tu\233 25, vous recevrez la r\233compense suivante: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "Tuez 4 ennemis "
gameforge.locale.questscroll_20_text = "C'est fini pour moi. Ma vue se trouble d\233j\224...[ENTER]Quand vous lirez cette lettre mon corps sera d\233j\224[ENTER]d\233compos\233. Ces fils de chiens m'ont captur\233, j'ai[ENTER]r\233ussi \224 m'\233chapper mais ma blessure \233tait trop[ENTER]profonde et je n'ai pas pu continuer. Je ne vous[ENTER]connais pas mais je vous supplie de me venger![ENTER]Tuez 4 ennemis sur le lieu du combat. Si vous[ENTER]r\233ussissez, vous recevrez ceci en r\233compense: "
gameforge.locale.questscroll_2_hunt = "Grand tigre "
gameforge.locale.questscroll_2_mis = "Tuez 20 Grands tigres "
gameforge.locale.questscroll_2_text = "Le nom d'un mal est dans l'air : le Grand Tigre.[ENTER]Ces Tigres sont souvent aux abords de la[ENTER]capitale. Ils attaquent les gens et mangent les[ENTER]marchands. On ne compte plus leurs victimes.[ENTER][ENTER]Chassez les grands tigres. D\232s que vous en aurez[ENTER]tu\233 20, vous recevrez la r\233compense suivante: "
gameforge.locale.questscroll_3_hunt = "Le Dieu Chien de la montagne "
gameforge.locale.questscroll_3_mis = "Tuez le Dieu Chien de la montagne "
gameforge.locale.questscroll_3_text = "Le Dieu Chien de la montagne est \224 la t\234te d'une[ENTER]meute de chiens monstrueux dans les environs. Il[ENTER]est sauvage et puissant. Il n'y a pas longtemps[ENTER]qu'il est apparu dans les parages et a commenc\233 \224[ENTER]attaquer les marchands. Ce monstre a d\233j\224 caus\233[ENTER]beaucoup de morts, ses m\233faits ne peuvent plus[ENTER]\234tre laiss\233s impunis.[ENTER][ENTER]Tuez le Dieu Chien de la montagne. Si vous[ENTER]r\233ussissez, vous obtiendrez ceci en r\233compense: "
gameforge.locale.questscroll_4_hunt = "Le Dieu Porc "
gameforge.locale.questscroll_4_mis = "Tuez le Dieu Porc "
gameforge.locale.questscroll_4_text = "\192 cette \233poque de l'ann\233e, les champs sont pr\234ts[ENTER]\224 \234tre moissonn\233s mais le Dieu Cochon et ses[ENTER]compagnons d\233vorent tout le grain. Leur avidit\233[ENTER]est une menace pour les fermiers, nous devons les[ENTER]\233liminer.[ENTER][ENTER]Tuez le Dieu Cochon, il est d'habitude pr\232s de la[ENTER]ville principale. Si vous r\233ussissez vous[ENTER]obtiendrez ceci en r\233compense: "
gameforge.locale.questscroll_5_hunt = "Le Dieu Ours "
gameforge.locale.questscroll_5_mis = "Tuez le Dieu Ours "
gameforge.locale.questscroll_5_text = "Dans son environnement naturel, le Dieu Ours[ENTER]\233tait bon. Mais depuis quelque temps, il se[ENTER]trouve pr\232s de la capitale et attaque les[ENTER]passants. Il fait de plus en plus de victimes et[ENTER]il semble impossible de savoir combien de[ENTER]personnes sont d\233j\224 mortes. Il doit \234tre chass\233[ENTER]d'ici.[ENTER]Tuez le Dieu Ours. Si vous nous en d\233barrassez,[ENTER]vous recevrez ceci en r\233compense: "
gameforge.locale.questscroll_6_hunt = "Le Dieu Tigre "
gameforge.locale.questscroll_6_mis = "Tuez le Dieu Tigre "
gameforge.locale.questscroll_6_text = "Je n'arrive pas \224 croire que le Dieu Tigre ferait[ENTER]une chose pareille... Je suis juste une femme[ENTER]simple, et j'ai toujours honor\233 le Dieu Tigre qui[ENTER]apparaissait parfois sur le chemin de la[ENTER]montagne. Mais un jour, le Dieu Tigre et ses[ENTER]sbires ont attaqu\233 ma famille et les ont tous[ENTER]tu\233s! Et j'ai moi-m\234me perdu un bras.[ENTER][ENTER]Je vous en prie, vengez ma famille. Si vous tuez[ENTER]le Dieu Tigre, vous obtiendrez ceci en[ENTER]r\233compense: "
gameforge.locale.questscroll_7_hunt = "Leader du Serment Blanc "
gameforge.locale.questscroll_7_mis = "Tuez le leader du Serment Blanc "
gameforge.locale.questscroll_7_text = "Le Serment blanc est un groupe de femmes laiss\233es[ENTER]par leurs maris et maltrait\233es par le monde.[ENTER]Elles sont peut \234tre pauvres mais la fa\231on dont[ENTER]elles s'en prennent aux villageois est cruelle.[ENTER]Une femme fut tu\233e \224 coups de pierres[ENTER]lorsqu'elles vinrent au village. Nous ne pouvons[ENTER]pas leur permettre de revenir au village et[ENTER]d'attaquer les gens.[ENTER][ENTER]Tuez 20 chefs du Serment blanc. Si vous[ENTER]r\233ussissez cette mission, vous recevrez ceci en[ENTER]r\233compense: "
gameforge.locale.questscroll_8_hunt = "Chef du gang du Vent Noir "
gameforge.locale.questscroll_8_mis = "Tuez le chef du gang du vent noir "
gameforge.locale.questscroll_8_text = "Les voleurs du gang du vent noir hantent depuis[ENTER]longtemps les colporteurs. Ils sont si[ENTER]terrifiants que personne n'a jamais os\233 s'opposer[ENTER]\224 eux. Mais cela ne peut pas continuer, ils font[ENTER]v\233ritablement trop de ravages.[ENTER]Tuez 20 leaders du gang du Vent noir. Si vous y[ENTER]parvenez, vous recevrez ceci en r\233compense: "
gameforge.locale.questscroll_9_hunt = "Chefs Barbares "
gameforge.locale.questscroll_9_mis = "Tuez les chefs barbares "
gameforge.locale.questscroll_9_text = "Il y a quelque temps que les Barbares traversent[ENTER]les fronti\232res et attaquent le village. Leurs[ENTER]victimes se comptent par centaines, et ce nombre[ENTER]augmente sans cesse. Ces Barbares sont si brutaux[ENTER]que nul n'est parvenu \224 les arr\234ter. Mais nous ne[ENTER]pouvons plus continuer ainsi.[ENTER][ENTER]Tuez 25 Chefs Barbares. Si vous en sortez[ENTER]victorieux, il y aura une r\233compense pour vous: "
gameforge.locale.quest_temp_reward_1 = "R\233compense "
gameforge.locale.quest_temp_reward_2 = "Durant la p\233riode de test des qu\234tes, aucune[ENTER]r\233compense ne peut \234tre obtenue. Une fois la[ENTER]r\233compense re\231ue, la qu\234te peut \234tre de nouveau[ENTER]jou\233e. "
