gameforge.locale.skeleton_gem.order_say2 = "Le colporteur\160:[ENTER]Je vous en prie, aidez-moi. Si vous pouvez[ENTER]arracher la gemme du d\233mon+ des mains du magicien[ENTER]d\233mon, je vous r\233compenserai bien. "
gameforge.locale.skeleton_gem.order_too_late = "Le colporteur\160:[ENTER]Quelqu'un d'autre me l'a d\233j\224 apport\233e.[ENTER]Vous n'avez plus besoin de vous en occuper. "
gameforge.locale.skeleton_gem.start_find_peddler_label = "Allez voir le colporteur. "
gameforge.locale.skeleton_gem.start_find_peddler_text_1 = "Allez voir le colporteur. "
gameforge.locale.skeleton_gem.start_find_peddler_text_2 = "Allez voir le marchand ambulant et interrogez-le[ENTER]sur la gemme du d\233mon +. "
gameforge.locale.skeleton_gem.start_say = "La lettre du colporteur\160:[ENTER]Je ne sais plus quoi faire.[ENTER]On m'a vol\233 la gemme du d\233mon+ et comme j'avais[ENTER]donn\233 tout ce que je poss\233dais pour la payer je[ENTER]suis ruin\233...[ENTER]Pourriez-vous m'aider je vous en prie? J'ai[ENTER]vraiment besoin de votre aide. "
gameforge.locale.skeleton_gem.success_say = "Le marchand ambulant:[ENTER]Vous avez vraiment r\233ussi ? Dans mes bras ma[ENTER]pierre bien-aim\233e ! Je suis tellement soulag\233![ENTER]C'est fantastique! "
gameforge.locale.skeleton_gem.talk_about_skeleton_gem = "\192 propos de la Gemme du D\233mon + "
gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "Ce qui est \233crit sur le tract:[ENTER]Nous recrutons des hommes et des femmes courageux[ENTER]qui sont pr\234ts \224 se battre pour la paix de[ENTER]l'empire et de ses habitants![ENTER][ENTER]Pr\233requis pour s'enr\244ler dans l'arm\233e: niveau 5. "
gameforge.locale.skill_group.dialog_assassin_1 = "Ici nous entra\238nons les ninjas dans l'art de[ENTER]l'embuscade et du camouflage. Dagues et poisons[ENTER]sont les armes de pr\233dilection. Seuls les ninjas[ENTER]qui ont commenc\233 leur apprentissage et sont au[ENTER]niveau 5 ou plus \233lev\233 peuvent participer. Si[ENTER]vous atteignez un certain niveau dans votre[ENTER]entra\238nement, vous aurez la possibilit\233 de[ENTER]participer. Si vous \234tes pr\234t \224 rester cach\233[ENTER]parmi les ombres pour toujours en tant que Ninja[ENTER]venez me voir. Nous en reparlerons. "
gameforge.locale.skill_group.dialog_assassin_2 = "Ici nous entra\238nons les ninjas dans l'art de[ENTER]l'embuscade et du camouflage. Dagues et poisons[ENTER]sont les armes de pr\233dilection. Si vous \234tes pr\234t[ENTER]\224 rester cach\233 parmi les ombres pour toujours en[ENTER]tant que Ninja venez me voir. Nous combattrons[ENTER]c\244te \224 c\244te. tous ceux qui veulent se joindre \224[ENTER]nous sont les bienvenus. "
gameforge.locale.skill_group.dialog_assassin_3 = "Ici s'entra\238nent les Ninjas sp\233cialis\233s dans le[ENTER]Tir \224 l'arc. Ils apprennent des comp\233tences[ENTER]utiles pour l'utilisation de l'arc. Ils[ENTER]apprennent \224 envoyer des vol\233es de fl\232ches aux[ENTER]ennemis. Seuls les Ninjas en apprentissage et \224[ENTER]partir du niveau 5 peuvent participer. Si vous[ENTER]atteignez un certain niveau \224 l'entra\238nement vous[ENTER]vous verrez propos\233 un poste. Revenez me voir si[ENTER]vous \234tes int\233ress\233. "
gameforge.locale.skill_group.dialog_assassin_4 = "Ici s'entra\238nent les Ninjas sp\233cialis\233s dans le[ENTER]Tir \224 l'arc. Ils apprennent des comp\233tences[ENTER]utiles pour l'utilisation d'arc. Ils apprennent \224[ENTER]envoyer des vol\233es de fl\232ches bien dirig\233es sur[ENTER]les ennemis. Suivez-moi. Et je ferai de vous le[ENTER]meilleur archer de tout le continent. "
gameforge.locale.skill_group.dialog_assassin_5 = "Choisissez entre le combat au corps \224 corps et le[ENTER]combat mental, et vous gagnerez les comp\233tences[ENTER]en fonction de votre choix. "
gameforge.locale.skill_group.dialog_shaman_1 = "C'est ici que s'assemblent les Chamanes qui[ENTER]suivent la voie du Dieu Dragon. Ils apprennent[ENTER]l'usage des amulettes et des pouvoirs mentaux.[ENTER]Sous la protection du Dieu Dragon, ils peuvent[ENTER]contrer les attaques de leurs ennemis, augmenter[ENTER]leurs propres d\233fenses et soutenir leurs alli\233s.[ENTER]Seuls les Chamanes en apprentissage et ayant au[ENTER]moins le niveau 5 peuvent participer. Si vous[ENTER]continuez \224 vous entra\238ner s\233rieusement, vous[ENTER]pourrez \234tre recrut\233. Si vous \234tes pr\234t pour la[ENTER]Force du Dragon, venez me trouver. "
gameforge.locale.skill_group.dialog_shaman_2 = "C'est ici que s'assemblent les chamanes qui[ENTER]suivent la voie du Dieu Dragon. Ils apprennent[ENTER]l'usage des amulettes et des pouvoirs mentaux.[ENTER]Sous la protection du Dieu Dragon, ils peuvent[ENTER]contrer les attaques de leurs ennemis, augmenter[ENTER]leurs propres d\233fenses et soutenir leurs alli\233s.[ENTER]Pensez-vous \234tre pr\234t \224 r\233pandre l'enseignement[ENTER]du Dieu Dragon avec nous? Tous les croyants sont[ENTER]les bienvenus. "
gameforge.locale.skill_group.dialog_shaman_3 = "Les Chamanes viennent ici apprendre des Forces de[ENTER]la Nature et de la Lumi\232re. Ils \233tudient les[ENTER]comp\233tences en rapport avec la Lumi\232re, la Foudre[ENTER]et le Soin. Ils travaillent souvent en groupe[ENTER]pour s'aider les uns les autres. Les Chamanes en[ENTER]apprentissage et de niveau 5 peuvent participer.[ENTER]Vous n'avez pas encore les qualit\233s requises,[ENTER]vous devriez retourner vous entra\238ner. Je vous[ENTER]attendrai ici. "
gameforge.locale.skill_group.dialog_shaman_4 = "Les Chamanes viennent ici apprendre des Forces de[ENTER]la Nature et de la Lumi\232re. Ils \233tudient les[ENTER]comp\233tences en rapport avec la Lumi\232re, la Foudre[ENTER]et le Soin. Ils travaillent souvent en groupe[ENTER]pour s'aider les uns les autres. Voulez-vous[ENTER]aussi apporter votre aide \224 ceux qui en ont[ENTER]besoin? Toute aide est la bienvenue. "
gameforge.locale.skill_group.dialog_shaman_5 = "Choisissez entre la Voie du Dieu Dragon et le[ENTER]Soin, et vous obtiendrez les comp\233tences dont[ENTER]vous avez besoin. "
gameforge.locale.skill_group.dialog_sura_1 = "J'apprends aux gens \224 utiliser la magie qui a \233t\233[ENTER]implant\233e dans mon bras gauche par la graine du[ENTER]diable. J'enchante les armes et armures, augmente[ENTER]l'attaque et la d\233fense et invoque des Esprits[ENTER]des Enfers pour d\233moraliser les ennemis.[ENTER]Seuls les Sura en apprentissage et \224 partir du[ENTER]niveau 5 peuvent participer. Si vous atteignez un[ENTER]certain niveau \224 l'entra\238nement vous vous verrez[ENTER]invit\233 \224 participer. Si vous \234tes pr\234t \224 envo\251ter[ENTER]des \233p\233es de t\233n\232bres et invoquer des Esprits[ENTER]mal\233fiques. Rejoignez-moi. "
gameforge.locale.skill_group.dialog_sura_2 = "J'apprends aux gens \224 utiliser la magie qui a \233t\233[ENTER]implant\233e dans mon bras gauche par la graine du[ENTER]diable. J'enchante les armes et armures, augmente[ENTER]l'attaque et la d\233fense et invoque des Esprits[ENTER]des Enfers pour d\233moraliser les ennemis.[ENTER]\202tes-vous pr\234t \224 envo\251ter des \233p\233es de t\233n\232bres[ENTER]et invoquer des Esprits mal\233fiques? Je peux vous[ENTER]assurer qu'ici, votre puissance sera grandement[ENTER]augment\233e. "
gameforge.locale.skill_group.dialog_sura_3 = "Si vous \234tes int\233ress\233 par cet endroit, sachez[ENTER]qu'ici vous ne trouverez que ceux qui se sont[ENTER]enti\232rement vou\233s aux t\233n\232bres. Ils apprennent[ENTER]les comp\233tences li\233es aux flammes des enfers, aux[ENTER]Esprits et aux d\233mons. Seuls les Sura en[ENTER]apprentissage et \224 partir du niveau 5 peuvent[ENTER]participer Si vous atteignez un certain niveau \224[ENTER]l'entra\238nement vous vous verrez invit\233 \224 nous[ENTER]rejoindre. Si vous voulez vivre \224 jamais dans les[ENTER]t\233n\232bres, c'est ici que vous trouverez les[ENTER]r\233ponses \224 vos questions. "
gameforge.locale.skill_group.dialog_sura_4 = "Si vous \234tes int\233ress\233 par cet endroit, sachez[ENTER]qu'ici vous ne trouverez que ceux qui se sont[ENTER]enti\232rement vou\233s aux t\233n\232bres. Ils apprennent[ENTER]les comp\233tences li\233es aux flammes des enfers, aux[ENTER]Esprits et aux d\233mons. Si vous la compagnie des[ENTER]esprits mal\233fiques qui vous consumeront de[ENTER]l'int\233rieur ne vous effraie pas, venez. *rire[ENTER]sinistre*. Si vous nous rejoignez, laissez toute[ENTER]humanit\233 derri\232re vous. "
gameforge.locale.skill_group.dialog_sura_5 = "Choisissez entre la magie noire et l'enchantement[ENTER]d'armes et vous obtiendrez les comp\233tences[ENTER]d\233sir\233e. "
gameforge.locale.skill_group.dialog_warrior_1 = "Savez-vous o\249 vous \234tes\160? C'est ici que sont[ENTER]form\233s les combattants, des guerriers qui[ENTER]deviendront les plus forts et les plus rapides.[ENTER]Des techniques de rafales de coups et d'attaques[ENTER]concentr\233es y sont enseign\233es. Seuls les[ENTER]guerriers en apprentissage et \224 partir du niveau[ENTER]5 sont autoris\233s \224 les rejoindre. Quand vous[ENTER]aurez atteint ce niveau, vous recevrez un[ENTER]formulaire de recrutement. Si vous voulez[ENTER]d\233couvrir la vraie force de votre corps, je suis[ENTER]celui qu'il vous faut\160! "
gameforge.locale.skill_group.dialog_warrior_2 = "Savez-vous o\249 vous \234tes? Ici sont entra\238n\233s les[ENTER]combattants, les guerriers qui deviendront les[ENTER]plus forts et les plus rapides de toutes les[ENTER]unit\233s. Les techniques de rafales de coups et[ENTER]attaques concentr\233es sont enseign\233es. Vous allez[ENTER]subir un entra\238nement intensif au maniement de[ENTER]l'\233p\233e et de la lance. Alors, qu'en dites-vous?[ENTER]Pr\234t pour l'entra\238nement? "
gameforge.locale.skill_group.dialog_warrior_3 = "Ici les guerriers apprennent l'utilisation du[ENTER]Chi. Ils apprennent les techniques de combat[ENTER]mental et les r\233p\232tent inlassablement avec une[ENTER]totale concentration. L'entra\238nement est \233puisant[ENTER]mais ces attaques sont tr\232s puissantes et[ENTER]efficaces. Seuls les guerriers en apprentissage[ENTER]et \224 partir du niveau 5 sont autoris\233s \224[ENTER]participer. Revenez alors me voir si vous \234tes[ENTER]int\233ress\233. "
gameforge.locale.skill_group.dialog_warrior_4 = "Ici les guerriers apprennent l'utilisation du[ENTER]Chi. Ils apprennent les techniques de combat[ENTER]mental et les r\233p\232tent inlassablement avec une[ENTER]totale concentration. L'entra\238nement est \233puisant[ENTER]mais ces attaques sont tr\232s puissantes et[ENTER]efficaces. De votre assiduit\233 \224 l'entra\238nement[ENTER]d\233pendront les comp\233tences que vous utiliserez[ENTER]dans les combats. \202tes-vous int\233ress\233 par le[ENTER]combat mental? "
gameforge.locale.skill_group.dialog_warrior_5 = "Choisissez entre le combat au corps \224 corps et le[ENTER]combat mental et vous gagnerez les comp\233tences en[ENTER]fonction de votre choix. "
gameforge.locale.skill_group.invite = "Annonce de recrutement par l'arm\233e: "
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Annonce de recrutement de[ENTER]guerriers[/COLOR][ENTER]Si vous admirez les Guerriers pour leur vitesse[ENTER]et la puissance de leurs attaques, vous devriez[ENTER]apprendre le combat au corps \224 corps. Si vous[ENTER]voulez pouvoir tuer des groupes entiers de[ENTER]monstres en une seule attaque, apprenez Combat[ENTER]Mental.[ENTER][ENTER]Nous vous attendons sur la place de la ville. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Annonce de recrutement de[ENTER]ninjas[/COLOR][ENTER]Si vous voulez devenir un archer d'\233lite, vous[ENTER]devriez apprendre le combat \224 distance. Si vous[ENTER]pr\233f\233rez les missions secr\232tes dans les ombres[ENTER]nocturnes, le combat \224 mains nues est fait pour[ENTER]vous.[ENTER][ENTER]Nous vous attendons sur la place de la ville. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Annonce de recrutement de[ENTER]Sura[/COLOR][ENTER]Voulez-vous devenir un ma\238tre d'arme surhumain[ENTER]qui fera go\251ter ses ennemis \224 ses lames[ENTER]enchant\233es ? Alors apprenez l'art des armes[ENTER]magiques.[ENTER]Si par contre vous voulez inspirer la peur gr\226ce[ENTER]\224 vos talents de Magicien des t\233n\232bres et vos[ENTER]mal\233dictions apprenez l'art de la magie noire.[ENTER][ENTER]Nous vous attendons sur la place du village. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]Annonce de recrutement de[ENTER]chamanes[/COLOR][ENTER]Si vous voulez devenir un magicien qui contr\244le[ENTER]la magie du dieu Dragon et son souffle br\251lant,[ENTER]vous devriez apprendre La voie Du Dragon.[ENTER]Si vous voulez soulager les douleurs caus\233es par[ENTER]les blessures en r\233g\233n\233rant et soignantvos amis,[ENTER]vous devriez apprendre la voie des Soins.[ENTER][ENTER]Nous vous attendons sur la place du village. "
