gameforge.locale.stamina_food.butcher = {}
gameforge.locale.stamina_food.butcher.start_say = "Vieil homme dans le restaurant Suhpyung\160:[ENTER]Mon corps me trahit, je ne suis plus aussi[ENTER]vigoureux qu'avant. Dans ma jeunesse je pouvais[ENTER]travailler une semaine sans m'arr\234ter et faire la[ENTER]f\234te tous les soirs. Maintenant j'ai du mal \224 me[ENTER]tenir debout. C'est l\224 qu'on a envie d'un bon bol[ENTER]de soupe de grenouilles vertes pour restaurer son[ENTER]\233nergie. "
gameforge.locale.stamina_food.butcher.start_say2 = "Vieil homme dans le restaurant Suhpyung\160:[ENTER]Vous voulez savoir ce qu'est la soupe de[ENTER]grenouille verte ? Si vous en buvez un bol, vous[ENTER]ne serez plus du tout fatigu\233 ! Et m\234me si vous[ENTER]travaillez une semaine compl\232te dans les champs,[ENTER]vous aurez encore de l'\233nergie le soir ![ENTER]Un de mes amis, Oakgu, et le meilleur cuisinier[ENTER]que je connaisse lorsqu'il s'agit de soupe de[ENTER]grenouille verte. Mais pour je ne sais quelle[ENTER]raison, il ne fait plus de ce genre de soupe. "
gameforge.locale.stamina_food.butcher.talk = "Parler. "
gameforge.locale.stamina_food.complete_say = "Oakgu :[ENTER]C'est compris? Ne parlez jamais \224 personne de[ENTER]cette soupe de grenouille verte. Et certainement[ENTER]pas \224 ce bavard du restaurant Suhpyung! Il n'y en[ENTER]a pas beaucoup. Si tout le monde en entend parler[ENTER]ils voudront tous en manger et il n'y aura plus[ENTER]de viande de grenouille verte! "
