gameforge.locale.stash.enlarge_2_have_mark2 = "Il n'y a pas de symbole![ENTER]O\249 l'avez-vous perdu?[ENTER]Je d\233teste les menteurs![ENTER]Cherchez le symbole! "
gameforge.locale.stash.enlarge_2_have_mark3 = "Oh! La vieille dame vous a donn\233 sa b\233n\233diction![ENTER]Je vous l'avais bien dit! Vous avez tout pour[ENTER]devenir un h\233ros! Ne m'oubliez pas lorsque vous[ENTER]serez devenu c\233l\232bre![ENTER][ENTER]Je vais agrandir votre entrep\244t de 15 cases "
gameforge.locale.stash.enlarge_2_msg1 = "Vous voulez que je l'agrandisse encore? Ai-je[ENTER]l'air d'un philanthrope?[ENTER][ENTER]D'un autre c\244t\233 ... Vous avez l'air d'\234tre un[ENTER]h\233ros ... Hm ... "
gameforge.locale.stash.enlarge_2_msg2 = "\201coutez : je vais vous donner une lettre de[ENTER]recommandation, apportez-la \224 la vieille dame.[ENTER]Elle saura vous dire si l'\233nergie et la volont\233[ENTER]d'un h\233ros coulent dans vos veines. "
