gameforge.main_quest_flame_lv100 = {}
gameforge.main_quest_flame_lv100._010_sendLetter = "Mati\232re obscure "
gameforge.main_quest_flame_lv100._020_say = "Yak-Hwan vous demande. Allez le voir. "
gameforge.main_quest_flame_lv100._030_say = "Bienvenue. Yon-I-Walker a termin\233 ses recherches.[ENTER]Le ph\233nom\232ne que vous avez pu observer dans la[ENTER]Terre de Feu est appel\233 mati\232re obscure. "
gameforge.main_quest_flame_lv100._040_say = "Elle rayonne depuis les entrailles de la[ENTER]forteresse et m\233tamorphose les d\233mons des[ENTER]environs. Plus ils sont soumis longtemps \224 son[ENTER]influence, plus ils deviennent forts et[ENTER]agressifs.[ENTER]Nous devons emp\234cher la mati\232re obscure de se[ENTER]r\233pandre encore plus\160! "
gameforge.main_quest_flame_lv100._050_say = {}
gameforge.main_quest_flame_lv100._060_say = "Nous n'allons pas nous tourner les pouces pendant[ENTER]que l'alchimiste cherche une solution. Retournez[ENTER]dans la Terre de Feu et tuez 300 d\233mons dans les[ENTER]environs de la forteresse. "
gameforge.main_quest_flame_lv100._070_say = "Bien entendu. "
gameforge.main_quest_flame_lv100._080_say = "Merci. Et maintenant, d\233p\234chez-vous\160! "
gameforge.main_quest_flame_lv100._090_notice = "Tuez 300 d\233mons de la Terre de Feu aux alentours[ENTER]de la forteresse et \224 l'endroit o\249 vous avez[ENTER]trouv\233 les herbes solaires. "
gameforge.main_quest_flame_lv100._100_sayTitle = "D\228monenhatz "
gameforge.main_quest_flame_lv100._110_say = "Erledige 300 Feuerland-D\228monen in der N\228he der Festung und dem Fundort der Sonnenkr\228uter. "
gameforge.main_quest_flame_lv100._120_say = "Je crains que vous n'ayez pas encore tu\233 assez de[ENTER]d\233mons. Retournez dans la Terre de Feu et[ENTER]continuez le combat. "
gameforge.main_quest_flame_lv100._130_notice = "Vous avez tu\233 tous les d\233mons.[ENTER]Faites votre rapport \224 Yak-Hwan. "
gameforge.main_quest_flame_lv100._140_say = "Rendez visite \224 Yak-Hwan. "
gameforge.main_quest_flame_lv100._150_say = "Tr\232s bien, voil\224 qui devrait avoir ralenti la[ENTER]propagation de la mati\232re obscure. Reposez-vous[ENTER]pendant que je m'entretiens avec l'alchimiste. "
gameforge.main_quest_flame_lv100._160_sendLetter = "Teinture des nimbes "
gameforge.main_quest_flame_lv100._170_say = "L'alchimiste vous demande. Cela semble urgent\160! "
gameforge.main_quest_flame_lv100._180_say = "Une v\233ritable catastrophe\160! J'avais pourtant bien[ENTER]demand\233 \224 Yak-Hwan d'agir prudemment. Et que[ENTER]fait-il\160? Il nous pr\233cipite dans le chaos\160! La[ENTER]mati\232re obscure se propage plus vite lorsque[ENTER]p\233rit l'h\244te chez qui elle se tapit. Et[ENTER]j'apprends que vous avez d\233j\224 tu\233 300 d\233mons[ENTER]infect\233s\160! Ce n'est pas bien... "
gameforge.main_quest_flame_lv100._190_say = "Dans ces conditions, ma teinture des nimbes ne[ENTER]suffit naturellement plus \224 bannir la mati\232re[ENTER]obscure. Il me faut, de toute urgence, des[ENTER]ingr\233dients me permettant d'en fabriquer plus. "
gameforge.main_quest_flame_lv100._200_say = {}
gameforge.main_quest_flame_lv100._210_say = "Ramenez-moi 10 pierres de fondation, 50 biles[ENTER]d'ours, 10 glandes venin d'araign\233e et 200[ENTER]fragments d'\233nergie. J'imagine qu'il est inutile[ENTER]d'expliquer \224 un guerrier aguerri comme vous[ENTER]comment trouver tous ces ingr\233dients, n'est-ce[ENTER]pas\160? "
gameforge.main_quest_flame_lv100._220_say = "Je pars imm\233diatement. "
gameforge.main_quest_flame_lv100._230_say = "Parfait. D\233p\234chez-vous car chaque minute qui[ENTER]passe sans que nous n'entreprenions quoi que ce[ENTER]soit permet \224 la mati\232re obscure de se propager[ENTER]d'avantage. "
gameforge.main_quest_flame_lv100._240_notice = "Besorge die Zutaten, mit denen der Alchemist die Nimbustinktur herstellen kann. "
gameforge.main_quest_flame_lv100._250_say = "Verbleibende Zutaten "
gameforge.main_quest_flame_lv100._260_sayTitle = "Teinture des nimbes "
gameforge.main_quest_flame_lv100._270_say = "Procurez-vous 10 pierres de fondation, 50 biles[ENTER]d'ours, 10 glandes venin d'araign\233e et 200[ENTER]fragments d'\233nergie. Rapportez ces ingr\233dients \224[ENTER]l'alchimiste. "
gameforge.main_quest_flame_lv100._280_say = "Vous avez r\233cup\233r\233 tous les ingr\233dients\160![ENTER]Parfait, je vais pouvoir me mettre au travail. Je[ENTER]vous fais appeler sit\244t que la teinture des[ENTER]nimbes est pr\234te. "
gameforge.main_quest_flame_lv100._290_say = "Si nous n'arr\234tons pas bient\244t la mati\232re[ENTER]obscure, les cons\233quences s'annoncent fort[ENTER]sinistres.[ENTER]Allez, ramenez-moi les ingr\233dients pour la[ENTER]teinture des nimbes. "
gameforge.main_quest_flame_lv100._300_notice = "Vous avez r\233uni tous les ingr\233dients. Retournez[ENTER]voir l'alchimiste. "
gameforge.main_quest_flame_lv100._310_say = "Parlez \224 l'alchimiste. "
gameforge.main_quest_flame_lv100._320_sendLetter = "Arr\234ter la mati\232re obscure "
gameforge.main_quest_flame_lv100._330_say = "Quelle... pfff... Je me suis plaint aupr\232s du[ENTER]forgeron que les pierres de fondation \233taient[ENTER]moulues trop grossi\232rement. Et voil\224 qu'il est[ENTER]vex\233 et refuse de r\233duire en poudre le reste des[ENTER]pierres de fondation. Cette vieille t\234te de[ENTER]mule\160![ENTER]Pourriez-vous aller lui parler\160? "
gameforge.main_quest_flame_lv100._340_say = "Bien s\251r. "
gameforge.main_quest_flame_lv100._350_say = "Merci. Apportez-lui donc ce panier de victuailles[ENTER]en guise d'excuse et persuadez-le de continuer \224[ENTER]moudre finement les pierres de fondation. "
gameforge.main_quest_flame_lv100._360_sayTitle = "Apaiser le forgeron "
gameforge.main_quest_flame_lv100._370_say = "Apaisez le forgeron et persuadez-le de moudre les[ENTER]pierres de fondation en une poudre fine. "
gameforge.main_quest_flame_lv100._380_say = "Poudre de pierre de fondation\160: 1 sachet "
gameforge.main_quest_flame_lv100._390_say = "Que puis-je faire pour vous\160? Aff\251ter votre \233p\233e\160?Polir votre armure\160? "
gameforge.main_quest_flame_lv100._400_say = "Non, pas aujourd'hui. Je suis venu car[ENTER]l'alchimiste souhaite demander pardon pour ses[ENTER]mots durs. Il vous envoie ce panier de[ENTER]victuailles. "
gameforge.main_quest_flame_lv100._410_say = "Aider cet ingrat personnage me r\233pugne. Mais[ENTER]puisque c'est vous qui le demandez, je vais[ENTER]continuer \224 moudre les pierres de fondations.[ENTER]Attendez un instant. "
gameforge.main_quest_flame_lv100._420_say = "Je vous remercie. "
gameforge.main_quest_flame_lv100._430_say = "Le forgeron s'ent\234te-t-il\160? Donnez-lui le panier[ENTER]et demandez-lui de l'aide. Si c'est vous qui[ENTER]demandez, il ne pourra pas refuser. "
gameforge.main_quest_flame_lv100._440_notice = "La poudre de pierres de fondation est pr\234te.[ENTER]Ramenez-la \224 l'alchimiste. "
gameforge.main_quest_flame_lv100._450_say = "Oh, fein wie Babypuder, ausgezeichnet! Der alte Sturkopf kann es also doch, hehe. Nun kann ich die Nimbustinktur mischen. Ruhe dich etwas aus. Ich werde dich rufen, wenn sie fertig ist. "
gameforge.main_quest_flame_lv101 = {}
gameforge.main_quest_flame_lv101._010_sendLetter = "Forteresse myst\233rieuse "
gameforge.main_quest_flame_lv101._020_say = "Yak-Hwan vous demande. Allez le voir et d\233couvrez[ENTER]ce qu'il vous veut. "
gameforge.main_quest_flame_lv101._030_say = "L'alchimiste m'a inform\233 de l'erreur monumentale[ENTER]que j'ai commise. J'esp\232re qu'il n'est pas trop[ENTER]tard pour la r\233parer. "
gameforge.main_quest_flame_lv101._040_say = "Je vais enduire votre arme de teinture des nimbes.D\233sormais, lorsque vous tuerez des d\233mons[ENTER]infect\233s, la mati\232re obscure qu'ils renferment[ENTER]sera exorcis\233e et ne pourra plus se propager. "
gameforge.main_quest_flame_lv101._050_say = "Vous pouvez maintenant vous risquer dans[ENTER]l'enceinte de la forteresse myst\233rieuse. Vous[ENTER]poss\233dez d\233j\224 le ticket n\233cessaire pour y entrer.[ENTER]Peut-\234tre y d\233couvrirez un indice sur les[ENTER]agissements des serviteurs de l'Obscurit\233 et sur[ENTER]ce qu'il est advenu de mon \233claireur. "
gameforge.main_quest_flame_lv101._060_say = {}
gameforge.main_quest_flame_lv101._070_say = "Je me mets tout de suite en route. "
gameforge.main_quest_flame_lv101._080_say = "Danke. Ich w\252nsche dir das Beste. "
gameforge.main_quest_flame_lv101._090_notice = "Introduisez-vous dans la forteresse et combattez[ENTER]les d\233mons que vous y trouverez.[ENTER]Soyez \224 l'aff\251t d'indices importants ainsi que de[ENTER]l\146\233claireur disparu. "
gameforge.main_quest_flame_lv101._100_sayTitle = "Festung erkunden "
gameforge.main_quest_flame_lv101._110_say = "Introduisez-vous dans la forteresse et combattez[ENTER]les d\233mons que vous y trouverez.[ENTER]Recherchez l'\233claireur disparu ainsi que des[ENTER]indices sur les agissements des serviteurs. "
gameforge.main_quest_flame_lv101._120_sayReward = "Du kannst diesen Dungeon nicht alleine betreten. Bilde eine Gruppe, um passieren zu d\252rfen. Du erh\228ltst keinen weiteren Passierschein. "
gameforge.main_quest_flame_lv101._130_say = "Avez-vous d\233j\224 \233t\233 dans l'enceinte de la[ENTER]forteresse\160? Il doit \234tre possible d'y trouver[ENTER]des indices sur les agissements des serviteurs de[ENTER]l'obscurit\233 ainsi que sur ce qu'il est advenu de[ENTER]mon \233claireur. Retournez dans la Terre de Feu et[ENTER]explorez la forteresse. "
gameforge.main_quest_flame_lv101._140_say = "Der Sp\228her ist schon eine Weile tot. In seiner Tasche findest du einen Brief. \220berbringe ihn Yak-Hwan. "
gameforge.main_quest_flame_lv101._150_notice = "Vous avez d\233couvert l'\233claireur de Yak-Hwan. "
gameforge.main_quest_flame_lv101._160_say = "Hast du Neuigkeiten? "
gameforge.main_quest_flame_lv101._170_say = {}
gameforge.main_quest_flame_lv101._180_say = "Et elles ne sont pas bonnes, si j'en crois votre[ENTER]mine d\233faite... c'est bien ce que je craignais.[ENTER]Il portant une lettre\160? Montrez-moi \231a\160! La[ENTER]forteresse doit \233galement abriter des indices sur[ENTER]les agissements de serviteurs de l'Obscurit\233.[ENTER]Retournez-y et cherchez-en. Nous lirons cette[ENTER]lettre plus tard. "
gameforge.main_quest_flame_lv101._190_notice = "Vous avez d\233couvert un collier clout\233 des[ENTER]serviteurs de l'Obscurit\233. Montrez-le \224 Yak-Hwan. "
gameforge.main_quest_flame_lv101._200_say = "C'est int\233ressant. Ce collier clout\233 appartient[ENTER]aux serviteurs de l'Obscurit\233. Peut-\234tre[ENTER]contient-il des indices sur leurs agissements\160![ENTER]Et toujours aucune trace de mon \233claireur\160? Je[ENTER]vous en prie, continuez \224 le chercher. Il doit se[ENTER]trouver dans la forteresse. "
gameforge.main_quest_flame_lv101._210_notice = "Vous avez d\233couvert un collier clout\233 ainsi que[ENTER]l'\233claireur. Allez faire votre rapport \224[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv101._220_say = "Informez Yak-Hwan. "
gameforge.main_quest_flame_lv101._230_say = "Ainsi, vous avez r\233ussi\160! Ce collier clout\233[ENTER]appartient aux serviteurs de l'Obscurit\233. Il[ENTER]contient sans doute un indice sur leurs projets.[ENTER]Et qu'est-ce que vous avez l\224\160? Une lettre\160?[ENTER]Montrez-moi \231a\160! "
gameforge.main_quest_flame_lv101._240_say = {}
gameforge.main_quest_flame_lv101._250_say = "Ein Brief ... den mir mein Sp\228her hinterlassen hat? Ich bin ersch\252ttert. Lass uns gemeinsam seine letzten Worte lesen. "
gameforge.main_quest_flame_lv101._260_sayTitle = "Mots griffonn\233s \224 la h\226te\160: "
gameforge.main_quest_flame_lv101._270_say = "Yak-Hwan, je me fais aucune illusion sur mes[ENTER]chances de rentrer vivant, mais j\146esp\232re que[ENTER]cette lettre vous parviendra. Lors de mon[ENTER]exploration de la Terre de Feu, je suis tomb\233 sur[ENTER]une forteresse dont aucune carte ne fait mention.[ENTER]Son ma\238tre est un puissant d\233mon de la Terre de[ENTER]Feu et il est envelopp\233 par une aura \233trange, de[ENTER]m\234me que tous les d\233mons sous ses ordres.[ENTER]Ses hurlements sont assourdissants et il semble[ENTER]prot\233ger quelque chose. Malheureusement, je n'ai[ENTER]pas r\233ussi \224 d\233couvrir de quoi il s'agit.[ENTER]Veuillez pardonner cet \233chec... "
gameforge.main_quest_flame_lv101._280_say = "Il nous faut d\233couvrir ce que cette forteresse[ENTER]abrite.[ENTER]Regardez, une inscription est grav\233e sur la paroi[ENTER]int\233rieure du collier. Je vais demander conseil \224[ENTER]Yon-I-Walker. Il vous fera appeler sit\244t qu'il[ENTER]aura besoin de votre aide. "
gameforge.main_quest_flame_lv101._290_sendLetter = "Gravur entschl\252sseln "
gameforge.main_quest_flame_lv101._300_say = "Yon-I-Walker vous demande. Allez le voir. "
gameforge.main_quest_flame_lv101._310_say = "Willkommen, ich habe dich bereits erwartet. Ich brauche etwas Hilfe dabei, die Gravur in diesem Nietenhalsband zu entschl\252sseln. "
gameforge.main_quest_flame_lv101._320_say = {}
gameforge.main_quest_flame_lv101._330_say = "Les caract\232res recouvrant la paroi int\233rieure du[ENTER]collier clout\233 proviennent d'une culture antique,[ENTER]ayant prosp\233r\233 il y a bien longtemps. Afin de la[ENTER]d\233chiffrer, j'ai besoin de sang du roi flamme.[ENTER]C'est un v\233ritable torrent de lave qui coule dans[ENTER]les veines de ce d\233mon\160! "
gameforge.main_quest_flame_lv101._340_say = "Je m'en occupe. "
gameforge.main_quest_flame_lv101._350_say = "Wenn du das Blut erhalten hast, musst du so schnell wie m\246glich zu mir zur\252ckkehren. Denn selbst dieses Gef\228\223 kann seine Hitze nur f\252r eine begrenzte Zeit ohne Schaden \252berstehen. "
gameforge.main_quest_flame_lv101._360_notice = "R\233cup\233rez le sang du roi flamme. "
gameforge.main_quest_flame_lv101._370_say = "Sans la moindre goutte de sang du roi flamme, il[ENTER]nous est impossible de d\233chiffrer l'inscription. "
gameforge.main_quest_flame_lv101._380_notice = "Vous avez obtenu le sang du roi flamme. Retournez[ENTER]voir Yon-I-Walker. "
gameforge.main_quest_flame_lv101._390_say = "Parlez \224 Yon-I-Walker. "
gameforge.main_quest_flame_lv101._400_say = "Ah, tr\232s bien. Ce sang va me permettre de[ENTER]d\233chiffrer l'inscription. Toutefois, cela va[ENTER]prendre un peu de temps. Revenez demain. "
gameforge.main_quest_flame_lv101._410_say = "Patientez encore %d heure(s) et %d minute(s). "
gameforge.main_quest_flame_lv101._420_say = "Il me faut encore un peu de temps. Revenez plus[ENTER]tard\160! "
gameforge.main_quest_flame_lv101._430_sendLetter = "L'inscription "
gameforge.main_quest_flame_lv101._440_say = "Vous arrivez au bon moment\160! J'ai r\233ussi \224[ENTER]d\233chiffrer l'inscription du collier clout\233. "
gameforge.main_quest_flame_lv101._450_say = "Sie verr\228t uns, dass die Diener der Dunkelheit einen der m\228chtigesten Feuerd\228monen entsandt haben, um die Siegel der Tore zu schmelzen, hinter denen die Sechs Drachen an einem verborgenen Ort gefangen gehalten werden. Es wird auch ein spezieller Schmelzofen erw\228hnt. Ich habe alles in diesem Schreiben an Yak-Hwan festgehalten. Bringe es bitte zu ihm! "
gameforge.main_quest_flame_lv101._460_say = {}
gameforge.main_quest_flame_lv101._470_notice = "\220berbringe Yak-Hwan den Brief von Yon-I-Walker. "
gameforge.main_quest_flame_lv101._480_sayTitle = "Post f\252r Yak-Hwan "
gameforge.main_quest_flame_lv101._490_say = "\220berbringe Yak-Hwan den Brief von Yon-I-Walker. "
gameforge.main_quest_flame_lv101._500_say = "Konnte Yon-I-Walker die Gravur lesen? Oh, ein Brief mit allen Informationen von ihm? Sehr gut, zeig her! "
gameforge.main_quest_flame_lv101._510_say = "Le sceau des grands dragons... Aha\160! La[ENTER]forteresse que nous avons d\233couverte doit donc[ENTER]\234tre la l\233gendaire forteresse du dragon rouge\160![ENTER]La l\233gende veut qu'elle serve de prison \224 un des[ENTER]dragons que les serviteurs doivent tuer afin[ENTER]d'obtenir des perles nocturnes. Tenez, prenez ce[ENTER]ticket et prenez-en soin. Vous allez bient\244t en[ENTER]avoir besoin... "
gameforge.main_quest_flame_lv101._520_say = "T\246te den Flammenk\246nig und fange sein brennendes Blut auf. "
gameforge.main_quest_flame_lv101._530_say = {}
gameforge.main_quest_flame_lv102 = {}
gameforge.main_quest_flame_lv102._010_sendLetter = "Assaut de la forteresse "
gameforge.main_quest_flame_lv102._020_say = "Yak-Hwan vous demande. Il souhaite vous instruire[ENTER]de la suite \224 donner aux \233v\232nements. "
gameforge.main_quest_flame_lv102._030_say = "Nous avons barricad\233 la forteresse du dragon[ENTER]rouge. Ainsi, aucun d\233mon infect\233 ne peut plus en[ENTER]sortir, ce qui entrave la propagation de la[ENTER]mati\232re obscure. "
gameforge.main_quest_flame_lv102._040_say = "Deine Aufgabe wird es nun sein, in die Festung einzufallen, so viele D\228monen wie m\246glich unsch\228dlich zu machen und herauszufinden, ob darin tats\228chlich der legend\228re Rotdrache gefangen ist. "
gameforge.main_quest_flame_lv102._050_say = "D'accord. "
gameforge.main_quest_flame_lv102._060_say = "Erledige 30 D\228monen und bringe mir als Beweis daf\252r ihre D\228monenkrallen. "
gameforge.main_quest_flame_lv102._070_notice = "Erledige 30 D\228monen und bringe Yak-Hwan als Beweis ihre D\228monenkrallen. "
gameforge.main_quest_flame_lv102._080_sayTitle = "Prenez la forteresse du dragon rouge d'assaut\160! "
gameforge.main_quest_flame_lv102._090_say = "Besiege 30 D\228monen in der Rotdrachenfestung und bringe Yak-Hwan ihre D\228monenkrallen als Beweis. "
gameforge.main_quest_flame_lv102._100_say = "%s : %d unit\233s[ENTER]%s : %d unit\233s "
gameforge.main_quest_flame_lv102._110_say = "%s : %d[ENTER]%s : %d[ENTER]%s : %d "
gameforge.main_quest_flame_lv102._120_say = "Du hast noch nicht gen\252gend D\228monen besiegt. Erledige insgesamt 30 St\252ck und bringe mir ihre D\228monenkrallen als Beweis! "
gameforge.main_quest_flame_lv102._130_notice = "Vous avez terrass\233 tous les d\233mons flamme ardents.[ENTER]Allez faire votre rapport \224 Yak-Hwan. "
gameforge.main_quest_flame_lv102._140_say = "Allez voir Yon-I-Walker. "
gameforge.main_quest_flame_lv102._150_say = "Vous voil\224 de retour et je vois que vous avez[ENTER]triomph\233\160! Qu'avez-vous d'autre \224 me[ENTER]communiquer\160? "
gameforge.main_quest_flame_lv102._160_say = {}
gameforge.main_quest_flame_lv102._170_say = "Un d\233mon flamme puissant, vous dites\160? Il s'agit[ENTER]de Razador, le ma\238tre du feu\160! Si les serviteurs[ENTER]l'ont envoy\233 lui, c'est que quelque chose de[ENTER]pr\233cieux doit se trouver dans la forteresse. Il[ENTER]s'agit peut-\234tre du l\233gendaire dragon rouge\160! Je[ENTER]vais commencer par m'entretenir avec mes[ENTER]conseillers. En attendant, prenez ce ticket et ne[ENTER]le perdez pas. Vous allez en avoir besoin plus[ENTER]tard. "
gameforge.main_quest_flame_lv102._180_sendLetter = "Razador "
gameforge.main_quest_flame_lv102._190_say = "Yon-I-Walker vous cherche. Allez le voir afin[ENTER]d'en savoir plus. "
gameforge.main_quest_flame_lv102._200_say = "Ainsi, vous avez surv\233cu \224 une rencontre avec le[ENTER]terrible Razador. Je m'incline devant tant de[ENTER]vaillance\160! "
gameforge.main_quest_flame_lv102._210_say = {}
gameforge.main_quest_flame_lv102._220_say = "Le ma\238tre du feu est, avec le roi du gel Alastor,[ENTER]une des cr\233atures infernales les plus[ENTER]malfaisantes et meurtri\232res que l'humanit\233 ait[ENTER]jamais connu.[ENTER]Il est m\234me probable que Razador lui-m\234me soit la[ENTER]source de la mati\232re obscure. "
gameforge.main_quest_flame_lv102._230_say = {}
gameforge.main_quest_flame_lv102._240_say = {}
gameforge.main_quest_flame_lv102._250_say = "Cela en fait un adversaire surpuissant. Commencez[ENTER]par occire les d\233mons subalternes de la[ENTER]forteresse du dragon rouge et r\233coltez la mati\232re[ENTER]noire de leur d\233pouille. Dix fragments devraient[ENTER]suffire.[ENTER]Peut-\234tre arriverons-nous ainsi \224 trouver un[ENTER]moyen de neutraliser sa force, avant d'affronter[ENTER]Razador. "
gameforge.main_quest_flame_lv102._260_say = "Je pars imm\233diatement. "
gameforge.main_quest_flame_lv102._270_notice = "Affrontez les d\233mons flamme ardents dans[ENTER]l'enceinte de la forteresse du dragon rouge. "
gameforge.main_quest_flame_lv102._280_sayTitle = "Materie-Kugeln "
gameforge.main_quest_flame_lv102._290_say = "Prenez la forteresse du dragon rouge d'assaut,[ENTER]combattez les d\233mons flamme ardents et r\233coltez[ENTER]10 unit\233s de mati\232re obscure. "
gameforge.main_quest_flame_lv102._300_sayReward = "Pour pouvoir entrer dans la forteresse du dragon[ENTER]rouge, vous devez \234tre muni d'un ticket et faire[ENTER]partie d'un groupe. "
gameforge.main_quest_flame_lv102._310_say = "Cela ne suffit pas encore. J'ai besoin de dix[ENTER]unit\233s de mati\232re noire afin de mener mes[ENTER]recherches \224 bien. "
gameforge.main_quest_flame_lv102._320_notice = "Vous avez r\233colt\233 10 fragments de mati\232re obscure.[ENTER]Rapportez-les \224 Yon-I-Walker. "
gameforge.main_quest_flame_lv102._330_say = "La simple vue de la mati\232re obscure me remplit[ENTER]d'effroi\160! Allons, au travail... Je vous fais[ENTER]appeler si les r\233sultats sont concluants. "
gameforge.main_quest_flame_lv102._340_say = {}
gameforge.main_quest_flame_lv102._350_sendLetter = "Neutralisation de la mati\232re obscure "
gameforge.main_quest_flame_lv102._360_say = "Bonne nouvelle\160! J'ai d\233couvert comment[ENTER]neutraliser la force de la mati\232re obscure. "
gameforge.main_quest_flame_lv102._370_say = {}
gameforge.main_quest_flame_lv102._380_say = "Toutes les forces de la nature ont un contrepoids.La lumi\232re et l'ombre, l'eau et le feu, le bien[ENTER]et le mal. La mati\232re obscure n'\233chappe pas \224[ENTER]cette r\232gle et elle a son pendant lumineux,[ENTER]capable de la neutraliser : le Lumen pur\160! "
gameforge.main_quest_flame_lv102._390_say = "Afin de produire du Lumen pur, il faut faire[ENTER]fondre des fragments d'\233nergie dans de l'eau de[ENTER]Mong. Pouvez-vous aller chercher 50 bouteilles[ENTER]d'eau de Mong ainsi que 100 fragments d'\233nergie,[ENTER]puis les rapporter \224 Yu-Hwan\160? Merci. "
gameforge.main_quest_flame_lv102._400_say = "C'est comme si c'\233tait fait. "
gameforge.main_quest_flame_lv102._410_notice = "Rassemblez 50 bouteilles d'eau de Mong ainsi que[ENTER]100 fragments d'\233nergie et rapportez tout cela \224[ENTER]Yu-Hwan. "
gameforge.main_quest_flame_lv102._420_sayTitle = "Lumen pur "
gameforge.main_quest_flame_lv102._430_say = "Rassemblez 50 bouteilles d'eau de Mong ainsi que[ENTER]100 fragments d'\233nergie et rapportez tout cela \224[ENTER]Yu-Hwan. "
gameforge.main_quest_flame_lv102._440_say = "Ah, Yon-I-Walker m'a d\233j\224 pr\233venu de votre venue.[ENTER]Bon, je vais me mettre au travail imm\233diatement.[ENTER]Pourquoi n'en profiteriez-vous pas pour prendre[ENTER]un peu de repos\160? "
gameforge.main_quest_flame_lv102._450_say = "Ah, Yon-I-Walker m'a d\233j\224 pr\233venu de votre venue.[ENTER]Je me mettrais bien volontiers au travail, mais[ENTER]il n'y a pas l\224 suffisamment d'ingr\233dients pour[ENTER]confectionner du Lumen pur. Remettez-vous en[ENTER]route et continuez la r\233colte. "
gameforge.main_quest_flame_lv102._460_notice = "Vous avez rassembl\233 suffisamment d'eau de Mong et[ENTER]de fragments d'\233nergie. Rapportez-les \224 Yu-Hwan. "
gameforge.main_quest_flame_lv102._470_say = "Allez voir Yu-Hwan. "
gameforge.main_quest_flame_lv102._480_sendLetter = "Transmettre le Lumen pur "
gameforge.main_quest_flame_lv102._490_say = "Yu-Hwan a confectionn\233 le Lumen pur. Allez le[ENTER]voir. "
gameforge.main_quest_flame_lv102._500_say = "Vous voil\224\160! Pile au bout moment. Nous venons[ENTER]tout juste d'en terminer avec la confection du[ENTER]Lumen pur. Allez en informer Yak-Hwan. "
gameforge.main_quest_flame_lv102._510_say = {}
gameforge.main_quest_flame_lv102._520_say = {}
gameforge.main_quest_flame_lv102._530_say = {}
gameforge.main_quest_flame_lv102._540_notice = "Kehre mit dem Reinen Lumen zu Yak-Hwan zur\252ck. "
gameforge.main_quest_flame_lv102._550_say = "Du bist noch hier? Es eilt sehr! Bringe das Reine Lumen zu Yak-Hwan. "
gameforge.main_quest_flame_lv102._560_say = "Ah, willkommen! Du hast das Reine Lumen bei dir? Phantastisch! "
gameforge.main_quest_flame_lv102._570_say = {}
gameforge.main_quest_flame_lv102._580_say = "Impressionnant. Nous avons maintenant un atout[ENTER]dans la manche pour notre assaut sur la[ENTER]forteresse du dragon rouge. Reposez-vous un peu,[ENTER]pendant que je rassemble mes troupes. "
gameforge.main_quest_flame_lv103 = {}
gameforge.main_quest_flame_lv103._010_sendLetter = "Assaut de la forteresse "
gameforge.main_quest_flame_lv103._020_say = "Yak-Hwan vous fait appeler. Il tient \224 vous[ENTER]donner les derni\232res consignes avant que vous ne[ENTER]vous lanciez dans la bataille. "
gameforge.main_quest_flame_lv103._030_say = "L'heure a sonn\233. La bataille a commenc\233. J'ai[ENTER]envoy\233 un bataillon \224 l'assaut de la forteresse[ENTER]du dragon rouge. Tous les soldats sont \233quip\233s de[ENTER]Lumen pur. Les effets du Lumen sont[ENTER]extraordinaires\160: leur esprit est aff\251t\233 comme[ENTER]une lame. "
gameforge.main_quest_flame_lv103._040_say = "Folge ihnen und treffe sie in der Rotdrachenfestung! Suche nach dem Kommandanten. Er wird dich in den Angriffsplan einweihen. "
gameforge.main_quest_flame_lv103._060_say = "Soyez sur vos gardes ! "
gameforge.main_quest_flame_lv103._070_notice = "Folge dem Angriffstrupp in die Rotdrachenfestung und suche nach dem Kommandanten. "
gameforge.main_quest_flame_lv103._080_sayTitle = "En route vers la forteresse\160! "
gameforge.main_quest_flame_lv103._090_say = "Folge dem Angriffstrupp in die Rotdrachenfestung und suche nach dem Kommandanten. "
gameforge.main_quest_flame_lv103._100_say = "Vous \234tes encore ici\160? Allons, suivez mes hommes[ENTER]jusqu'\224 la forteresse du dragon rouge\160! "
gameforge.main_quest_flame_lv103._110_say = "Gut, dass du hier bist. Wir wurden entdeckt und mussten die Festung fr\252her als geplant st\252rmen. Zuerst lief es gut, doch dann ... gegen Razador waren wir chancenlos \150 das ganze Bataillon ist gefallen. Ich bin der letzte. Kannst du Yak-Hwan Bericht erstatten? Danke. "
gameforge.main_quest_flame_lv103._120_say = "Informez Yak-Hwan des \233v\232nements de la forteresse[ENTER]du dragon rouge. "
gameforge.main_quest_flame_lv103._130_say = "Vous \234tes d\233j\224 de retour\160? Comment...[ENTER]quelque chose a mal tourn\233\160? Racontez\160! "
gameforge.main_quest_flame_lv103._140_say = {}
gameforge.main_quest_flame_lv103._150_say = "Le bataillon entier a \233t\233 d\233cim\233\160? Quelle[ENTER]trag\233die... et c'est de ma faute\160! L'assaut n'a[ENTER]pas \233t\233 suffisamment pens\233 et mes hommes ont pay\233[ENTER]le prix ultime. "
gameforge.main_quest_flame_lv103._160_say = {}
gameforge.main_quest_flame_lv103._170_say = "Il me faut revoir toute ma strat\233gie. Il doit y[ENTER]avoir un autre moyen d'\233liminer ces d\233mons.[ENTER]Tenez-vous pr\234t. Je vous fais appeler sit\244t que[ENTER]nous avons \233labor\233 notre nouveau plan. "
gameforge.main_quest_flame_lv103._180_sendLetter = "\201tape par \233tape "
gameforge.main_quest_flame_lv103._190_say = "Une bonne chose que vous soyez l\224. Nous avons[ENTER]d\233cid\233 de commencer par attaquer les d\233mons, afin[ENTER]de les affaiblir avant d'attaquer Razador une[ENTER]nouvelle fois. "
gameforge.main_quest_flame_lv103._200_say = "W\228hrend meine M\228nner vor den Toren der Rotdrachenfestung Wache halten und alle Gegner erledigen, die ins Freie st\252rmen, wirst du hinein gehen und die Flammend\228monen im Inneren bek\228mpfen. Das Reine Lumen wird dich vor dem Einfluss der Schwarzen Materie sch\252tzen und ihre Kraft neutralisieren. "
gameforge.main_quest_flame_lv103._210_say = "Wenn du es schaffst, 1000 Flammend\228monen zu besiegen, wird die Verteidigungslinien um Razador empfindlich schw\228chen. "
gameforge.main_quest_flame_lv103._220_say = "Aux armes\160! "
gameforge.main_quest_flame_lv103._230_notice = "Lancez l'assaut sur la forteresse du dragon rouge[ENTER]et exterminez 1000 d\233mons flamme. "
gameforge.main_quest_flame_lv103._240_sayTitle = "Premi\232re \233tape : 1000 d\233mons "
gameforge.main_quest_flame_lv103._250_say = "Lancez l'assaut sur la forteresse du dragon rouge[ENTER]et exterminez 1000 d\233mons flamme. "
gameforge.main_quest_flame_lv103._260_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein! "
gameforge.main_quest_flame_lv103._270_say = "Les lignes de d\233fense ennemies sont encore trop[ENTER]puissantes. \201liminez plus de d\233mons. Nous[ENTER]comptons sur vous\160! "
gameforge.main_quest_flame_lv103._280_notice = "Vous avez extermin\233 1000 d\233mons flamme. Allez en[ENTER]informer Yak-Hwan. "
gameforge.main_quest_flame_lv103._290_say = "Gute Arbeit! Die Verteidigungslinien der Flammend\228monen wurde durch dich empfindlich geschw\228cht. Warte einen Moment, w\228hrend ich mich mit meinen Strategen \252ber das weitere Vorgehen berate. "
gameforge.main_quest_flame_lv103._300_sendLetter = "Deuxi\232me \233tape "
gameforge.main_quest_flame_lv103._310_say = "Il est temps de passer \224 l'\233tape suivante. Il[ENTER]nous faut maintenant attaquer les guerriers[ENTER]d\233mons de haut rang.[ENTER]Immiscez-vous encore une fois dans la Forteresse[ENTER]du dragon rouge et tuez 50 de chacun des d\233mons[ENTER]suivants\160: rois flamme ardents, barbeflammes[ENTER]ardents, trolls flamme ardents, g\233n\233raux flamme[ENTER]ardents et princes flamme ardents. "
gameforge.main_quest_flame_lv103._320_say = {}
gameforge.main_quest_flame_lv103._330_notice = "Immiscez-vous encore une fois dans la Forteresse[ENTER]du dragon rouge et tuez 50 de chacun des d\233mons[ENTER]suivants\160: rois flamme ardents, barbeflammes[ENTER]ardents, trolls flamme ardents, g\233n\233raux flamme[ENTER]ardents et princes flamme ardents. "
gameforge.main_quest_flame_lv103._340_sayTitle = "Deuxi\232me \233tape "
gameforge.main_quest_flame_lv103._350_say = "Dringe erneut in die Rotdrachenfestung ein und besiege jeweils 50 Glut-Flammenk\246nige, Glut-Flammenb\228rte, Glut-Flammengolem, Glut-Flammengener\228le und Glut-Flammenf\252rste. "
gameforge.main_quest_flame_lv103._360_say = "Les troupes adverses sont encore trop puissantes.[ENTER]Vous n'avez pas occis suffisamment de d\233mons[ENTER]flamme ardents. Retournez dans la forteresse et[ENTER]continuez le combat\160! "
gameforge.main_quest_flame_lv103._370_notice = "Vous avez triomph\233 des d\233mons flamme ardents.[ENTER]Allez faire votre rapport \224 Yak-Hwan. "
gameforge.main_quest_flame_lv103._380_say = "Formidable\160! Les troupes des d\233mons flamme[ENTER]ardents sont maintenant affaiblies et mes hommes[ENTER]peuvent lancer l'assaut sur la forteresse.[ENTER]Excellent travail\160! Je vous fais signe sit\244t que[ENTER]j'ai du nouveau. "
gameforge.main_quest_flame_lv103._390_sendLetter = "Razador "
gameforge.main_quest_flame_lv103._400_say = "Mes hommes ont r\233ussi \224 p\233n\233trer dans la[ENTER]forteresse du dragon rouge et, gr\226ce \224 votre[ENTER]travail de sape, les pertes restent raisonnables.[ENTER]Yon-I-Walker va maintenant vous expliquer la[ENTER]prochaine \233tape de notre strat\233gie. Allez-le[ENTER]voir. "
gameforge.main_quest_flame_lv103._410_notice = "Allez voir Yon-I-Walker et \233coutez sa strat\233gie. "
gameforge.main_quest_flame_lv103._420_say = "Allez voir Yon-I-Walker et \233coutez sa strat\233gie. "
gameforge.main_quest_flame_lv103._430_say = "Je vous attendais. Nous sommes \224 deux doigts de[ENTER]r\233ussir une nouvelle fois \224 contrecarrer les[ENTER]plans des serviteurs de l'Obscurit\233. Je vais vous[ENTER]expliquer comment nous comptons proc\233der. "
gameforge.main_quest_flame_lv103._440_say = "Gr\226ce \224 nos espions, nous avons pu apprendre que[ENTER]Razador tire une grande partie de sa force du[ENTER]Metin du Purgatoire. Il a fait porter cette[ENTER]pierre dans la forteresse du dragon rouge, o\249[ENTER]elle est \233troitement gard\233e. D\233truisez ce Metin\160![ENTER]Cela devrait grandement faciliter le combat face[ENTER]\224 Razador. "
gameforge.main_quest_flame_lv103._450_say = {}
gameforge.main_quest_flame_lv103._460_say = "Nous ne savons pas exactement o\249 il cache le[ENTER]Metin du Purgatoire. Mais il doit se trouver dans[ENTER]la forteresse. Une fois votre mission accomplie,[ENTER]retournez faire votre rapport \224 Yak-Hwan. "
gameforge.main_quest_flame_lv103._470_say = {}
gameforge.main_quest_flame_lv103._480_notice = "D\233truisez la Metin du Purgatoire dans la[ENTER]forteresse du dragon rouge. "
gameforge.main_quest_flame_lv103._490_sayTitle = "Flammen des Fegefeuers "
gameforge.main_quest_flame_lv103._500_say = "Mettez-vous \224 la recherche de la Metin du[ENTER]Purgatoire, dans la forteresse du dragon rouge,[ENTER]et d\233truisez-la. "
gameforge.main_quest_flame_lv103._510_say = "Restants "
gameforge.main_quest_flame_lv103._520_say = "Il nous faut d\233truire la Metin du Purgatoire,[ENTER]sans quoi, nous n'avons pas l'ombre d'une chance[ENTER]de vaincre Razador. Allez, je sais que vous[ENTER]pouvez y arriver\160! "
gameforge.main_quest_flame_lv103._530_notice = "Vous avez d\233truit la Metin du Purgatoire. Allez[ENTER]faire votre rapport \224 Yak-Hwan. "
gameforge.main_quest_flame_lv103._540_say = "Gute Arbeit. Nun k\246nnen wir der Schlange den Kopf abschlagen. Diesmal werden wir Razador vernichten! Nimm schon mal das Reine Lumen an dich. Ich werde ein paar letzte Vorbereitungen treffen. Ruhe dich so lange aus. "
gameforge.main_quest_flame_lv104 = {}
gameforge.main_quest_flame_lv104._010_sendLetter = "L'affrontement de Razador "
gameforge.main_quest_flame_lv104._020_say = "Allez voir Yak-Hwan et prenez connaissance de son[ENTER]plan de bataille. "
gameforge.main_quest_flame_lv104._030_say = "Le jour de gloire est \224 port\233e de main\160! Cette[ENTER]fois-ci, nous sommes fins pr\234ts et allons pouvoir[ENTER]vaincre Razador. "
gameforge.main_quest_flame_lv104._040_say = "Avez-vous encore le Lumen pur\160? Gardez bien en[ENTER]t\234te que son effet ne dure qu'une heure. Ne[ENTER]l'utilisez donc que juste avant le combat. Aux[ENTER]armes\160! "
gameforge.main_quest_flame_lv104._050_say = "C'est entendu. "
gameforge.main_quest_flame_lv104._060_notice = "Prenez la forteresse du dragon rouge d'assaut et[ENTER]\233liminez Razador. "
gameforge.main_quest_flame_lv104._070_sayTitle = "L'affrontement de Razador "
gameforge.main_quest_flame_lv104._080_say = "Prenez la forteresse du dragon rouge d'assaut et[ENTER]\233liminez Razador, le ma\238tre du feu. "
gameforge.main_quest_flame_lv104._090_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein! "
gameforge.main_quest_flame_lv104._100_say = "S'attaquer \224 Razador ne sera pas t\226che facile.[ENTER]Mais nous n'avons pas d'autre choix, si nous[ENTER]souhaitons contrecarrer les plans des serviteurs[ENTER]de l'Obscurit\233. Rassemblez toutes vos forces et[ENTER]affrontez le ma\238tre du feu avant qu'il ne soit[ENTER]trop tard\160! "
gameforge.main_quest_flame_lv104._110_say = "Mortel, \233coutez-moi bien\160! Profitez bien de votre[ENTER]malheureuse heure de gloire, car elle ne durera[ENTER]pas. Le dragon rouge va rompre ses cha\238nes. Fort[ENTER]de sa puissance, je reviendrai dans votre[ENTER]mis\233rable monde afin de parachever ma mission. "
gameforge.main_quest_flame_lv104._120_notice = "Vous avez vaincu Razador, le ma\238tre du feu. Allez[ENTER]en informer Yak-Hwan. "
gameforge.main_quest_flame_lv104._130_say = "Retournez aupr\232s de Yak-Hwan. "
gameforge.main_quest_flame_lv104._140_say = "Quel triomphe\160! Jusqu'\224 pr\233sent, jamais personne[ENTER]n'avait r\233ussi \224 vaincre le ma\238tre du feu. C'est[ENTER]une journ\233e historique\160! "
gameforge.main_quest_flame_lv104._150_say = {}
gameforge.main_quest_flame_lv104._160_say = "Que dites-vous\160? Le dragon rouge va permettre \224[ENTER]Razador de rena\238tre de ses cendres\160? Comment[ENTER]est-ce possible\160? Nous avons si peu de[ENTER]connaissances sur les grands dragons... et[ENTER]pourtant, leur puissance semble infinie. "
gameforge.main_quest_flame_lv104._170_sendLetter = "Contrecarrer les plans I "
gameforge.main_quest_flame_lv104._180_say = "Mauvaises nouvelles\160! Razador a bien ressuscit\233,[ENTER]gr\226ce au pouvoir du dragon rouge. Ses forces s'en[ENTER]sont trouv\233es d\233cupl\233es et l'influence de la[ENTER]mati\232re obscure semble \233galement plus puissante[ENTER]que jamais. "
gameforge.main_quest_flame_lv104._190_say = "Allez voir Yon-I-Walker. Il sait comment vaincre[ENTER]Razador une bonne fois pour toutes. "
gameforge.main_quest_flame_lv104._200_notice = "Allez voir Yon-I-Walker et d\233couvrez comment[ENTER]vaincre Razador une bonne fois pour toutes. "
gameforge.main_quest_flame_lv104._210_sayTitle = "Parlez \224 Yon-I-Walker. "
gameforge.main_quest_flame_lv104._220_say = "Allez voir Yon-I-Walker et d\233couvrez comment[ENTER]vaincre Razador une bonne fois pour toutes. "
gameforge.main_quest_flame_lv104._230_say = "Vous n'avez pas encore \233t\233 voir Yon-I-Walker\160?[ENTER]Comment voulez-vous vaincre Razador\160? Allez,[ENTER]qu'attendez-vous\160? "
gameforge.main_quest_flame_lv104._240_say = "Oui, c'est la v\233rit\233. Razador est de retour et[ENTER]son humeur est plus massacrante que jamais\160! Nous[ENTER]n'avons plus qu'une possibilit\233 d'emp\234cher les[ENTER]serviteurs de l'Obscurit\233 de mener leurs plans \224[ENTER]bien... "
gameforge.main_quest_flame_lv104._250_say = "Razador n'aura aucun r\233pit tant qu'il n'aura pas[ENTER]men\233 sa mission \224 bien et lib\233r\233 le dragon rouge.[ENTER]Afin de l'en emp\234cher, nous allons devoir bannir[ENTER]le dragon rouge. "
gameforge.main_quest_flame_lv104._260_say = {}
gameforge.main_quest_flame_lv104._270_say = "L'\233l\233ment du dragon rouge est le feu... et[ENTER]comment combattre le feu\160? Par le feu\160! Le c\156ur[ENTER]de chaque d\233mon flamme ardent est enserr\233 dans un[ENTER]anneau de magma. Rapportez-moi cinq de ces[ENTER]anneaux de magma. "
gameforge.main_quest_flame_lv104._280_notice = "Beschaffe die Magmakerne der Flammend\228monen. "
gameforge.main_quest_flame_lv104._290_say = "Beschaffe jeweils f\252nf Magmakerne dieser Gegner: Glut-Flammenk\246nig Glut-Flammenbart Glut-Flammengolem Glut-Flammengeneral Glut-Flammenf\252rst Kehre damit zu Yon-I-Walker zur\252ck. "
gameforge.main_quest_flame_lv104._300_say = "Oh ja, du hast schon einige gefunden. Bringe noch %d, das sollte dann reichen. "
gameforge.main_quest_flame_lv104._310_say = "Bien, j'ai d\233sormais tous les anneaux de magma[ENTER]n\233cessaires. Il faut qu'ils refroidissent encore[ENTER]un peu avant que je puisse les travailler. Je[ENTER]vous fais appeler sit\244t que j'ai besoin de vous. "
gameforge.main_quest_flame_lv104._320_say = "Hm, ces anneaux de magma sont d\233j\224 froids. Je ne[ENTER]peux plus rien en faire. Apportez-m'en des[ENTER]nouveaux. "
gameforge.main_quest_flame_lv104._330_sendLetter = "Contrecarrer les plans II "
gameforge.main_quest_flame_lv104._340_say = "Yon-I-Walker vous demande. Allez le voir. "
gameforge.main_quest_flame_lv104._350_say = "Il me faut encore un peu de temps avant que les[ENTER]anneaux de magma soient assez froids pour que je[ENTER]puisse les travailler. En attendant, pouvez-vous[ENTER]aller me chercher de l'eau de Dok\160? Je pourrais[ENTER]alors y dissoudre les anneaux de magma. "
gameforge.main_quest_flame_lv104._360_say = "Mit dieser Magmasuspension werden wir den Rotdrachen verbannen k\246nnen. Yak-Hwan wird dich dann sp\228ter \252ber das genaue Prozedere aufkl\228ren. Bitte beschaffe mir nun 100 Flaschen Dok-Wasser. Ich mache hier so lange weiter. "
gameforge.main_quest_flame_lv104._370_notice = "Rassemblez 100 flacons d'eau de Dok et[ENTER]rapportez-les \224 Yon-I-Walker. "
gameforge.main_quest_flame_lv104._380_say = "Rassemblez 100 flacons d'eau de Dok et[ENTER]rapportez-les \224 Yon-I-Walker. "
gameforge.main_quest_flame_lv104._390_say = "Nun habe ich alles beisammen und kann den Verbannungszauber herstellen. "
gameforge.main_quest_flame_lv104._400_say = "Bald? Brauchst du noch etwas? "
gameforge.main_quest_flame_lv104._410_say = "J'ai toutefois besoin d'un ingr\233dient[ENTER]suppl\233mentaire. Mais pour le moment, il me faut[ENTER]me concentrer sur le processus de fusion. Il ne[ENTER]faut surtout pas qu'il tourne mal\160! Je vous[ENTER]recontacte plus tard. "
gameforge.main_quest_flame_lv104._420_say = "Vous n'avez pas les 100 flacons. Ramenez-moi[ENTER]d'avantage d'eau de Dok. "
gameforge.main_quest_flame_lv104._430_notice = "Vous avez rassembl\233 100 flacons d'eau de Dok.[ENTER]Retournez aupr\232s de Yon-I-Walker. "
gameforge.main_quest_flame_lv104._440_say = "Allez voir Yon-I-Walker. "
gameforge.main_quest_flame_lv104._450_sendLetter = "Contrecarrer les plans III "
gameforge.main_quest_flame_lv104._460_say = "Ich komme gut voran mir der Suspension. Doch ein weiteres Mal bin ich noch auf deine Hilfe angewiesen. "
gameforge.main_quest_flame_lv104._470_say = "Nun ben\246tige ich noch ein geeignetes Gef\228\223 f\252r den Verbannungszauber. Die Fl\252gelhaut Martyaxwars, H\228uptling der Mantikore, sollte uns gute Dienste leisten. Beschaffe f\252nf St\252cke. "
gameforge.main_quest_flame_lv104._480_notice = "Bringe Yon-I-Walker f\252nf St\252cke aus der Fl\252gelhaut Martyaxwars. "
gameforge.main_quest_flame_lv104._490_say = "Bringe Yon-I-Walker f\252nf St\252cke aus der Fl\252gelhaut Martyaxwars in guter Qualit\228t. "
gameforge.main_quest_flame_lv104._500_say = "Nous sommes si pr\232s du but. Vous n'allez pas[ENTER]abandonner maintenant\160! Rapportez-moi le cuir de[ENTER]Manticore\160! "
gameforge.main_quest_flame_lv104._510_say = "Perfekt! Die Fl\252gelhaut ist sehr widerstandsf\228hig. Aus ihr kann ich nun Lederbeutel f\252r den Verbannungszauber herstellen. Yak-Hwan wird dich sp\228ter noch genauer instruieren. Aber nun mache ich mich erstmal an die Arbeit! "
gameforge.main_quest_flame_lv104._520_notice = "Vous avez r\233colt\233 tous les morceaux de cuir de[ENTER]Manticore. Rapportez-les \224 Yon-I-Walker. "
gameforge.main_quest_flame_lv105 = {}
gameforge.main_quest_flame_lv105._010_sendLetter = "D\233but des hostilit\233s "
gameforge.main_quest_flame_lv105._020_say = "Pr\233parez-vous car la bataille commence. Yak-Hwan[ENTER]va vous donner les derni\232res recommandations. "
gameforge.main_quest_flame_lv105._030_say = "L'heure a sonn\233. Nos troupes sont pr\234tes et le[ENTER]combat peut commencer. Avez-vous l'anneau de[ENTER]Sama\235l sur vous\160? "
gameforge.main_quest_flame_lv105._040_say = "Ja, hier sind sie. "
gameforge.main_quest_flame_lv105._050_say = "Ah, parfait. Je vous expliquerai plus tard[ENTER]comment vous en servir. Mais, tout d'abord, nous[ENTER]devons percer la nouvelle ligne de d\233fense des[ENTER]d\233mons flamme. Retournez \224 la Forteresse du[ENTER]dragon rouge et terrassez\160:[ENTER]10\160rois flamme ardents[ENTER]10\160barbeflammes ardents[ENTER]10\160trolls flamme ardents[ENTER]10\160g\233n\233raux flamme ardents[ENTER]10\160princes flamme ardents "
gameforge.main_quest_flame_lv105._060_say = {}
gameforge.main_quest_flame_lv105._070_say = "C'est entendu. "
gameforge.main_quest_flame_lv105._080_notice = "Besiege jeweils 10 Glut-Flammenk\246nige, Glut-Flammenb\228rte, Glut-Flammengolem, Glut-Flammengener\228le und Glut-Flammenf\252rste. "
gameforge.main_quest_flame_lv105._090_sayTitle = "Starte die Offensive "
gameforge.main_quest_flame_lv105._100_say = "Prenez la forteresse du dragon rouge d'assaut\160! "
gameforge.main_quest_flame_lv105._110_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein! "
gameforge.main_quest_flame_lv105._120_say = "Nous ne pouvons pas encore percer la ligne de[ENTER]d\233fense ennemie. Triomphez de la horde de d\233mons[ENTER]flamme ardents. "
gameforge.main_quest_flame_lv105._130_notice = "Vous avez d\233cim\233 l'arm\233e des d\233mons flamme[ENTER]ardents. Allez faire votre rapport \224 Yak-Hwan. "
gameforge.main_quest_flame_lv105._140_say = "Retournez aupr\232s de Yak-Hwan. "
gameforge.main_quest_flame_lv105._150_say = "Du bon travail\160! Nous avons fait un grand pas[ENTER]vers notre objectif. La menace que repr\233sente le[ENTER]dragon rouge ne planera plus bien longtemps sur[ENTER]nos t\234tes\160! "
gameforge.main_quest_flame_lv105._160_sendLetter = "Gunst und Groll "
gameforge.main_quest_flame_lv105._170_say = "Votre ennemi jur\233, Razador, semble avoir tr\232s mal[ENTER]pris le fait que vous l'avez tu\233. Ses hurlements[ENTER]retentissent plus fort que jamais sur les[ENTER]plateaux de Doyyumhwan. "
gameforge.main_quest_flame_lv105._180_say = "Il est temps de lui faire mordre la poussi\232re une[ENTER]fois de plus. En effet, il surveille avec grand[ENTER]soin le portail derri\232re lequel le dragon rouge[ENTER]est emprisonn\233. Mais prudence\160! Il a sans doute[ENTER]tir\233 des le\231ons de sa d\233faite et ne commettra pas[ENTER]les m\234mes erreurs. "
gameforge.main_quest_flame_lv105._190_notice = "Triomphez de Razador, le ma\238tre du feu. "
gameforge.main_quest_flame_lv105._200_sayTitle = "Jouer avec le feu "
gameforge.main_quest_flame_lv105._210_say = "Triomphez de Razador, le ma\238tre du feu, dans la[ENTER]forteresse du dragon rouge. "
gameforge.main_quest_flame_lv105._220_say = "Cette fois-ci, Razador vous est sup\233rieur\160? J'ai[ENTER]vraiment du mal \224 le croire\160! Vous y \234tes arriv\233[ENTER]une fois, il n'y a donc aucune raison que vous ne[ENTER]le terrassiez pas \224 nouveau\160! "
gameforge.main_quest_flame_lv105._230_notice = "Razador a \233t\233 vaincu. Faites votre rapport \224[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv105._240_say = "Je savais bien que vous pouviez y arriver\160! Je[ENTER]vais maintenant faire les derniers pr\233paratifs[ENTER]pour le rituel de bannissement. Je vous fais[ENTER]appeler sit\244t que nous sommes pr\234ts. "
gameforge.main_quest_flame_lv105._250_sendLetter = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._260_say = "Nous y voil\224. Tout est pr\234t pour le bannissement[ENTER]du dragon rouge. "
gameforge.main_quest_flame_lv105._270_say = "Meine M\228nner haben bereits bereits zwei Bannkreise aufgestellt. Deine Aufgabe ist es nun, sie zu entz\252nden. Wirf den Bannbeutel auf die Kreise und sie werden sich entflammen. Das wird die Verbannung des Rotdrachen vollziehen. "
gameforge.main_quest_flame_lv105._280_notice = "Entz\252nde die Bannkreise und schicke den Rotdrachen in die Verbannung. "
gameforge.main_quest_flame_lv105._290_say = "Restliche Verbannungsanzahl "
gameforge.main_quest_flame_lv105._300_sayTitle = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._310_say = "Entz\252nde mithilfe der Bannbeutel die magischen Kreissymbole und schicke den Rotdrachen in die Verbannung. "
gameforge.main_quest_flame_lv105._320_say = "Tombe de Taramor : 1 unit\233 "
gameforge.main_quest_flame_lv105._330_sayTitle = "Rotdrachen Flammenschauspiel "
gameforge.main_quest_flame_lv105._340_say = "C'est tout ce dont vous \234tes capable, mis\233rable[ENTER]asticot\160? \199a a bien un peu chatouill\233, mais vous[ENTER]\234tes encore loin de m'avoir banni\160! Je vais faire[ENTER]revenir Razador du Royaume des morts. Il va me[ENTER]lib\233rer de ma captivit\233 et me permettre d'abattre[ENTER]sur vous mon immense courroux\160! "
gameforge.main_quest_flame_lv105._350_notice = "Le bannissement du dragon rouge a \233chou\233. Allez[ENTER]faire votre rapport \224 Yak-Hwan. "
gameforge.main_quest_flame_lv105._360_say = "Die Verbannung ist fehlgeschlagen? Wie konnte das passieren? "
gameforge.main_quest_flame_lv105._370_say = "Ja. Eigentlich wurden die Bannkreise aktiviert und die Entflammung hat auch stattgefunden und die Verbannung hatte begonnen, aber der Rotdrache war so m\228chtig, dass dies fehlgeschlagen ist. Er sagte, dass er Yamachun (6091) wiederbeleben wird und er die Versiegelung entfernen wird. Aber er hat auch gro\223en Schaden durch unseren Verbannungs-Versuch erlitten. "
gameforge.main_quest_flame_lv105._380_say = "Ach so. Gute Arbeit. Dank dir, konnten wir es so weit bringen. Ich habe bereits mit Yon-I-Walker (20380) gesprochen und \252berlegt, was wir nun tun k\246nnen. Meine M\228nner werden weiterhin die Lage beobachten und wir werden ach anderen Methoden suchen, wie wir die Verbannung vollziehen k\246nnen. Wenn wir eine perfekte Methoe gefunden haben, den Rotdrachen zu verbannen, werde ich nach dir rufen lassen. Gute Arbeit! "
gameforge.main_quest_flame_lv99 = {}
gameforge.main_quest_flame_lv99._010_sendLetter = "L'\233preuve du feu "
gameforge.main_quest_flame_lv99._020_say = "Yak-Hwan vous demande. Allez le voir et d\233couvrez[ENTER]ce qu'il vous veut. "
gameforge.main_quest_flame_lv99._030_say = "Bienvenue\160! Nous ne disposons que d'un court[ENTER]r\233pit\160: les serviteurs de l'Obscurit\233 sont \224[ENTER]nouveau en mouvement. Cela n'augure rien de bon. "
gameforge.main_quest_flame_lv99._040_say = {}
gameforge.main_quest_flame_lv99._050_say = "Malheureusement, mes informations ne sont que[ENTER]tr\232s vagues. Nous savons qu'ils r\233sident[ENTER]d\233sormais dans la Terre de Feu. "
gameforge.main_quest_flame_lv99._060_say = "Nous y avons d\233j\224 envoy\233 un \233claireur.[ENTER]Malheureusement, nous n'avons plus de nouvelles[ENTER]de lui et cela m'inqui\232te fortement.[ENTER]Pourriez-vous essayer de le d\233nicher, lors de[ENTER]votre p\233riple vers la Terre de Feu\160? "
gameforge.main_quest_flame_lv99._070_say = "Bien entendu. "
gameforge.main_quest_flame_lv99._080_say = "Merci. Je vais vous indiquer sa derni\232re position[ENTER]connue, en la signalant sur votre carte. Bonne[ENTER]chance\160! "
gameforge.main_quest_flame_lv99._090_notice = "Recherchez l'\233claireur manquant dans la Terre de[ENTER]Feu. Coordonn\233es\160: %d,%d "
gameforge.main_quest_flame_lv99._100_sayTitle = "Explorez la Terre de Feu\160! "
gameforge.main_quest_flame_lv99._110_say = "Rendez-vous dans la Terre de Feu. Recherchez-y[ENTER]l'\233claireur ainsi que des indices sur les[ENTER]agissements des serviteurs de l'Obscurit\233. "
gameforge.main_quest_flame_lv99._120_say = "Il doit pourtant bien y avoir quelque chose \224 cet[ENTER]endroit. Peut-\234tre avez-vous omis un indice.[ENTER]Continuez \224 fouiller. "
gameforge.main_quest_flame_lv99._130_notice = "Dies ist der Ort, den Yak-Hwan auf der Karte markiert hat. Schaue dich um und kehre dann zu Yak-Hwan zur\252ck. "
gameforge.main_quest_flame_lv99._140_say = "Yak-Hwan attend votre rapport sur le rocher du[ENTER]Dragon Sombre. "
gameforge.main_quest_flame_lv99._150_say = "Vous voil\224 de retour\160! Avez vous d\233couvert[ENTER]quelque chose\160? "
gameforge.main_quest_flame_lv99._160_say = "Aucune trace de l'\233claireur, malheureusement. En[ENTER]revanche, j'ai d\233couvert une forteresse qui[ENTER]n'avait jamais attir\233 mon attention jusque-l\224.[ENTER]Une aura puissante s'en \233chappe et influe sur les[ENTER]alentours. "
gameforge.main_quest_flame_lv99._170_say = "Hum, cela ne me dit rien qui vaille. Je vais[ENTER]t\226cher d'en savoir plus sur cette forteresse.[ENTER]Apr\232s quoi je vous recontacterai. "
gameforge.main_quest_flame_lv99._180_sendLetter = "Explorer la forteresse "
gameforge.main_quest_flame_lv99._190_say = "Hm, wir tappen im Dunkeln. Ich habe rein gar nichts \252ber diese geheimnisvolle Festung herausfinden k\246nnen. In diesem Brief habe ich alles zusammengetragen, was wir bis jetzt wissen. Bitte \252berbringe ihn Yon-I-Walker. Er wird wissen, was zu tun ist. "
gameforge.main_quest_flame_lv99._200_say = "Allez voir Yon-I-Walker. "
gameforge.main_quest_flame_lv99._210_say = "Was kann ich f\252r dich tun? ... Ah, ein Brief. Yak-Hwan bittet also um meine Hilfe. Dann werden wir mal versuchen, Licht in die Dunkelheit zu bringen. "
gameforge.main_quest_flame_lv99._220_say = {}
gameforge.main_quest_flame_lv99._230_say = {}
gameforge.main_quest_flame_lv99._240_say = "Eine geheimnisvolle Aura, die aus dem Inneren einer Festung str\246mt? Interessant ... Schaue dich zun\228chst einmal in der n\228heren Umgebung dort um. Ich habe da einen Verdacht, worum es sich bei dieser Aura handeln k\246nnte. Hier, nimm dieses Papier und wickel es um deine Waffe. Wenn sich mein Verdacht best\228tigt, sollte sich das Papier schwarz f\228rben, sobald du damit D\228monen t\246test, die unter dem Einfluss der dunklen Aura stehen. "
gameforge.main_quest_flame_lv99._250_notice = "Tuez des d\233mons qui errent aux alentours de la[ENTER]forteresse. "
gameforge.main_quest_flame_lv99._260_sayTitle = "La chasse aux d\233mons "
gameforge.main_quest_flame_lv99._270_say = "Tuez des d\233mons de la Terre de Feu qui errent aux[ENTER]alentours de la forteresse et observez si votre[ENTER]arme change de couleur. "
gameforge.main_quest_flame_lv99._280_say = "Je suis certain qu'un indice sur cette aura[ENTER]peut-\234tre trouv\233 dans la Terre de Feu.[ENTER]Retournez-y et tuez des d\233mons se trouvant dans[ENTER]le voisinage imm\233diat de cette forteresse. "
gameforge.main_quest_flame_lv99._290_notice = "Votre arme s'est teinte en noir. Retournez voir[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv99._300_say = "Ah, so wie ich es erwartet hatte! Das ist h\246chst bemerkenswert. Ich werde dieses Papier etwas n\228her untersuchen. Ruhe dich solange aus. "
gameforge.main_quest_flame_lv99._310_sendLetter = "Aura erforschen "
gameforge.main_quest_flame_lv99._320_say = "Yon-I-Walker vous cherche. Allez le voir afin[ENTER]d'en savoir plus. "
gameforge.main_quest_flame_lv99._330_say = "Ah, vous voil\224\160! L'aura est perfide et trouble[ENTER]mon esprit.[ENTER]J'ai besoin d'herbes solaires afin d'y revoir[ENTER]clair et de continuer mes analyses. Pourriez-vous[ENTER]m'en procurer\160? "
gameforge.main_quest_flame_lv99._340_say = "Bien entendu. "
gameforge.main_quest_flame_lv99._350_say = "Les herbes solaires poussent dans des endroits[ENTER]chauds et secs. Dans la Terre de Feu, on en[ENTER]trouve toute l'ann\233e. J'ai indiqu\233, sur votre[ENTER]carte, le dernier lieu o\249 j'en ai trouv\233. M\234me si[ENTER]je dois avouer que je ne suis soudain plus tout \224[ENTER]fait certain que c'\233tait bien l\224-bas... "
gameforge.main_quest_flame_lv99._360_say = "Je pars imm\233diatement. "
gameforge.main_quest_flame_lv99._370_notice = "Rendez-vous dans la Terre de Feu et cherchez des[ENTER]herbes solaires \224 l'endroit indiqu\233 sur votre[ENTER]carte. "
gameforge.main_quest_flame_lv99._380_sayTitle = "Sonnenkr\228uter besorgen "
gameforge.main_quest_flame_lv99._390_say = "Rendez-vous \224 l'endroit indiqu\233 par Yon-I-Walker[ENTER]et cherchez-y des herbes solaires. "
gameforge.main_quest_flame_lv99._400_say = "Vous revenez les mains vides\160? Voil\224 qui n'est[ENTER]pas bon. Je sens que le trouble jet\233 par l'aura[ENTER]sur mon esprit s'aggrave toujours plus. Je vous[ENTER]en prie, ramenez-moi des herbes solaires. "
gameforge.main_quest_flame_lv99._410_notice = "Vous avez trouv\233 les herbes solaires. Ramenez-les[ENTER]\224 Yon-I-Walker. "
gameforge.main_quest_flame_lv99._420_say = "Ah, vous avez trouv\233 les herbes solaires\160![ENTER]Parfait\160! Je vais pouvoir continuer mes analyses.[ENTER]Yak-Hwan vous en communiquera les r\233sultats. "
gameforge.main_quest_flame_lv99._430_say = "Vous pourrez poursuivre l'aventure sit\244t que vous[ENTER]aurez atteint le niveau %d. "
gameforge.main_quest_lv1 = {}
gameforge.main_quest_lv1._10_sendLetter = "Bienvenue sur Metin2 "
gameforge.main_quest_lv1._20_say = "La grande aventure de Metin2 va bient\244t d\233buter.[ENTER]Pour commencer, le Garde du Village vous donnera[ENTER]les informations de bases et diverses t\226ches \224[ENTER]accomplir pour vous familiariser avec Metin2.[ENTER]Allez le voir, il vous cherche d\233j\224.[ENTER][ENTER]Si vous voulez chasser, sortez du village, vous y[ENTER]trouverez beaucoup de b\234tes sauvages qui sont[ENTER]affich\233es en rouge sur la mini-carte. Vous[ENTER]devriez commencer par chasser les chiens errants[ENTER]qui sont les cibles les plus faciles. Bonne[ENTER]chance ! "
gameforge.main_quest_lv1._30_targetVid = "Trouvez le Garde du Village "
gameforge.main_quest_lv1._40_sayTitle = "Trouvez le Garde du Village "
gameforge.main_quest_lv1._50_sayReward = "Parlez au garde du village. Trouvez le PNJ[ENTER]indiqu\233 par la fl\232che rouge et cliquez dessus. Si[ENTER]vous ne voyez pas de PNJ, il est sans doute trop[ENTER]loin. Suivez les points rouges clignotants sur la[ENTER]carte jusqu'\224 ce que vous arriviez \224 lui. "
gameforge.main_quest_lv1._60_sayTitle = "Le Garde du Village : "
gameforge.main_quest_lv1._70_say = "Vous \234tes nouveau\160? Comme je vois, ils n'ont pas[ENTER]encore fait de vous un soldat. Avez-vous au moins[ENTER]re\231u une formation quelconque\160? Regardez-vous\160![ENTER]Savez-vous au moins comment on se sert d'une[ENTER]arme\160? \201coutez, soyez toujours sur vos gardes, si[ENTER]vous voulez survivre. Jusqu'\224 ce que vous ayez[ENTER]atteint le niveau 10, je vous aiderai. J'ai[ENTER]beaucoup de travail donc ne me faites pas perdre[ENTER]mon temps\160! En avant\160! "
gameforge.main_quest_lv1._80_say = "Partez et apprenez les m\233thodes de chasse de[ENTER]base\160! Lorsque vous aurez atteint un niveau[ENTER]sup\233rieur, revenez me voir. Vous n'\234tes pas[ENTER]encore parti\160? Ce n'est pas en restant plant\233 l\224[ENTER]que vous arriverez \224 quelque chose\160! "
gameforge.main_quest_lv10 = {}
gameforge.main_quest_lv10._100_sayReward = "Vous avez re\231u 50.000 points d'exp\233rience.[ENTER]Vous avez re\231u 12.000 yangs.[ENTER]Vous avez re\231u des chaussures de fil d'or +4.[ENTER]Vous avez re\231u 5 potions violettes. "
gameforge.main_quest_lv10._10_sendLetter = "Allez voir le Capitaine. "
gameforge.main_quest_lv10._110_sayTitle = "L'entra\238nement du capitaine "
gameforge.main_quest_lv10._120_sayReward = "La premi\232re mission du Capitaine vous am\232ne au[ENTER]second village. L\224-bas vous devriez aller voir[ENTER]Yu-Hwan et lui demander les documents pour le[ENTER]Capitaine. "
gameforge.main_quest_lv10._130_sayTitle = "Yu-Hwan le musicien: "
gameforge.main_quest_lv10._140_say = "La vie n'est qu'un r\234ve comme tout le reste.[ENTER]D'o\249 venons-nous et o\249 allons-nous? Le monde[ENTER]n'est que conflits. Le travail honn\234te ne paie[ENTER]pas. \202tes-vous ici pour \233couter ma chanson? "
gameforge.main_quest_lv10._150_say = "Oh, c'est le capitaine qui vous envoie ! Oh,[ENTER]parlez moins fort...[ENTER][ENTER]Personne dans le village ne doit conna\238tre ma[ENTER]v\233ritable identit\233. Vous devez \234tre de confiance[ENTER]si le capitaine vous envoie. Voil\224. Ce document[ENTER]contient tous les renseignements que j'ai pu[ENTER]obtenir. Donnez-le au capitaine. "
gameforge.main_quest_lv10._160_sayTitle = "Yu-Hwan le musicien: "
gameforge.main_quest_lv10._170_say = "D\233p\234chez-vous de partir\160! Si vous restez ici trop[ENTER]longtemps, \231a va mal finir. Qu'est-ce que la[ENTER]vie\160? La vie est courte, profitez-en tant que[ENTER]vous le pouvez. "
gameforge.main_quest_lv10._180_targetVid = "Retournez voir le Capitaine. "
gameforge.main_quest_lv10._190_sayReward = "Le musicien Yu-Hwan qui est aussi en secret un[ENTER]espion vous a donn\233 d'importants documents.[ENTER]Apportez-les au Capitaine dans le premier village. "
gameforge.main_quest_lv10._200_say = "C'est le document que vous a donn\233 le musicien?[ENTER]pas mal pour un aventurier d\233butant! Je pense que[ENTER]vous ferez de grandes choses. Prenez ceci en[ENTER]r\233compense de votre travail. Continuez \224 \156uvrer[ENTER]pour le bien de notre pays! "
gameforge.main_quest_lv10._20_sayReward = "Vous \234tes maintenant assez exp\233riment\233 pour[ENTER]servir votre empire comme un valeureux et[ENTER]redoutable guerrier.[ENTER]De ce fait, le capitaine pourra vous confier de[ENTER]nouvelles missions. Vous le trouverez dans le[ENTER]premier village. Allez le voir, il vous attend. "
gameforge.main_quest_lv10._30_sayTitle = "Capitaine: "
gameforge.main_quest_lv10._40_say = "Il me semble que je vous connais... Ah oui j'ai[ENTER]entendu parler de vous. Vous \234tes le nouvel[ENTER]aventurier et vous avez d\233j\224 prouv\233 quelles[ENTER]\233taient vos capacit\233s. Je ne sais pas encore ce[ENTER]que vous valez exactement mais vous aurez[ENTER]l'occasion de faire vos preuves dans les missions[ENTER]qui vont vous \234tre confi\233es. "
gameforge.main_quest_lv10._50_say = "De nombreux d\233fis vous attendent, alors soyez[ENTER]pr\234t. Connaissez-vous l'histoire des trois[ENTER]empires ? Vous ne la connaissez pas\160? Mais[ENTER]qu'est-ce qu'on vous apprend de nos jours\160? Il[ENTER]faut donc je vous enseigne les choses les plus[ENTER]\233l\233mentaires ? "
gameforge.main_quest_lv10._60_say = "Il s'agit de choses importantes et je vais les[ENTER]r\233sumer. \201coutez bien je ne me r\233p\233terai pas deux[ENTER]fois ! Autrefois, il n'y avait qu'un seul Empire.[ENTER]Apr\232s l'apparition des pierres Metin, il a \233t\233[ENTER]partag\233 en 3 empires distincts. Shinsoo est[ENTER]l'empire du commerce, Chunjo, l'empire de la[ENTER]religion et Jinno, l'empire de l'arm\233e. "
gameforge.main_quest_lv10._70_say = "Chaque empire essaie de se remettre des \233meutes[ENTER]qui ont accompagn\233 l'arriv\233e des pierres Metin[ENTER]tout en essayant de r\233unifier le continent. Vous[ENTER]aussi devez participer \224 cette mission de[ENTER]r\233unification de l'empire ! C'est important, ne[ENTER]l'oubliez jamais. "
gameforge.main_quest_lv10._80_say = "Je vais vous donner votre premi\232re mission. Ne[ENTER]vous inqui\233tez pas, elle est assez simple. Dans[ENTER]le village d'\224 c\244t\233, il y a un musicien qui se[ENTER]nomme Yu-Hwan. Les gens croient qu'il a quitt\233[ENTER]l'arm\233e pour devenir musicien. Mais en fait,[ENTER]c'est un espion. J'ai besoin d'un document que[ENTER]poss\232de Yu-Hwan. Apportez-le-moi! N'oubliez pas,[ENTER]vous \234tes en mission secr\232te. "
gameforge.main_quest_lv10._90_say = "Appuyez sur la touche M pour trouver comment vous[ENTER]rendre au village voisin sur la carte. Utilisez[ENTER]le portail indiqu\233 par un point bleu.[ENTER]D\233p\234chez-vous ! Le musicien Yu-Hwan est un grand[ENTER]bonhomme avec un instrument. "
