gameforge.main_quest_lv12._110_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.main_quest_lv12._120_say = "Alors vous avez r\233ussi ? Bon travail ! Vous[ENTER]n'avez pas eu trop de probl\232mes, j'esp\232re? Quoi[ENTER]qu'il en soit, passons \224 l'\233tape suivante. "
gameforge.main_quest_lv12._130_targetVid = "Trouvez le Capitaine "
gameforge.main_quest_lv12._140_sendLetter = "Mission accomplie "
gameforge.main_quest_lv12._150_say = "Mission accomplie "
gameforge.main_quest_lv12._160_sayReward = "Vous avez tu\233 le nombre demand\233 de Loups alpha[ENTER]gris. Allez voir le Capitaine pour lui dire ! "
gameforge.main_quest_lv12._170_say = "Avez-vous tu\233 les Loups alpha gris ? Bon travail.[ENTER]Merci, cela va \234tre plus facile d'assurer la[ENTER]s\233curit\233 du village \224 pr\233sent. C'est un point[ENTER]positif pendant ces temps de guerre. "
gameforge.main_quest_lv12._180_sayReward = "Vous avez re\231u 40.000 points d'exp\233rience.[ENTER]Vous avez re\231u 10.000 yangs.[ENTER]Vous avez re\231u un livre de comp\233tence. "
gameforge.main_quest_lv12._20_say = "Plusieurs loups alpha gris ont fait des ravages[ENTER]aux alentours du village. Ils ont toujours \233t\233[ENTER]sauvages, mais l\224 ils deviennent intenables. Ils[ENTER]attaquent \224 pr\233sent le village et les gens sur[ENTER]les routes. Nous allons reprendre les choses en[ENTER]main, pour cela nous allons tuer des loups alpha[ENTER]gris. Je suis s\251r que vous allez y arriver. Tuez[ENTER]10 loups gris alpha pour nous. "
gameforge.main_quest_lv12._30_sayReward = "Votre r\233compense sera de 24\160000\160points[ENTER]d'exp\233rience et de 3\160500\160Yangs. "
gameforge.main_quest_lv12._40_sendLetter = "Tuez 10 Loups alpha gris "
gameforge.main_quest_lv12._50_sayReward = "Les loups alpha gris s'attaquent au village.[ENTER]Pour reprendre la situation en main, vous devez[ENTER]en tuer 10. "
gameforge.main_quest_lv12._60_sayReward = "Vous avez d\233j\224 tu\233 %s loups alpha gris. "
gameforge.main_quest_lv12._65_counter = "Nombre restant "
gameforge.main_quest_lv12._70_sayReward = "Vous avez tu\233 10 loups alpha gris. Retournez voir[ENTER]le capitaine. "
gameforge.main_quest_lv12._80_npcChat = "Tuez les loups alpha gris "
gameforge.main_quest_lv12._90_say = "Quoi, vous n'avez pas encore termin\233 la mission?[ENTER]Avez-vous du mal \224 tuer ces loups alpha gris?[ENTER]Vous devriez essayer encore. "
gameforge.main_quest_lv14 = {}
gameforge.main_quest_lv14._100_sayTitle = "Mission accomplie "
gameforge.main_quest_lv14._10_sayReward = "Le Capitaine a une nouvelle mission pour vous.[ENTER]Allez le voir. "
gameforge.main_quest_lv14._110_sayReward = "Vous avez d\233truit la Metin de Bataille. Allez[ENTER]voir le Capitaine pour lui annoncer. "
gameforge.main_quest_lv14._120_say = "Joli travail\160! On peut vraiment compter sur[ENTER]vous\160! Je sais maintenant que l'on peut vous[ENTER]confier n'importe quelle mission. Je suis fier de[ENTER]vous. Voici votre r\233compense et continuez comme[ENTER]\231a\160! "
gameforge.main_quest_lv14._130_sayReward = "Vous recevez 20.000 points d'exp\233rience.[ENTER]Vous recevez 20.000 Yangs.[ENTER]Vous recevez une p\233pite d'or. "
gameforge.main_quest_lv14._140_sayReward = "Vous avez re\231u une %s . "
gameforge.main_quest_lv14._20_say = "Je suis au courant pour les pierres Metin.[ENTER]Yu-Hwan le musicien m'a pr\233venu que les pierres[ENTER]Metin rendent les animaux fous furieux. De plus[ENTER]elles r\233pandent des maladies. "
gameforge.main_quest_lv14._30_say = "Si nous ne faisons rien contre les pierre Metin,[ENTER]les animaux vont continuer \224 attaquer les[ENTER]habitants du village ou, pire encore, l'\233pid\233mie[ENTER]va se propager. Occupez-vous des pierres Metin[ENTER]qui tombent aux abords du village s'il vous[ENTER]pla\238t. "
gameforge.main_quest_lv14._40_sayReward = "En r\233compense, vous recevrez 48\160000 points[ENTER]d'exp\233rience, 10\160000 Yangs et une pierre d'esprit[ENTER](+0 \224 +2). "
gameforge.main_quest_lv14._50_sendLetter = "D\233truisez la Metin de Bataille "
gameforge.main_quest_lv14._60_sayReward = "Les Pierres Metin sont un danger non n\233gligeable.[ENTER]Aidez le Capitaine et d\233truisez une Metin de[ENTER]Bataille. "
gameforge.main_quest_lv14._70_sayTitle = "Mission accomplie "
gameforge.main_quest_lv14._80_sayReward = "Vous avez d\233truit la Metin de Bataille. Allez[ENTER]parler au capitaine. "
gameforge.main_quest_lv14._90_sendLetter = "Retournez voir le Capitaine. "
gameforge.main_quest_lv15 = {}
gameforge.main_quest_lv15._100_say = "Jinno: Notre Empire a toujours \233t\233 une forte[ENTER]puissance militaire. Le roi Isup a uni le[ENTER]continent gr\226ce \224 sa cavalerie puissante. M\234me si[ENTER]nous sommes actuellement divis\233s par les[ENTER]\233v\232nements qui ont accompagn\233 l'apparition des[ENTER]pierres Metin, notre empire est l'h\233ritier de la[ENTER]puissance du roi Iryung. "
gameforge.main_quest_lv15._10_qSetTitle = "La situation actuelle "
gameforge.main_quest_lv15._110_say = "Nous avons encore l'arm\233e la plus puissante des[ENTER]trois empires, bien que nous ne puissions rien[ENTER]contre les pierres Metin \224 l'heure actuelle. Si[ENTER]nous le voulions vraiment, nous pourrions[ENTER]facilement conqu\233rir les autres empires. Vous[ENTER]devriez vous entra\238ner autant que vous le pouvez[ENTER]pour devenir un jour un tr\232s bon soldat. "
gameforge.main_quest_lv15._120_say = "Je vais vous confier une nouvelle mission. Amenez[ENTER]ces munitions \224 Yu-Hwan dans le village voisin.[ENTER]Notre pays est une grande puissance militaire[ENTER]mais nous devons veiller \224 toujours avoir assez[ENTER]de munitions. Si vous amenez ceci \224 Yu-Hwan, vous[ENTER]contribuerez \224 armer le village. "
gameforge.main_quest_lv15._130_sayReward = "Vous avez re\231u 36\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 10\160000 Yangs.[ENTER]Vous avez re\231u un ornement. "
gameforge.main_quest_lv15._140_sayTitle = "La situation actuelle "
gameforge.main_quest_lv15._150_sayReward = "Le Capitaine vous a charg\233 d'apporter quelque[ENTER]chose \224 Yu-Hwan au second village. "
gameforge.main_quest_lv15._160_say = "Il y a eu jadis une bataille sanglante entre Sung[ENTER]Mahi et le Dieu Dragon. Depuis ce jour, le peuple[ENTER]s'est divis\233 et s'entretue dans d'interminables[ENTER]guerres... Ah c'est vous de nouveau? Que vous[ENTER]faut-il aujourd'hui? Le Capitaine vous demande de[ENTER]m'apporter quelque chose d'important? C'est bien.[ENTER]Mais partez vite, je ne veux pas que les autres[ENTER]nous voient ainsi ensemble. "
gameforge.main_quest_lv15._170_makequestbutton = "Parlez au Capitaine. "
gameforge.main_quest_lv15._175_say = "Vous avez apport\233 \224 Yu-Hwan la livraison du[ENTER]capitaine. Retournez voir le Capitaine pour[ENTER]recevoir votre r\233compense. "
gameforge.main_quest_lv15._180_say = "Bien jou\233 ! Si vous r\233ussissez tout comme cela,[ENTER]vous serez d'une grande aide \224 notre village.[ENTER]Tenez, votre r\233compense. "
gameforge.main_quest_lv15._20_say = "Allez voir le capitaine. Il vous parlera de la[ENTER]situation actuelle dans les trois empires. "
gameforge.main_quest_lv15._30_say = "Comme je vois, vous \234tes pr\234t \224 en savoir plus[ENTER]sur la situation actuelle. Commen\231ons par notre[ENTER]empire. Pour gagner une guerre, il faut se[ENTER]conna\238tre soi-m\234me avant de vouloir chercher \224[ENTER]conna\238tre ses ennemis. "
gameforge.main_quest_lv15._40_say = "Shinsoo: Notre empire a depuis toujours \233t\233 bas\233[ENTER]sur le commerce. Nous avons des routes[ENTER]commerciales bien d\233velopp\233es et le n\233goce \233tait[ENTER]le fleuron de l'empire. Mais depuis l'apparition[ENTER]des pierres Metin les affaires se sont effondr\233es[ENTER]et l'\233conomie se d\233t\233riore de jour en jour. En[ENTER]tant que puissance commerciale, nous n'avons[ENTER]jamais eu une grande arm\233e.[ENTER][ENTER]C'est pourquoi nous avons recrut\233 beaucoup de[ENTER]mercenaires que nous payons avec nos richesses.[ENTER]Les mercenaires sont dignes de confiance et[ENTER]loyaux tant qu'on les paye bien. "
gameforge.main_quest_lv15._50_say = "Gr\226ce aux mercenaires, notre pays a pu r\233cup\233rer[ENTER]en grande partie sa stabilit\233. Mais pour nous[ENTER]pr\233parer aux guerres \224 venir, il nous faut plus[ENTER]de mercenaires et une \233conomie tr\232s solide. Cela[ENTER]va demander de gros efforts \224 nous tous, vous y[ENTER]compris. "
gameforge.main_quest_lv15._60_say = "Je vais vous donner une nouvelle mission. Amenez[ENTER]cette sp\233cialit\233 \224 Yu-Hwan dans le village[ENTER]voisin. Notre pays est un pays de commerce et[ENTER]nous commer\231ons avec les sp\233cialit\233s des[ENTER]diff\233rentes r\233gions. Si vous amenez ceci \224[ENTER]Yu-Hwan, vous rendrez un grand service \224 notre[ENTER]village. "
gameforge.main_quest_lv15._70_say = "Chunjo: Notre empire est dirig\233 par le gouverneur[ENTER]Yoon-Young et notre identit\233 nationale est[ENTER]fond\233e, sur la religion. Gr\226ce \224 cette derni\232re,[ENTER]nous avons su avant tous les autres l'existence[ENTER]de Sung Mahi. Nos chamanes nous ont pr\233par\233 \224[ENTER]l'arriv\233e des pierres Metin. Nos grands chamanes[ENTER]travaillent continuellement pour l'instant pour[ENTER]assurer la s\233curit\233 de notre pays. Les chamanes[ENTER]poss\232dent la sagesse car leur puissance est bas\233e[ENTER]sur leurs pouvoirs mystiques. Sans eux, cela ne[ENTER]serait qu'une question de temps avant que notre[ENTER]empire soit conquis par un autre. "
gameforge.main_quest_lv15._80_say = "Notre population est tr\232s croyante et prie chaque[ENTER]jour le Dieu Dragon qui veille sur nous et nous[ENTER]prot\232ge contre la r\233surrection du Sung Mahi. Nous[ENTER]devons continuer de nous d\233fendre contre ces[ENTER]attaques barbares et nous nous devons de[ENTER]r\233unifier le continent sous notre \233tendard. "
gameforge.main_quest_lv15._90_say = "Je vais maintenant vous confier une nouvelle[ENTER]mission. Amenez cette statue en pierre du Dieu[ENTER]Dragon \224 Yu-Hwan dans le village voisin. Notre[ENTER]pays est religieux et la foi profonde que nous[ENTER]avons dans le Dieu Dragon est le ciment de notre[ENTER]empire. Si vous amenez cette statue \224 Yu-Hwan,[ENTER]vous rendrez un grand service aux villageois. "
gameforge.main_quest_lv16 = {}
gameforge.main_quest_lv16._100_sayReward = "Vous avez re\231u 3\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 5\160000 Yangs.[ENTER]Vous avez re\231u une fourrure de loup. "
gameforge.main_quest_lv16._10_sendLetter = "Capturez l'espion "
gameforge.main_quest_lv16._20_sayTitle = "Capturez l'espion "
gameforge.main_quest_lv16._30_sayReward = "Il y a un espion ennemi dans le village. Le[ENTER]Capitaine vous donnera plus d'informations le[ENTER]concernant. "
gameforge.main_quest_lv16._40_say = "J'ai l'impression que nous avons un espion dans[ENTER]notre village. Un des habitants semble collaborer[ENTER]avec le Serment Blanc. J'ai besoin de votre[ENTER]aide\160: Allez tuer les soldats du Serment Blanc,[ENTER]peut-\234tre que nous trouverons quelques[ENTER]informations sur l'espion. "
gameforge.main_quest_lv16._50_sayReward = "Votre r\233compense sera de 100\160000\160points[ENTER]d'exp\233rience et de 5\160000\160Yangs. "
gameforge.main_quest_lv16._60_sendLetter = "D\233masquez l'espion "
gameforge.main_quest_lv16._70_sayReward = "Le Capitaine pense qu'il y a un espion du Serment[ENTER]Blanc. Allez chercher des preuves au clan du[ENTER]Serment Blanc et amenez-les au Capitaine. "
gameforge.main_quest_lv16._75_say = "Vous avez trouv\233 une lettre.[ENTER]Apportez-la au capitaine. "
gameforge.main_quest_lv16._80_sayReward = "Vous avez trouv\233 une lettre. Peut-\234tre est-ce la[ENTER]preuve que le capitaine recherche.[ENTER]Apportez-lui. "
gameforge.main_quest_lv16._90_say = "Avez-vous trouv\233 des preuves? Faites-moi voir[ENTER]cela... Cette lettre est int\233ressante. Je pense[ENTER]que \231a pourrait nous suffire \224 d\233masquer[ENTER]l'espion. Gr\226ce \224 vous, nous pourrons parvenir \224[ENTER]surmonter cette crise. Nous sommes tr\232s heureux[ENTER]de compter un homme tel que vous dans nos rangs.[ENTER]Reposez-vous un peu, vous l'avez m\233rit\233![ENTER]Acceptez ceci en signe de ma reconnaissance. "
