gameforge.main_quest_lv2._40_targetVid = "Trouvez le Garde du Village "
gameforge.main_quest_lv2._50_sayReward = "Vous recevez cette lettre car vous avez gagn\233 un[ENTER]niveau. F\233licitations ! Allez voir le garde du[ENTER]village pour qu'il vous confie votre premi\232re[ENTER]mission d'entra\238nement ! "
gameforge.main_quest_lv2._60_say = "Vous manquez encore de discipline mais au moins[ENTER]vous avez prouv\233 que vous savez vous servir d'une[ENTER]arme ! Montrez-moi que ce n'\233tait pas juste un[ENTER]coup de chance. Quittez le village et tuez 9[ENTER]chiens errants. Quand vous aurez termin\233 revenez[ENTER]me voir et je vous r\233compenserai. "
gameforge.main_quest_lv2._70_say = "Les chiens errants ne sont pas tr\232s forts, cela[ENTER]ne devrait pas \234tre trop difficile. Si vous[ENTER]n'arrivez pas \224 tuer quelques chiens errants,[ENTER]vous n'aurez aucune chance de survivre ici.[ENTER]Partez et commencez tout de suite. "
gameforge.main_quest_lv2._80_sayReward = "De temps en temps les villageois vous chargent de[ENTER]missions qui vous rapportent des points[ENTER]d'exp\233rience et des Yangs. Cela rapporte de[ENTER]chercher des gens pour vous donner des choses \224[ENTER]faire ! "
gameforge.main_quest_lv2._90_sayReward = "R\233compense pour l'\233limination des chiens errants[ENTER]Points d'exp\233rience\160: 550[ENTER]Yang\160: 1\160000[ENTER]Objet\160: %s, quantit\233\160: %s "
