gameforge.main_quest_lv27._10_makequestbutton = "D\233truisez la Metin Noire "
gameforge.main_quest_lv27._110_say = "Avez-vous d\233truit la pierre Metin? Merci ! Le[ENTER]village est sauv\233. D'o\249 viennent ces pierres ?[ENTER]Nous ne savons quasiment rien d'elles \224 part[ENTER]qu'elles causent \233norm\233ment de probl\232mes...[ENTER]J'ai entendu dire qu'Uriel le Sage a entrepris[ENTER]des recherches \224 leur sujet mais je ne sais pas[ENTER]ce qu'il a pu d\233couvrir. En tous cas vous avez[ENTER]fait du bon travail. "
gameforge.main_quest_lv27._120_sayTitle = "R\233compense : "
gameforge.main_quest_lv27._130_sayReward = "Vous avez re\231u 3.300.000 points d'exp\233rience.[ENTER]Vous avez re\231u 270.000 yangs.[ENTER]Vous avez re\231u un Livre de Ma\238tre. "
gameforge.main_quest_lv27._140_sayReward = "Vous avez re\231u : %s "
gameforge.main_quest_lv27._20_say = "Les d\233g\226ts caus\233s par les Pierres Metin[ENTER]deviennent vraiment catastrophiques. Le pays[ENTER]souffre. Les Pierres Metin doivent \234tre[ENTER]d\233truites\160! Allez voir le Capitaine. "
gameforge.main_quest_lv27._30_say = "Les d\233g\226ts caus\233s par les Pierres Metin[ENTER]deviennent vraiment catastrophiques. Le pays[ENTER]souffre. Les Pierres Metin doivent \234tre[ENTER]d\233truites\160! Allez voir le Capitaine. "
gameforge.main_quest_lv27._40_say = "J'ai entendu dire que vous faites du tr\232s bon[ENTER]travail. Les gens parlent de vous. Gr\226ce \224 moi[ENTER]nous vous avons trouv\233 la place qui vous[ENTER]convient\160! Ne vous \233nervez pas, je plaisante\160![ENTER]Hahaha. Je sais que vous \234tes dou\233.[ENTER]Les pierres Metin se r\233pandent. Il faut[ENTER]s'attendre \224 des ennuis. "
gameforge.main_quest_lv27._50_say = "Si les pierres Metin se r\233pandent, la population[ENTER]en souffrira. Nous devons donc les d\233truire. Je[ENTER]me demande parfois si la pr\233diction des chamanes[ENTER]\224 propos de la r\233surrection du Dieu Sung Mahi est[ENTER]vraie... Mais nous devons d'abord nous en tenir[ENTER]aux preuves. Pr\233venez-moi quand vous aurez[ENTER]d\233truit une pierre Metin ! "
gameforge.main_quest_lv27._60_sayTitle = "Mission: "
gameforge.main_quest_lv27._70_say = "La pierre Metin que vous devez d\233truire est[ENTER]appel\233e Metin Noire. Trouvez-la! "
gameforge.main_quest_lv27._80_say = "R\233cemment de plus en plus de chutes de pierres[ENTER]Metin ont \233t\233 aper\231ues. Nous devons arr\234ter la[ENTER]propagation de leurs radiations n\233gatives ![ENTER]D\233truisez une pierre Metin Noire. "
gameforge.main_quest_lv27._90_say = "Vous avez d\233truit la pierre Metin Noire.[ENTER]Retournez voir le Capitaine. "
gameforge.main_quest_lv3 = {}
gameforge.main_quest_lv3._100_say = "Bonjour. \199a doit \234tre le garde du village qui[ENTER]vous envoie. J'ai une mission assez simple pour[ENTER]vous. Mon p\232re a oubli\233 ce livre ici ce matin. Il[ENTER]en a besoin d'urgence. "
gameforge.main_quest_lv3._10_npcChat = "J'ai termin\233 ma premi\232re t\226che "
gameforge.main_quest_lv3._110_say = "Pourriez-vous apporter ce livre \224 mon p\232re? Je le[ENTER]ferais bien moi-m\234me mais je ne peux pas laisser[ENTER]le magasin sans surveillance. Si vous faites ceci[ENTER]pour moi je vous r\233compenserai bien. Mon p\232re[ENTER]vend des armures dans le village. "
