gameforge.main_quest_lv3._150_sayReward = "Apportez le livre au p\232re de la marchande. C'est[ENTER]lui le marchand d'armures. "
gameforge.main_quest_lv3._160_sayTitle = "Le marchand d'armures: "
gameforge.main_quest_lv3._170_say = "Vous avez l'air investi d'une mission ! Ah, c'est[ENTER]ma fille qui vous envoie ? Merci. J'ai besoin de[ENTER]ce livre pour fabriquer de nouvelles armures. "
gameforge.main_quest_lv3._180_say = "Ma fille doit \234tre tr\232s occup\233e si elle vous a[ENTER]envoy\233 me remettre ce livre. Voyons, quelle[ENTER]r\233compense serait appropri\233e? "
gameforge.main_quest_lv3._190_say = "Comme r\233compense, je vais vous donner quelques[ENTER]yangs, ils vous permettront de vous acheter un[ENTER]bon \233quipement. Cela devrait suffire, je pense.[ENTER]Merci pour votre aide. Je n'h\233siterai pas \224 faire[ENTER]appel \224 vous dans le futur. Et quand vous aurez[ENTER]besoin d'une nouvelle armure venez me voir. Mon[ENTER]magasin est toujours ouvert. "
gameforge.main_quest_lv3._200_sayReward = "Vous avez re\231u 850\160points d'exp\233rience.[ENTER]Vous avez re\231u 5\160000\160Yangs.[ENTER]Vous avez re\231u 20\160potions bleues. "
gameforge.main_quest_lv3._20_say = "Je suppose que la premi\232re mission vous a bien[ENTER]plu. Inutile de demander sans arr\234t une nouvelle[ENTER]mission. Revenez me voir quand vous aurez acquis[ENTER]plus d'exp\233rience, je vous en donnerai une. "
gameforge.main_quest_lv3._30_sendLetter = "Des nouvelles du Garde du Village "
gameforge.main_quest_lv3._40_sayReward = "Arr\234tez de chasser et allez voir le garde du[ENTER]village. Il a du travail pour vous. "
gameforge.main_quest_lv3._50_say = "Je suis content de vous voir. Je suppose que vous[ENTER]connaissez la marchande. Elle a besoin d'aide.[ENTER]Pourriez-vous vous en charger? Je suis s\251r qu'il[ENTER]n'y a rien de tr\232s grave et que vous serez tout \224[ENTER]fait en mesure de l'aider. "
gameforge.main_quest_lv3._60_say = "Pour votre information: la marchande vend des[ENTER]potions et d'autres objets qui pourront vous \234tre[ENTER]utiles dans le futur. Il est donc plus sage[ENTER]d'\234tre de son c\244t\233. Allez-y maintenant. "
