gameforge.main_quest_lv30 = {}
gameforge.main_quest_lv30._100_say = "Il y a des inscriptions sur le Monument de Hasun.[ENTER]Vous devriez vite aller voir. "
gameforge.main_quest_lv30._10_targetVid = "Trouvez Uriel "
gameforge.main_quest_lv30._110_say = "Uriel a raison : Il y avait vraiment des[ENTER]inscriptions sur le M\233morial. Vous n'avez pas pu[ENTER]les d\233chiffrer mais en avez fait une copie.[ENTER]Apportez vos notes \224 Uriel. "
gameforge.main_quest_lv30._120_say = "Avez-vous trouv\233 le Monument de Hasun ? Ah, vous[ENTER]en avez m\234me fait une copie, parfait ! Cette[ENTER]d\233couverte est historique ! Voyons. Hum .... Cela[ENTER]semble vraiment contenir des informations[ENTER]concernant les Pierres Metin. Mais je ne peux[ENTER]tout d\233chiffrer. Ces \233crits sont vraiment[ENTER]anciens, certains caract\232res trop vieux.[ENTER]Qu'allons-nous faire ? "
gameforge.main_quest_lv30._130_say = "Ah, j'ai une id\233e ! Connaissez-vous la Vall\233e de[ENTER]Seungryong ? Il y a un site ancien l\224-bas. Si[ENTER]vous y trouvez de vieilles inscriptions je pense[ENTER]pouvoir terminer de comprendre vos notes. Allez[ENTER]donc chercher le Monument de Seul Rong dans la[ENTER]Vall\233e de Seungryong. "
gameforge.main_quest_lv30._140_targetVid = "Le m\233morial de la Vall\233e de Seungryong "
gameforge.main_quest_lv30._150_say = "Uriel l'\233rudit a besoin de plus de textes anciens[ENTER]pour terminer de d\233chiffrer les lettres qu'il ne[ENTER]connait pas. Allez \224 la vall\233e de Seungryong et[ENTER]trouvez le Monument de Seul Rong. "
gameforge.main_quest_lv30._160_say = "Vous avez trouv\233 plus d'inscriptions ? Oh![ENTER]Merci, je vais pouvoir percer le secret des[ENTER]pierres Metin maintenant. Mes recherches[ENTER]pourraient aboutir plus t\244t que je ne le pensais.[ENTER]Merci, merci. Voici un gage de ma gratitude,[ENTER]acceptez-le je vous en prie. "
gameforge.main_quest_lv30._20_sendLetter = "Le secret des Pierres Metin "
gameforge.main_quest_lv30._30_say = "Uriel le sage a enfin des pistes concernant le[ENTER]secret des pierres Metin. Allez le voir. "
gameforge.main_quest_lv30._40_sayTitle = "Uriel: "
gameforge.main_quest_lv30._50_say = "Le capitaine vous a d\233j\224 envoy\233 \224 moi[ENTER]pr\233c\233demment. Vous me semblez tr\232s comp\233tent. Je[ENTER]dois vous demander de me rendre un service. Vous[ENTER]\234tes au courant pour les pierres Metin je suppose[ENTER]puisque vous en avez d\233j\224 d\233truit quelques-unes\160?[ENTER]Elles sont tomb\233es du ciel. Elles poss\232dent des[ENTER]forces mal\233fiques, elles provoquent des \233pid\233mies[ENTER]et rendent les animaux sauvages. Nous ne savons[ENTER]pas comment elles sont arriv\233es dans notre monde,[ENTER]ni de quoi elles sont faites. Ceci rend mes[ENTER]recherches difficiles. Il y a peu, j'ai enfin[ENTER]trouv\233 la cl\233 du myst\232re des pierres Metin. "
gameforge.main_quest_lv30._60_say = "Il y a une tablette d'un ancien empire dans une[ENTER]grotte du Donjon facile des Singes. Je crois que[ENTER]cette tablette nous livrera le secret des pierres[ENTER]Metin. Si vous pouviez m'amener ces informations,[ENTER]je serais peut-\234tre en mesure de percer le[ENTER]myst\232re des pierres Metin. Amenez-moi les[ENTER]informations inscrites sur les tablettes dans le[ENTER]Donjon facile des Singes. "
gameforge.main_quest_lv30._70_sayReward = "Vous avez re\231u 122\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 20\160000 Yangs.[ENTER]Vous avez re\231u un bracelet d'argent. "
gameforge.main_quest_lv30._80_targetVid = "Le m\233morial du Donjon facile des Singes "
gameforge.main_quest_lv30._90_say = "Uriel pense avoir trouv\233 quelque chose pouvant[ENTER]l'aider \224 travailler sur le probl\232me des Pierres[ENTER]Metin. Allez au Donjon facile des Singes et[ENTER]cherchez le Monument de Hasun. "
