gameforge.main_quest_lv32._10_sendLetter = "Le livre secret "
gameforge.main_quest_lv32._110_npcChat = "Les pages du livre secret "
gameforge.main_quest_lv32._120_sayTitle = "Marchand ambulant: "
gameforge.main_quest_lv32._130_say = "Le monde entier est ravag\233 par les \233v\232nements et[ENTER]le commerce est devenu difficile. Que voulez-vous[ENTER]acheter? Ah, c'est Uriel le sage qui vous envoie?[ENTER]C'est un de mes bons clients, toujours \224 la[ENTER]recherche de livres anciens de partout. Il me[ENTER]fait rire. Ha Ha Ha. Vous voulez donc savoir[ENTER]quelque chose sur les livres anciens... Hm... Les[ENTER]livres anciens... "
gameforge.main_quest_lv32._140_say = "J'ai bien entendu quelque chose il y a quelques[ENTER]jours mais je ne vous le raconterai pas sans[ENTER]contrepartie. Si vous acc\233dez \224 ma demande, je[ENTER]vous r\233v\232lerai cette information. Ces temps-ci,[ENTER]le commerce d'armes bat son plein. Mais je ne[ENTER]peux pas procurer une telle quantit\233 d'armes.[ENTER]Tout le monde recherche des armes. Au lieu de[ENTER]tourner ici, \224 ne rien faire, procurez moi plut\244t[ENTER]20 \233p\233es d'argent+0.[ENTER][ENTER]D\232s que vous me les aurez amen\233es, je vous[ENTER]donnerai les informations que vous d\233sirez[ENTER]obtenir. "
gameforge.main_quest_lv32._150_targetVid = "Trouvez le Marchand Ambulant "
gameforge.main_quest_lv32._160_sayTitle = "Vous avez 20 \233p\233es en argent +0 "
gameforge.main_quest_lv32._170_say = "Le Marchand Ambulant a entendu parler des pages.[ENTER]Apportez-lui 20 \201p\233es en argent +0, il vous dira[ENTER]alors ce qu'il sait. "
gameforge.main_quest_lv32._180_sayTitle = "Trouvez 20 \233p\233es en argent +0 "
gameforge.main_quest_lv32._190_say = "Le Marchand Ambulant a entendu parler des pages[ENTER]mais il refuse de vous donner les informations[ENTER]gratuitement. Apportez-lui 20 \201p\233es en argent+0[ENTER]afin d'obtenir l'information. "
gameforge.main_quest_lv32._200_npcChat = "J'ai les \233p\233es. "
gameforge.main_quest_lv32._20_targetVid = "Cherchez Uriel le sage "
gameforge.main_quest_lv32._210_say = "C'est fantastique. Vous \234tes plus dou\233 que je ne[ENTER]le pensais. Gr\226ce \224 vous je vais faire des[ENTER]affaires. Comme promis je vais vous dire ce que[ENTER]je sais. Il y a quelque temps je suis pass\233 pr\232s[ENTER]d'un pavillon et d'un m\233morial. Je me suis repos\233[ENTER]au pied du m\233morial et j'y ai trouv\233 un morceau[ENTER]de papier coinc\233. "
gameforge.main_quest_lv32._220_say = "\192 ce moment l\224 j'ignorais ce que c'\233tait. Mais l\224[ENTER]je pense qu'il peut s'agir d'une des pages que[ENTER]vous cherchez. Le nom du monument .... Ah oui,[ENTER]Weo ! Monument de Weo, c'est cela ! Il se trouve[ENTER]au village voisin. Vous devriez aller jeter un[ENTER]\156il ! "
gameforge.main_quest_lv32._230_sayTitle = "Marchand ambulant: "
gameforge.main_quest_lv32._240_say = "Apportez-moi les 20 \233p\233es en argent +0 et je vous[ENTER]donnerai l'information \224 propos des pages[ENTER]anciennes... "
gameforge.main_quest_lv32._250_sendLetter = "Cherchez la premi\232re page "
gameforge.main_quest_lv32._260_targetVid = "Un monument pr\232s du pavillon "
gameforge.main_quest_lv32._270_say = "Le Marchand Ambulant a vu une vieille page au[ENTER]pied du Monument de Weo lorsqu'il se reposait au[ENTER]pavillon pr\232s du Monument.[ENTER]Allez au Monument de Weo au village voisin et[ENTER]cherchez la page. "
gameforge.main_quest_lv32._280_npcChat = "Le monument Weol "
gameforge.main_quest_lv32._290_say = "C'est le monument. La voil\224\160! J'ai trouv\233 la[ENTER]page\160!!! "
gameforge.main_quest_lv32._300_sendLetter = "La premi\232re page "
gameforge.main_quest_lv32._30_say = "Uriel a besoin de vous concernant ses recherches[ENTER]sur un vieux livre secret. Allez le voir pour[ENTER]savoir comment l'aider. "
gameforge.main_quest_lv32._310_targetVid = "Cherchez Uriel le sage "
gameforge.main_quest_lv32._320_sayTitle = "Vous avez trouv\233 la premi\232re page. "
gameforge.main_quest_lv32._330_say = "Vous avez suivi les conseils du Marchand Ambulant[ENTER]et avez trouv\233 la premi\232re des pages manquantes.[ENTER]Apportez la \224 Uriel. "
gameforge.main_quest_lv32._340_say = "Avez-vous trouv\233 cette fameuse page ? Oh, vous[ENTER]l'avez c'est formidable ! Voyons ce qu'elle[ENTER]contient... Humm on dirait un journal intime ...[ENTER]\201coutez "
gameforge.main_quest_lv32._350_sayTitle = "Premi\232re page du livre : "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop de l'empire Taejo a agrandi son[ENTER]territoire gr\226ce \224 ses conqu\234tes. Il veut[ENTER]conqu\233rir tous les territoires gr\226ce \224 son arm\233e[ENTER]mais ce n'est pas encore chose faite. Nous devons[ENTER]\233viter qu'il r\233ussisse \224 conqu\233rir notre pays. Il[ENTER]n'y a pas 36 solutions. C'est pourquoi nous avons[ENTER]d\233cid\233 d'utiliser la sorcellerie interdite ! "
gameforge.main_quest_lv32._370_sayTitle = "Suite de la premi\232re page du livre : "
gameforge.main_quest_lv32._380_sayReward = "C'est notre seule chance de survie. Nous ne[ENTER]savons pas, si nous r\233ussirons mais en tout cas[ENTER]nous devons absolument essayer. Avant qu'ils ne[ENTER]nous attaquent, nous devons en apprendre[ENTER]davantage sur la sorcellerie interdite. Les[ENTER]anciens disent que l'on peut trouver des[ENTER]informations sur la sorcellerie interdite dans la[ENTER]vall\233e du dragon. "
gameforge.main_quest_lv32._390_say = "Le contenu me montre qu'il y avait de vieilles[ENTER]croyances dans ce pays. Avant que Lee Seop de[ENTER]l'empire Taejo n'unisse les pays, chacun avait[ENTER]ses caract\233ristiques bien particuli\232res.[ENTER]D'apr\232s mes informations, chaque pays avait sa[ENTER]religion et ses croyances propres. Les guildes[ENTER]cr\233\233es dans ces pays repr\233sentaient les couches[ENTER]sup\233rieures de leurs soci\233t\233s respectives. "
gameforge.main_quest_lv32._400_say = "C'est probablement le chef d'une guilde qui a d\251[ENTER]\233crire ce vieux livre. Allez dans la vall\233e du[ENTER]dragon, vous y trouverez sans doute beaucoup[ENTER]d'informations. Peut-\234tre m\234me y trouverez vous[ENTER]d'autres pages perdues de ce livre. Il y a un[ENTER]chasseur dans le village voisin qui conna\238t tr\232s[ENTER]bien dans la vall\233e du dragon. Vous devriez aller[ENTER]le voir avant d'y aller, peut-\234tre en sait-il[ENTER]plus sur les pages perdues. "
gameforge.main_quest_lv32._40_say = "Bonjour. Ce que vous m'avez amen\233 la derni\232re[ENTER]fois m'a beaucoup aid\233. J'ai r\233ussi \224 bien[ENTER]avancer gr\226ce \224 votre aide pr\233cieuse. Mais j'ai[ENTER]un probl\232me pour l'instant. Lors de mes[ENTER]recherches sur la femme diable et les m\233t\233orites,[ENTER]j'ai d\233couvert ce vieux livre. Il a \233t\233 r\233dig\233[ENTER]dans une langue ancienne et ce n'est pas simple[ENTER]de le d\233chiffrer. Il me semble qu'il renferme des[ENTER]informations importantes sur les causes des[ENTER]changements qui nous affectent actuellement. "
gameforge.main_quest_lv32._410_say = "Tenez, votre r\233compense pour la premi\232re page ! "
gameforge.main_quest_lv32._420_sayReward = "Vous avez re\231u 1.000.000 de points d'exp\233rience. "
gameforge.main_quest_lv32._430_sayReward = "Vous recevez 50\160000 Yangs. "
gameforge.main_quest_lv32._440_sayReward = "Vous avez re\231u une Larme de la D\233esse. "
