gameforge.main_quest_lv32._460_targetVid = "Trouvez le chasseur Yang-Shin "
gameforge.main_quest_lv32._470_sayTitle = "Demandez \224 Yang-Shin pour la Vall\233e "
gameforge.main_quest_lv32._480_say = "Sur la premi\232re page du livre secret est[ENTER]mentionn\233 la Vall\233e du Dragon. Uriel a entendu[ENTER]des choses la dessus mais ne sait pas o\249 elle se[ENTER]situe. Allez au village voisin et questionnez[ENTER]Yang-Shin. "
gameforge.main_quest_lv32._490_sayReward = "Conseil : Le chasseur est dans le village voisin. "
gameforge.main_quest_lv32._500_npcChat = "Informations sur la Vall\233e du Dragon "
gameforge.main_quest_lv32._50_say = "Le probl\232me est que les pages sont d\233chir\233es.[ENTER]Cela rend le d\233chiffrage tr\232s difficile. Ce livre[ENTER]a d\251 passer de main en main et c'est la raison[ENTER]pour laquelle il est si endommag\233. Il manque 13[ENTER]pages dans ce livre, pouvez-vous me les procurer?[ENTER]Elles contiennent sans doute des informations[ENTER]importantes qui nous permettront de terminer[ENTER]cette guerre. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Vous voulez des renseignements sur la vall\233e du[ENTER]dragon? Pourquoi voulez-vous aller dans un[ENTER]endroit si dangereux? La vall\233e regorge de[ENTER]soldats orcs et en plus il y a une secte secr\232te.[ENTER]M\234me moi, chasseur exp\233riment\233, je n'aime pas y[ENTER]aller. Je pense que ce serait mieux pour vous de[ENTER]ne pas y aller. "
gameforge.main_quest_lv32._530_say = "Quoi? Vous recherchez ces vieilles pages? Hmmm![ENTER]Un jour un autre chasseur m'a dit que les[ENTER]sorciers orcs \233lites poss\233daient des vieux[ENTER]papiers. Savoir si c'est vrai... Si vous \234tes si[ENTER]curieux, allez voir par vous-m\234me. C'est un[ENTER]endroit dangereux, je vous l'ai d\233j\224 dit donc[ENTER]faites bien attention \224 vous! "
gameforge.main_quest_lv32._540_sendLetter = "\192 la recherche de la seconde page "
gameforge.main_quest_lv32._550_say = "Comme l'a dit le chasseur, les sorciers d'\233lite[ENTER]des orcs demeurent dans la vall\233e des dragons.[ENTER]Ils doivent poss\233der la deuxi\232me page que vous[ENTER]cherchez. Tuez les sorciers d'\233lite des orcs et[ENTER]procurez-vous cette deuxi\232me page. Apr\232s,[ENTER]ramenez-la au sage Uriel. "
gameforge.main_quest_lv32._560_sendLetter = "La deuxi\232me page "
gameforge.main_quest_lv32._570_sayTitle = "Trouvez la seconde page "
gameforge.main_quest_lv32._580_say = "En tuant un Sorcier Orc \201lite vous avez trouv\233 le[ENTER]seconde pas du livre secret. Apportez-la \224 Uriel. "
gameforge.main_quest_lv32._590_say = "C'est la deuxi\232me page? Voyons voir. Ce n'est pas[ENTER]facile \224 d\233chiffrer. Voici ce que \231a dit : "
gameforge.main_quest_lv32._600_sayTitle = "Deuxi\232me page : "
gameforge.main_quest_lv32._60_say = "Une fois que vous aurez trouv\233 une des vieilles[ENTER]pages, apportez-la moi et j'essaierai de la[ENTER]d\233chiffrer. Hummm... O\249 commencer vos recherches?[ENTER]Il y a quelque temps de \231a, j'ai entendu parler[ENTER]d'un marchand ambulant dans le village voisin, il[ENTER]avait trouv\233 une vieille page du livre. Allez le[ENTER]voir et voyez si vous pouvez apprendre quelque[ENTER]chose. "
gameforge.main_quest_lv32._610_sayReward = "Les magiciens obscurs ont \233t\233 d\233couverts. Ils se[ENTER]sont cach\233s dans la vall\233e du dragon. Ils[ENTER]connaissent bien la magie interdite qu'ils se[ENTER]sont transmise de g\233n\233ration en g\233n\233ration. Apr\232s[ENTER]avoir lu les pages qu'ils nous ont donn\233, nous[ENTER]nous sommes rendus compte que la sorcellerie[ENTER]interdite ne peut se faire que dans un endroit[ENTER]tr\232s sp\233cial. Ce lieu doit \234tre empli d'\233nergie[ENTER]mal\233fique. Y a-t-il un tel endroit? Il ne nous[ENTER]reste que peu de temps, il faut trouver trouver[ENTER]le plus rapidement possible un lieu ad\233quat. "
gameforge.main_quest_lv32._620_say = "Hmmm, pour la sorcellerie interdite il faut un[ENTER]lieu rempli d'\233nergie mal\233fique? Quel pourrait[ENTER]\234tre un endroit pareil ? O\249 pourrait-il \234tre ?[ENTER]Hum ... S\251rement le temple sombre. C'est un[ENTER]endroit que tous \233vitent, m\234me les animaux ne[ENTER]veulent pas y aller. C'est un lieu o\249 les[ENTER]puissances myst\233rieuses r\232gnent sur toutes sortes[ENTER]de monstres. "
gameforge.main_quest_lv32._630_say = "Qui plus est, il existe un lien entre les[ENTER]puissances myst\233rieuses et la sorcellerie[ENTER]interdite. La cl\233 de tout ceci se trouve dans le[ENTER]temple de Hwang. Trouvez la pour que nous[ENTER]puissions comprendre ces secrets.[ENTER][ENTER]Voici votre r\233compense pour la deuxi\232me page... "
gameforge.main_quest_lv32._640_sayReward = "Vous avez re\231u 1.000.000 de points d'exp\233rience. "
gameforge.main_quest_lv32._650_sayReward = "Vous recevez 50\160000 Yangs. "
gameforge.main_quest_lv32._660_sayReward = "Vous avez re\231u 10 Drapeaux Blancs. "
gameforge.main_quest_lv32._670_sendLetter = "La troisi\232me page "
gameforge.main_quest_lv32._680_say = "Vous avez apport\233 les deux premi\232res pages du[ENTER]livre secret \224 Uriel. La page suivante se trouve[ENTER]dans le Temple Hwang. "
gameforge.main_quest_lv32._690_sayReward = "Information : Cette s\233rie de qu\234tes continuera[ENTER]quand vous aurez atteint le niveau 40. "
gameforge.main_quest_lv32._70_targetVid = "Allez voir le marchand ambulant "
gameforge.main_quest_lv32._80_sayTitle = "Cherchez les pages du livre secret. "
gameforge.main_quest_lv32._90_say = "Uriel le sage dit qu'il a entendu parler d'un[ENTER]marchand ambulant qui poss\232derait une des[ENTER]vieilles pages. Allez voir ce marchand et[ENTER]demandez-le lui. Vous le trouverez dans le second[ENTER]village. "
