gameforge.main_quest_lv40._10_sayTitle = "Le Temple Obscur "
gameforge.main_quest_lv40._110_sayReward = "Vous recevez 50\160000 Yangs. "
gameforge.main_quest_lv40._120_sayReward = "Vous avez aussi re\231u une B\233n\233diction de Vie. "
gameforge.main_quest_lv40._130_sendLetter = "Dans le d\233sert de Yongbi "
gameforge.main_quest_lv40._140_targetVid = "La recherche du monument "
gameforge.main_quest_lv40._150_targetVid = "\192 la recherche du monument Wha "
gameforge.main_quest_lv40._160_sayTitle = "\192 la recherche de la quatri\232me page "
gameforge.main_quest_lv40._170_say = "Uriel le sage pense qu'une autre page doit se[ENTER]trouver dans les donjons des singes du d\233sert de[ENTER]Yongbi. Il y a un monument l\224-bas, peut-\234tre que[ENTER]la quatri\232me page s'y trouve. Allez dans le[ENTER]d\233sert de Yongbi et cherchez le monument au[ENTER]donjon des Singes. Astuce : Le guetteur dans le[ENTER]d\233sert de Yongbi peut vous aider a rejoindre les[ENTER]donjons des singes. "
gameforge.main_quest_lv40._180_say = "C'est le Monument Wha ! "
gameforge.main_quest_lv40._190_say = "Il n'y a rien ici. Il faut que j'aille chercher[ENTER]un autre Monument plus loin. "
gameforge.main_quest_lv40._200_npcChat = "\192 la recherche du monument Su "
gameforge.main_quest_lv40._20_say = "Uriel cherche les pages d'un vieux journal intime.Vous en avez d\233j\224 trouv\233 deux. \192 pr\233sent, la[ENTER]chasse aux pages du vieux livre secret continue.[ENTER]Nos derni\232res d\233couvertes nous ont indiqu\233 que[ENTER]les fiers fanatiques funestes vivant dans le[ENTER]Temple Hwang d\233tiennent la prochaine. Bonne[ENTER]chance ! "
gameforge.main_quest_lv40._210_say = "Ce doit \234tre \231a ! Le monument Su. "
gameforge.main_quest_lv40._220_say = "Il n'y a rien ici. Il faut que j'aille chercher[ENTER]un autre Monument plus loin. "
gameforge.main_quest_lv40._230_sendLetter = "La quatri\232me page "
gameforge.main_quest_lv40._240_sayTitle = "Quatri\232me page trouv\233e "
gameforge.main_quest_lv40._250_say = "Les m\233moriaux antiques s'av\232rent \234tre de fid\232les[ENTER]gardiens de leurs tr\233sors : Vous avez trouv\233 la[ENTER]quatri\232me page au Donjon. Apportez-la \224 Uriel le[ENTER]sage. "
gameforge.main_quest_lv40._260_npcChat = "La quatri\232me page "
gameforge.main_quest_lv40._270_say = "Oh! Vous avez trouv\233 la quatri\232me page. Esp\233rons[ENTER]qu'elle va nous apporter quelques[ENTER]\233claircissements. "
gameforge.main_quest_lv40._280_sayTitle = "Quatri\232me page : "
gameforge.main_quest_lv40._290_sayReward = "Je suis dans la grand caverne ou vivent les[ENTER]singes, mais m\234me ici l'\233nergie n\233gative n'est[ENTER]pas suffisante. Le temps passe... Il n'y a pas de[ENTER]m\233thode sp\233ciale. Tout le monde tremble de peur.[ENTER]Pourrons-nous trouver le bon endroit avant que la[ENTER]cavalerie de Lee Seop n'arrive dans l'empire de[ENTER]Taejo? Ahh, il faut que j'arr\234te de penser \224 ces[ENTER]horreurs. "
gameforge.main_quest_lv40._300_sayTitle = "Suite de la quatri\232me page : "
gameforge.main_quest_lv40._30_sayTitle = "Quatri\232me page trouv\233e "
gameforge.main_quest_lv40._310_sayReward = "Je dois trouver le prochain lieu le plus vite[ENTER]possible. Rien n'est encore perdu. Je vais[ENTER]essayer au Donjon des Araign\233es. Peut-\234tre que[ENTER]cette fois-ci nos souhaits vont enfin se[ENTER]r\233aliser... "
gameforge.main_quest_lv40._320_say = "Hum. Le Donjon des Singes n'est pas l'endroit que[ENTER]nous cherchons... Selon ce qui est \233crit nous[ENTER]devons aller dans celui des araign\233es.[ENTER]mais nous devons d'abord r\233gler une affaire[ENTER]importante : le capitaine est tr\232s inquiet, car[ENTER]beaucoup d'\233trangers tra\238nent aux alentours du[ENTER]village et posent des questions \233tranges.[ENTER]Vous devriez aller le voir et lui demander ce[ENTER]qu'il se passe. "
gameforge.main_quest_lv40._330_say = "Je ne sais pas pourquoi, mais je ne me sens pas[ENTER]tr\232s bien... Voyons ce que je peux apprendre du[ENTER]Capitaine. Oh, J'ai presque failli oublier... Je[ENTER]vous dois une r\233compense pour la quatri\232me page. "
gameforge.main_quest_lv40._340_sayReward = "Vous avez re\231u 2.000.000 de points d'exp\233rience. "
gameforge.main_quest_lv40._350_sayReward = "Vous avez aussi obtenu une B\233n\233diction magique "
gameforge.main_quest_lv40._360_sendLetter = "D'inqui\233tants \233trangers "
gameforge.main_quest_lv40._370_targetVid = "Allez voir le capitaine "
gameforge.main_quest_lv40._380_sayTitle = "Allez voir le capitaine pour en apprendre plus[ENTER]sur les \233trangers. "
gameforge.main_quest_lv40._390_say = "Il parait que de nombreux \233trangers sont[ENTER]r\233cemment arriv\233s au village. Il semblerait[ENTER]qu'ils enqu\234tent sur les monuments. Le Capitaine[ENTER]a prit des mesures contre \231a. Allez voir le[ENTER]Capitaine pour en apprendre davantage. "
gameforge.main_quest_lv40._400_npcChat = "Les \233trangers dans le village "
gameforge.main_quest_lv40._40_say = "Les pr\233somptions d'Uriel concernant les fiers[ENTER]fanatiques funestes \233taient justes. Ils[ENTER]d\233tenaient la troisi\232me page. Apportez-la \224[ENTER]Uriel. "
gameforge.main_quest_lv40._410_say = "Il y a une augmentation du nombre d'\233trangers qui[ENTER]viennent dans notre village. Ils am\232nent un tas[ENTER]de probl\232mes avec eux, et demandent aux habitant[ENTER]des renseignements sur les monuments et les vieux[ENTER]\233crits. Ce sont des personnes tr\232s inform\233es,[ENTER]mais qui disent ne rien connaitre. Ils sont un[ENTER]danger pour nous.[ENTER]Nous vivons des temps durs, domin\233s par la[ENTER]guerre. Les \233trangers n'apportent que des[ENTER]probl\232mes avec eux. "
gameforge.main_quest_lv40._420_say = "L'enqu\234te a prouv\233 que Nakajima \233tait en relation[ENTER]avec eux. Essayez de trouver ce que veulent les[ENTER]\233trangers ici. "
gameforge.main_quest_lv40._430_sendLetter = "Allez voir Nakajima "
gameforge.main_quest_lv40._440_say = "Le Capitaine pense qu'il y a des similitudes[ENTER]entre les \233trangers qui posent tout un tas de[ENTER]questions \224 propos des m\233moriaux et Nakajima.[ENTER]Allez voir Nakajima afin de d\233couvrir ce qu'il[ENTER]sait. Vous le trouverez \224 l'ext\233rieur du second[ENTER]village. "
gameforge.main_quest_lv40._450_npcChat = "Connaissez-vous les \233trangers ? "
gameforge.main_quest_lv40._460_sayTitle = "Nakajima: "
gameforge.main_quest_lv40._470_say = "Excusez-moi? Quelle sorte de question est ce ?[ENTER]Pour quelle raison j'aurai vu des \233trangers[ENTER]louches... ? Oups. Je suis d\233sol\233. Je ne peux pas[ENTER]t'aider. C'est dur de se trouver un travail et de[ENTER]s'assumer par ces temps de guerre... "
gameforge.main_quest_lv40._480_say = "Oui, je l'admets. Mais uniquement parce qu'ils[ENTER]m'ont promis beaucoup de yangs. Je ne sais pas ce[ENTER]que veulent ces \233trangers. Mais ils m'ont confi\233[ENTER]une mission : je dois tuer le Capitaine Bestial. "
gameforge.main_quest_lv40._490_say = "Vous en saurez surement plus gr\226e au Capitaine[ENTER]bestial. Les \233trangers voulaient vraiment que je[ENTER]le tue. Oh, j'ai une id\233e : Pourquoi n'allez-vous[ENTER]pas le tuer pour moi ? Qu'en dites-vous ? "
gameforge.main_quest_lv40._500_sendLetter = "Tuer le Capitaine bestial "
gameforge.main_quest_lv40._50_say = "Oh, tu as trouv\233 la partie suivante ?! C'est la[ENTER]troisi\232me page. Laisse-moi regarder ce qu'elle[ENTER]dit. "
gameforge.main_quest_lv40._510_say = "Apr\232s une enqu\234te d\233taill\233e, j'ai d\233couvert que[ENTER]le Capitaine Bestial est la raison des soudaines[ENTER]arriv\233es de tant d'\233trangers. Je dois tuer[ENTER]plusieurs fois ce Capitaine Bestial afin de[ENTER]comprendre le contenu des pages. Le Capitaine[ENTER]Bestial peut \234tre trouv\233 \224 l'ext\233rieur du second[ENTER]village. "
gameforge.main_quest_lv40._520_sendLetter = "Vous avez trouv\233 la cinqui\232me page "
gameforge.main_quest_lv40._530_say = "Apr\232s une enqu\234te d\233taill\233e, j'ai d\233couvert que[ENTER]le Capitaine Bestial est la raison des arriv\233es[ENTER]de tant d'\233trangers. Apr\232s \231a, j'ai tu\233 le[ENTER]Capitaine, et j'ai re\231u une autre page. C'est la[ENTER]cinqui\232me page du livre secret. Cette page[ENTER]contient des caract\232res que je ne peux[ENTER]d\233chiffrer. Le mieux est que je le montre \224[ENTER]Uriel, lui il saura le d\233chiffrer pour moi. "
gameforge.main_quest_lv40._540_sayTitle = "La cinqui\232me page "
gameforge.main_quest_lv40._550_sayReward = "Un conseil : Vous pourrez montrer cette cinqui\232me[ENTER]page uniquement lorsque vous aurez atteint le[ENTER]niveau 47. Faites attention \224 cette page jusque[ENTER]l\224. "
gameforge.main_quest_lv40._60_sayTitle = "Troisi\232me page : "
gameforge.main_quest_lv40._70_sayReward = "Nous sommes arriv\233s \224 un endroit ou l'\233nergie[ENTER]n\233gative est transform\233e. Mais \231a ne suffit[ENTER]pas... Ou pouvez-vous am\233liorer cette[ENTER]sorcellerie\160? Une nouvelle information nous[ENTER]apprend qu'il y a un endroit cach\233 dans le d\233sert[ENTER]de Yongbi.[ENTER]Plein d'espoir, nous allons prendre le[ENTER]t\233l\233porteur pour aller au d\233sert de Yongbi. "
gameforge.main_quest_lv40._80_say = "Hmmm... Ils n'ont pas pu atteindre leur objectif[ENTER]dans la Vall\233e du Dragon...[ENTER]Et maintenant, le d\233sert de Yongbi\160?[ENTER]Vous y trouverez peu d'\234tres humains et le[ENTER]territoire est en grande partie inexplor\233. C'est[ENTER]tr\232s compliqu\233. O\249 se sont-ils exactement[ENTER]t\233l\233port\233s ? Je pense que le mieux est d'aller[ENTER]directement au Donjon des Singes Jungsun Dong.[ENTER]C'est une caverne profonde dans laquelle on peut[ENTER]facilement accumuler de l'\233nergie mal\233fique. "
gameforge.main_quest_lv40._90_say = "S'il vous pla\238t, allez au Donjon Jungsun et[ENTER]cherchez d'autres monuments. Avec un peu de[ENTER]chance, vous y trouverez d'autres pages. Oh,[ENTER]n'oubliez pas votre r\233compense pour la troisi\232me[ENTER]page. "
gameforge.main_quest_lv47 = {}
gameforge.main_quest_lv47._100_sayTitle = "La page au Donjon des Araign\233es "
gameforge.main_quest_lv47._10_sayTitle = "La page du Capitaine Bestial "
gameforge.main_quest_lv47._110_say = "Uriel pense qu'on peut trouver de nouvelles[ENTER]informations sur cette magie secr\232te dans le[ENTER]Donjon des Araign\233es.[ENTER]Peut-\234tre y trouverons-nous un monument comme au[ENTER]Donjon des Singes aussi.[ENTER][ENTER]Pour trouver le Donjon des Araign\233es, vous devez[ENTER]traverser le D\233sert de Yongbi. "
gameforge.main_quest_lv47._120_npcChat = "Le monument de Mok "
gameforge.main_quest_lv47._130_say = "Vraiment ! Il y a bien un monument, et une page ![ENTER]Il faut vite l'apporter \224 Uriel. "
gameforge.main_quest_lv47._140_sayTitle = "Sixi\232me page trouv\233e "
gameforge.main_quest_lv47._150_say = "Vous avez trouv\233 un autre monument au Donjon des[ENTER]Araign\233es et la sixi\232me page y \233tait cach\233e.[ENTER]Apportez la \224 Uriel. "
gameforge.main_quest_lv47._160_npcChat = "La sixi\232me page "
gameforge.main_quest_lv47._170_say = "Comment \233tait le donjon des araign\233es? Avez vous[ENTER]trouv\233 la sixi\232me page? C'est bien!! Laissez-moi[ENTER]regarder quelles informations nous pouvons tirer[ENTER]de la sixi\232me page. C'est bien que vous l'ayez[ENTER]trouv\233. J'ai entendu dire que d'autres[ENTER]cherchaient toujours le secret. Depuis que[ENTER]beaucoup tentent de le trouver, les informations[ENTER]sont devenues tr\232s importantes. "
gameforge.main_quest_lv47._180_say = "Ohh, cette page est tr\232s difficile \224 lire.[ENTER]J'aurais besoin de plus de temps que d'habitude[ENTER]pour la d\233chiffrer. Le contenu semble tr\232s[ENTER]important. Peut \234tre pourrons nous prouver que la[ENTER]magie secr\232te peut nous \234tre utile. Ce n'est pas[ENTER]sans raison qu'il est d\233conseill\233 de l'utiliser. "
gameforge.main_quest_lv47._190_say = "J'ai besoin de plus de temps pour d\233chiffrer la[ENTER]page. En attendant, tu devrais aller voir le[ENTER]musicien Yu-Hwan. J'ai entendu qu'il avait des[ENTER]informations concernant notre recherche. Dans le[ENTER]m\234me temps, je vais me concentrer sur la sixi\232me[ENTER]page. Dans tout les cas, vous pouvez r\233cup\233rer la[ENTER]r\233compense pour avoir trouv\233 la sixi\232me page. "
gameforge.main_quest_lv47._200_sayReward = "Vous avez re\231u 3.000.000 de points d'exp\233rience. "
gameforge.main_quest_lv47._20_say = "Au niveau 40 tu as trouv\233 la 5i\232me page du livre[ENTER]secret. Tu devrais la donner \224 Uriel aussi vite[ENTER]que possible. "
gameforge.main_quest_lv47._210_sayReward = "Vous avez re\231u 75.000 yangs. "
gameforge.main_quest_lv47._220_sayReward = "Vous avez re\231u une B\233n\233diction du Dragon. "
gameforge.main_quest_lv47._230_sendLetter = "Allez voir Yu-Hwan "
gameforge.main_quest_lv47._240_targetVid = "Trouvez le musicien Yu-Hwan "
gameforge.main_quest_lv47._250_sayTitle = "Les forces secr\232tes "
gameforge.main_quest_lv47._260_say = "Il est possible que le musicien Yu-Hwan soit au[ENTER]courant de quelque chose \224 propos des pages.[ENTER]Allez lui demander. "
gameforge.main_quest_lv47._270_npcChat = "Des nouvelles ? "
gameforge.main_quest_lv47._280_say = "Profitons de la vie, elle est si courte !. Ah,[ENTER]c'est encore vous. Vous \234tes surement envoy\233 par[ENTER]Uriel, il m'avait pr\233venu. Dans tous les empires,[ENTER]des gens sont \224 la recherche de quelque chose[ENTER]d'important. Malheureusement, personne n'a su me[ENTER]dire exactement de quoi il s'agit. "
gameforge.main_quest_lv47._290_say = "Seule une guerre peut provoquer une telle crainte[ENTER]en vous. Vous devriez toujours \234tre pr\233par\233 \224 la[ENTER]force de votre ennemi. R\233cemment, certaines[ENTER]informations ont \233t\233 entendues. J'ai entendu dire[ENTER]que les Brigands du D\233sert ont vol\233 certaines[ENTER]choses qui pourraient \234tre d'une grande[ENTER]importance pour vous. Peut-\234tre devriez-vous[ENTER]aller les bousculer un peu. "
gameforge.main_quest_lv47._300_say = "Les Hors la loi du d\233sert sont de dangereuses[ENTER]b\234tes. Faites attention, mais je pense que si[ENTER]vous les battez \231a vous rapportera. Bonne chance! "
gameforge.main_quest_lv47._30_npcChat = "La cinqui\232me page "
gameforge.main_quest_lv47._310_sendLetter = "Les hors la loi du d\233sert "
gameforge.main_quest_lv47._320_sayTitle = "La qu\234te de l'information secr\232te "
gameforge.main_quest_lv47._330_say = "Uriel a dit que les informations \224 propos de la[ENTER]magie peuvent \234tre tr\232s importantes. Le musicien[ENTER]nous a dit que certaines de ces informations[ENTER]pouvaient se trouver gr\226ce aux hors la loi du[ENTER]d\233sert. Nous devrions aller les affronter et tuer[ENTER]quelques hors-la-loi dans le d\233sert. "
gameforge.main_quest_lv47._340_sendLetter = "Septi\232me page trouv\233e "
gameforge.main_quest_lv47._350_targetVid = "Trouvez le musicien Yu-Hwan "
gameforge.main_quest_lv47._360_say = "Gr\226ce aux informations que Yu-Hwan vous a[ENTER]transmises, vous avez trouv\233 la septi\232me page au[ENTER]D\233sert sur les Hors la loi.[ENTER]Allez dire \224 Yu-hWan que ses informations \233taient[ENTER]exactes. "
gameforge.main_quest_lv47._370_say = "Vos yeux sont aussi beau qu'un lac de montagne...[ENTER]Ah... c'est vous. Avez vous trouv\233 les[ENTER]informations aupr\232s des hors la loi du d\233sert ?[ENTER]Quoi ? un bout de papier...[ENTER]Je ne peux rien faire avec \231a. Vous devriez le[ENTER]donner \224 Uriel le sage, il saura quoi en faire.[ENTER]Saluez le pour moi. "
gameforge.main_quest_lv47._380_sendLetter = "Allez voir Uriel "
gameforge.main_quest_lv47._390_targetVid = "Allez voir Uriel "
gameforge.main_quest_lv47._400_sayTitle = "La septi\232me page "
gameforge.main_quest_lv47._40_say = "Vous avez trouv\233 la cinqui\232me page. Bien. Laissez[ENTER]moi regarder. Je vais essayer de la d\233crypter. "
gameforge.main_quest_lv47._410_say = "Vous avez trouv\233 la septi\232me page. Apportez la \224[ENTER]Uriel. "
gameforge.main_quest_lv47._420_say = "Bonne nouvelle, le d\233chiffrage de la sixi\232me page[ENTER]est d\233j\224 fini. Quoi? Vous en avez trouv\233 une[ENTER]autre? Parfait, vous \234tes tr\232s fort. Je ne peux[ENTER]pas d\233chiffrer au rythme ou vous les trouvez.[ENTER]Oh!? Dans cette langue ? Ou l'avez vous trouv\233e ?[ENTER]Cette \233criture et ce langage sont commun\233ment[ENTER]utilis\233s dans la famille imp\233riale. "
gameforge.main_quest_lv47._430_say = "\201tant donn\233 que ces caract\232res ont \233t\233 utilis\233[ENTER]par peu de gens, et tr\232s rarement, il est[ENTER]difficile de les comprendre... Mais j'aime les[ENTER]challenges. Les Hors la Loi du d\233sert ont vol\233[ENTER]cette page aux \233trangers ? Cela signifie t-il que[ENTER]les \233trangers comprennent ces caract\232res ? Si \231a[ENTER]continue comme \231a, nous devrons faire attention \224[ENTER]ne manquer aucune information cruciale, ou nous[ENTER]tomberons dans une confusion totale. "
gameforge.main_quest_lv47._440_say = "Je pense que je dois vous dire le contenu de la[ENTER]sixi\232me page avant de commencer \224 d\233chiffrer une[ENTER]nouvelle. "
gameforge.main_quest_lv47._450_sayTitle = "Sixi\232me page : "
gameforge.main_quest_lv47._460_sayReward = "Le temps passe. Nous avons d\233j\224 tent\233 d'utiliser[ENTER]la magie noire au Donjon des Araign\233es et \231a n'a[ENTER]pas fonctionn\233. Qu'avons-nous oubli\233 ? Nos[ENTER]chamanes pensent qu'il faut faire de gros[ENTER]sacrifices pour pratiquer la magie noire. C'est[ENTER]vrai, mais cette force est si grande ! "
gameforge.main_quest_lv47._470_sayReward = "D'apr\232s les l\233gendes, pratiquer la magie noire[ENTER]demande des sacrifices humains. Mais si je tue[ENTER]quelqu'un, ma r\233putation va en prendre un coup.[ENTER]Nous avons besoin d'un rempla\231ant ad\233quat.[ENTER]Tentons donc avec un \233p\233iste serpent du d\233sert. "
gameforge.main_quest_lv47._480_say = "Ah ah ! Depuis qu'ils ne peuvent plus utiliser[ENTER]des humains comme sacrifice, ils ont d\233cid\233 de[ENTER]tuer des \201p\233istes serpent. J'avoue que cette id\233e[ENTER]me plait, suivons donc leur exemple. Vous devriez[ENTER]aller dans le d\233sert et tuer des Archers serpent[ENTER]et des \201p\233istes serpent. Qui sait ce que nous y[ENTER]trouverons. Vous serez r\233compens\233 de toutes[ENTER]fa\231ons ! "
gameforge.main_quest_lv47._490_sendLetter = "Tuer les \233p\233istes serpents "
gameforge.main_quest_lv47._500_sayTitle = "La huiti\232me page "
gameforge.main_quest_lv47._50_sayTitle = "Cinqui\232me page : "
gameforge.main_quest_lv47._510_say = "Le journal d\233crit la fa\231on dont on doit sacrifier[ENTER]les \233p\233istes serpents et les archers serpents[ENTER]afin de pouvoir pratiquer la magie noire. Allez[ENTER]en tuer au d\233sert. Tentez de trouver d'autres[ENTER]informations. "
gameforge.main_quest_lv47._520_sendLetter = "Huiti\232me page trouv\233e "
gameforge.main_quest_lv47._530_targetVid = "Allez voir Uriel "
gameforge.main_quest_lv47._540_say = "Vous avez trouv\233 la huiti\232me page sur les[ENTER]\233p\233istes serpents du d\233sert. Apportez la \224 Uriel. "
gameforge.main_quest_lv47._550_say = "C'est la huiti\232me page. Vu qu'elle est tr\232s[ENTER]courte, je pourrais la d\233chiffrer rapidement. "
gameforge.main_quest_lv47._560_sayTitle = "Huiti\232me page : "
gameforge.main_quest_lv47._570_sayReward = "Les victimes n\233cessaires ont \233t\233 trouv\233es. Nous[ENTER]avons de la chance. Je me demande si c'est un[ENTER]signe ? Nous avons besoin d'une cloche pour la[ENTER]c\233r\233monie, il me semble que les araign\233es en[ENTER]avaient. Allons-y. "
gameforge.main_quest_lv47._580_say = "Ah, le donjon des araign\233es, encore, \233trange?[ENTER]Allez y pour trouver la clochette. Cette journ\233e[ENTER]va \234tre difficile, reposez vous un peu avant et[ENTER]repassez plus tard. Il n'est pas utile de[ENTER]r\233soudre ce myst\232re imm\233diatement et j'ai besoin[ENTER]de plus de temps pour d\233chiffrer ces pages comme[ENTER]il faut. \192 votre retour, je vous donnerai une[ENTER]autre mission, et bien s\251r vous avez votre[ENTER]r\233compense pour la huiti\232me page. "
gameforge.main_quest_lv47._590_sayReward = "Points d'exp\233rience : 3\160000\160000[ENTER]Yangs : 70\160000[ENTER]Capes de Bravoure : 20[ENTER]Attention : Pour la prochaine mission, tu devras[ENTER]au moins \234tre au niveau 50. "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop est arriv\233 avec sa cavalerie dans Taejo[ENTER]et est rest\233 l\224 peu de temps. \192 cause des[ENTER]nombreuses petites m\233t\233orites ainsi que du chaos[ENTER]que la grande m\233t\233orite a caus\233 parmi tous les[ENTER]\234tres vivants, l'empire a \233t\233 divis\233 en trois[ENTER]petits empires. Le pire c'est est que les empires[ENTER]ne se battent pas contre le chaos, mais entre[ENTER]eux. Le Dieu Dragon, avec son pouvoir, soutient[ENTER]l'empire le plus fort, mais cela entra\238ne une[ENTER]haine encore plus forte entre eux.[ENTER]Et bien s\251r, la m\233t\233orite provoque un chaos de[ENTER]plus en plus d\233vastateur. "
gameforge.main_quest_lv47._70_sayTitle = "Uriel: "
gameforge.main_quest_lv47._80_say = "Petit compte rendu d'un t\233moin oculaire de cet[ENTER]ancien temps. Cela n'a pas de prix ! Ah, au fait.[ENTER]Voici une r\233compense pour votre excellent[ENTER]travail. Autre chose : Quelqu'un d'autre semble[ENTER]tenter de r\233soudre les m\234mes qu\234tes que nous.[ENTER]Donc nous n'avons pas de temps \224 perdre. En bas[ENTER]de page, il est dit que Lee Seop est all\233 cherch\233[ENTER]l'\233nergie n\233gative au donjon des araign\233es. Si[ENTER]vous trouvez quelque chose l\224-bas, venez voir-moi[ENTER]imm\233diatement. Je ne peux pas attendre! "
gameforge.main_quest_lv47._90_sendLetter = "La sixi\232me page "
gameforge.main_quest_lv50 = {}
gameforge.main_quest_lv50._100_say = "H\233, pas si vite jeune ami ! N'oubliez pas votre[ENTER]r\233compense pour la neuvi\232me page. "
gameforge.main_quest_lv50._10_sayTitle = "Tuez des soldats araign\233e \233lite "
gameforge.main_quest_lv50._110_sayReward = "Vous recevez 5.000.000 de points d'exp\233rience. "
gameforge.main_quest_lv50._120_sayReward = "Vous avez re\231u 125.000 yangs. "
gameforge.main_quest_lv50._130_sayReward = "Vous recevez un Symbole du Roi Sage "
gameforge.main_quest_lv50._140_sendLetter = "Les indices en terre glaciaire "
gameforge.main_quest_lv50._150_targetVid = "La vieille bo\238te \224 papier. "
gameforge.main_quest_lv50._160_sayTitle = "Chercher la vieille bo\238te \224 papiers "
gameforge.main_quest_lv50._170_say = "Au Mont Sohan, des arm\233es ennemies sont tomb\233es[ENTER]par hasard l'une sur l'autre.[ENTER]Cherchez-y d'autres pages ou texte concernant le[ENTER]d\233roulement de cette bataille. "
gameforge.main_quest_lv50._180_npcChat = "Une Vieille Bo\238te \224 Papiers "
gameforge.main_quest_lv50._190_say = "Ce sont des plans militaires et des notes.[ENTER]Et une nouvelle page du jounal ! Je devrais[ENTER]apporter tout \231a \224 Uriel. "
gameforge.main_quest_lv50._200_sendLetter = "La dixi\232me page "
gameforge.main_quest_lv50._20_say = "D'apr\232s nos enqu\234tes pr\233c\233dentes, des indices[ENTER]seraient cach\233s dans le donjon des Araign\233es.[ENTER]Tuez des soldats araign\233e \233lite au donjon. Si[ENTER]vous trouvez une autre page, retournez voir[ENTER]Uriel. "
gameforge.main_quest_lv50._210_sayTitle = "Dixi\232me page trouv\233e "
gameforge.main_quest_lv50._220_say = "Vous avez trouv\233 la dixi\232me page du journal[ENTER]intime secret au Mont Sohan. Elle \233tait dans une[ENTER]vieille boite.[ENTER]Apportez la \224 Uriel. "
gameforge.main_quest_lv50._230_say = "Ah, vous avez trouv\233 la dixi\232me page ![ENTER]Formidable, nous approchons de la fin de[ENTER]l'histoire. C'est bien qu'ils aient tout[ENTER]consign\233, comme \231a rien n'est perdu. Voyons ce[ENTER]que cette page raconte. "
gameforge.main_quest_lv50._235_sayTitle = "Dixi\232me page du journal : "
gameforge.main_quest_lv50._240_sayReward = "Nous sommes parvenus \224 refouler la premi\232re[ENTER]attaque. Mais une nouvelle vague arrive. Le[ENTER]terrain a g\234n\233 les lourds soldats d'acier de Lee[ENTER]Seop et nous a donn\233 un avantage, mais ils sont[ENTER]vraiment trop nombreux. Nous ne pouvons pas[ENTER]gagner. Il ne nous reste qu'une derni\232rechance[ENTER]pour pouvoir terminer notre enqu\234te sur la magie[ENTER]noire. Nous allons essayer de nuitamment percer[ENTER]les lignes ennemies pour retourner au donjon des[ENTER]araign\233es. Je prie, non pas pour une victoire[ENTER]mais pour un peu de courage... "
gameforge.main_quest_lv50._250_say = "Oh, je pense que nous approchons du but. bient\244t,[ENTER]on d\233couvrira ce qu'est cette magie noire. Je[ENTER]n'en peux plus d'attendre !! Vous devez retourner[ENTER]au donjon des araign\233es. Vous y trouverez[ENTER]peut-\234tre la onzi\232me page du journal. "
gameforge.main_quest_lv50._260_say = "Et voici une fois de plus une r\233compense bien[ENTER]m\233rit\233e ! "
gameforge.main_quest_lv50._270_sayReward = "Vous avez re\231u 5.500.000 points d'exp\233rience. "
gameforge.main_quest_lv50._280_sayReward = "Vous avez re\231u 137.500 yangs. "
gameforge.main_quest_lv50._290_sayReward = "Vous avez re\231u des Gants du Roi Sage. "
gameforge.main_quest_lv50._300_sayTitle = "Tuez des Araign\233es \224 griffes "
gameforge.main_quest_lv50._30_sendLetter = "La neuvi\232me page "
gameforge.main_quest_lv50._310_say = "Les recherches sur la magie noire ont continu\233[ENTER]dans le donjon des araign\233es. Rendez-y vous et[ENTER]tuez des Araign\233es \224 griffes jusqu'\224 avoir trouv\233[ENTER]les informations n\233cessaires. "
gameforge.main_quest_lv50._320_sendLetter = "La onzi\232me page "
gameforge.main_quest_lv50._330_targetVid = "Retournez voir Uriel le sage. "
gameforge.main_quest_lv50._335_sayTitle = "Page onze trouv\233e "
gameforge.main_quest_lv50._340_say = "Vous avez trouv\233 la onzi\232me page de journal[ENTER]intime au Donjon des Araign\233es. Apportez-la \224[ENTER]Uriel. "
gameforge.main_quest_lv50._350_say = "Avez-vous appris de nouvelles choses ?[ENTER]Hoho, la onzi\232me page ! Faites-voir ...[ENTER]Oui, cela semble assez simple. Finalement, je[ENTER]suis devenu un expert dans la lecture de ces[ENTER]signes. \201coutez-moi bien ! "
gameforge.main_quest_lv50._355_sayTitle = "Onzi\232me page du journal : "
gameforge.main_quest_lv50._360_sayReward = "Cela n'a pas fonctionn\233.[ENTER]En d\233pit de toutes nos pr\233parations, nous avons[ENTER]d\251 agir rapidement. Trop probablement. Du coup,[ENTER]beaucoup d'entre nous sont bless\233s ou devenus[ENTER]fous. Cette magie noire est v\233ritablement[ENTER]mal\233fique. La cavalerie de Lee Seop nous talonne[ENTER]de pr\232s, mais cela m'est \233gal. Nous n'avons de[ENTER]toute fa\231on plus assez de troupes pour pouvoir[ENTER]lui r\233sister. Nous allons tous mourir. "
gameforge.main_quest_lv50._365_sayTitle = "Suite de la onzi\232me page du journal : "
gameforge.main_quest_lv50._370_sayReward = "Seul un dernier \233lan maintient la coh\233sion de[ENTER]notre troupe et nous donne suffisamment de force[ENTER]pour aller de l'avant : Nos informateurs dans la[ENTER]vall\233e des dragons nous ont dissimul\233 a dessein[ENTER]les terribles effets secondaires de cette magie[ENTER]noire. Mais ils vont nous le payer, m\234me si cela[ENTER]doit \234tre notre derni\232re action dans cette vie. "
gameforge.main_quest_lv50._380_say = "Finalement, rien ne s'est pass\233 commepr\233vu.[ENTER]Une triste histoire.[ENTER]Malheureusement on ne peut avoir aucune confiance[ENTER]envers les pratiquants de la magie noire. Ils[ENTER]auraient du y penser. Il est assez \233trange que[ENTER]l'auteur de ces lignes ait m\234me r\233ussi \224 recevoir[ENTER]des informations sur ces th\232mes interdits. Qui[ENTER]sait quel genre du but ces informateurs avaient.[ENTER]Nous devrions terminer notre qu\234te m\234me si elle[ENTER]reste dangereuse. Nous savons d\233j\224 tant, ce[ENTER]serait une honte d'abandonner[ENTER]maintenant.  "
gameforge.main_quest_lv50._390_say = "Vous \234tes d\233j\224 all\233 \224 la vall\233e de Seungryong.[ENTER]Je ne pense pas que nous y trouverons quelque[ENTER]chose de plus.[ENTER]Hmm, je me demande \224 quel autre endroit nous[ENTER]pourrions regarder... Je sais ! Les monuments[ENTER]nous ont permis d'obtenir beaucoup[ENTER]d'informations. Et il reste des monuments non[ENTER]examin\233s \224 ce jour. Ceux des autres empires ![ENTER]C'est tr\232s dangereux de s'y rendre. Vous serez[ENTER]probablement attaqu\233 sans rel\226che. Pr\233parez-vous[ENTER]bien et revenez me voir quand vous serez pr\234t. "
gameforge.main_quest_lv50._400_say = "Mais avant tout vous recevez votre r\233compense[ENTER]pour la onzi\232me page. "
gameforge.main_quest_lv50._40_targetVid = "Allez voir Uriel "
gameforge.main_quest_lv50._410_sayReward = "Vous recevez : 6.000.000 d'exp\233rience[ENTER]Vous recevez : 150.000 Yangs[ENTER]De plus, vous recevez une M\233daille du Dragon[ENTER]Conseil : Pour la prochaine mission, vous devez[ENTER]\234tre au moins niveau 55. "
gameforge.main_quest_lv50._50_sayTitle = "Neuvi\232me page trouv\233e "
gameforge.main_quest_lv50._60_say = "Vous avez trouv\233 la neuvi\232me page au Donjon des[ENTER]Araign\233es. Apportez la \224 Uriel. "
gameforge.main_quest_lv50._70_say = "Tu as trouv\233 des traces de la Magie noire ?[ENTER]Hmmm. effectivement, voici a neuvi\232me page ![ENTER]Je suis tr\232s impatient de voir si le sort a[ENTER]fonctionn\233 D\233p\234chons-nous ! Voyons, on peut lire[ENTER]ici ... "
gameforge.main_quest_lv50._75_sayTitle = "Neuvi\232me page du journal : "
gameforge.main_quest_lv50._80_sayReward = "L'attaque de Lee Seop a commenc\233. Nous ne savons[ENTER]pas exactement de quelle mani\232re la magie op\232re.[ENTER]Nous somme ici en premi\232re ligne pour d\233fendre[ENTER]notre empire, mais nos moyens ne sont pas[ENTER]suffisants. L'arm\233e ennemie est bien trop[ENTER]puissante et si rien ne se passe rapidement, nous[ENTER]ne pourrons que perdre cette bataille.[ENTER]Nous devons nous replier vers un endroit o\249 ils[ENTER]ne pourrons pas utiliser efficacement leur[ENTER]cavalerie : Le d\233sert de glace. Avec un peu de[ENTER]chance il nous restera suffisamment de temps pour[ENTER]faire encore quelques recherches.[ENTER]Dieu nous vienne en aide ... "
gameforge.main_quest_lv50._90_say = "Hmm... l'assaut a \233t\233 donn\233 avant qu'ils aient pu[ENTER]faire suffisamment de recherche sur la magie[ENTER]noire. Ils ont du se r\233fugier dans le d\233sert de[ENTER]glace. Ils font s\251rement r\233f\233rence au Mont Sohan[ENTER]qu'on nomme aujourd'hui aussi la terre glaciaire.[ENTER]Nous devrions y faire des recherches[ENTER]suppl\233mentaires. Rendez-vous au mont Sohan et[ENTER]cherchez des indices. "
gameforge.main_quest_lv55 = {}
gameforge.main_quest_lv55._100_say = "Apr\232s avoir trouv\233 la douzi\232me page \224 l'empire[ENTER]Joan, vous devriez aller voir Uriel. Amenez-la \224[ENTER]Uriel de votre empire. "
gameforge.main_quest_lv55._10_sendLetter = "Chercher les monuments "
gameforge.main_quest_lv55._110_say = "Apr\232s avoir trouv\233 la douzi\232me page dans la zone[ENTER]Yongan. Apportez-la \224 Uriel dans la zone[ENTER]Pyungmoo. "
gameforge.main_quest_lv55._120_say = "Je suis content de vous revoir. Vous avez trouv\233[ENTER]la douzi\232me page ? Parfait. Regardons ce que l'on[ENTER]peut trouver comme informations \224 propos de la[ENTER]magie secr\232te. "
gameforge.main_quest_lv55._130_sayTitle = "Douzi\232me page : "
gameforge.main_quest_lv55._140_sayReward = "Nous avons enfin trouv\233 quelques indices. Comme[ENTER]nous l'ont dit nos ennemis, nous ne trouverons[ENTER]pas la Magie chez les Araign\233es. Nous devons[ENTER]allez chercher dans le Temple. C'est un lieu[ENTER]emplit de vieilles croyances et de sombres[ENTER]rituels. "
gameforge.main_quest_lv55._145_sayTitle = "Suite de la douzi\232me page : "
gameforge.main_quest_lv55._150_sayReward = "Afin de pouvoir compl\233ter cette magie, nous[ENTER]devrions aller au Temple Maudit, m\234me si nous[ENTER]sommes \233puis\233s. Nous devrons y aller de toutes[ENTER]fa\231ons. Avec de la chance, nous serons en mesure[ENTER]de compl\233ter notre secret sur cette magie l\224 bas.[ENTER]Nous sommes pr\232s du but et nous allons[ENTER]l'atteindre bient\244t. "
gameforge.main_quest_lv55._160_say = "Oh, les anc\234tres de cette magie noire ont trouv\233[ENTER]le bon endroit. Nous atteignons la fin de[ENTER]l'histoire. L'endroit suivant est le Temple dans[ENTER]l'all\233e des Dragons. Il y a un lieu ou de[ENTER]diverses c\233r\233monies religieuses ont eu lieu par[ENTER]le pass\233, qui a provoqu\233 la guerre sanglante.[ENTER]C'est un lieu plein d'\233nergies n\233gatives et[ENTER]mauvaises. "
gameforge.main_quest_lv55._170_say = "\192 pr\233sent, il n'y a que des monstres qui vivent[ENTER]dans le Temple. Il n'y a pas eu d'humains depuis[ENTER]bien longtemps. Malgr\233 le danger, nous pourrons[ENTER]s\251rement trouver les derniers indices l\224-bas.[ENTER]Bonne chance ! Et ceci est votre r\233compense pour[ENTER]la douzi\232me page ... "
gameforge.main_quest_lv55._180_sayReward = "Vous avez re\231u 26\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 15\160000 Yangs.[ENTER]Vous avez re\231u un groin. "
gameforge.main_quest_lv55._190_sayReward = "Vous avez re\231u 162.500 yangs. "
gameforge.main_quest_lv55._200_sendLetter = "La derni\232re page "
gameforge.main_quest_lv55._20_say = "Comme vous avez d\233j\224 trouv\233 plusieurs pages du[ENTER]journal pr\232s des tablettes, Uriel pense que vous[ENTER]serez capable de d\233couvrir plus d'informations[ENTER]sur la sorcellerie sombre secr\232te pr\232s des[ENTER]tablettes inexplor\233es. Rejoignez l'empire Chunjo[ENTER]et examinez le m\233morial se trouvant \224 Joan. "
gameforge.main_quest_lv55._210_sayTitle = "Tuez les croque-mitaines dans le Temple "
gameforge.main_quest_lv55._220_say = "Jusque-l\224, vous avez trouv\233 les 12 pages. A[ENTER]pr\233sent, il ne reste plus qu'une \233tape. Uriel dit[ENTER]que la Magie Noire a \233t\233 trouv\233e dans le Temple.[ENTER]C'est pourquoi vous devez y aller pour trouver[ENTER]des informations. Le Temple est un endroit[ENTER]dangereux. Tuez quelques croque-mitaines; ils ont[ENTER]s\251rement des informations. "
gameforge.main_quest_lv55._230_say = "Je dois aller un peu plus loin dans le Temple ! "
gameforge.main_quest_lv55._240_sendLetter = "Le Temple Obscur "
gameforge.main_quest_lv55._250_sayTitle = "L'\233nergie diabolique du Temple "
gameforge.main_quest_lv55._260_sayReward = "Apr\232s avoir pass\233 un peu de temps dans le temple,[ENTER]vous ressentez une compassion face \224 cet \233trange[ENTER]et sombre lieu : Lentement les ombres vacillent[ENTER]dans chaque coin.[ENTER]L'\233nergie n\233gative suinte et craque dans les[ENTER]moindres recoins. Il est \233vident que le temple[ENTER]lui-m\234me est responsable de cela. C'est ici que[ENTER]tout a commenc\233... "
gameforge.main_quest_lv55._270_say = "Vous prenez conscience du fait que le Mal dans[ENTER]l'air devient plus fort, au fur et \224 mesure que[ENTER]vous avancez dans le Temple. Vous devriez essayer[ENTER]de trouver le centre du temple.[ENTER]C'est o\249 la source de l'obscurit\233 doit \234tre. "
gameforge.main_quest_lv55._280_npcChat = "Le Monument Gum "
gameforge.main_quest_lv55._290_say = "Le Monument Gum est au c\156ur du temple.[ENTER]Vous vous rapprochez lentement et trouvez en fait[ENTER]la derni\232re page de journal. "
gameforge.main_quest_lv55._300_say = "Vous avez trouv\233 la derni\232re page du journal[ENTER]intime dans le Temple Obscur. Allez voir Uriel et[ENTER]montrez lui votre d\233couverte. "
gameforge.main_quest_lv55._30_say = "Comme vous avez d\233j\224 trouv\233 plusieurs pages de[ENTER]journal pr\232s des tablettes, Uriel pense qu'on[ENTER]peut en trouver d'autres sur les tablettes non[ENTER]encore examin\233es. Rejoignez l'empire Jinno et[ENTER]explorez le m\233morial \224 Pyungmo. "
gameforge.main_quest_lv55._310_say = "Ceci est la derni\232re page, la treizi\232me page![ENTER]Avec votre aide, je peux poursuivre mes[ENTER]recherches. Ce fut compliqu\233 et dangereux, mais[ENTER]c'\233tait tr\232s important aussi. Regardons donc ce[ENTER]que disent les derni\232res pages. "
gameforge.main_quest_lv55._320_sayTitle = "Treizi\232me page : "
gameforge.main_quest_lv55._330_sayReward = "Nous y sommes enfin arriv\233s.[ENTER]Nos efforts nous am\232nent ici : nous devons[ENTER]ex\233cuter la c\233r\233monie et pratiquer la magie[ENTER]noire. J'esp\232re juste que nous sommes assez[ENTER]forts. Beaucoup d'entre nous vacillent, \233puis\233s[ENTER]par ces longues journ\233es \224 fuir les guerriers de[ENTER]Lee Seop. Cependant, nous devons essayer ou notre[ENTER]empire p\233rira. "
gameforge.main_quest_lv55._335_sayTitle = "Suite de la treizi\232me page : "
gameforge.main_quest_lv55._340_sayReward = "Nous sommes sept. Nous avons mis nos plus beaux[ENTER]v\234tements, m\234me s'ils ressemblent vraiment \224 des[ENTER]lambeaux de tissu \224 pr\233sent. Nous allons nous[ENTER]r\233unir dans un cercle et nous tenir les mains[ENTER]pour que les lignes de puissance soient scell\233es.[ENTER]Alors nous commencerons \224 chanter nos[ENTER]incantations et esp\233rerons que la sorcellerie[ENTER]noire ne fait plus de sacrifices. "
gameforge.main_quest_lv55._350_sayReward = "... C'est termin\233 ...[ENTER]Au commencement tout \233tait tr\232s prometteur. La[ENTER]pi\232ce est remplie d'\233nergie et de chant, mais[ENTER]soudainement je me suis senti vraiment \233trange.[ENTER]Mes six compagnons sont tomb\233s \224 genoux. Le[ENTER]temple a commenc\233 \224 trembler. J'ai contr\244l\233 toute[ENTER]mon \233nergie pour ne pas m'\233vanouir.[ENTER]Alors la foudre a frapp\233 et on nous a propuls\233s[ENTER]violemment en arri\232re. Et ensuite les lignes de[ENTER]puissance se sont bris\233es.[ENTER]Quand je me suis r\233veill\233, tout \233tait calme et[ENTER]mes camarades \233taient couch\233s sur le sol,[ENTER]inconscients. La magie n'a pas fonctionn\233. Nous[ENTER]avons \233chou\233. "
gameforge.main_quest_lv55._360_say = "Qu'est-ce que c'est ?[ENTER]C'est fou ! Tout ce que travail pour rien ? Je ne[ENTER]peux pas le croire. Nous avons voyag\233, nous[ENTER]sommes battus, avons traduits et r\233fl\233chis \224 cela[ENTER]durant des heures. Tout pour rien! Nous en sommes[ENTER]au m\234me point qu'au d\233part. Cependant, rester[ENTER]\233loign\233s de cette magie noire me semble encore la[ENTER]meilleure chose, comme je le pensais.[ENTER]Mais le savoir est meilleur que la croyance,[ENTER]n'est-ce pas ? "
gameforge.main_quest_lv55._370_say = "Nous allons faire une pause d'abord. J'ai mal \224[ENTER]la t\234te et vous \234tes probablement fatigu\233 aussi.[ENTER]Je dois travailler mais ma t\234te doit se reposer[ENTER]d'abord. Quand j'irai mieux, nous en reparlerons.[ENTER]Malgr\233 tout, vous m'avez fourni un service[ENTER]inestimable.Cela m\233rite une r\233compense! "
gameforge.main_quest_lv55._380_sayReward = "Vous avez re\231u 7.000.000 de points d'exp\233rience. "
gameforge.main_quest_lv55._390_sayReward = "Vous avez re\231u 175.000 yangs. "
gameforge.main_quest_lv55._400_sayReward = "Vous avez re\231u un Livre du Chef. "
gameforge.main_quest_lv55._40_say = "Comme vous avez d\233j\224 trouv\233 plusieurs pages du[ENTER]journal pr\232s des tablettes, Uriel pense que vous[ENTER]serez capables de d\233couvrir plus d'informations[ENTER]sur la sorcellerie sombre secr\232te pr\232s des[ENTER]tablettes inexplor\233es. Rejoignez l'empire Shinsoo[ENTER]et examinez le m\233morial dans le secteur Yongan. "
gameforge.main_quest_lv55._50_npcChat = "Il y en a ici ! "
gameforge.main_quest_lv55._60_say = "C'est le Monument dont Uriel m'a parl\233. Il y[ENTER]avait une page cach\233e, je ferais mieux de vite[ENTER]l'apporter \224 Uriel. "
gameforge.main_quest_lv55._70_sendLetter = "Douzi\232me page trouv\233e "
gameforge.main_quest_lv55._80_targetVid = "Retournez voir Uriel "
gameforge.main_quest_lv55._90_say = "Vous avez trouv\233 la 12e page dans la zone[ENTER]Pyungmo. Apportez-la \224 Uriel dans la zone Joan. "
gameforge.main_quest_lv6 = {}
gameforge.main_quest_lv6._100_sayReward = "Allez voir le forgeron. Il a besoin de votre aide. "
gameforge.main_quest_lv6._10_targetVid = "Allez voir le Garde du Village "
gameforge.main_quest_lv6._110_say = "Qui \234tes-vous et que voulez-vous ? Je suis tr\232s[ENTER]occup\233, ne me d\233rangez pas.[ENTER]Ah, le garde du Village vous envoie ? Je ne[ENTER]pensais pas voir quelqu'un un jour. Cette mission[ENTER]n'est pas trop difficile et ne prend pas trop de[ENTER]temps. Une mission ad\233quate pour un aventurier[ENTER]comme vous. "
gameforge.main_quest_lv6._120_say = "J'ai esp\233r\233 que le magasinier vous donne un groin[ENTER]mais il n'\233tait pas encore arriv\233. Allez me le[ENTER]chercher. Je suis press\233. J'en ai besoin pour[ENTER]continuer mon travail. "
gameforge.main_quest_lv6._130_targetVid = "Allez voir le magasinier "
gameforge.main_quest_lv6._140_sendLetter = "Allez voir le Magasinier "
gameforge.main_quest_lv6._150_sayReward = "Le forgeron attend une livraison urgente[ENTER]provenant du Magasinier. Allez voir le Magasinier[ENTER]et demandez-lui le Groin pour le forgeron. "
gameforge.main_quest_lv6._160_sayTitle = "Magasinier : "
gameforge.main_quest_lv6._170_say = "Bienvenue. Je suis le magasinier du village. Si[ENTER]vous avez trop de choses sur vous, vous pouvez[ENTER]les stocker dans mon magasin. Cela peut arriver \224[ENTER]tout moment! "
gameforge.main_quest_lv6._180_say = "Voulez-vous ... Ah, le forgeron vous envoie \224[ENTER]propos du Groin ! "
gameforge.main_quest_lv6._190_say = "J'ai bien peur d'\234tre devenu vieux et \233tourdi.[ENTER]Avant cela n'arrivait jamais. Voici le groin.[ENTER]Apportez le tout de suite au forgeron s'il vous[ENTER]plait. \192 bient\244t. "
gameforge.main_quest_lv6._200_sendLetter = "Retournez voir le forgeron "
gameforge.main_quest_lv6._20_sayReward = "Le Garde du Village a une mission pour vous.[ENTER]Allez le voir. "
gameforge.main_quest_lv6._210_sayReward = "Le Magasinier a totalement oubli\233 sa livraison.[ENTER]Il vous a donn\233 le Groin pour le forgeron.[ENTER]Apportez lui vite il ne peut plus attendre. "
gameforge.main_quest_lv6._220_say = "Vous \234tes revenu plus vite que ce que je[ENTER]pensais\160! Soyez toujours si rapide, cela vous[ENTER]aidera plus tard. \201coutez-moi attentivement, j'ai[ENTER]d'importantes informations pour vous. "
gameforge.main_quest_lv6._230_say = "Connaissez-vous le raffinage ? Mais non, bien[ENTER]s\251r, vous \234tes encore si jeune. Alors voil\224 : si[ENTER]vous me donnez un objet de votre \233quipement, pour[ENTER]quelques Yangs, je pourrai enrichir ses[ENTER]performances en le raffinant. "
gameforge.main_quest_lv6._240_say = "L'art du raffinage peut se d\233rouler de plusieurs[ENTER]mani\232res. Plus vos attentes sont grandes, plus la[ENTER]t\226che sera difficile. Pour un raffinage de[ENTER]jusqu'\224 +3, quelques Yangs suffiront, au-del\224, il[ENTER]vous faudra un objet suppl\233mentaire, par exemple[ENTER]le groin que vous m'avez apport\233.[ENTER]Cependant, m\234me quelqu'un de mon exp\233rience peut[ENTER]voir l'objet se d\233truire au cours du proc\233d\233.[ENTER]Venez me voir si vous avec un peu de temps. Je[ENTER]pourrais vous forger des armes fantastiques\160! "
gameforge.main_quest_lv6._250_sayReward = "Vous avez re\231u %s points d'exp\233rience. "
gameforge.main_quest_lv6._260_sayReward = "Vous avez re\231u %s yangs. "
gameforge.main_quest_lv6._270_sayReward = "Vous recevez une fourrure de loup+. "
gameforge.main_quest_lv6._30_say = "Hey toi! Ne tourne pas dans le village en disant[ENTER]qu'il n'y a rien \224 faire. Tu as besoin de plus[ENTER]d'entra\238nement. Dans ces temps sombres,[ENTER]l'entra\238nement est la seule voie pour augmenter[ENTER]tes chances de survie. "
gameforge.main_quest_lv6._40_say = "Puisque vous \234tes l\224, j'ai une mission pour[ENTER]vous\160: il y a quelque temps le Forgeron parlait[ENTER]d'une commande urgente et de Groin. Je pense[ENTER]qu'il a besoin d'aide. Allez le voir pour savoir[ENTER]comment l'aider ! "
gameforge.main_quest_lv6._50_sayReward = "Si vous r\233ussissez la mission vous aurez une[ENTER]r\233compense. "
gameforge.main_quest_lv6._60_sayReward = "Points d'exp\233rience: %s "
gameforge.main_quest_lv6._70_sayReward = "Yang: %s  "
gameforge.main_quest_lv6._80_targetVid = "Trouvez le Forgeron "
gameforge.main_quest_lv6._90_sendLetter = "La mission du Forgeron "
gameforge.main_quest_lv60 = {}
gameforge.main_quest_lv60._100_say = "Le mont Sohan\160? J'y ai vraiment vu un tombeau[ENTER]ancien une fois\160! "
gameforge.main_quest_lv60._10_sendLetter = "Une nouvelle piste "
gameforge.main_quest_lv60._110_say = "Par hasard, vous souvenez-vous s'il y avait une[ENTER]inscription dessus ?![ENTER]Apparemment non. Cette tombe peut nous donner[ENTER]beaucoup d'informations importantes sur la Nation[ENTER]Obscure. Pouvez-vous vous rendre au mont Sohan et[ENTER]me faire une copie de l'inscription ? "
gameforge.main_quest_lv60._120_say = "D'apr\232s les recherches d'Uriel, les sept[ENTER]pr\234tresses du Dragon appartenaient \224 la Nation[ENTER]Obscure. Fouillez l'ancien tombeau sur le mont[ENTER]Sohan. C'est ici que devait se trouver, dans des[ENTER]temps imm\233moriaux, la capitale de la Nation[ENTER]Obscure. "
gameforge.main_quest_lv60._130_say = "Par hasard, vous souvenez-vous s'il y avait une[ENTER]inscription dessus ?![ENTER]Apparemment non. Cette tombe peut nous donner[ENTER]beaucoup d'informations importantes sur la Nation[ENTER]Obscure. Pouvez-vous vous rendre au mont Sohan et[ENTER]me faire une copie de l'inscription ? "
gameforge.main_quest_lv60._140_sayReward = "Vous avez trouv\233 un tombeau ancien de l'\233poque de[ENTER]la Nation Obscure. Vous avez fait une copie de[ENTER]l'\233pitaphe. Apportez-la \224 Uriel. "
gameforge.main_quest_lv60._150_say = "D'apr\232s les recherches d'Uriel, les sept[ENTER]pr\234tresses du Dragon appartenaient \224 la Nation[ENTER]Obscure. Fouillez l'ancien tombeau sur le mont[ENTER]Sohan. C'est ici que devait se trouver, dans des[ENTER]temps imm\233moriaux, la capitale de la Nation[ENTER]Obscure. "
gameforge.main_quest_lv60._160_say = "Enfin\160! Laissez-moi analyser l'inscription...[ENTER]Voici ce qui est \233crit\160: la Nation Obscure[ENTER]pratiquait la magie noire et servait Sung Mahi,[ENTER]le dieu des d\233mons. "
gameforge.main_quest_lv60._170_say = "Grands dieux... Sung Mahi\160! Alors les sept[ENTER]pr\234tresses ont-elles essay\233 de conjurer Sung Mahi[ENTER]\224 l'aide de la magie maudite\160? "
gameforge.main_quest_lv60._180_say = "Vous avez fait du bon travail. Naturellement vous[ENTER]m\233ritez une r\233compense. "
gameforge.main_quest_lv60._190_sayReward = "Vous obtenez %d points d'exp\233rience. "
gameforge.main_quest_lv60._200_sayReward = "Vous obtenez %d de Yang. "
gameforge.main_quest_lv60._20_say = "Uriel en sait plus sur l'histoire du vieux[ENTER]journal. Rendez-lui visite et apprenez-en plus \224[ENTER]ce sujet. "
gameforge.main_quest_lv60._210_sayReward = "Vous obtenez %s. "
gameforge.main_quest_lv60._220_sendLetter = "Nation Obscure II "
gameforge.main_quest_lv60._230_say = "D'apr\232s Uriel, le bois enchant\233 appartenait[ENTER]autrefois \224 l'empire de la Nation Obscure.[ENTER]Peut-\234tre que nous allons en savoir plus l\224-bas.[ENTER]Mais ce bois cache plein de dangers et les[ENTER]pierres Metin rendent toutes les cr\233atures[ENTER]folles. Trouvez l'arbre mal\233fique afin d'avoir[ENTER]plus d'\233l\233ments puis parlez-en \224 Uriel. "
gameforge.main_quest_lv60._240_say = "La Nation Obscure rec\232le d'innombrables secrets.[ENTER]Gr\226ce \224 vous, nous en connaissons quelques uns,[ENTER]mais il nous manque encore des informations[ENTER]importantes. S'il vous pla\238t partez \224 la[ENTER]recherche d'un document ancien. Il doit se[ENTER]trouver dans le bois enchant\233, pr\232s du mont[ENTER]Sohan. "
gameforge.main_quest_lv60._250_counter = "Pages manquantes\160: "
gameforge.main_quest_lv60._260_say = "La Nation Obscure rec\232le d'innombrables secrets.[ENTER]Gr\226ce \224 vous, nous en connaissons quelques uns,[ENTER]mais il nous manque encore des informations[ENTER]importantes. S'il vous pla\238t partez \224 la[ENTER]recherche d'un document ancien. Il doit se[ENTER]trouver dans le bois enchant\233, pr\232s du mont[ENTER]Sohan. "
gameforge.main_quest_lv60._270_sayReward = "Vous avez vaincu l'arbre mal\233fique et vous avez[ENTER]r\233cup\233r\233 le document. Il est \233crit dans une[ENTER]langue \233trang\232re. Faites-le traduire par Uriel. "
gameforge.main_quest_lv60._280_say = "Enfin\160! Vous avez trouv\233 le document ancien.[ENTER]Esp\233rons qu'il nous \233claire un peu\160! "
gameforge.main_quest_lv60._290_say = "Mais...?! Il n'y a quasiment rien dedans\160! Le[ENTER]document original contient 10 pages. S'il vous[ENTER]pla\238t, retournez dans le bois enchant\233 et trouvez[ENTER]les 9 pages manquantes. "
gameforge.main_quest_lv60._300_say = "Vous devez encore trouver %d pages. "
gameforge.main_quest_lv60._30_say = "Comment allez-vous\160? Vous souvenez-vous encore du[ENTER]journal et de l'histoire qui y \233tait \233crite, qui[ENTER]se terminait abruptement \224 la 13e et derni\232re[ENTER]page\160? "
gameforge.main_quest_lv60._310_say = "Donc maintenant nous allons voir... Apparemment[ENTER]la Nation Obscure a lanc\233 une mal\233diction sur les[ENTER]grandes pr\234tresses du culte du Dragon et a[ENTER]utilis\233 la force sacr\233e des sept femmes afin de[ENTER]pratiquer l'art imm\233morial de la magie noire. "
gameforge.main_quest_lv60._320_say = "Pour invoquer Sung Mahi, il faut utiliser un sort[ENTER]de magie noire qui doit \234tre lanc\233 de sept lieux[ENTER]diff\233rents en m\234me temps.[ENTER]Pourtant Lee Seop et son arm\233e ont contr\233 le[ENTER]rituel \224 temps et ont fait \233chouer le plan[ENTER]mal\233fique de la Nation Obscure. "
gameforge.main_quest_lv60._330_say = "Cette nation avait des pratiques terrifiantes.[ENTER]Gr\226ce \224 la magie noire, elle \233tait en mesure de[ENTER]contr\244ler la conscience humaine. "
gameforge.main_quest_lv60._340_sendLetter = "L'indice "
gameforge.main_quest_lv60._350_say = "Uriel a d\233couvert des informations sur le[ENTER]monument Gum dans les textes anciens. Allez le[ENTER]voir pour en savoir plus. "
gameforge.main_quest_lv60._360_say = "Faisons le point ensemble sur ce que nous savons[ENTER]d\233j\224\160: Il y avait autrefois un peuple appel\233 la[ENTER]Nation Obscure qui \233tait au service du dieu des[ENTER]D\233mons Sung Mahi. Pour l'invoquer, ils ont tir\233[ENTER]parti de sept pr\234tresses du Dragon, ils ont[ENTER]utilis\233 leur force sacr\233e pour pratiquer l'art[ENTER]imm\233morial de la magie noire. Leur sort devait[ENTER]imp\233rativement \234tre lanc\233 de sept lieux[ENTER]diff\233rents \224 la fois. "
gameforge.main_quest_lv60._370_say = "Les pr\234tresses du Dragon ont lanc\233 le sort de[ENTER]magie noire depuis une tour seulement et non pas[ENTER]depuis sept lieux diff\233rents... C'est pour \231a que[ENTER]l'invocation de Sung Mahi n'a pas fonctionn\233\160! "
gameforge.main_quest_lv60._380_say = "La Nation Obscure a d\251 donner de mauvaises[ENTER]informations aux sept pr\234tresses du Dragon. "
gameforge.main_quest_lv60._390_say = "Peut-\234tre qu'elles non plus ne savaient pas...[ENTER]C'est peut-\234tre un hasard mais les textes anciens[ENTER]mettent en relation cette tour et le monument[ENTER]Gum. Il semble qu'il s'agisse ici de la Tour des[ENTER]d\233mons au temple de Hwang. "
gameforge.main_quest_lv60._400_say = "Nous avons enfin trouv\233 l'information[ENTER]d\233terminante sur les sept pr\234tresses du Dragon\160![ENTER]Reposez-vous un peu et nous allons vous raconter[ENTER]la prochaine \233tape. Je crains qu'il n'y ait un[ENTER]voyage \224 la Tour des d\233mons qui vous attende... "
gameforge.main_quest_lv60._40_say = "Oui, bien s\251r. Fuyant devant Lee Seop et sa[ENTER]cavalerie, sept personnes se sont r\233fugi\233es dans[ENTER]le temple de Hwang. En dernier recours, elles ont[ENTER]fait appel \224 la magie noire, ce qui est[ENTER]interdit... Au final, seule une d'entre elles a[ENTER]surv\233cu. "
gameforge.main_quest_lv60._410_sayReward = "La prochaine \233tape de cette aventure commencera[ENTER]d\232s que vous aurez atteint le niveau 66. "
gameforge.main_quest_lv60._50_say = "C'est \231a. J'ai fait des recherches[ENTER]suppl\233mentaires et j'ai d\233couvert que ces sept[ENTER]personnes \233taient membres du culte sacr\233 des[ENTER]pr\234tresses du Dragon. Dans les textes anciens,[ENTER]elles sont associ\233es \224 un peuple th\233ocratique[ENTER]appel\233 la Nation Obscure. Ces sept pr\234tresses du[ENTER]Dragon appartenaient-elles bien \224 cette[ENTER]myst\233rieuse nation\160? Ici, lisez enti\232rement ce[ENTER]myst\233rieux parchemin et revenez me parler quand[ENTER]vous aurez fini. "
gameforge.main_quest_lv60._60_sendLetter = "Nation Obscure I "
gameforge.main_quest_lv60._70_say = "D'apr\232s les recherches d'Uriel, les sept[ENTER]pr\234tresses du Dragon \233taient originaires de la[ENTER]Nation Obscure. Fouillez l'ancien tombeau dans le[ENTER]mont Sohan. C'est ici que devait se trouver la[ENTER]capitale de la Nation Obscure.[ENTER]Auparavant, parlez de nouveau avec Uriel. "
gameforge.main_quest_lv60._80_say = "Leur sorcellerie incroyablement d\233velopp\233e et le[ENTER]fait qu'elles aient \233t\233 an\233anties, si on en croit[ENTER]le journal de Lee Seop, indiquent que les sept[ENTER]pr\234tresses du Dragon appartenaient effectivement[ENTER]\224 la Nation Obscure. "
gameforge.main_quest_lv60._90_say = "Il y a une carte dans les textes anciens. En[ENTER]observant attentivement, on constate que la[ENTER]capitale de la Nation Obscure devait[ENTER]effectivement se trouver sur le mont Sohan. "
gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "Incroyable\160! Comprenez-vous ce que cela[ENTER]signifie\160? \192 l'origine il n'y avait ni d\233mons ni[ENTER]esprits dans la Tour des d\233mons. C'est le[ENTER]testament de la pr\234tresse du Dragon. Dans une[ENTER]derni\232re tentative d\233sesp\233r\233e pour an\233antir la[ENTER]cavalerie de Lee Seops, elle a ouvert aux d\233mons[ENTER]la porte de notre monde avec ce rituel maudit. Au[ENTER]final, elle l'a pay\233 de sa vie. "
gameforge.main_quest_lv66._10_sendLetter = "Le journal "
gameforge.main_quest_lv66._110_say = "C'est par l\224 que la faucheuse et son cort\232ge de[ENTER]d\233mons sont arriv\233s dans notre monde. Cependant,[ENTER]la grande mission de la Nation Obscure et des[ENTER]pr\234tresses du Dragon a \233chou\233\160: l'invocation de[ENTER]Sung Mahi n'a pas r\233ussi, le pouvoir de Lee Seop[ENTER]en est sorti renforc\233 et il a cr\233\233 au final un[ENTER]empire mondial unifi\233.[ENTER][ENTER]Gr\226ce \224 votre aide, le plus grand myst\232re de ma[ENTER]vie est enfin r\233solu\160! "
gameforge.main_quest_lv66._120_say = "Pour vous remercier, je voudrais vous offrir un[ENTER]parchemin de b\233n\233diction. Acceptez mon pr\233sent,[ENTER]j'insiste\160! "
gameforge.main_quest_lv66._130_sendLetter = "Vous avez du courrier. "
gameforge.main_quest_lv66._140_say = "Le gardien du village a une lettre pour vous.[ENTER]Lisez-la et d\233couvrez qui est le myst\233rieux[ENTER]exp\233diteur. "
gameforge.main_quest_lv66._150_say = "Vous vous \234tes fait rare ces derniers temps,[ENTER]non\160? Je dois vous donner cette lettre. Je ne[ENTER]sais pas du tout qui en est l'auteur, il ne s'est[ENTER]pas pr\233sent\233. "
gameforge.main_quest_lv66._160_say = "Le papier sur lequel la lettre a \233t\233 \233crite[ENTER]semble tr\232s ancien. Ces quelques mots ont \233t\233[ENTER]trac\233s rapidement\160:[ENTER]J'ai des informations importantes sur les sept[ENTER]pr\234tresses du Dragon et sur Sung Mahi. Je vous[ENTER]attends derri\232re la Tour des d\233mons au temple de[ENTER]Hwang.[ENTER]Vous me trouverez \224 l'ombre de l'arbre.[ENTER]D\233p\234chez-vous, le temps presse\160! "
gameforge.main_quest_lv66._170_sendLetter = "Lettre anonyme "
gameforge.main_quest_lv66._180 = "Rendez-vous au temple de Hwang et rencontrez-y le[ENTER]myst\233rieux exp\233diteur derri\232re la Tour des[ENTER]d\233mons. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "Je vous souhaite la bienvenue\160! Permettez-moi[ENTER]d'abord de me pr\233senter\160: je m'appelle Lee Chung.[ENTER]C'est tr\232s courageux de votre part de suivre les[ENTER]consignes d'un inconnu. Je ne me suis pas tromp\233[ENTER]\224 votre sujet, et vous n'allez pas le regretter.[ENTER]\201coutez ce que j'ai \224 vous dire\160! "
gameforge.main_quest_lv66._20_say = "Uriel a de nouvelles informations sur la derni\232re[ENTER]survivante des pr\234tresses du Dragon. Son journal[ENTER]doit se trouver dans la Tour des d\233mons. Allez[ENTER]voir Uriel afin d'en savoir plus. "
gameforge.main_quest_lv66._210_sendLetter = "Nouveau malheur "
gameforge.main_quest_lv66._220_say = "\201coutez ce que Lee Chung a \224 vous dire. "
gameforge.main_quest_lv66._230_say = "Ce n'est pas par hasard que je vous ai demand\233 de[ENTER]venir au temple de Hwang\160: ces derniers temps il[ENTER]s'y passe des choses \233tranges. Et il n'y a pas[ENTER]longtemps nous avons d\233couvert \224 l'arri\232re de la[ENTER]Tour des d\233mons l'entr\233e d'une gigantesque[ENTER]caverne\160! "
gameforge.main_quest_lv66._240_say = "Une gigantesque caverne\160? Et qu'y a-t-il \224[ENTER]l'int\233rieur\160? "
gameforge.main_quest_lv66._250_say = "Dans cette caverne nous attend un nouveau mal[ENTER]indescriptible. Nos \233claireurs ont fait \233tat[ENTER]d'une cr\233ature horrible qui fait peur aux d\233mons[ENTER]eux-m\234mes "
gameforge.main_quest_lv66._260_say = "Plus terrifiants que des d\233mons... Cette cr\233ature[ENTER]doit \234tre vraiment puissante et malfaisante. "
gameforge.main_quest_lv66._270_say = "Voil\224 l'histoire. Mes hommes et moi avons[ENTER]plusieurs fois essay\233 de donner l'assaut aux[ENTER]Catacombes du diable. Mais nous n'avons jamais[ENTER]r\233ussi et nous avons subi de lourdes pertes.[ENTER]Dans cette affaire, nous avons besoin de l'aide[ENTER]d'un excellent guerrier. C'est pourquoi nous[ENTER]avons fait appel \224 vous. Voulez-vous nous aider\160? "
gameforge.main_quest_lv66._280_say = "Oui, je vais vous aider. "
gameforge.main_quest_lv66._290_say = "Oh, voil\224 qui nous redonne espoir\160! Maintenant,[ENTER]comme je sais que vous \234tes des n\244tres, je vais[ENTER]vous r\233v\233ler toute la v\233rit\233\160: moi, Lee Chung,[ENTER]suis le commandant des combattans de l'ombre.[ENTER]Nous sommes une unit\233 secr\232te d'\233lite appartenant[ENTER]\224 l'arm\233e de Lee Seops. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ah, \231a fait plaisir de vous voir sauf et en bonne[ENTER]sant\233. \202tes-vous pr\234t pour de nouvelles[ENTER]aventures\160? Il nous manque toujours des[ENTER]informations importantes sur la Nation Obscure et[ENTER]les sept pr\234tresses du Dragon. La derni\232re[ENTER]pr\234tresse du Dragon a d\251 cacher son journal dans[ENTER]la Tour des d\233mons avant de pratiquer sa magie[ENTER]noire. Partez \224 l'aventure et ramenez-moi le[ENTER]journal. Il est peut-\234tre dans les griffes du roi[ENTER]d\233mon. "
gameforge.main_quest_lv66._310_say = "Les combattants de l'ombre poursuivent depuis[ENTER]lors leur objectif en secret\160: emp\234cher une[ENTER]nouvelle r\233surrection de Sung Mahi. Voil\224 notre[ENTER]mission. "
gameforge.main_quest_lv66._320_sendLetter = "Pas de temps "
gameforge.main_quest_lv66._330_say = "Lee Chung, le commandant des combattants de[ENTER]l'ombre, vous recherche. Il dit que c'est tr\232s[ENTER]urgent\160! "
gameforge.main_quest_lv66._340_say = "J'ai une requ\234te urgente. Voyez-vous les soldats[ENTER]bless\233s l\224-bas\160? Parmi eux se trouve un de mes[ENTER]\233claireurs parti sur mes ordres explorer les[ENTER]Catacombes du diable. Il y a \233t\233 attaqu\233 et[ENTER]empoisonn\233 par Agwi. Le poison est en train de se[ENTER]r\233pandre dans son corps et il ne lui reste plus[ENTER]beaucoup de temps. "
gameforge.main_quest_lv66._350_say = "Il a besoin d'un antidote. Et ce le plus vite[ENTER]possible\160![ENTER]Pouvez-vous lui en apporter\160? Vous en trouverez[ENTER]dans le Bois Rouge \224 c\244t\233 de la dryade rouge.[ENTER]C'est un de mes combattants les plus pr\233cieux.[ENTER]Sauvez-lui la vie et je vous donnerai %s. "
gameforge.main_quest_lv66._360_say = "Je vais aller chercher l'antidote\160! "
gameforge.main_quest_lv66._370_say = "Je vous remercie\160! Il est encore en vie mais il[ENTER]s'affaiblit \224 chaque instant. Nous n'avons pas de[ENTER]temps \224 perdre\160! "
gameforge.main_quest_lv66._380_notice = "Il vous reste encore %d minutes. "
gameforge.main_quest_lv66._390_sendLetter = "L'antidote "
gameforge.main_quest_lv66._400_say = "Lee Chung vous a expliqu\233 que vous trouverez[ENTER]l'antidote dans le Bois Rouge. Pour cela vous[ENTER]devez attraper %d dryades rouges.[ENTER][ENTER]Dans le Bois Rouge menacent des dangers encore[ENTER]plus grands que le bois enchant\233, alors prenez[ENTER]garde. "
gameforge.main_quest_lv66._40_say = "Vous avez vaincu le roi d\233mon et vous avez[ENTER]r\233cup\233r\233 le journal de la pr\234tresse du Dragon.[ENTER]Apportez-le au savant Uriel. Il l'analysera. "
gameforge.main_quest_lv66._410_say = "Le temps est \233coul\233. Le soldat est \224 l'article de[ENTER]la mort. Apportez-lui l'antidote le plus vite[ENTER]possible. "
gameforge.main_quest_lv66._420_say = "Il vous reste encore %d minutes. "
gameforge.main_quest_lv66._430_say = "Vous avez enfin trouv\233 l'antidote\160! Apportez-le[ENTER]vite \224 Lee Chung. "
gameforge.main_quest_lv66._440_say = "Par ici, vite ! Je crois que vous \234tes revenu \224[ENTER]temps. C'est un poids qu'on m'enl\232ve du coeur.[ENTER]Mes hommes et moi-m\234me vous sommes infiniment[ENTER]reconnaissants. "
gameforge.main_quest_lv66._450_say = "Gr\226ce \224 v\244tre aide mon soldat a surv\233cu. Voici[ENTER]votre r\233compense pour l'avoir sauv\233. "
gameforge.main_quest_lv66._460_say = "Cela vous a pris beaucoup de temps. Il se[ENTER]cramponne \224 la vie de ses derni\232res forces.[ENTER]Heureusement vous \234tes arriv\233 juste \224 temps. "
gameforge.main_quest_lv66._470_say = "On dirait qu'il va s'en sortir. Mais c'\233tait tr\232s[ENTER]juste, il \233tait presque mort tellement vous avez[ENTER]\233t\233 long \224 trouver l'antidote.[ENTER]Je suis d\233sol\233e, mais c'est tout ce que je peux[ENTER]vous donner en r\233compense. "
gameforge.main_quest_lv66._480_sendLetter = "Le rapport "
gameforge.main_quest_lv66._490_say = "L'\233claireur a repris conscience.[ENTER]\201coutez-le raconter ce qu'il a vu dans les[ENTER]Catacombes du diable. "
gameforge.main_quest_lv66._500_say = "Merci de m'avoir sauv\233. J'ai vu des choses[ENTER]incroyables dans les Catacombes du diable. Mais[ENTER]ensuite j'ai \233t\233 d\233couvert et ... "
gameforge.main_quest_lv66._50_say = "Vous l'avez trouv\233\160! Le journal de la derni\232re[ENTER]pr\234tresse du Dragon. Mes mains tremblent[ENTER]d'\233motion. Je vais avoir besoin de temps pour[ENTER]\233tudier ses lignes. Reposez-vous entre temps. Je[ENTER]vous appellerai quand je pourrai vous en dire[ENTER]plus. "
gameforge.main_quest_lv66._510_say = "Qu'avez-vous vu\160? "
gameforge.main_quest_lv66._520_say = "Il y avait des gens v\234tus de capes noires dont[ENTER]les capuches cachaient presque enti\232rement le[ENTER]visage. Des bribes de leurs conversations j'ai pu[ENTER]d\233duire que ce groupe faisait partie des[ENTER]serviteurs de l'Obscurit\233. Mais ce n'est pas[ENTER]tout\160: un esprit monstrueux qui a l'apparence[ENTER]d'une femme plane sur eux. Les serviteurs de[ENTER]l'Obscurit\233 l'appellent banshee. "
gameforge.main_quest_lv66._530_say = "\199a ne me dit rien de bon. Que pr\233parent les[ENTER]serviteurs de l'Obscurit\233 et cette banshee\160? "
gameforge.main_quest_lv66._540_say = "\192 travers un sort de magie noire la banshee[ENTER]invoque l'Agwi, l'\234tre diabolique qui vient[ENTER]directement des portes de l'Enfer. Le roi de[ENTER]l'Agwi s'appelle Azra\235l. "
gameforge.main_quest_lv66._550_say = "Je me suis d\233p\234ch\233 pour en informer Lee Chung au[ENTER]plus vite. Mais j'ai tr\233buch\233 et j'ai \233t\233[ENTER]d\233couvert.[ENTER]Ah, cela me rappelle que le commandant Lee Chung[ENTER]a encore quelque chose d'important \224 vous[ENTER]confier. Allez-le voir tout de suite. "
gameforge.main_quest_lv66._560_sendLetter = "Sombre menace "
gameforge.main_quest_lv66._570_say = "Allez voir Lee Chung et parlez-lui de la nouvelle[ENTER]menace qui r\244de dans les Catacombes du diable. "
gameforge.main_quest_lv66._580_say = "Ce que nous a rapport\233 notre \233claireur est[ENTER]effrayant n'est-ce pas\160? Les serviteurs de[ENTER]l'Obscurit\233, une sorte de secte, sont charg\233s de[ENTER]faire appara\238tre Agwi. Ils ont r\233veill\233 l'esprit[ENTER]de la derni\232re pr\234tresse du Dragon.[ENTER]Une banshee, une manifestation du Mal, est de[ENTER]retour dans notre monde et avec l'aide de ses[ENTER]forces magiques, ils vont maintenant invoquer le[ENTER]dieu des d\233mons Sung Mahi. "
gameforge.main_quest_lv66._590_say = "Quoi\160? Cette banshee est l'esprit de la derni\232re[ENTER]pr\234tresse du Dragon\160? "
gameforge.main_quest_lv66._600_say = "Sans aucun doute. M\234me parmi ses soeurs du culte[ENTER]du Dragon, elle \233tait la seule \224 d\233tenir le[ENTER]pouvoir d'appeler les quatre gardiens du ciel[ENTER]sacr\233s et de pratiquer la magie noire.[ENTER]D\233sormais nous savons qui se cache derri\232re la[ENTER]nouvelle menace\160: les serviteurs de l'Obscurit\233[ENTER]et la banshee ont pr\233vu d'achever l'oeuvre[ENTER]immonde de la Nation Obscure et de r\233veiller Sung[ENTER]Mahi\160! "
gameforge.main_quest_lv66._60_sendLetter = "La solution de la devinette "
gameforge.main_quest_lv66._610_say = "Nous vous devons beaucoup\160: vous avez sauv\233 un de[ENTER]mes meilleurs hommes d'une mort certaine et c'est[ENTER]seulement gr\226ce \224 vous que nous savons tout sur[ENTER]l'apparition brutale de l'Agwi et sur la nouvelle[ENTER]menace dans les Catacombes du diable.[ENTER]Maintenant, commencez par vour reposer, et[ENTER]ensuite nous r\233fl\233chirons \224 une tactique[ENTER]appropri\233e. "
gameforge.main_quest_lv66._620_say = "L'aventure continue d\232s que vous avez atteint le[ENTER]niveau 72. "
gameforge.main_quest_lv66._70_say = "Uriel vous cherche. Il a lu le journal. "
gameforge.main_quest_lv66._80_say = "Ah, tr\232s bien\160! Vous \234tes l\224.[ENTER]Les \233crits de la derni\232re pr\234tresse du Dragon[ENTER]sont dans les faits tr\232s \233tonnants. \201coutez[ENTER]bien\160: "
gameforge.main_quest_lv66._90_say = "Mon destin est scell\233\160! Je me suis barricad\233e au[ENTER]dernier \233tage de cette tour et les hommes de Lee[ENTER]Seops sont \224 deux doigts de briser la porte de ma[ENTER]derni\232re prison. Il n'y a pas d'issue... J'ai[ENTER]perdu.[ENTER]Non, \231a ne doit pas finir comme \231a\160! Ce n'est pas[ENTER]possible, pas tout \231a pour rien. Je dois faire[ENTER]appel \224 la magie noire, cette alli\233e imm\233moriale[ENTER]des mauvais, toute seule, et invoquer les forces[ENTER]obscures.[ENTER]Cela signifie que je ne m'en sortirai pas[ENTER]vivante. Mais j'entra\238nerai mes ennemis dans ma[ENTER]chute, m\234me si c'est la derni\232re chose que je[ENTER]dois faire\160! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "Quoi, vous ne l'avez pas encore apport\233 ? Le[ENTER]P\234cheur se trouve pr\232s de la rivi\232re. Allez[ENTER]d\233p\234chez-vous ! "
gameforge.main_quest_lv7._10_targetVid = "Une autre faveur "
gameforge.main_quest_lv7._110_npcChat = "Le Forgeron a envoy\233 cette nouveaut\233 ! "
gameforge.main_quest_lv7._120_say = "Merci. Je peux me d\233barrasser de cette vieille[ENTER]mais n\233anmoins jolie canne. Je ne gagne pas ma[ENTER]vie rien qu'en p\234chant, mais c'est mon plus grand[ENTER]plaisir. Avez-vous quelques connaissances en[ENTER]p\234che ? "
gameforge.main_quest_lv7._130_say = "D'abord, prenez la canne \224 p\234che dans votre main.[ENTER]Mettez une amorce sur le crochet. Jetez-le alors[ENTER]utilisant votre comp\233tence de p\234che. Si vous[ENTER]voyez qu'un poisson a mordu (une bulle[ENTER]l'indique), utilisez votre comp\233tence de p\234che de[ENTER]nouveau. Parfois \231a marche, parfois il faut[ENTER]retenter \224 nouveau. Il y a toutes sortes de[ENTER]poissons que vous pouvez attraper. Le poisson est[ENTER]bon pour votre sant\233 et parfois, vous p\234chez des[ENTER]tr\233sors de valeur. Essayez-le donc quand vous[ENTER]avez du temps \224 perdre ! "
gameforge.main_quest_lv7._140_say = "Oh oui, voici l'argent pour payer la canne \224[ENTER]p\234che. S'il te pla\238t, donne-la au forgeron. "
gameforge.main_quest_lv7._150_sayItem = "Paiement de la canne \224 p\234che "
gameforge.main_quest_lv7._160_sayReward = "Tu as donn\233 la canne \224 p\234che au p\234cheur. Retourne[ENTER]voir le forgeron avec l'argent et tu recevras ta[ENTER]r\233compense. "
gameforge.main_quest_lv7._170_say = "Avez-vous trouv\233 le p\234cheur\160?[ENTER]Formidable. Vous m'avez fait gagner beaucoup de[ENTER]temps en faisant cette course. En r\233compense, je[ENTER]vous donne des Yangs et 1\160500\160points[ENTER]d'exp\233rience. "
gameforge.main_quest_lv7._180_sendLetter = "Un bon pour une am\233lioration "
gameforge.main_quest_lv7._190_sayReward = "Avec ce bon, le forgeron vous raffinera[ENTER]gratuitement une partie de votre armure. Prenez[ENTER]une pi\232ce de votre armure et donnez-la au[ENTER]forgeron pour ouvrir la fen\234tre de raffinage. "
gameforge.main_quest_lv7._200_sayItem = "Bon pour le raffinage gratuit d'un objet "
gameforge.main_quest_lv7._20_sayReward = "Allez voir le forgeron. Il a besoin de quelqu'un[ENTER]pour faire une livraison pour lui. "
gameforge.main_quest_lv7._210_sayTitle = "Conseil : "
gameforge.main_quest_lv7._220_sayReward = "1) Le bon ne sera pas visible dans l'inventaire.[ENTER]2) Le succ\232s du raffinage \150 comme tout raffinage[ENTER]\150 n'est pas garanti \224 100 %. "
gameforge.main_quest_lv7._230_sayTitle = "Le bon a d\233j\224 \233t\233 utilis\233. "
gameforge.main_quest_lv7._240_sayReward = "Vous avez d\233j\224 utilis\233 votre bon pour un[ENTER]raffinage gratuit. Il n'est valable qu'une seule[ENTER]fois. "
gameforge.main_quest_lv7._30_say = "H\233, aventurier\160! Pouvez-vous me rendre une autre[ENTER]faveur\160? Habituellement, je ne demande pas \224[ENTER]d'autre personne de faire des choses pour moi,[ENTER]mais tu semble \234tre une personne de confiance.[ENTER]C'est tout \224 ton honneur\160! "
gameforge.main_quest_lv7._40_say = "J'ai fait une canne \224 p\234che pour le p\234cheur; mais[ENTER]je suis tr\232s occup\233. Je n'ai pas le temps de la[ENTER]lui donner moi-m\234me. Peux-tu le faire pour moi? "
gameforge.main_quest_lv7._50_sayItem = "Une canne \224 p\234che tr\232s flexible "
gameforge.main_quest_lv7._60_say = "Le p\234cheur devrait \234tre quelque part \224 c\244t\233 de la[ENTER]rivi\232re. Si tu donnes ce colis au p\234cheur, je[ENTER]raffinerai un objet de ton \233quipement[ENTER]gratuitement. C'est un bon deal, tu ne trouves[ENTER]pas ? "
gameforge.main_quest_lv7._70_sendLetter = "Trouvez le P\234cheur "
gameforge.main_quest_lv7._80_sayReward = "Le forgeron a fait une canne \224 p\234che pour le[ENTER]p\234cheur. Trouve le p\234cheur pr\232s de la rivi\232re, et[ENTER]donne-lui sa nouvelle canne \224 p\234che. "
gameforge.main_quest_lv7._90_npcChat = "Pour qui est la canne \224 p\234che ? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "Le lien magique qui unit la r\233sine d'arbre sacr\233,[ENTER]l'essence de cristal bleu et le quartz de l'enfer[ENTER]rouge donne \224 la larme du ciel son rayonnement[ENTER]parfait.[ENTER]L'essence de cristal bleu vous sera fournie par[ENTER]le seigneur de la Terre Glaciaire. "
gameforge.main_quest_lv72._10_sendLetter = "Pierre effrit\233e "
gameforge.main_quest_lv72._110_say = "Vous avez pris des notes sur cette inscription[ENTER]intrigante.[ENTER]Faites tout de suite votre rapport \224 Lee Chung[ENTER]sur ce que vous avez lu. "
gameforge.main_quest_lv72._120_say = "Vous \234tes revenu sain et sauf\160! \192 l'expression de[ENTER]votre visage, on dirait que vous avez r\233ussi\160? "
gameforge.main_quest_lv72._130_say = "Oui en effet\160! Gr\226ce \224 l'inscription sur la[ENTER]pierre effrit\233e, j'ai d\233couvert que les pouvoirs[ENTER]sacr\233s pouvaient \234tre invoqu\233s \224 travers une[ENTER]pierre pr\233cieuse magique appel\233e larme du ciel. "
gameforge.main_quest_lv72._140_say = "La larme du ciel... Elle existe donc vraiment.[ENTER]Avez-vous trouv\233 des informations sur comment se[ENTER]la procurer\160? "
gameforge.main_quest_lv72._150_say = "Pour fabriquer la larme du ciel, vous avez besoin[ENTER]de r\233sine de l'arbre sacr\233, de l'essence de[ENTER]cristal bleu et du quartz de l'enfer rouge. Il[ENTER]est \233crit que l'essence de cristal bleue peut[ENTER]\234tre obtenue aupr\232s du seigneur de la Terre[ENTER]Glaciaire. "
gameforge.main_quest_lv72._160_say = "Le seigneur de la Terre Glaciaire\160? Hmm... Il[ENTER]s'agit du mont Sohan.[ENTER]Je vais tout de suite montrer vos notes aux[ENTER]magiciens des combattants de l'ombre et nous[ENTER]allons \233tudier \231a ensemble.[ENTER]Je vous tiens au courant d\232s que j'en sais plus\160! "
gameforge.main_quest_lv72._170_say = "Consid\233rez cela comme votre r\233compense pour vos[ENTER]actions. Je compte sur vous pour continuer \224[ENTER]m'aider\160! "
gameforge.main_quest_lv72._180_sendLetter = "Tr\233sor glac\233 "
gameforge.main_quest_lv72._190_say = "Le commandant Lee Chung vous a dit que le premier[ENTER]\233l\233ment de la larme du ciel, l'essence de cristal[ENTER]bleu est le tr\233sor l\233gendaire gard\233 par[ENTER]Neuf-Queues sur le mont Sohan.[ENTER]Elle est surveill\233e tr\232s \233troitement par les[ENTER]golems de glace, les y\233tis et les hommes de glace[ENTER]furieux. Chassez ces monstres pour vous[ENTER]approprier l'essence de cristal bleu. Avant de[ENTER]vous lancer dans le combat, parlez encore une[ENTER]fois \224 Lee Chung. "
gameforge.main_quest_lv72._200_say = "Les magiciens des combattants de l'ombre ont[ENTER]d\233couvert que Neuf-Queues du mont Sohan garde[ENTER]l'essence bleue comme la prunelle de ses yeux. "
gameforge.main_quest_lv72._20_say = "Lee Chung, le commandant des combattants de[ENTER]l'ombre voudrait vous parler. Il a trouv\233 comment[ENTER]battre l'Agwi des Catacombes du diable. "
gameforge.main_quest_lv72._210_say = "Le tr\233sor du Neuf-Queues est gard\233 par des golems[ENTER]de glace, des y\233tis et des hommes de glace[ENTER]furieux.[ENTER]Pour fabriquer la larme du ciel, vous avez besoin[ENTER]de 50 essences de cristal bleu. "
gameforge.main_quest_lv72._220_say = "Le quartz de l'enfer rouge se trouve[ENTER]vraisemblablement dans le temple de Hwang ou dans[ENTER]la Terre de Feu.[ENTER]J'ai envoy\233 un \233claireur afin d'en savoir plus. "
gameforge.main_quest_lv72._230 = "Le commandant Lee Chung vous a dit que le premier[ENTER]\233l\233ment de la larme du ciel, l'essence de cristal[ENTER]bleu, est le tr\233sor l\233gendaire gard\233 par[ENTER]Neuf-Queues sur le mont Sohan.[ENTER]Elle est surveill\233e tr\232s \233troitement par les[ENTER]golems de glace, les y\233tis et les hommes de glace[ENTER]furieux. Chassez ces monstres pour vous[ENTER]approprier l'essence de cristal bleu. "
gameforge.main_quest_lv72._240_notice = "Vous fouillez les cadavres des monstres vaincus[ENTER]et trouvez une pierre pr\233cieuse bleue brillante.[ENTER]\199a doit \234tre l'essence de cristal bleu. "
gameforge.main_quest_lv72._250_notice = "Vous devez encore trouver %d essence(s) de[ENTER]cristal bleu. "
gameforge.main_quest_lv72._260_say = "Vous avez re\231u assez de conseils pour[ENTER]aujourd'hui. Revenez demain. "
gameforge.main_quest_lv72._270_say = "Ces cristaux sont inutiles. Voyez-vous m\234me\160: ils[ENTER]sont fissur\233s. Si vous voulez vous en servir, ils[ENTER]doivent \234tre impeccables. Continuez \224 chercher\160! "
gameforge.main_quest_lv72._280_say = "Ceux-ci sont d'une bien meilleure qualit\233.[ENTER]Continuez comme \231a\160! Apportez-moi en encore %d. "
gameforge.main_quest_lv72._290_say = "Vous avez collect\233 toutes les essences de cristal[ENTER]bleu. Je peux sentir le pouvoir du Neuf queue.[ENTER]Incroyable... Ils vibrent d'\233nergie. Bien jou\233\160! "
gameforge.main_quest_lv72._300_say = "L'aventure continue d\232s que vous avez atteint le[ENTER]niveau 78. "
gameforge.main_quest_lv72._30_say = "Au contraire des autres d\233mons, il n'est pas[ENTER]facile de venir \224 bout de l'Agwi. Nous,[ENTER]combattants de l'ombre, avons tout essay\233, sans[ENTER]succ\232s. "
gameforge.main_quest_lv72._40_say = "Mais j'ai d\233couvert que les pr\234tresses du Dragon[ENTER]avaient la capacit\233 d'utiliser les pouvoirs[ENTER]sacr\233s pour chasser les esprits mauvais. "
gameforge.main_quest_lv72._50_say = "Dans le Bois Rouge se trouvait jadis le temple[ENTER]sacr\233 des pr\234tresses du Dragon. Cherchez-y des[ENTER]ruines ou des vestiges d'un ancien culte. Les[ENTER]\233claireurs ont mentionn\233 une pierre effrit\233e[ENTER]envahie par les broussailles... Nous allons[ENTER]peut-\234tre y trouver des pr\233cisions[ENTER]suppl\233mentaires. "
gameforge.main_quest_lv72._60_sendLetter = "La d\233couverte "
gameforge.main_quest_lv72._70_say = "Lee Chung vous a appris que les pr\234tresses du[ENTER]Dragon pouvaient utiliser les pouvoirs sacr\233s,[ENTER]une magie blanche tr\232s ancienne, pour chasser les[ENTER]esprits mal\233fiques.[ENTER]Cherchez la pierre effrit\233e dans le Bois Rouge,[ENTER]celle dont vous a parl\233 Lee Chung, et obtenez des[ENTER]informations suppl\233mentaires. "
gameforge.main_quest_lv72._80_say = "Apr\232s de longues recherches, vous tombez dans les[ENTER]broussailles sur une pierre qui semble \234tre l\224[ENTER]depuis des si\232cles. \199a doit \234tre la pierre dont[ENTER]vous a parl\233 Lee Chung\160![ENTER]P\233niblement vous d\233chiffrez l'inscription abim\233e. "
gameforge.main_quest_lv72._90_say = "La larme du ciel est le secret le plus pr\233cieux[ENTER]des pr\234tresses du Dragon. L'art de sa fabrication[ENTER]est jalousement gard\233 depuis des g\233n\233rations et[ENTER]du sang a d\233j\224 \233t\233 vers\233 pour sa protection,[ENTER]quand c'\233tait n\233cessaire. Les Agwis et les d\233mons[ENTER]ne peuvent pas s'approcher du porteur de cette[ENTER]pierre pr\233cieuse magique. Quand la larme du ciel[ENTER]est remplie de la force des pouvoirs sacr\233s, son[ENTER]effet est quasiment foudroyant. Pendant 7 jours[ENTER]elle irradie, lumineuse comme l\146\233toile polaire au[ENTER]firmament. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "Ah, fantastique\160! \199a a fonctionn\233. Voici le[ENTER]quartz de l'enfer rouge. "
gameforge.main_quest_lv78._10_sendLetter = "Quartz de l'enfer rouge "
gameforge.main_quest_lv78._110_sendLetter = "Dernier \233l\233ment "
gameforge.main_quest_lv78._120_say = "Lee Chung et le conseil des magiciens ont[ENTER]d\233couvert que l'on pouvait trouver le dernier[ENTER]\233l\233ment, la r\233sine d'arbre sacr\233 dans l'arbre[ENTER]mal\233fique rouge. Partez \224 la recherche d'arbres[ENTER]mal\233fiques rouges dans le Bois Rouge et r\233coltez[ENTER]100 \233chantillons de r\233sine d'arbre sacr\233.[ENTER]Avant de vous lancer dans le combat, parlez[ENTER]encore une fois \224 Lee Chung. "
gameforge.main_quest_lv78._130_say = "Lee Chung et le conseil des magiciens ont[ENTER]d\233couvert que l'on pouvait trouver le dernier[ENTER]\233l\233ment, la r\233sine d'arbre sacr\233 dans l'arbre[ENTER]mal\233fique rouge. Partez \224 la recherche d'arbres[ENTER]mal\233fiques rouges dans le Bois Rouge et r\233coltez[ENTER]100 \233chantillons de r\233sine d'arbre sacr\233. "
gameforge.main_quest_lv78._140_say = "C'est la derni\232re \233tape avant la fabrication de[ENTER]la larme du ciel. Faites attention \224 vous, dans[ENTER]le Bois Rouge, les cr\233atures l\233tales grouillent\160! "
gameforge.main_quest_lv78._150_say = "Vous devez encore r\233colter %d \233chantillon(s) de[ENTER]r\233sine d'arbre sacr\233. "
gameforge.main_quest_lv78._160_notice = "Vous avez suffisamment de r\233sine d'arbre sacr\233\160![ENTER]Apportez tout \231a au commandant Lee Chung. "
gameforge.main_quest_lv78._170_say = "Est-ce la r\233sine d'arbre sacr\233\160? Je peux sentir[ENTER]son \233norme force. L\233gendaire\160! Malheureusement[ENTER]j'ai d\251 envoyer tous les magiciens en mission.[ENTER]Ils vont \234tre partis un moment. N'y a-t-il pas[ENTER]dans votre village natal un pharmacien nomm\233[ENTER]Baek-Go\160? "
gameforge.main_quest_lv78._180_say = "Oui, en effet. "
gameforge.main_quest_lv78._190_say = "Ah, \231a tombe bien\160! Prenez les trois \233l\233ments et[ENTER]apportez-les \224 Baek-Go. Il pourra alors fabriquer[ENTER]la larme du ciel. "
gameforge.main_quest_lv78._200_say = "Vous avez un voyage fatigant derri\232re vous.[ENTER]Acceptez cette r\233compense pour vous remercier de[ENTER]tous vos efforts. "
gameforge.main_quest_lv78._20_say = "Lee Chung, commandant des combattants de l'ombre,[ENTER]en a appris plus sur le quartz de l'enfer rouge.[ENTER]Pour le fabriquer, trois substances diff\233rentes[ENTER]sont n\233cessaires\160: terre volcanique du[ENTER]Doyyumhwan, crini\232re flamboyante et pierre de[ENTER]fondation. Chassez les flammes, les guerriers[ENTER]flammes et les tigres combattants en Terre de Feu[ENTER]pour atteindre ces substances.[ENTER]Rassemblez-en 20 pour former des quartz de[ENTER]l'enfer rouge. Avant de vous lancer dans le[ENTER]combat, parlez encore une fois \224 Lee Chung. "
gameforge.main_quest_lv78._210_sendLetter = "Larme du ciel "
gameforge.main_quest_lv78._220_say = "Retournez dans votre village natal et cherchez-y[ENTER]Baek-Go. Demandez-lui, au nom de Lee Chung, de[ENTER]fabriquer une larme du ciel \224 partir de ces trois[ENTER]\233l\233ments. "
gameforge.main_quest_lv78._230_say = "Vous avez \233t\233 absent quelque temps. Je me suis[ENTER]d\233j\224 demand\233 s'il vous \233tait arriv\233 quelque[ENTER]chose. Qu'est-ce qui vous am\232ne ? "
gameforge.main_quest_lv78._240_say = "Lee Chung m'a pri\233 de vous demander une faveur. "
gameforge.main_quest_lv78._250_say = "Lee Chung\160? Le commandant des combattants de[ENTER]l'ombre... Oh, chut\160! Moins fort\160! Devant vous se[ENTER]trouve un magicien des combattants de l'ombre.[ENTER]Mais c'est un secret bien gard\233 et personne dans[ENTER]le village n'est au courant.[ENTER]De quoi Lee Chung a-t-il besoin\160? "
gameforge.main_quest_lv78._260_say = "Il souhaiterait que vous fabriquiez une larme du[ENTER]ciel \224 partir de ces trois \233l\233ments. "
gameforge.main_quest_lv78._270_say = "La larme du ciel, tiens tiens... Il a tellement[ENTER]de magiciens qui travaillent pour lui, pourquoi[ENTER]me demande-t-il toujours \224 moi d'accomplir les[ENTER]t\226ches les plus difficiles\160?[ENTER]...[ENTER]Bon, passons. La voil\224, la larme du ciel.[ENTER]Magnifique\160! Je vais l'envoyer directement \224 Lee[ENTER]Chung avec un messager et il vous contactera[ENTER]quand tout sera pr\234t.[ENTER]Pouvez-vous me r\233v\233ler \224 quoi elle va servir\160? "
gameforge.main_quest_lv78._280_say = "Je ne peux malheureusement pas vous dire[ENTER]exactement. Voici tout ce que je peux vous dire\160:[ENTER]cette pierre convoque les forces sacr\233es pour[ENTER]chasser les d\233mons et autres esprits mal\233fiques. "
gameforge.main_quest_lv78._290_say = "Tr\232s int\233ressent. Je vous souhaite bien du succ\232s[ENTER]dans votre mission. Voici deux t\234tes r\233duites[ENTER]pour vous remercier de vos efforts.[ENTER]Maintenant que je sais de quoi il s'agit, je vous[ENTER]aiderai volontiers si vous avez besoin d'une[ENTER]deuxi\232me larme du ciel.[ENTER]Oh, et pouvez-vous passer bien le bonjour \224 Lee[ENTER]Chung de ma part\160? "
gameforge.main_quest_lv78._300_say = "L'aventure continue d\232s que vous avez atteint le[ENTER]niveau 84. "
gameforge.main_quest_lv78._30_say = "Nos magiciens ont d\233couvert que le quartz de[ENTER]l'enfer rouge, qui est utilis\233 pour la[ENTER]fabrication de la larme du ciel, est porteur du[ENTER]pouvoir du feu. Ce quartz doit \234tre la source de[ENTER]la force incroyable des cr\233atures de la Terre de[ENTER]Feu. "
gameforge.main_quest_lv78._40_say = "Trois substances sont n\233cessaires \224 la[ENTER]fabrication du quartz de l'enfer rouge\160: terre[ENTER]volcanique du Doyyumhwan, crini\232re flamboyante et[ENTER]pierre de fondation. "
gameforge.main_quest_lv78._50_say = "Vous avez r\233ussi\160! Nous avons enfin les %d[ENTER]\233l\233ments n\233cessaires \224 la fabrication du quartz[ENTER]de l'enfer rouge. Votre bravoure et votre[ENTER]aptitudes au combat m'ont une nouvelle fois[ENTER]impressionn\233\160! "
gameforge.main_quest_lv78._60_say = "Il manque un ingr\233dient. Nous avons besoin de[ENTER]terre volcanique, de crini\232re flamboyante ainsi[ENTER]que de pierre de fondation. "
gameforge.main_quest_lv78._70_say = "Je suis d\233sol\233, mais je ne peux pas fabriquer[ENTER]plus de sept pi\232ces de quartz de l'enfer rouge[ENTER]par jour. Ce produit est un d\233fi pour mes[ENTER]comp\233tences magiques. En fin de compte, je ne[ENTER]suis pas un magicien\160! "
gameforge.main_quest_lv78._80_say = "C'est parti\160! Je vais maintenant m\233langer les[ENTER]trois substances et essayer de fabriquer un[ENTER]quartz de l'enfer rouge. "
gameforge.main_quest_lv78._90_say = "Argh\160! Le sort a \233chou\233. Apparemment j'ai[ENTER]surestim\233 mes capacit\233s magiques. \199a marchera[ENTER]s\251rement mieux la prochaine fois. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "Apr\232s avoir vaincu le g\233n\233ral Tartare, l'acc\232s[ENTER]vers un niveau jusqu'alors cach\233 des Catacombes[ENTER]du diable sera ouvert. C'est l\224 que doit se[ENTER]trouver le prince Charon\160! T\233l\233portez-vous au 6e[ENTER]niveau et faites face au prince de l'Agwi. Mais[ENTER]attention\160! Il est extr\234mement fort et malin[ENTER]comme un diable\160! "
gameforge.main_quest_lv84._10_sendLetter = "Le combat commence "
gameforge.main_quest_lv84._110_say = "Vu comme vous vous agitez dans les Catacombes du[ENTER]diable, libre et sans peur, vous ne pouvez pas[ENTER]\234tre un mortel normal\160![ENTER]L'ob\233lisque en basalte au 5e niveau sert de porte[ENTER]vers le 6e niveau, cach\233. "
gameforge.main_quest_lv84._120_say = "C'est d'ici que le prince Charon donne tous ses[ENTER]ordres au g\233n\233ral Agwi Tartare.[ENTER]Qu'attendez-vous encore? Battez Charon et faites[ENTER]\233chouer les sombres plans des serviteurs de[ENTER]l'Obscurit\233 et de la banshee\160! "
gameforge.main_quest_lv84._130_sayReward = "Vous avez r\233ussi\160! Charon, prince de l'Agwi, a[ENTER]\233t\233 \233cras\233. "
gameforge.main_quest_lv84._140_say = "Fourbu et soulag\233, vous essuyez la sueur de votre[ENTER]front.[ENTER]Mais soudain un rire strident \233branle les[ENTER]Catacombes du diable, tellement aigu qu'il[ENTER]p\233n\232tre jusqu'aux os.[ENTER][ENTER]Hahahaha\160! Trop tard, ridicules humains\160! Notre[ENTER]ma\238tre, Sung Mahi, est d\233j\224 revenu et vous ne[ENTER]pouvez plus rien faire pour l'arr\234ter.[ENTER]Le jour o\249 Sung Mahi retrouvera compl\232tement ses[ENTER]pouvoirs sur l'\238le o\249 dorment les mauvais dragons[ENTER]est proche. Votre monde est vou\233 \224 sa perte\160! "
gameforge.main_quest_lv84._150_sendLetter = "Histoire inachev\233e "
gameforge.main_quest_lv84._160_say = "Allez voir Lee Chung et informez-le du message[ENTER]mena\231ant de la banshee. "
gameforge.main_quest_lv84._170_say = "Apr\232s avoir rapport\233 vos victoires sur Tartare et[ENTER]Charon au commandant, r\233p\233tez-lui le message[ENTER]terrifiant de la banshee.[ENTER]D'un air grave, il commence \224 parler\160: "
gameforge.main_quest_lv84._180_say = "Je pensais qu'en vainquant le prince Agwi, nous[ENTER]allions faire \233chouer les sombres plans des[ENTER]serviteurs de l'Obscurit\233 et de la banshee. Loin[ENTER]de l\224... "
gameforge.main_quest_lv84._190_say = "La banshee, avec l'aide d'Azra\235l, le mal\233fique[ENTER]roi de l'Agwi, a d\251 s'occuper de la r\233surrection[ENTER]du dieu des d\233mons Sung Mahi. Je fr\233mis \224 cette[ENTER]id\233e... "
gameforge.main_quest_lv84._200_say = "L'\238le sur laquelle dorment les mauvais dragons...[ENTER]Hum, il doit \234tre question du rocher du Dragon[ENTER]Sombre, une \238le inexplor\233e tr\232s loin d'ici. M\234me[ENTER]si nous n'avons pas atteint notre but, nous vous[ENTER]devons beaucoup. Sans vous, nous n'aurions jamais[ENTER]connu la source du malheur qui r\244de dans les[ENTER]profondeurs des Catacombes du diable. "
gameforge.main_quest_lv84._20_say = "Lee Chung a obtenu la larme du ciel et tout est[ENTER]pr\234t pour votre incursion dans les Catacombes du[ENTER]diable. Allez le voir pour en savoir plus. "
gameforge.main_quest_lv84._210_say = "Vous avez vraiment fait beaucoup, personne[ENTER]d'autre que vous n'\233tait en mesure d'en faire[ENTER]autant. Je serai toujours \224 vos c\244t\233s quand vous[ENTER]aurez besoin de moi. Bonne chance\160! "
gameforge.main_quest_lv84._30_say = "Maintenant que la larme du ciel est entre nos[ENTER]mains, ce n'est plus qu'une question de temps[ENTER]avant les serviteurs de l'Obscurit\233 soient[ENTER]vaincus et que l'Agwi soit chass\233 de notre monde.[ENTER]Mais la force de la larme du ciel ne se d\233ploie[ENTER]compl\232tement que si elle est enclench\233e dans un[ENTER]endroit pr\233cis des Catacombes du diable. "
gameforge.main_quest_lv84._40_say = "Nous avons connaissance de 5 niveaux dans les[ENTER]Catacombes du diable. Au 5e et dernier niveau[ENTER]connu vous rencontrerez Tartare, le cruel g\233n\233ral[ENTER]Agwi et 3e dans la hi\233rarchie sous le roi Azra\235l[ENTER]et le prince Charon. An\233antissez-le \224 l'aide de[ENTER]la larme du ciel\160! "
gameforge.main_quest_lv84._50_say = "Mais o\249 se cache le prince Charon\160? "
gameforge.main_quest_lv84._60_sendLetter = "G\233n\233ral Tartare "
gameforge.main_quest_lv84._70_say = "N'utilisez la larme du ciel que quand vous avez[ENTER]atteint le 5e niveau des Catacombes du diable.[ENTER]L'entr\233e des Catacombes du diable se trouvent[ENTER]derri\232re la Tour des d\233mons. "
gameforge.main_quest_lv84._80_say = "Les pouvoirs sacr\233s commencent \224 agir dans la[ENTER]larme du ciel. Vous sentez une \233nergie[ENTER]monstrueuse affluer dans votre corps. La force de[ENTER]cette pierre est incroyable\160![ENTER][ENTER]An\233antissez le g\233n\233ral Tartare. "
gameforge.main_quest_lv84._90_sendLetter = "Prince Charon "
gameforge.main_quest_lv9 = {}
gameforge.main_quest_lv9._10_targetVid = "Trouvez le Garde du Village "
gameforge.main_quest_lv9._20_sendLetter = "Parlez au Garde du Village "
gameforge.main_quest_lv9._30_sayReward = "Vous avez franchi les premi\232res \233tapes pour[ENTER]devenir un h\233ros. Il est temps de passer aux[ENTER]choses s\233rieuses. Allez voir le Garde du Village[ENTER]pour conna\238tre votre derni\232re mission en tant que[ENTER]d\233butant. "
gameforge.main_quest_lv9._40_say = "Je pense que tu es pr\234t pour des missions plus[ENTER]difficiles. Elles ne seront pas aussi facile que[ENTER]les pr\233c\233dentes. Tu as \224 travailler dur pour le[ENTER]futur de notre empire, et tu devras combattre[ENTER]plusieurs fois. Peut-\234tre souffriras-tu, mais[ENTER]n'oublie jamais de rester debout. Tu as finis[ENTER]quelques missions. Voici pour r\233compenser tes[ENTER]efforts. J'esp\232re que cela te sera utile. "
gameforge.main_quest_lv9._50_say = "\192 partir de maintenant, Le capitaine te guidera.[ENTER]Il te surveillera dans le futur, et te donnera[ENTER]des missions. Engrange encore plus de points[ENTER]d'exp\233riences, et apr\232s va voir le capitaine.[ENTER]Bonne chance! "
gameforge.main_quest_lv90 = {}
gameforge.main_quest_lv90._010_sendLetter = "Rocher du Dragon Sombre "
gameforge.main_quest_lv90._020_say = "Votre voyage \233tait long et p\233nible. Cependant,[ENTER]vous avez enfin atteint votre objectif\160: le[ENTER]rocher du Dragon Sombre. Cherchez l'amiral[ENTER]Angmur. Vous le trouverez au Cap du Feu[ENTER]dragonesque. "
gameforge.main_quest_lv90._030_say = "Bienvenue au rocher du Dragon Sombre, \233tranger\160![ENTER]\202tes-vous venu pour nous aider \224 combattre Sung[ENTER]Mahi\160? "
gameforge.main_quest_lv90._040_say = "Oui, pr\233cis\233ment. Lee Chung, le chef des[ENTER]combattants de l'ombre, m'envoie. "
gameforge.main_quest_lv90._050_say = "Lee Chung\160! Nous sommes de vieux compagnons. Vous[ENTER]\234tes donc ici parce qu'il vous l'a ordonn\233. Ah,[ENTER]alors je sais que je peux vous faire confiance. "
gameforge.main_quest_lv90._060_say = "Je vous remercie. Maintenant, faites-moi un[ENTER]compte-rendu de la situation. "
gameforge.main_quest_lv90._070_say = "Les d\233mons contr\244lent de vastes r\233gions de l'\238le.[ENTER]Rien ni personne n'est en s\233curit\233 face \224 eux.[ENTER]Ils se mangent m\234me entre eux. L'influence sombre[ENTER]de Sung Mahi leur font perdre la raison. "
gameforge.main_quest_lv90._080_say = "Je pourrais avoir besoin de votre aide.[ENTER]Pourriez-vous explorer l'\238le et me faire un[ENTER]rapport\160? "
gameforge.main_quest_lv90._090_say = "Bien entendu. "
gameforge.main_quest_lv90._1000_say = "D'accord. "
gameforge.main_quest_lv90._100_say = "Je vous remercie. Attendez, je vous montre le[ENTER]chemin. "
gameforge.main_quest_lv90._1010_say = "Vous \234tes tr\232s appliqu\233, mais malheureusement,[ENTER]cela ne suffit pas encore. Continuez \224 en[ENTER]ramasser\160! "
gameforge.main_quest_lv90._1020_sayTitle = "Ramasser des briques "
gameforge.main_quest_lv90._1030_say = "Partez au combat contre la manticore afin de[ENTER]ramasser des briques. "
gameforge.main_quest_lv90._1040_1_notice = "Vous avez ramass\233 assez de briques. "
gameforge.main_quest_lv90._1040_2_notice = "Portez-les \224 l'amiral Angmur. "
gameforge.main_quest_lv90._1050_say = "Parlez \224 l'amiral Angmur. "
gameforge.main_quest_lv90._1060_say = "Tr\232s bien, gr\226ce \224 vous, nous avons assez de[ENTER]mat\233riaux pour renforcer le mur de d\233fense. D\232s[ENTER]que nous serons pr\234ts, je vous ferai appeler. "
gameforge.main_quest_lv90._1070_sendLetter = "La mission de Lee Chung "
gameforge.main_quest_lv90._1080_say = "Lee Chung a une mission \224 vous proposer. "
gameforge.main_quest_lv90._1090_say = "De mauvaises nouvelles nous r\233unissent \224[ENTER]nouveau\160: les serviteurs de l'Obscurit\233 sont[ENTER]proches du but. Bient\244t Sung Mahi sera bient\244t[ENTER]invincible.[ENTER]Nous n'avons pas de temps \224 perdre\160! Allez au[ENTER]t\233l\233porteur. De l\224, un navire vous emm\232nera au[ENTER]rocher du Dragon Sombre. Une fois l\224-bas,[ENTER]cherchez l'amiral Angmur. J'ai d\233j\224 envoy\233 une[ENTER]lettre pour annoncer votre arriv\233e. "
gameforge.main_quest_lv90._1100_say = "Je pars imm\233diatement. "
gameforge.main_quest_lv90._110_sayReward = "Explorez le rocher du Dragon Sombre. Commencez[ENTER]par ici\160: (%d, %d). "
gameforge.main_quest_lv90._1110_sayTitle = "D\233part pour l'\238le "
gameforge.main_quest_lv90._1120_say = "Allez au t\233l\233porteur. Il vous emm\232nera au rocher[ENTER]du Dragon Sombre. "
gameforge.main_quest_lv90._1160_targetInfo = "La fl\232che sur le PNJ vous indique que celui-ci[ENTER]souhaite vous parler. Si vous ne voyez pas le PNJ[ENTER]sur votre \233cran, suivez le point clignotant sur[ENTER]votre mini-carte. "
gameforge.main_quest_lv90._1170_posInfo = "Suivez le point clignotant sur la mini-carte. "
gameforge.main_quest_lv90._1180_say = "Restants "
gameforge.main_quest_lv90._1180_say_count = "Das Item %s bekommst du in %s kills. "
gameforge.main_quest_lv90._1190_say = "%s\160: %d pi\232ces "
gameforge.main_quest_lv90._1200_say = "L'aventure continue d\232s que vous avez atteint le[ENTER]niveau 91. "
gameforge.main_quest_lv90._120_sayTitle = "Rapport "
gameforge.main_quest_lv90._130_say = "Allez sur l'\238le et ensuite allez faire un rapport[ENTER]\224 l'amiral Angmur. "
gameforge.main_quest_lv90._140_sayReward = "C'est votre premi\232re destination\160: %d, %d "
gameforge.main_quest_lv90._150_sayReward = "Vous avez atteint votre premi\232re destination. La[ENTER]prochaine est\160: (%d, %d) "
gameforge.main_quest_lv90._160_say = "Vous n'avez pas encore visit\233 toutes les r\233gions.[ENTER]Veuillez explorer davantage de r\233gions. "
gameforge.main_quest_lv90._170_sayReward = "Votre deuxi\232me objectif est\160: %d, %s "
gameforge.main_quest_lv90._180_sayReward = "Vous avez atteint votre deuxi\232me objectif.[ENTER]Le suivant est\160: (%d, %d) "
gameforge.main_quest_lv90._190_say = {}
gameforge.main_quest_lv90._200_say = {}
gameforge.main_quest_lv90._210_sayReward = "Votre troisi\232me objectif est\160: %d, %d "
gameforge.main_quest_lv90._220_sayReward = "Vous avez explor\233 toutes les r\233gions. Retournez[ENTER]voir l'amiral Angmur. "
gameforge.main_quest_lv90._230_say = "Parlez \224 l'amiral Angmur. "
gameforge.main_quest_lv90._240_say = "Apr\232s avoir parcouru toute l'\238le, vous \234tes s\251r[ENTER]d'une chose\160: les d\233mons sont partout. "
gameforge.main_quest_lv90._250_say = "Vous avez fait du bon travail. Prenez ceci en[ENTER]guise de remerciement pour votre aide. "
gameforge.main_quest_lv90._260_sendLetter = "La lettre de Lee Chung "
gameforge.main_quest_lv90._270_say = "Alors que vous d\233crivez la situation actuelle au[ENTER]rocher du Dragon Sombre, le regard de l'amiral[ENTER]Angmur s'assombrit. "
gameforge.main_quest_lv90._280_say = "Je regrette de ne pas vous apporter de meilleures[ENTER]nouvelles. "
gameforge.main_quest_lv90._290_say = "Les d\233mons sur l'\238le deviennent de plus en plus[ENTER]forts. Si nous ne pouvons pas arr\234ter Sung Mahi[ENTER]et les serviteurs de l'Obscurit\233, puisse le dieu[ENTER]Dragon avoir piti\233 de nous. "
gameforge.main_quest_lv90._300_say = "Oui, je le reconnais, cela ne s'annonce pas tr\232s[ENTER]bien. "
gameforge.main_quest_lv90._310_say = "Ah \231a, vous pouvez le dire...[ENTER]Lee Chung a d\251 d\233couvrir un indice capital. Il[ENTER]m'a envoy\233 une lettre avec des informations[ENTER]importantes. Mais je ne l'ai jamais re\231ue. Le[ENTER]messager s'est fait attaquer par des Gnolls. "
gameforge.main_quest_lv90._320_say = "Nous devons trouver cette lettre. Pouvez-vous[ENTER]nous aider\160? "
gameforge.main_quest_lv90._330_say = "Bien s\251r. Je suis d\233j\224 en chemin. "
gameforge.main_quest_lv90._340_say = "Je vous remercie. Les Gnolls sont \233tablis juste \224[ENTER]c\244t\233. "
gameforge.main_quest_lv90._350_sayTitle = "Trouvez la lettre de Lee Chung. "
gameforge.main_quest_lv90._360_say = "Une des cr\233atures suivantes poss\232de la lettre de[ENTER]Lee Chung\160: le combattant gnoll, l'archer gnoll,[ENTER]le d\233fenseur gnoll, le magicien gnoll, le g\233n\233ral[ENTER]gnoll, le seigneur gnoll ou le garde gnoll[ENTER]supr\234me "
gameforge.main_quest_lv90._370_say = "Si nous voulons arr\234ter Sung Mahi, nous avons[ENTER]besoin de cette lettre\160! Le voleur provient des[ENTER]rangs de la tribu des Gnolls. "
gameforge.main_quest_lv90._380_1_notice = "Vous avez trouv\233 la lettre. "
gameforge.main_quest_lv90._380_2_notice = "Apportez-la \224 l'amiral Angmur. "
gameforge.main_quest_lv90._390_say = "Parlez \224 l'amiral Angmur. "
gameforge.main_quest_lv90._400_say = "Vous \234tes de retour. Et vous avez la lettre\160! Ah,[ENTER]je savais que je pouvais compter sur vous.[ENTER]Donnez-la-moi. "
gameforge.main_quest_lv90._410_say = "Salutations Angmur, Cher ami, voici ce que nous[ENTER]avons trouv\233 dans les camps abandonn\233s de Sung[ENTER]Mahi\160: les serviteurs de l'obscurit\233 ont fait[ENTER]parvenir des informations secr\232tes \224 leurs alli\233s[ENTER]sur l'\238le. Une lettre est parvenue \224 la tribu des[ENTER]Gnolls. Si vous pouviez intercepter celle-ci,[ENTER]nous devancerions les d\233mons\160! J'envoie %s pour[ENTER]vous soutenir et je vous souhaite bon courage[ENTER]ainsi que de rester fort en ces temps troubl\233s.[ENTER]L.C. "
gameforge.main_quest_lv90._420_say = "Mes \233claireurs vont nous apprendre si les Gnolls[ENTER]ont d\233j\224 re\231u la lettre. En attendant prenez ceci[ENTER]en guise de remerciement. "
gameforge.main_quest_lv90._430_sendLetter = "La lettre gnolle I "
gameforge.main_quest_lv90._440_say = "L'amiral Angmur vous recherche. Essayez de savoir[ENTER]ce qu'il d\233sire. "
gameforge.main_quest_lv90._450_say = "Le g\233n\233ral gnoll a d\233j\224 re\231u la lettre du[ENTER]serviteur. Pouvez-vous nous l'apporter? Mais[ENTER]attention\160: les Gnolls sont extr\234mement[ENTER]agressifs.[ENTER]D'abord ils frappent, ensuite ils posent des[ENTER]questions. "
gameforge.main_quest_lv90._460_say = "Je suis d\233j\224 en route. "
gameforge.main_quest_lv90._470_say = "Merci, je savais que nous pouvions compter sur[ENTER]vous. "
gameforge.main_quest_lv90._480_sayTitle = "Trouvez la lettre gnolle\160! "
gameforge.main_quest_lv90._490_say = "Trouvez le g\233n\233ral Gnoll. C'est lui qui a la[ENTER]lettre\160! "
gameforge.main_quest_lv90._500_say = "Nous n'avons pas de temps \224 perdre. D\233p\234chez-vous[ENTER]et apportez-moi cette lettre. "
gameforge.main_quest_lv90._510_1_notice = "Vous avez re\231u la lettre gnolle. "
gameforge.main_quest_lv90._510_2_notice = "Apportez-la \224 l'amiral Angmur. "
gameforge.main_quest_lv90._520_say = "Parlez \224 l'amiral Angmur. "
gameforge.main_quest_lv90._530_say = "Vous avez la lettre\160! Enfin des bonnes nouvelles.[ENTER]Hmm...[ENTER]Je n'arrive pas \224 la lire. La lettre est[ENTER]apparemment cod\233e.[ENTER]Notre savant s'y conna\238t en cryptologie. Je vais[ENTER]tout de suite le chercher. D\232s que j'en saurai[ENTER]plus, je vous le ferai savoir. "
gameforge.main_quest_lv90._540_say = {}
gameforge.main_quest_lv90._550_say = {}
gameforge.main_quest_lv90._560_sendLetter = "La lettre gnolle II "
gameforge.main_quest_lv90._570_say = "L'amiral Angmur vous recherche. Cela semble[ENTER]important. D\233couvrez ce qu'il attend de vous. "
gameforge.main_quest_lv90._580_say = "La lettre cod\233e comporte deux pages. Pour pouvoir[ENTER]d\233coder le message, il faut superposer les deux.[ENTER]Le seigneur gnoll poss\232de la deuxi\232me page.[ENTER]Pouvez-vous nous aider\160? "
gameforge.main_quest_lv90._590_say = "Bien entendu. "
gameforge.main_quest_lv90._600_say = "Merci. Votre aide est pr\233cieuse\160! "
gameforge.main_quest_lv90._610_sayTitle = "La lettre gnolle II "
gameforge.main_quest_lv90._620_say = "Trouvez la deuxi\232me page de la lettre gnolle\160![ENTER]Vous pouvez l'obtenir aupr\232s du seigneur gnoll. "
gameforge.main_quest_lv90._630_say = "Le temps presse\160! D\233p\234chez-vous de trouver la[ENTER]deuxi\232me page de la lettre. "
gameforge.main_quest_lv90._640_1_notice = "Vous avez retrouv\233 la deuxi\232me page. Apportez-la[ENTER]\224 l'amiral Angmur. "
gameforge.main_quest_lv90._650_say = "Parfait, \224 pr\233sent, nous pouvons d\233chiffrer le[ENTER]message\160: Hmm, il est question de dragons qui[ENTER]dorment profond\233ment au c\156ur de la terre. Et[ENTER]d'une m\233thode gr\226ce \224 laquelle on peut les[ENTER]r\233veiller et les rendre furieux. Oh, oh, cela ne[ENTER]me dit rien qui vaille... "
gameforge.main_quest_lv90._660_say = {}
gameforge.main_quest_lv90._670_say = "Apparemment, les manticores et les voleurs rouges[ENTER]ont \233galement re\231u des lettres. Je dois en savoir[ENTER]plus et ensuite je vous ferai appeler. "
gameforge.main_quest_lv90._680_say = "L'amiral Angmur a une mission \224 vous proposer. "
gameforge.main_quest_lv90._690_sendLetter = "La manticore "
gameforge.main_quest_lv90._700_say = "L'amiral Angmur a une nouvelle qu\234te \224 vous[ENTER]proposer. "
gameforge.main_quest_lv90._710_say = "Ah, enfin vous voil\224\160! Nos informations sur la[ENTER]manticore sont trop anciennes. Nous devons[ENTER]conna\238tre l'\233tat actuel de leurs forces. "
gameforge.main_quest_lv90._720_say = "Pouvez-vous les espionner\160? Leur camp se situe[ENTER]non loin d'ici. "
gameforge.main_quest_lv90._730_say = "Bien s\251r. Qu'est-ce que je dois faire\160? "
gameforge.main_quest_lv90._740_say = "\201liminez 50 combattants manticores, 40 soldats[ENTER]manticores, 20\160bourreaux manticores ainsi que 10[ENTER]fois le g\233n\233ral core.[ENTER]Ensuite, venez me faire un rapport. "
gameforge.main_quest_lv90._750_say = "Restants "
gameforge.main_quest_lv90._760_say = "%s\160: %d[ENTER]%s\160: %d "
gameforge.main_quest_lv90._770_say = "Ces informations ne suffisent pas. Vous devez en[ENTER]apprendre plus. "
gameforge.main_quest_lv90._780_1_notice = "Vous avez appris des informations utiles sur les[ENTER]manticores. "
gameforge.main_quest_lv90._780_2_notice = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv90._790_say = "Avez-vous accompli votre mission? Tr\232s bien.[ENTER]Alors faites-moi un rapport sur la situation[ENTER]actuelle. "
gameforge.main_quest_lv90._800_say = "Les troupes des manticores ne sont pas[ENTER]particuli\232rement nombreuses. Vous leur \234tes[ENTER]sup\233rieur en nombre. Mais leurs combattants sont[ENTER]tr\232s bien form\233s et extr\234mement combatifs. Je[ENTER]vous conseillerais de renforcer le mur de[ENTER]protection autour du fort, sinon il ne r\233sistera[ENTER]pas \224 un assaut des manticores. "
gameforge.main_quest_lv90._810_say = "Ouh, ce sont les informations dont nous avions[ENTER]besoin. Je vais suivre vos conseils et renforcer[ENTER]le mur de protection.[ENTER]Voici votre r\233compense. "
gameforge.main_quest_lv90._820_say = "Parlez \224 l'amiral Angmur. "
gameforge.main_quest_lv90._830_sayTitle = "Troupes de la manticore "
gameforge.main_quest_lv90._840_say = "Battez 50 combattants manticores, 40 soldats[ENTER]manticores, 20\160bourreaux manticores ainsi que 10[ENTER]fois le g\233n\233ral core. "
gameforge.main_quest_lv90._850_sendLetter = "Renforcer le mur de protection I "
gameforge.main_quest_lv90._860_say = "L'amiral Angmur vous cherche. Cela semble[ENTER]important, allez le voir imm\233diatement. "
gameforge.main_quest_lv90._870_say = "Ah, vous voil\224 enfin. Vous aviez raison, notre[ENTER]mur de protection ne r\233sistera \224 aucun assaut.[ENTER]Cependant, il nous manque un mat\233riau pour le[ENTER]renforcer. "
gameforge.main_quest_lv90._880_say = "Nous avons besoin de briques et de sable fin.[ENTER]Pourriez-vous nous procurer ces mat\233riaux de[ENTER]construction\160? "
gameforge.main_quest_lv90._890_say = "Bien entendu. "
gameforge.main_quest_lv90._900_say = "Tr\232s bien. Allez d'abord chercher du sable fin.[ENTER]Les Gnolls en poss\232dent d'importants gisements.[ENTER]50 seaux devraient suffire. "
gameforge.main_quest_lv90._910_sayTitle = "Sable fin "
gameforge.main_quest_lv90._920_say = "Combattez les Gnolls et rapportez 50 seaux de[ENTER]sable fin. "
gameforge.main_quest_lv90._930_say = "Malheureusement, cela ne suffit pas encore. Nous[ENTER]avons besoin de plus de sable fin. Continuez \224 en[ENTER]ramasser. "
gameforge.main_quest_lv90._940_1_notice = "Vous avez maintenant ramass\233 suffisamment de[ENTER]sable fin. "
gameforge.main_quest_lv90._940_2_notice = "Apportez-le \224 l'amiral Angmur. "
gameforge.main_quest_lv90._950_say = "D'accord. "
gameforge.main_quest_lv90._960_say = "Je vous remercie\160! Gr\226ce au sable fin, nous[ENTER]pouvons \224 pr\233sent renforcer le mur de protection.[ENTER]Mes hommes vont imm\233diatement se mettre au[ENTER]travail. Je vous appellerai d\232s que j'aurai \224[ENTER]nouveau besoin de votre aide. "
gameforge.main_quest_lv90._970_sendLetter = "Renforcer le mur de protection II "
gameforge.main_quest_lv90._980_say = "L'amiral Angmur demande votre aide. Allez voir ce[ENTER]qu'il souhaite. "
gameforge.main_quest_lv90._990_say = "Pour terminer la construction, nous avons besoin[ENTER]de briques. Les manticores les amassent comme si[ENTER]c'\233tait de l'or. Je pense que 100 briques[ENTER]devraient faire l'affaire. Bien entendu, vous[ENTER]serez g\233n\233reusement r\233compens\233 pour votre aide. "
gameforge.main_quest_lv91 = {}
gameforge.main_quest_lv91._010_sendLetter = "La lettre de la manticore "
gameforge.main_quest_lv91._020_say = "L'amiral Angmur a une mission \224 vous proposer. "
gameforge.main_quest_lv91._030_say = "Ah, il est maintenant temps de se pencher \224[ENTER]nouveau sur les machinations des Serviteurs de[ENTER]l'Obscurit\233. Nous devons mettre la main sur les[ENTER]lettres qu'ils ont envoy\233es aux manticores et aux[ENTER]voleurs rouges\160![ENTER]Allez d'abord rendre une petite visite aux[ENTER]manticores. "
gameforge.main_quest_lv91._040_say = {}
gameforge.main_quest_lv91._050_say = "Compris. "
gameforge.main_quest_lv91._060_say = "Le g\233n\233ral core est parti avec la lettre afin de[ENTER]la remettre \224 Martyaxwar. Vous devez l'emp\234cher[ENTER]de la donner\160! "
gameforge.main_quest_lv91._070_sayTitle = "La lettre de la manticore "
gameforge.main_quest_lv91._080_say = "Battez le g\233n\233ral core et trouvez la lettre. "
gameforge.main_quest_lv91._090_1_notice = "Vous \234tes arriv\233 trop tard. Martyaxwar a d\233j\224[ENTER]re\231u la lettre. "
gameforge.main_quest_lv91._090_2_notice = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv91._100_say = "Vous arrivez trop tard. J'ai d\233j\224 transmis la[ENTER]lettre \224 Martyaxwar. Le sort des humains est[ENTER]scell\233\160! "
gameforge.main_quest_lv91._110_say = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv91._120_say = "Enfin vous voil\224. Avez-vous la lettre\160? "
gameforge.main_quest_lv91._130_say = "Non, je suis arriv\233 trop tard, le g\233n\233ral core a[ENTER]d\233j\224 transmis la lettre \224 Martyaxwar. "
gameforge.main_quest_lv91._140_say = {}
gameforge.main_quest_lv91._150_say = "Ah, cela n'arrange pas les choses...[ENTER]Mes \233claireurs trouveront o\249 se cache Martyaxwar.[ENTER]En attendant, prenez ceci comme r\233compense. Je[ENTER]vous informerai d\232s que j'en saurai plus. "
gameforge.main_quest_lv91._160_sendLetter = "Le repaire de Martyaxwar "
gameforge.main_quest_lv91._170_say = "L'amiral Angmur vous cherche. Il sait o\249 se cache[ENTER]Martyaxwar. "
gameforge.main_quest_lv91._180_say = "Ah, vous voil\224 enfin\160! Nous savons maintenant o\249[ENTER]se cache Martyaxwar. Mon \233claireur a vu qu'il[ENTER]cachait la lettre dans son collier \224 clous qu'il[ENTER]ne retire jamais. "
gameforge.main_quest_lv91._190_say = "Je pars imm\233diatement. "
gameforge.main_quest_lv91._200_sayTitle = "\201liminez Martyaxwar. "
gameforge.main_quest_lv91._210_say = "Pourchassez Martyaxwar et prenez-lui son collier[ENTER]\224 clous. "
gameforge.main_quest_lv91._220_say = "Nous n'avons pas de temps \224 perdre. D\233p\234chez-vous[ENTER]et apportez-moi le collier \224 clous\160! "
gameforge.main_quest_lv91._230_1_notice = "Vous avez obtenu le collier \224 clous. La lettre se[ENTER]trouve dans une poche \224 l'int\233rieur. "
gameforge.main_quest_lv91._230_2_notice = "Apportez-la \224 l'amiral Angmur. "
gameforge.main_quest_lv91._240_say = "Allez voir l'amiral Angmur. "
gameforge.main_quest_lv91._250_say = "Beau travail. Ce n'\233tait pas un adversaire facile[ENTER]\224 vaincre. Esp\233rons que la lettre nous en[ENTER]apprendra plus sur les sombres projets des[ENTER]d\233mons. "
gameforge.main_quest_lv91._260_say = "Zut, j'aurais d\251 m'y attendre, elle aussi est[ENTER]cod\233e\160! Yon-I-Walker, notre savant, doit jeter un[ENTER]coup d'\156il dessus. Allez le trouver. "
gameforge.main_quest_lv91._270_sendLetter = "D\233codage "
gameforge.main_quest_lv91._280_say = "Allez chez Yon-I-Walker afin de faire d\233coder la[ENTER]lettre. "
gameforge.main_quest_lv91._290_say = "*Il murmure* Oh, vous m'avez fait peur\160! Qui[ENTER]\234tes-vous\160? "
gameforge.main_quest_lv91._300_say = "L'amiral Angmur m'envoie. "
gameforge.main_quest_lv91._310_say = "Ah, oui\160! Vous venez au sujet de la lettre.[ENTER]Angmur m'a d\233j\224 parl\233 de vous. "
gameforge.main_quest_lv91._320_say = "Je n'ai pas encore pu d\233chiffrer la lettre.[ENTER]Cependant, il semble qu'il s'agit de l'\233criture[ENTER]de la tribu des Crustac\233ens de la baie de[ENTER]N\233phrite. "
gameforge.main_quest_lv91._330_say = "Pour pouvoir interpr\233ter ces symboles, j'ai[ENTER]besoin des tablettes carapax de la tribu des[ENTER]Crustac\233ens.[ENTER]Pouvez-vous m'en rapporter dix\160? "
gameforge.main_quest_lv91._340_say = "Bien entendu. "
gameforge.main_quest_lv91._350_sayTitle = "Tablettes carapax "
gameforge.main_quest_lv91._360_say = "Partez combattre la tribu des Crustac\233ens et[ENTER]rapportez dix tablettes carapax. "
gameforge.main_quest_lv91._370_say = "Cette tablette carapax a malheureusement \233t\233[ENTER]endommag\233e et je ne peux pas l'utiliser. Apportez[ENTER]m'en une autre. "
gameforge.main_quest_lv91._380_say = "Vous avez trouv\233 les tablettes carapax. Elles ont[ENTER]la forme de carapaces de tortues. "
gameforge.main_quest_lv91._390_say = "Parfait, \224 pr\233sent, je peux d\233coder la lettre.[ENTER]Beau travail\160! Prenez ceci en t\233moignage de ma[ENTER]reconnaissance. "
gameforge.main_quest_lv91._400_say = "Apportez m'en encore %s pi\232ces. "
gameforge.main_quest_lv91._410_1_notice = "Vous avez trouv\233 une tablette carapax. "
gameforge.main_quest_lv91._410_2_notice = "Apportez-la \224 Yon-I-Walker. "
gameforge.main_quest_lv91._420_sendLetter = "Lettre de manticore d\233cod\233e "
gameforge.main_quest_lv91._430_say = "Yon-I-Walker vous cherche. Allez le trouver pour[ENTER]savoir s'il a d\233j\224 pu d\233coder la lettre. "
gameforge.main_quest_lv91._440_say = "*Il murmure*... Ah, enfin vous voil\224\160! Gr\226ce \224[ENTER]votre aide, j'ai d\233j\224 pu d\233coder une grande[ENTER]partie du message. Mais je bute sur la derni\232re[ENTER]partie.[ENTER]Je crains de ne devoir encore une fois solliciter[ENTER]votre aide. J'ai besoin d'urgence de poudre de[ENTER]carapax. Vous en trouverez chez le g\233n\233ral homard[ENTER]ou le roi des crabes de la tribu des Crustac\233ens. "
gameforge.main_quest_lv91._450_say = "De la poudre de carapax\160? "
gameforge.main_quest_lv91._460_say = "Oui, seule la tribu des Crustac\233ens en poss\232de.[ENTER]Une dose m\234me infime de cette poudre est[ENTER]mortelle\160![ENTER]Trois doses devraient suffire. Bonne chance. "
gameforge.main_quest_lv91._470_say = "Je me mets tout de suite en route. "
gameforge.main_quest_lv91._480_sayTitle = "Poudre de carapax "
gameforge.main_quest_lv91._490_say = "Affrontez le g\233n\233ral homard et le roi des crabes[ENTER]de la tribu des Crustac\233ens et rapportez trois[ENTER]doses de poudre de carapax. "
gameforge.main_quest_lv91._500_say = "La poudre de carapax est extr\234mement toxique. Je[ENTER]dois attendre une journ\233e afin de laisser ses[ENTER]effets s'att\233nuer quelque peu. Revenez demain, et[ENTER]esp\233rons que je pourrais vous en dire plus. "
gameforge.main_quest_lv91._510_say = "Vous avez la poudre de carapax\160! "
gameforge.main_quest_lv91._520_say = "Beau travail. Maintenant, je peux enfin d\233coder[ENTER]la lettre. Voici pour vous r\233compenser. "
gameforge.main_quest_lv91._530_say = "Apportez m'en encore %d\160! "
gameforge.main_quest_lv91._540_say = "Cette poudre de carapax est impure. Apportez m'en[ENTER]une nouvelle dose s'il vous pla\238t. "
gameforge.main_quest_lv91._550_1_notice = "Vous avez trouv\233 une dose de poudre de carapax. "
gameforge.main_quest_lv91._550_2_notice = "Apportez-la \224 Yon-I-Walker. "
gameforge.main_quest_lv91._560_sendLetter = "Empoisonn\233\160! "
gameforge.main_quest_lv91._570_say = "L'amiral Angmur vous cherche partout. D\233couvrez[ENTER]ce qu'il veut. "
gameforge.main_quest_lv91._580_say = "Ah enfin, vous voil\224\160! Gr\226ce soit rendue au dieu[ENTER]Dragon. Yon-I-Walker s'est empoisonn\233 avec de la[ENTER]poudre de carapax. "
gameforge.main_quest_lv91._590_say = "Il voulait se d\233p\234cher et il a \233t\233 imprudent.[ENTER]Pour ne rien arranger, notre stock de plantes[ENTER]m\233dicinales est \233puis\233.[ENTER]Partez cueillir des fleurs de rocher, leur racine[ENTER]peut neutraliser le poison. J'ai indiqu\233 sur[ENTER]cette carte l'endroit o\249 vous pourrez en trouver. "
gameforge.main_quest_lv91._600_say = "Bien entendu. "
gameforge.main_quest_lv91._610_say = "Je savais que je pouvais compter sur vous.[ENTER]D\233p\234chez-vous s'il vous pla\238t, il ne nous reste[ENTER]que peu de temps\160! "
gameforge.main_quest_lv91._620_sayTitle = "Sauvez Yon-I-Walker\160! "
gameforge.main_quest_lv91._630_say = "Trouvez la racine de la fleur de rocher afin de[ENTER]gu\233rir Yon-I-Walker qui s'est empoisonn\233. "
gameforge.main_quest_lv91._640_1_notice = "Apportez la racine de la fleur de rocher \224[ENTER]Yon-I-Walker. "
gameforge.main_quest_lv91._650_say = "*Il hal\232te*[ENTER]*Il tousse*[ENTER]Ah, vous voil\224. Je suis au plus mal. Avez-vous[ENTER]trouv\233 une racine de fleur de rocher\160? "
gameforge.main_quest_lv91._660_say = "Oui, la voici. "
gameforge.main_quest_lv91._670_say = "Ah, je me sens d\233j\224 mieux. Mon heure n'a pas[ENTER]encore sonn\233.[ENTER]Je vous remercie. Prenez ceci, c'est pour vous[ENTER]r\233compenser. \192 pr\233sent, je peux finir mon[ENTER]travail.[ENTER]L'amiral Angmur vous informera d\232s que j'aurai[ENTER]r\233ussi \224 d\233coder la lettre. "
gameforge.main_quest_lv91._680_say = "Yon-I-Walker aimerait vous parler. "
gameforge.main_quest_lv91._760_say = "Restants "
gameforge.main_quest_lv91._770_say = "%s : %d "
gameforge.main_quest_lv91._780_say = "L'aventure continue d\232s que vous avez atteint le[ENTER]niveau 92. "
gameforge.main_quest_lv92 = {}
gameforge.main_quest_lv92._010_sendLetter = "La lettre du voleur rouge "
gameforge.main_quest_lv92._020_say = "La derni\232re lettre des serviteurs de l'Obscurit\233[ENTER]se trouve chez la bande des voleurs rouges.[ENTER]L'amiral Angmur a d'autres informations \224 vous[ENTER]communiquer. "
gameforge.main_quest_lv92._030_say = "Nous nous rapprochons de plus en plus de la[ENTER]conspiration des serviteurs de l'Obscurit\233. La[ENTER]derni\232re lettre se trouve entre les mains de la[ENTER]bande des voleurs rouges. "
gameforge.main_quest_lv92._040_say = "La bande des voleurs rouges\160? "
gameforge.main_quest_lv92._050_say = "Il s'agit d'une bande de criminels qui a \233t\233[ENTER]bannie sur le rocher du Dragon Sombre. Ce qui est[ENTER]extraordinaire avec les voleurs rouges, c'est que[ENTER]des humains se soient alli\233s avec des d\233mons. "
gameforge.main_quest_lv92._060_say = "Des d\233mons qui s'allient \224 des humains au lieu de[ENTER]les d\233vorer\160? Remarquable. "
gameforge.main_quest_lv92._070_say = "Un but commun les unit\160: l'or.[ENTER]Le camp de la bande des voleurs rouges se trouve[ENTER]non loin d'ici. \201liminez le voleur rouge bourreau[ENTER]et le g\233n\233ral noir. L'un des deux poss\232de la[ENTER]lettre. "
gameforge.main_quest_lv92._080_say = "Cependant on les a mis en garde contre nous et[ENTER]ils ont d\233chir\233 la lettre en quatre morceaux.[ENTER]Nous devons tous les retrouver. "
gameforge.main_quest_lv92._090_say = "Compris. "
gameforge.main_quest_lv92._100_say = "Je vous remercie. "
gameforge.main_quest_lv92._110_sayTitle = "La lettre du voleur rouge "
gameforge.main_quest_lv92._120_say = "Combattez le voleur rouge bourreau et le g\233n\233ral[ENTER]noir. Trouvez les quatre morceaux de la lettre. "
gameforge.main_quest_lv92._130_say = "La lettre n'est pas encore compl\232te. Trouvez tous[ENTER]les morceaux. "
gameforge.main_quest_lv92._140_1_notice = "Vous avez trouv\233 tous les morceaux de la lettre[ENTER]voleur rouge. "
gameforge.main_quest_lv92._140_2_notice = "Montrez-la \224 l'amiral Angmur. "
gameforge.main_quest_lv92._150_say = "Parlez \224 l'amiral Angmur. "
gameforge.main_quest_lv92._160_say = "Beau travail. Tenez, prenez ceci en t\233moignage de[ENTER]ma reconnaissance. "
gameforge.main_quest_lv92._170_sendLetter = "La lettre du voleur rouge "
gameforge.main_quest_lv92._180_say = "L'amiral Angmur a besoin de votre aide. "
gameforge.main_quest_lv92._190_say = "Vous arrivez \224 point nomm\233. Nous avons un[ENTER]probl\232me. "
gameforge.main_quest_lv92._200_say = "De quoi s'agit-il\160? "
gameforge.main_quest_lv92._210_say = "Il manque encore une cinqui\232me partie de la[ENTER]lettre du voleur rouge. Sans elle, le reste ne[ENTER]sert \224 rien.[ENTER]J'ai d\233j\224 envoy\233 Bae-Yong, un de mes hommes les[ENTER]plus courageux, mais il a d\251 se passer quelque[ENTER]chose. Il aurait d\251 revenir depuis longtemps.[ENTER]Pourriez-vous partir \224 sa recherche\160? "
gameforge.main_quest_lv92._220_say = "Bien entendu\160! Avez-vous une id\233e de l\224 o\249 il[ENTER]pourrait se trouver\160? "
gameforge.main_quest_lv92._230_say = "Oui. Il voulait notamment se rendre \224 la baie de[ENTER]N\233phrite. Mais personne ne peut dire s'il y est[ENTER]bien arriv\233. "
gameforge.main_quest_lv92._240_say = "Je pars imm\233diatement. "
gameforge.main_quest_lv92._250_sayTitle = "Le soldat disparu "
gameforge.main_quest_lv92._260_say = "Trouvez le cinqui\232me morceau de lettre. Pour cela[ENTER]recherchez Bae-Yong \224 la baie de N\233phrite. "
gameforge.main_quest_lv92._270_say = "Vous n'avez pas encore retrouv\233 Bae-Yong\160? C'est[ENTER]une question de vie ou de mort\160! Continuez \224 le[ENTER]rechercher. "
gameforge.main_quest_lv92._280_say = "*Il tousse*[ENTER]Merci de m'avoir retrouv\233. J'ai \233t\233 gri\232vement[ENTER]bless\233 au combat et je crains qu'il ne me reste[ENTER]que peu de temps...[ENTER]Voici ce que j'ai pris \224 un voleur rouge.[ENTER]Apportez-le \224 l'amiral. Allez-y\160! Je vais[ENTER]bient\244t...[ENTER](Il meurt dans vos bras.) "
gameforge.main_quest_lv92._290_1_notice = "Avant de mourir, Bae-Yong vous a donn\233 le morceau[ENTER]de lettre manquant. "
gameforge.main_quest_lv92._290_2_notice = "Retournez maintenant voir l'amiral Angmur. "
gameforge.main_quest_lv92._300_say = "Vous \234tes de retour\160! Avez-vous retrouv\233[ENTER]Bae-Yong\160? "
gameforge.main_quest_lv92._310_say = "Oui, mais... "
gameforge.main_quest_lv92._320_say = "Mais quoi\160?[ENTER]Oh non. Il est mort\160? "
gameforge.main_quest_lv92._330_say = "Je ne pouvais plus rien faire pour lui. Mes[ENTER]condol\233ances. C'\233tait un homme courageux, il a[ENTER]sacrifi\233 sa vie pour prot\233ger le dernier morceau[ENTER]de la lettre. Le voici. "
gameforge.main_quest_lv92._340_say = "La perte de Bae-Yong nous attriste profond\233ment.[ENTER]N\233anmoins, je suis tr\232s fier de lui. Il a[ENTER]accompli sa mission et nous poss\233dons maintenant[ENTER]tous les morceaux de la lettre. "
gameforge.main_quest_lv92._350_say = "Je vous remercie pour tout. Voici votre[ENTER]r\233compense. Je vais aller au temple allumer un[ENTER]b\226tonnet d'encens en m\233moire de Bae-Yong.[ENTER]Je vous contacterai plus tard. "
gameforge.main_quest_lv92._360_say = "Allez voir l'amiral Angmur. "
gameforge.main_quest_lv92._370_sendLetter = "D\233coder la lettre du voleur rouge "
gameforge.main_quest_lv92._380_say = "L'amiral Angmur a des informations importantes au[ENTER]sujet de la lettre de la bande des voleurs[ENTER]rouges.[ENTER]\201coutez ce qu'il a \224 dire. "
gameforge.main_quest_lv92._390_say = "Ah, vous voil\224. Les Serviteurs de l'Obscurit\233 me[ENTER]donnent du fil \224 retordre. Cette lettre aussi est[ENTER]cod\233e. Apportez-la \224 Yon-I-Walker. "
gameforge.main_quest_lv92._400_say = "C'est d'accord. "
gameforge.main_quest_lv92._410_say = "Apportez la lettre cod\233e \224 Yon-I-Walker. "
gameforge.main_quest_lv92._420_say = "Oh\160! Faut-il toujours que vous arriviez \224 pas de[ENTER]loup\160?[ENTER]Que puis-je faire pour vous\160? "
gameforge.main_quest_lv92._430_say = "Voici la lettre des voleurs rouges. Cependant[ENTER]elle est cod\233e, comme les autres. "
gameforge.main_quest_lv92._440_say = "Laissez-moi jeter un coup d'\156il. Hmm, ce sont les[ENTER]symboles des tritons. Ils ne devraient pas \234tre[ENTER]difficile \224 d\233chiffrer. "
gameforge.main_quest_lv92._450_say = "Parfait. De combien de temps avez-vous besoin\160? "
gameforge.main_quest_lv92._460_say = "Pas si vite. Le d\233codage n'est pas[ENTER]particuli\232rement compliqu\233. Mais sans moyen[ENTER]suppl\233mentaire, je ne pourrai rien faire. "
gameforge.main_quest_lv92._470_say = "\201videmment. Cela aurait \233t\233 trop facile. "
gameforge.main_quest_lv92._480_say = "Je vois que vous n'avez pas perdu votre humour,[ENTER]h\233, h\233. Pour d\233coder la lettre, j'ai besoin[ENTER]d'\233cailles d'Oin. Seuls le g\233n\233ral Kappa et[ENTER]Triton de la tribu des Tritons peuvent porter ces[ENTER]\233cailles rares. Allez m'en chercher 10. "
gameforge.main_quest_lv92._490_say = "Je pars imm\233diatement. "
gameforge.main_quest_lv92._500_sayTitle = "Trouvez des \233cailles d'Oin. "
gameforge.main_quest_lv92._510_say = "Seuls Triton, le roi des tritons et le g\233n\233ral[ENTER]Kappa portent des \233cailles d'Oin. "
gameforge.main_quest_lv92._520_say = "Sans ces \233cailles, je ne peux pas d\233coder la[ENTER]lettre. J'en ai absolument besoin. "
gameforge.main_quest_lv92._530_1_notice = "Vous avez trouv\233 les \233cailles d'Oin des tritons. "
gameforge.main_quest_lv92._530_2_notice = "Apportez-les vite \224 Yon-I-Walker. "
gameforge.main_quest_lv92._540_say = "Vous avez fait du bon travail. D\232s que j'aurai[ENTER]d\233cod\233 la lettre, je pr\233viendrai l'amiral Angmur.[ENTER]Vous devriez vous reposer. Prenez ceci comme[ENTER]t\233moignage de ma reconnaissance. "
gameforge.main_quest_lv92._550_say = "Yon-I-Walker aimerait vous parler. "
gameforge.main_quest_lv92._560_sendLetter = "Sombres projets "
gameforge.main_quest_lv92._570_say = "La lettre des Serviteurs de l'Obscurit\233 a \233t\233[ENTER]d\233cod\233e. L'amiral Angmur vous mettra au courant[ENTER]de leurs sombres projets. "
gameforge.main_quest_lv92._580_say = "Nous sommes parvenus \224 d\233chiffrer compl\232tement le[ENTER]message secret. Vous souvenez-vous de la lettre[ENTER]des Gnolls\160? Il y \233tait d\233j\224 question de dragons[ENTER]qui dorment profond\233ment au c\156ur de l'\238le ainsi[ENTER]que d'une m\233thode destin\233e \224 les r\233veiller et \224[ENTER]les rendre furieux. Nous savons \224 pr\233sent quels[ENTER]buts poursuivent les Serviteurs de l'Obscurit\233. "
gameforge.main_quest_lv92._590_say = "Si l'on tue un dragon exactement au moment o\249 sa[ENTER]raison est noire comme les portes de l'Enfer,[ENTER]alors il recrache la perle de la nuit. Et gr\226ce \224[ENTER]cette perle, les forces incommensurables de Sung[ENTER]Mahi peuvent \234tre invoqu\233es en ce monde. Voici[ENTER]donc leurs sinistres projets\160! "
gameforge.main_quest_lv92._600_say = "\192 pr\233sent, nous devons agir avec prudence. Si[ENTER]j'ai du nouveau, je vous ferai appeler. Merci[ENTER]pour tout. "
gameforge.main_quest_lv92._610_say = "L'aventure continue d\232s que vous avez atteint le[ENTER]niveau 93. "
gameforge.main_quest_lv93 = {}
gameforge.main_quest_lv93._010_sendLetter = "Prendre des forces I "
gameforge.main_quest_lv93._020_say = "L'amiral Angmur souhaiterait vous parler. "
gameforge.main_quest_lv93._030_say = "Nous sommes sur les traces des serviteurs de[ENTER]l'Obscurit\233. "
gameforge.main_quest_lv93._040_say = "Pour pouvoir les vaincre, nous devons d\233velopper[ENTER]vos forces. Connaissez-vous la lumi\232re[ENTER]int\233rieure\160?[ENTER]C'est de l'\233nergie concentr\233e.[ENTER]Certains \234tres ou plantes mythiques en poss\232dent.[ENTER]Gr\226ce \224 elle, Yon-I-Walker peut fabriquer un[ENTER]moyen de renforcement. Allez le voir[ENTER]imm\233diatement. "
gameforge.main_quest_lv93._050_say = "D'accord. "
gameforge.main_quest_lv93._060_say = "Ah, voici mon sauveur\160![ENTER]La lumi\232re int\233rieure, oui... Mon fortifiant fera[ENTER]de vous un adversaire du m\234me niveau que les[ENTER]Serviteurs de l'Obscurit\233. "
gameforge.main_quest_lv93._070_say = "Pour cela, j'ai besoin de la lumi\232re int\233rieure[ENTER]des cyclopes et des g\233ants. Seuls leurs chefs la[ENTER]poss\232dent. Allez d'abord chez les cyclopes. "
gameforge.main_quest_lv93._080_say = "D'accord. "
gameforge.main_quest_lv93._090_sayTitle = "La lumi\232re int\233rieure I "
gameforge.main_quest_lv93._100_say = "Battez le roi des cyclopes Polyph\232me et volez-lui[ENTER]sa lumi\232re int\233rieure. "
gameforge.main_quest_lv93._110_say = "Vous arrivez les mains vides\160? Dans ce cas, je ne[ENTER]peux pas vous aider. Apportez-moi la lumi\232re[ENTER]int\233rieure\160! "
gameforge.main_quest_lv93._120_1_notice = "Vous avez trouv\233 la lumi\232re int\233rieure.[ENTER]Rapportez-la \224 Yon-I-Walker. "
gameforge.main_quest_lv93._130_say = "Parlez \224 Yon-I-Walker. "
gameforge.main_quest_lv93._140_say = "Voici donc la lumi\232re int\233rieure... Avant de[ENTER]pouvoir l'utiliser, je dois la purifier. Cela va[ENTER]durer un certain temps. Je vous tiendrai au[ENTER]courant. "
gameforge.main_quest_lv93._150_sendLetter = "Prendre des forces II "
gameforge.main_quest_lv93._160_say = "Yon-I-Walker vous recherche. "
gameforge.main_quest_lv93._170_say = "La lumi\232re int\233rieure de Polyph\232me est maintenant[ENTER]pure. Ensuite, nous avons besoin de celle des[ENTER]g\233ants. Battez le roi Wobba. "
gameforge.main_quest_lv93._180_say = "Je pars imm\233diatement. "
gameforge.main_quest_lv93._190_sayTitle = "La lumi\232re int\233rieure II "
gameforge.main_quest_lv93._200_say = "Battez le roi des g\233ants Wobba et volez-lui sa[ENTER]lumi\232re int\233rieure. "
gameforge.main_quest_lv93._210_say = "Vous arrivez les mains vides? "
gameforge.main_quest_lv93._220_1_notice = "Vous avez entre les mains la lumi\232re int\233rieure[ENTER]des g\233ants. "
gameforge.main_quest_lv93._220_2_notice = "Apportez-la \224 Yon-I-Walker. "
gameforge.main_quest_lv93._230_say = "Parlez \224 Yon-I-Walker. "
gameforge.main_quest_lv93._240_say = "La lumi\232re int\233rieure du roi Wobba poss\232de une[ENTER]force terrifiante. Je suppose que c'est \224 cause[ENTER]de la masse. Maintenant, je dois encore la[ENTER]purifier.[ENTER]Cela va prendre un certain temps. "
gameforge.main_quest_lv93._250_sendLetter = "Prendre des forces III "
gameforge.main_quest_lv93._260_say = "Yon-I-Walker vous recherche. "
gameforge.main_quest_lv93._270_say = "Vous \234tes l\224, c'est parfait. J'ai besoin de votre[ENTER]aide. Afin que les effets de mon \233lixir[ENTER]fortifiant soient optimaux, j'ai encore besoin[ENTER]d'un autre ingr\233dient\160: de l'essence de[ENTER]mill\233nium. "
gameforge.main_quest_lv93._280_say = "De l'essence de mill\233nium\160? Je n'en ai encore[ENTER]jamais entendu parler. "
gameforge.main_quest_lv93._290_say = "C'est une mixture tr\232s efficace faite \224 partir de[ENTER]diff\233rentes essences d'herbes. Connaissez-vous[ENTER]Octavio\160? Il habite sur la terre ferme et c'est[ENTER]le seul qui soit en mesure de fabriquer de[ENTER]l'essence de mill\233nium. Allez le voir. J'esp\232re[ENTER]qu'il nous aidera. Il est parfois un peu born\233... "
gameforge.main_quest_lv93._300_say = "D'accord. "
gameforge.main_quest_lv93._310_sayTitle = "Parlez \224 Octavio\160! "
gameforge.main_quest_lv93._320_say = "Recherchez Octavio. Il vit sur la terre ferme et[ENTER]c'est le seul qui puisse concocter de l'essence[ENTER]de mill\233nium. "
gameforge.main_quest_lv93._330_say = "Bonjour\160! Qu'est-ce que je vous sers\160? Un[ENTER]samgyetang, peut-\234tre\160? C'est la sp\233cialit\233 de la[ENTER]maison avec... "
gameforge.main_quest_lv93._340_say = "Octavio, je ne suis pas venu ici pour go\251ter vos[ENTER]bons petits plats\160! J'ai besoin d'autre chose\160:[ENTER]de l'essence de mill\233nium. "
gameforge.main_quest_lv93._350_say = "Oh, chut, pas si fort\160! L'essence de mill\233nium...[ENTER]Non, ce n'est pas possible. Qui vous en a parl\233\160?[ENTER]Tr\232s peu de gens ma\238trisent le pouvoir qu'elle[ENTER]dispense. Je ne veux courir aucun risque. Et[ENTER]maintenant partez avant que quelqu'un ne vous[ENTER]entende. "
gameforge.main_quest_lv93._360_say = "Octavio, attendez et \233coutez-moi\160! Yon-I-Walker[ENTER]du rocher du Dragon Sombre m'envoie. Nous avons[ENTER]absolument besoin de cette essence. Sans elle,[ENTER]nous n'avons aucune chance face aux serviteurs de[ENTER]l'Obscurit\233. Et le monde tel que nous le[ENTER]connaissons sera vou\233 \224 la destruction. Vous seul[ENTER]pouvez la fabriquer. S'il vous pla\238t\160! "
gameforge.main_quest_lv93._370_say = "Yon-I-Walker, vous dites\160? Hmm, c'est un vieil[ENTER]ami \224 moi. Nous avons eu de si belles[ENTER]conversations autour d'une bonne bouteille de[ENTER]vin. Je dois y r\233fl\233chir. Revenez demain et je[ENTER]vous donnerai ma r\233ponse. "
gameforge.main_quest_lv93._380_say = {}
gameforge.main_quest_lv93._390_say = "Je n'ai pas encore pris de d\233cision. Revenez plus[ENTER]tard. "
gameforge.main_quest_lv93._400_npcChat = "L'essence de mill\233nium "
gameforge.main_quest_lv93._410_say = "Octavio souhaiterait vous parler. "
gameforge.main_quest_lv93._420_say = "Alors, j'ai r\233fl\233chi toute la nuit \224 votre[ENTER]requ\234te. Je cours un grand risque. N\233anmoins, je[ENTER]sais que j'agis bien. Oui, je vais vous aider. "
gameforge.main_quest_lv93._430_say = "Tr\232s bien\160! "
gameforge.main_quest_lv93._440_say = "Toutefois, je n'en ai pas en stock.[ENTER]Pourriez-vous me procurer quelques ingr\233dients\160?[ENTER]Ensuite, je vous fabriquerai l'essence. "
gameforge.main_quest_lv93._450_say = "Bien s\251r. De quoi avez-vous besoin\160? "
gameforge.main_quest_lv93._460_say = "Il me manque des racines de gango, des[ENTER]champignons Tue et des roses des montagnes. J'ai[ENTER]besoin de 200 exemplaires de chaque. "
gameforge.main_quest_lv93._470_say = "Je pars tout de suite. O\249 trouverai-je tout cela\160? "
gameforge.main_quest_lv93._480_say = "Vous trouverez ces plantes dans les endroits les[ENTER]plus divers du continent. Pendant que vous serez[ENTER]en chemin, je m'occuperai de mes pr\233parations. "
gameforge.main_quest_lv93._490_sayTitle = "La recette du mill\233nium "
gameforge.main_quest_lv93._500_say = "Partez \224 la recherche de la racine de gango, du[ENTER]champignon Tue et de la rose des montagnes.[ENTER]Vous avez besoin de 200 exemplaires de chaque. "
gameforge.main_quest_lv93._510 = "Vous trouverez ces plantes dans les endroits les[ENTER]plus divers du continent. Pendant que vous serez[ENTER]en chemin, je m'occuperai de mes pr\233parations. "
gameforge.main_quest_lv93._520_say = "Ah, tr\232s bien, vous \234tes de retour. Et vous avez[ENTER]tout trouv\233. Alors je me mets imm\233diatement au[ENTER]travail. Il ne faut pas me d\233ranger. Revenez[ENTER]demain \224 la m\234me heure. L'essence devrait \234tre[ENTER]pr\234te. "
gameforge.main_quest_lv93._530_say = "Tr\232s bien. \192 demain. "
gameforge.main_quest_lv93._540_say = "Je comprends que vous \234tes press\233. Cependant, il[ENTER]faut que vous preniez patience. Revenez plus[ENTER]tard. "
gameforge.main_quest_lv93._550_say = "Octavio vous cherche. "
gameforge.main_quest_lv93._560_say = "Ah, vous arrivez \224 temps\160: l'essence de mill\233nium[ENTER]est justement pr\234te\160! Vous pouvez d\232s \224 pr\233sent[ENTER]l'apporter \224 Yon-I-Walker. "
gameforge.main_quest_lv93._570_say = "Je vous remercie. "
gameforge.main_quest_lv93._580_sendLetter = "Essence de mill\233nium "
gameforge.main_quest_lv93._590_say = "Yon-I-Walker vous recherche. "
gameforge.main_quest_lv93._600_say = "Vous avez l'essence de mill\233nium\160![ENTER]Je dispose maintenant de tous les ingr\233dients[ENTER]pour mon \233lixir fortifiant. Je vous appellerai[ENTER]quand j'aurai termin\233. "
gameforge.main_quest_lv93._610_say = "Compris. "
gameforge.main_quest_lv93._620_say = "L'aventure continue d\232s que vous avez atteint le[ENTER]niveau 94. "
gameforge.main_quest_lv93._630_say = "%s\160: %d unit\233s, %s\160: %d unit\233s,[ENTER]%s\160: %d unit\233s "
gameforge.main_quest_lv93._640_say = "J'ai une auberge \224 g\233rer et je n'ai pas tout mon[ENTER]temps. Apportez-moi tous les ingr\233dients[ENTER]manquants et d\233p\234chez-vous s'il vous pla\238t. "
gameforge.main_quest_lv93._650_1_notice = "Vous avez trouv\233 tous les ingr\233dients n\233cessaires[ENTER]\224 l'essence de mill\233nium. "
gameforge.main_quest_lv93._650_2_notice = "Retournez voir Octavio. "
gameforge.main_quest_lv94 = {}
gameforge.main_quest_lv94._010_sendLetter = "Perles du L\233viathan "
gameforge.main_quest_lv94._020_say = "Yon-I-Walker vous recherche. "
gameforge.main_quest_lv94._030_say = "J'ai r\233ussi ! J'ai combin\233 les essences les plus[ENTER]puissantes dont nous avons connaissance et je[ENTER]peux fi\232rement vous pr\233senter : les perles du[ENTER]L\233viathan ! "
gameforge.main_quest_lv94._040_say = "Je vous remercie. "
gameforge.main_quest_lv94._050_say = "Si vous ing\233rez ces pilules, vous n'en[ENTER]ressentirez peut-\234tre pas les effets. Mais,[ENTER]aupr\232s d'un \156il aguerri, comme le mien ou celui[ENTER]d'Angmur, cela ne passera pas inaper\231u.[ENTER]Angmur souhaite vous parler. Allez le trouver[ENTER]sans plus attendre. "
gameforge.main_quest_lv94._060_sayTitle = "Reprenez des forces ! "
gameforge.main_quest_lv94._070_say = "Ing\233rez les perles du L\233viathan et allez voir[ENTER]l'amiral Angmur. "
gameforge.main_quest_lv94._080_sendLetter = "L'appel des montagnes fulgurantes. "
gameforge.main_quest_lv94._090_say = "L'amiral Angmur a des nouvelles \224 vous[ENTER]transmettre. "
gameforge.main_quest_lv94._1000_say = "L'analyse des p\233pites va me prendre un peu de[ENTER]temps. Revenez demain, j'esp\232re \234tre alors[ENTER]capable de vous livrer des r\233sultats. "
gameforge.main_quest_lv94._100_say = "Ah, les perles du L\233viathan commencent \224 faire[ENTER]leur effet : je discerne clairement une aura du[ENTER]pouvoir autour de vous.[ENTER]Mes \233claireurs pensent savoir o\249 le quartier[ENTER]g\233n\233ral des serviteurs de l'obscurit\233 pourrait se[ENTER]trouver. Cet endroit est \233troitement surveill\233.[ENTER]Pourriez-vous y aller y jeter un \156il ? "
gameforge.main_quest_lv94._1010_say = "Je transmettrai mes r\233sultats \224 Angmur, qui vous[ENTER]tiendra inform\233. "
gameforge.main_quest_lv94._1020_say = "L'amiral Angmur dispose d'informations sur l'or[ENTER]noir. Allez le voir. "
gameforge.main_quest_lv94._1030_say = "Ah, vous voil\224. L'analyse de l'or noir n'est pas[ENTER]termin\233e. J'esp\232re \234tre bient\244t en mesure de vous[ENTER]en dire plus \224 son sujet.[ENTER]Tenez, prenez ceci pour vous r\233compenser de vos[ENTER]efforts. "
gameforge.main_quest_lv94._1040_say = "Ne perdons pas de temps. Vite, ramenez-moi des[ENTER]p\233pites d'or noir ! "
gameforge.main_quest_lv94._1050_say = "Vous pourrez poursuivre l'aventure, sit\244t que[ENTER]vous aurez atteint le niveau 95. "
gameforge.main_quest_lv94._1060_say = "Restants "
gameforge.main_quest_lv94._1070_say = "%s : %d[ENTER]%s : %d[ENTER]%s : %d "
gameforge.main_quest_lv94._1080_say = "Nombre manquant : "
gameforge.main_quest_lv94._1090_say = "%s : %d "
gameforge.main_quest_lv94._110_say = "Bien entendu. "
gameforge.main_quest_lv94._120_say = "Je vous remercie. Venez, que je vous montre[ENTER]quelles r\233gions vous devez explorer, suite \224[ENTER]quoi, vous me ferez un rapport. "
gameforge.main_quest_lv94._130_say = {}
gameforge.main_quest_lv94._140_say = "Sur ordre de l'amiral Angmur, il vous faut[ENTER]explorer les montagnes fulgurantes. Votre[ENTER]premi\232re destination est : (%d, %d) "
gameforge.main_quest_lv94._150_sayTitle = "Les montagnes fulgurantes. "
gameforge.main_quest_lv94._160_say = "Explorez les montagnes fulgurantes et revenez[ENTER]ensuite faire un rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv94._170_say = "Vous n'avez pas encore explor\233 tous les lieux,[ENTER]n'est-ce pas ? Nous avons besoin de ces[ENTER]informations. Veuillez mener la mission \224 bien. "
gameforge.main_quest_lv94._180_say = "Votre premi\232re destination est : %d, %d "
gameforge.main_quest_lv94._190_say = "Votre deuxi\232me destination est : %d, %d "
gameforge.main_quest_lv94._200 = {}
gameforge.main_quest_lv94._210_say = "Votre troisi\232me destination est : %d, %d "
gameforge.main_quest_lv94._220_say = "Vous avez atteint la premi\232re destination. Le[ENTER]prochain lieu o\249 il vous faut vous rendre est :[ENTER](%d, %d) "
gameforge.main_quest_lv94._230_say = "Vous avez atteint votre deuxi\232me destination. Le[ENTER]prochain lieu o\249 il vous faut vous rendre est :[ENTER](%d, %d) "
gameforge.main_quest_lv94._240 = "Vous avez atteint la troisi\232me destination. "
gameforge.main_quest_lv94._250_say = "Vous avez pu vous faire une id\233e de la situation[ENTER]sur les montagnes fulgurantes.[ENTER]Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv94._260_say = "Retournez aupr\232s de l'amiral Angmur. "
gameforge.main_quest_lv94._270_say = "Ah, vous \234tes de retour ! Tr\232s bien, nous allons[ENTER]pouvoir \233valuer les informations que vous avez[ENTER]recueillies afin d'\233laborer une strat\233gie. "
gameforge.main_quest_lv94._280_say = "Voici votre r\233compense. "
gameforge.main_quest_lv94._290_sendLetter = "Points faibles des voleurs rouges "
gameforge.main_quest_lv94._300_say = "L'amiral Angmur vous demande. "
gameforge.main_quest_lv94._310_say = "Un assaut frontal me semble encore trop risqu\233.[ENTER]Il serait judicieux d'affaiblir les troupes,[ENTER]avant de lancer l'offensive. "
gameforge.main_quest_lv94._320_say = "Les groupes suivants peuplent les montagnes[ENTER]fulgurantes : les g\233ants, les cyclopes et les[ENTER]voleurs rouges.[ENTER]Nous allons commencer par attaquer les voleurs[ENTER]rouges. "
gameforge.main_quest_lv94._330_say = "Quels sont les points faibles des voleurs rouges ? "
gameforge.main_quest_lv94._340_say = "Le chef rouge porte toujours une cape sp\233ciale,[ENTER]symbole de force et d'invincibilit\233. Arrachez-lui[ENTER]cette cape, afin de saper le moral des voleurs[ENTER]rouges. "
gameforge.main_quest_lv94._350_say = "Le chef rouge ? Voila une t\226che qui s'annonce[ENTER]ardue... "
gameforge.main_quest_lv94._360_say = "Vous avez raison. Mais s'il y a quelqu'un capable[ENTER]de l'affronter, c'est bien vous. Bonne chance ! "
gameforge.main_quest_lv94._370_sayTitle = "Le chef rouge "
gameforge.main_quest_lv94._380_say = "Triomphez du chef rouge et arrachez-lui sa cape. "
gameforge.main_quest_lv94._390_say = "... vous avez \233chou\233 ? Voil\224 qui est dur \224 croire.Repartez \224 l'assaut du chef rouge. Je suis[ENTER]certain que, cette fois-ci, vous triompherez. "
gameforge.main_quest_lv94._400_1_notice = "Vous avez vaincu le chef rouge. "
gameforge.main_quest_lv94._400_2_notice = "Saisissez-vous de sa cape et ramenez-la \224[ENTER]l'amiral Angmur. "
gameforge.main_quest_lv94._410_say = "L'amiral Angmur vous attend. "
gameforge.main_quest_lv94._420_say = "La cape ! Je savais que vous en \233tiez capable.[ENTER]Nous allons maintenant la suspendre \224 la vue de[ENTER]tous aux alentours de leur campement. Cela fera[ENTER]douter la bande des voleurs rouges.[ENTER]Mes hommes vont s'en occuper, apr\232s quoi, vous[ENTER]pourrez vous reposer. "
gameforge.main_quest_lv94._430_sendLetter = "Affaiblir les cyclopes "
gameforge.main_quest_lv94._440_say = "L'amiral Angmur d\233sire vous parler. "
gameforge.main_quest_lv94._450_say = "Notre plan a fonctionn\233 : lorsque les voleurs[ENTER]rouges ont vu la cape, cela a sem\233 la zizanie[ENTER]dans leurs rangs. Finalement les d\233mons et les[ENTER]humains se sont attaqu\233s mutuellement. Cette[ENTER]bande est d\233sormais compl\232tement d\233sorganis\233e.[ENTER]Nous pouvons maintenant nous occuper des[ENTER]cyclopes. "
gameforge.main_quest_lv94._460_say = "Et comment allons-nous proc\233der ? "
gameforge.main_quest_lv94._470_say = "Les cyclopes v\233n\232rent leurs commandants. Si nous[ENTER]d\233faisons leurs officiers, cela s\232mera la panique[ENTER]dans leurs rangs et ils se disperseront.[ENTER]Vainquez le g\233n\233ral Outis %d fois, Arg\232s %d fois[ENTER]et Polyph\232me %d fois. "
gameforge.main_quest_lv94._480_say = "C'est avec plaisir. "
gameforge.main_quest_lv94._490_say = "Soyez sur vos gardes ! "
gameforge.main_quest_lv94._500_sayTitle = "Combattez les cyclopes ! "
gameforge.main_quest_lv94._510_say = "Vainquez le g\233n\233ral Outis %d fois, Arg\232s %d[ENTER]autres fois et enfin, %d fois Polyph\232me. "
gameforge.main_quest_lv94._520 = "J'ai du mal \224 croire que pr\233cis\233ment les cyclopes[ENTER]puissent vous \234tre sup\233rieurs. Allons, je sais[ENTER]que vous pouvez y arriver ! "
gameforge.main_quest_lv94._530_1_notice = "Vous avez vaincu les commandants des cyclopes. "
gameforge.main_quest_lv94._530_2_notice = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv94._540_say = "Allez voir l'amiral Angmur. "
gameforge.main_quest_lv94._550_say = "Les nouvelles de vos exploits vous pr\233c\232dent ![ENTER]Les cyclopes sont en fuite.[ENTER]Ne restent que les g\233ants. Je vais t\226cher de[ENTER]r\233unir des informations sur leurs points faibles[ENTER]puis vous ferai appeler. "
gameforge.main_quest_lv94._560_sendLetter = "Affaiblir les g\233ants "
gameforge.main_quest_lv94._570_say = "L'amiral Angmur vous demande. "
gameforge.main_quest_lv94._580_say = "Mes \233claireurs ont d\233couvert le point faible des[ENTER]g\233ants. "
gameforge.main_quest_lv94._590_say = "Dites-moi tout ! "
gameforge.main_quest_lv94._600_say = "Les g\233ants poss\232dent un totem \224 qui ils accordent[ENTER]une inestimable valeur spirituelle. Si nous les[ENTER]en privons, cela brisera leur volont\233. "
gameforge.main_quest_lv94._610_say = "O\249 puis-je trouver ce totem ? "
gameforge.main_quest_lv94._620_say = "Le totem est taill\233 dans une grande pierre[ENTER]d'ambre. Afin de la prot\233ger des voleurs, cette[ENTER]pierre a \233t\233 morcel\233e en %d fragments que portent[ENTER]le roi Wobba et ses officiers. "
gameforge.main_quest_lv94._630_say = "C'est entendu. "
gameforge.main_quest_lv94._640_sayTitle = "Totem des g\233ants "
gameforge.main_quest_lv94._650_say = "Emparez-vous de tous les fragments du totem. "
gameforge.main_quest_lv94._660_say = "Les g\233ants sont des adversaires redoutables.[ENTER]Mais il vous faut les vaincre et me ramener ce[ENTER]totem. "
gameforge.main_quest_lv94._670_say_1_notice = "Vous avez acquis tous les fragments du totem. "
gameforge.main_quest_lv94._670_say_2_notice = "Retournez aupr\232s de l'amiral Angmur. "
gameforge.main_quest_lv94._680_say = "Ah, je commen\231ais \224 m'inqui\233ter ! Mais vous y[ENTER]\234tes bel et bien arriv\233. Nous sommes maintenant[ENTER]en possession du totem des g\233ants. Voil\224 qui[ENTER]m\233rite une somptueuse r\233compense. "
gameforge.main_quest_lv94._690_sendLetter = "Vers les montagnes fulgurantes "
gameforge.main_quest_lv94._700_say = "L'amiral Angmur vous demande. "
gameforge.main_quest_lv94._710_say = "Mes \233claireurs ont surpris les cyclopes en train[ENTER]d'amasser quelque chose, avant de l'emporter. "
gameforge.main_quest_lv94._720_say = "D\233couvrez ce que les cyclopes manigancent. Rien[ENTER]de bon, je le crains... Et je doute fort qu'ils[ENTER]r\233v\232lent leur secret de leur plein gr\233. "
gameforge.main_quest_lv94._730_say = "C'est entendu. "
gameforge.main_quest_lv94._740_sayTitle = "Que manigancent les cyclopes ? "
gameforge.main_quest_lv94._750_say = "D\233couvrez ce que les cyclopes amassent dans les[ENTER]montagnes fulgurantes. "
gameforge.main_quest_lv94._760_say = "D\233couvrez ce que les cyclopes manigancent. Rien[ENTER]de bon, je le crains... Et je doute fort qu'ils[ENTER]r\233v\232lent leur secret de leur plein gr\233. "
gameforge.main_quest_lv94._770_1_notice = "Vous tenez une pierre \224 la brillance sombre ainsi[ENTER]qu'un morceau de papier. "
gameforge.main_quest_lv94._770_2_notice = "Montrez votre trouvaille \224 l'amiral Angmur. "
gameforge.main_quest_lv94._780_say = "Allez voir l'amiral Angmur. "
gameforge.main_quest_lv94._790_say = "Avez-vous d\233couvert ce que trament les cyclopes[ENTER]dans les montagnes fulgurantes ? "
gameforge.main_quest_lv94._800_say = "Les cyclopes n'ont pas accept\233 de parler de leur[ENTER]plein gr\233, mais j'ai r\233ussi \224 les convaincre de[ENTER]me donner ceci : une pierre noire et ce morceau[ENTER]de papier. "
gameforge.main_quest_lv94._810_say = "Nous avons localis\233 les filons d'or noir dans les[ENTER]montagnes fulgurantes et les exploitons pour[ENTER]vous.[ENTER]Nous vous remettrons le minerai au point de[ENTER]rendez-vous convenu, dans les entrailles des[ENTER]montagnes fulgurantes. "
gameforge.main_quest_lv94._820_say = "De l'or noir ! Il s'agit d'un minerai qu'on ne[ENTER]trouve qu'au c\156ur des montagnes fulgurantes.[ENTER]Pourquoi diable les serviteurs de l'obscurit\233 en[ENTER]ont-ils besoin ? "
gameforge.main_quest_lv94._830_say = "Il nous faut \224 tout prix d\233couvrir quel usage ils[ENTER]comptent en faire. "
gameforge.main_quest_lv94._840_say = "Voici ce qui est \233crit : "
gameforge.main_quest_lv94._850_sendLetter = "Or noir "
gameforge.main_quest_lv94._860_say = "L'amiral Angmur souhaite s'entretenir de l'or[ENTER]noir avec vous. "
gameforge.main_quest_lv94._870_say = "L'alchimiste n'a pas r\233ussi \224 analyser l'or noir.[ENTER]La p\233pite est trop petite.[ENTER]Il nous faut d\233couvrir quelles sont ses[ENTER]propri\233t\233s et pourquoi les serviteurs de l'ombre[ENTER]le convoitent.[ENTER]Pouvez-vous retourner dans les montagnes[ENTER]fulgurantes et vous procurer d'autres p\233pites[ENTER]d'or noir ? "
gameforge.main_quest_lv94._880_say = "Rendez-vous tout d'abord chez l'alchimiste, il[ENTER]vous dira de combien de p\233pites il a besoin. "
gameforge.main_quest_lv94._890_say = "Parlez \224 l'alchimiste. "
gameforge.main_quest_lv94._900_say = "Je vous salue. Angmur vous a-t-il d\233j\224 inform\233 de[ENTER]la teneur de votre mission ? "
gameforge.main_quest_lv94._910_say = "Oui. De combien de p\233pites d'or noir aurez-vous[ENTER]besoin ? "
gameforge.main_quest_lv94._920_say = "Eh bien, r\233fl\233chissons. Je pense que %d p\233pites[ENTER]devraient suffire \224 mon analyse. "
gameforge.main_quest_lv94._930_say = "C'est entendu. "
gameforge.main_quest_lv94._940_sayTitle = "L'or des montagnes fulgurantes. "
gameforge.main_quest_lv94._950_sayTitle = "Allez voir l'alchimiste. "
gameforge.main_quest_lv94._960_say = "Recherchez des p\233pites d'or noir dans les[ENTER]montagnes fulgurantes. "
gameforge.main_quest_lv94._970_1_notice = "Vous avez d\233couvert un filon d'or noir et vous[ENTER]\234tes empar\233 d'une p\233pite du minerai. "
gameforge.main_quest_lv94._970_2_notice = "Ramenez-le \224 l'alchimiste. "
gameforge.main_quest_lv94._980_say = "Ah, vous avez trouv\233 de l'or noir. Montrez-moi[ENTER]\231a\160! Aucune fissure et le fragment est de taille[ENTER]suffisante. Oui, il s'agit d'une p\233pite qui me[ENTER]sera utile pour mon analyse. Je n'ai donc plus[ENTER]besoin que de %d. "
gameforge.main_quest_lv94._990_say = "Je ne peux malheureusement rien faire de ce[ENTER]fragment. Sa taille n'est pas suffisante pour une[ENTER]analyse digne de ce nom.[ENTER]Rapportez-en moi un autre. "
gameforge.main_quest_lv95 = {}
gameforge.main_quest_lv95._010_sendLetter = "La fi\232vre de l'or "
gameforge.main_quest_lv95._020_say = "L'amiral Angmur vous recherche. Il dispose de[ENTER]nouvelles informations sur l'or noir. "
gameforge.main_quest_lv95._030_say = "L'or noir draine l'\233nergie des \234tres vivants de[ENTER]son entourage et la retransmet dans un autre[ENTER]corps.[ENTER]Les serviteurs de l'obscurit\233 veulent insuffler \224[ENTER]Sung Mahi la puissance ainsi subtilis\233e ![ENTER]Crochet, capitaine des g\233ants, entasse[ENTER]d'impressionnantes r\233serves d'or noir dans les[ENTER]montagnes fulgurantes. Emparez-vous en ! "
gameforge.main_quest_lv95._040_say = "C'est comme si c'\233tait fait ! "
gameforge.main_quest_lv95._050_say = {}
gameforge.main_quest_lv95._060_say = {}
gameforge.main_quest_lv95._070_sayTitle = "Le capitaine Crochet mord \224 l'hame\231on. "
gameforge.main_quest_lv95._080_say = "Triomphez du Capitaine Crochet le g\233ant et[ENTER]emparez-vous de l'or noir ! "
gameforge.main_quest_lv95._090_say = "Pas de temps \224 perdre. Venez \224 bout du capitaine[ENTER]Crochet et emparez-vous de l'or noir ! "
gameforge.main_quest_lv95._100_1_notice = "Aucune trace d'or noir. En revanche, le capitaine[ENTER]Crochet portait une lettre sur lui. "
gameforge.main_quest_lv95._100_2_notice = {}
gameforge.main_quest_lv95._110_say = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv95._120_say = "Ah, vous \234tes venu \224 bout du capitaine Crochet.[ENTER]Qu'avez-vous l\224 ? Une lettre ? Montrez-moi \231a ! "
gameforge.main_quest_lv95._130_say = {}
gameforge.main_quest_lv95._140_say = "Mal\233diction ! Le capitaine Crochet a d\233j\224 envoy\233[ENTER]l'or \224 la banshee.[ENTER]La derni\232re phrase est \233nigmatique : La[ENTER]mal\233diction du souffle de vie fera ressurgir[ENTER]l'arm\233e des t\233n\232bres de la brume des temps. "
gameforge.main_quest_lv95._150_say = "Il nous faut emp\234cher la livraison co\251te que[ENTER]co\251te ! Le refuge de la banshee devrait se[ENTER]trouver sur la falaise de Gautama \150 un endroit[ENTER]d\233sol\233 et ignor\233 de tous, envelopp\233 jour et nuit[ENTER]d'un \233pais brouillard. Les ogres et les l\233mures y[ENTER]ont \233lu domicile. "
gameforge.main_quest_lv95._160_say = {}
gameforge.main_quest_lv95._170_say = "Sit\244t que je sais par quelle route l'or noir est[ENTER]achemin\233 vers la banshee, je vous le fais savoir. "
gameforge.main_quest_lv95._180_sendLetter = "Intercepter la livraison. "
gameforge.main_quest_lv95._190_say = "Allez voir l'amiral Angmur. Il dispose de[ENTER]nouvelles informations sur l'acheminement de l'or[ENTER]noir. "
gameforge.main_quest_lv95._200_say = "Mes \233claireurs ont pu d\233couvrir que le capitaine[ENTER]Shrouk, commandant des ogres, achemine l'or noir[ENTER]en direction de la falaise de Gautama. L'or se[ENTER]trouve dans une sacoche accroch\233e \224 sa ceinture.[ENTER]D\233robez-la lui ! "
gameforge.main_quest_lv95._210_say = {}
gameforge.main_quest_lv95._220_say = "Entendu, je me mets \224 sa recherche sans plus[ENTER]attendre. "
gameforge.main_quest_lv95._230_sayTitle = "Interceptez la livraison ! "
gameforge.main_quest_lv95._240_say = "D\233nichez le capitaine Shrouk et emparez-vous de[ENTER]la sacoche d'or noir avant qu'il n'atteigne la[ENTER]banshee. "
gameforge.main_quest_lv95._250_say = "Vaincre le capitaine Shrouk n'est pas une mince[ENTER]affaire ! Mais vous pouvez y arriver ! R\233essayez[ENTER]encore une fois. "
gameforge.main_quest_lv95._260_1_notice = "Vous avez obtenu la sacoche. "
gameforge.main_quest_lv95._260_2_notice = "Ramenez-la \224 l'amiral Angmur. "
gameforge.main_quest_lv95._270_say = "Ramenez votre butin \224 l'amiral Angmur. "
gameforge.main_quest_lv95._280_say = "L'or noir se trouve dans cette sacoche ?[ENTER]Vite, montrez-la moi ! Tiens ! Il n'y a qu'un[ENTER]morceau de papier... "
gameforge.main_quest_lv95._290_say = "L'or noir sera d\233livr\233 sit\244t qu'il aura \233t\233[ENTER]enti\232rement trait\233. "
gameforge.main_quest_lv95._300_say = "Mal\233diction ! L'or noir se trouve encore en de[ENTER]mauvaises mains. Par chance, nous savons[ENTER]maintenant qu'il doit \234tre trait\233 avant que la[ENTER]banshee puisse s'en servir pour ses sombres[ENTER]desseins. "
gameforge.main_quest_lv95._310_say = "Il n'est pas encore trop tard. Je vais t\226cher de[ENTER]d\233couvrir qui est actuellement en possession de[ENTER]l'or noir et si celui-ci a d\233j\224 \233t\233 trait\233. Je[ENTER]vous fais appeler sit\244t que j'en sais plus. En[ENTER]attendant, voici votre r\233compense. \192 bient\244t ! "
gameforge.main_quest_lv95._320_sendLetter = "Interrompre le processus de traitement. "
gameforge.main_quest_lv95._330_say = "Rendez-vous aupr\232s de l'amiral Angmur, il a de[ENTER]nouvelles informations sur l'or noir. "
gameforge.main_quest_lv95._340_say = "Nous avons d\233couvert que le gros ogre en personne[ENTER]supervise le processus de traitement de l'or noir[ENTER]et que c'est ensuite lui qui en assurera la[ENTER]livraison \224 la banshee. "
gameforge.main_quest_lv95._350_say = "Il se trouve actuellement sur la falaise de[ENTER]Gautama.[ENTER]Emp\234chez l'or noir d'atteindre sa cible. Vite,[ENTER]avant qu'il ne soit trop tard ! "
gameforge.main_quest_lv95._360_say = {}
gameforge.main_quest_lv95._370_sayTitle = "Le gros ogre "
gameforge.main_quest_lv95._380_say = "Terrassez le grand chef des ogres et emp\234chez le[ENTER]traitement de l'or noir d'\234tre men\233 \224 bien. "
gameforge.main_quest_lv95._390_say = "Chaque minute est pr\233cieuse ! Vous devez arr\234ter[ENTER]le gros ogre ! "
gameforge.main_quest_lv95._400_notice = "Vous avez vaincu le gros ogre. "
gameforge.main_quest_lv95._410_say = "Vous ne pouvez rien faire pour nous arr\234ter ! La[ENTER]banshee est d\233j\224 en possession de l'or noir. Vous[ENTER]arrivez trop tard, imb\233ciles ! "
gameforge.main_quest_lv95._420_say = "L'\233tau se resserre. Retournez aupr\232s de l'amiral[ENTER]Angmur et dressez-lui un rapport de la situation. "
gameforge.main_quest_lv95._430_say = "Parlez \224 l'amiral Angmur. "
gameforge.main_quest_lv95._440_say = "Vous avez \233t\233 rapide ! Avez-vous l'or noir ? "
gameforge.main_quest_lv95._450_say = "Non, je suis arriv\233 trop tard. L'or est d\233j\224[ENTER]entre les mains de la banshee. "
gameforge.main_quest_lv95._460_say = "Que le Dieu Dragon nous vienne en aide ! Mais[ENTER]nous ne nous avouons pas vaincus pour autant ! Je[ENTER]vais envoyer mes \233claireurs afin qu'ils d\233nichent[ENTER]le repaire de la banshee. Sit\244t que j'en sais[ENTER]plus, je vous le ferai savoir. Reprenez donc des[ENTER]forces et acceptez cette r\233compense. "
gameforge.main_quest_lv95._470_sendLetter = "La mal\233diction du souffle de vie "
gameforge.main_quest_lv95._480_say = "L'amiral Angmur a de nouvelles informations pour[ENTER]vous. "
gameforge.main_quest_lv95._490_say = "Nous savons maintenant ce que signifient la[ENTER]mal\233diction du souffle de vie et l'arm\233e des[ENTER]t\233n\232bres. Il y a bien longtemps, un ignoble[ENTER]sorcier vivait sur le Rocher du Dragon Sombre. Il[ENTER]aspirait \224 r\233gner sur l'ensemble du continent et[ENTER]a litt\233ralement jonch\233 sa route de cadavres pour[ENTER]y arriver : \224 l'aide d'un sortil\232ge mal\233fique, il[ENTER]a r\233veill\233 les morts afin de cr\233er une arm\233e pour[ENTER]livrer ses batailles. "
gameforge.main_quest_lv95._500_say = {}
gameforge.main_quest_lv95._510_say = "Conjurer les morts, l'id\233e seule me remplit[ENTER]d'effroi. \192 l'aide de l'or noir, les serviteurs[ENTER]de l'obscurit\233 forment une arm\233e de[ENTER]morts-vivants.[ENTER]Nous devons les arr\234ter, co\251te que co\251te ! "
gameforge.main_quest_lv95._520_say = "Rendez-vous dans les ruines ancestrales de la[ENTER]falaise de Gautama et cherchez-y le sorcier[ENTER]l\233mure. Il a des informations sur cette[ENTER]mal\233diction. Il vous les r\233v\233lera sans doute, si[ENTER]vous le lui demandez gentiment. "
gameforge.main_quest_lv95._530_say = "Demander gentiment ? On se comprend. Bien, c'est[ENTER]entendu. "
gameforge.main_quest_lv95._540_sayTitle = "La mal\233diction du souffle de vie "
gameforge.main_quest_lv95._550_say = "Venez \224 bout du sorcier l\233mure et rassemblez[ENTER]toutes les informations que vous pouvez trouver[ENTER]sur la mal\233diction du souffle de vie et[ENTER]l'invocation des morts. "
gameforge.main_quest_lv95._560_say = "Pas de temps \224 perdre ! Venez \224 bout du sorcier[ENTER]l\233mure et soutirez-lui les informations dont il[ENTER]dispose sur la mal\233diction du souffle de vie. "
gameforge.main_quest_lv95._570_1_notice = "Vous avez vaincu le sorcier l\233mure et trouv\233 un[ENTER]tableau de pierre sur lequel est grav\233e une[ENTER]inscription. "
gameforge.main_quest_lv95._570_2_notice = "Montrez-la \224 l'amiral Angmur. "
gameforge.main_quest_lv95._580_say = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv95._590_say = "Ah, le sorcier l\233mure \233tait en possession de[ENTER]cette tablette ?[ENTER]Faites-moi voir \231a. "
gameforge.main_quest_lv95._600_sayReward = "Afin de r\233veiller les morts, trois ingr\233dients[ENTER]sont n\233cessaires :[ENTER]1. un corps humain[ENTER]2. ...[ENTER]La tablette des l\233mures est bris\233e ici et le[ENTER]reste de l'inscription manque. "
gameforge.main_quest_lv95._610_say = "Je crains fort qu'il vous faille encore cheminer.[ENTER]Nous avons besoin du reste de l'inscription. Deux[ENTER]autres fragments de la tablette des l\233mures[ENTER]doivent exister quelque part. "
gameforge.main_quest_lv95._620_say = "Voici votre r\233compense pour tous les exploits[ENTER]r\233alis\233s jusqu'\224 maintenant. Mettez-vous[ENTER]maintenant en qu\234te des autres fragments de la[ENTER]tablette des l\233mures ! "
gameforge.main_quest_lv95._630_sendLetter = "L'inscription "
gameforge.main_quest_lv95._640_sayTitle = "Trouvez les fragments de la tablette des l\233mures ! "
gameforge.main_quest_lv95._650_say = "Triomphez des sorciers l\233mures et trouvez les[ENTER]fragments manquants de la tablette des l\233mures. "
gameforge.main_quest_lv95._660_say = "Il nous faut \224 tout prix savoir ce que dit[ENTER]l'inscription. Ne baissez pas les bras, je vous[ENTER]en prie ! "
gameforge.main_quest_lv95._670_say = "Ramenez les fragments manquants de la tablette[ENTER]des l\233mures \224 l'amiral Angmur. "
gameforge.main_quest_lv95._680_say = "Ah, vous revoil\224 ! Reconstituons donc la tablette[ENTER]des l\233mures afin de d\233chiffrer l'inscription ! "
gameforge.main_quest_lv95._690_sayReward = "Trois ingr\233dients sont n\233cessaires afin de[ENTER]r\233veiller les morts :[ENTER]1. un corps humain[ENTER]2. de l'or noir[ENTER]3. l'\233corce d'un arbre d\233moniaque[ENTER]Seul un sorcier aux pouvoirs prodigieux pourra[ENTER]invoquer et faire perdurer la mal\233diction du[ENTER]souffle de vie. Et s'il vient \224 p\233rir, alors[ENTER]l'arm\233e des morts-vivants tout enti\232re sombrera[ENTER]avec lui. "
gameforge.main_quest_lv95._700_say = "C'est donc pour \231a que, ces derniers temps, nos[ENTER]cimeti\232res ont \233t\233 profan\233s et des cadavres ont[ENTER]\233t\233 sortis de leur tombe puis emport\233s. Ils[ENTER]veulent les ramener \224 la vie pour les enr\244ler[ENTER]dans leur arm\233e de morts-vivants. Quelle abjecte[ENTER]perspective ! "
gameforge.main_quest_lv95._710_say = "Il nous faut \224 tout prix emp\234cher ce sacril\232ge ! "
gameforge.main_quest_lv95._720_say = "Certes, mais le temps tourne. Seule la banshee[ENTER]est suffisamment puissante pour conjurer une[ENTER]mal\233diction de cette ampleur. Malheureusement,[ENTER]nous ne savons pas o\249 elle se cache. Je vais[ENTER]envoyer d'avantage d'hommes afin de d\233nicher le[ENTER]repaire de la grande pr\234tresse des t\233n\232bres. Je[ENTER]vous fais appeler sit\244t que j'ai du nouveau. "
gameforge.main_quest_lv95._730_say = {}
