gameforge.main_quest_lv96._050_say = {}
gameforge.main_quest_lv96._060_say = "Afin que les \226mes lib\232rent leur corps, un m\233dium[ENTER]est requis. En l'occurrence, il s'agit de terre[ENTER]b\233nie que les g\233ants conservent dans des sacs. Si[ENTER]vous arrivez \224 mettre la main sur 100 de ces[ENTER]sacs, alors nous pourrons emp\234cher que la[ENTER]mal\233diction du souffle de vie ne soit conjur\233e. "
