gameforge.main_quest_lv96._080_sayTitle = "Terre b\233nie "
gameforge.main_quest_lv96._090_say = "Triomphez des g\233ants et emparez-vous de 100 sacs[ENTER]de terre b\233nie. "
gameforge.main_quest_lv96._100_say = "Le temps joue en notre d\233faveur. Vite,[ENTER]d\233p\234chez-vous de vous emparer des sacs de terre[ENTER]b\233nie ! "
gameforge.main_quest_lv96._110_1_notice = "Vous \234tes en possession de tous les sacs de terre[ENTER]b\233nie. "
gameforge.main_quest_lv96._110_2_notice = "Ramenez-les \224 l'amiral Angmur. "
gameforge.main_quest_lv96._120_say = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv96._130_say = "Je peux d\233cid\233ment toujours compter sur vous ![ENTER]Acceptez donc cette r\233compense. "
gameforge.main_quest_lv96._140_sendLetter = "Entraver la mal\233diction "
gameforge.main_quest_lv96._150_say = "L'amiral Angmur a une nouvelle mission \224 vous[ENTER]confier. "
gameforge.main_quest_lv96._160_say = "Les ogres sont \233galement en possession d'un[ENTER]m\233dium d'invocation des morts. Mais nous ne[ENTER]savons pas \224 quoi celui-ci ressemble. Rendez-vous[ENTER]chez les ogres et ramenez tout ce qui vous semble[ENTER]suspect. "
gameforge.main_quest_lv96._170_say = {}
gameforge.main_quest_lv96._180_say = {}
gameforge.main_quest_lv96._190_say = "C'est entendu. "
gameforge.main_quest_lv96._200_sayTitle = "Le m\233dium des ogres "
gameforge.main_quest_lv96._210_say = "Vainquez les ogres et d\233couvrez \224 quoi leur[ENTER]m\233dium ressemble. "
gameforge.main_quest_lv96._220_say = "Je sais bien que vous ne disposez pas de beaucoup[ENTER]d'indices. Mais vous arriverez bien \224 d\233nicher[ENTER]quelque chose ! "
gameforge.main_quest_lv96._230_1_notice = "Vous avez trouv\233 une bourse et un insigne dor\233. "
gameforge.main_quest_lv96._230_2_notice = "Rapportez ces deux objets \224 l'amiral Angmur. "
gameforge.main_quest_lv96._240_say = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv96._250_say = "Du bon travail\160! Je vais demander \224 Yon-I-Walker[ENTER]d'analyser ces objets. "
gameforge.main_quest_lv96._260_say = "Allez voir Yon-I-Walker et prenez connaissance[ENTER]des r\233sultats de son analyse. "
gameforge.main_quest_lv96._270_say = "Ah, vous revoil\224\160! J'ai d\233j\224 pu jeter un \156il aux[ENTER]objets que vous avez trouv\233s chez les ogres. "
gameforge.main_quest_lv96._280_say = {}
gameforge.main_quest_lv96._290_say = "Les pi\232ces d'or de la bourse \233mettent une force[ENTER]mal\233fique puissante. Ce sont elles qui servent de[ENTER]m\233dium. Allez en informer Angmur. "
gameforge.main_quest_lv96._300_sendLetter = "Entraver la mal\233diction "
gameforge.main_quest_lv96._310_say = "Allez voir l'amiral Angmur. "
gameforge.main_quest_lv96._320_say = "Prenez donc ce bandeau du prospecteur.[ENTER]Utilisez-le pour rep\233rer les bourses des ogres. "
gameforge.main_quest_lv96._330_say = "Nous avons besoin de 100 pi\232ces d'or. Mais je[ENTER]crains que toutes celles que vous trouvez ne[ENTER]soient pas n\233cessairement utilis\233es comme m\233dium.[ENTER]Un travail titanesque vous attend donc. "
gameforge.main_quest_lv96._340_say = "Pas de probl\232me. "
gameforge.main_quest_lv96._350_sayTitle = "La ru\233e vers l'or "
gameforge.main_quest_lv96._360_say = "Lancez l'assaut contre les ogres et r\233cup\233rez[ENTER]leurs bourses. Toutes les pi\232ces d'or ne sont pas[ENTER]des m\233diums, il vous faut donc les faire[ENTER]expertiser par Yon-I-Walker. "
gameforge.main_quest_lv96._370_say = "Oui, je per\231ois une force mal\233fique ind\233niable. "
gameforge.main_quest_lv96._380_say = "Fantastique, nous avons mis la main sur toutes[ENTER]les pi\232ces d'or \224 m\234mes de servir de m\233diums.[ENTER]Cela va sans doute d\233plaire \224 la banshee ! Voici[ENTER]votre r\233compense. Angmur va vous assigner votre[ENTER]prochaine mission. "
gameforge.main_quest_lv96._390_say = "Il vous manque encore des pi\232ces d'or. Trouvez-en[ENTER]%d suppl\233mentaires. "
gameforge.main_quest_lv96._400_sendLetter = "Entraver la mal\233diction "
gameforge.main_quest_lv96._410_say = "L'amiral Angmur vous demande. "
gameforge.main_quest_lv96._420_say = "Nous devons nous assurer que les serviteurs de[ENTER]l'obscurit\233 ne mettent pas la main sur de[ENTER]l'\233corce d'arbre d\233moniaque. "
gameforge.main_quest_lv96._430_say = "Les arbres d\233moniaques comptent parmi les \234tres[ENTER]les plus \233nigmatiques de notre monde. Ils ne[ENTER]servent personne, pas m\234me Sung Mahi.[ENTER]Trois esp\232ces peuplent la falaise de Gautama :[ENTER]Aku-Boku, Arboretris et Sycomore. Pr\233levez[ENTER]l'\233corce de chacune. "
gameforge.main_quest_lv96._440_say = {}
gameforge.main_quest_lv96._450_say = "C'est entendu. "
gameforge.main_quest_lv96._460_sayTitle = "\201cimer les arbres d\233moniaques. "
gameforge.main_quest_lv96._470_say = "Pr\233levez l'\233corce d'un Aku-Boku, d'un Arboretris[ENTER]et d'un Sycomore. "
gameforge.main_quest_lv96._480_counterName = "Restants "
gameforge.main_quest_lv96._490_say = "%s : %d[ENTER]%s : %d[ENTER]%s : %d "
gameforge.main_quest_lv96._500_say = "Le temps presse. R\233duisez les arbres d\233moniaques[ENTER]en copeaux et emparez-vous de leur \233corce avant[ENTER]que les serviteurs ne puissent en faire autant. "
gameforge.main_quest_lv96._510_1_notice = "Vous avez vaincu tous les arbres d\233moniaques,[ENTER]mais quelqu'un vous a pr\233c\233d\233 : l'\233corce a d\233j\224[ENTER]\233t\233 arrach\233e de leur tronc. "
gameforge.main_quest_lv96._510_2_notice = "Allez en informer l'amiral Angmur. "
gameforge.main_quest_lv96._520_say = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv96._530_say = "Ah, vous revoil\224 sain et sauf, tr\232s bien ![ENTER]Avez-vous rempli votre mission ? Comment ?! Les[ENTER]arbres d\233moniaques \233taient d\233j\224 d\233lest\233s de leur[ENTER]\233corce et vous avez vu des traces de joutes[ENTER]r\233centes ? Cela indique que les serviteurs de[ENTER]l'obscurit\233 nous ont certainement devanc\233s. "
gameforge.main_quest_lv96._540_say = {}
gameforge.main_quest_lv96._550_say = "S'ils ont l'\233corce, alors ils trouveront sans[ENTER]doute un moyen de conjurer la mal\233diction du[ENTER]souffle de vie. C'est d\233sormais in\233vitable : nous[ENTER]devons entrer en guerre. La banshee ne se[ENTER]d\233robera plus longtemps. Mes hommes sont d\233j\224 sur[ENTER]sa trace. Je vous ferai appeler sit\244t qu'ils[ENTER]l'auront trouv\233e. "
gameforge.main_quest_lv96._560_sayTitle = "Vous pourrez poursuivre l'aventure sit\244t que vous[ENTER]aurez atteint le niveau 97. "
gameforge.main_quest_lv96._570_counterName = "Restants "
gameforge.main_quest_lv96._580_sayReward = "%s\160: %d unit\233s "
gameforge.main_quest_lv96._590_say = "Les pi\232ces d'or servent donc de m\233dium. Bien, je[ENTER]vais consulter Yon-I-Walker afin que nous[ENTER]d\233cidions de la marche \224 adopter. Je reviens vous[ENTER]voir dans un instant. "
gameforge.main_quest_lv96._600_say = {}
gameforge.main_quest_lv96._610_say = {}
gameforge.main_quest_lv96._620_1_notice = "Vous avez obtenu une bourse. "
gameforge.main_quest_lv96._620_2_notice = "Rapportez-la \224 Yon-I-Walker. "
gameforge.main_quest_lv96._630_say = "Il s'agit d'une pi\232ce normale et pas d'un m\233dium.[ENTER]Continuez votre recherche ! "
gameforge.main_quest_lv97 = {}
gameforge.main_quest_lv97._010_sendLetter = "D\233jouer les plans de la banshee "
gameforge.main_quest_lv97._020_say = "Nous avons d\233couvert le repaire de la banshee\160![ENTER]Allez voir l'amiral Angmur afin d'en savoir plus. "
gameforge.main_quest_lv97._030_say = "Mes hommes ont enfin d\233nich\233 le repaire de la[ENTER]banshee sur la falaise de Gautama. Elle se tapit[ENTER]dans l'obscurit\233 des for\234ts avoisinantes et y[ENTER]perp\232tre sa magie noire. De plus, elle a r\233veill\233[ENTER]une ancienne vestale du culte du Dragon, \224 l'aide[ENTER]de qui elle compte invoquer la mal\233diction du[ENTER]souffle de vie. "
gameforge.main_quest_lv97._040_say = "Sans son aide, la banshee ne pourra pas maintenir[ENTER]la mal\233diction. Triomphez de la vestale Mu-Shu et[ENTER]apaisez les \226mes tourment\233es de nos camarades,[ENTER]avant que leur d\233pouille ne se rel\232ve et qu'ils[ENTER]ne marchent sur nous. "
gameforge.main_quest_lv97._050_say = "Il est quasiment impossible de s'approcher[ENTER]furtivement de la vestale pour l'attaquer par[ENTER]surprise.[ENTER]Profitez du moment o\249 elle est tellement[ENTER]profond\233ment plong\233e dans sa magie noire, qu'elle[ENTER]entre dans une transe intense. "
gameforge.main_quest_lv97._060_say = "C'est d'accord. "
gameforge.main_quest_lv97._070_say = "Soyez prudent\160! De son vivant, il s'agissait de[ENTER]la protectrice attitr\233e de la grande pr\234tresse et[ENTER]elle ne se contente pas de ma\238triser la magie\160:[ENTER]elle est \233galement redoutable une \233p\233e \224 la main. "
gameforge.main_quest_lv97._080_sayTitle = "La vestale "
gameforge.main_quest_lv97._090_say = "Triomphez de Mu-Shu, vestale de la banshee, sur[ENTER]la falaise de Gautama. "
gameforge.main_quest_lv97._100_notice = "Mortellement touch\233e, la vestale s'effondre. "
gameforge.main_quest_lv97._110_say = "Imb\233ciles\160! Vous avez saut\233 des deux pieds dans[ENTER]le pi\232ge tendu par la banshee. Tandis que vous[ENTER]perdiez votre temps \224 me combattre, la ma\238tresse[ENTER]et Yah-Ki, la v\233ritable vestale, ont d\233j\224 entam\233[ENTER]le rituel d'invocation. Je prie de toute mon \226me[ENTER]que celui-ci r\233ussisse\160! "
gameforge.main_quest_lv97._120_say = "Cette vestale \233tait un leurre cens\233 vous faire[ENTER]suivre une fausse piste. Apr\232s l'avoir inspect\233e,[ENTER]vous trouvez un collier ressemblant \224 celui[ENTER]trouv\233 sur Martyaxwar. Dans la poche int\233rieure,[ENTER]vous trouvez un document. "
gameforge.main_quest_lv97._130_say = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv97._140_say = "Vous voil\224 de retour\160! Avez-vous vaincu la[ENTER]vestale\160? "
gameforge.main_quest_lv97._150_say = "Non, nous avons \233t\233 tromp\233s par un double.[ENTER]Pendant ce temps, la v\233ritable vestale a pu[ENTER]pr\233parer l'invocation des morts en toute[ENTER]s\233r\233nit\233. Tenez, j'ai trouv\233 ce document. "
gameforge.main_quest_lv97._160_say = "Mal\233diction ! Comment avons-nous pu nous laisser[ENTER]aussi facilement berner\160? Montrez-moi vite ce[ENTER]document\160! "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Hmm, il est cod\233. Mais peut-\234tre que ce message[ENTER]nous r\233v\233lera o\249 se trouve leur v\233ritable[ENTER]repaire.[ENTER]Il me semble avoir d\233j\224 vu ces symboles quelque[ENTER]part... Je crois que Yak-Hwan, le gardien du[ENTER]palais, m'a r\233cemment montr\233 quelque chose de[ENTER]semblable. Il faut qu'il y jette un \156il. "
gameforge.main_quest_lv97._200_sendLetter = "D\233crypter le document "
gameforge.main_quest_lv97._210_say = "Allez voir Yak-Hwan et montrez-lui le document[ENTER]cod\233. "
gameforge.main_quest_lv97._220_say = "La paix soit avec vous\160! Mon nom est Yak-Hwan.[ENTER]Honor\233 de vous rencontrer. La r\233putation de vos[ENTER]faits d'armes vous pr\233c\232de\160! Que puis-je faire[ENTER]pour vous\160? Ah, un document cod\233. Montrez-moi \231a. "
gameforge.main_quest_lv97._230_say = "Oui, d\233crypter ces symboles devrait \234tre un jeu[ENTER]d'enfant. J'ai juste besoin d'un peu de terre[ENTER]fossile. L'alchimiste devrait en avoir une motte.[ENTER]Demandez-la-lui. "
gameforge.main_quest_lv97._240_say = {}
gameforge.main_quest_lv97._250_say = {}
gameforge.main_quest_lv97._260_say = "Bien entendu. "
gameforge.main_quest_lv97._270_sayTitle = "Terre fossile "
gameforge.main_quest_lv97._280_say = "Allez voir l'alchimiste et demandez-lui de vous[ENTER]donner de la terre fossile. "
gameforge.main_quest_lv97._290_say = "N'avez-vous rien oubli\233 ? Vous \233tiez cens\233 me[ENTER]ramener de la terre fossile. "
gameforge.main_quest_lv97._300_notice = "L'alchimiste vous a donn\233 de la terre fossile.[ENTER]Retournez voir Yak-Hwan. "
gameforge.main_quest_lv97._310_say = "Ah, la terre fossile. Parfait, je vais pouvoir me[ENTER]mettre au travail. Je communiquerai le r\233sultat \224[ENTER]l'amiral Angmur. "
gameforge.main_quest_lv97._320_sendLetter = "Par la petite porte. "
gameforge.main_quest_lv97._330_say = "L'amiral Angmur vous demande. "
gameforge.main_quest_lv97._340_say = "Nous savons d\233sormais o\249 la vestale Yah-Ki se[ENTER]tapit.[ENTER]Malheureusement, son repaire est une v\233ritable[ENTER]forteresse. Des gardes y patrouillent jour et[ENTER]nuit.[ENTER]Pour le moment, un assaut frontal serait un[ENTER]suicide pur et dur. "
gameforge.main_quest_lv97._350_say = "C'est la raison pour laquelle nous comptons[ENTER]tendre une embuscade. Mes hommes recherchent un[ENTER]endroit ad\233quat. Distrayez les gardes, afin de[ENTER]nous faire gagner un peu de temps. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "Le plus grand p\233ril provient d'une troupe de[ENTER]garde qui se fait nommer la brigade de la mort[ENTER]lugubre. Elle compte dans ses rangs les[ENTER]redoutables Moghu, Carnifex et le g\233n\233ral Albus.[ENTER]Leur chef est Squelettos. D\233barrassez-nous en[ENTER]avant qu'ils ne rep\232rent mes \233claireurs. "
gameforge.main_quest_lv97._380_say = "Compris. "
gameforge.main_quest_lv97._390_sayTitle = "Brigade de la mort lugubre. "
gameforge.main_quest_lv97._400_say = "\201liminez la brigade de la mort lugubre, incarn\233e[ENTER]par Moghu, Carnifex, le g\233n\233ral Albus et[ENTER]Squelettos. "
gameforge.main_quest_lv97._410_say = "Ex\233cutez les membres de la brigade de la mort[ENTER]lugubre avant qu'ils ne tombent nez \224 nez avec[ENTER]nos \233claireurs. "
gameforge.main_quest_lv97._420_say = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv97._430_say = "Notre plan a fonctionn\233\160! Tandis que vous faisiez[ENTER]diversion en combattant la brigade de la mort[ENTER]lugubre, mes hommes ont trouv\233 un emplacement[ENTER]parfait pour une embuscade. Sit\244t que nous aurons[ENTER]mis notre strat\233gie d'attaque en place, je vous[ENTER]ferai appeler. "
gameforge.main_quest_lv97._440_sendLetter = "La vestale "
gameforge.main_quest_lv97._450_say = "L'amiral Angmur a besoin de votre aide\160! "
gameforge.main_quest_lv97._460_say = "Ah, vous voil\224. Squelettos, le chef de la brigade[ENTER]de la mort lugubre, a surv\233cu et attaqu\233 mes[ENTER]hommes, alors qu'ils s'appr\234taient \224 donner[ENTER]l'assaut sur le repaire. D\233sormais, personne ne[ENTER]peut passer outre. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Vous l'avez d\233j\224 vaincu une premi\232re fois. Pr\234tez[ENTER]donc main-forte \224 mes hommes sur la falaise de[ENTER]Gautama\160! Occupez-vous de Squelettos, puis lancez[ENTER]l'assaut sur le repaire et exterminez la vestale[ENTER]Yah-ki. "
gameforge.main_quest_lv97._490_say = "Entendu\160! "
gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Exterminer Yah-Ki "
gameforge.main_quest_lv97._520_say = "Triomphez de la vestale Yah-ki et emp\234chez-la[ENTER]d'invoquer l'arm\233e des morts. "
gameforge.main_quest_lv97._530_say = "L'heure du jugement final a sonn\233. Si nous[ENTER]\233chouons, alors le monde entier sombrera avec[ENTER]nous.[ENTER]Mais si nous triomphons, alors les g\233n\233rations[ENTER]des si\232cles futures continueront \224 chanter nos[ENTER]louanges. Arr\234tez les serviteurs de l'Obscurit\233[ENTER]et exterminez la vestale Yah-ki\160! "
gameforge.main_quest_lv97._540_say = "Qu'est-ce que vous faites ici\160? Le combat n'est[ENTER]pas encore gagn\233\160! Triomphez de la vestale[ENTER]Yah-Ki.[ENTER]Tous nos espoirs reposent sur vos \233paules. "
gameforge.main_quest_lv97._550_1_notice = "Vous avez mis vos adversaires \224 genoux et la[ENTER]victoire vous appartient\160! "
gameforge.main_quest_lv97._550_2_notice = "Pas le temps de souffler\160: la vestale Yah-Ki vous[ENTER]attend d\233j\224. "
gameforge.main_quest_lv97._560_notice = "Vous avez triomph\233\160! Yah-Ki s'effondre en lan\231ant[ENTER]un cri d\233chirant. "
gameforge.main_quest_lv97._570_say = "Aaaaah\160! C'est impossible\160! Vaincue par un[ENTER]mortel... \212 banshee, pardonne-moi, j'ai \233chou\233.[ENTER]Je n'ai pas pu mener ma t\226che \224 b... "
gameforge.main_quest_lv97._580_say = "Vous fouillez son corps inerte et trouvez une[ENTER]lettre scell\233e. Ramenez-la \224 l'amiral Angmur. "
gameforge.main_quest_lv97._590_say = "Ah\160! Le dieu Dragon soit lou\233, vous \234tes sain et[ENTER]sauf. Avez-vous vaincu la vestale\160? "
gameforge.main_quest_lv97._600_say = "Oui, je l'ai renvoy\233e dans l'enfer qu'elle[ENTER]n'aurait jamais d\251 quitter. Son dernier souffle[ENTER]lui a servi \224 demander pardon pour son \233chec. Et[ENTER]voici ce qu'elle portait sur elle. "
gameforge.main_quest_lv97._610_say = "Une lettre scell\233e. Montrez-moi \231a\160! "
gameforge.main_quest_lv97._620_sayReward = "Ch\232re ma\238tresse, ils ont mordu \224 l'hame\231on et[ENTER]votre plan a fonctionn\233. L\146invocation de votre[ENTER]arm\233e de morts-vivants avance \224 grands pas et[ENTER]plus personne ne pourra l'emp\234cher. Une fois que[ENTER]ces corps sans \226mes seront en marche, nous[ENTER]pourrons fondre sur le cap du Feu dragonesque et[ENTER]r\233duire ses habitants en poussi\232re. Nous pourrons[ENTER]alors rejoindre le continent et vous retrouver \224[ENTER]Doyyumhwan pour mettre ensemble la terre enti\232re[ENTER]\224 feu et \224 sang\160![ENTER]Je m'incline r\233v\233rencieusement.[ENTER]Votre servante \233ternelle "
gameforge.main_quest_lv97._630_say = "Un message \224 la banshee\160! D\233sormais, l'odieuse[ENTER]sorci\232re de Doyyumhwan attend son arm\233e des[ENTER]t\233n\232bres. Je vous en remercie en vain. Sans votre[ENTER]aide, la horde des morts-vivants aurait r\233duit en[ENTER]cendres le Cap et ses habitants. Vous nous avez[ENTER]non seulement sauv\233s, mais vous avez \233galement[ENTER]apais\233 les \226mes de nos anc\234tres. J'ai l'insigne[ENTER]honneur de vous remettre cette r\233compense, au nom[ENTER]de tout le fort. "
gameforge.main_quest_lv97._640_sayTitle = "Vous pourrez poursuivre l'aventure sit\244t que vous[ENTER]aurez atteint le niveau 98. "
gameforge.main_quest_lv97._650_say = "D\233nicher le repaire nous a pris beaucoup de temps.Je vous en prie, nous ne pouvons en perdre[ENTER]d'avantage\160! "
gameforge.main_quest_lv97._660_say = "Yak-Hwan a besoin de terre fossile\160? Quelle[ENTER]chance que je ne m'en sois pas encore servie.[ENTER]Tenez, la voil\224. Ramenez-la-lui et[ENTER]transmettez-lui mes salutations. "
gameforge.main_quest_lv97._670_counterName = "Restants "
gameforge.main_quest_lv97._680_sayReward = "%s\160: %d[ENTER]%s\160: %d "
gameforge.main_quest_lv97._690_1_notice = "Vous avez extermin\233 la brigade de la mort lugubre. "
gameforge.main_quest_lv97._690_2_notice = "Allez faire votre rapport \224 l'amiral Angmur. "
gameforge.main_quest_lv97._700_sayTitle = "Terrassez Squelettos, chef de la brigade de la[ENTER]mort lugubre. "
gameforge.main_quest_lv97._710_say = "Vous ne pourrez porter l\146estocade finale \224 la[ENTER]vestale qu'une fois Squelettos terrass\233. "
gameforge.main_quest_lv98 = {}
gameforge.main_quest_lv98._010_sendLetter = "Reconstruction du fort "
gameforge.main_quest_lv98._020_say = "Amiral Angmur a besoin de votre aide. Allez le[ENTER]voir. "
gameforge.main_quest_lv98._030_say = "Je vous remercie d'\234tre venu. La bataille ne nous[ENTER]a pas laiss\233s indemne. L'ennemi a \233galement[ENTER]attaqu\233 le fort et abattu la muraille de[ENTER]protection \224 bien des endroits. La paix risque[ENTER]d'\234tre de courte dur\233e. Il nous faut donc[ENTER]profiter de ce r\233pit pour entamer la[ENTER]reconstruction. "
gameforge.main_quest_lv98._040_say = "Afin de renforcer la muraille, nous avons besoin[ENTER]de carapaces de la tribu des crustac\233ens. "
gameforge.main_quest_lv98._050_say = "Je m'en charge. Combien de carapaces vous[ENTER]faut-il\160? "
gameforge.main_quest_lv98._060_say = "Une centaine devrait faire l'affaire. La tribu[ENTER]des crustac\233ens occupe toujours la baie de[ENTER]N\233phrite. "
gameforge.main_quest_lv98._070_say = "Non, ce n'est pas suffisant. Je vous en prie,[ENTER]ramenez-moi d'avantage de carapaces. "
gameforge.main_quest_lv98._080_1_notice = "Vous avez r\233cup\233r\233 suffisamment de carapaces[ENTER]crustac\233es. "
gameforge.main_quest_lv98._080_2_notice = "Ramenez-les \224 l'amiral Angmur. "
gameforge.main_quest_lv98._090_say = "Ah, parfait\160! Ces carapaces vont nous permettre[ENTER]de renforcer la muraille. Tenez, prenez cette[ENTER]r\233compense. Je vais demander \224 mes ing\233nieurs[ENTER]s'ils ont besoin d'autres mat\233riaux et vous le[ENTER]ferai alors savoir. "
gameforge.main_quest_lv98._130_sendLetter = "Reconstruction du fort "
gameforge.main_quest_lv98._140_say = "L'amiral Angmur a encore une fois besoin de votre[ENTER]aide. Allez le voir. "
gameforge.main_quest_lv98._150_say = "Afin d'achever la r\233paration des fortifications,[ENTER]nous avons besoin de javelots de tritons. Comme[ENTER]leur nom l'indique, c'est chez les tritons que[ENTER]vous en trouverez. Merci de m'en ramener une[ENTER]centaine. "
gameforge.main_quest_lv98._160_say = "C'est entendu. "
gameforge.main_quest_lv98._170_say = "Ah, vous voil\224. Mais le nombre de javelots est[ENTER]insuffisant. Veuillez m'en ramener d'avantage. "
gameforge.main_quest_lv98._180_1_notice = "Vous avez r\233cup\233r\233 tous les javelots de triton. "
gameforge.main_quest_lv98._180_2_notice = "Ramenez-les \224 l'amiral Angmur. "
gameforge.main_quest_lv98._190_say = "Parfait, nous allons maintenant pouvoir[ENTER]construire une enceinte imprenable. Je vous[ENTER]remercie de votre aide. Tant que j'y pense,[ENTER]Yak-Hwan vous demande.[ENTER]Allez voir ce qu'il veut. "
gameforge.main_quest_lv98._200_sendLetter = "\201tat d'urgence "
gameforge.main_quest_lv98._210_say = "Allez voir Yak-Hwan. Il a une t\226che importante \224[ENTER]vous confier. "
gameforge.main_quest_lv98._220_say = "Ah, vous voil\224, tr\232s bien. Nous avons encore une[ENTER]fois besoin de votre aide. "
gameforge.main_quest_lv98._230_say = {}
gameforge.main_quest_lv98._240_say = {}
gameforge.main_quest_lv98._250_say = {}
gameforge.main_quest_lv98._260_say = "Cette abominable guerre a r\233clam\233 un lourd tribut[ENTER]aux habitants du fort. Leur ventre crie famine et[ENTER]leur mis\232re empire chaque jour. Je ne donne pas[ENTER]cher de leur peau, si nous ne r\233agissons pas au[ENTER]plus vite. "
gameforge.main_quest_lv98._270_say = {}
gameforge.main_quest_lv98._280_say = "Des bandes d'ogres \233pient et attaquent nos[ENTER]caravanes de ravitaillement. Nous devons mettre[ENTER]un terme \224 ces pillages. Le capitaine Shrouk et[ENTER]ses g\233n\233raux sont les cerveaux de cette[ENTER]op\233ration.[ENTER]Tuez le capitaine des ogres ainsi que 50 g\233n\233raux[ENTER]ogres\160! "
gameforge.main_quest_lv98._290_say = {}
gameforge.main_quest_lv98._300_say = "Vous \234tes d\233j\224 de retour\160? Une partie des ogres[ENTER]est pourtant encore debout. Je vous en prie,[ENTER]tuez-les tous\160! "
gameforge.main_quest_lv98._310_1_notice = "Vous avez vaincu tous les ogres. "
gameforge.main_quest_lv98._310_2_notice = "Vous pouvez retourner voir Yak-Hwan. "
gameforge.main_quest_lv98._320_say = "Nos caravanes de ravitaillement arrivent enfin \224[ENTER]destination et les habitants du fort ont[ENTER]d\233sormais acc\232s \224 de la nourriture et aux soins.[ENTER]La mis\232re touche \224 sa fin. Vous \234tes vraiment un[ENTER]authentique h\233ros\160! "
gameforge.main_quest_lv98._330_sendLetter = "Gratitude "
gameforge.main_quest_lv98._340_say = "Yak-Hwan souhaite vous parler. "
gameforge.main_quest_lv98._350_say = "Gr\226ce \224 votre courage, le danger est \233cart\233 du[ENTER]rocher du Dragon Sombre. Pour le moment, du[ENTER]moins. Ses habitants souhaitent vous exprimer en[ENTER]personne leur \233ternelle reconnaissance. "
gameforge.main_quest_lv98._360_say = "Faites donc un tour du fort et parlez \224 ses[ENTER]habitants. "
gameforge.main_quest_lv98._370_say = {}
gameforge.main_quest_lv98._380_say = "Merci, je vais aller parler avec tous les[ENTER]habitants. "
gameforge.main_quest_lv98._390_say = "Tous les habitants n'ont pas eu l'occasion de[ENTER]vous remercier. Ils risquent d'\234tre tr\232s d\233\231us.[ENTER]Veuillez vous assurer que vous n'oubliez[ENTER]personne. "
gameforge.main_quest_lv98._400_say = "Le courage et la sagesse cohabitent en parfaite[ENTER]harmonie dans votre c\156ur valeureux. Nombreuses[ENTER]sont les g\233n\233rations futures qui chanteront[ENTER]encore vos louanges. Je me prosterne devant vous. "
gameforge.main_quest_lv98._410_say = "Que jamais le moindre danger ne vous trouve[ENTER]d\233sarm\233\160! "
gameforge.main_quest_lv98._420_say = "Vous occuperez pour toujours une place de choix[ENTER]dans nos c\156urs. "
gameforge.main_quest_lv98._430_say = "C'est une p\233riode bien tumultueuse qui s'ach\232ve,[ENTER]n'est-ce pas\160? Je suis certain que c'est le dieu[ENTER]Dragon lui-m\234me qui a guid\233 vos pas vers notre[ENTER]\238le. "
gameforge.main_quest_lv98._440_1_notice = "Vous avez parl\233 \224 tous les habitants. "
gameforge.main_quest_lv98._440_2_notice = "Vous pouvez retourner voir Yak-Hwan. "
gameforge.main_quest_lv98._450_say = "Encore merci pour les habitants du fort, cela[ENTER]leur tenait vraiment \224 c\156ur. L'amiral souhaite[ENTER]\233galement vous parler. Allez le voir sans plus[ENTER]attendre. "
gameforge.main_quest_lv98._460_say = {}
gameforge.main_quest_lv98._470_say = {}
gameforge.main_quest_lv98._480_sendLetter = "Reconnaissance de l'amiral "
gameforge.main_quest_lv98._490_say = "L'amiral souhaite vous t\233moigner sa[ENTER]reconnaissance. Allez le voir. "
gameforge.main_quest_lv98._500_say = "Sans vous, les habitants de ce fort auraient \233t\233[ENTER]d\233cim\233s par les d\233mons. Au nom de mes troupes et[ENTER]du peuple tout entier, je tiens \224 vous t\233moigner[ENTER]notre profonde reconnaissance pour votre[ENTER]assistance dans la guerre contre les serviteurs[ENTER]de l'Obscurit\233. Le rocher du Dragon Sombre vous[ENTER]accueillera toujours \224 bras ouverts. "
gameforge.main_quest_lv98._510_say = {}
gameforge.main_quest_lv98._520_say = "Mais la banshee et les serviteurs de l'Obscurit\233[ENTER]ne vont pas nous laisser de r\233pit. Ils fomentent[ENTER]sans doute d\233j\224 de nouveaux plans d\233moniaques.[ENTER]L'aventure continue sit\244t que vous avez atteint[ENTER]le niveau 99. "
