gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "Ho ho ho\160! "
gameforge.new_christmas._020_say = "Ah, c'est vous\160![ENTER]\199a fait un bail qu'on ne s'est pas vus\160![ENTER]D\233j\224 un an, ho ho\160![ENTER]Vous vous demandez peut-\234tre pourquoi je suis de[ENTER]retour au village.[ENTER]Je vais vous expliquer\133 "
gameforge.new_christmas._030_say = "Les temps sont durs. De nos jours, plus personne[ENTER]n'ach\232te de livres ou ce genre de choses.[ENTER]\192 mon \226ge, c'est bien trop fatigant de parcourir[ENTER]les airs en tra\238neau. C'est pourquoi cette ann\233e[ENTER]j'ai d\233cid\233 de passer No\235l au village. "
gameforge.new_christmas._040_say = "Si vous avez encore des questions, passez me voir[ENTER]quand vous voulez. Joyeux No\235l\160! "
gameforge.new_christmas._050_npcChat = "Un petit vin chaud\160? "
gameforge.new_christmas._060_say = "Ho ho ho\160! Vous le savez bien, non\160? Il n'y a pas[ENTER]de meilleure boisson en hiver\160![ENTER]Un bon vin, une pinc\233e de cannelle, quelques[ENTER]clous de girofle\133 Mmm\160! "
gameforge.new_christmas._070_say = "Avec ce froid, une gorg\233e de vin chaud vous fera[ENTER]le plus grand bien\160! \199a vous donnera des forces[ENTER]et vous pourrez vous d\233placer plus rapidement.[ENTER]Vous voulez go\251ter\160? Tr\232s bien, je vous pr\233pare[ENTER]\231a tout de suite\160! "
gameforge.new_christmas._080_say = "Vous avez l'air d'appr\233cier mon vin chaud, ho[ENTER]ho\160! \199a r\233chauffe, hein\160? Et ce go\251t... sucr\233 et[ENTER]fruit\233. Joyeux No\235l\160! "
gameforge.new_christmas._090_npcChat = "Encore du vin chaud, s'il vous pla\238t\160! "
gameforge.new_christmas._100_say = "Ah, un instant\160![ENTER]J'ai oubli\233 un d\233tail. Avec les ingr\233dients dont[ENTER]je dispose, je ne peux pr\233parer du vin chaud[ENTER]qu'une fois par jour. Il se conserve 20 heures.[ENTER]Une gourde contient 6 portions, et chaque gorg\233e[ENTER]agit pendant 30 minutes. Sachez bien les[ENTER]r\233partir\160! "
gameforge.new_christmas._110_say = "Et voil\224\160! Vous avez d\251 attendre un peu, mais ce[ENTER]formidable breuvage vous donnera des ailes, ho ho[ENTER]ho\160! \192 votre sant\233, et joyeux No\235l\160! "
gameforge.new_christmas._120_say = "Vous en voulez encore\160??[ENTER]D\233sol\233, mais vous en avez d\233j\224 bu assez. Votre[ENTER]derni\232re ration de vin chaud ne remonte pas \224[ENTER]plus de 24 heures\160! Il ne faut pas abuser des[ENTER]bonnes choses...[ENTER]Revenez plus tard.[ENTER]Et Joyeuses f\234tes\160! "
gameforge.new_christmas_gift_box = {}
