gameforge.new_christmas_gift_box._020_say = "D\233ballez le prochain cadeau dans %d m. "
gameforge.new_christmas_sock = {}
gameforge.new_christmas_sock._010_npcChat = "Qu'en est-il des chaussettes\160? "
gameforge.new_christmas_sock._020_say = "Les chaussettes\160! Je les avais presque oubli\233es\160![ENTER]Je voulais cacher mes cadeaux dans les[ENTER]chaussettes accroch\233es au-dessus des chemin\233es.[ENTER]Mais d'irrespectueuses cr\233atures les ont toutes[ENTER]vol\233es\160! Aidez-moi \224 les r\233cup\233rer. "
gameforge.new_christmas_sock._030_say = "Les chaussettes ne sont pas faciles \224 trouver.[ENTER]Vous aurez besoin d'un faon pour les rep\233rer. "
gameforge.new_christmas_sock._040_say = "Il n'est pas mignon\160?[ENTER]Et il a un odorat hors du commun. Un sp\233cialiste[ENTER]pour traquer les chaussettes\160![ENTER]Il restera 2 heures avec vous et vous aidera dans[ENTER]vos recherches. Il sera ensuite fatigu\233 et devra[ENTER]se reposer 24 heures.[ENTER]Si vous ne voulez pas attendre aussi longtemps,[ENTER]cliquez sur cette pi\232ce qui tourne, en bas \224[ENTER]gauche \150 j'ai entendu dire que vous y trouverez[ENTER]un autre faon. Mais naturellement, je serai ravi[ENTER]de vous revoir demain\160! "
gameforge.new_christmas_sock._050_npcChat = "Je vous apporte des chaussettes\160! "
gameforge.new_christmas_sock._060_say = "Apportez-moi au moins 5 chaussettes et je vous[ENTER]donnerai une r\233compense.[ENTER]Argh, cette odeur de vieille chaussette est[ENTER]insupportable\160! Revenez quand vous en aurez[ENTER]rassembl\233 assez. Joyeux No\235l\160! "
gameforge.new_christmas_sock._070_say = "Oh oh oh\160! vous avez rassembl\233 suffisamment de[ENTER]chaussettes.[ENTER]Alors, voyons voir.[ENTER]Beurk, quelle odeur\133 Pas de doute, ce sont les[ENTER]bonnes chaussettes\160![ENTER]Joyeux No\235l\160! "
gameforge.new_christmas_sock._080_npcChat = "Faon "
gameforge.new_christmas_sock._090_say = "Je vous ai d\233j\224 donn\233 un sceau du faon[ENTER]aujourd'hui. Cette pauvre b\234te doit maintenant se[ENTER]reposer jusqu'\224 demain. Si vous ne voulez pas[ENTER]attendre aussi longtemps, cliquez sur la pi\232ce[ENTER]tournante en bas \224 gauche \150 j'ai entendu dire que[ENTER]vous y trouverez un autre faon. Mais[ENTER]naturellement, je serai ravi de vous revoir[ENTER]demain ! "
gameforge.new_christmas_sock._100_say = "Vous m'avez d\233j\224 apport\233 vos chaussettes[ENTER]aujourd'hui. N'oubliez pas que vous ne pouvez[ENTER]m'en donner qu'une fois toutes les 24 heures. "
gameforge.new_quest_lv17 = {}
gameforge.new_quest_lv17._010_target = "Wonda-Rim "
gameforge.new_quest_lv17._012_say_title = "Wonda-Rim: "
gameforge.new_quest_lv17._020_say_title = "Le cadeau pour Chaegirab "
gameforge.new_quest_lv17._021_say = "Mon oncle Chaegirab a vou\233 sa vie \224 la science et[ENTER]d\233pense tout son argent dans ses recherches.[ENTER]Il a toujours \233t\233 gentil avec moi donc j'aimerais[ENTER]lui faire un cadeau. Pourriez-vous aller voir[ENTER]Uriel et lui demander s'il a une id\233e? C'est le[ENTER]mentor et l'ancien professeur de mon oncle et il[ENTER]le conna\238t tr\232s bien. "
gameforge.new_quest_lv17._030_say = "Mais ne dites rien \224 mon oncle ! "
gameforge.new_quest_lv17._031_say = "Pourriez-vous m'aider\160? "
gameforge.new_quest_lv17._039_say_title = "Uriel: "
gameforge.new_quest_lv17._040_say_title = "Parlez avec Uriel "
gameforge.new_quest_lv17._040_target = "Uriel "
gameforge.new_quest_lv17._041_say = "Parlez avec Uriel de Chaegirab, son ancien \233l\232ve. "
gameforge.new_quest_lv17._042_say = "Uriel se trouve \224 %s. "
gameforge.new_quest_lv17._050_say_title = "Wonda-Rim veut faire un cadeau \224 Chaegirab... "
gameforge.new_quest_lv17._051_say = "Le plaisir d'un scientifique commence par la[ENTER]recherche. C'est aussi simple que cela. La[ENTER]meilleure fa\231on de faire plaisir \224 Chaegirab est[ENTER]de l'aider dans ses recherches. Le loup Mu-Rang[ENTER]se fait rare dans notre r\233gion, et sa fourrure[ENTER]est un plaisir tout aussi rare pour n'importe[ENTER]quel biologiste. 5 fourrures de loup devraient[ENTER]suffire. Allez dire ceci \224 Wonda-Rim. "
gameforge.new_quest_lv17._052_say = "Je suis s\251r que le biologiste sera impressionn\233[ENTER]par une si belle fourrure. "
gameforge.new_quest_lv17._060_select = "Oui, je vais lui dire. "
gameforge.new_quest_lv17._065_say_title = "Retourner voir Wonda-Rim "
gameforge.new_quest_lv17._066_say = "Uriel a une super id\233e de cadeau pour Chaegirab.[ENTER]Retournez voir Wonda-Rim pour le lui dire. "
gameforge.new_quest_lv17._067_say = "Wonda-Rim est \224 %s. "
gameforge.new_quest_lv17._070_say = "Uriel est de bon conseil. Je veux vraiment faire[ENTER]un beau cadeau \224 mon oncle, il me faut cette[ENTER]fourrure. Pourriez-vous aller chasser 5 Mu-Rangs[ENTER]et me ramener leurs fourrures ? "
gameforge.new_quest_lv17._071_say = "Il faut que je tue des Loups Mu-Rang pour[ENTER]r\233cup\233rer leur fourrure. "
gameforge.new_quest_lv17._072_say = "5 suffiront pour lui faire un beau cadeau. "
gameforge.new_quest_lv17._073_say = "Allons-y ! "
gameforge.new_quest_lv17._074_notice = "Vous avez trouv\233 une fourrure en bon \233tat. "
gameforge.new_quest_lv17._075_say = "Chassez des loups Mu-Rang et r\233cup\233rez leur[ENTER]fourrure. "
gameforge.new_quest_lv17._076_say_reward = "Vous avez d\233j\224 r\233cup\233r\233 %s fourrure(s) sur les 5. "
gameforge.new_quest_lv17._081_say_title = "Fourrure pour Wonda-Rim "
gameforge.new_quest_lv17._082_say = "Vous avez trouv\233 assez de fourrures, ramenez les[ENTER]\224 Wonda-Rim. "
gameforge.new_quest_lv17._092_say_reward = "Vous avez d\233j\224 trouv\233 %s fourrure(s) de loup. "
gameforge.new_quest_lv17._110_say = "Cette fourrure est vraiment magnifique, merci[ENTER]beaucoup. Pouvez-vous l'apporter \224 mon oncle ? "
gameforge.new_quest_lv17._120_target = "Oncle Chaegirab "
gameforge.new_quest_lv17._121_say = "Wonda-Rim vous a demand\233 d'apporter la fourrure[ENTER]de Mu-Rang \224 Chaegirab. "
gameforge.new_quest_lv17._122_say = "Chaegirab est \224 %s. "
gameforge.new_quest_lv17._130_say = "Ah ah ! Il s'y prend donc de cette fa\231on[ENTER]maintenant. "
gameforge.new_quest_lv17._131_say = "De qui tenez-vous cette fourrure ? De Wonda-Rim ?[ENTER]Mais c'est vous qui avez tu\233 les loups pour lui ?[ENTER]J'ai honte d'avoir un neveu qui fait travailler[ENTER]les autres \224 sa place. Je ne peux pas accepter[ENTER]cette fourrure, m\234me si je suis g\234n\233 que vous[ENTER]ayez donn\233 tant d'efforts pour rien. "
gameforge.new_quest_lv17._132_say_reward = "Dites \224 Wonda-Rim que j'ai vu clair dans son[ENTER]jeu\160! S'il veut vraiment me faire plaisir, il[ENTER]faudrait qu'il aille lui-m\234me \224 la chasse. "
gameforge.new_quest_lv17._140_say = "Chaegirab n'a pas voulu de la fourrure et est[ENTER]tr\232s en col\232re contre Wonda-Rim qui est bien[ENTER]paresseux. Il vous renvoie voir Wonda-Rim. "
gameforge.new_quest_lv17._141_say = "Qu'est ce que mon oncle a dit ? J'esp\232re qu'il a[ENTER]aim\233 mon cadeau ? "
gameforge.new_quest_lv17._142_1_select = "Oui, il \233tait ravi. "
gameforge.new_quest_lv17._142_2_select = "Non, pas du tout. "
gameforge.new_quest_lv17._143_say = "Super ! J'aime faire plaisir aux autres. Et bien[ENTER]s\251r vous aurez droit \224 une jolie r\233compense.[ENTER]Tenez, prenez ceci ! "
gameforge.new_quest_lv17._144_say_reward_a = "Vous recevez 20.000 points d'exp\233rience.[ENTER]Vous recevez 20.000 Yangs.[ENTER]Vous recevez une p\233pite d'or. "
gameforge.new_quest_lv17._144_say_reward_b = "Vous avez menti \224 Wonda-Rim et vous en perdez des[ENTER]points de grade. "
gameforge.new_quest_lv17._145_say = "Il n'a pas voulu acheter la fourrure ? Hum,[ENTER]peut-\234tre que ce n'\233tait pas une si bonne id\233e de[ENTER]vous envoyer chasser \224 ma place. Je m'y prendrai[ENTER]autrement la prochaine fois. "
gameforge.new_quest_lv17._146_say_reward = "Mais vous n'avez pas fait tout ce travail pour[ENTER]rien, Yang-Shin vous rach\232tera cette fourrure \224[ENTER]un bon prix. "
gameforge.new_quest_lv17._147_say = "Les \233v\232nements ont pris une tournure bien[ENTER]d\233cevante. Heureusement, vous avez toujours la[ENTER]fourrure avec vous. Allez voir Yang-Shin le[ENTER]chasseur \224 Jayan et vendez-lui la fourrure. "
gameforge.new_quest_lv17._148_say = "Les \233v\232nements ont pris une tournure bien[ENTER]d\233cevante. Heureusement, vous avez toujours la[ENTER]fourrure avec vous. Allez voir Yang-Shin le[ENTER]chasseur \224 Bokjung et vendez-lui la fourrure. "
gameforge.new_quest_lv17._149_say = "Les \233v\232nements ont pris une tournure bien[ENTER]d\233cevante. Heureusement, vous avez toujours la[ENTER]fourrure avec vous. Allez voir Yang-Shin le[ENTER]chasseur \224 Bakra et vendez-lui la fourrure. "
gameforge.new_quest_lv17._151_say = "Des fourrures de Mu-Rang ? Elles vont m'\234tre[ENTER]vraiment utiles. Je vais m'en faire une nouvelle[ENTER]tenue. Tenez, prenez ces quelques yangs pour vous[ENTER]r\233compenser. Oh, j'ai trouv\233 ce livre aussi hier,[ENTER]prenez-le vous lui trouverez peut-\234tre une[ENTER]utilit\233.. "
gameforge.new_quest_lv17._152_say_reward = "Vous avez re\231u 40.000 points d'exp\233rience.[ENTER]Vous avez re\231u 10.000 yangs.[ENTER]Vous avez re\231u un livre de comp\233tence. "
