gameforge.new_quest_lv22._018_say_title = "Baek-Go: "
gameforge.new_quest_lv22._019_say_title = "Le Garde de la Tour des d\233mons\160: "
gameforge.new_quest_lv22._021_say = "Je m'inqui\232te pour mon fr\232re, le Garde de la Tour[ENTER]des d\233mons. Il ne se sentait pas bien r\233cemment[ENTER]et \224 pr\233sent il est vraiment malade. Il a une[ENTER]grosse migraine et d'\233tranges \233ruptions cutan\233es,[ENTER]mais il ne peut quitter son poste. Pourriez-vous[ENTER]lui apporter un m\233dicament de Baek-Go ? "
gameforge.new_quest_lv22._022_say = "Je l'aurais bien fait moi-m\234me, mais la Tour des[ENTER]d\233mons se trouve dans le temple de Hwang, en[ENTER]plein milieu de la Vall\233e de Seungryong. Et[ENTER]l'endroit est compl\232tement envahi par de[ENTER]dangereuses cr\233atures... "
gameforge.new_quest_lv22._023_say = "Vous revoil\224. Vous avez oubli\233 les sympt\244mes ?[ENTER]Vous pourriez \233couter quand quelqu'un vous parle.[ENTER]Mon fr\232re a une migraine et une \233ruption cutan\233e.[ENTER]Allez le dire \224 Baek-Go ! "
gameforge.new_quest_lv22._024_select = "Aider le fr\232re "
gameforge.new_quest_lv22._025_say_title = "Le m\233dicament de Baek-Go "
gameforge.new_quest_lv22._026_say = "Parlez \224 Baek-Go pour qu'il trouve un rem\232de pour[ENTER]gu\233rir le Garde de la Tour des d\233mons. "
gameforge.new_quest_lv22._027_say = "Baek-Go est \224 %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go "
gameforge.new_quest_lv22._031_say = "Donc vous avez besoin d'un rem\232de ? Il est[ENTER]dangereux de donner un rem\232de sans vraiment[ENTER]savoir s'il c'est le bon. Donnez-moi les[ENTER]sympt\244mes. "
gameforge.new_quest_lv22._032_1_select = "Migraine et \233ruptions "
gameforge.new_quest_lv22._032_2_select = "Mal de gorge et crampes "
gameforge.new_quest_lv22._032_3_select = "Je ne sais pas. "
gameforge.new_quest_lv22._035_say = "C'est comme si j'\233tais lac\233r\233 par un D\233mon.[ENTER]Cela arrive le plus souvent lorsque les b\234tes[ENTER]sont infect\233es par les mites. Je peux pr\233parer[ENTER]quelque chose pour l'aider. Vous allez devoir[ENTER]trouver quelques ingr\233dients pour cela. "
gameforge.new_quest_lv22._040_say = "J'ai besoin de: "
gameforge.new_quest_lv22._041_say_reward = "Vous devez chasser: "
gameforge.new_quest_lv22._042_say = "J'ai aussi besoin de : "
gameforge.new_quest_lv22._043_say = "Je n'ai jamais entendu parler d'une telle[ENTER]maladie. \202tes-vous s\251r des sympt\244mes que vous me[ENTER]rapportez ? SI j'\233tais vous, j'irais \224 nouveau[ENTER]demander. "
gameforge.new_quest_lv22._044_say = "Je ne peux faire de diagnostique sans les[ENTER]sympt\244mes. Retournez demander. "
gameforge.new_quest_lv22._050_set_title = "M\233dicament "
gameforge.new_quest_lv22._056_notice = "Bien, il ne me manque plus que %s herbes. "
gameforge.new_quest_lv22._057_notice = "C'est toutes les herbes dont j'ai besoin. Allez[ENTER]vite voir Baek-Go. "
gameforge.new_quest_lv22._058_notice = "Bien, il ne manque plus que %s foies. "
gameforge.new_quest_lv22._060_notice = "Ah, du foie. Il ne m'en manque que %s. "
gameforge.new_quest_lv22._061_notice = "C'est tout le foie dont j'ai besoin. Allez vite[ENTER]voir Baek-Go. "
gameforge.new_quest_lv22._062_notice = "Malheureusement ce foie ne peut me servir. "
gameforge.new_quest_lv22._063_say = "Vous avez encore besoin de %s Herbes. "
gameforge.new_quest_lv22._064_say = "Vous avez encore besoin de %s foie(s) de tigre. "
gameforge.new_quest_lv22._065_say = "Maintenant vous avez tous les ingr\233dients pour[ENTER]pr\233parer un rem\232de. Allez voir Baek-Go. "
gameforge.new_quest_lv22._066_say = "Ingr\233dients trouv\233s pour le rem\232de de Baek-Go: "
gameforge.new_quest_lv22._070_say = "Merci, \224 pr\233sent je peux pr\233parer un m\233dicament. "
gameforge.new_quest_lv22._071_say = "Termin\233 ! Voici le m\233dicament. Il ne se garde que[ENTER]peu de temps en raison de ses ingr\233dients - vous[ENTER]n'avez que %s minutes pour l'apporter au patient. "
gameforge.new_quest_lv22._072_say = "Vous pouvez trouver le fr\232re du gardien au centre[ENTER]du Temple Hwang. Mais faites attention sur la[ENTER]route, la Vall\233e de Seungryong est peupl\233e de[ENTER]dangereuses cr\233atures ! "
gameforge.new_quest_lv22._073_say = "Ce n'est pas suffisant. Avez-vous perdu des[ENTER]ingr\233dients en route ? Je ne peux rien faire si[ENTER]je n'ai pas tout. "
gameforge.new_quest_lv22._080_target = "Garde de la Tour des d\233mons "
gameforge.new_quest_lv22._082_set_clock = "Temps restant "
gameforge.new_quest_lv22._083_say = "Bien vous \234tes dans les temps encore, mais il[ENTER]faut tout de m\234me vous d\233p\234cher un peu. Allez[ENTER]vite rejoindre le Garde de la Tour des d\233mons, ou[ENTER]bien le rem\232de sera inutilisable ! "
gameforge.new_quest_lv22._084_say = "Le temps est \233coul\233, vous avez \233t\233 trop lent.[ENTER]Apportez quand m\234me le rem\232de au garde de la Tour[ENTER]des d\233mons, on ne sait jamais. "
gameforge.new_quest_lv22._085_say = "Merci de m'avoir apport\233 ce m\233dicament. Ces[ENTER]d\233mangeaisons sont en train de me tuer. "
gameforge.new_quest_lv22._086_say = "Oh, mais \231a fonctionne bien. Je sens d\233j\224 que \231a[ENTER]me d\233mange moins. "
gameforge.new_quest_lv22._087_say = "Vous allez recevoir une r\233compense sp\233ciale pour[ENTER]avoir fait cela ! "
gameforge.new_quest_lv22._088_say_reward = "Vous avez re\231u 50.000 points d'exp\233rience.[ENTER]Vous avez re\231u 12.000 yangs.[ENTER]Vous avez re\231u des chaussures de fil d'or +4.[ENTER]Vous avez re\231u 5 potions violettes. "
gameforge.new_quest_lv22._089_say = "Oh, quel go\251t infecte. Le m\233dicament ne fait plus[ENTER]effet - depuis combien de temps le trainez-vous ?[ENTER]J'ai l'impression d'avoir des excr\233ments de singe[ENTER]dans la bouche. "
gameforge.new_quest_lv22._090_say = "Hum, attendez une seconde... \231a semble faire[ENTER]effet l\224 ... Oui, \231a fonctionne ! Je vais quand[ENTER]m\234me aller mieux. Vous aurez quand m\234me votre[ENTER]r\233compense apr\232s tout. "
gameforge.new_quest_lv22._091_say = "Vous semblez avoir perdu le rem\232de. S'il vous[ENTER]plait retournez chasser et trouvez \224 nouveau les[ENTER]ingr\233dients dont Baek-Go a besoin. Je vais finir[ENTER]par devenir moi-m\234me un D\233mon si ces[ENTER]d\233mangeaisons ne s'arr\234tent pas. "
gameforge.new_quest_lv22._095_say_reward = "Vous avez re\231u 50.000 points d'exp\233rience.[ENTER]Vous avez re\231u 8.000 yangs. "
gameforge.new_quest_lv22._098_say = "Vous avez de nouveau perdu les m\233dicaments\160?[ENTER]Quelle t\234te en l'air\160![ENTER]Bon, c'est comme \231a, on ne peut rien y faire... "
gameforge.new_quest_lv22._100_say_reward = "Vous recevez 25.000 points d'exp\233rience. "
gameforge.new_quest_lv26 = {}
gameforge.new_quest_lv26._010_target = "Yang-Shin "
gameforge.new_quest_lv26._020_say_title = "Yang-Shin: "
gameforge.new_quest_lv26._020_set_title = "Le d\233serteur "
gameforge.new_quest_lv26._021_say = "Yang-Shin a du mal \224 trouver de bons coins pour[ENTER]chasser. Allez le voir et voyez comment vous[ENTER]pouvez l'aider. "
gameforge.new_quest_lv26._025_say = "De toutes fa\231ons tout a commenc\233 lorsque les[ENTER]Pierres Metins sont tomb\233es. Depuis ce jour,[ENTER]chasser est devenu impossible un peu partout,[ENTER]parce que les animaux sauvages se comportent[ENTER]comme s'ils avaient la rage. Le vagabond Nakajima[ENTER]vit quelque part l\224-bas, je suis s\251r qu'il[ENTER]conna\238t un bon endroit o\249 chasser.[ENTER]Pouvez-vous allez lui demander ? "
gameforge.new_quest_lv26._030_target = "Nakajima "
gameforge.new_quest_lv26._031_say = "Vous voulez donc conna\238tre un bon endroit o\249[ENTER]chasser ? Ne vous pr\233cipitez pas, puisque je suis[ENTER]suppos\233 vous aider, vous allez devoir faire[ENTER]quelque chose pour moi aussi. "
gameforge.new_quest_lv26._032_say = "Vous devriez savoir ... Je ne vis pas ici[ENTER]volontairement. Je dois me cacher car je fuis les[ENTER]atrocit\233s de la guerre. J'esp\232re seulement que ma[ENTER]femme bien-aim\233e Ah-Yu sait que je suis toujours[ENTER]en vie. Pouvez-vous le lui dire ? Mais[ENTER]souvenez-vous, seule elle doit \234tre au courant.[ENTER]En retour, elle vous dira \224 quel endroit nous[ENTER]nous sommes embrass\233s pour la premi\232re fois - je[ENTER]veux la revoir l\224-bas, c'est d'ailleurs un tr\232s[ENTER]bon endroit pour chasser. "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Cherchez Nakajima "
gameforge.new_quest_lv26._037_say = "Nakajima doit savoir o\249 l'on peut trouver de bons[ENTER]endroits pour chasser. Allez lui demander. "
gameforge.new_quest_lv26._038_say = "Nakajima est \224 %s. "
gameforge.new_quest_lv26._040_say = "\202tes-vous Nakajima\160? C'est Yank-Shin qui[ENTER]m'envoie\160! Il cherche de bons coins pour chasser,[ENTER]peut-\234tre connaissez-vous un lieu ou chasser ne[ENTER]sera pas trop dangereux\160? "
gameforge.new_quest_lv26._050_target = "Ah-Yu "
gameforge.new_quest_lv26._051_say = "Nakajima est un d\233serteur et doit se cacher de[ENTER]l'arm\233e. Sa femme Ah-Yu pense qu'il est mort au[ENTER]combat. Allez lui annoncer que Nakajima est[ENTER]toujours en vie. "
gameforge.new_quest_lv26._052_say = "Ah-Yu est \224 %s. "
gameforge.new_quest_lv26._057_say = "Nakajima ... est en vie ??? Mon cher mari est en[ENTER]vie ? Je ne vous remercierais jamais assez de me[ENTER]l'avoir annonc\233 ! Il parlait de la Vall\233e de[ENTER]Yonjang. Je pars de suite l\224-bas pour l'y[ENTER]retrouver. "
gameforge.new_quest_lv26._058_say = "Merci d'avoir permis cette rencontre. Prenez[ENTER]cette Rose avec vous, offrez-la \224 quelqu'un que[ENTER]vous aimez peut-\234tre ? \192 pr\233sent excusez-moi,[ENTER]mais je dois me d\233p\234cher ! "
gameforge.new_quest_lv26._061_say = "La Vall\233e de Yonjang - lieu o\249 Nakajima et Ah-Yu[ENTER]se sont embrass\233s pour la premi\232re fois - est[ENTER]toujours un lieu de chasse id\233al. "
gameforge.new_quest_lv26._062_say = "Yang-Shin sera content d'entendre ceci. Allez \224[ENTER]%s et transmettez lui l'information. "
gameforge.new_quest_lv26._063_say = "La Vall\233e de Yonjang ? C'est tout \224 fait[ENTER]possible, je n'ai jamais entendu parler de[ENTER]Pierres Metins contaminant l'endroit. Je pense[ENTER]que je vais pouvoir m'enrichir l\224-bas ! Tenez,[ENTER]voici votre r\233compense. "
gameforge.new_quest_lv26._064_sayReward = "Vous avez re\231u 35.000 points d'exp\233rience. "
gameforge.new_quest_lv26._065_sayReward = "Vous avez re\231u 17.500 yangs. "
gameforge.new_quest_lv28 = {}
gameforge.new_quest_lv28._010_target = "Yu-Hwan "
gameforge.new_quest_lv28._011_say = "Yu-Hwan le musicien a besoin de votre aide. Allez[ENTER]vite le voir pour savoir ce qu'il veut ! "
gameforge.new_quest_lv28._015_npcChat = "Les soucis de Ah-Yu "
gameforge.new_quest_lv28._016_say = "Ah-Yu semble avoir quelque chose sur le coeur[ENTER]qu'elle n'ose annoncer \224 Yu-Hwan. Rendez-lui une[ENTER]petite visite et tentez de la faire parler. "
gameforge.new_quest_lv28._017_say = "Ah-Yu est \224 %s. "
gameforge.new_quest_lv28._018_select = "Je vais tout de suite parler \224 Ah-Yu\160! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "Vous connaissez Ah-Yu ? Elle r\233cup\232re des herbes[ENTER]pour mes potions. D'habitude elle est de bonne[ENTER]humeur, mais hier elle semblait presque d\233vast\233e.[ENTER]Elle n'a pas voulu me dire ce qui la tracassait,[ENTER]mais peut-\234tre est-ce parce qu'elle travaille[ENTER]pour moi ? S'il vous plait allez la voir et[ENTER]trouvez ce qui la tracasse. Elle se confiera[ENTER]peut-\234tre ! "
gameforge.new_quest_lv28._022_say = "C'est tr\232s gentil \224 Yu-Hwan de s'inqui\233ter pour[ENTER]moi. Oui en effet, quelque chose me tracasse ...[ENTER]Je ne voulais pas en parler, mais \231a me torture[ENTER]depuis si longtemps ! C'est \224 propos de[ENTER]yang-Shin, le chasseur. Il me fait chanter depuis[ENTER]qu'il sait que mon mari Nakajima est un[ENTER]d\233serteur. Yang-Shin menace de le d\233noncer ! Et[ENTER]apr\232s, ils le tueront ... "
gameforge.new_quest_lv28._023_say = "Cette fois il me demande une Patte d'Ours en[ENTER]\233change de son silence. Mais je ne peux sortir[ENTER]chasser. Pouvez-vous m'aider et apporter \224[ENTER]Yang-Shin ce qu'il demande ? "
gameforge.new_quest_lv28._024_set_title = "Tuer des ours "
gameforge.new_quest_lv28._025_notice = "Allons chasser ! Tuer Bera est la meilleure fa\231on[ENTER]pour obtenir une Patte d'Ours. "
gameforge.new_quest_lv28._026_notice = "J'ai trouv\233 une Patte d'Ours ! "
gameforge.new_quest_lv28._027_notice = "Cela devrait suffire. Allez voir Yang-Shin ! "
gameforge.new_quest_lv28._028_notice = "Cette Patte d'Ours est inutilisable. "
gameforge.new_quest_lv28._029_say = "Vous avez besoin d'encore %s Pattes d'Ours. "
gameforge.new_quest_lv28._031_say_reward = "Vous devez chasser: "
gameforge.new_quest_lv28._032_say = "Ah-Yu vous a demand\233 de satisfaire la demande de[ENTER]Yang-Shin. "
gameforge.new_quest_lv28._032_say_reward = "Vous avez encore besoin de %s Pattes d'ours.[ENTER]Tuez Bera pour en trouver. "
gameforge.new_quest_lv28._035_target = "Yang-Shin "
gameforge.new_quest_lv28._036_say = "Vous avez trouv\233 assez de Pattes d'Ours.[ENTER]Apportez-les \224 Yang-Shin pour payer la dette[ENTER]d'Ah-Yu. "
gameforge.new_quest_lv28._037_say = "Yang-Shin est \224 %s. "
gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "Le chantage "
gameforge.new_quest_lv28._041_say_title = "Pattes d'Ours "
gameforge.new_quest_lv28._042_say = "Vous m'avez apport\233 des pattes d'Ours ? Je vous[ENTER]en supplie ne me prenez pas pour un monstre ! Les[ENTER]temps sont durs et je dois joindre les deux[ENTER]bouts, surtout depuis la chute des Pierres Metins[ENTER]qui rendent la chasse si difficile \224 cause des[ENTER]animaux se comportant comme des b\234tes enrag\233es.[ENTER]La vie de Chasseur n'a jamais \233t\233 aussi difficile. "
gameforge.new_quest_lv28._043_say = "S'il vous plait dites \224 Ah-Yu qu'elle n'a pas de[ENTER]soucis \224 se faire. Elle peut en \234tre s\251re.[ENTER]Jusqu'\224 ce que j'ai besoin de quelque chose[ENTER]d'autre ... h\233 h\233 h\233 ! "
gameforge.new_quest_lv28._044_say = "Quoi, vous voulez vous d\233barrasser de moi sans[ENTER]rien ? Je voulais des Pattes d'Ours fra\238ches ! "
gameforge.new_quest_lv28._045_say_reward = "C'est gentil \224 vous d'aider Ah-Yu. Mais cela[ENTER]signifie que vous devez faire ce qu'elle vous a[ENTER]demand\233. Allez chasser maintenant et ne revenez[ENTER]que lorsque vous aurez deux Pattes d'Ours ! "
gameforge.new_quest_lv28._046_say = "Dites \224 Ah-Yu que le chasseur Yang-Shin va cesser[ENTER]de lui faire du chantage parce que vous l'avez[ENTER]aid\233. "
gameforge.new_quest_lv28._051_say = "Vous \234tes notre sauveur ! Je vous en serai[ENTER]\233ternellement reconnaissante. Tenez, prenez tous[ENTER]mes yangs ! Ce n'est pas \233norme, mais vous les[ENTER]m\233ritez. "
gameforge.new_quest_lv28._055_1_select = "Merci, \231a va m'\234tre bien utile ! "
gameforge.new_quest_lv28._055_2_select = "Non, je ne peux accepter. "
gameforge.new_quest_lv28._056_say = "C'est tout ce que j'ai. Mais \231a en vaut la peine[ENTER]si je peux me d\233barrasser de ce barbare assassin. "
gameforge.new_quest_lv28._057_say = "Oh, merci ! Votre place aux c\244t\233s du Dieu Dragon[ENTER]est assur\233e ! "
gameforge.new_quest_lv28._058_say_reward = "Vous avez re\231u %s yangs. "
gameforge.new_quest_lv28._059_say_reward = "Vous avez re\231u %s points d'exp\233rience. "
gameforge.new_quest_lv28._070_say = "J'ai besoin de: "
gameforge.new_quest_lv29 = {}
gameforge.new_quest_lv29._010_target = "Yonah "
gameforge.new_quest_lv29._015_npcChat = "La porcelaine bris\233e "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "Ma porcelaine Celadon tant aim\233e ! Elle est dans[ENTER]la famille depuis 3 g\233n\233rations et \224 pr\233sent 3[ENTER]des pr\233cieux vases sont bris\233s. J'ai vu que ce[ENTER]bon \224 rien deTaurean tra\238nait non loin de[ENTER]l'entrep\244t tout \224 l'heure. Je suis s\251r qu'il est[ENTER]responsable ! "
gameforge.new_quest_lv29._022_say = "Ce ne serait pas la premi\232re chose idiote qu'il[ENTER]aurait faite, mais l\224 ca serait la goutte d'eau[ENTER]qui ferait d\233border le vase. Quelqu'un devrait[ENTER]lui donner une le\231on ! Avez-vous le temps de vous[ENTER]en charger ? "
gameforge.new_quest_lv29._023_1_select = "Avec plaisir "
gameforge.new_quest_lv29._023_2_select = "Ce n'est pas mon probl\232me "
gameforge.new_quest_lv29._024_say = "Je n'ai pas le temps d'\233duquer les enfants mal[ENTER]\233lev\233s. Vous devrez vous en charger vous-m\234me.[ENTER]Cependant, je doute que vous y parveniez. .. "
gameforge.new_quest_lv29._030_target = "Taurean "
gameforge.new_quest_lv29._031_say = "Les h\233ritages familiaux pr\233cieux de Yonah, trois[ENTER]vases fabriqu\233s \224 partir de porcelaine c\233ladon,[ENTER]sont tous bris\233s. Il pense que Taurean est[ENTER]responsable. Allez voir Taurean afin de savoir si[ENTER]c'est lui. "
gameforge.new_quest_lv29._032_say = "Taurean est \224 %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "Pourquoi me regardez-vous comme cela ? Je n'ai[ENTER]rien fait ... "
gameforge.new_quest_lv29._035_say_reward = "Qu'avez-vous fait avec les vases de Yonah ? "
gameforge.new_quest_lv29._036_say_reward = "Vases ? Yonah ? Je ne vois pas de quoi vous[ENTER]parlez ! "
gameforge.new_quest_lv29._037_say_reward = "Alors expliquez-moi encore pourquoi trois d'entre[ENTER]eux sont cass\233s. "
gameforge.new_quest_lv29._038_say_reward = "Je jure que je ne me suis jamais trouv\233 pr\232s d'un[ENTER]vase et que je n'ai jamais vu Yonah. En fait, je[ENTER]passe la majorit\233 de mon temps \224 me bagarrer avec[ENTER]Harang. Elle m'a m\234me enferm\233 dans la grange[ENTER]pendant un moment ! Allez lui demander si vous ne[ENTER]me croyez pas ! "
gameforge.new_quest_lv29._040_target = "Harang "
gameforge.new_quest_lv29._041_say = "Taurean clame son innocence. Il a jou\233 avec[ENTER]Harang toute la journ\233e donc il n'a pas pu briser[ENTER]les vases. Allez demander \224 Harang si c'est la[ENTER]v\233rit\233. "
gameforge.new_quest_lv29._042_say_reward = "Harang, avez-vous vu Taurean aujourd'hui ? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taurean ? Oui, nous avons jou\233 ensemble toute la[ENTER]journ\233e. Quelque chose ne va pas ? "
gameforge.new_quest_lv29._045_say_reward = "Yonah dit que Taurean a bris\233 trois de ses vases. "
gameforge.new_quest_lv29._046_say_reward = "Yonah est un peu limite. Il en a apr\232s Taurean et[ENTER]moi-m\234me d\232s qu'on se trouve proches de lui. Il[ENTER]s'inqui\232te toujours tant pour sa porcelaine. La[ENTER]seule personne qui a le droit de toucher \224 ses[ENTER]pr\233cieux vases est son ami le Palefrenier.[ENTER]Peut-\234tre a t-il cass\233 les vases ? "
gameforge.new_quest_lv29._047_say = "Harang est \224 %s. "
gameforge.new_quest_lv29._050_target = "Palefrenier "
gameforge.new_quest_lv29._051_say = "Harang confirme que Taurean est innocent. Mais[ENTER]ils pourraient aussi \234tre de m\232che l'un avec[ENTER]l'autre. Avant de rendre votre verdict vous[ENTER]devriez parler au Palefrenier. "
gameforge.new_quest_lv29._052_say = "Oh, ce bon Yonah. Il est si inquiet pour sa[ENTER]porcelaine qu'il en vient \224 soup\231onner les[ENTER]enfants du village. Il ne se rend pas compte que[ENTER]ce sont les Pierres Metins les responsables -[ENTER]depuis qu'elles ont commenc\233 \224 empoisonner nos[ENTER]r\233gions, nos ressources ne sont plus les m\234mes.[ENTER]M\234me la porcelaine est devenue fragile. Mais[ENTER]Yonah refuse d'y croire... "
gameforge.new_quest_lv29._053_say = "Si vous lui ramenez du Foin, il pourrait[ENTER]\233ventuellement prot\233ger sa porcelaine dans leurs[ENTER]cartons de mani\232re plus s\251re. Je suis certain que[ENTER]\231a serait une bonne fa\231on de le rassurer. "
gameforge.new_quest_lv29._054_say = "Le palefrenier est \224[ENTER]%s ou \224 %s. "
gameforge.new_quest_lv29._061_say = "Taurean n'est pas responsable des vases bris\233s de[ENTER]Yonah. Ce sont les radiations diaboliques des[ENTER]Pierres metins qui cassent tout. Apportez du Foin[ENTER]\224 Yonah afin qu'il prot\232ge sa porcelaine de fa\231on[ENTER]plus s\251re. Je suis s\251re que certains villageois[ENTER]peuvent vous en donner. "
gameforge.new_quest_lv29._062_say = "Vous pouvez trouver %s et %s devant les portes du[ENTER]village Vous devriez pouvoir trouver suffisamment[ENTER]de Foin gr\226ce aux chapeaux de paille qu'ils[ENTER]portent. "
gameforge.new_quest_lv29._063_notice = "J'ai trouv\233 une bonne quantit\233 de Foin. Il ne[ENTER]m'en manque plus que %s. "
gameforge.new_quest_lv29._064_notice = "Ce chapeau n'est pas fait de paille, mais de[ENTER]fibres de noix de coco. Il m'est inutile. "
gameforge.new_quest_lv29._065_1_say = "Je vois que vous avez un chapeau de paille sur[ENTER]vous. Je suis s\251r que Yonah serait plus agr\233able[ENTER]si vous m'en donniez un peu. "
gameforge.new_quest_lv29._065_notice = "Ce chapeau n'est pas fait de paille, mais de[ENTER]fibres de noix de coco. Il est aussi tr\232s[ENTER]abim\233... "
gameforge.new_quest_lv29._066_say = "Vous pouvez aussi tuer des Soldats Barbares et[ENTER]des Forts Soldats Barbares. Vous pourrez[ENTER]r\233cup\233rer du foin sur leurs chapeaux de paille. "
gameforge.new_quest_lv29._067_say_reward = "Vous avez trouv\233 %s sur %s bottes de Foin. "
gameforge.new_quest_lv29._068_notice = "Vous avez trouv\233 une botte de Foin. "
gameforge.new_quest_lv29._070_npcChat = "La meule de foin "
gameforge.new_quest_lv29._071_say_reward = "Taurean, vous avez mentionn\233 avoir \233t\233 proche des[ENTER]meules de foin tout \224 l'heure. Avez-vous pris un[ENTER]peu de Foin avec vous ? "
gameforge.new_quest_lv29._072_say_reward = "Ah ah, voyons voir ... Tout \233tait dans mes[ENTER]cheveux et dans mes chaussures. Vous voyez ?[ENTER]Prenez le tout ! "
gameforge.new_quest_lv29._073_notice = "Ce n'est pas grand chose, mais cela devrait \234tre[ENTER]suffisant pour une petite botte. Il ne m'en[ENTER]manque plus que %s . "
gameforge.new_quest_lv29._074_say_reward = "Ce n'est pas moi, je le jure ! Harang ne vous a[ENTER]pas dit qu'on s'est m\234me battu dans le foin ? "
gameforge.new_quest_lv29._075_say_reward = "Vous \233tiez pr\232s du foin tout \224 l'heure n'est-ce[ENTER]pas ? Avez-vous pens\233 \224 prendre un peu de Foin[ENTER]avec vous ? "
gameforge.new_quest_lv29._076_say_reward = "Comment savez-vous pour le foin ? Quoi, j'ai[ENTER]encore du foin sur mes v\234tements ? Ah oui il y en[ENTER]a ! "
gameforge.new_quest_lv29._077_say_reward = "Puis-je l'avoir ? "
gameforge.new_quest_lv29._078_say_reward = "Je suppose donc ... "
gameforge.new_quest_lv29._079_say_reward = "Je n'ai pas le temps l\224. Je dois aller calmer[ENTER]Taurean \224 propos de cette histoire de vases. "
gameforge.new_quest_lv29._080_npcChat = "Du Foin pour Yonah "
gameforge.new_quest_lv29._081_say_reward = "Y a-t-il encore un peu de foin dans la grange que[ENTER]je pourrait apporter \224 Yonah? "
gameforge.new_quest_lv29._082_say_title = "Le palefrenier: "
gameforge.new_quest_lv29._083_say_reward = "Nous n'avons pas beaucoup de Foin. Les animaux[ENTER]sauvages et les bandits \224 l'ext\233rieur du village[ENTER]nous ont emp\234ch\233s d'en prendre plus. "
gameforge.new_quest_lv29._084_say_reward = "Mais je peux vous en donner un peu ! "
gameforge.new_quest_lv29._085_notice = "Ce n'est vraiment pas beaucoup, mais c'est assez[ENTER]pour une botte. Il ne m'en manque plus que %s . "
gameforge.new_quest_lv29._086_say_reward = "J'ai bien peur de ne rien pouvoir faire de plus[ENTER]pour vous. "
gameforge.new_quest_lv29._090_send_letter = "Du Foin et non des Coups "
gameforge.new_quest_lv29._091_say = "Vous avez trouv\233 assez de Foin pour Yonah.[ENTER]Apportez-lui les %s. "
gameforge.new_quest_lv29._101_say_reward = "Ce n'est pas la faute de Taurean. Les radiations[ENTER]des Pierres Metins ont bris\233 votre porcelaine. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "Que dites-vous ? Mais \231a n'a pas de sens, ce bon[ENTER]\224 rien vous a menti ! "
gameforge.new_quest_lv29._104_say_reward = "Taurean a jou\233 avec Harang dans le foin toute la[ENTER]journ\233e. "
gameforge.new_quest_lv29._105_say_reward = "Je vous transmets les amiti\233s du Palefrenier et[ENTER]vous ai apport\233 du Foin pour prot\233ger vos vases. "
gameforge.new_quest_lv29._106_say_reward = "Je l'admets, je suis un peu g\234n\233 de ma r\233action.[ENTER]Mais vous savez bien que je tiens beaucoup \224 ma[ENTER]porcelaine car elle rappelle tant de souvenirs \224[ENTER]ma famille. Quand un vase se brise, c'est bien[ENTER]plus qu'un objet perdu pour moi ... "
gameforge.new_quest_lv29._107_say_reward = "Je dois m'excuser aupr\232s de vous et de Taurean.[ENTER]Voici une petite r\233compense pour vos efforts. "
gameforge.new_quest_lv29._108_notice = "Vous avez re\231u %s points d'exp\233rience. "
gameforge.new_quest_lv29._109_say_reward = "Je vous transmets les amiti\233s du Palefrenier et[ENTER]vous ai apport\233 du Foin pour prot\233ger vos vases. "
gameforge.new_quest_lv29._110_say_reward = "C'est vraiment aimable \224 vous. Mais pouvez-vous[ENTER]m'en apporter encore %s afin que mes vases soient[ENTER]vraiment bien prot\233g\233s ? "
gameforge.new_quest_lv29._111_say_reward = "Je pense que c'est difficile de trouver du Foin.[ENTER]Mais mes vases si pr\233cieux pour moi. Si vous m'en[ENTER]apportiez d'autres je vous en serai \233ternellement[ENTER]reconnaissant et vous donnerai quelques yangs. "
gameforge.new_quest_lv29._112_say_reward = "Ce morveux de Harang est \233videmment de m\232che avec[ENTER]Taurean. "
gameforge.new_quest_lv29._113_say_reward = "Apparemment personne ne me croit quand je dis que[ENTER]j'ai vu le gar\231on tra\238ner pr\232s de l'entrep\244t tout[ENTER]\224 l'heure. "
gameforge.new_quest_lv29._114_say_reward = "C'est bon. Voici une compensation pour vos[ENTER]efforts. "
gameforge.new_quest_lv29._115_say_reward = "Tenez, %s Yangs. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "Grouic Grouic "
gameforge.new_quest_lv42._020_target = "Octavio "
gameforge.new_quest_lv42._021_say = "Mon estomac grogne comme un ours sauvage.[ENTER]Peut-\234tre devrais-je passer chez Octavio. Il fait[ENTER]le meilleur ragout de fruits de mer du coin. "
gameforge.new_quest_lv42._022_say_title = "Octavio: "
gameforge.new_quest_lv42._023_say = "Vous voulez un rago\251t de fruits de mer ? Celui[ENTER]avec toutes les vari\233t\233s dedans ? Oh, je suis[ENTER]d\233sol\233, ma cuisine n'a pas vu de poisson depuis[ENTER]des jours. D'habitude le p\234cheur me livre un[ENTER]fantastique poisson de haute mer pour mon rago\251t. "
gameforge.new_quest_lv42._024_say = "Je ne l'ai pas vu dans le coin depuis des jours.[ENTER]Peut-\234tre pourriez-vous aller voir ce qui lui[ENTER]arrive ? "
gameforge.new_quest_lv42._025_say = "Octavio est \224 %s. "
gameforge.new_quest_lv42._026_select = "Je vais chercher le p\234cheur\160! "
gameforge.new_quest_lv42._030_target = "Le P\234cheur "
gameforge.new_quest_lv42._031_say = "C'est termin\233 la mer calme et apaisante ! Chaque[ENTER]jour de nouveaux p\234cheurs disparaissent, c'est[ENTER]terrible ! Depuis que les Pierres Metins sont[ENTER]tomb\233es jusque dans la mer, m\234me la plus[ENTER]inoffensive des baleines s'est transform\233e en un[ENTER]abominable monstre. P\234cher est devenu un commerce[ENTER]dangereux. "
gameforge.new_quest_lv42._032_say = "Nos lances ne peuvent plus blesser les baleines.[ENTER]Leur peau est plus dure que celle d'un ogre ! "
gameforge.new_quest_lv42._033_say = "Peut-\234tre que Yonah sait quoi faire, autrefois il[ENTER]allait souvent au lac et il a longtemps chass\233 la[ENTER]baleine. "
gameforge.new_quest_lv42._034_say_title = "Le P\234cheur : "
gameforge.new_quest_lv42._035_say = "Octavio attend son ragout de fruits de mer.[ENTER]Demandez au p\234cheur pourquoi la livraison est si[ENTER]longue. "
gameforge.new_quest_lv42._036_say = "Le P\234cheur est \224 %s. "
gameforge.new_quest_lv42._037_send_letter = "Les monstres marins "
gameforge.new_quest_lv42._038_say = "Le P\234cheur vous a demand\233 de questionner Yonah[ENTER]sur la meilleure mani\232re de chasser les[ENTER]monstrueuses baleines. "
gameforge.new_quest_lv42._039_say = "Yonah est \224 %s. "
gameforge.new_quest_lv42._040_target = "Yonah "
gameforge.new_quest_lv42._041_say = "J'ai entendu parler de ce qui est arriv\233 aux[ENTER]baleines. C'est mauvais pour le commerce des[ENTER]p\234cheurs. M\234me en r\233ussissant \224 braver les[ENTER]temp\234tes, leurs lances ne parviennent plus \224[ENTER]transpercer les baleines. \192 l'\233poque on utilisait[ENTER]des lances sp\233ciales pour transpercer la peau[ENTER]dure et us\233e des baleines. Elles pouvaient tout[ENTER]transpercer... "
gameforge.new_quest_lv42._042_say = "C'est une technique sp\233ciale pour pouvoir[ENTER]transpercer les baleines. La seule personne qui[ENTER]peut faire ce type de lance est un Forgeron. "
gameforge.new_quest_lv42._043_say_reward = "Allez voir le Forgeron. "
gameforge.new_quest_lv42._044_say_title = "Yonah: "
gameforge.new_quest_lv42._045_say = "Yonah recommande d'utiliser de tr\232s robuste[ENTER]lances bien affut\233es pour transpercer les[ENTER]baleines. Allez voir le Forgeron et demandez-lui[ENTER]de vous fabriquer quelques lances. "
gameforge.new_quest_lv42._050_target = "Forgeron "
gameforge.new_quest_lv42._051_say = "Oui, j'ai entendu parler de ces lances, et je[ENTER]peux en fabriquer. Cependant, pour en fabriquer[ENTER]de solides et durables, j'ai besoin de Pierre de[ENTER]Diamant. "
gameforge.new_quest_lv42._052_say = "J'ai besoin de: "
gameforge.new_quest_lv42._053_say_reward = "Processus : "
gameforge.new_quest_lv42._054_say_title = "Le forgeron: "
gameforge.new_quest_lv42._060_set_title = "Pierre de Diamant "
gameforge.new_quest_lv42._061_notice = "Voyons. J'ai besoin d'une pioche pour extraire le[ENTER]minerai. Je me demande s'il est pr\233f\233rable que je[ENTER]cherche ou j'ai pos\233 la mienne, ou bien que j'en[ENTER]demande une nouvelle \224 Deokbae ? "
gameforge.new_quest_lv42._062_say = "Vous avez encore besoin de %s Pierres de Diamant. "
gameforge.new_quest_lv42._063_say = "Vous avez ce qu'il faut. Retournez vite voir le[ENTER]Forgeron. "
gameforge.new_quest_lv42._064_say = "Super, j'ai tout ce dont j'ai besoin. Revenez \224[ENTER]la m\234me heure demain pour r\233cup\233rer les lances.[ENTER]Il faut temps et minutie pour fabriquer de telles[ENTER]lances. "
gameforge.new_quest_lv42._065_say = "Vous pouvez extraire des Pierres de Diamant d'une[ENTER]veine \224 l'aide d'une pioche. "
gameforge.new_quest_lv42._066_say = "Le Forgeron a besoin de Pierre de Diamant pour[ENTER]fabriquer des lances sp\233ciales tueuses de[ENTER]baleines. Cherchez des Veines de Diamant afin[ENTER]d'en extraire des Pierres de Diamant.Si vous[ENTER]n'avez pas de pioche, allez en acheter une \224[ENTER]Deokbae. "
gameforge.new_quest_lv42._067_say = "Le Forgeron est \224 %s. "
gameforge.new_quest_lv42._068_say = "Nous avons encore besoin de %s Pierres de Diamant[ENTER]avant de pouvoir travailler sur des lances. "
gameforge.new_quest_lv42._070_set_title = "Les Lances "
gameforge.new_quest_lv42._071_set_clock = "Temps d'attente "
gameforge.new_quest_lv42._072_say = "Le Forgeron a surement termin\233 maintenant. Allez[ENTER]le voir et r\233cup\233rez les lances sp\233ciales tueuses[ENTER]de baleines. "
gameforge.new_quest_lv42._073_say = "Les lances ne sont pas termin\233es. Soyez encore un[ENTER]petit peu patient. "
gameforge.new_quest_lv42._074_say = "Voici vos lances. Apportez les au P\234cheur. "
gameforge.new_quest_lv42._075_say = "Je vous ai d\233j\224 demand\233 d'attendre encore un peu[ENTER]pour avoir vos lances. Repassez plus tard. "
gameforge.new_quest_lv42._079_say = "Vous avez re\231u des lances tueuses de baleines du[ENTER]Forgeron. Apportez les au P\234cheur. "
gameforge.new_quest_lv42._080_say = "Fabuleux ! Ces lances sont impressionnantes ![ENTER]Nous pourrons parer les attaques des baleines \224[ENTER]pr\233sent. S'il vous plait allez dire \224 Octavio[ENTER]qu'il aura bient\244t sa livraison ! "
gameforge.new_quest_lv42._081_say_reward = "Vous avez re\231u 500.000 yangs. "
gameforge.new_quest_lv42._082_say_reward = "En guise de reconnaissance vous avez re\231u 3x: "
gameforge.new_quest_lv42._083_say = "Ces lances ne sont pas suffisamment solides pour[ENTER]ma\238triser une baleine. Tout juste \224 les[ENTER]chatouiller. "
gameforge.new_quest_lv42._084_say_reward = "S'il vous plait retournez voir le Forgeron et[ENTER]demandez lui de faire d'autres lances. "
gameforge.new_quest_lv42._090_say = "Les p\234cheurs sont mieux \233quip\233s et peuvent partir[ENTER]en mer. Retournez voir Octavio et expliquez lui[ENTER]qu'il peut \234tre certain d'avoir sa livraison[ENTER]bient\244t. "
gameforge.new_quest_lv42._095_say = "Que dites-vous ? Nos gentilles baleines sont[ENTER]devenues d'affreux monstres agressifs ? C'est[ENTER]terrible ... Merci d'avoir aid\233 les p\234cheurs.[ENTER]Une grosse partie de ma carte d\233pend de leurs[ENTER]livraisons. "
gameforge.new_quest_lv42._096_say = "Oh et \224 propos de votre estomac criant famine :[ENTER]Bien s\251r je peux vous offrir du rago\251t de fruits[ENTER]de mer, mais vous ne pr\233f\233reriez pas du sushi ? "
gameforge.new_quest_lv42._098_say_reward = "Vous avez re\231u 750.000 points d'exp\233rience.[ENTER]Vous avez re\231u 2 sushis. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "Aller voir Wonda-Rim "
gameforge.new_quest_lv43._006_send_letter = "L'orphelin "
gameforge.new_quest_lv43._010_target = "Wonda-Rim "
gameforge.new_quest_lv43._011_say = "Vous n'avez pas entendu parler de Wonda-Rim[ENTER]r\233cemment. Sa relation avec son oncle pourrait[ENTER]s'\234tre am\233lior\233 \224 ce jour et ils semblent avoir[ENTER]oubli\233 l'\233pisode de la Fourrure de Mu-Rang.[ENTER]Pourquoi n'iriez-vous pas lui rendre une petite[ENTER]visite? "
gameforge.new_quest_lv43._012_say = "Wonda-Rim est \224 %s. "
gameforge.new_quest_lv43._020_say = "C'est gentil \224 vous de passer. "
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "J'ai \233t\233 \233lev\233 par mon oncle Chaegirab. Nous nous[ENTER]sommes toujours bien entendu ... mais lorsque je[ENTER]lui pose des questions sur mes parents, il \233vite[ENTER]de r\233pondre. Ils sont morts, c'est tout ce qu'il[ENTER]m'a dit. "
gameforge.new_quest_lv43._023_say_reward = "J'ai envie de me marier et de fonder une famille,[ENTER]donc j'aimerais vraiment savoir d'o\249 je viens.[ENTER]Pourriez-vous poser des questions \224 mon oncle sur[ENTER]mes parents ? Ne lui dites pas que c'est moi qui[ENTER]vous envie ... "
gameforge.new_quest_lv43._024_select = "Je lui parlerai\160! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim n'est pas le neveu biologique de[ENTER]Chaegirab, il l'a juste \233lev\233. Il est temps pour[ENTER]lui de d\233couvrir qui sont ses vrais parents.[ENTER]Demandez \224 Chaegirab de vous parler de la famille[ENTER]de Wonda-Rim. "
gameforge.new_quest_lv43._026_say = "Chaegirab est \224 %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim ... non, je ne suis pas son oncle[ENTER]biologique. J'ignore qui sont ses parents. Je[ENTER]l'ai prot\233g\233 de la v\233rit\233 jusqu'ici parce que je[ENTER]pensais qu'il n'\233tait pas pr\234t. Mais peut-\234tre[ENTER]qu'il est temps aujourd'hui. "
gameforge.new_quest_lv43._033_say = "Je l'ai trouv\233 avec une horde de Combattants Orcs[ENTER]dans la Vall\233e de Seungryong. S'il est toujours[ENTER]possible d'en apprendre sur la famille de[ENTER]Wonda-Rim, vous devriez en trouver aupr\232s des[ENTER]Orcs. "
gameforge.new_quest_lv43._034_say = "Je peux \234tre strict avec lui, mais je serai[ENTER]toujours son Oncle. M\234me s'il reste un bon \224[ENTER]rien. "
gameforge.new_quest_lv43._035_say_reward = "Allez \224 la Vall\233e de Seungryong et chassez des[ENTER]Combattants Orcs jusqu'\224 ce que vous trouviez un[ENTER]indice concernant la famille de Wonda-Rim. "
gameforge.new_quest_lv43._036_say = "Vous avez d\233couvert une vieille lettre dans une[ENTER]v\233ritable tuerie d'orcs. C'est \224 peine[ENTER]d\233chiffrable, mais vous pouvez reconna\238tre le nom[ENTER]de Wonda-Rim. C'est la preuve que vous cherchiez,[ENTER]apportez-la \224 Wonda-Rim. "
gameforge.new_quest_lv43._041_say = "Allons-y ! La meilleure fa\231on de trouver des[ENTER]indices concernant la famille de Wonda-Rim est de[ENTER]tuer des Combattants Orcs. Ils peuvent avoir des[ENTER]preuves sur eux. "
gameforge.new_quest_lv43._043_notice = "Indices \224 propos de Wonda-Rim... "
gameforge.new_quest_lv43._045_say = "Je vous ai dit tout ce que je savais. La seule[ENTER]preuve que vous avons, c'est les Combattants[ENTER]Orcs. Malheureusement, il est difficile d'avoir[ENTER]une conversation avec eux ... "
gameforge.new_quest_lv43._049_say = "Une lettre ? Voyons voir... Ces caract\232res sont[ENTER]vraiment tr\232s difficiles \224 d\233chiffrer...[ENTER]Apparemment c'\233tait une attaque d'Orcs, ils ont[ENTER]mis le feu \224 la ferme, et ils ont \233t\233 oblig\233 de[ENTER]fuir pour sauver leur vie. Ils ont du abandonner[ENTER]leur enfant ... Et voici un nom. "
gameforge.new_quest_lv43._050_say = "Merci de m'avoir apport\233 cela. Je sais enfin ce[ENTER]qu'il s'est pass\233. "
gameforge.new_quest_lv43._051_say = "Je devrais parler \224 Chaegirab. Il m'a prot\233g\233[ENTER]dans bien des cas. Je vais essayer d'\234tre un[ENTER]meilleur neveu \224 ses yeux \224 pr\233sent. \192 bient\244t[ENTER]mon ami ! "
gameforge.new_quest_lv43._052_say_title = "Information: "
gameforge.new_quest_lv43._053_say_reward = "Vous avez re\231u 32.000 yangs. "
gameforge.new_quest_lv43._054_say_reward = "Vous avez 1.250.000 points d'exp\233rience. "
gameforge.new_quest_lv43._060_say = "Avez-vous d\233j\224 parl\233 \224 mon oncle Chaegirab\160? Une[ENTER]indication\160? De quoi parlez-vous\160? Si vous n'avez[ENTER]rien de concret, gardez vos th\233ories pour vous\160![ENTER]Redemandez \224 mon oncle. Apr\232s tout, je vous paye[ENTER]pour \231a. "
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "Lettre du Capitaine "
gameforge.new_quest_lv52._020_say_title = "Loyal Citoyen "
gameforge.new_quest_lv52._021_say_reward = "J'aimerais que vous fassiez quelque chose pour[ENTER]moi. Je n'arrive plus \224 dormir et ce malgr\233 les[ENTER]rem\232des de Baek-Go, je passe la majorit\233 de ma[ENTER]nuit \224 me retourner et \224 bouger. Pourriez-vous[ENTER]aller le voir et lui demander de me donner des[ENTER]m\233dicaments plus forts ? "
gameforge.new_quest_lv52._022_say = "Baek-Go est \224 %s. "
gameforge.new_quest_lv52._030_set_title = "Une bonne nuit de sommeil "
gameforge.new_quest_lv52._035_target = "Baek-Go "
gameforge.new_quest_lv52._040_say = "Le Capitaine a des soucis de sommeil. Allez voir[ENTER]Baek-Go et demandez-lui de vous donner des[ENTER]somnif\232res pour le Capitaine. "
gameforge.new_quest_lv52._041_say = "Des somnif\232res pour le Capitaine ? J'ai bien peur[ENTER]de ne rien avoir de plus fort \224 vous donner.[ENTER]Cependant, Yu-Hwan pourrait faire quelque chose \224[ENTER]partir d'herbes qui vous donnerait les r\233sultats[ENTER]attendus. "
gameforge.new_quest_lv52._042_say = "Ah, vous avez eu ma lettre. Je ne sais pas quoi[ENTER]faire de plus, je n'arrive plus \224 passer ue bonne[ENTER]nuit de sommeil. Aidez-moi s'il vous pla\238t et[ENTER]demandez des conseils \224 Baek-Go. "
gameforge.new_quest_lv52._042_select = "Dans ce cas, je ferais mieux d'aller voir Yu-Hwan\160! "
gameforge.new_quest_lv52._043_say = "Baek-Go est \224 %s. "
gameforge.new_quest_lv52._044_say_title = "Baek-Go: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan est \224 %s. "
gameforge.new_quest_lv52._046_say = "Alors allez voir le capitaine et dites-lui que[ENTER]vous ne pouvez pas l'aider. "
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan "
gameforge.new_quest_lv52._051_say = "Baek-Go n'avait pas de m\233dicament plus efficace.[ENTER]Yu-Hwan pourrait peut-\234tre vous aider, il connait[ENTER]une herbe qui a les effets recherch\233s. "
gameforge.new_quest_lv52._052_say = "Je connaissais bien le Capitaine. Comme vous le[ENTER]savez d\233j\224, j'ai accompli des missions secr\232tes[ENTER]pour lui pendant quelque temps. Mais je peux vous[ENTER]dire maintenant que les herbes ne r\233soudront pas[ENTER]ses probl\232mes. "
gameforge.new_quest_lv52._053_say = "Il y a une autre raison pour laquelle le[ENTER]Capitaine ne peut dormir. Et croyez-moi, il sait[ENTER]ce qu'il en est. Mais c'est quelle chose qu'il[ENTER]doit r\233gler seul. Allez le voir et parlez-en avec[ENTER]lui. "
gameforge.new_quest_lv52._054_say_title = "Capitaine: "
gameforge.new_quest_lv52._055_say_reward = "Ah, vous avez eu ma lettre. Je ne sais plus quoi[ENTER]faire. Allez demander des conseils \224 Baek-Go s'il[ENTER]vous plait, afin que je puisse enfin passer une[ENTER]bonne nuit. "
gameforge.new_quest_lv52._055_select = "\192 vos ordres\160! "
gameforge.new_quest_lv52._056_say = "Je vous remercie\160! "
gameforge.new_quest_lv52._056_say_reward = "Je l'ai d\233j\224 vu, il m'a dit ne rien avoir de[ENTER]mieux pour vous aider. Mais l\224 je vais voir[ENTER]Yu-Hwan et lui demander de l'aide. "
gameforge.new_quest_lv52._060_target = "Capitaine "
gameforge.new_quest_lv52._061_say = "Yu-Hwan n'aime pas d\233voiler les secrets des[ENTER]autres, il doit s'agir d'un sujet d\233licat.[ENTER]Mais cela ne change rien\160: vous devez en parler[ENTER]au capitaine. Si nous ignorons la cause de ses[ENTER]soucis, nous ne pourrons pas r\233soudre ses[ENTER]probl\232mes de sommeil. Allez donc \224 %s. "
gameforge.new_quest_lv52._062_say_reward = "Il n'existe pas de m\233dicament plus efficace.[ENTER]Mais Capitaine, je pourrais peut-\234tre vous aider[ENTER]si je connais les causes de ces troubles du[ENTER]sommeil. "
gameforge.new_quest_lv52._063_say_reward = "Ce n'est pas le genre de choses que j'ai envie de[ENTER]raconter \224 quelqu'un de votre \226ge. "
gameforge.new_quest_lv52._064_say_reward = "Ce n'est pas le genre de choses que j'ai envie de[ENTER]raconter \224 quelqu'un d'aussi jeune que vous. "
gameforge.new_quest_lv52._065_say_reward = "Mais si je ne r\233sous pas mon probl\232me de sommeil,[ENTER]je vais devenir fou. Je suppose qu'il faut que je[ENTER]parle ... Mais souvenez-vous, gardez cela pour[ENTER]vous : je suis hant\233 par quatre fant\244mes chaque[ENTER]nuit. Et le pire de tout \231a... c'est que je suis[ENTER]le responsable de leurs morts. "
gameforge.new_quest_lv52._066_say_reward = "Ils \233taient quatre soldats. Ils disent qu'ils ont[ENTER]\233t\233 tortur\233s et tu\233s par des Bourreaux funeste et[ENTER]des Invocateurs funestes dans la Vall\233e de[ENTER]Seungryong. C'est moi qui leur avait ordonn\233 d'y[ENTER]aller... Je les ai envoy\233s \224 leur propre mort ! "
gameforge.new_quest_lv52._067_say_reward = "Que pouvons-vous faire contre ce genre de[ENTER]fant\244mes ? "
gameforge.new_quest_lv52._068_say_reward = "Ils veulent se venger\160! Que suis-je suppos\233[ENTER]faire\160? Si j'accepte mon ch\226timent, le village se[ENTER]retrouvera sans personne pour le diriger et sera[ENTER]envahi. Et si je n'y vais pas, je vais devenir[ENTER]fou. "
gameforge.new_quest_lv52._069_say_reward = "Si je n'\233tais pas responsable de la s\233curit\233 du[ENTER]village, j'irais imm\233diatement. Je en vois qu'une[ENTER]solution: "
gameforge.new_quest_lv52._070_say_reward = "Quelqu'un doit aller les venger \224 ma place ![ENTER]Mais comment pourrais-je encore demander \224[ENTER]quelqu'un d'aller risquer sa vie dans la Vall\233e ?[ENTER]Je ne peux pas demander \231a \224 quelqu'un juste[ENTER]parce que j'ai envie de dormir ! "
gameforge.new_quest_lv52._071_say_reward = "Une telle d\233cision n'est pas facile \224 prendre. "
gameforge.new_quest_lv52._080_1_select = "Le bon du Village... "
gameforge.new_quest_lv52._080_2_select = "Cela ne pas pas \234tre facile ... "
gameforge.new_quest_lv52._080_3_select = "Vous ne pouvez attendre cela ! "
gameforge.new_quest_lv52._081_say_reward = "... porte plus de poids sur ses \233paules que votre[ENTER]l\226chet\233. Je vengerai vos hommes. Et si je ne[ENTER]reviens pas, je vous verrai ce soir! "
gameforge.new_quest_lv52._082_say_reward = "... n\233gocier avec ces Bourreaux funestes et ces[ENTER]Invocateurs funestes. Mais vous dormirez bien ce[ENTER]soir, je le promets\160! "
gameforge.new_quest_lv52._083_say_reward = "Avez-vous envie de mourir ? C'est tellement[ENTER]dangereux de tenter de traiter avec les Bourreaux[ENTER]funestes et les Invocateurs. Essayez de dire aux[ENTER]fant\244mes que vous avez besoin d'eux ! "
gameforge.new_quest_lv52._084_say_reward = "Vous avez raison. J'avais esp\233r\233 que vous vous[ENTER]porteriez volontaire pour le faire, ce qui nous[ENTER]rendrait au village et \224 moi-m\234me un immense[ENTER]service. "
gameforge.new_quest_lv52._090_1_select = "Bien ... "
gameforge.new_quest_lv52._090_2_select = "Non, je ne peux pas faire \231a ! "
gameforge.new_quest_lv52._091_say_reward = "... si je suis votre dernier espoir, alors je[ENTER]tuerai tous les Bourreaux funestes et Invocateurs[ENTER]funestes pour vous ! "
gameforge.new_quest_lv52._092_say_reward = "Si j'essaie, un autre fant\244me vous hantera. "
gameforge.new_quest_lv52._093_say_reward = "Ok, laissez-moi vous offrir quelques yangs pour[ENTER]vos efforts. "
gameforge.new_quest_lv52._093_say_reward_exp = "Vous avez re\231u 20.000 points d'exp\233rience. "
gameforge.new_quest_lv52._093_say_reward_gold = "Vous avez re\231u 25\160000 Yangs. "
gameforge.new_quest_lv52._100_notice = "La conversation est termin\233e. "
gameforge.new_quest_lv52._110_say_reward = "J'esp\233rais que vous diriez cela.[ENTER]Malheureusement, j'ignore quels bourreaux et[ENTER]invocateurs les ont tu\233. Je suppose qu'une fois[ENTER]qu'ils seront morts, je le ressentirai. "
gameforge.new_quest_lv52._111_say_reward = "Je vous ai envoy\233 une lettre. Les fant\244mes m'ont[ENTER]expliqu\233 que la vengeance doit avoir lieu au[ENTER]Triangle du Dieu Dragon. Il y a trois piliers[ENTER]formant un triangle l\224-bas. "
gameforge.new_quest_lv52._120_set_title = "4 Soldats \224 venger "
gameforge.new_quest_lv52._125_say_title = "Lettre du Capitaine "
gameforge.new_quest_lv52._130_say_reward = "Encore 3 Soldats \224 venger ! "
gameforge.new_quest_lv52._131_say = "Vous semblez avoir r\233ussi, je viens d'entendre la[ENTER]voix d'un de mes soldats. Il a dit qu'il me[ENTER]pardonnait et qu'il savait que sa mort avait \233t\233[ENTER]veng\233e. Et plein de remerciements pour vous ! "
gameforge.new_quest_lv52._132_say = "S'il vous pla\238t, vengez les autres soldats qui[ENTER]sont morts et tuez des Bourreaux funestes, des[ENTER]Invocateurs funestes, des Hauts Tourmenteurs et[ENTER]des Hauts \201vocateurs. Souvenez-vous que vous ne[ENTER]devez le faire qu'\224 l'int\233rieur du Triangle que[ENTER]forment les trois piliers du Dieu Dragon. "
gameforge.new_quest_lv52._140_say_reward = "Encore 2 soldats \224 venger ! "
gameforge.new_quest_lv52._141_say = "Vous avez tu\233 un autre de mes soldats ![ENTER]Meurtriers ! J'ai aper\231u le salut d'un soldat[ENTER]tombant au combat. "
gameforge.new_quest_lv52._150_say_reward = "Il y a un autre soldat \224 venger ! "
gameforge.new_quest_lv52._151_say = "Vous \234tes incroyable ! Le fant\244me d'un soldat[ENTER]tomb\233 \233tait debout \224 c\244t\233 de moi il y a \224 peine[ENTER]une minute en me disant adieu Il va surement \234tre[ENTER]bien difficile de trouver le dernier meurtrier. "
gameforge.new_quest_lv52._160_say = "Les fant\244mes qui hantent le Capitaine sont les[ENTER]jeunes soldats morts au combat. Ils ont \233t\233 tu\233[ENTER]par des Bourreaux funestes, des Invocateurs[ENTER]funestes, des Hauts tourmenteurs et des Hauts[ENTER]\201vocateurs. "
gameforge.new_quest_lv52._161_say = "Vous devez tuer les responsables de la mort des[ENTER]soldats dans le triangle du Dieu Dragon pour[ENTER]venger leurs morts. "
gameforge.new_quest_lv52._162_say = "Le Triangle du Dieu Dragon se trouve au centre de[ENTER]la Vall\233e de Seungryong. "
gameforge.new_quest_lv52._170_send_letter = "Premier soldat veng\233 "
gameforge.new_quest_lv52._171_send_letter = "Deuxi\232me soldat veng\233 "
gameforge.new_quest_lv52._172_send_letter = "Troisi\232me soldat veng\233 "
gameforge.new_quest_lv52._173_send_letter = "Les soldats sont tous veng\233s "
gameforge.new_quest_lv52._180_say_reward = "Vous avez veng\233 les 4 soldats ! "
gameforge.new_quest_lv52._181_say = "Vous avez trouv\233 le dernier meurtrier ! Le[ENTER]dernier des soldats vient d'appara\238tre \224 c\244t\233 de[ENTER]moi et m'a demand\233 de vous remercier pour votre[ENTER]courage. Il a aussi laiss\233 ceci pour vous : %s "
gameforge.new_quest_lv52._182_say = "Venez me voir pour votre r\233compense. Je vous[ENTER]attends \224 %s. "
gameforge.new_quest_lv52._183_say_reward = "Vous nous avez rendu au village et \224 moi-m\234me un[ENTER]grand service. Voici la r\233compense que le fant\244me[ENTER]m'a demand\233 de vous donner : %s "
gameforge.new_quest_lv52._184_say_reward = "Et voici quelques yangs de ma part. Je vais aller[ENTER]dormir un peu \224 pr\233sent. "
gameforge.new_quest_lv52._185_say_reward = "Je vous suis profond\233ment redevable, mon fils. "
gameforge.new_quest_lv52._186_say_reward = "Je vous serai redevable \224 vie. "
gameforge.new_quest_lv52._190_say_title = "Information: "
gameforge.new_quest_lv52._191_say_reward = "Vous avez re\231u 3.300.000 points d'exp\233rience.[ENTER]Vous avez re\231u 270.000 yangs.[ENTER]Vous avez re\231u un Livre de Ma\238tre. "
gameforge.new_quest_lv52._85_say = "Plus tard, peut-\234tre\160? Quand vous serez pr\234t,[ENTER]allez voir Baek-Go\160! "
gameforge.new_quest_lv54 = {}
gameforge.new_quest_lv54._010_target = "Capitaine "
gameforge.new_quest_lv54._020_say_title = "Les provisions "
gameforge.new_quest_lv54._030_say = "Il est dur de motiver nos troupes \224 l'heure[ENTER]actuelle, d'autant plus qu'il est encore plus[ENTER]difficile de trouver des produits frais. La[ENTER]Marchande, qui est un de nos meilleurs[ENTER]fournisseurs, nous a seulement apport\233 un petit[ENTER]stock des potions dont nous avons besoin. "
gameforge.new_quest_lv54._031_say_reward = "S'il vous plait allez voir la Marchande afin de[ENTER]savoir ce qu'il se passe. "
gameforge.new_quest_lv54._032_select = "Je vous procurerai les potions\160! "
gameforge.new_quest_lv54._040_say_title = "La marchande\160: "
gameforge.new_quest_lv54._040_set_title = "Des produits frais "
gameforge.new_quest_lv54._050_target = "La marchande "
gameforge.new_quest_lv54._051_say = "Oui, trouver des produits frais est devenu[ENTER]probl\233matique de nos jours. Les routes sont[ENTER]devenues dangereuses, les voleurs de grands[ENTER]chemins et les b\234tes sauvages sont de plus en[ENTER]plus nombreux. Les marchands ambulants, qui me[ENTER]fournissent la marchandise, n'ont aucune chance[ENTER]contre les tigres. "
gameforge.new_quest_lv54._052_say = "Peut-\234tre que le Capitaine et ses soldats peuvent[ENTER]aider. Allez le voir s'il vous plait, et[ENTER]demandez-lui s'il peut envoyer ses soldats[ENTER]prot\233ger nos marchands. "
gameforge.new_quest_lv54._054_say = "Allez voir la Marchande pour savoir pourquoi il[ENTER]n'y a pas eu de ravitaillement suffisant de[ENTER]potions. "
gameforge.new_quest_lv54._055_say = "La Marchande est \224 %s. "
gameforge.new_quest_lv54._056_say_title = "Capitaine: "
gameforge.new_quest_lv54._060_say = "S\233curiser les routes ? Oui... j'aimerais le[ENTER]faire. Mais je n'ai pas assez de soldats pour[ENTER]prot\233ger tous les marchands des autres empires. "
gameforge.new_quest_lv54._061_say = "En outre, l'arm\233e ne doit pas servir \224 chasser[ENTER]des Tigres. Seuls les chasseurs de la guilde des[ENTER]Chasseurs peuvent le faire. Cela n'apporterait[ENTER]pas la paix dans le village de violer ces r\232gles. "
gameforge.new_quest_lv54._062_say_reward = "Vous devriez en parler \224 Yang-Shin. Il est membre[ENTER]de la guilde des Chasseurs. peut-\234tre pourra t-il[ENTER]vous aider \224 garder les tigres sous contr\244le. "
gameforge.new_quest_lv54._064_say = "Allez voir le Capitaine et tentez de le[ENTER]convaincre de prot\233ger les routes contre les[ENTER]attaques de Tigres. "
gameforge.new_quest_lv54._065_say = "Le Capitaine est \224 %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin "
gameforge.new_quest_lv54._071_say = "Bon nombre de mes chasseurs ont \233t\233 enr\244l\233s comme[ENTER]guerriers et sont morts pendant la guerre. A[ENTER]l'heure actuelle il est devenu presque impossible[ENTER]d'\233quilibrer la population d'animaux sauvages.[ENTER]Les chats sauvages sont un probl\232me particulier[ENTER]car ils \233tendent leur territoire et mettent en[ENTER]danger les voyageurs. "
gameforge.new_quest_lv54._072_say = "Si vous nous aidez je vous offrirai ce bouclier[ENTER]Tigre Singe +3 qui appartenait \224 mon camarade[ENTER]Mi-Song aujourd'hui d\233c\233d\233. Pour l'obtenir vous[ENTER]devez r\233duire consid\233rablement le nombre de[ENTER]Tigres. "
gameforge.new_quest_lv54._073_say = "Particuli\232rement les tigres Blancs Maudits qui se[ENTER]sont multipli\233s consid\233rablement. "
gameforge.new_quest_lv54._074_say = "Comme preuve, j'ai besoin de : "
gameforge.new_quest_lv54._075_say = "Vous devez chasser: "
gameforge.new_quest_lv54._076_say = "Allez voir yang-Shin et tentez de le convaincre[ENTER]de s\233curiser les routes contre les Tigres. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "Yang-Shin est \224 %s. "
gameforge.new_quest_lv54._080_set_title = "La Fourrure de Tigre "
gameforge.new_quest_lv54._081_notice = "Ah, splendide sp\233cimen! Plus que %s ! "
gameforge.new_quest_lv54._082_notice = "C'est fait! Allez vite voir Yang-Shin. "
gameforge.new_quest_lv54._083_notice = "Cette Fourrure de Tigre est inutile. "
gameforge.new_quest_lv54._084_say = "Vous avez besoin de %s Fourrures de Tigre[ENTER]\233clatantes. "
gameforge.new_quest_lv54._085_say = "Trouvez des Fourrures de Tigre \233clatantes sur les[ENTER]Tigres Blancs Maudits. "
gameforge.new_quest_lv54._090_npcChat = "J'ai la Fourrure de Tigre. "
gameforge.new_quest_lv54._091_say = "Ce n'est pas assez selon moi. Comment puis-je[ENTER]savoir si les routes sont s\251res avec le peu de[ENTER]fourrures que vous m'apportez ? "
gameforge.new_quest_lv54._092_say = "Ahh enfin! Ces fourrures vont m'enrichir ...[ENTER]euh! Vous \234tes toujours ici ? Gr\226ce \224 vous les[ENTER]routes sont enfin s\251res de nouveau! Je suis s\251r[ENTER]que le Capitaine vous donnera une belle[ENTER]r\233compense. "
gameforge.new_quest_lv54._093_say = "Partez maintenant. Je dois nettoyer les fourrures. "
gameforge.new_quest_lv54._094_say = "Oh, le Capitaine ne vous donnera pas de[ENTER]r\233compense ? Ce n'est pas mon probl\232me. Et au cas[ENTER]ou vous tenteriez de r\233cup\233rer les fourrures :[ENTER]oubliez de suite, je ne suis pas pr\234t de m'en[ENTER]s\233parer ! "
gameforge.new_quest_lv54._095_say_reward = "Mais je vous ai promis un bouclier et vous devez[ENTER]donc y avoir droit. Cette chose sale ne me[ENTER]servirait jamais \224 rien de toutes fa\231ons. "
gameforge.new_quest_lv54._096_say = "R\233compense : "
gameforge.new_quest_lv54._097_say_reward = "Vous avez re\231u un Bouclier Tigre Singe +3. "
gameforge.new_quest_lv54._098_say = "Vous voulez vous d\233barrasser de moi avec ces[ENTER]quelques fourrures ? Afin de rembourser mes[ENTER]dettes .... Je veux dire que de cette mani\232re les[ENTER]routes ne seront jamais assez s\251res! "
gameforge.new_quest_lv54._099_say_reward = "Ne revenez pas avant d'avoir trouv\233 %s fourrures !  "
gameforge.new_quest_lv54._100_say = "C'est tout, allez vite voir Yang-Shin. "
gameforge.new_quest_lv54._101_say_reward = "Vous avez re\231u 3.750.000 points d'exp\233rience. "
gameforge.new_quest_lv54._102_say_reward = "Vous avez re\231u 125.000 yangs. "
