gameforge.new_quest_lv7._020_say_title = "Le mariage de la fille "
gameforge.new_quest_lv7._021_say = "Avez-vous des enfants ? Vous allez donc[ENTER]comprendre mes soucis... C'est \224 propos de ma[ENTER]fille ! Elle a rencontr\233 un homme qui lui fait[ENTER]compl\232tement tourner la t\234te. \192 pr\233sent, elle[ENTER]veut partir dans un autre empire avec son[ENTER]amoureux. "
gameforge.new_quest_lv7._022_say = "Il est de Chunjo. \201videmment j'\233tais contre ! Je[ENTER]pensais qu'une femme de Shinsoo ne pouvait pas se[ENTER]marier avec un r\234veur spirituel de Chunjo.[ENTER]Nous nous sommes disput\233s, et elle a fui avec lui[ENTER]\224 Chunjo. "
gameforge.new_quest_lv7._023_say = "Il est de Jinno. \201videmment que j'\233tais contre ![ENTER]Je pensais qu'une jeune fille de Chunjo ne[ENTER]pouvait se marier \224 une brute de Jinno. Nous nous[ENTER]sommes disput\233s, elle s'est enfuie avec lui \224[ENTER]Jinno. "
gameforge.new_quest_lv7._024_say = "Il est de Shinsoo. \201videmment que j'\233tais[ENTER]contre\160! Je pensais qu'une jeune fille de Jinno[ENTER]ne pouvait se marier \224 un pauvre fossoyeur de[ENTER]Shinsoo. Nous nous sommes disput\233s, elle s'est[ENTER]enfuie avec lui \224 Shinsoo. "
gameforge.new_quest_lv7._030_say = "J'ai entendu dire qu'elle veut se marier avec lui[ENTER]l\224-bas. "
gameforge.new_quest_lv7._031_say = "Maintenant ma fille attend un signe de moi. Que[ENTER]suis-je suppos\233 faire\160? Elle est mon seul[ENTER]enfant\160! \201videmment que je vais lui donner ma[ENTER]b\233n\233diction. Allez voir la Vieille Dame s'il vous[ENTER]plait et demandez-lui de m'aider pour les[ENTER]pr\233paratifs. "
gameforge.new_quest_lv7._040_target = "Vieille Dame "
gameforge.new_quest_lv7._041_say = "Allez voir la Vieille dame et demandez-lui de[ENTER]commencer les pr\233paratifs du mariage. "
gameforge.new_quest_lv7._042_say = "La Vieille Dame est \224 %s. "
gameforge.new_quest_lv7._051_say = "Un mariage, dites-vous? C'est un moment important[ENTER]dans la vie d'une femme. Tout doit \234tre parfait,[ENTER]de la robe de mari\233e ,en passant par celles des[ENTER]demoiselles d'honneur pour finir par la c\233r\233monie[ENTER]et l'\233change des alliances.[ENTER]Quand le p\232re de la mari\233e donne son consentement[ENTER]et l'argent n\233cessaire, la c\233l\233bration peut \234tre[ENTER]faite. "
gameforge.new_quest_lv7._052_say = "Les Fleurs sont particuli\232rement importantes -[ENTER]aucun mariage ne peut avoir lieu sans un bouquet[ENTER]de noce que le mari\233 offre \224 sa promise. Le[ENTER]bouquet devrait contenir les fleurs suivantes : "
gameforge.new_quest_lv7._054_say = "J'ai besoin de: "
gameforge.new_quest_lv7._055_say = "Vous devez chasser: "
gameforge.new_quest_lv7._056_say = "J'ai toujours besoin de: "
gameforge.new_quest_lv7._060_say = "Revenez me voir quand vous aurez les trois[ENTER]vari\233t\233s de fleurs. Je v\233rifierai qu'elles ne[ENTER]soient pas fan\233es et pourrai ainsi pr\233parer un[ENTER]joli bouquet. Vous pourrez alors l'apporter \224 ma[ENTER]s\156ur. Elle organisera la c\233r\233monie. "
gameforge.new_quest_lv7._081_say = "Trouvez une fleur de chaque vari\233t\233. Vous pouvez[ENTER]en trouver en tuant des : Loup alpha affam\233, Loup[ENTER]bleu affam\233, Loup alpha bleu affam\233. "
