gameforge.new_quest_lv7._141_say = "Quelles magnifiques fleurs ! Elles vont servir[ENTER]pour le bouquet de la mari\233e. Cela continuera les[ENTER]pr\233parations. S'il vous plait dites \224 Octavio[ENTER]qu'il est invit\233 \224 la c\233r\233monie. Je sais qu'il en[ENTER]sera tr\232s heureux. "
gameforge.new_quest_lv7._142_say = "Chez Octavio maintenant ! Qu'attendez-vous ? "
gameforge.new_quest_lv7._143_say = "Vous avez apport\233 des fleurs pour la fille[ENTER]d'Octavio qui se marie? C'est si gentil \224 vous![ENTER]Mais... o\249 sont-elles? Les avez-vous perdues en[ENTER]chemin? "
gameforge.new_quest_lv7._144_say_reward = "Retournez dans votre empire et pr\233parez un[ENTER]nouveau bouquet de fleur pour le mariage. "
gameforge.new_quest_lv7._145_say = "Allez voir la s\156ur de la Vieille Dame avant que[ENTER]les fleurs ne fanent. "
gameforge.new_quest_lv7._150_say = "Pourquoi sentez-vous le potage de grenouille ? Oh[ENTER]bien, ce n'est pas vraiment important tant que[ENTER]vous avez de bonnes nouvelles. "
gameforge.new_quest_lv7._151_say = "Je n'ai pas de mot assez fort pour vous[ENTER]remercier. Je suis si heureux d'aller au mariage[ENTER]de ma fille ! "
gameforge.new_quest_lv7._152_say = "Tenez, voici votre r\233compense: "
gameforge.new_quest_lv7._153_say_reward = "Une arme forg\233e de la main d'un ma\238tre d'arts[ENTER]martiaux. Prenez-en soin ! "
gameforge.new_quest_lv7._154_say_reward = "Vous avez re\231u %s points d'exp\233rience. "
gameforge.new_quest_lv7._155_say_reward = "Vous avez re\231u %s yangs. "
gameforge.new_quest_lv7._160_say = "Vous me confondez avec un parent \233loign\233. Je n'ai[ENTER]pas de fille et je n'ai pas assez de Yangs pour[ENTER]pouvoir payer un mariage. "
gameforge.new_quest_lv7._165_say = "Voudriez-vous essayer une cuiller\233e de mon potage[ENTER]de grenouille-taureau ? Je l'ai fait en utilisant[ENTER]une vieille recette de ma tante. "
gameforge.new_quest_lv75 = {}
gameforge.new_quest_lv75._010_target = "Heuk-Young "
gameforge.new_quest_lv75._020_set_title = "Journal intime d'une l\233gende "
gameforge.new_quest_lv75._021_say = "J'ai trouv\233 les restes du corps d'un guerrier.[ENTER]Par contre, je ne sais pas s'il s'agit de ce Sura[ENTER]que Heuk-Young recherche, mais cela devrait[ENTER]certainement l'int\233resser. "
gameforge.new_quest_lv75._022_say = "Le Sura n'est pas le seul mort ici, j'ai vu les[ENTER]restes de plusieurs corps. Je me demande si ce[ENTER]guerrier l\233gendaire \233tait parmi eux.[ENTER]Je devrais faire un rapport \224 Heuk-Young \224 ce[ENTER]sujet. "
gameforge.new_quest_lv75._023_say = "J'ai trouv\233 un vieux morceau de papier, gel\233 dans[ENTER]les entrailles d'un Golem de glace d'enfer. Je[ENTER]n'ai pas pu d\233chiffrer grand chose, mais il est[ENTER]possible qu'on y trouve des indices pouvant[ENTER]int\233resser Heuk-Young. "
gameforge.new_quest_lv75._024_say = "Je commence \224 avoir rassembl\233 beaucoup de choses[ENTER]pouvant int\233resser Heuk-Young. Je devrais aller[ENTER]la voir et lui donner le morceau de papier et en[ENTER]profiter pour lui parler du cadavre que j'ai[ENTER]trouv\233. "
gameforge.new_quest_lv75._025_say = "Heuk-Young m'a demand\233 d'\234tre \224 l'aff\251t du[ENTER]moindre indice concernant les l\233gendaires Sura.[ENTER]Malheureusement je n'ai aucune id\233e de la forme[ENTER]sous laquelle je pourrais trouver ces indices. "
gameforge.new_quest_lv75._030_say = "Partez \224 la recherche du l\233gendaire Guerrier[ENTER]Akuma. Il est probablement le Sura le plus connu[ENTER]qui ait jamais exist\233 : un guerrier r\233put\233[ENTER]invincible. On dit m\234me qu'il aurait provoqu\233[ENTER]l'empereur en Duel. Je pense que l'endroit o\249[ENTER]nous nous trouvons est l'endroit o\249 il a disparu,[ENTER]il y a plusieurs si\232cles. Ouvrez les yeux, il se[ENTER]pourrait qu'il y ait des indices quant \224 son[ENTER]passage qui aient surv\233cu aux al\233as des si\232cles. "
gameforge.new_quest_lv75._040_say = "dummy "
gameforge.new_quest_lv75._050_npcChat = "Observer le cadavre du guerrier "
gameforge.new_quest_lv75._060_say = "Il s'agit du cadavre d'un guerrier, mais son bras[ENTER]gauche ne semble pas humain ... C'est[ENTER]probablement un Sura ! Il faut que j'en parle \224[ENTER]Heuk-Young. "
gameforge.new_quest_lv75._070_notice = "Une page de livre ... gel\233e dans les entrailles[ENTER]d'un Golem de glace d'enfer ... "
gameforge.new_quest_lv75._090_say = "Je ne peux pas vous dire exactement ce que nous[ENTER]recherchons. Ouvrez grand vos yeux et venez me[ENTER]voir d\232s que vous aurez trouv\233 quelque chose[ENTER]sortant de l'ordinaire. "
gameforge.new_quest_lv75._100_say = "Qu'avez-vous donc l\224 ? Laissez-moi voir ! "
gameforge.new_quest_lv75._105_say = "Une note ... Mais quel est cet alphabet ? Cela[ENTER]doit \234tre tr\232s ancien. Il se pourrait que vous[ENTER]ayez trouv\233 quelque chose de vraiment important.[ENTER]Ce qu'il y a d'\233crit ici me semble familier. On[ENTER]dirait que cette page provient d'un livre. "
gameforge.new_quest_lv75._109_say = "Si nous arrivons \224 trouver d'autres pages, nous[ENTER]pourrions comprendre le sens des textes. Ouvre[ENTER]l'\156il, il se pourrait qu'il y ait d'autres[ENTER]indices ! "
gameforge.new_quest_lv75._110_say = "Vous revoil\224. Vous avez trouv\233 quelque chose ?[ENTER]Racontez-moi ! "
gameforge.new_quest_lv75._115_say = "Un cadavre de Sura. Peut-\234tre est-ce celui que[ENTER]nous recherchons ... Ou l'un de ses serviteurs ?[ENTER]Il nous faut plus d'indices permettant de[ENTER]s'assurer de son identit\233. Armes, bijoux ... ou[ENTER]un \233crit ou \233quivalent. "
gameforge.new_quest_lv75._120_say = "Le cadavre d'un Sura et une page ? Laisse moi[ENTER]jeter un \156il sur ce parchemin ... Hmmm, il se[ENTER]pourrait vraiment que vous ayez trouv\233 le cadavre[ENTER]d'Akuma. Mais il nous faut tout de m\234me plus[ENTER]d'indices. Voyez si vous pouvez trouver d'autres[ENTER]pages ... "
gameforge.new_quest_lv75._130_say = "J'ai trouv\233 des indices certes concluants, mais[ENTER]je ne suis pas encore tout \224 fait certaine que ce[ENTER]l\233gendaire Sura est vraiment venu ici.[ENTER]J'aimerais avoir plus d'indices pour arr\234ter ma[ENTER]d\233cision. "
gameforge.new_quest_lv75._140_1_select = "Bien. "
gameforge.new_quest_lv75._140_2_select = "Cr\233ature de glace "
gameforge.new_quest_lv75._140_3_select = "Au bord du d\233couragement "
gameforge.new_quest_lv75._140_4_select = "Sombre terreur "
gameforge.new_quest_lv75._140_5_select = "Face \224 la mort "
gameforge.new_quest_lv75._140_6_select = "Le destin du guerrier "
gameforge.new_quest_lv75._140_7_select = "Non, cela ne m'int\233resse pas. "
gameforge.new_quest_lv75._150_say = "Je n'arrive \224 lire ici que des bribes de phrases.[ENTER]Cela parle de vie \224 la cour et de d\233sir exag\233r\233[ENTER]d'aventure... "
gameforge.new_quest_lv75._160_1_say = "L'\233criture sur le parchemin jauni est \224 moiti\233[ENTER]effac\233e et difficile \224 lire, zigzaguant comme si[ENTER]elle avait \233t\233 \233crite par une personne tr\232s[ENTER]vielle ou tr\232s faible : \...cr\233atures de glace.[ENTER]M\234me mes capacit\233s de Sura n'ont pas pu m'aider \224[ENTER]les terrasser. Certains patrouillent ces grottes[ENTER]et gare \224 moi s'ils me trouvent. Je suis pour le[ENTER]moment \224 l'abri dans ma cachette, mais d'ici peu[ENTER]...\" - \224 partir de l\224 l'\233criture devient[ENTER]illisible. "
gameforge.new_quest_lv75._160_2_say = "Cette page aussi est tr\232s ab\238m\233e par le temps.[ENTER]Vous pouvez reconna\238tre \224 la date se trouvant[ENTER]dans le coin haut gauche qu'il s'agit d'une sorte[ENTER]de journal intime : Cela n'est pas la premi\232re[ENTER]fois que je regrette la fa\231on dont je me suis[ENTER]comport\233 en cherchant cette grotte. Que j'\233tais[ENTER]fier de moi, imbu m\234me, narcissique et cr\226neur.[ENTER]Tous ces d\233faut qui m'ont pouss\233 \224 me surestimer[ENTER]et aller au devant d'une mort certaine ...[ENTER](Le mot mort est soulign\233 plusieurs fois.) "
gameforge.new_quest_lv75._160_3_say = "Le parchemin est en tr\232s mauvais \233tat, parfois il[ENTER]y a m\234me des morceaux qui ont \233t\233 d\233chir\233s. Vous[ENTER]ne pouvez comprendre qu'une partie du message :[ENTER]... Cour de l'empereur... lorsque les \233rudits[ENTER]m'ont appris ce que j'avais toujours voulu[ENTER]savoir... facile d'ouvrir les portails, mais ...[ENTER]mort et horreur dans les ombr...( Une grosse[ENTER]d\233chirure en diagonale vous emp\234che de lire le[ENTER]reste.) "
gameforge.new_quest_lv75._160_4_say = "Sur cette page de parchemin se trouve un dessin :[ENTER]Le visage souriant d'une femme. En dessous,[ENTER]consign\233s dans une \233criture qui vous est[ENTER]d\233sormais famili\232re mais encore plus zigzaguante[ENTER]et impr\233cise que d'habitude, se trouvent les mots[ENTER]suivants : \"La mort a des griffes : je le sais[ENTER]depuis hier. Je n'ai pu lancer qu'un coup d'\156il \224[ENTER]la cr\233ature avant de fuir, la peur au ventre. Oh,[ENTER]Sunmi, mon aim\233e, si seulement j'avais su ! Si[ENTER]j'avais su l'horreur qui m'y attendait, jamais je[ENTER]ne serais descendu ici.\" "
gameforge.new_quest_lv75._160_5_say = "Sous le r\232gne de la dynastie Hee-Se vivait un[ENTER]Sura l\233gendaire du nom de Akuma. Il \233tait[ENTER]tellement talentueux au combat qu'avec le temps,[ENTER]il eut du mal \224 trouver des adversaires voulant[ENTER]se mesurer \224 lui. Il chercha donc de nouveaux[ENTER]d\233fis. Lorsqu'il tomba sur la description d'un[ENTER]lieu scell\233 depuis tr\232s longtemps, il fit tout ce[ENTER]qui \233tait en son pouvoir pour le trouver. Il[ENTER]finit par trouver le moyen d'ouvrir un portail y[ENTER]menant. Il promis \224 son aim\233e, Sunmi, de revenir[ENTER]lui raconter personnellement ses faits ... Mais[ENTER]il n'est jamais revenu. "
gameforge.new_quest_lv75._170_say = "L'\233criture semble antique ... irr\233guli\232re et[ENTER]zigzaguante aussi, comme si l'auteur \233tait \224 bout[ENTER]de force ... "
gameforge.new_quest_lv75._171_say = "Cela n'a aucun sens. Il nous faut plus de pages. "
gameforge.new_quest_lv75._172_say = "Je crois commencer \224 comprendre ce qu'il y pu se[ENTER]passer ici, mais tant de d\233tails sont encore[ENTER]impossible \224 d\233duire. "
gameforge.new_quest_lv75._173_say = "Voulez-vous conna\238tre les d\233tails? "
gameforge.new_quest_lv75._174_say = "Encore une page ! celui qui a \233crit ces lignes[ENTER]devait vraiment \234tre d\233sesp\233r\233. Voulez-vous que[ENTER]je vous r\233sume ce qui est \233crit ici ? "
gameforge.new_quest_lv75._175_say = "Certaines pages sont tellement ab\238m\233es que je ne[ENTER]peux que supposer la signification de ce qui est[ENTER]\233crit, mais je commence \224 me faire une id\233e sur[ENTER]ce qui s'est pass\233 dans ces caves. "
gameforge.new_quest_lv75._176_say = "Il ne nous manque plus grand chose. Voulez-vous[ENTER]un r\233sum\233 de ce que j'ai pu lire jusqu'ici ? "
gameforge.new_quest_lv75._177_say = "Il semblerait que beaucoup d'autres pages[ENTER]manquent. "
gameforge.new_quest_lv75._178_say = "Voulez-vous entendre le r\233sultat de mes[ENTER]recherches ? "
gameforge.new_quest_lv75._180_notice = "J'ai trouv\233 la derni\232re page sur un Golem de[ENTER]glace d'enfer. "
gameforge.new_quest_lv75._185_send_letter = "Je pense que nous avons toutes les pages ! "
gameforge.new_quest_lv75._190_notice = "J'ai trouv\233 une page sur le Golem de glace d'enfer "
gameforge.new_quest_lv75._195_send_letter = "La page trouv\233e "
gameforge.new_quest_lv75._200_npcChat = "Observer le cadavre du guerrier "
gameforge.new_quest_lv75._210_say = "Aux alentours du cadavre de l'humano\239de se[ENTER]trouvent 3 pages de parchemins dont les coins[ENTER]parfaitement carr\233s permettent d'imaginer[ENTER]qu'elles ont \233t\233 arrach\233es d'un livre. L'encre a[ENTER]p\226li et est difficile \224 lire. "
gameforge.new_quest_lv75._220_say = "Je pense que cela devrait suffire. Je vais[ENTER]apporter nos trouvailles \224 Heuk-Young. "
gameforge.new_quest_lv75._230_say = "Qui a bien pu perdre sa vie ici ? En tout cas il[ENTER]semble qu'il n'aie plus rien d'utilisable[ENTER]aujourd'hui en sa possession. "
gameforge.new_quest_lv75._240_send_letter = "J'ai les pages ! "
gameforge.new_quest_lv75._250_say = "Je devrais retourner aupr\232s de Heuk-Young.[ENTER]Peut-\234tre saura-t-elle r\233soudre cette \233nigme. "
gameforge.new_quest_lv75._270_say = "Je suis \233tonn\233e que tu aies trouv\233 tant de choses[ENTER]dans ces grottes. Ces pages semblent avoir fait[ENTER]partie d'un livre. Ce qui est \233crit ici est tr\232s[ENTER]int\233ressant. Cela compl\232te parfaitement ce que[ENTER]j'ai appris en lisant les l\233gendes. Si vous me[ENTER]laissez les pages, je peux vous les relier pour[ENTER]en faire un livre qui pourrait vous \234tre utile si[ENTER]vous vous rendez de nouveau dans la Grotte de[ENTER]l'Exil. Et si vous n'en avez plus l'utilit\233, vous[ENTER]trouverez certainement qui vous l'ach\232tera pour[ENTER]un somme rondelette. "
gameforge.new_quest_lv75._280_say = "J'ai reli\233 les pages en un livre en y ajoutant[ENTER]aussi mes notes. Peut-\234tre vous seront-elles[ENTER]utiles. Si vous voulez, je peux aussi vous[ENTER]raconter le reste de l'histoire. "
gameforge.new_quest_lv75._290_1_select = "Oui, racontez-moi ! "
gameforge.new_quest_lv75._290_2_select = "Non merci, cela ne m'int\233resse pas. "
gameforge.new_quest_lv75._310_say = "Que me voulez-vous ? Vous ne voyez pas que je[ENTER]suis en train de relier un livre ? "
gameforge.new_quest_lv75._320_say = "Soon: "
gameforge.new_quest_lv75._330_say = "C'est un livre tr\232s int\233ressant que vous avez l\224.[ENTER]D'o\249 vient-il ? Puis-je y jeter un \156il ? "
gameforge.new_quest_lv75._340_say = "Ce sont les manuscrits de la Grotte de l'Exil,[ENTER]n'est-ce pas ? Il ont vraiment l'air antiques.[ENTER]L'\233criture est assez d\233routante, tr\232s ancienne[ENTER]... Cela a d\251 \234tre tr\232s compliqu\233 de r\233cup\233rer un[ENTER]tel livre. Comme vous pouvez vous imaginer, je[ENTER]suis amoureux de ce genre de livres.[ENTER]Seriez-vous pr\234t \224 me le vendre ? "
gameforge.new_quest_lv75._350_1_select = "Oui. "
gameforge.new_quest_lv75._350_2_select = "Non. "
gameforge.new_quest_lv75._360_say = "Combien de Yangs voulez-vous pour ce Journal[ENTER]L\233gendaire ? "
gameforge.new_quest_lv75._370_say = "Hahaha... Je vois que vous aimez faire des[ENTER]blagues. Je ne pense pas que nous puissions faire[ENTER]affaire ensemble. Ou alors \233valuez ma[ENTER]proposition\160: 500\160000 Yangs pour ce Journal[ENTER]L\233gendaire. \192 prendre ou \224 laisser. "
gameforge.new_quest_lv75._380_1_select = "D'accord pour 500.000 Yang. "
gameforge.new_quest_lv75._380_2_select = "Et bien tant pis ! "
gameforge.new_quest_lv75._390_say = "Bien, tant pis ! "
gameforge.new_quest_lv75._400_say = "Non je suis d\233sol\233 mais c'est vraiment trop cher[ENTER]pour moi. "
gameforge.new_quest_lv75._410_say = "Laissez-moi vous faire une contre-proposition. Je[ENTER]vous offre %s Yangs pour ce Journal L\233gendaire. "
gameforge.new_quest_lv75._420_say = "\202tes-vous d'accord ? "
gameforge.new_quest_lv75._425_say = "C'est mon dernier prix ! "
gameforge.new_quest_lv75._430_1_select = "Je prends les %s Yang. "
gameforge.new_quest_lv75._430_2_select = "Nous n'allons donc pas pouvoir faire affaire. "
gameforge.new_quest_lv75._440_say = "Comme vous voulez ... "
gameforge.new_quest_lv75._450_say = "Cela n'est pas un prix d'ami. Mais bon, je veux[ENTER]bien \234tre g\233n\233reux. "
gameforge.new_quest_lv75._460_say = "Je ne suis pas pr\234t \224 marchander toute la nuit.[ENTER]Je vous offre 500\160000 Yangs pour votre Journal[ENTER]L\233gendaire. "
gameforge.new_quest_lv75._470_say = "\192 prendre ou \224 laisser ! "
gameforge.new_quest_lv75._480_say = "Bien, tant pis ! "
gameforge.new_quest_lv75._490_say = "Vraiment dommage. Mais bon, peut-\234tre[ENTER]reviendrez-vous sur votre d\233cision. "
gameforge.new_quest_lv80 = {}
gameforge.new_quest_lv80._010_target = "Soon "
gameforge.new_quest_lv80._020_set_title = "Le Sombre Masque de Bois "
gameforge.new_quest_lv80._030_say = "Vous ne pouviez pas mieux tomber! J'ai entendu[ENTER]dire que vous \234tes entr\233 dans la Grotte de l'Exil[ENTER]il n'y a pas tr\232s longtemps? "
gameforge.new_quest_lv80._040_say = "C'est la premi\232re fois que j'entends parler de[ENTER]quelqu'un qui y a surv\233cu. Je dois vous avouer[ENTER]que j'aimerais bien en apprendre davantage... "
gameforge.new_quest_lv80._050_1_say = "J'aurais une t\226che \224 remplir... mais elle n'est[ENTER]pas tout \224 fait sans danger. Cela dit, je crois[ENTER]qu'un homme avec vos capacit\233s devrait \234tre en[ENTER]mesure de la r\233ussir. "
gameforge.new_quest_lv80._050_2_say = "J'aurais une t\226che \224 remplir... mais elle n'est[ENTER]pas tout \224 fait sans danger. Cela dit, je crois[ENTER]qu'une femme avec vos capacit\233s devrait \234tre en[ENTER]mesure de la r\233ussir. "
gameforge.new_quest_lv80._060_say = "Prenez ce Masque de Bois et rendez-vous dans la[ENTER]r\233gion de Doyyumhwan. Cherchez-y des esprits[ENTER]flammes. Si \231a se trouve, vous les connaissez[ENTER]d\233j\224 - ces cr\233atures sph\233riques recouvertes de[ENTER]flammes. "
gameforge.new_quest_lv80._070_say = "Lorsque vous en tuez un, le Masque de Bois[ENTER]r\233agira. Il prendra feu et sera vite r\233duit en[ENTER]cendres. T\226chez de ne pas vous d\233courager si \231a[ENTER]ne fonctionne pas la premi\232re fois. "
gameforge.new_quest_lv80._080_say = "Vous m'apporterez ensuite les cendres. "
gameforge.new_quest_lv80._090_say = "Et pendant que vous \234tes dans ces r\233gions[ENTER]sauvages, pourriez-vous aussi me trouver %s[ENTER]Gla\231ons? J'en ai vraiment besoin, c'est urgent. "
gameforge.new_quest_lv80._100_say = "Les Y\233tis ont tr\232s souvent des Gla\231ons. Et alors,[ENTER]vous attendez quoi? "
gameforge.new_quest_lv80._110_say_title = "Feu et Glace "
gameforge.new_quest_lv80._120_say = "Soon m'a confi\233 une mission... "
gameforge.new_quest_lv80._130_say = "J'ai d\233j\224 trouv\233 les Gla\231ons. "
gameforge.new_quest_lv80._140_say = "J'ai encore besoin de: "
gameforge.new_quest_lv80._150_say_reward = "Il para\238t que je peux en trouver en chassant des[ENTER]Y\233tis! "
gameforge.new_quest_lv80._160_say = "Le Sombre Masque de Bois s'est d\233j\224 transform\233 en[ENTER]Cendres Ensorcel\233es. "
gameforge.new_quest_lv80._170_say = "J'ai besoin de: "
gameforge.new_quest_lv80._180_say_reward = "Pour \231a, je dois porter "
gameforge.new_quest_lv80._190_say_reward = "pr\232s de moi. D'apr\232s ce que m'a dit Soon, le[ENTER]Masque sera r\233duit en cendres ensorcel\233es lorsque[ENTER]je me battrai contre des esprits flammes. "
gameforge.new_quest_lv80._200_say = "Maintenant il me faut les Cendres Ensorcel\233es et[ENTER]les Gla\231ons.[ENTER]Tr\232s bien, attendez s'il vous pla\238t un instant... "
gameforge.new_quest_lv80._210_say = "J'ai r\233ussi! Ce que renferment les anciens[ENTER]parchemins est vraiment vrai! "
gameforge.new_quest_lv80._220_say = "J'ai fabriqu\233 de la Glace Noire \224 partir des[ENTER]objets que vous m'avez rapport\233s. "
gameforge.new_quest_lv80._230_say = "J'ai cependant une autre t\226che \224 vous confier.[ENTER]Elle est li\233e \224 la premi\232re. Si vous r\233ussissez[ENTER]aussi celle-ci, vous serez richement r\233compens\233 ! "
gameforge.new_quest_lv80._240_say = "Apportez la Glace Noire dans la Grotte de l'Exil[ENTER]et sacrifiez-la sur l'Autel Sombre. "
gameforge.new_quest_lv80._250_say = "Il vous manque encore %s Gla\231ons. "
gameforge.new_quest_lv80._260_notice = "Quelque chose ne tourne pas rond ici. "
gameforge.new_quest_lv80._270_say = "Excellent - comme je vois, vous portez les[ENTER]Gla\231ons sur vous. Maintenant il ne me manque que[ENTER]les Cendres ensorcel\233es. "
gameforge.new_quest_lv80._280_say = "Qu'attendez-vous encore? "
gameforge.new_quest_lv80._290_say = "Hmm... ce sont des cendres, mais on dirait des[ENTER]cendres normales. Elles ne sont pas ensorcel\233es.[ENTER]Cela n'a pas fonctionn\233. "
gameforge.new_quest_lv80._300_target = "Autel Sombre "
gameforge.new_quest_lv80._310_set_title = "L'Autel Sombre "
gameforge.new_quest_lv80._320_say = "Je dois apporter la Glace Noire dans la Grotte de[ENTER]l'Exil et la sacrifier sur un autel. Ce lieu de[ENTER]sacrifice ne sera pas facile \224 trouver! "
gameforge.new_quest_lv80._330_npcChat = "Sacrifier la Glace Noire! "
gameforge.new_quest_lv80._340_say = "Plus vous vous approchez de l'autel, plus[ENTER]l'obscurit\233 semble vous encercler. Dans la[ENTER]p\233nombre, les voix d\233sincarn\233es murmurent leurs[ENTER]\233ternelles angoisses. Cet endroit est vraiment[ENTER]blasph\233matoire. Voulez-vous vraiment sacrifier la[ENTER]Glace Noire ? "
gameforge.new_quest_lv80._350_1_select = "Oui ! Que pourrait-il nous arriver de pire ? "
gameforge.new_quest_lv80._350_2_select = "Non, tout se terminera dans les larmes ! "
gameforge.new_quest_lv80._360_say = "Je ne suis pas tout \224 fait certain d'avoir fait[ENTER]le bon choix - faire un sacrifice dans cette[ENTER]Grotte... \199a ne fera certainement pas plaisir au[ENTER]Dieu Dragon. J'aimerais tant pouvoir recommencer. "
gameforge.new_quest_lv80._370_say = "Je n'aime pas du tout cela. Le Dieu Dragon[ENTER]n'approuverait probablement pas qu'on fasse une[ENTER]victime dans la Grotte. Je ne le ferai pas. "
gameforge.new_quest_lv80._380_say = "C'est le mauvais autel! "
gameforge.new_quest_lv80._390_send_letter = "Retournez voir Soon "
gameforge.new_quest_lv80._400_set_title = "Monstre \233trange "
gameforge.new_quest_lv80._410_say = "Je devrais retourner chez Soon afin d'obtenir ma[ENTER]r\233compense. "
gameforge.new_quest_lv80._420_say = "J'ai entendu dire qu'on a aper\231u des monstres[ENTER]\233tranges dans certaines r\233gions ces derniers[ENTER]temps. "
gameforge.new_quest_lv80._430_say = "J'esp\232re que \231a n'a rien \224 voir avec la Glace[ENTER]Noire que j'ai sacrifi\233e dans la Grotte de[ENTER]l'Exil. "
gameforge.new_quest_lv80._440_say = "Magnifique! Voici votre r\233compense. "
gameforge.new_quest_lv80._450_npcChat = "Avez-vous vu le monstre? "
gameforge.new_quest_lv80._460_say = "Un %s?! Oh l\224 l\224... je me demande comment cela a[ENTER]pu se produire... je vais consulter mes livres[ENTER]sans tarder! "
gameforge.new_quest_lv80._470_say = "Je ne pouvais pas sacrifier la Glace Noire ... \231a[ENTER]paraissait si mal ! Je vais aller voir Soon pour[ENTER]lui dire que je ne terminerai pas cette mission. "
gameforge.new_quest_lv80._475_npcChat = "La Glace Noire "
gameforge.new_quest_lv80._476_say = "Je vois que vous n'avez plus la Glace Noire avec[ENTER]vous. Vous l'avez donc bien sacrifi\233e ?[ENTER]Dites-moi ce qu'il s'est pass\233 ! "
gameforge.new_quest_lv80._477_say = "Pardonnez-moi, mais nous nous sommes mal compris.[ENTER]j'ai toujours la Glace Noire avec moi. Je m'en[ENTER]vais la sacrifier et je repasse vous voir[ENTER]apr\232s... "
gameforge.new_quest_lv80._480_say = "Ah, vous voil\224 ! Pourquoi avez-vous toujours la[ENTER]Glace Noire sur vous ? "
gameforge.new_quest_lv80._490_say = "Je ne peux pas faire ce que vous m'avez demand\233.[ENTER]Cela va contre les d\233sirs du Dieu Dragon. Je ne[ENTER]sacrifierai pas la Glace ! "
gameforge.new_quest_lv80._495_say = "Rah, quel bon \224 rien ! M\234me une t\226che toute[ENTER]simple il ne peut l'accomplir ! Je vais donc[ENTER]devoir trouver quelqu'un d'autre pour le faire.[ENTER]Rendez-moi la Glace Noire, et partez ! "
gameforge.new_quest_lv80._500_say = "Est-ce que je dois vraiment donner la Glace Noire[ENTER]\224 Soon ? "
gameforge.new_quest_lv80._510_1_select = "Oui, je veux m'en d\233barrasser ! "
gameforge.new_quest_lv80._510_2_select = "Non, cela pourrait causer des probl\232mes ! "
gameforge.new_quest_lv80._520_say = "Tenez, prenez la Glace Noire et laissez moi seul ! "
gameforge.new_quest_lv80._530_say = "Vous attendez peut-\234tre que je vous remercie ?[ENTER]Hors de ma vue ! "
gameforge.new_quest_lv80._535_sayReward = "Vous avez re\231u 70.000.000 points d'exp\233rience. "
gameforge.new_quest_lv80._540_say = "Vous ne sacrifierez pas la Glace Noire. Je vais[ENTER]aller la jeter dans la mer - elle ne fera pas de[ENTER]mal l\224-bas ! "
gameforge.new_quest_lv80._550_say = "Vous n'oseriez pas ! Rendez-le-moi ou je vous[ENTER]maudirai vous et votre famille ! "
gameforge.new_quest_lv80._560_say = "Faites comme vous le sentez - Je ne vous[ENTER]laisserai pas m'arr\234ter. "
gameforge.new_quest_lv80._570_target_pos = "Rivage du Sud "
gameforge.new_quest_lv80._580_target_pos = "Rivage Occidental "
gameforge.new_quest_lv80._590_target_pos = "Rivage Oriental "
gameforge.new_quest_lv80._599_set_title = "Apr\232s une fausse piste ... "
gameforge.new_quest_lv80._600_say = "Je devrais aller \224 Yongan jeter la Glace Noire[ENTER]dans la mer. "
gameforge.new_quest_lv80._610_say = "Je devrais aller \224 Joan jeter la Glace Noire dans[ENTER]la mer. "
gameforge.new_quest_lv80._620_say = "Je devrais aller \224 Pyungmoo jeter la Glace Noire[ENTER]dans la mer. "
gameforge.new_quest_lv80._630_say_reward = "Juste au moment ou vous voulez jeter la Glace[ENTER]Noire, elle se met \224 fondre. Un liquide noir[ENTER]glisse le long de vos doigts, tombe sur le sol et[ENTER]s'\233vapore avant m\234me que vous puissiez le[ENTER]toucher. "
gameforge.new_quest_lv80._640_say = "Soudain les objets suivants apparaissent devant[ENTER]vous : "
gameforge.new_quest_lv80._650_say = "Alors que vous prenez les objets, vous \234tes[ENTER]satisfait de votre d\233cision. Et \224 pr\233sent vous[ENTER]tenez la gratitude du Dieu de Dragon dans vos[ENTER]mains. "
gameforge.new_quest_lv80._660_say = "Oh, non ! J'ai oubli\233 d'emporter la Glace Noire[ENTER]avec moi ! Je pense qu'il n'y a rien de plus \224[ENTER]faire que faire demi-tour et revenir plus tard. "
gameforge.new_quest_lv80._670_sayReward = "Vous avez de plus re\231u 120.000.000 points[ENTER]d'exp\233rience. "
gameforge.new_quest_premium_lv4 = {}
gameforge.new_quest_premium_lv4._100_npcChat = "Voir le magasin "
gameforge.new_quest_premium_lv4._100_say_reward = "Vous devez chasser: "
gameforge.new_quest_premium_lv4._10_targetVid = "La marchande "
gameforge.new_quest_premium_lv4._110_say = "Trouvez le marchand d'armes et demandez-lui[ENTER]pourquoi il ne passe plus ses nuits \224 chanter[ENTER]sous la fen\234tre de la marchande. "
gameforge.new_quest_premium_lv4._120_qSetTitle = "Trouver du lilas "
gameforge.new_quest_premium_lv4._130_notice = "Ah, tu as r\233cup\233r\233 une jolie branche de lilas\160! "
gameforge.new_quest_premium_lv4._140_notice = "Fini! Retournez vite voir le marchand d'armes! "
gameforge.new_quest_premium_lv4._150_notice = "Malheureusement, ce lilas est fan\233. "
gameforge.new_quest_premium_lv4._160_say = "Il vous manque toujours %s lilas. "
gameforge.new_quest_premium_lv4._170_say = "\199a ne suffit pas. Ce lilas ne fera que quelques[ENTER]gouttes! "
gameforge.new_quest_premium_lv4._180_say = "Ahh, le lilas! Mais il me manque toujours une[ENTER]huile de Musc. Vous ne pourrez en commander que[ENTER]dans un magasin tr\232s sp\233cial. La pi\232ce qui tourne[ENTER]en bas \224 gauche de votre \233cran vous y m\232nera.[ENTER]Vous aurez besoin de Marques du Dragon, mais vous[ENTER]en avez s\251rement dans vos manches, hein? Je vous[ENTER]serais \233ternellement reconnaissant! Apr\232s, vous[ENTER]pourrez passer prendre votre commande chez le[ENTER]magasinier. Alors, enfin, j'aurai tous les[ENTER]ingr\233dients! "
gameforge.new_quest_premium_lv4._190_say = "S'il vous pla\238t, faites vite et ramenez-moi[ENTER]l'huile de Musc! Vous recevrez une r\233compense! "
gameforge.new_quest_premium_lv4._200_say_reward = "Continuez \224 chercher jusqu'\224 ce que vous ayez[ENTER]trouv\233 %s branches de lilas! "
gameforge.new_quest_premium_lv4._20_sayTitle = "Mon tr\233sor "
gameforge.new_quest_premium_lv4._210_say = "Tuez des loups bleus afin d'en recevoir. "
gameforge.new_quest_premium_lv4._220_say = "C'est tout. Retournez vite chez le marchand[ENTER]d'armes! "
gameforge.new_quest_premium_lv4._230_qSetTitle = "L'huile de Musc "
gameforge.new_quest_premium_lv4._240_say = "Je vous remercie du fond du c\156ur. Je peux enfin[ENTER]cr\233er une nouvelle huile parfum\233e. "
gameforge.new_quest_premium_lv4._250_say = "Vous pouvez dire \224 ma tourterelle que je[ENTER]chanterai aujourd'hui sous sa fen\234tre. Elle sera[ENTER]r\233jouie. "
gameforge.new_quest_premium_lv4._260_say = "Vous m\233ritez une r\233compense: "
gameforge.new_quest_premium_lv4._270_say_reward = "%s Yangs "
gameforge.new_quest_premium_lv4._280_say = "Sans Huile de Musc, je ne pourrai pas cr\233er mon[ENTER]huile parfum\233e. Je vous en prie! Cliquez sur la[ENTER]pi\232ce en bas \224 gauche de votre \233cran et apportez[ENTER]moi un sp\233cimen. "
gameforge.new_quest_premium_lv4._290_say_reward = "Revenez avec %s x Huile de Musc! "
gameforge.new_quest_premium_lv4._300_say = "Je dois ramener de l'huile de Musc au marchand[ENTER]d'armes. Il faut que j'aille \224 la boutique (en[ENTER]cliquant sur la pi\232ce en bas \224 gauche de mon[ENTER]\233cran) afin de commander une huile parfum\233e[ENTER]inhabituelle et la r\233cup\233rer chez le magasinier. "
gameforge.new_quest_premium_lv4._30_say = "Je m'ennuie de mon tr\233sor, le marchand d'armes.[ENTER]Pendant des semaines, il a chant\233 tous les soirs[ENTER]sous ma fen\234tre, mais je ne l'ai pas entendu[ENTER]depuis quelques jours. Il a peut-\234tre peur de mon[ENTER]p\232re? Pourriez-vous d\233couvrir ce qui l'emp\234che de[ENTER]venir? "
gameforge.new_quest_premium_lv4._310_say_title = "Le marchand d'armes "
gameforge.new_quest_premium_lv4._320_say = "Oh, merci beaucoup! Ce n'\233tait qu'un emp\234chement,[ENTER]vous me dites? Je suis si contente![ENTER]Je l'attendrai ce soir. "
gameforge.new_quest_premium_lv4._330_say_reward = "Pour votre peine vous recevez: %s points[ENTER]d'exp\233rience. "
gameforge.new_quest_premium_lv4._340_say = "Retournez vite chez la marchande! "
gameforge.new_quest_premium_lv4._350_npcChat = "Lilas "
gameforge.new_quest_premium_lv4._35_qSetTitle = "Parlez avec le marchand d'armes "
gameforge.new_quest_premium_lv4._360_npcChat = "L'huile de Musc "
gameforge.new_quest_premium_lv4._40_qSetTitle = "Un nouvel ar\244me "
gameforge.new_quest_premium_lv4._45_qSetTitle = "Chassez des loups bleus "
gameforge.new_quest_premium_lv4._50_targetVid = "Marchand d'armes "
gameforge.new_quest_premium_lv4._55_qSetTitle = "Retourner au marchand d'armes "
gameforge.new_quest_premium_lv4._60_sayTitle = "Le coquin "
gameforge.new_quest_premium_lv4._65_qSetTitle = "Rapportez l'Huile de Musc au marchand d'armes. "
gameforge.new_quest_premium_lv4._70_say = "C'est vrai, je ne chante plus sous sa fen\234tre.[ENTER]C'est parce-que... ouf, c'est g\234nant d'en parler![ENTER]Mon odeur corporelle est devenue un peu[ENTER]repoussante... Je me lave et me relave, mais[ENTER]l'odeur persiste. Je voudrais cr\233er une huile[ENTER]parfum\233e afin d'ensorceler ma tourterelle avec[ENTER]mon parfum envo\251tant. L'apparence ext\233rieure[ENTER]compte beaucoup pour elle. "
gameforge.new_quest_premium_lv4._75_qSetTitle = "Vers la Marchande "
gameforge.new_quest_premium_lv4._80_say = "Je dois absolument cr\233er cette huile parfum\233e![ENTER]C'est la seule fa\231on que je pourrai \233liminer mon[ENTER]odeur corporelle r\233pugnante! "
gameforge.new_quest_premium_lv4._90_say = "Je dois m\233langer quelques ingr\233dients. En[ENTER]commen\231ant par ceux-ci: "
gameforge.notify_test_server = {}
gameforge.notify_test_server._10_chat = "Serveur test "
gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "Je suis un tr\232s vieil homme, mais je suis[ENTER]toujours en vie et en bonne sant\233 parce que je[ENTER]d\233tiens un secret particulier. J'ai d\233couvert que[ENTER]m\233langer des racines de Gango et des[ENTER]Champignons-Tue prolongeait la vie. Si vous[ENTER]voulez essayer cette potion, apportez les[ENTER]ingr\233dients n\233cessaires \224 Yu-Hawn. Il vous[ENTER]fabriquera \224 coup s\251r une de ces potions. "
gameforge.npc_talk._10_say = "Soyez calme et entra\238nez-vous. Comportez-vous[ENTER]bien et ne cherchez pas les ennuis. Vous devriez[ENTER]respecter les gens de votre empire. Compris ? "
gameforge.npc_talk._110_npcChat = "Vous paraissez assez fort ... "
gameforge.npc_talk._120_say = "Pendant de nombreuses ann\233es, le secret de notre[ENTER]force a \233t\233 transmis dans notre famille de[ENTER]g\233n\233ration en g\233n\233ration. Mon p\232re racontait que[ENTER]si vous pr\233parez une campanule comme il le faut,[ENTER]le breuvage qui en d\233coule vous donne des forces[ENTER]suppl\233mentaires pendant une courte dur\233e. Si je[ENTER]ne me trompe, Baek-Go sait comment pr\233parer ce[ENTER]breuvage. Vous devez juste lui apporter une[ENTER]campanule. "
gameforge.npc_talk._130_npcChat = "Va, r\233p\232te le dans les montagnes... "
gameforge.npc_talk._140_sayTitle = "Yu-Hwan le musicien: "
gameforge.npc_talk._150_say = "...par del\224 les collines et partout ailleurs...[ENTER]Vous aimez aussi la musique ?[ENTER]Je chante toutes sortes de chansons ici dans ma[ENTER]solitude, je ne suis donc pas impliqu\233e dans[ENTER]cette guerre. Mais sans le peuple pour me[ENTER]prot\233ger, je ne pourrais plus continuer \224 le[ENTER]faire. "
gameforge.npc_talk._160_npcChat = "Pourquoi lisez-vous autant ? "
gameforge.npc_talk._170_sayTitle = "Soon, le rat de biblioth\232que: "
gameforge.npc_talk._180_say = "Oh, aventurier. Le monde est plein de soucis, et[ENTER]seule la connaissance peut vous aider \224 survivre.[ENTER]Honorez toujours vos livres. Ils vous aideront[ENTER]dans les moments difficiles. Croyez-moi! "
gameforge.npc_talk._190_npcChat = "Avez-vous des enfants ? "
gameforge.npc_talk._200_say = "En r\233alit\233 je n'ai pas voulu d'enfants, mais...[ENTER]Bref je continue de collecter des Fleurs de Kaki[ENTER]parce que si vous les pr\233parez correctement, vous[ENTER]pouvez renforcer votre intelligence magique avec.[ENTER]Baek-Go l'a d\233couvert. Il a seulement besoin[ENTER]d'une fleur pour faire 100 breuvages magiques.[ENTER]Malheureusement la Fleur de Kaki a aussi un effet[ENTER]secondaire. Si une femme porte un collier fait de[ENTER]cette fleur, elle aura un fils. Entre vous et[ENTER]moi, ma femme l'a utilis\233 sans aucune honte. "
gameforge.npc_talk._20_npcChat = "Hmmm, quelle bonne odeur par ici ... "
gameforge.npc_talk._210_npcChat = "Quel est le probl\232me avec votre pied ? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "Je vais mieux. En faisant une promenade[ENTER]r\233cemment, j'ai tr\233buch\233 sur une Racine de Gango[ENTER]et foul\233 ma cheville. Heureusement je connais le[ENTER]docteur Baek-Go, il m'a soign\233 et donn\233 un[ENTER]conseil\160: Pour gu\233rir de petites blessures vous[ENTER]pouvez fabriquer un breuvage magique avec ces[ENTER]m\234mes Racines de Gango. Donc j'ai infus\233 ces[ENTER]vilaines racines dans un th\233 et elles m'ont[ENTER]gu\233ri\160! "
gameforge.npc_talk._240_npcChat = "Vous \234tes qui? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Je suis Wonda-Rim, le neveu de Chaegirab. Mon[ENTER]oncle est c\233l\232bre ! Le connaissez-vous ? Il fait[ENTER]beaucoup d'exp\233riences sur les breuvages magiques[ENTER]avec des herbes. Au cours ses recherches, il a[ENTER]d\233couvert que vous pouvez obtenir une bonne[ENTER]protection contre la magie si vous m\233langez 100[ENTER]Eau de Bo avec une baie. Il me semble que[ENTER]Huahn-So peut vous pr\233parer ce genre de potions[ENTER]si vous lui apportez les ingr\233dients. "
gameforge.npc_talk._270_npcChat = "Pourquoi avec-vous tant de cicatrices ? "
gameforge.npc_talk._280_sayTitle = "Balso le tra\238tre : "
gameforge.npc_talk._290_say = "Je suis un pi\232tre combattant et je me blessais[ENTER]constamment pendant la guerre. \192 tel point que[ENTER]j'ai demand\233 \224 Yu-Hwan s'il pourrait pr\233parer un[ENTER]breuvage magique pour moi qui pourrait prot\233ger[ENTER]mon corps des blessures. Il me pr\233para un m\233lange[ENTER]de sirop de campanule et de Lilas, mais[ENTER]malheureusement la protection n'\233tait pas[ENTER]suffisante. Ou peut-\234tre \233tait-ce juste ma propre[ENTER]incomp\233tence. Mais je suis s\251r que cette potion[ENTER]magique vous aidera. "
gameforge.npc_talk._300_npcChat = "Pourquoi tant de gens vous traitent-ils de tra\238tre ? "
gameforge.npc_talk._30_sayTitle = "Octavio, le propri\233taire du restaurant: "
gameforge.npc_talk._310_say = "J'ai fui la guerre et ai rejoint le Gang du Vent[ENTER]Noir. Mes camarades ne m'ont jamais pardonn\233 pour[ENTER]cela.[ENTER]Ensuite j'ai d\233couvert que les Soldats du Vent[ENTER]Noir tuent d'innocentes personnes, donc je les ai[ENTER]imm\233diatement quitt\233s. C'\233tait terrible! "
gameforge.npc_talk._320_say = "Vous avez la mort d'innocents sur la conscience ?[ENTER]Alors vous m\233ritez vraiment votre nom. Vous leur[ENTER]avez enlev\233 la vie. "
gameforge.npc_talk._330_say = "Je ne ferai rien le mal d\233sormais, pas m\234me dans[ENTER]ce monde plein d'injustices. Je ne veux pas que[ENTER]le peuple me traite de tra\238tre.[ENTER]Avez-vous quelques Yangs pour moi ? "
gameforge.npc_talk._340_npcChat = "Ils vous surnomment le savant ? "
gameforge.npc_talk._350_sayTitle = "Uriel le sage: "
gameforge.npc_talk._360_say = "Il y a tant de choses \224 apprendre dans ce vaste[ENTER]monde. L'ignorance li\233e avec la puissance[ENTER]militaire est une mauvaise combinaison. Vous ne[ENTER]voulez pas vivre comme ces soldats ignorants,[ENTER]n'est-ce pas ? La connaissance est la puissance! "
gameforge.npc_talk._370_npcChat = "On m'a dit que vous pratiquiez la m\233decine ? "
gameforge.npc_talk._380_say = "Je fais du mieux que je peux. Mais il y a de plus[ENTER]en plus de victimes chaque jour dans ce monde[ENTER]dangereux. Nous n'avons pas assez d'aide ni de[ENTER]m\233dicaments. Les temps sont durs\160! Peut-\234tre[ENTER]pourrez-vous me donner un coup de main plus[ENTER]tard\160? "
gameforge.npc_talk._390_npcChat = "Comment se porte l'industrie de la chasse ? "
gameforge.npc_talk._400_sayTitle = "Yang-Shin Le chasseur: "
gameforge.npc_talk._40_say = "Bienvenue! Notre restaurant fait parti d'une[ENTER]chaine internationale prestigieuse. Entrez et[ENTER]testez ! "
gameforge.npc_talk._410_say = "Hmm, depuis que les pierres Metin sont tomb\233es du[ENTER]ciel, les animaux sont devenus sauvages. De nos[ENTER]jours, vous risquez m\234me votre vie lorsque vous[ENTER]sortez de chez vous pour tuer quelques poulets.[ENTER]Les temps sont durs pour les chasseurs.[ENTER]Heureusement je suis l'un des meilleurs ! "
gameforge.npc_talk._420_npcChat = "D'o\249 provient votre si grande pr\233cision ? "
gameforge.npc_talk._430_say = "Je suis dou\233 avec un arc, parce que j'ai une[ENTER]recette sp\233ciale ! Quand vous m\233langez le sirop[ENTER]de Fleur de P\234cher avec du Lilas, vous obtenez un[ENTER]breuvage magique qui augmente votre pr\233cision.[ENTER]Apportez les ingr\233dients \224 Yu-Hwan, je suis s\251r[ENTER]qu'il pr\233parera le breuvage magique pour vous. "
gameforge.npc_talk._440_npcChat = "Une si jolie couronne de fleurs ... "
gameforge.npc_talk._450_say = "J'avais l'habitude de ramasser des Fleurs de[ENTER]P\234cher avec mon fr\232re.[ENTER]Mais je dois le faire seule aujourd'hui. Ces[ENTER]fleurs ne sont pas tr\232s belles, mais elles sont[ENTER]sp\233ciales.[ENTER]Si vous apportez une Fleur de P\234cher \224 Baek-Go,[ENTER]il pr\233parera un breuvage magique qui vous fera[ENTER]courir plus vite ! "
gameforge.npc_talk._460_npcChat = "Ou est votre fr\232re ? "
gameforge.npc_talk._470_say = "Ces derniers temps, mon fr\232re voyage beaucoup, et[ENTER]je m'inqui\232te pour lui. "
gameforge.npc_talk._480_npcChat = "Vendez-vous des g\226teaux de riz ? "
gameforge.npc_talk._490_sayTitle = "Yu-Rang, le vendeur de g\226teau de riz: "
gameforge.npc_talk._500_say = "\192 cause de la guerre, il est difficile de vendre[ENTER]des g\226teaux de riz. \192 cause des bandits, j'ai[ENTER]perdu tout un tas de clients. J'ignore quel[ENTER]m\233tier je devrais faire aujourd'hui. "
gameforge.npc_talk._50_say = "Bien que ce restaurant soit immense, son[ENTER]am\233nagement int\233rieur est d'une simplicit\233[ENTER]\233tonnante. "
gameforge.npc_talk._510_npcChat = "Qui a pour habitude de vous acheter des choses ? "
gameforge.npc_talk._520_say = "Un jour, un cavalier myst\233rieux est venu et a[ENTER]voulu acheter un g\226teau de riz. Il n'avait pas[ENTER]d'argent, alors j'ai accept\233 une recette en[ENTER]paiement. Cette recette explique comment[ENTER]fabriquer l'eau de Zin. Cette eau fait augmenter[ENTER]la puissance d'attaque de celui qui la boit.[ENTER]Huahn-Son est capable de cr\233er de l'eau de Zin si[ENTER]vous lui apportez de l'eau de Sim et des roses[ENTER]des montagnes. "
gameforge.npc_talk._530_npcChat = "Pourquoi semblez-vous si triste ? "
gameforge.npc_talk._540_say = "Je ne pouvais pas savoir que nos doux r\234ves de[ENTER]jeune couple mari\233 seraient bris\233s si[ENTER]impitoyablement ... Mon pauvre mari, il a[ENTER]succomb\233 pendant la bataille.[ENTER]Je vous en supplie vengez sa mort. "
gameforge.npc_talk._550_npcChat = "Tellement de personnes sont tomb\233es pendant la guerre ... "
gameforge.npc_talk._560_say = "Puisque nous perdons de plus en plus d'hommes[ENTER]pendant la guerre, nous, les femmes du village,[ENTER]unies toutes ensemble, avons demand\233 \224 Huahn-so[ENTER]d'am\233liorer l'eau de Dok qui augmente la d\233fense.[ENTER]Apr\232s de longues recherches, il a d\233couvert que[ENTER]s'il ajoute une rose des montagnes \224 l'eau de[ENTER]Dok, le breuvage magique est plus fort. Allez[ENTER]chez lui; il peut s\251rement faire le breuvage[ENTER]magique appel\233 la l'eau de Sambo si vous lui[ENTER]apportez les mat\233riaux. "
gameforge.npc_talk._570_npcChat = "Quel adorable enfant ! "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "Il pleure encore... Je ne sais pas s'il veut un[ENTER]calin, un bonbon ou ... ohhh non ! "
gameforge.npc_talk._600_npcChat = "Et vous, comment allez-vous ? "
gameforge.npc_talk._60_npcChat = "Parlez-moi de poterie. "
gameforge.npc_talk._610_say = "Mon fils ! Erf... Depuis que mon mari est mort[ENTER]pendant la guerre, je dois m'en occuper seule.[ENTER]J'essaie de subvenir \224 nos besoins. Avec l'eau de[ENTER]Bo, j'ai trouv\233 un moyen d'am\233liorer mon train de[ENTER]vie. Je dois rapporter \224 Yu-Hwan 100 sirops de[ENTER]fleurs de kaki et un champignon-tue. A partir de[ENTER]\231a, il fabrique de l'eau de Bo que je peux[ENTER]facilement vendre. J'en ai besoin d'une fa\231on ou[ENTER]d'une autre pour m'en sortir de toutes fa\231ons... "
gameforge.npc_talk._620_npcChat = "Comment se porte votre mari ? "
gameforge.npc_talk._630_sayTitle = "Aranyo : "
gameforge.npc_talk._640_say = "Mon pr\233tendu mari est mari\233 \224 ses livres. Il me[ENTER]regarde \224 peine d\233sormais. Et pourtant je ne suis[ENTER]pas laide... "
gameforge.npc_talk._650_npcChat = "Comment vont les affaires ? "
gameforge.npc_talk._660_say = "Depuis le d\233but de la guerre, le commerce a \233t\233[ENTER]mauvais. L'union des commer\231ants \233tait tr\232s[ENTER]puissante \224 une \233poque, mais c'est termin\233[ENTER]maintenant. Nous ne pouvons plus ignorer les[ENTER]animaux sauvages, les soldats du Serment blanc et[ENTER]le gang du Vent Noir comme nous avons eu[ENTER]l'habitude de faire. "
gameforge.npc_talk._670_npcChat = "Pourquoi \234tes-vous de si mauvaise humeur ? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "Harang est une mauvaise fille! Je la hais! Je[ENTER]suis faible et elle me harc\232le souvent! "
gameforge.npc_talk._700_say = "Tu es un homme et tu as des muscles. Entra\238ne-toi[ENTER]\224 l'occasion\160! "
gameforge.npc_talk._70_sayTitle = "Yonah le potier: "
gameforge.npc_talk._710_npcChat = "Que faites vous? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "J'attends Taurean. On jouait souvent ensemble, et[ENTER]on se battait aussi.Quel l\226che ! S'il ne vient[ENTER]pas de lui-m\234me, je lui ferai passer un sale[ENTER]quart d'heure ! "
gameforge.npc_talk._740_npcChat = "Taurean a peur de vous. "
gameforge.npc_talk._750_say = "Taurean est plus fort que moi. J'ai r\233fl\233chi \224[ENTER]une technique pour \234tre s\251r de gagner. Un Ninja[ENTER]blanc m'a dit que vous pouvez m\233langer de l'Eau[ENTER]de Yuong avec une baie et faire un breuvage[ENTER]magique qui permet d'augmenter la vitesse[ENTER]d'attaque. Alors je pourrai battre Taurean! Si[ENTER]vous souhaiter faire de m\234me, apportez les[ENTER]ingr\233dients \224 Huahn-So. Je suis s\251r qu'il vous[ENTER]pr\233parera la potion. "
gameforge.npc_talk._760_npcChat = "Les nouvelles connaissances... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "Mon ami, le monde est plein de myst\232res[ENTER]irr\233solus. Et moi, je suis un chercheur de[ENTER]r\233ponses, un chercheur de connaissances.[ENTER]Avez-vous d\233j\224 entendu parler d'armes et de[ENTER]Pierres d'Esprit \233piques? "
gameforge.npc_talk._790_npcChat = "Qu'est-ce que vous faites en ce moment? "
gameforge.npc_talk._800_say = "Vous savez d\233j\224 que je suis \224 la recherche de[ENTER]nouvelles connaissances. Actuellement,[ENTER]j'exp\233rimente avec une nouvelle m\233thode[ENTER]d'am\233lioration qui rend les armes plus[ENTER]performantes et les Pierres d'Esprit plus[ENTER]puissantes qu'elles ne pouvait l'\234tre auparavant. "
gameforge.npc_talk._80_say = "J'aime \234tre un potier. C'est une grande[ENTER]satisfaction de malaxer l'argile avec vos mains[ENTER]et de fabriquer un objet vous-m\234me ...[ENTER]D'habitude je cr\233e des objets assez simples. \192[ENTER]l'est, aux fronti\232res du continent, les m\233thodes[ENTER]de production sont beaucoup plus d\233velopp\233es.[ENTER]J'ai vu quelques poteries l\224 une fois et j'ai \233t\233[ENTER]vraiment inspir\233. Parfois, quand j'ai le temps,[ENTER]j'essaye d'exp\233rimenter. Mais j'ai du mal \224[ENTER]trouver toutes leurs techniques. "
gameforge.npc_talk._810_npcChat = "La recherche d'armes... "
gameforge.npc_talk._820_say = "Int\233ressant, n'est-ce pas\160? Vous voulez en savoir[ENTER]plus\160? Alors, apportez-moi la bonne arme de[ENTER]niveau 65. J'aurais aussi besoin d'un Trait\233[ENTER]d'escrime et de deux Parchemins de B\233n\233diction.[ENTER]J'essaierai ensuite de vous forger une arme[ENTER]\233pique \224 partir de ces objets. "
gameforge.npc_talk._830_say = "Je ne peux cependant pas vous promettre que cela[ENTER]va fonctionner. "
gameforge.npc_talk._840_npcChat = "Les Pierres d'Esprit... "
gameforge.npc_talk._850_say = "Les Pierres d'Esprit sont tr\232s populaires.[ENTER]Plusieurs s'en servent, mais jusqu'ici personne[ENTER]n'avait compris leurs vrais pouvoirs. Au cours de[ENTER]mes recherches, j'ai acquis de nouvelles[ENTER]connaissances \224 leur sujet. Si vous m'apportez[ENTER]une Pierre d'Esprit, je vous l'am\233liorerai. "
gameforge.npc_talk._90_npcChat = "Vous \234tes tr\232s alerte pour votre \226ge ... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "M\233daille de h\233ros "
gameforge.olympic_badge._020_say = "\192 l'aide\160! "
gameforge.olympic_badge._030_say = "Maudits voleurs...[ENTER]J'ai \233t\233 cambriol\233 la nuit derni\232re\160![ENTER]Ils ont vol\233 la m\233daille des h\233ros. Mon anc\234tre[ENTER]l'avait obtenue apr\232s avoir couru 42,195[ENTER]kilom\232tres du champ de bataille jusqu'au palais[ENTER]de l'Empereur pour lui annoncer la victoire de[ENTER]ses troupes.[ENTER]\192 pr\233sent, elle a disparu\160! "
gameforge.olympic_badge._040_say = "Ah l\224 l\224... elle a une valeur consid\233rable pour[ENTER]ma famille. Que vais-je bien pouvoir faire\160? "
gameforge.olympic_badge._050_say = "Pourriez-vous m'aider\160? "
gameforge.olympic_badge._060_npcChat = "M\233daille de h\233ros "
gameforge.olympic_badge._070_say = "Enfin, vous \234tes de retour\160![ENTER]Avez-vous retrouv\233 la m\233daille\160? "
gameforge.olympic_badge._080_say = "Mais pourquoi\160? Qu'est-ce que ces voleurs[ENTER]comptent faire de ma m\233daille\160? Pour des[ENTER]\233trangers, elle n'a aucune valeur marchande\160![ENTER]Pourriez-vous m'aider \224 la retrouver\160? "
gameforge.olympic_badge._090_npcChat = "Trouvez la m\233daille de h\233ros\160! "
gameforge.olympic_badge._100_say = "Vous revenez les mains vides\160? Oh non, je suis[ENTER]d\233sesp\233r\233. Si vous ne pouvez pas m'aider, qui le[ENTER]pourra\160? Cherchez encore, je vous en prie\160! "
gameforge.olympic_badge._110_say = "Vous avez retrouv\233 ma m\233daille\160! Mais attendez,[ENTER]elle n'est pas compl\232te. Ces sauvages l'ont[ENTER]bris\233e en cinq morceaux\160! Rapportez-les-moi tous,[ENTER]pour que je puisse reconstituer la m\233daille. "
gameforge.olympic_badge._120_say = "Ces mis\233rables ont bris\233 mon pr\233cieux h\233ritage[ENTER]familial\160![ENTER]Je vous remercie d'avoir retrouv\233 tous les[ENTER]morceaux. Je vais pouvoir les recoller. "
gameforge.olympic_badge._130_say = "Mille mercis\160! Vous avez r\233tabli l'honneur de ma[ENTER]famille.[ENTER]Vos efforts doivent \234tre r\233compens\233s. Tenez,[ENTER]prenez ceci, vous l'avez bien m\233rit\233\160! "
gameforge.olympic_badge._140_say = "Voulez-vous vraiment refuser cette mission\160? Si[ENTER]vous cliquez sur \171\160Oui\160\187, vous ne pourrez plus[ENTER]l'accepter plus tard. "
gameforge.olympic_badge._150_say = "Je comprends que vous ayez d'autres choses \224[ENTER]faire. Revenez quand vous aurez un peu de temps,[ENTER]mais ne me faites pas trop attendre\160! "
gameforge.olympic_badge._160_say = "Malheureusement, vous \234tes arriv\233 trop tard. Vous[ENTER]ne pouvez plus rien faire pour moi. Je vous[ENTER]souhaite bonne chance pour la suite\160! "
gameforge.olympic_badge._170_say = "Traquez les monstres qui m'ont vol\233 mon bien\160![ENTER]Mais prenez garde, ils \233taient tr\232s forts, au[ENTER]moins de niveau 30. Si vous me rapportez ma[ENTER]m\233daille, je vous r\233compenserai g\233n\233reusement\160! "
gameforge.olympic_badge._180_say = "Trouvez la m\233daille de h\233ros et rapportez-la \224[ENTER]Yu-Hwan. "
gameforge.olympic_badge._190_say = "Yu-Hwan a besoin d'aide, allez le voir\160! Vous le[ENTER]trouverez dans le deuxi\232me village. "
