gameforge.spider_dungeon_3floor_boss = {}
gameforge.spider_dungeon_3floor_boss._100_say = "Vous ne voulez pas me dire que vous n'\233tiez pas[ENTER]assez confiant pour le donjon des araign\233es\160?[ENTER]Vous \234tes un guerrier exp\233riment\233 \224 la technique[ENTER]sophistiqu\233e. Quelques gros crabes ne devraient[ENTER]pas \234tre un probl\232me pour vous. Mais savez-vous[ENTER]que vous vous avez besoin du ticket pour entrer[ENTER]dans la caverne\160? "
gameforge.spider_dungeon_3floor_boss._10_npcChat = "Entr\233e de la caverne du nid "
gameforge.spider_dungeon_3floor_boss._110_sendLetter = "Nouveau danger "
gameforge.spider_dungeon_3floor_boss._120_say = "Vous avez termin\233 la copie exacte de[ENTER]l'inscription. Montrez-la maintenant au[ENTER]capitaine. "
gameforge.spider_dungeon_3floor_boss._130_say = "Tr\232s bien, vous avez r\233ussi\160! Montrez-moi... Hum,[ENTER]ces caract\232res me sont inconnus, je ne comprends[ENTER]pas un mot. Vous devriez peut-\234tre demander[ENTER]conseil \224 Uriel le savant. "
gameforge.spider_dungeon_3floor_boss._140_say = "Allez voir Uriel le savant et montrez-lui[ENTER]l'inscription. Il pourra certainement la[ENTER]traduire. "
gameforge.spider_dungeon_3floor_boss._150_say = "Le capitaine me demande de d\233chiffrer cette[ENTER]inscription myst\233rieuse\160? Naturellement. J'adore[ENTER]les d\233fis intellectuels. Montrez-moi. C'est...[ENTER]Oh, c'est monstrueux. J'\233cris la traduction sur[ENTER]ce papier. Apportez-le le plus vite possible au[ENTER]capitaine puis revenez me voir. Si ce qui \233crit[ENTER]ici est vrai, alors nous courrons tous un grand[ENTER]danger\160! Vite, vite\160! "
gameforge.spider_dungeon_3floor_boss._160_say = "Vous n'\234tes pas encore all\233 voir le capitaine\160?[ENTER]S'il vous pla\238t, vous devez vous d\233p\234cher. Nous[ENTER]n'avons pas de temps \224 perdre. Il doit absolument[ENTER]lire cette lettre\160! "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "Remettez la lettre d'Uriel "
gameforge.spider_dungeon_3floor_boss._180_say = "Cette vieille t\234te de mule... C'\233tait trop[ENTER]demander, un petit merci\160? Mais bien. Il a dit[ENTER]que les informations \233taient extr\234mement[ENTER]importantes, je vais donc rapidement les[ENTER]transmettre au capitaine. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "Lettre d'Uriel "
gameforge.spider_dungeon_3floor_boss._200_say = "Oh non\160! Un araign\233e d\233moniaque et agressive a[ENTER]fait son nid au troisi\232me niveau du donjon des[ENTER]araign\233es, la baronne araign\233e. Selon[ENTER]l'inscription, une cl\233 sp\233ciale est n\233cessaire[ENTER]pour acc\233der \224 cette caverne cach\233e. Allez voir[ENTER]Uriel et demandez-lui ce qu'il sait sur cette[ENTER]cl\233. Rassemblez ensuite une troupe de guerriers[ENTER]comp\233tents et donnez l'assaut ensemble \224 la[ENTER]cachette de la baronne araign\233e\160! Tenez, j'ai un[ENTER]autre ticket pour vous. "
gameforge.spider_dungeon_3floor_boss._20_say = "Cette porte ne peut \234tre ouverte qu'avec la cl\233[ENTER]des araign\233es. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "La cl\233 des araign\233es "
gameforge.spider_dungeon_3floor_boss._220_say = "Je dois maintenant rendre visite \224 Uriel le plus[ENTER]vite possible. "
gameforge.spider_dungeon_3floor_boss._230_say = "Ah, vous \234tes de retour. Alors le capitaine a d\251[ENTER]aussi vous demander d'aller tuer la baronne[ENTER]araign\233e\160? Mais l'entr\233e de la caverne du nid est[ENTER]ferm\233e et ne peut \234tre ouverte qu'avec la cl\233 des[ENTER]araign\233es. Sa fabrication est tr\232s co\251teuse. Mais[ENTER]si vous m'apportez une glande de venin[ENTER]d'araign\233e, une poche avec des oeufs d'araign\233e,[ENTER]une toile d'araign\233e, des yeux d'araign\233e, des[ENTER]pattes d'araign\233e ainsi que le poison de la reine[ENTER]Araign\233e, je la fabriquerai pour vous. "
gameforge.spider_dungeon_3floor_boss._240_say = "Vous voulez que je fabrique la cl\233 des araign\233es[ENTER]pour vous\160? Pour cela j'ai besoin d'une glande de[ENTER]venin d'araign\233e, d'une poche avec des oeufs[ENTER]d'araign\233e, d'une toile d'araign\233e, d'yeux[ENTER]d'araign\233e, de pattes d'araign\233e ainsi que de[ENTER]poison de la reine Araign\233e. Pouvez-vous trouver[ENTER]tous les ingr\233dients\160? "
gameforge.spider_dungeon_3floor_boss._250_say = "Impressionnant\160! Vous avez trouv\233 tous les[ENTER]ingr\233dients n\233cessaires \224 la fabrication de la[ENTER]cl\233 des araign\233es. Attendez un instant. Cela ne[ENTER]doit pas durer trop longtemps... "
gameforge.spider_dungeon_3floor_boss._260_say = "Ah, r\233ussi\160! Voici la cl\233 des araign\233es. Elle[ENTER]ouvre la porte de la cachette de la baronne[ENTER]araign\233e. Je vous souhaite bonne chance, \224 vous[ENTER]et \224 vos camarades, pour votre combat contre ce[ENTER]monstre aux longues pattes\160! Mais vous devez vous[ENTER]d\233p\234cher, la cl\233 est tr\232s instable. Au bout de 24[ENTER]heures, les diff\233rents \233l\233ments qui la composent[ENTER]ne tiennent plus ensemble, la cl\233 se d\233sagr\232ge. "
gameforge.spider_dungeon_3floor_boss._270_say = "Oh oh\160! Ma crainte s'est r\233alis\233e, c'est bien en[ENTER]forgeant qu'on devient forgeron. Vous devez[ENTER]savoir que le proc\233d\233 utilis\233 pour forger cette[ENTER]cl\233 est tr\232s compliqu\233. La plus petite erreur[ENTER]fait tout \233chouer. Malheureusement, j'ai gaspill\233[ENTER]tous les ingr\233dients \224 base d'araign\233e que vous[ENTER]avez consciencieusement collect\233. \199a fonctionnera[ENTER]s\251rement mieux la prochaine fois\160! "
gameforge.spider_dungeon_3floor_boss._280_say = "Il manque encore quelque chose, je ne peux pas[ENTER]fabriquer la cl\233 des araign\233es. Voici un rappel[ENTER]des mat\233riaux n\233cessaires\160: une glande de venin[ENTER]d'araign\233e, une poche avec des oeufs d'araign\233e,[ENTER]une toile d'araign\233e, des yeux d'araign\233e, des[ENTER]pattes d'araign\233e ainsi que le poison de la reine[ENTER]Araign\233e. "
gameforge.spider_dungeon_3floor_boss._300_say = "Le chef de groupe est entr\233 dans le donjon.[ENTER]Souhaitez-vous le suivre\160? "
gameforge.spider_dungeon_3floor_boss._30_npcChat = "Recommencer la qu\234te SD3 "
gameforge.spider_dungeon_3floor_boss._310_say = "Cela vous a pris trop longtemps. La cl\233 s'est[ENTER]d\233sagr\233g\233e. Fabriquez-en une nouvelle pour[ENTER]pouvoir entrer. "
gameforge.spider_dungeon_3floor_boss._320_say = "Il y a d\233j\224 un groupe en train d'attaquer dans la[ENTER]caverne du nid de la baronne araign\233e. "
gameforge.spider_dungeon_3floor_boss._330_say = "Vous pouvez entrer quand le groupe pr\233c\233dent a[ENTER]fini ses missions. Revenez dans %s minutes. "
gameforge.spider_dungeon_3floor_boss._340_say = "Temps d'attente avant que la porte vers la[ENTER]caverne du nid de la baronne araign\233e ne soit[ENTER]rouverte\160: "
gameforge.spider_dungeon_3floor_boss._350_say = "%s minutes "
gameforge.spider_dungeon_3floor_boss._360_say = "Le guerrier qui est entr\233 avant vous dans la[ENTER]caverne pourra de nouveau se d\233placer dans dix[ENTER]secondes. Merci de patienter quelques instants. "
gameforge.spider_dungeon_3floor_boss._370_say = "Souhaitez-vous commencer un raid\160? Vous avez 20[ENTER]minutes. Personne ne peut quitter la caverne du[ENTER]nid de la baronne avant l'\233coulement de ce temps.[ENTER]Vous pouvez commencer un nouveau raid au bout[ENTER]d'une heure. "
gameforge.spider_dungeon_3floor_boss._380_say = "Pour ouvrir la porte, vous avez besoin de la cl\233[ENTER]des araign\233es. "
gameforge.spider_dungeon_3floor_boss._390_say = "Seul un chef de groupe peut utiliser la cl\233 des[ENTER]araign\233es. "
gameforge.spider_dungeon_3floor_boss._400_say = "La baronne araign\233e a \233t\233 tu\233e\160! Tous les[ENTER]guerriers seront t\233l\233port\233s hors de la caverne[ENTER]dans trois minutes. "
gameforge.spider_dungeon_3floor_boss._40_say = "Avant de forger la cl\233 "
gameforge.spider_dungeon_3floor_boss._410_say = "\199a n'a pas fonctionn\233. Essayez encore une fois. "
gameforge.spider_dungeon_3floor_boss._420_notice = "Attention\160: la baronne araign\233e s'\233nerve\160! Ses[ENTER]attaques deviennent plus puissantes, mais sa[ENTER]d\233fense est diminu\233e. "
gameforge.spider_dungeon_3floor_boss._50_npcChat = "Donjon des araign\233es 3 "
gameforge.spider_dungeon_3floor_boss._60_say = "Ah, vous \234tes l\224\160! Un \233claireur a d\233couvert un[ENTER]troisi\232me niveau dans le donjon des araign\233es.[ENTER]Des araign\233es particuli\232rement monstrueuses et[ENTER]sournoises ont d\251 se r\233fugier dans cette caverne[ENTER]jusqu'alors oubli\233e. De plus, mes hommes y ont[ENTER]trouv\233 une pierre tombale ancienne portant une[ENTER]inscription grav\233e, qu'ils n'ont pas pu[ENTER]d\233chiffrer. Partez \224 la recherche de cette pierre[ENTER]et apportez-moi une copie de l'inscription. Ce[ENTER]ticket permet d'entrer dans le donjon des[ENTER]araign\233es sans se cacher. "
gameforge.spider_dungeon_3floor_boss._70_sendLetter = "L'inscription "
gameforge.spider_dungeon_3floor_boss._80_say = "Au troisi\232me niveau du donjon des araign\233es vous[ENTER]trouverez une pierre tombale ancienne grav\233e[ENTER]d'une inscription. Faites-en une copie et[ENTER]apportez-la au capitaine. "
gameforge.spider_dungeon_3floor_boss._90_say = "Parfait, vous avez trouv\233 l'ancienne pierre[ENTER]tombale et vous avez fait une copie de[ENTER]l'inscription\160! Retournez voir le capitaine et[ENTER]montrez-la lui. "
