gameforge.subquest_01._120_targetVid = "Trouvez Yonah le Potier "
gameforge.subquest_01._130_sayReward = "La marchande a besoin d'une bouteille vide de[ENTER]Yonah le potier pour sa potion rouge. "
gameforge.subquest_01._140_sayTitle = "Yonah: "
gameforge.subquest_01._150_say = "Oh mon dieu ! Je n'en peux plus ! Je ne peux pas[ENTER]arr\234ter de tousser! Comment suis-je supposer[ENTER]travailler dans cet \233tat ?[ENTER]La marchande vous a envoy\233 ? J'ai des Bouteilles[ENTER]Vides, mais je ne peux pas vous les donner[ENTER]gratuitement . "
gameforge.subquest_01._160_say = "Je suis asthmatique. On m'a dit que les noyaux de[ENTER]p\234ches sont un rem\232de fantastique. Si vous allez[ENTER]m'en chercher quelques-uns je vous donnerai une[ENTER]bouteille vide. Vous pourrez vous en procurer[ENTER]aupr\232s des sangliers sauvages en dehors du[ENTER]village. D\232s que les fermiers plantent des noyaux[ENTER]de p\234ches, les sangliers s'empressent de les[ENTER]d\233terrer \224 nouveau. "
gameforge.subquest_01._170_sendLetter = "Trouver des noyaux de p\234che. "
gameforge.subquest_01._180_sayReward = "La marchande a besoin d'une bouteille vide de[ENTER]Yonah le potier pour sa potion rouge. Yonah, qui[ENTER]est asthmatique, vous donnera une bouteille vide[ENTER]en \233change de noyaux de p\234ches. Vous trouverez[ENTER]ces noyaux en chassant des sangliers sauvages en[ENTER]dehors du village. "
gameforge.subquest_01._190_npcChat = "Trouver des noyaux de p\234che "
gameforge.subquest_01._200_say = "Vous trouverez les noyaux aupr\232s des sangliers[ENTER]sauvages en dehors du village. D\232s que les[ENTER]fermiers les plantent, les sangliers les[ENTER]d\233terrent \224 nouveau pour les d\233vorer.[ENTER]*tousse*.*tousse*[ENTER]Merci d'avance. "
