gameforge.subquest_01._300_say = "Merci. J'esp\232re que \231a n'a pas \233t\233 trop[ENTER]difficile. Je vous donne ceci en signe de ma[ENTER]reconnaissance. Merci encore! "
gameforge.subquest_01._30_say = "Excusez-moi; si vous n'\234tes pas trop occup\233 en ce[ENTER]moment pourriez-vous m'aider? J'ai besoin d'une[ENTER]bouteille vide pour ma potion rouge. "
gameforge.subquest_01._310_sayReward = "Vous avez re\231u 1\160500 points d'exp\233rience.[ENTER]Vous avez re\231u 1\160000 Yangs. "
gameforge.subquest_01._320_say = "Vous n'avez toujours pas de bouteille vide pour[ENTER]moi? "
gameforge.subquest_01._330_say = "Voulez-vous recommencer \224 chasser des sangliers[ENTER]pour avoir une autre bouteille ou pr\233f\233rez-vous[ENTER]annuler la t\226che? "
gameforge.subquest_01._340_select = "Oui je vais chasser des sangliers. "
gameforge.subquest_01._350_select = "Non, j'annule la t\226che. "
