gameforge.subquest_02._110_say = "Parler de toute cette nourriture me met en[ENTER]app\233tit. J'ai vraiment envie d'un rago\251t de[ENTER]gibier d'ours avec du chou et deux \156ufs. "
gameforge.subquest_02._120_say = "Mon p\232re vous a-t-il dit ce qu'il voulait manger? "
gameforge.subquest_02._121_select = "Rago\251t de porc, d'ours et du chou et 1 \156uf "
gameforge.subquest_02._122_select = "Rago\251t de gibier, d'ours et du chou et 1 \156uf "
gameforge.subquest_02._123_select = "Rago\251t de gibier,d'ours,du chou et 2 \156ufs "
gameforge.subquest_02._124_select = "Oh ... j'ai oubli\233 ce que c'\233tait ... "
gameforge.subquest_02._130_say = "Je vous remercie de m'avoir apport\233 cette[ENTER]information aussi vite. Voici votre r\233compense. "
gameforge.subquest_02._140_sayReward = "Vous avez re\231u 1\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 1\160500 Yangs. "
gameforge.subquest_02._150_say = "La marchande:[ENTER]Cela ne me surprend pas, il demande toujours des[ENTER]choses inhabituelles Vous pourriez retourner le[ENTER]lui demander? "
gameforge.subquest_02._160_say = "La marchande:[ENTER]Il a vraiment dit \231a? C'est \233trange! Il n'a[ENTER]jamais appr\233ci\233 ce plat. Vous pourriez retourner[ENTER]le lui demander? Je doute qu'il ait pens\233 \224 ce[ENTER]plat. "
gameforge.subquest_02._20_say = "Vous savez bien que le marchand d'armures est mon[ENTER]p\232re, n'est-ce pas ? Je veux lui pr\233parer son[ENTER]d\238ner mais je ne sais pas ce qu'il souhaite[ENTER]manger. Pourriez-vous donc aller le lui demander.[ENTER]Je vous d\233dommagerai, bien s\251r, pour le[ENTER]d\233rangement. "
gameforge.subquest_02._30_sayReward = "La marchande voudrait savoir ce que son p\232re, le[ENTER]marchand d'armures veut manger pour le d\238ner. "
gameforge.subquest_02._40_sayReward = "Trouvez le marchand d'armures et demandez-le lui. "
gameforge.subquest_02._50_say = "Bienvenue ![ENTER][ENTER]Je fabrique des armures pour vous prot\233ger des[ENTER]attaques au couteau ou \224 l'\233p\233e. "
gameforge.subquest_02._60_say = "Ah, ma fille vous envoie? Elle se demande[ENTER]s\251rement ce qu'elle va bien pouvoir cuisiner pour[ENTER]le d\238ner. Une minute... Mmmhhh, Je voudrais un[ENTER]rago\251t \233pic\233 avec du gibier, de l'ours, un chou[ENTER]aromatique et deux \156ufs. C'est ce dont j'ai[ENTER]vraiment envie! "
gameforge.subquest_02._70_targetVid = "Le d\238ner "
gameforge.subquest_02._80_sayReward = "La marchande voudrait savoir ce que son p\232re, le[ENTER]marchand d'armures veut manger pour le d\238ner. "
gameforge.subquest_02._90_sayReward = "Retournez la voir et dites lui ce que vous avez[ENTER]trouv\233. "
