gameforge.subquest_03._20_say = "Vous pouvez m'aider? Depuis que les pierres Metin[ENTER]sont tomb\233es une maladie \233trange est apparue.[ENTER]Beaucoup de m\233decins travaillent dur, mais il[ENTER]manque un ingr\233dient pour fabriquer le[ENTER]m\233dicament. \192 l'ext\233rieur du village les animaux[ENTER]sauvages nous emp\234chent de nous d\233placer[ENTER]librement. "
gameforge.subquest_03._30_say = "Pourriez-vous aller me chercher l'ingr\233dient du[ENTER]m\233dicament? Je vous demande \231a car vous \234tes un[ENTER]aventurier. Il me faut le foie d'un loup bleu[ENTER]pour le m\233dicament. "
gameforge.subquest_03._40_say = "Apportez-moi le foie d'un loup bleu, s'il vous[ENTER]pla\238t. Pr\233venez-moi d\232s que vous l'aurez. "
gameforge.subquest_03._50_sayReward = "Depuis que les pierres Metin sont tomb\233es une[ENTER]maladie inconnue est apparue. Pour fabriquer un[ENTER]m\233dicament contre cette maladie Baek-Go a besoin[ENTER]du foie d'un loup bleu. Rapportez-le-lui. "
