gameforge.subquest_03._70_say = "Il n'existe qu'un seul moyen de se procurer le[ENTER]foie d'un loup bleu, c'est d'en trouver un et de[ENTER]le tuer. "
gameforge.subquest_03._80_say = "Je suis d\233sol\233 pour le loup bleu, mais il nous[ENTER]faut ce foie pour fabriquer le m\233dicament. Merci[ENTER]d'avance. "
