gameforge.subquest_04._10_targetVid = "Comment va Deokbae\160? "
gameforge.subquest_04._110_sayReward = "Partez et apportez la Lettre du Forgeron \224[ENTER]Deokbae, le b\251cheron. Vous le trouverez dans le[ENTER]deuxi\232me village , vous pouvez y aller par le[ENTER]portail. "
gameforge.subquest_04._120_sendLetter = "Une lettre du forgeron. "
gameforge.subquest_04._130_targetVid = "Trouvez Deokbae le b\251cheron. "
gameforge.subquest_04._140_npcChat = "Une lettre du forgeron. "
gameforge.subquest_04._150_sayTitle = "Deokbae le b\251cheron: "
gameforge.subquest_04._160_say = "Bienvenu. J'ai quelques bonnes haches ici.[ENTER]Voulez-vous acheter celle ci\160? Vous n'avez pas[ENTER]besoin d'une hache\160? Alors pourquoi \234tes vous[ENTER]ici\160? Oh, une Lettre du Forgeron. Merci. Je suis[ENTER]un b\251cheron, mais je vends aussi des pioches et[ENTER]d'autres outils. Parfois je re\231ois quelques[ENTER]commandes venant de lui. C'est comme cela que[ENTER]nous sommes devenus de bons amis. "
gameforge.subquest_04._170_say = "Merci pour la lettre. Il faudrait vraiment que[ENTER]j'aille prendre un verre avec lui un de ces[ENTER]quatre au bistro. Et passez-lui mon bonjour. "
gameforge.subquest_04._180_say = "Une lettre du forgeron? Eh bien \231a faisait un[ENTER]bail. O\249 est-elle? Vous ne l'avez pas perdue en[ENTER]route j'esp\232re? "
gameforge.subquest_04._190_select = "Voil\224. "
gameforge.subquest_04._200_select = "Oh, je ne l'ai pas. "
gameforge.subquest_04._20_say = "H\233 vous! Jeune aventurier, j'ai quelque chose \224[ENTER]vous demander. Vous connaissez un type nomm\233[ENTER]Deokbae? Il est b\251cheron, c'est un bon ami \224 moi.[ENTER]Il peut \234tre un peu ennuyeux mais il est l'un des[ENTER]derniers b\251cherons qui sache travailler dur. "
gameforge.subquest_04._210_say = "Abandonner cette qu\234te ? "
gameforge.subquest_04._220_say = "\231a me fait plaisir. Revenez me voir \224 l'occasion! "
gameforge.subquest_04._230_say = "Vous l'avez perdue? Sortez d'ici! "
gameforge.subquest_04._240_say = "Retournez la chercher chez le forgeron. Et ne la[ENTER]perdez plus! "
gameforge.subquest_04._250_sayReward = "Retournez chez le forgeron pour avoir votre[ENTER]r\233compense. "
gameforge.subquest_04._260_targetVid = "Retournez voir le forgeron "
gameforge.subquest_04._270_npcChat = "J'ai apport\233 la lettre. "
gameforge.subquest_04._280_say = "Alors, comment va Deokbae? Ha ha ha, il n'a pas[ENTER]chang\233 d'un poil. Merci. Voil\224 votre r\233compense.[ENTER]Ce n'est pas grand chose, mais cela vous sera[ENTER]certainement utile. Merci encore. "
gameforge.subquest_04._290_sayReward = "Vous gagnez 4\160000 points d'exp\233rience.[ENTER]Vous gagnez 3\160000 Yangs. "
gameforge.subquest_04._30_say = "Je ne l'ai pas vu depuis longtemps et je lui ai[ENTER]\233crit une lettre pour lui demander s'il va bien.[ENTER]Je voudrais que vous la lui portiez. Ces temps-ci[ENTER]les routes ne sont vraiment pas s\251res alors soyez[ENTER]prudent. Et ne perdez pas la lettre! "
gameforge.subquest_04._40_say = "Oh, vous ne savez pas comment aller au village[ENTER]voisin ? Appuyez sur M pour voir la mini-carte.[ENTER]Normalement un point bleu y clignote.[ENTER]Il repr\233sente le portail que vous devez prendre[ENTER]pour vous rendre au village voisin. "
