gameforge.subquest_05._40_say = "Bla, bla ... Par l'enfer... Qui \234tes vous? Ne me[ENTER]d\233rangez jamais pendant ma lecture! Argh! une[ENTER]minute. D\233sol\233 je ne voulais pas vous hurler[ENTER]dessus. Parfois dans mes lectures je tombe sur[ENTER]des choses que je ne comprends pas et c'est[ENTER]vraiment tr\232s frustrant. Pourriez-vous me donner[ENTER]un coup de main ? "
gameforge.subquest_05._50_say = "J'examine les \233ventails de guerre des chamanes.[ENTER]J'ai du mal \224 d\233terminer lesquels sont les[ENTER]meilleurs. Il m'est impossible de tous les[ENTER]tester. Uriel l'\233rudit doit tout savoir de ces[ENTER]\233ventails. Pourriez-vous aller lui demander? Je[ENTER]suis int\233ress\233 en particulier par ceux-ci:[ENTER]\201ventail aile de grue, \233ventail aquatique,[ENTER]\233ventail triple et \233ventail oiseau c\233leste. "
gameforge.subquest_05._60_say = "Je veux qu'il me classe les \233ventails en fonction[ENTER]de leurs capacit\233s d'attaque. "
