gameforge.subquest_06._130_npcChat = "L'armure de l'armurier "
gameforge.subquest_06._140_say = "Quoi encore ? Pourquoi m'emb\234tez vous encore ?[ENTER]Oh, le marchand d'Armure vous a envoy\233 ? Ce vieil[ENTER]homme est tr\232s impatient. Ce n'est pas que je ne[ENTER]veuille pas le faire. Je n'ai pas les mat\233riaux[ENTER]n\233cessaires pour cela. Pourriez-vous les obtenir[ENTER]pour moi ? Pour produire l'armure j'ai besoin de[ENTER]Minerai de fer, de Cuir et de Charbon. Vous[ENTER]pouvez obtenir le Minerai de fer aupr\232s d'Uriel,[ENTER]le Cuir aupr\232s d'Octavio et le Charbon aupr\232s[ENTER]d'Yonah. "
gameforge.subquest_06._150_select = "Je t'apporte les mat\233riaux. "
gameforge.subquest_06._160_select = "Non, pas pour l'instant. "
gameforge.subquest_06._170_say = "\202tes-vous s\251r de vouloir abandonner cette qu\234te ? "
gameforge.subquest_06._180_say = "Vous pouvez aussi le faire plus tard. Mais[ENTER]n'attendez pas trop longtemps, cette qu\234te est[ENTER]urgente. "
gameforge.subquest_06._190_say = "Bon, je suppose que je peux me les procurer[ENTER]moi-m\234me. Faites attention. "
gameforge.subquest_06._200_say = "Ne revenez plus, je pourrai enfin travailler[ENTER]tranquillement... "
