gameforge.subquest_06._260_npcChat = "Ich brauche Eisenerz. "
gameforge.subquest_06._270_say = "Merci de m'avoir rapport\233 mon livre ! Je peux \224[ENTER]pr\233sent continuer mes recherches. Tenez, voici le[ENTER]minerai de fer. Faites-en bon usage. "
gameforge.subquest_06._280_say = "Vous avez besoin de minerai de fer ? Je peux vous[ENTER]en donner. Mais j'ai un service \224 vous demander :[ENTER]j'ai r\233cemment perdu un livre alors que j'\233tais[ENTER]pourchass\233 par une meute de chiens errants. Je[ENTER]pense que ces chiens errants ont mon livre.[ENTER]Rapportez le moi et je vous donnerai le minerai[ENTER]de fer. "
gameforge.subquest_06._285_say = "Uriel vous donnera du minerai de fer si vous lui[ENTER]rapportez son livre vol\233 par les chiens errants. "
gameforge.subquest_06._290_npcChat = "Ich brauche Eisenerz. "
gameforge.subquest_06._300_say = "Plus de minerai de fer ? Je vous en ai d\233j\224[ENTER]donn\233. Je n'en ai plus du tout. "
gameforge.subquest_06._30_say = "Je vous remercie d'avoir rendu service \224 ma[ENTER]fille. Maintenant c'est \224 moi de vous demander de[ENTER]l'aide. J'ai command\233 des armures au forgeron[ENTER]mais je n'en ai aucune nouvelle.[ENTER]Pourriez-vous aller voir o\249 il en est? "
gameforge.subquest_06._310_npcChat = "J'ai besoin de cuir. "
gameforge.subquest_06._320_sayTitle = "Octavio: "
gameforge.subquest_06._330_say = "Merci pour la bile ! Je peux enfin retourner[ENTER]pr\233parer mes plats d\233licieux. Hmm... Tenez,[ENTER]prenez ce Cuir comme r\233compense. "
gameforge.subquest_06._340_say = "Je peux vous donner du cuir.[ENTER]Cependant, rien n'est gratuit dans cette vie\160![ENTER]Que diriez-vous d'un \233change\160? Je vous donnerai[ENTER]du cuir si vous me rapportez une bile.[ENTER]J'en utilise souvent pour mes recettes.[ENTER]Si \231a ne vous int\233resse pas, ce n'est pas grave. "
gameforge.subquest_06._345_say = "Octavio vous donnera du cuir si vous lui[ENTER]rapportez une bile. "
gameforge.subquest_06._350_npcChat = "J'ai besoin de cuir. "
gameforge.subquest_06._360_say = "Je vous ai d\233j\224 donn\233 du cuir. L'avez-vous perdu?[ENTER]Je n'en ai plus. "
gameforge.subquest_06._370_npcChat = "J'ai besoin de charbon. "
gameforge.subquest_06._380_say = "Merci pour la terre glaise. \201change de bons[ENTER]proc\233d\233s : voici votre charbon. \192 bient\244t ! "
gameforge.subquest_06._390_say = "Quoi donc ? Vous \234tes ici pour du charbon ? J'en[ENTER]ai plein. Mais ce n'est pas gratuit. Vous devez[ENTER]faire quelque chose pour moi d'abord. "
gameforge.subquest_06._395_say = "Yonah vous donnera du charbon si vous lui[ENTER]rapportez de la boue. Il vous faudra des[ENTER]sangliers rouges. "
gameforge.subquest_06._400_say = "Je suis \224 court de terre glaise pour ma poterie.[ENTER]Si vous m'en apportez, je vous donnerai un peu de[ENTER]Charbon. L'id\233al serait de tuer des sangliers[ENTER]rouges sauvages pour vous en procurer. Merci[ENTER]d'avance ! "
gameforge.subquest_06._40_select = "Oui, je vais le faire. "
