gameforge.subquest_07._100_say = "Attendez une seconde, je veux \234tre certain que[ENTER]c'est le bon livre... Hmmm, c'est vraiment[ENTER]fantastique. Je vais enfin pouvoir pr\233parer cette[ENTER]recette. Merci ! "
gameforge.subquest_07._10_targetVid = "Le meilleure livre de cuisine "
gameforge.subquest_07._110_say = "Hmmm, pour faire cela, j'aurais besoin de...[ENTER]Attendez mon ami! Pourrais-je vous demander un[ENTER]autre service?[ENTER]J'ai presque tous les ingr\233dients n\233cessaires[ENTER]pour cuisiner ce plat merveilleux, mais il me[ENTER]manque un intestin de loup gris. Cet ingr\233dient[ENTER]n'est pas facile \224 trouver et il doit \234tre tr\232s[ENTER]frais! Pourriez-vous m'en rapporter un s'il vous[ENTER]pla\238t? "
gameforge.subquest_07._120_sayReward = "Apportez un intestin de loup \224 Octavio. Vous[ENTER]pourrez vous en procurer sur les loups gris. "
gameforge.subquest_07._130_npcChat = "J'ai l'intestion de loup. "
gameforge.subquest_07._140_say = "Merci, je peux enfin pr\233parer cette recette rare.[ENTER]Cela va \234tre un festin ! Je vous suis vraiment[ENTER]reconnaissant pour votre aide. Acceptez cette[ENTER]modeste r\233compense. "
gameforge.subquest_07._150_sayReward = "Vous avez re\231u 12\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 5\160000 Yangs.[ENTER]Vous avez re\231u une griffe de loup. "
gameforge.subquest_07._160_say = "J'ai besoin d'entrailles de loups gris. S'il vous[ENTER]pla\238t trouvez-en pour moi. "
gameforge.subquest_07._20_npcChat = "Le meilleure livre de cuisine "
gameforge.subquest_07._30_say = "Ah, vous connaissez peut-\234tre Soon? C'est un rat[ENTER]de biblioth\232que qui passe tout son temps dans les[ENTER]livres. J'ai entendu dire qu'il a un livre de[ENTER]cuisine fantastique. S'il vous pla\238t voulez-vous[ENTER]v\233rifier si c'est le cas? On dit que ce livre est[ENTER]rempli de recettes rares et exotiques que[ENTER]j'aimerais apprendre. "
gameforge.subquest_07._40_targetVid = "Demandez \224 Soon "
gameforge.subquest_07._50_sayReward = "Demandez \224 Soon s'il poss\232de un livre de cuisine[ENTER]exotique. "
gameforge.subquest_07._60_npcChat = "Avez-vous un livre de cuisine sp\233cial ? "
gameforge.subquest_07._70_say = "Blablabla ... Oh, encore vous\160?! Que[ENTER]voulez-vous\160? Oui j'ai un livre de cuisine qui[ENTER]contient des recettes exotiques. Prenez-le si[ENTER]vous voulez, je n'en ai pas besoin. Mais s'il[ENTER]vous plait arr\234tez de me d\233ranger quand je suis[ENTER]en train de lire\160! "
