gameforge.subquest_08._120_sayTitle = "Le marchand d'armes: "
gameforge.subquest_08._130_say = "Hein? quoi? des g\226teaux de riz? pour quoi faire?[ENTER]Voil\224 une arme que je ne connais pas. Je ne[ENTER]comprends pas ...[ENTER][ENTER]Aaah, des g\226teaux de riz qui se mangent. Vous[ENTER]devriez plut\244t demander \224 Octavio, il conna\238t[ENTER]tout ce qui est comestible. "
gameforge.subquest_08._140_makequestbutton = "G\226teau de riz "
gameforge.subquest_08._150_sayReward = "Allez voir Octavio et demandez lui ce qu'il sait[ENTER]\224 propos des g\226teaux de riz. "
gameforge.subquest_08._160_say = "Hmmm, c'est ce genre de g\226teau avec des cerises[ENTER]et du sucre, c'est \231a? Oui, je connais. Vous[ENTER]pourrez vous en procurer aupr\232s du marchand[ENTER]ambulant vendeur de g\226teaux de riz dans le[ENTER]village d'\224-c\244t\233. "
gameforge.subquest_08._170_select = "Non, je n'ai pas le temps. "
gameforge.subquest_08._180_say = "Un long chemin vous attend. \192 la prochaine. "
gameforge.subquest_08._190_say = "Quel dommage, je peux t'assurer que tu manques[ENTER]quelque chose... \192 bient\244t ! "
gameforge.subquest_08._200_say = "C'est tr\232s aimable \224 vous. Bon voyage. "
gameforge.subquest_08._20_say = "Excusez-moi, aidez-moi s'il vous pla\238t... Vous[ENTER]entendez mon b\233b\233 crier? Je n'arrive pas \224 le[ENTER]calmer. Je ne sais plus quoi faire. Mon b\233b\233[ENTER]adore les g\226teaux de riz, je pense que lui en[ENTER]donner un le calmerait. Je crois que le marchand[ENTER]d'armes sait ou en trouver. Voudriez-vous lui[ENTER]demander pour moi? "
gameforge.subquest_08._210_makequestbutton = "Trouvez Yu-Rang "
gameforge.subquest_08._220_targetVid = "G\226teau de riz "
gameforge.subquest_08._230_sayReward = "Allez voir Yu-Rang, la vendeuse de g\226teaux de[ENTER]riz. Vous la trouverez au village voisin. "
gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "Est-ce que je peux vous aider? Oh! Des g\226teaux de[ENTER]riz, bien s\251r je vais vous en donner! Mais... une[ENTER]fille nomm\233e Taurean vient souvent ici pour[ENTER]m'emb\234ter. Je ne sais pas pourquoi, elle vient[ENTER]juste m'emb\234ter et repart. Si vous allez lui en[ENTER]toucher deux mots je vous donnerez des g\226teaux de[ENTER]riz. D'accord? "
gameforge.subquest_08._260_makequestbutton = "Trouvez Taurean "
gameforge.subquest_08._270_sayReward = "Yu-Rang est tout le temps emb\234t\233e par Taurean.[ENTER]Grondez le et elle vous donnera un g\226teau de riz. "
gameforge.subquest_08._280_npcChat = "Pourquoi emb\234tes-tu Yu-Rang? "
gameforge.subquest_08._290_say = "Qui est-ce que j'emb\234te? Oh, la fille qui vend[ENTER]des g\226teaux de riz? C'est juste pour m'amuser,[ENTER]vous voyez ? Ce n'est pas ce que vous pensiez![ENTER]Je ne voulais pas la taquiner. Je m'ennuyais et[ENTER]elle ne semblait pas tr\232s occup\233e, alors j'ai[ENTER]voulu discuter avec elle. Je ne voulais pas[ENTER]l'emb\234ter. Je ne le ferai plus, Promis! "
gameforge.subquest_08._300_makequestbutton = "Retournez voir Yu-Rang "
gameforge.subquest_08._30_select = "Accepter "
gameforge.subquest_08._310_targetVid = "G\226teau de riz "
gameforge.subquest_08._320_sayReward = "Taurean n'emb\234tera plus Yu-Rang. Allez la voir et[ENTER]prenez le g\226teau de riz. "
gameforge.subquest_08._330_say = "Ha, ha! Vous avez puni Taurean! Merci. Maintenant[ENTER]il y r\233fl\233chira \224 deux fois avant de revenir ici.[ENTER]Voici votre g\226teau de riz. Bon app\233tit! "
