gameforge.subquest_08._350_targetVid = "G\226teau de riz pour Ah-Yu "
gameforge.subquest_08._360_sayReward = "Vous avez re\231u le g\226teau de riz. Apportez le \224[ENTER]Ah-Yu. Vous la trouverez elle et son enfant au[ENTER]village voisin. "
gameforge.subquest_08._370_npcChat = "Voici le g\226teau de riz pour votre fils. "
gameforge.subquest_08._380_say = "Vous m'apportez le g\226teau de riz ! Merci[ENTER]beaucoup. Oh regardez, mon b\233b\233 a cess\233 de[ENTER]pleurer et mange son g\226teau avec plaisir. Merci[ENTER]pour votre aide. "
gameforge.subquest_08._390_sayReward = "Vous avez re\231u 26\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 10\160000 Yangs. "
gameforge.subquest_08._40_say = "Mais ... je ne peux pas quitter cet endroit et le[ENTER]b\233b\233 terrorise le voisinage entier... Cela ne[ENTER]prendra pas beaucoup de temps ! \202tes-vous s\251r que[ENTER]vous n'avez pas assez de temps ? "
gameforge.subquest_08._50_say = "Je suppose que vous \234tes trop occup\233?[ENTER]S'il vous pla\238t revenez plus tard.[ENTER]Chut, ne pleure pas mon petit. "
gameforge.subquest_08._60_say = "Je pense que je dois demander \224 quelqu'un[ENTER]d'autre. Bonne journ\233e ! "
gameforge.subquest_08._70_say = "Vous voulez vraiment m'aider? Merci beaucoup! "
