gameforge.subquest_10._100_sayReward = "Demandez au forgeron o\249 se trouve l'\233pingle \224[ENTER]cheveux. "
gameforge.subquest_10._10_targetVid = "Trouvez l'\233pingle \224 cheveux "
gameforge.subquest_10._110_npcChat = "L'\233pingle \224 cheveux vol\233e. "
gameforge.subquest_10._120_say = "Quoi? Elle pense que je la lui ai vol\233e, son[ENTER]\233pingle? Mais c'est pas croyable! C'est \231a ce[ENTER]qu'elle pense de moi? Je travaillais dans ma[ENTER]forge! Par contre... Je ne devrais peut-\234tre pas[ENTER]vous le dire mais le marchand d'armes tournait[ENTER]autour du magasin un peu plus t\244t! "
gameforge.subquest_10._130_makequestbutton = "L'\233pingle \224 cheveux vol\233e. "
gameforge.subquest_10._140_sayReward = "Questionnez le marchand d'armes \224 propos de[ENTER]l'\233pingle vol\233e. "
gameforge.subquest_10._150_say = "Quoi? Vous croyez que j'ai vol\233 l'\233pingle de la[ENTER]marchande? Jamais je ne ferais une chose[ENTER]pareille! Je vous assure que je n'y suis pour[ENTER]rien! Cela dit... Je suis bien all\233 dans le[ENTER]magasin voir la marchande mais elle n'\233tait pas[ENTER]l\224... Par contre il y avait une arch\232re du[ENTER]Serment Blanc. D\232s qu'elle m'a vu elle s'est[ENTER]pr\233cipit\233e dehors. Elle a peut-\234tre vol\233[ENTER]l'\233pingle \224 cheveux. "
gameforge.subquest_10._160_sayReward = "R\233cup\233rez l'\233pingle \224 cheveux vol\233e par l'arch\232re[ENTER]du Serment Blanc. "
gameforge.subquest_10._170_sendLetter = "Vous avez trouv\233 l'\233pingle \224 cheveux "
gameforge.subquest_10._180_targetVid = "Allez voir la marchande. "
gameforge.subquest_10._190_npcChat = "J'ai votre \233pingle \224 cheveux. "
gameforge.subquest_10._200_say = "Oh, merci beaucoup. Je suis si heureuse d'avoir[ENTER]r\233cup\233r\233 ma pr\233cieuse \233pingle \224 cheveux! Vous[ENTER]m'aidez si souvent. Comment pourrais-je jamais[ENTER]vous rendre la pareille? J'ai un ticket[ENTER]d'\233quitation, ce n'est pas grand chose mais je[ENTER]n'en ai plus besoin puisque je peux difficilement[ENTER]laisser mon magasin sans surveillance. Prenez-la[ENTER]en signe de ma gratitude.[ENTER]Merci encore. "
gameforge.subquest_10._20_say = "S'il vous pla\238t \233coutez-moi, j'ai un gros[ENTER]probl\232me. J'ai laiss\233 le magasin un instant pour[ENTER]faire quelque chose d'important et quelqu'un en a[ENTER]profit\233 pour me voler mon \233pingle \224 cheveux[ENTER]favorite. "
gameforge.subquest_10._210_sayReward = "Vous avez re\231u 60\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 10\160000 Yangs.[ENTER]Vous avez re\231u un ticket d'\233quitation. "
gameforge.subquest_10._220_say = "Vous n'avez pas encore retrouv\233 mon \233pingle \224[ENTER]cheveux ? J'esp\232re que vous arriverez \224 la[ENTER]r\233cup\233rer. "
gameforge.subquest_10._230_select = "Abandonner "
gameforge.subquest_10._240_say = "Voulez-vous r\233ellement abandonner? "
gameforge.subquest_10._250_say = "On ne peut pas dire que ce sont des chiffes[ENTER]molles. Peut-\234tre pourriez-vous vous reposer un[ENTER]peu et tenter \224 nouveau plus tard ? "
gameforge.subquest_10._260_say = "O\249 est mon \233pingle \224 cheveux pr\233f\233r\233e? Je suppose[ENTER]que vous n'y \234tes pas arriv\233... au revoir. "
gameforge.subquest_10._270_say = "Merci beaucoup. Cela signifie vraiment beaucoup[ENTER]pour moi. "
gameforge.subquest_10._30_say = "C'est mon p\232re qui m'a offert cette splendide[ENTER]\233pingle \224 cheveux pour mon anniversaire, j'y[ENTER]tiens beaucoup. Je ne peux pas laisser mon[ENTER]magasin encore une fois, sinon on va encore me[ENTER]voler. Vous pourriez la chercher pour moi? Je[ENTER]suspecte le forgeron parce qu'il m'avait dit[ENTER]qu'il l'aimait beaucoup. "
gameforge.subquest_10._40_select = "Je vais la chercher pour vous "
gameforge.subquest_10._50_say = "Voulez-vous r\233ellement abandonner cette qu\234te? "
gameforge.subquest_10._60_say = "\192 la prochaine. Portez-vous bien! "
gameforge.subquest_10._70_say = "O\249 est mon \233pingle \224 cheveux? Au revoir... "
gameforge.subquest_10._80_say = "Vous allez la chercher pour moi? Merci beaucoup! "
gameforge.subquest_10._90_targetVid = "Retournez voir le forgeron. "
gameforge.subquest_11 = {}
gameforge.subquest_11._100_targetVid = "Questionnez Yu-Hwan \224 propos du fr\232re de Mirine. "
gameforge.subquest_11._10_targetVid = "Trouvez mon fr\232re "
gameforge.subquest_11._110_npcChat = "Avez-vous vu le fr\232re de Mirine? "
gameforge.subquest_11._120_say = "Je suis tomb\233 amoureux sans m\234me savoir ce qu'est[ENTER]l'amour ... Ah la la ...[ENTER]Qui cherchez-vous ? Le fr\232re de Mirine ? Nous[ENTER]avons rapidement discut\233 avant qu'il n'atteigne[ENTER]les montagnes afin d'y chercher des plantes.[ENTER]J'ignore ou il se trouve \224 pr\233sent. Le chasseur[ENTER]du village va souvent dans les montagnes.[ENTER]Pourquoi ne pas lui demander ? Ah la la, l'amour[ENTER]c'est triste mais tellement beau ... "
gameforge.subquest_11._130_targetVid = "Questionnez Yang-Shin \224 propos du fr\232re de Mirine. "
gameforge.subquest_11._140_say = "Le fr\232re de Mirine ? Il cherchait des herbes dans[ENTER]les montagnes. Il \233tait si heureux de trouver[ENTER]quelques herbes rares. Il avait voulu acheter de[ENTER]nouvelles robes pour sa s\156ur avec le b\233n\233fice[ENTER]qu'il avait fait. C'est quelqu'un de vraiment[ENTER]gentil. Je suis s\251r qu'il sera de retour dans[ENTER]quelques jours. Vous ne pensez pas ? "
gameforge.subquest_11._150_targetVid = "Donnez des nouvelles \224 Mirine. "
gameforge.subquest_11._160_npcChat = "Des nouvelles du fr\232re de Mirine. "
gameforge.subquest_11._170_say = "Regardez, j'ai re\231u cette lettre de mon fr\232re ![ENTER]Il m'a \233crit qu'il a trouv\233 un endroit avec plein[ENTER]de vari\233t\233s de plantes et qu'il n'est pas pr\234t de[ENTER]rentrer \224 la maison.[ENTER]Je suis d\233sol\233e, je n'aurais pas du vous emb\234ter[ENTER]avec mes histoires. Tenez, ce n'est pas beaucoup,[ENTER]mais j'esp\232re que vous accepterez et que vous me[ENTER]pardonnerez. Merci encore d'avoir sacrifi\233 toute[ENTER]une journ\233e pour moi. "
gameforge.subquest_11._180_sayReward = "Vous gagnez 122\160000 points d'exp\233rience.[ENTER]Vous gagnez 5\160000 Yangs. "
gameforge.subquest_11._20_npcChat = "Trouvez mon fr\232re "
gameforge.subquest_11._30_say = "Puis-je vous demander une faveur? Mon fr\232re est[ENTER]parti depuis assez longtemps et je suis sans[ENTER]nouvelles de lui. Je commence \224 m'inqui\233ter.[ENTER]Pourriez-vous partir \224 sa recherche ? "
gameforge.subquest_11._40_say = "Mon fr\232re devait rendre visite \224 Yu-Hwan le[ENTER]musicien du le village d'\224 cot\233. Si vous allez le[ENTER]voir il pourra s\251rement vous donner des nouvelles[ENTER]de mon fr\232re. Merci d'avance. "
gameforge.subquest_11._50_select = "Oui, je vais le faire. "
gameforge.subquest_11._60_say = "Souhaitez-vous abandonner cette qu\234te ? "
gameforge.subquest_11._70_say = "Merci. S'il vous pla\238t retrouvez-le, je suis[ENTER]vraiment tr\232s inqui\232te. \192 bient\244t j'esp\232re. "
gameforge.subquest_11._80_say = "Dommage que vous ne puissiez pas m'aider. Au[ENTER]revoir. "
gameforge.subquest_11._90_say = "Vous allez partir \224 sa recherche? Merci beaucoup![ENTER]Je suis tr\232s inqui\232te. Bonne chance! "
gameforge.subquest_12 = {}
gameforge.subquest_12._100_qSetTitle = "Mi-Jung du Serment Blanc "
gameforge.subquest_12._10_targetVid = "Tuez Mi-Jung du Serment Blanc "
gameforge.subquest_12._110_sayReward = "Retournez voir le gardien du village. "
gameforge.subquest_12._120_sayTitle = "Mi-Jung du Serment Blanc "
gameforge.subquest_12._130_sayReward = "Allez tuer Mi-Jung du Serment Blanc. Quand ce[ENTER]sera fait, retournez voir le gardien "
gameforge.subquest_12._140_targetVid = "Allez voir le gardien. "
gameforge.subquest_12._150_sayTitle = "Vous avez tu\233 Mi-Jung du Serment Blanc "
gameforge.subquest_12._160_sayReward = "Retournez voir le gardien pour recevoir votre[ENTER]r\233compense. "
gameforge.subquest_12._170_npcChat = "J'ai tu\233 Mi-Jung. "
gameforge.subquest_12._180_say = "Oh, vous \234tes aussi fort qu'on me l'avait dit![ENTER]Vous \234tes fantastique. Merci, gr\226ce \224 vous nous[ENTER]aurons moins de probl\232mes avec le Serment Blanc[ENTER]d\233sormais. Bien jou\233 ! "
gameforge.subquest_12._190_sayReward = "Vous avez re\231u 122\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 20\160000 Yangs.[ENTER]Vous avez re\231u un bracelet d'argent. "
gameforge.subquest_12._20_say = "Venez par ici un instant. Vous savez manier une[ENTER]arme. Notre Capitaine fait souvent votre \233loge. "
gameforge.subquest_12._30_say = "Pourriez-vous nous d\233barrasser de Mi-Jung du[ENTER]Serment Blanc? Prot\233ger le village et ses[ENTER]habitants des attaques du Serment Blanc est une[ENTER]lourde t\226che. Si nous tuons Mi-Jung, un de leurs[ENTER]leaders, la situation s'am\233liorera. La s\233curit\233[ENTER]du village repose entre vos mains! J'ai confiance[ENTER]en vous! "
gameforge.subquest_12._40_select = "Oui, je vais le faire. "
gameforge.subquest_12._50_select = "Pas maintenant. "
gameforge.subquest_12._60_say = "Vous ne voulez vraiment pas nous aider? "
gameforge.subquest_12._70_say = "Je suppose que ce n'est pas le bon moment. \192 la[ENTER]prochaine. "
gameforge.subquest_12._80_say = "Si vous ne voulez pas nous aider, je ne peux rien[ENTER]y faire. Allez-vous-en... "
gameforge.subquest_12._90_say = "Vous ne voulez vraiment pas nous aider? "
gameforge.subquest_13 = {}
gameforge.subquest_13._100_targetVid = "Allez voir Ariyoung. "
gameforge.subquest_13._10_targetVid = "Mat\233riaux pour fabriquer des armes. "
gameforge.subquest_13._110_targetVid = "Allez voir Ah-Yu. "
gameforge.subquest_13._120_sayReward = "Le marchand d'armes a besoin de votre aide.[ENTER]Demandez du fer \224 Uriel et du Lin \224 Ariyoung et[ENTER]apportez-lui. "
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz. "
gameforge.subquest_13._140_say = "Vous avez besoin de minerai de fer? Je pourrais[ENTER]vous en donner si vous me rendez un service. "
gameforge.subquest_13._150_say = "J'ai perdu quelque chose en tentant de sauver ma[ENTER]vie, poursuivi par des tigres : C'est un colis[ENTER]contenant d'importants livres, attach\233s ensemble[ENTER]par du tissu. Sans ces livres, je ne peux[ENTER]continuer mes recherches sur les pierres Metin.[ENTER]Rapportez-moi mon colis s'il vous plait et je[ENTER]vous donnerai du Fer en remerciement. "
gameforge.subquest_13._160_npcChat = "J'ai votre colis. "
gameforge.subquest_13._170_say = "Merci! Je fais vraiment trop souvent appel \224 vos[ENTER]services. Tenez, voici du minerai de fer.[ENTER]J'esp\232re qu'il vous sera utile. "
gameforge.subquest_13._180_say = "Quoi ? Vous avez besoin de plus de Fer ? Vous[ENTER]savez que \231a ne pousse pas sur les arbres ? Je[ENTER]peux vous en donner, mais j'ai une faveur \224 vous[ENTER]demander avant. Des tigres ont vol\233 mon colis.[ENTER]J'ai du m'enfuir pour sauver ma vie et mon paquet[ENTER]plein d'importants documents est tomb\233.[ENTER]Sans mes documents, mes recherches concernant les[ENTER]pierres Metin ne peuvent aboutir. Rapportez-moi[ENTER]le colis que les Tigres m'ont vol\233. "
gameforge.subquest_13._190_say = "Je vous l'ai d\233j\224 donn\233. Vous ne vous en rappelez[ENTER]pas? "
gameforge.subquest_13._200_sayTitle = "Colis trouv\233 "
gameforge.subquest_13._20_npcChat = "Mat\233riaux pour armes "
gameforge.subquest_13._210_say = "Vous avez trouv\233 le colis d'Uriel. Retournez le[ENTER]voir. "
gameforge.subquest_13._220_npcChat = "J'ai besoin de lin. "
gameforge.subquest_13._230_say = "Vous avez besoin de Lin ? J'en ai donn\233 \224 Ah-Yu.[ENTER]Attendez ![ENTER]Si vous allez la voir, pouvez-vous lui remettre[ENTER]cette lettre ? Nous sommes bons amis mais \224 cause[ENTER]de son enfant nous n'avons pas pu nous voir[ENTER]depuis longtemps. J'ai ajout\233 sur la lettre[ENTER]qu'elle serait aimable de vous donner du Lin,[ENTER]comme \231a tout le monde est content ![ENTER]Transmettez-lui mon bon souvenir. "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Ah-Yu vous a bien donn\233 du lin, n'est-ce pas? "
gameforge.subquest_13._250_npcChat = "La lettre de Ariyoung. "
gameforge.subquest_13._260_say = "Une lettre d'Ariyoung ? C'est bon d'avoir de ses[ENTER]nouvelles apr\232s tout ce temps. Avant nous[ENTER]essayions de nous voir de temps-en temps. Mais[ENTER]ces derniers temps ce fut un peu compliqu\233.[ENTER]Attendez un peu, il me dit que vous avez besoin[ENTER]de Lin. Ariyoung m'en avait donn\233 un peu. Je peux[ENTER]donc vous en donner. Merci de m'avoir apport\233[ENTER]cette lettre. Je vais lui r\233pondre de suite ... "
gameforge.subquest_13._270_qSetTitle = "Retournez voir le marchand d'armes "
gameforge.subquest_13._280_targetVid = "Allez voir le marchand d'armes. "
gameforge.subquest_13._290_sayTitle = "Donner les mat\233riaux. "
gameforge.subquest_13._300_sayReward = "J'ai tous les mat\233riaux. Direction : le marchand[ENTER]d'armes. "
gameforge.subquest_13._30_say = "H\233, pourriez-vous me rendre service? Je voudrais[ENTER]cr\233er de nouveaux types d'armes. Ce n'est pas[ENTER]facile de trouver les mat\233riaux ad\233quats. J'ai[ENTER]beaucoup de commandes \224 traiter et je n'ai pas le[ENTER]temps d'en chercher. Pourriez-vous le faire pour[ENTER]moi? "
gameforge.subquest_13._310_say = "Bien jou\233. Vous \234tes vraiment rapide.[ENTER]Je vais me mettre imm\233diatement au travail.[ENTER]*bruit de marteau*[ENTER]Voici les nouvelles armes que j'ai mises au point.J'ai fait de mon mieux, j'esp\232re que vous[ENTER]appr\233ciez la v\244tre. Faites-en bon usage\160! "
gameforge.subquest_13._320_sayTitle = "R\233compense: "
gameforge.subquest_13._330_sayReward = "Vous avez re\231u 122\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 20\160000 Yangs. "
gameforge.subquest_13._340_sayReward = "Vous avez re\231u une \233p\233e large +3. "
gameforge.subquest_13._350_sayReward = "Vous avez re\231u des dagues ciseaux +3. "
gameforge.subquest_13._360_sayReward = "Vous avez re\231u un \233ventail du paon +3. "
gameforge.subquest_13._40_say = "Bien s\251r je vous r\233compenserai. D\232s que les armes[ENTER]seront pr\234tes je vous en donnerai une. Voici les[ENTER]mat\233riaux dont j'ai besoin: Minerai de Fer et[ENTER]Lin. Procurez-vous le Fer aupr\232s d'Uriel, et le[ENTER]Lin aupr\232s d'Ariyoung. Faites-moi savoir quand[ENTER]vous aurez tout. "
gameforge.subquest_13._50_say = "Vous ne voulez vraiment pas le faire? "
gameforge.subquest_13._60_say = "Je me doute que \231a fasse beaucoup pour vous.[ENTER]Revenez quand vous aurez plus de temps ! "
gameforge.subquest_13._70_say = "Si vous ne voulez pas le faire, tant pis. Au[ENTER]revoir. "
gameforge.subquest_13._80_say = "Parfait ![ENTER]D\232s que les armes seront termin\233es, je vous en[ENTER]donnerai une. Bonne chance. "
gameforge.subquest_13._90_sendLetter = "Cherchez les mat\233riaux "
gameforge.subquest_15 = {}
gameforge.subquest_15._100_targetVid = "Retournez voir le Garde du Village "
gameforge.subquest_15._10_targetVid = "Eun-Jung du Serment Blanc "
gameforge.subquest_15._110_sayReward = "Vous avez tu\233 Eun-Jung du Serment Blanc.[ENTER]Retournez voir le Garde du Village et[ENTER]racontez-lui. "
gameforge.subquest_15._120_say = "Vous \234tes formidable ! Encore meilleur que ce que[ENTER]j'esp\233rais. Nous ne pouvions rien faire face \224[ENTER]ces deux chefs du Serment Blanc, et vous les avez[ENTER]battu comme \231a sans effort ! "
gameforge.subquest_15._130_say = "C'est incroyable. Il faut faut une r\233compense de[ENTER]taille. Prenez la s'il vous plait et continuez de[ENTER]faire perdurer la paix dans notre village. "
gameforge.subquest_15._140_sayReward = "Vous avez re\231u 150\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 25\160000 Yangs.[ENTER]Vous avez re\231u un collier d'or +4. "
gameforge.subquest_15._20_say = "Venez par ici.[ENTER]Je n'ai entendu que du bien \224 votre sujet par le[ENTER]Capitaine. Vous semblez n'avoir peur de rien.[ENTER]C'est pourquoi j'ai \224 nouveau besoin de votre[ENTER]aide : le Serment Blanc est encore plus cruel et[ENTER]fort qu'avant ! "
gameforge.subquest_15._30_say = "Vous avez battu Mi-Jung, chef du Serment Blanc.[ENTER]Mais nous sommes toujours en danger ! La menace[ENTER]venant du Serment Blanc n'a jamais \233t\233 aussi[ENTER]forte ! "
gameforge.subquest_15._40_say = "Pour en finir, nous devons tuer leur capitaine,[ENTER]Eun-Jung. Les autres ne seront plus une menace[ENTER]apr\232s. Allez tuer Eun-Jung\160! Notre destin est[ENTER]entre vos mains\160! "
gameforge.subquest_15._50_sayTitle = "Gardien : "
gameforge.subquest_15._60_say = "Repasserez-vous plus tard ? Vous \234tes la personne[ENTER]ad\233quate pour cette mission. "
gameforge.subquest_15._70_say = "Vous ne pouvez pas le faire? Soit, \224 bient\244t... "
gameforge.subquest_15._80_say = "Je savais que vous nous aideriez ! Tuez Eun-Jung[ENTER]et nous nous occuperons du reste. Bonne chance! "
gameforge.subquest_15._90_sayReward = "Tuez la chef Eun-Jung, ainsi nous ne serons plus[ENTER]inqui\233t\233s par le Serment Blanc. "
gameforge.subquest_16 = {}
gameforge.subquest_16._100_qSetTitle = "Questionnez Yu-Hwan "
gameforge.subquest_16._10_targetVid = "Chercher la cavalerie lourde. "
gameforge.subquest_16._110_targetVid = "Allez voir Yu-Hwan "
gameforge.subquest_16._120_say = "La vie est si belle ... La vie est si belle ...[ENTER]Oh, encore vous ? Que voulez-vous cette fois ?[ENTER]Ah, des informations sur la Cavalerie Lourde ![ENTER]Pourquoi me demandez vous cela ?[ENTER]Le Capitaine doit avoir de grands projets[ENTER]n'est-ce pas ? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Tr\232s peu de textes originaux concernant la[ENTER]Cavalerie Lourde ont pu \234tre conserv\233s mais je[ENTER]connais quelques chansons .. Laissez-moi une[ENTER]minute, le temps d'accorder mon instrument ...[ENTER]Ah, vous \234tes press\233 ! De toutes fa\231ons personne[ENTER]ne prend jamais la peine de m'\233couter...[ENTER]Bien. J'ai souvent entendu dire que la Cavalerie[ENTER]Isup \233tait invincible. Des soldats extr\234mement[ENTER]bien entrain\233s, rapides et mobiles, avec de[ENTER]solides armures. "
gameforge.subquest_16._150_say = "C'\233tait la meilleure arm\233e que le continent ait[ENTER]connu. Beaucoup de r\233gions ne purent r\233sister ni[ENTER]contrer la cavalerie. Aujourd'hui cela pourrait[ENTER]\234tre la m\234me chose. Mais vous allez devoir vous[ENTER]entrainer dur pour atteindre la m\234me qualit\233[ENTER]d'arm\233e. Vous devriez parler avec le marchand[ENTER]ambulant ainsi qu'avec Uriel. Ils en savent[ENTER]surement plus que moi. "
gameforge.subquest_16._160_makequestbutton = "Allez voir le marchand ambulant "
gameforge.subquest_16._170_qSetTitle = "La cavalerie lourde "
gameforge.subquest_16._180_targetVid = "Marchand ambulant "
gameforge.subquest_16._190_sayReward = "Yu-Hwan le musicien vous a conseill\233 d'aller voir[ENTER]le marchand ambulant et Uriel pour avoir quelques[ENTER]informations concernant la cavalerie lourde.[ENTER]Allez donc voir le marchand ambulant. "
gameforge.subquest_16._200_sayTitle = "Marchand ambulant: "
gameforge.subquest_16._20_npcChat = "La cavalerie lourde "
gameforge.subquest_16._210_say = "Que voulez-vous \224 un simple marchand ambulant[ENTER]comme moi ? L'armure de fer de la cavalerie[ENTER]lourde ? Ce sont de vieilles histoires, pourquoi[ENTER]vous int\233ressent-elles ? Je dois gagner ma vie,[ENTER]je n'ai pas de temps \224 perdre \224 discuter ! "
gameforge.subquest_16._220_say = "Il devient de plus en plus difficile de joindre[ENTER]les deux bouts. Depuis que ces pierres sont[ENTER]tomb\233es du ciel j'ai... Que dites-vous ?[ENTER]Bien s\251r, la cavalerie.[ENTER]D'aussi loin que je me souvienne, ils portaient[ENTER]des armures sp\233ciales dont la fabrication[ENTER]demandait des connaissances particuli\232res. Jamais[ENTER]nous n'avions vu meilleures armures ! Des[ENTER]couteaux standards et m\234me des fl\232ches n'avaient[ENTER]pas le pouvoir de transpercer ces armures ! "
gameforge.subquest_16._230_say = "Je suppose que vous pouvez imaginer le co\251t d'une[ENTER]telle cavalerie. On disait qu'ils avaient vid\233[ENTER]les caisses de l'empire pour s'\233quiper ![ENTER]Si j'avais de telles armures \224 vendre, je serais[ENTER]\224 l'abri des soucis financiers pour le restant de[ENTER]mes jours ! "
gameforge.subquest_16._240_say = "De nos jours, de telles armures peuvent \233merger[ENTER]de Pierres Metin. Avec cette nouvelle forme[ENTER]d'armure, il devient \224 nouveau possible d'avoir[ENTER]une cavalerie lourde comme autrefois. Mais je[ENTER]parle trop, je dois y aller ! \192 bient\244t ! "
gameforge.subquest_16._250_sayTitle = "La cavalerie lourde "
gameforge.subquest_16._260_say = "Le marchand ambulant vous a appris des choses[ENTER]concernant les armures de fer de la cavalerie[ENTER]lourde. Allez au village d'\224 c\244t\233 et questionnez[ENTER]Uriel \224 pr\233sent \224 propos de l'entrainement. "
gameforge.subquest_16._270_sayTitle = "Uriel: "
gameforge.subquest_16._280_say = "Qu'est ce qui vous am\232ne ? La cavalerie lourde ?[ENTER]\201videmment que je connais certaines choses ![ENTER]Comme tout le monde. Cette arm\233e restera la plus[ENTER]connue dans toute l'histoire de tous les temps.[ENTER]Beaucoup de ce qui est racont\233 est exag\233r\233 mais[ENTER]ces soldats furent r\233ellement craints. Il y avait[ENTER]du vrai aussi donc. "
gameforge.subquest_16._290_say = "La cavalerie lourde \233tait au-dessus de toutes les[ENTER]autres, s\251rement gr\226ce \224 son entra\238nement[ENTER]intensif. Seuls les meilleurs arrivaient \224[ENTER]terminer l'entra\238nement, les autres mourraient[ENTER]souvent. Si aujourd'hui l'entra\238nement \233tait le[ENTER]m\234me, je pense que beaucoup de soldats[ENTER]abandonneraient avant la fin. "
gameforge.subquest_16._300_say = "Je vais vous donner quelques informations[ENTER]concernant l'entrainement, comme \231a vous saurez[ENTER]tout. Je sais qu'en ce moment de terribles[ENTER]guerres perdurent, mais je doute de l'efficacit\233[ENTER]et du besoin de cr\233er une arm\233e aussi form\233e que[ENTER]la Cavalerie Lourde. "
gameforge.subquest_16._30_say = "J'ai une nouvelle mission pour vous. Vous avez[ENTER]re\231u l'ordre de trouver des informations[ENTER]concernant la Cavalerie Lourde. C'\233tait la pi\232ce[ENTER]ma\238tresse de l'arm\233e d'Isup, le roi qui a jadis[ENTER]unifi\233 le continent. La cavalerie lourde \233tait[ENTER]crainte de toutes les nations gr\226ce \224 sa[ENTER]remarquable vitesse et \224 sa force d'attaque. "
gameforge.subquest_16._310_say = "Allez voir le Capitaine et dites-lui tout ce que[ENTER]vous avez appris au sujet de la cavalerie lourde. "
gameforge.subquest_16._320_makequestbutton = "Allez voir le Capitaine. "
gameforge.subquest_16._330_npcChat = "Rapport sur la Cavalerie Lourde "
gameforge.subquest_16._340_sayTitle = "Capitaine: "
gameforge.subquest_16._350_say = "Alors avez-vous trouv\233 quelque chose d'utile ?[ENTER]Dites-moi tout ![ENTER]Hum, c'est tr\232s int\233ressant. Ce n'est donc rien[ENTER]de plus qu'une armure de fer et un entra\238nement[ENTER]rigoureux ? Tout est donc possible ! Une telle[ENTER]arm\233e r\233unira les trois empires ! "
gameforge.subquest_16._360_say = "Mais je vais avoir besoin de beaucoup d'argent.[ENTER]Et de beaucoup de forgerons. Et il va falloir[ENTER]recruter des volontaires dispos\233s \224 devenir les[ENTER]meilleurs en bravant les pires dangers ! Non, ne[ENTER]me regardez pas comme cela. Ne vous inqui\233tez[ENTER]pas, vous avez d\233j\224 fait beaucoup. "
gameforge.subquest_16._370_say = "Voici votre r\233compense. Pensez \224 vous reposer[ENTER]aussi. \192 bient\244t ! "
gameforge.subquest_16._380_sayReward = "Vous gagnez 150\160000 points d'exp\233rience.[ENTER]Vous gagnez 30\160000 Yangs.[ENTER]Vous gagnez des Boucles d'oreille en or. "
gameforge.subquest_16._40_say = "Avec ces informations, nous allons pouvoir[ENTER]multiplier notre puissance militaire. Allez[ENTER]d'abord voir le musicien Yu-Hwan. Je suis certain[ENTER]qu'il sait quelque chose \224 propos de la Cavalerie[ENTER]Isup. "
gameforge.subquest_16._50_say = "Comme vous voulez. \192 bient\244t alors. "
gameforge.subquest_16._60_say = "Vais-un jour un avoir le commandement d'un tel[ENTER]r\233giment ? Soyez prudent. "
gameforge.subquest_16._70_say = "Merci. Prenez soin de vous. "
gameforge.subquest_16._80_sayTitle = "La cavalerie lourde "
gameforge.subquest_16._90_sayReward = "Le Capitaine est \224 la recherche d'informations[ENTER]concernant la l\233gendaire Cavalerie Royale[ENTER]d'Isup.Yu-Hwan le musicien d\233tient surement des[ENTER]informations. Allez le voir. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Parler \224 la marchande. "
gameforge.subquest_17._10_targetVid = "L'histoire du mari d'Ariyoung "
gameforge.subquest_17._110_say = "Allez voir la marchande pour lui poser des[ENTER]questions \224 propos du mari d'Ariyoung. "
gameforge.subquest_17._120_npcChat = "Le mari de Ariyoung "
gameforge.subquest_17._130_say = "C'est une triste histoire. Elle ne sais toujours[ENTER]pas ce qui est arriv\233 \224 son mari ? Il est \224 un[ENTER]endroit dont on ne reviens jamais ...[ENTER]Il \233tait en chemin pour rentrer au village avec[ENTER]ses marchandises quand il a \233t\233 enlev\233 puis tu\233[ENTER]par le Clan du Vent Noir "
gameforge.subquest_17._140_say = "Elle sera tr\232s malheureuse quand vous lui[ENTER]annoncerez. Ils s'aimaient beaucoup tous les[ENTER]deux. Mais bon, il faut bien qu'elle l\146apprenne[ENTER]un jour. Elle finirait par mourir d'incertitude,[ENTER]sinon. "
gameforge.subquest_17._150_targetVid = "Mauvaises nouvelles "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "La marchande a de mauvaises nouvelles. Allez voir[ENTER]Ariyoung et annoncez-lui la mort de son mari. "
gameforge.subquest_17._180_npcChat = "Votre mari est d\233c\233d\233 ... "
gameforge.subquest_17._190_say = "Comment... qu'est-ce que vous dites...?! Il...[ENTER]il a \233t\233 tu\233 par le gang du Vent Noir? Oh non..[ENTER]il est mort... Qu'est ce que je vais faire sans[ENTER]lui? *sanglots* "
gameforge.subquest_17._200_say = "Pourriez-vous me rapporter le corps de mon mari?[ENTER]Je vous en prie, comme \231a je pourrai au moins lui[ENTER]dire un dernier adieu. Si ce n'est pas possible[ENTER]ramenez-moi au moins quelque chose qui lui[ENTER]appartenait. N'importe quoi, du moment que \231a[ENTER]vienne de lui. Le Goo-Pae du Vent Noir a s\251rement[ENTER]quelque chose. Ramenez-moi quelque chose. "
gameforge.subquest_17._20_say = "Beaucoup de temps a pass\233 depuis la derni\232re fois[ENTER]o\249 j'ai eu des nouvelles de mon mari. Je suis[ENTER]inqui\232te, j'esp\232re qu'il ne lui est rien arriv\233.[ENTER]Je sais bien qu'il est inutile de s'inqui\233ter[ENTER]mais mon c\156ur bat si fort. Je n'arrive pas \224 me[ENTER]calmer. "
gameforge.subquest_17._210_select = "Oui, je vous aiderai. "
gameforge.subquest_17._220_say = "Revenez si vous changez d'avis. Je vous en prie... "
gameforge.subquest_17._230_say = "Vous n'avez rien trouv\233? Merci quand m\234me.[ENTER]Pauvre de moi ... "
gameforge.subquest_17._240_say = "Je ne trouve pas les mots pour exprimer ma[ENTER]gratitude. Je prierai pour vous. "
gameforge.subquest_17._250_sendLetter = "Tuer les Goo-Paes "
gameforge.subquest_17._260_say = "Le Gang du Vent Noir a d\233trouss\233 puis tu\233 le mari[ENTER]de Ariyoung. Tuez des Goo-Paes jusqu'\224 ce que[ENTER]vous trouviez un souvenir \224 rapporter \224 la pauvre[ENTER]femme. "
gameforge.subquest_17._270_npcChat = "\192 propos de votre mari ... "
gameforge.subquest_17._280_say = "Comment \231a s'est pass\233? Avez-vous pu retrouver[ENTER]quelque chose de mon mari? Il \233tait tout pour[ENTER]moi. Rien du tout ? "
gameforge.subquest_17._290_select = "Pas encore. Je cherche toujours ! "
gameforge.subquest_17._300_say = "Un Goo-Pae du Vent Noir n'est pas une proie[ENTER]facile. Reposez vous un peu. Merci pour votre[ENTER]aide. "
gameforge.subquest_17._30_say = "Peut-\234tre que la marchande a eu des nouvelles de[ENTER]mon mari. Elle a beaucoup de clients, il se peut[ENTER]que quelqu'un lui ait dit quelque chose. "
gameforge.subquest_17._310_say = "Bien, je vais devoir attendre un autre h\233ros qui[ENTER]consentira \224 m'aider... Adieu. "
gameforge.subquest_17._320_say = "Oh, vous \234tes si gentil! Je vous en prie[ENTER]ramenez-moi quelque chose de mon mari. "
gameforge.subquest_17._330_sendLetter = "Alliance du mari de Ariyoung "
gameforge.subquest_17._340_targetVid = "Allez voir Ariyoung "
gameforge.subquest_17._350_sayTitle = "Allez voir Ariyoung "
gameforge.subquest_17._360_say = "Vous avez trouv\233 l'alliance du mari de Ariyoung[ENTER]en tuant l'un des Goo-Pae. Vous pouviez[ENTER]difficilement trouver plus beau souvenir. Allez[ENTER]lui apporter. "
gameforge.subquest_17._370_npcChat = "J'ai trouv\233 cette alliance. "
gameforge.subquest_17._380_say = "Cet anneau...c'est son alliance! Maintenant mon[ENTER]mari peut reposer en paix... Je vais enterrer[ENTER]cette alliance avec une lettre que j'ai \233crite.[ENTER]Maintenant je vivrai seule. Au moins vous m'avez[ENTER]rapport\233 l'alliance. C'est un grand soulagement.[ENTER]Je ne pourrai jamais assez vous remercier. "
gameforge.subquest_17._390_sendLetter = "Qu\234te termin\233e! "
gameforge.subquest_17._400_say = "La nouvelle de ce que vous avez fait pour[ENTER]Ariyoung se r\233pand. Beaucoup de gens vous[ENTER]consid\232rent comme un h\233ros. "
gameforge.subquest_17._40_select = "Je vais voir la marchande. "
gameforge.subquest_17._410_sayReward = "Vous recevez 300.000 points d'exp\233rience. "
gameforge.subquest_17._420_sayReward = "Vous avez re\231u 10\160000 Yangs. "
gameforge.subquest_17._50_select = "Non, je n'ai pas le temps. "
gameforge.subquest_17._60_say = "Souhaitez-vous abandonner cette qu\234te ? "
gameforge.subquest_17._70_say = "Revenez si vous changez d'avis. Je vous en prie... "
gameforge.subquest_17._80_say = "Vous n'avez pas le temps ?[ENTER]Pas de temps pour une mission si simple ?[ENTER]Bon, d'accord ... "
gameforge.subquest_17._90_say = "Merci de votre gentillesse. Oooh mon dieu, o\249[ENTER]peut donc \234tre mon mari... "
