gameforge.subquest_18._100_say = "Cherchez un homme qui lit des po\232mes et est[ENTER]habill\233 comme un \233pouvantail et parlez lui. "
gameforge.subquest_18._10_targetVid = "O\249 se cache-t-il\160? "
gameforge.subquest_18._110_npcChat = "O\249 est votre mari ? "
gameforge.subquest_18._120_say = "J'ignore ou il se cache. Il est bon maintenant \224[ENTER]ce jeu, cela devient difficile de le trouver.[ENTER]devrais-je vraiment attacher une cloche \224 son cou[ENTER]comme le magasinier me l'a sugg\233r\233 ? "
gameforge.subquest_18._130_npcChat = "Trouvez Soon! "
gameforge.subquest_18._140_say = "Vous entendez une merveilleuse po\233sie. Enchant\233[ENTER]par les mots, vous suivez le son de la voix et[ENTER]vous vous trouvez face \224 un homme habill\233 de[ENTER]loques.[ENTER]C'est forc\233ment le mari d'Aranyo ![ENTER][ENTER]Juste au moment ou vous alliez faire demi-tour[ENTER]pour pr\233venir Aranyo, une main agrippa votre[ENTER]\233paule. "
gameforge.subquest_18._150_say = "Vous n'\234tes pas d'ici. C'est ma femme qui vous[ENTER]envoie?[ENTER]Oh non! Il sait qui je suis! Dois-je lui dire la[ENTER]v\233rit\233? "
gameforge.subquest_18._153_select = "Non, absolument pas, je ne fais que passer... "
gameforge.subquest_18._157_select = "Bien... "
gameforge.subquest_18._160_say = "Hm, enchant\233 de faire votre connaissance. Beau[ENTER]temps n'est-ce pas? Avez vous lu un bon livre[ENTER]derni\232rement? En ce moment je lis un livre de[ENTER]Oja. Vous devriez le lire aussi. "
gameforge.subquest_18._170_say = "J'ai raison, n'est-ce pas ? Les railleries de ma[ENTER]femme sont tellement insupportables que je ne[ENTER]peux lire en paix dans ma propre maison. Elle ne[ENTER]me comprend pas et continue d'envoyer des gens[ENTER]pour me trouver... Vous m'avez trouv\233, mais je[ENTER]pourrais aller ailleurs \224 tout moment.[ENTER]Pourquoi ne pas garder cela pour vous et ne rien[ENTER]dire ? Je vous donnerai quelques pr\233cieux[ENTER]conseils de chasse si vous y consentez. "
gameforge.subquest_18._180_sendLetter = "Retournez voir Aranyo "
gameforge.subquest_18._190_say = "Retournez voir Aranyo et dites-lui que vous[ENTER]n'avez pas trouv\233 Soon. "
gameforge.subquest_18._200_npcChat = "Le secret de Soon. "
gameforge.subquest_18._20_sayTitle = "Aranyo : "
gameforge.subquest_18._210_say = "Vous ne l'avez pas trouv\233? J'ai m\234me dispos\233 des[ENTER]pi\232ges. O\249 a-t-il pu se cacher, bon sang?[ENTER]Comme si je n'avais que \231a a faire. Je n'ai[ENTER]vraiment pas de chance... "
gameforge.subquest_18._220_sendLetter = "Retournez voir Soon "
gameforge.subquest_18._230_say = "Retournez voir Soon pour lui dire que vous avez[ENTER]r\233ussi. "
gameforge.subquest_18._240_npcChat = "Me voil\224. "
gameforge.subquest_18._250_say = "Tout va bien? Vous m'avez sauv\233 la vie ! Prenez[ENTER]ceci, aventurier. Comme promis, c'est votre[ENTER]r\233compense. "
gameforge.subquest_18._260_sayReward = "Vous avez re\231u 7\160000 points d'exp\233rience. "
gameforge.subquest_18._270_sayReward = "Vous avez re\231u 10\160000 Yangs. "
gameforge.subquest_18._280_say = "Retournez voir Aranyo pour lui dire o\249 se trouve[ENTER]Soon. "
gameforge.subquest_18._290_npcChat = "Il est difficile de se cacher. "
gameforge.subquest_18._300_say = "Merci de ne pas avoir d\233truit ma couverture.[ENTER]C'est dur de se cacher de ma femme. Je veux juste[ENTER]\233tudier en paix ici. "
gameforge.subquest_18._30_say = "Mon mari est un casse-pieds de premi\232re classe.[ENTER]Il s'auto-proclame \233rudit! Alors que nous devons[ENTER]nous battre chaque jour pour pouvoir nous[ENTER]nourrir, il passe tout son temps \224 lire des[ENTER]livres. Vous l'avez vu? Pourquoi a-t-il fallu que[ENTER]je me marie \224 pareil rat de biblioth\232que... "
gameforge.subquest_18._310_npcChat = "O\249 se trouve Soon "
gameforge.subquest_18._320_say = "Vous l'avez trouv\233 ?[ENTER]Merci beaucoup ! S'il d\233couvre que vous l'avez[ENTER]trouv\233, il risque de s'enfuir. Je vais y aller de[ENTER]ce pas. Cette fois-ci il ne m'\233chappera pas ![ENTER]Prenez ceci en guise de reconnaissance.[ENTER]Qu'attendez-vous, souriez ! "
gameforge.subquest_18._33_select = "Je vais vous aider "
gameforge.subquest_18._37_select = "Je n'ai pas le temps. "
gameforge.subquest_18._40_say = "Voulez-vous abandonner cette qu\234te? "
gameforge.subquest_18._50_say = "Bien...[ENTER]Tant pis, peut-\234tre pourrez-vous le chercher pour[ENTER]moi une autre fois... "
gameforge.subquest_18._60_say = "Je vais peut-\234tre finir par le trouver... "
gameforge.subquest_18._70_say = "Je vous en serai reconnaissante. Quand vous[ENTER]trouverez un mauvais \233crivain, faites-le moi[ENTER]savoir. C'est s\251rement le seul dans ce village de[ENTER]toute fa\231on. Peut-\234tre pense-t-il \224 un po\232me et[ENTER]qu'il s'est isol\233 pour \231a. S'il sait que je le[ENTER]cherche, prenez garde, il pourrait s'enfuir. "
gameforge.subquest_18._80_sendLetter = "Trouvez Soon. "
gameforge.subquest_18._90_sayTitle = "Trouvez le rat de biblioth\232que "
