gameforge.subquest_19._120_sayReward = "Trouvez une fourrure de loup pour que la vieille[ENTER]dame puisse nettoyer sa maison et ne tousse plus.[ENTER]Vous trouverez \231a sur un loup gris. "
gameforge.subquest_19._130_targetVid = "Retournez voir la vieille dame. "
gameforge.subquest_19._140_npcChat = "Apportez la fourrure de loup. "
