gameforge.subquest_19._160_say = "J'ai besoin d'un vrai plumeau. D\233sol\233e mais je ne[ENTER]pourrai rien faire avec \231a. "
gameforge.subquest_19._170_select = "Je vais r\233essayer. "
gameforge.subquest_19._180_select = "Je ne veux pas. "
gameforge.subquest_19._190_say = "Voulez-vous vraiment abandonner cette qu\234te? "
gameforge.subquest_19._200_say = "Revenez plus tard. "
gameforge.subquest_19._20_say = "*Tousse* Mon dieu, cette toux aura raison de moi.[ENTER]Je n'ai rien pour nettoyer ma maison et elle est[ENTER]pleine de poussi\232re. Mais pourquoi n'ai-je pas de[ENTER]plumeau ? Mon fils me l'a pris, apparemment pour[ENTER]fabriquer une arme. La chair de ma chair est en[ENTER]train de me tuer ! "
gameforge.subquest_19._210_say = "Je sais que ce n'est pas facile mais r\233essayez je[ENTER]vous en prie. "
gameforge.subquest_19._220_say = "Merci de vous en \234tre occup\233. "
gameforge.subquest_19._230_say = "Vous \234tes l'aventurier... Ma toux est toujours[ENTER]aussi inqui\233tante. *tousse* *tousse* Vous pouvez[ENTER]constater qu'elle ne s'est pas am\233lior\233e, la[ENTER]maison est toujours pleine de poussi\232re.[ENTER][ENTER]Oh, vous m'avez apport\233 une fourrure de loup?[ENTER]Oui, c'est exactement ce qu'il me fallait, merci[ENTER]beaucoup. Attendez-moi ici. "
gameforge.subquest_19._240_say = "Un, deux, un, deux. Un pied devant l''autre...[ENTER]Ok, me revoil\224. Merci beaucoup ! Finalement, je[ENTER]peux nettoyer ma maison correctement. J'ai aussi[ENTER]trouv\233 quelque chose que j'ai envie de vous[ENTER]donner. J'en ignore sa valeur mais peut-\234tre[ENTER]qu'il vous sera utile. Merci encore. Adieu! "
gameforge.subquest_19._250_sendLetter = "Quelque chose de poussi\233reux "
gameforge.subquest_19._260_say = "En r\233compense vous avez r\233cup\233r\233 un objet qui ne[ENTER]semble \234tre qu'un vulgaire d\233tritus. Vous le[ENTER]d\233poussi\233rez par curiosit\233. "
gameforge.subquest_19._270_say = "C'est une vieille armure de grande valeur.[ENTER]L'\156uvre d'un excellent forgeron. Quelle chance! "
gameforge.subquest_19._280_say = "C'est une armure. Elle est vieille mais peut[ENTER]servir. C'est toujours mieux que rien ! "
gameforge.subquest_19._290_say = "C'est une armure, mais malgr\233 tous vos espoirs,[ENTER]elle est compl\232tement inutile et sans valeur. "
gameforge.subquest_19._300_sayReward = "Vous avez re\231u 15.000 points d'exp\233rience. "
gameforge.subquest_19._30_select = "Je vais vous en trouver un. "
gameforge.subquest_19._40_say = "Tout est si poussi\233reux... il me faut un plumeau.[ENTER]Pouvez-vous m'aider? "
gameforge.subquest_19._50_say = "\199a ne date pas d'hier, mais je crois que mon[ENTER]mari, paix \224 son \226me, l'avait fabriqu\233 \224 partir[ENTER]d'une fourrure de loup. *Tousse, tousse.*[ENTER]Pourriez-vous aller chercher une fourrure de loup[ENTER]pour une vieille dame\160? Vous en trouverez sur les[ENTER]loups gris. Vous me rendriez un immense service. "
gameforge.subquest_19._60_say = "Voulez-vous vraiment abandonner? "
gameforge.subquest_19._70_say = "Bon tant pis... Quel dommage, moi qui pensais que[ENTER]vous m'aideriez. Revenez me voir si vous changez[ENTER]d'avis. "
gameforge.subquest_19._80_say = "Quel genre de r\233compense peut-on attendre d'une[ENTER]pauvre vieille dame\160? "
gameforge.subquest_19._90_say = "Il n'est pas ais\233 de trouver une fourrure de[ENTER]loup, mais je vais essayer. Apr\232s tout, moi j'ai[ENTER]envie de devenir un h\233ros un jour ! "
