gameforge.subquest_20._350_say = "Merci de ne pas abandonner ! "
gameforge.subquest_20._360_say = "Oh, les voil\224! Je suis tr\232s heureuse, merci. Ce[ENTER]n'est pas grand chose, mais tenez, prenez \231a. "
gameforge.subquest_20._370_sayReward = "Vous avez re\231u 300\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 20\160000 Yangs. "
gameforge.subquest_20._40_say = "Oh, vous semblez bien triste en ce moment. Vous[ENTER]qui \234tes d'habitude si gai ! Il s'est pass\233[ENTER]quelque chose ? "
gameforge.subquest_20._50_say = "Je suis inqui\232te. Mon mari prenait soin de moi[ENTER]avant mais maintenant il est mort \224 la guerre. Il[ENTER]ne me reste que notre b\233b\233 et les lances pour me[ENTER]rem\233morer mon mari. "
gameforge.subquest_20._60_say = "Pendant que j'\233tais au travail on m'a vol\233 les[ENTER]lances. Les voisins ont dit que les coupables[ENTER]sont des Barbares. Je ne peux pas les chercher[ENTER]moi-m\234me \224 cause du b\233b\233. "
gameforge.subquest_20._70_say = "Pourriez-vous me rapporter les lances? Vous les[ENTER]trouverez s\251rement chez les Barbares. "
gameforge.subquest_20._80_select = "Je vais les chercher. "
gameforge.subquest_20._90_select = "Je n'ai pas le temps. "
gameforge.subquest_21 = {}
gameforge.subquest_21._100_say = "Merci, mon ami.[ENTER]J'esp\232re que vous allez r\233ussir. "
gameforge.subquest_21._10_targetVid = "Balso? "
gameforge.subquest_21._110_sendLetter = "Un m\233dicament pour Balso "
gameforge.subquest_21._120_targetVid = "Allez voir Balso "
gameforge.subquest_21._130_sayReward = "Vous avez trouv\233 le m\233dicament pour Balso qui[ENTER]s'est infect\233 aupr\232s des pestif\233r\233s avec une[ENTER]maladie inconnue. Allez le lui donner. "
gameforge.subquest_21._140_sayTitle = "Trouvez le m\233dicament "
gameforge.subquest_21._150_say = "Pendant sa longue cavale, Balso a attrap\233 une[ENTER]maladie inconnue. Trouvez lui un m\233dicament sur[ENTER]les Pestif\233r\233s du Mont Sohan. "
gameforge.subquest_21._160_npcChat = "J'ai votre m\233dicament ! "
gameforge.subquest_21._170_say = "Oh merci beaucoup. C'est terrible de vivre une[ENTER]vie de fugitif. Alors quand vous tombez malade en[ENTER]prime... Maintenant je vais pouvoir me soigner.[ENTER]Merci beaucoup. "
gameforge.subquest_21._180_sayTitle = "R\233compense : "
gameforge.subquest_21._190_sayReward = "Vous avez re\231u 1\160900\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 30\160000 Yangs. "
gameforge.subquest_21._20_npcChat = "\199a gratte trop ... "
gameforge.subquest_21._30_sayTitle = "Balso le tra\238tre : "
gameforge.subquest_21._40_say = "Puis-je vous demander une faveur ? Vous savez[ENTER]s\251rement d\233j\224 que je suis connu comme \233tant un[ENTER]tra\238tre et \231a me rend la vie dure. J'ai travers\233[ENTER]de bonnes p\233riodes dans ma vie mais maintenant[ENTER]rien ne va plus pour moi... Depuis je passe mon[ENTER]temps \224 fuir et jamais je ne peux me reposer.[ENTER]Comme si \231a ne suffisait pas je suis en contact[ENTER]avec beaucoup de maladies. "
gameforge.subquest_21._50_say = "Il y a quelques jours, j'\233tais au Mont Sohan et[ENTER]j'ai \233t\233 m\234l\233 \224 un groupe de Pestif\233r\233s.[ENTER]Heureusement j'ai r\233ussi \224 m'enfuir, mais j'ai[ENTER]apparemment attrap\233 une maladie en entrant en[ENTER]contact avec leur peau. Pourriez-vous m'aider \224[ENTER]trouver un rem\232de ? Je suppose qu'ils ont un[ENTER]m\233dicament sur eux. Je n'aime pas demander cela,[ENTER]mais, pourriez-vous aller m'en chercher s'il vous[ENTER]plait ? "
gameforge.subquest_21._60_select = "Oui, je vous aiderai. "
gameforge.subquest_21._70_say = "Vous voulez arr\234ter les recherches? "
gameforge.subquest_21._80_say = "Bon, j'ai l'habitude. Il y a partout des gens qui[ENTER]ne m'appr\233cie pas. Si vous vous ravisez revenez[ENTER]me voir. "
gameforge.subquest_21._90_say = "Partez ! Et ne revenez jamais ! C'est toujours la[ENTER]m\234me chose ... "
gameforge.subquest_22 = {}
gameforge.subquest_22._100_say = "Merci, j'ai confiance en vous ! Rapportez-moi[ENTER]vite la hache. "
gameforge.subquest_22._10_targetVid = "La hache d'or de Deokbae "
gameforge.subquest_22._110_targetVid = "Allez voir Deokbae "
gameforge.subquest_22._120_sayTitle = "Hache d'or trouv\233e "
gameforge.subquest_22._130_say = "Vous avez repris la hache d'or des mains des[ENTER]Barbares. Apportez-la \224 Deokbae. "
gameforge.subquest_22._140_sayTitle = "\192 la recherche de la hache d'or. "
gameforge.subquest_22._150_say = "R\233cup\233rez des mains des g\233n\233raux barbares la[ENTER]hache d'or si pr\233cieuse et rapportez la \224[ENTER]Deokbae. "
gameforge.subquest_22._160_npcChat = "J'ai trouv\233 la hache d'or ! "
gameforge.subquest_22._170_sayTitle = "Deokbae le b\251cheron: "
gameforge.subquest_22._180_say = "Sans votre aide je n'aurais jamais retrouv\233 la[ENTER]Hache d'or. Merci beaucoup. J'y ferai plus[ENTER]attention \224 l'avenir et la garderai toujours avec[ENTER]moi. "
gameforge.subquest_22._190_sayReward = "Vous gagnez 400.000 Points d'Exp\233rience. "
gameforge.subquest_22._200_sayReward = "Vous avez re\231u 30\160000 Yangs. "
gameforge.subquest_22._20_npcChat = "\192 propos de votre Hache d'or... "
gameforge.subquest_22._30_sayTitle = "Deokbae le b\251cheron: "
gameforge.subquest_22._40_say = "Oh non ! J'ai perdu la Hache ! Vous savez[ENTER]peut-\234tre de quelle hache je veux parler ? C'est[ENTER]la hache d'or qui me vient du Forgeron. Un[ENTER]Barbare me l'a vol\233e. "
gameforge.subquest_22._50_say = "Si le forgeron d\233couvre cela il sera furieux et[ENTER]refusera de r\233parer mes haches \224 l'avenir. En[ENTER]plus cette hache \233tait vraiment utile. Peut-\234tre[ENTER]pourriez-vous me la rapporter ? "
gameforge.subquest_22._60_select = "Refuser "
gameforge.subquest_22._70_say = "Vous voulez arr\234ter les recherches? "
gameforge.subquest_22._80_say = "Oh... Revenez quand vous aurez plus de temps. "
gameforge.subquest_22._90_say = "Trop difficile pour vous? Il n'y a rien que je[ENTER]puisse faire alors. Mais faites attention, il y a[ENTER]des Barbares partout. "
gameforge.subquest_23 = {}
gameforge.subquest_23._100_sendLetter = "Cherchez Yu-Hwan "
gameforge.subquest_23._10_targetVid = "S'il vous pla\238t, cherchez mon fr\232re a\238n\233! "
gameforge.subquest_23._110_targetVid = "Allez voir Yu-Hwan "
gameforge.subquest_23._120_say = "Le fr\232re a\238n\233 de Mirine a disparu \224 nouveau. Il[ENTER]n'a pas donn\233 signe de vie depuis un bon moment.[ENTER]La lettre que vous lui avez apport\233e la derni\232re[ENTER]fois a \233t\233 son dernier contact. Allez voir[ENTER]Yu-Hwan et cherchez le grand fr\232re de Mirine. "
gameforge.subquest_23._130_npcChat = "Avez-vous vu le fr\232re de Mirine? "
gameforge.subquest_23._140_say = "Le fr\232re de Mirine ? J'ai bien peur de ne pouvoir[ENTER]vous aider. Cela fait un moment que je n'ai pas[ENTER]eu de ses nouvelles. Je peux \224 peine me souvenir[ENTER]la derni\232re fois que je l'ai vu. Je suis inquiet[ENTER]moi aussi.[ENTER]Peut-\234tre que quelque chose lui est arriv\233 ?[ENTER]Allez demander au chasseur Yang-Shin. Vu qu'il se[ENTER]prom\232ne toujours partout, il l'a peut-\234tre[ENTER]aper\231u. "
gameforge.subquest_23._150_sendLetter = "Allez voir Yang-Shin "
gameforge.subquest_23._160_targetVid = "Allez voir Yang-Shin le chasseur "
gameforge.subquest_23._170_say = "Le chasseur Yang-Shin est toujours parti \224 droite[ENTER]\224 gauche. Il a peut-\234tre vu le fr\232re de Mirine. "
gameforge.subquest_23._180_npcChat = "Avez-vous vu le fr\232re de Mirine? "
gameforge.subquest_23._190_say = "Vous parlez du grand fr\232re de Mirine ? La[ENTER]derni\232re fois que je l'ai vu, il \233tait sur le[ENTER]chemin de la Vall\233e de Seungryong en train de[ENTER]ramasser des plantes. J'\233tais m\234me surpris, parce[ENTER]que c'est extr\234mement dangereux l\224-bas, mais[ENTER]j'avoue ne pas m'\234tre alarm\233 plus que \231a. "
gameforge.subquest_23._200_say = "Je devrais l'avoir arr\234t\233. S'il n'a pas donn\233 de[ENTER]nouvelles, quelque chose doit lui \234tre arriv\233.[ENTER]Vous feriez mieux d'aller \224 la Vall\233e de[ENTER]Seungryong le chercher. "
gameforge.subquest_23._20_npcChat = "Pourquoi pleurez-vous ? "
gameforge.subquest_23._210_select = "Commencer les recherches "
gameforge.subquest_23._220_say = "Abandonner la recherche? "
gameforge.subquest_23._230_say = "Mirine \233tait si triste ... Je reviendrai plus[ENTER]tard. "
gameforge.subquest_23._240_say = "Ce n'est pas parce qu'on est sans nouvelles du[ENTER]fr\232re de Mirine depuis son d\233part vers la vall\233e[ENTER]du dragon qu'il lui est forc\233ment arriv\233 quelque[ENTER]chose. Vous n'\234tes pas oblig\233 d'y aller juste[ENTER]parce qu'une gamine vous l'a demand\233. "
gameforge.subquest_23._250_say = "La mission n'est pas aussi insignifiante qu'il[ENTER]n'y semble.[ENTER]La Vall\233e de Seungryong est un endroit dangereux.[ENTER]Mais j'ai promis, donc je le ferai. "
gameforge.subquest_23._260_sendLetter = "Le fr\232re disparu "
gameforge.subquest_23._270_targetVid = "Cherchez le fr\232re a\238n\233 de Mirine dans la vall\233e[ENTER]de Seungryong ! "
gameforge.subquest_23._280_sayTitle = "Cherchez le fr\232re de Mirine "
gameforge.subquest_23._290_say = "Le fr\232re de Mirine cherche des plantes dans la[ENTER]Vall\233e de Seungryong. Allez vous assurer qu'il va[ENTER]bien.[ENTER]Le t\233l\233porteur peut \233ventuellement raccourcir[ENTER]votre trajet. "
gameforge.subquest_23._300_npcChat = "Le corps! "
gameforge.subquest_23._30_say = "Un moment s'il vous pla\238t... Vous m'aviez apport\233[ENTER]une lettre de mon fr\232re il y a quelque temps[ENTER]n'est ce pas? Je vous en \233tais tr\232s[ENTER]reconnaissante. Mais je n'ai \224 nouveau plus de[ENTER]nouvelles de lui. Mon fr\232re est toujours par[ENTER]monts et par vaux pour chercher des herbes. "
gameforge.subquest_23._310_say = "Un mort git ici. Il est jeune et mince et semble[ENTER]avoir rassembl\233 le Ginseng. J'ai peur que cela[ENTER]puisse \234tre le fr\232re plus vieux de Mirine, que[ENTER]nous avons cherch\233. Le corps porte un collier[ENTER]avec un pendentif. Je vais le prendre et[ENTER]l'apporter \224 Mirine. "
gameforge.subquest_23._320_sendLetter = "Allez voir Mirine. "
gameforge.subquest_23._330_sayTitle = "Mauvaises nouvelles "
gameforge.subquest_23._340_say = "Vous avez trouv\233 un pendentif sur un corps dans[ENTER]la Vall\233e de Seungryong, sur lequel le nom de[ENTER]Mirine est grav\233. Allez voir Mirine et donnez-lui[ENTER]le collier et le pendentif. "
gameforge.subquest_23._350_npcChat = "Connaissez-vous ce collier ? "
gameforge.subquest_23._360_say = "Oh, ce collier... Mon fr\232re le portait tout le[ENTER]temps. J'ai le m\234me. Nous les portions toujours,[ENTER]cela nous permettait de penser l'un \224 l'autre et[ENTER]de nous retrouver. Mais... mon fr\232re n'est pas l\224[ENTER]... Et seul ce collier a \233t\233 retrouv\233. "
gameforge.subquest_23._370_say = "Mon pauvre fr\232re...[ENTER]Tout \231a \224 cause de cette guerre. Mon fr\232re[ENTER]vendait des herbes m\233dicinales, c'\233tait sa seule[ENTER]rentr\233e d'argent d'ailleurs. Cela lui permettait[ENTER]d'acheter \224 manger. Il travaillait vraiment dur[ENTER]pour que j'ai assez \224 manger. Et \224 pr\233sent, il[ENTER]est mort ... Par ma faute ... "
gameforge.subquest_23._380_say = "Merci de m'avoir rapport\233 ceci, comme \231a je sais[ENTER]ce qu'il s'est pass\233. Sans votre aide je n'aurais[ENTER]jamais su ce qui lui \233tait arriv\233. "
gameforge.subquest_23._390_say = "Je vais prendre grand soin du pendentif de mon[ENTER]fr\232re, le collier est \224 vous...pour vous[ENTER]remercier de votre aide. Il pourra vous \234tre[ENTER]utile.[ENTER]Merci pour votre aide.[ENTER]Il est s\251rement au ciel maintenant, vous ne[ENTER]croyez pas? "
gameforge.subquest_23._400_sayReward = "Vous avez re\231u 600\160000 points d'exp\233rience.[ENTER]Vous avez re\231u 35\160000 Yangs. "
gameforge.subquest_23._40_say = "Je suis inqui\232te pour lui car il ne donne aucun[ENTER]signe de vie Pardon, mais vous pourriez \224 nouveau[ENTER]partir \224 la recherche de mon fr\232re? Peut-\234tre que[ENTER]Yuhwan sait quelque chose. "
gameforge.subquest_23._50_select = "Refuser "
gameforge.subquest_23._60_say = "Voulez-vous abandonner? "
gameforge.subquest_23._70_say = "Oh ...[ENTER]J'attendrai, revenez s'il vous pla\238t... "
gameforge.subquest_23._80_say = "Je n'ai pas le temps ![ENTER]Bonne chance pour votre fr\232re. "
gameforge.subquest_23._90_say = "Aider cette fille est gentil et ne demande pas[ENTER]beaucoup de travail. Alors allons-y! "
gameforge.subquest_24 = {}
gameforge.subquest_24._100_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_24._10_targetVid = "Le g\226teau de riz de Yu-Rang. "
gameforge.subquest_24._110_say = "Si vous avez un peu de temps plus tard, revenez[ENTER]s'il vous plait. J'ignore comment je vais[ENTER]survivre si je n'ai pas de g\226teaux de riz \224[ENTER]vendre. "
gameforge.subquest_24._120_say = "Tout tourne toujours autour des gens riches qui[ENTER]jettent leurs Yangs par les fen\234tres comme si ils[ENTER]\233taient \224 l'abri de tout. Alors que nous, nous ne[ENTER]savons m\234me pas si nous aurons de la nourriture \224[ENTER]notre table demain ! Partez ! "
gameforge.subquest_24._130_say = "Merci, vous \234tes tr\232s gentil. Je vais attendre[ENTER]ici jusqu'\224 ce que vous reveniez. "
gameforge.subquest_24._140_sendLetter = "Le g\226teau de riz vol\233 "
gameforge.subquest_24._150_say = "Rapportez les g\226teaux de Yu-Rang que les[ENTER]araign\233es du d\233sert ont vol\233. Si vous n'\234tes pas[ENTER]assez rapide les araign\233es vont les manger ou les[ENTER]g\226teaux s\232cheront au soleil... d\233p\234chez vous! "
gameforge.subquest_24._160_sayReward = "Tuez les jeunes araign\233es au d\233sert de Yongbi. "
gameforge.subquest_24._170_npcChat = "\192 propos du g\226teau de riz vol\233 ... "
gameforge.subquest_24._180_say = "Quoi, les araign\233es ont mang\233 le g\226teau de riz ?[ENTER]Oh non ! Ou bien est-il tout sec ? Je vous en[ENTER]supplie ne me dites pas que tout est perdu ! "
gameforge.subquest_24._190_select = "Non, tout va bien. "
gameforge.subquest_24._200_select = "J'abandonne. "
gameforge.subquest_24._20_npcChat = "Votre g\226teau de riz vol\233 ... "
gameforge.subquest_24._210_say = "Ne pourriez-vous pas le faire quand m\234me ? Ce[ENTER]g\226teau de riz est tr\232s important pour moi. Je[ENTER]vous en supplie.[ENTER][ENTER]Souhaitez-vous abandonner la qu\234te demandant de[ENTER]trouver le g\226teau de riz de Yu-Rang dans le[ENTER]d\233sert ? "
gameforge.subquest_24._220_select = "Je vais r\233essayer. "
gameforge.subquest_24._230_select = "D\233sol\233, c'est trop dur. "
gameforge.subquest_24._240_say = "Je n'arrive pas \224 y croire. Qui va nous aider[ENTER]maintenant ? "
gameforge.subquest_24._250_say = "Soyez gentil ! Aidez-moi je vous en prie ! "
gameforge.subquest_24._260_say = "Donc vous allez continuer les recherches\160?[ENTER]Merci\160! S'il vous plait trouvez ce g\226teau de riz[ENTER]au plus vite\160! "
gameforge.subquest_24._270_say = "Non, c'est trop tard. M\234me si vous les retrouvez,[ENTER]ils vont \234tre secs et je ne pourrai plus les[ENTER]vendre... "
gameforge.subquest_24._280_say = "En jetant un \156il par terre, vous apercevez des[ENTER]miettes de g\226teaux que les araign\233es ont laiss\233[ENTER]sur leur passage. Malheureusement, ils sont tr\232s[ENTER]secs. "
gameforge.subquest_24._290_sayReward = "Vous avez perdu trop de temps, les g\226teaux sont[ENTER]secs. Vous avez \233chou\233. "
gameforge.subquest_24._300_sendLetter = "Retournez voir Yu-Rang "
gameforge.subquest_24._30_say = "Hey, comment va votre m\232re? "
gameforge.subquest_24._310_targetVid = "Retournez voir Yu-Rang "
gameforge.subquest_24._320_say = "Vous avez r\233cup\233r\233 le g\226teau de riz de Yu-Rang \224[ENTER]temps. Apportez lui. "
gameforge.subquest_24._330_npcChat = "Vous avez de la chance. Voici le g\226teau. "
gameforge.subquest_24._340_say = "Vous \234tes vraiment fantastique. Je ne sais pas[ENTER]quoi dire... Maintenant je vais pouvoir les[ENTER]vendre au march\233 de demain. Merci beaucoup! "
gameforge.subquest_24._350_sayReward = "Vous avez re\231u 900.000 points d'exp\233rience. "
gameforge.subquest_24._360_sayReward = "Vous avez re\231u 25\160000 Yangs. "
gameforge.subquest_24._40_say = "Oh, elle va beaucoup mieux, merci. "
gameforge.subquest_24._50_say = "On dirait que vous avez des ennuis. Que se[ENTER]passe-t-il? "
gameforge.subquest_24._60_say = "Je vends des g\226teaux de riz ici m\234me tous les[ENTER]jours, mais il s'est pass\233 quelque chose de[ENTER]terrible aujourd'hui. De gigantesques araign\233es[ENTER]sont apparues et m'ont vol\233 mon g\226teau de riz.[ENTER]J'\233tais p\233trifi\233 et ne me suis pas d\233fendu. A[ENTER]pr\233sent je n'ai plus de g\226teau de riz \224 vendre.[ENTER]Comment vais-je survivre ? Ma famille n'a pas[ENTER]d'autres rentr\233es d'argent... "
gameforge.subquest_24._70_select = "je vous les ram\232nerai. "
gameforge.subquest_24._80_select = "D\233sol\233, je n'ai pas le temps. "
gameforge.subquest_24._90_sayTitle = "Question: "
gameforge.subquest_25 = {}
gameforge.subquest_25._100_npcChat = "Qu'aimez-vous ? "
gameforge.subquest_25._10_targetVid = "Huahn-So "
gameforge.subquest_25._110_say = "Eh bien..depuis que j'ai perdu mon mari \224 la[ENTER]guerre r\233cemment, je me sens tr\232s seule. Hm,[ENTER]qu'est-ce qui me ferait aller mieux? Mon mari[ENTER]avait l'habitude de m'apporter des fleurs. "
gameforge.subquest_25._120_say = "Ces fleurs poussent tr\232s loin d'ici. Malgr\233 le[ENTER]danger il allait me les chercher, mais depuis sa[ENTER]mort je n'ai plus revu ces fleurs. Des jours[ENTER]comme celui-ci me rappellent comme il me manque.[ENTER]Hum, qu'est-ce que je disais? S'il vous pla\238t[ENTER]oubliez ce que je viens de dire. "
gameforge.subquest_25._130_qSetTitle = "Retournez voir Huahn-So "
gameforge.subquest_25._140_makequestbutton = "Retournez voir Huahn-So "
gameforge.subquest_25._150_targetVid = "Huahn-So "
gameforge.subquest_25._160_say = "Les Fleurs que le mari d'Ariyoung lui offrait[ENTER]toujours lui manquent. Allez voir Huahn-so et[ENTER]parlez-lui de cela. "
gameforge.subquest_25._170_npcChat = "Le cadeau pour Ariyoung "
gameforge.subquest_25._180_say = "Alors qu'est-ce qu'elle aime? Vous ne lui avez[ENTER]rien dit \224 mon propos? Hm, elle voudrait une[ENTER]fleur comme celles que son mari lui apportait?[ENTER]C'est assez loin du village, pas facile pour moi[ENTER]d'en avoir. Et il pourrait y avoir des monstres,[ENTER]des tigres par exemple. "
gameforge.subquest_25._190_say = "Oui, pourquoi ne pas m'aider\160? Vous pourriez[ENTER]aller cueillir la fleur \224 ma place\160? Cela nous[ENTER]arrangerait tous les deux. Hein\160? ce n'\233tait pas[ENTER]le march\233 conclu\160? Allez, vous ne voyez pas[ENTER]combien j'essaie d'avoir son amour\160? Je vous[ENTER]couvrirai de Yangs\160! "
gameforge.subquest_25._200_select = "Refuser "
gameforge.subquest_25._20_npcChat = "Oh Ariyoung ma bien-aim\233e "
gameforge.subquest_25._210_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_25._220_say = "Mon dieu, comment vais-je faire pour trouver ces[ENTER]fleurs ? Je vous en prie revenez si jamais vous[ENTER]changez d'avis. "
gameforge.subquest_25._230_say = "Avez vous jamais \233t\233 amoureux? N'avez vous pas[ENTER]id\233e de combien j'aime Ariyoung? Oh Ariyoung... "
gameforge.subquest_25._240_say = "Merci beaucoup! Ramenez-moi ces fleurs, je vous[ENTER]en prie. "
gameforge.subquest_25._250_qSetTitle = "Ramenez les fleurs "
gameforge.subquest_25._260_targetVid = "Les fleurs "
gameforge.subquest_25._270_sayTitle = "Les Fleurs pour Ariyoung "
gameforge.subquest_25._280_say = "Afin d'aider Huah-So a montrer ce qu'il ressent[ENTER]pour Ariyoung, vous devez trouver ces Fleurs[ENTER]sp\233ciales. Ces Fleurs peuvent \234tre trouv\233es dans[ENTER]un coin de la carte du premier village. "
gameforge.subquest_25._290_npcChat = "Je n'ai pas trouv\233 les Fleurs. "
gameforge.subquest_25._300_say = "Et puis zut ![ENTER]Je voulais lui avouer mes sentiments.[ENTER]C'est si dur de gagner son amour.[ENTER]Ma ch\232re Ariyoung... "
gameforge.subquest_25._30_say = "Hm... Vous connaissez Dame Ariyoung? H\233 bien elle[ENTER]\233tait mari\233e mais elle ne l'est plus. Mais \231a n'a[ENTER]aucune importance, elle est toujours aussi belle.[ENTER]Je suis tomb\233 amoureux d'elle il y a bien[ENTER]longtemps. Mais elle s'est mari\233e alors qu'elle[ENTER]\233tait encore jeune... Je n'ai pas eu de[ENTER]chance...  "
gameforge.subquest_25._310_select = "Je vais r\233essayer. "
gameforge.subquest_25._320_select = "J'abandonne. "
gameforge.subquest_25._330_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_25._340_say = "Oh...[ENTER]Si vous changez d'avis...[ENTER]Vous me trouverez ici.[ENTER]Aidez-moi s'il vous pla\238t... "
gameforge.subquest_25._350_say = "Mon amour se terminera-t-il ainsi? Ariyoung... "
gameforge.subquest_25._360_say = "J'ai tant de remerciements \224 vous faire. Vous[ENTER]devez aussi \234tre amoureux si vous pouvez[ENTER]comprendre ce que je ressens pour Ariyoung. "
gameforge.subquest_25._370_npcChat = "Les fleurs pr\233f\233r\233es d'Ariyoung "
gameforge.subquest_25._380_say = "Ces Fleurs ressemblent \224 celles que Ariyoung a[ENTER]d\233crites. Je vais en prendre quelques-unes. "
gameforge.subquest_25._390_qSetTitle = "Retournez voir Huahn-So "
gameforge.subquest_25._400_say = "J'ai trouv\233 les fleurs pr\233f\233r\233es d'Ariyoung et[ENTER]j'en ai cueilli quelques-unes. Je ferais mieux de[ENTER]les apporter \224 Huahn-So afin qu'il puisse[ENTER]d\233clarer sa flamme \224 Ariyoung. "
gameforge.subquest_25._40_say = "Mais son mari est mort \224 la guerre. Elle est[ENTER]maintenant jeune et veuve. Bien qu'elle ait \233t\233[ENTER]mari\233e je veux lui faire savoir ce que je[ENTER]ressens. Je sais que c'est une requ\234te vraiment[ENTER]\233trange mais pourriez-vous m'aider? "
gameforge.subquest_25._410_npcChat = "Voici les fleurs pr\233f\233r\233es de Ariyoung. "
gameforge.subquest_25._420_say = "Oh, ce sont les Fleurs ? Je vais enfin pouvoir[ENTER]dire \224 Ariyoung ce que je ressens pour elle![ENTER]Pensez-vous que c'est trop t\244t ? En fait, ce[ENTER]n'est pas grave si c'est trop t\244t. Il faut que je[ENTER]lui annonce, je n'en peux plus. Voici votre[ENTER]r\233compense, et merci infiniment ! "
gameforge.subquest_25._430_sayReward = "Vous gagnez 400.000 Points d'Exp\233rience. "
gameforge.subquest_25._440_sayReward = "Vous avez re\231u 12\160000 Yangs. "
gameforge.subquest_25._50_say = "Vous pensez qu'elle aime les gentilshommes? Ou[ENTER]les beaux atours? Je dois d'abord savoir ce qui[ENTER]l'int\233resse, ensuite je pourrai aller lui parler.[ENTER]Pouvez-vous d\233couvrir cela pour moi s'il vous[ENTER]pla\238t? Mais ne lui parlez pas de moi! Je vous en[ENTER]prie, je vous r\233compenserai quand ce sera fait. "
gameforge.subquest_25._60_qSetTitle = "Allez voir Ariyoung "
gameforge.subquest_25._70_makequestbutton = "Allez voir Ariyoung "
gameforge.subquest_25._80_targetVid = "Allez voir Ariyoung "
gameforge.subquest_25._90_say = "Huahn-So aime Ariyoung la jeune veuve. Pour aider[ENTER]Huahn-So \224 avouer ses sentiments \224 Ariyoung, vous[ENTER]devez d\233couvrir ses go\251ts. Demandez \224 Ariyoung ce[ENTER]qui l'int\233resse mais n'en dites pas trop! "
gameforge.subquest_26 = {}
gameforge.subquest_26._100_say = "Vous savez pas ce que vous perdez, vous ratez la[ENTER]chance de votre vie. "
gameforge.subquest_26._10_targetVid = "Allez voir le magasinier. "
gameforge.subquest_26._110_say = "Parfait, je savais que vous seriez int\233ress\233. Si[ENTER]vous en attrapez, apportez les ici et partagez[ENTER]les avec moi s'il vous plait ! "
gameforge.subquest_26._120_sendLetter = "Allez voir Octavio "
gameforge.subquest_26._130_targetVid = "Ok-gu "
gameforge.subquest_26._140_sayTitle = "Allez voir Octavio "
gameforge.subquest_26._150_say = "Le magasinier vous a fait un joli cadeau : le[ENTER]potage aux pattes de grenouilles est un excellent[ENTER]rem\232de contre la fatigue et les courbatures.[ENTER]Demandez \224 Octavio de vous pr\233parer cette soupe. "
gameforge.subquest_26._160_npcChat = "De la soupe de pattes de grenouilles ? "
gameforge.subquest_26._170_say = "De la soupe de pattes de grenouilles... Oui, j'en[ENTER]faisais avant. Mais plus maintenant. A l'\233poque[ENTER]je n'\233tais pas effray\233 par les monstres, donc je[ENTER]me procurais facilement les pattes de grenouille. "
gameforge.subquest_26._180_say = "Mais \224 pr\233sent ... Je suis trop vieux et fatigu\233.[ENTER]Avec cette soupe, je pourrais reprendre un peu[ENTER]d'\233nergie, mais les grenouilles ne sont pas[ENTER]faciles \224 tuer. Si vous me rapportez quelques[ENTER]pattes de grenouilles, je vous pr\233parerai la[ENTER]meilleure soupe au monde ! "
gameforge.subquest_26._190_select = "Pas de probl\232me, je m'en charge. "
gameforge.subquest_26._200_select = "Non je ne peux pas. "
gameforge.subquest_26._20_npcChat = "Comment allez-vous ? "
gameforge.subquest_26._210_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_26._220_say = "Vous \234tes occup\233? Revenez si vous changez d'avis. "
gameforge.subquest_26._230_say = "Ma soupe n'est pas tr\232s connue. Si vous la[ENTER]connaissiez, vous le feriez. Enfin, ... au[ENTER]revoir. "
gameforge.subquest_26._240_say = "Alors d\233p\234chez vous! Je vais tout pr\233parer pour[ENTER]la soupe de pattes de grenouilles. "
gameforge.subquest_26._250_sendLetter = "Vous avez re\231u des pattes de grenouilles "
gameforge.subquest_26._260_targetVid = "Octavio "
gameforge.subquest_26._270_sendLetter = "Trouver des pattes de grenouilles "
gameforge.subquest_26._280_say = "Vous avez trouv\233 une patte de grenouille g\233ante.[ENTER]Apportez les \224 Octavio. "
gameforge.subquest_26._290_sayTitle = "Tuez le Chef grenouille arboricole "
gameforge.subquest_26._300_say = "Octavio a besoin de pattes de grenouilles pour[ENTER]pr\233parer une soupe. Vous pouvez en trouver en[ENTER]tuant des chefs grenouilles arboricoles au Temple[ENTER]de Hwang. "
gameforge.subquest_26._30_sayTitle = "Magasinier : "
gameforge.subquest_26._310_npcChat = "Je ne peux pas le faire maintenant. "
gameforge.subquest_26._320_say = "Pourquoi\160? Quand j'avais votre \226ge, j'attrapais[ENTER]10 pattes de grenouilles par jour\160! "
gameforge.subquest_26._330_select = "R\233essayez "
gameforge.subquest_26._340_say = "Vous \234tes fatigu\233? Pourquoi ne pas faire une[ENTER]pause et r\233essayer plus tard? "
gameforge.subquest_26._350_say = "Cette soupe aurait vraiment pu m'\234tre utile.[ENTER]Mais \231a n'arrivera pas .... Quelle honte...[ENTER]Adieu ! "
gameforge.subquest_26._360_say = "Alors ne restez pas plant\233 l\224 et allez-y ! L'eau[ENTER]boue d\233j\224 et tout est pr\234t ! "
gameforge.subquest_26._370_targetVid = "Allez voir Octavio "
gameforge.subquest_26._380_say = "\199a c'est ce que j'appelle une patte de[ENTER]grenouille\160! Normalement elles sont plus petites[ENTER]mais je suis s\251re que celle-ci sera excellente.[ENTER]Attendez un moment... \199a sent d\233j\224 tr\232s bon. Une[ENTER]pinc\233e de sel... Voil\224\160! Voici votre part. Ha ha[ENTER]ha, maintenant j'ai assez d'\233nergie pour[ENTER]travailler une semaine enti\232re. "
gameforge.subquest_26._390_say = "Attention que personne n'entende parler de cette[ENTER]soupe. Surtout le magasinier... Je ne la fais que[ENTER]rarement. Sinon, tout le monde vient me d\233ranger[ENTER]\224 longueur de temps. "
gameforge.subquest_26._400_sayReward = "Vous recevez 5.000.000 de points d'exp\233rience. "
gameforge.subquest_26._40_say = "Je ne me sentais pas tr\232s bien ces derniers temps.Mon corps n'est plus ce qu'il \233tait. Quand[ENTER]j'\233tais jeune, je pouvais travailler jusqu'\224 la[ENTER]tomb\233e de la nuit, tous les jours de la semaine,[ENTER]m\234me en buvant de l'alcool. Maintenant, me lever[ENTER]le matin me demande d\233j\224 beaucoup d'efforts.[ENTER]Cette soupe de pattes de grenouille me serait[ENTER]r\233ellement d'une grande aide. "
gameforge.subquest_26._410_sayReward = "Vous recevez 50\160000 Yangs. "
gameforge.subquest_26._50_say = "Vous ne savez pas ce qu'est la soupe de pattes de[ENTER]grenouilles ? Quand vous en buvez un bol, vous[ENTER]\234tes imm\233diatement plein d'\233nergie et de[ENTER]vitalit\233. Et ensuite, vous pouvez travailler une[ENTER]semaine enti\232re sans ressentir aucune fatigue.[ENTER]Octavio avait pour habitude de pr\233parer cette[ENTER]soupe, mais pour je ne sais quelle raison, il a[ENTER]arr\234t\233 depuis quelque temps. "
gameforge.subquest_26._60_select = "J'irai parler \224 Octavio "
gameforge.subquest_26._70_select = "Je suis occup\233. "
gameforge.subquest_26._80_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_26._90_say = "Ah, si vous \234tes occup\233...[ENTER]Revenez quand vous aurez le temps. "
gameforge.subquest_27 = {}
gameforge.subquest_27._100_say = "Est-ce qu'un livre vous donne de la nourriture ou[ENTER]des v\234tements? Si je le trouve... Que dieu[ENTER]l'aide! Demandez aux autres villageois, ils vous[ENTER]diront s\251rement la m\234me chose. "
gameforge.subquest_27._10_targetVid = "Soon "
gameforge.subquest_27._110_targetVid = "La marchande "
gameforge.subquest_27._120_makequestbutton = "Allez voir la Marchande "
gameforge.subquest_27._130_say = "Peut-\234tre que la marchande sait ce que Soon est[ENTER]sur le point de faire.. Allez la voir et demandez[ENTER]lui si elle a entendu quelque chose concernant[ENTER]Soon. "
gameforge.subquest_27._140_npcChat = "Que se passe-t-il avec Soon? "
gameforge.subquest_27._150_say = "Hier, il est pass\233 ici et cherchait le livre sur[ENTER]le Temple Secret. Il n'avait pas d'argent sur[ENTER]lui, il y a donc juste jet\233 un \156il. Cela doit[ENTER]\234tre tr\232s important pour lui s'il en arrive m\234me[ENTER]\224 n\233gliger sa famille. Pourquoi s'int\233resse t-il[ENTER]\224 cela ? "
gameforge.subquest_27._160_sayTitle = "La marchande\160: "
gameforge.subquest_27._170_say = "Je suis d\233sol\233e pour Aranyo. Elle n'a pas \233pous\233[ENTER]Soon pour travailler jour et nuit. Elle ne[ENTER]pensait s\251rement pas qu'elle devrait nourrir la[ENTER]famille. Vous devriez parler \224 Soon, peut-\234tre...[ENTER]peut-\234tre qu'il comprendra. "
gameforge.subquest_27._180_makequestbutton = "Allez voir Soon "
gameforge.subquest_27._190_qSetTitle = "Allez voir Soon "
gameforge.subquest_27._200_targetVid = "Encore Soon "
gameforge.subquest_27._20_npcChat = "La joie de la lecture "
gameforge.subquest_27._210_say = "Allez voir Soon[ENTER]Allez voir Soon et parlez-lui du livre du temple. "
gameforge.subquest_27._220_npcChat = "Que dire sur le livre du Temple secret? "
gameforge.subquest_27._230_say = "Vous savez, j'ai lu tous les livres du monde.[ENTER]Derni\232rement j'ai entendu parler de ce livre.[ENTER]Des rumeurs pr\233tendent qu'il renferme tous les[ENTER]secrets du temple et comment devenir un Saint. "
gameforge.subquest_27._240_say = "J'ai tellement envie de lire ce livre, vous[ENTER]pourriez l'avoir pour moi? Si vous le faites, je[ENTER]vous donnerai une r\233compense, m\234me si je dois[ENTER]vendre ma maison. "
