gameforge.subquest_27._260_select = "Non je ne peux pas, d\233sol\233. "
gameforge.subquest_27._270_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_27._280_say = "Allez vous ne voulez pas m'aider? Si vous ne le[ENTER]faites pas maintenant, faites-le plus tard.[ENTER]J'attendrai. "
gameforge.subquest_27._290_say = "Vous n'allez vraiment pas m'aider? Vous avez[ENTER]besoin de repos. Ce livre est vraiment important[ENTER]pour moi... Que vais-je faire? Fl\251te... "
gameforge.subquest_27._300_say = "Merci, je vous attends. "
gameforge.subquest_27._30_say = "Vous aimez lire autant que moi?[ENTER]Les mots qui forment des phrases et qui sont[ENTER]finalement unifi\233es dans un livre. Comme c'est[ENTER]merveilleux! Et la joie pure d'\233crire un livre[ENTER]pour que les autres personnes puissent le lire![ENTER]Il n'y a rien de mieux ! "
gameforge.subquest_27._310_makequestbutton = "Vous avez trouv\233 le livre du temple secret. "
