gameforge.subquest_27._400_sayReward = "Vous avez re\231u 850.000 points d'exp\233rience. "
gameforge.subquest_27._40_say = "Vous r\233coltez ce que vous semez, de la joie dans[ENTER]ce que vous faites. Que serait ma vie sans mes[ENTER]livres! C'est la vraie vie! Mais ma femme ne[ENTER]comprend pas, peut-\234tre pourriez-vous la[ENTER]convaincre. "
gameforge.subquest_27._410_sayReward = "Vous avez re\231u 20\160000 Yangs. "
gameforge.subquest_27._420_say = "H\233... Vous ne l'avez pas encore? Si vous[ENTER]commencez une qu\234te arrangez-vous pour la[ENTER]terminer. Terminez la qu\234te! "
gameforge.subquest_27._430_say = "Les fanatiques funestes ne doivent pas \234tre pris[ENTER]\224 la l\233g\232re. Retentez votre chance plus tard. "
gameforge.subquest_27._440_say = "Bon, je n'ai plus qu'\224 demander de l'aide \224[ENTER]quelqu'un d'autre. Adieu. "
gameforge.subquest_27._450_say = "Merci. Je vous attends. Je suis tellement[ENTER]impatient de l'avoir entre mes mains et de le[ENTER]lire. "
