gameforge.subquest_27._70_say = "Allez voir Aranyo et parlez-lui de son mari. "
gameforge.subquest_27._80_npcChat = "Pourquoi \234tes-vous si f\226ch\233 ? "
gameforge.subquest_27._90_say = "F\226ch\233e ? Mais j'explose de rage ! Mon mari[ENTER]travaille t-il ? Non. Ram\232ne t-il de l'argent \224[ENTER]la maison ? Non. Au lieu de \231a, il part se cacher[ENTER]on ne sait ou pour lire des pages et des pages de[ENTER]ses livres ! Avez-vous jamais entendu des choses[ENTER]pareilles ? Un livre nous habillera t-il ? Nous[ENTER]pr\233servera t-il de la famine ? "
