gameforge.subquest_32._120_targetVid = "Allez voir la Marchande "
gameforge.subquest_32._130_sayReward = "Mat\233riel pour le marchand "
gameforge.subquest_32._140_sayReward = "Le marchand ambulant a besoin de mat\233riel pour[ENTER]fabriquer son collier. Apportez-lui 100 dents[ENTER]d'Unggyi (sur les sorciers orcs \233lites), une[ENTER]pi\232ce de joaillerie (\224 la Marchande) et du Fil[ENTER](aupr\232s d'Ariyoung). "
gameforge.subquest_32._150_npcChat = "J'ai besoin de Fil. "
gameforge.subquest_32._160_say = "La production du Fil n'a rien d'exceptionnel.[ENTER]Mais cela m'emp\234che d'effectuer mon autre[ENTER]travail. J'ai recousu quelques v\234tements pour[ENTER]Ah-Yu aujourd'hui et j'aurais vraiment aim\233 lui[ENTER]rendre... "
gameforge.subquest_32._170_say = "Qu'en pensez-vous : Vous apportez les v\234tements \224[ENTER]Ah-Yu et en \233change je vous donne du Fil.[ENTER]C'est d'accord ? "
gameforge.subquest_32._180_say = "Souhaitez-vous d\233finitivement abandonner cette[ENTER]qu\234te ? "
gameforge.subquest_32._190_say = "Ce n'est vraiment pas loin. Pourquoi h\233sitez-vous[ENTER]toujours ? Revenez quand vous serez pr\234t. "
gameforge.subquest_32._200_say = "Oh, je pensais que vous auriez le temps. Je vais[ENTER]donc devoir le faire moi-m\234me. Adieu ! "
gameforge.subquest_32._20_npcChat = "\192 propos des colliers ... "
gameforge.subquest_32._210_say = "Magnifique, merci beaucoup ! Transmettez mes[ENTER]amiti\233s \224 Ah-Yu et assurez-vous de ne pas[ENTER]froisser les v\234tements sur la route. Je vous[ENTER]attends. "
gameforge.subquest_32._220_sayTitle = "Ariyoung: "
gameforge.subquest_32._230_say = "Le temps que vous vous rendiez au village d'\224[ENTER]c\244t\233, j'aurai termin\233 de pr\233parer votre Fil.[ENTER]Vous n'avez pas oubli\233 de prendre les v\234tements[ENTER]pour Ah-Yu au moins ? Elle m'en voudrait[ENTER]beaucoup. "
gameforge.subquest_32._240_say = "Ah-Yu est-elle contente de ses v\234tements? Si[ENTER]c'est le cas, \231a valait la peine de se donner[ENTER]autant de mal. Voici votre fil. Il est r\233sistant[ENTER]et peut \234tre utilis\233 pour tout un tas de choses. "
gameforge.subquest_32._250_say = "Je vous ai d\233j\224 donn\233 du Fil. L'avez-vous perdu ? "
gameforge.subquest_32._260_npcChat = "Ces v\234tements viennent d'Ariyoung. "
gameforge.subquest_32._270_sayTitle = "Ah-Yu: "
gameforge.subquest_32._280_say = "Oh, comme c'est gentil. Ce fut rapide en plus.[ENTER]Vous entretenez les amiti\233s n'est-ce pas ? Nous[ENTER]nous aidons souvent les uns les autres...[ENTER]Merci de m'avoir apport\233 les v\234tements.[ENTER]Transmettez mes amiti\233s \224 Ariyoung. "
gameforge.subquest_32._290_npcChat = "J'ai besoin de ce bijou. "
gameforge.subquest_32._300_say = "Vous cherchez une pi\232ce de joaillerie ?[ENTER]Je peux vous en donner une si vous m'aidez. A[ENTER]l'heure actuelle je travaille sur un m\233dicament[ENTER]anti-douleur, et il me manque un ingr\233dient : le[ENTER]foie d'un Tigre. Ils sont difficiles \224 tuer.[ENTER]J'ai besoin de 100 foies de tigres. "
gameforge.subquest_32._30_say = "En ces temps de guerre, la vie est difficile pour[ENTER]nous, les marchands ambulants. La demande est[ENTER]grande, mais elle change si rapidement que je[ENTER]n'ai pas le temps de m'adapter et de vendre les[ENTER]choses recherch\233es. Inutile aussi de parler du[ENTER]long chemin parcouru dans des milieux sauvages et[ENTER]hostiles rempli de monstres assoiff\233s de sang[ENTER]attendant dans l'ombre un randonneur inconscient.[ENTER]Voulez-vous gagner quelques Yangs ?[ENTER]Je vous en propose contre un peu d'aide. "
gameforge.subquest_32._310_say = "Il me faut aussi des herbes curatives que vous[ENTER]trouverez sur les m\234mes tigres. Ils se roulent[ENTER]dedans car ils aiment l'odeur. En \233change des[ENTER]herbes et des foies, je vous donnerai un bijou. "
gameforge.subquest_32._320_say = "Tuez des tigres et tigres blancs. "
gameforge.subquest_32._330_say = "Que dites-vous ? Peut-on faire affaire ? "
gameforge.subquest_32._340_say = "Ma demande est trop compliqu\233e pour vous ? Je ne[ENTER]peux y croire ! Revenez quand vous aurez chang\233[ENTER]d'avis. "
gameforge.subquest_32._350_say = "Vous \234tes venu jusqu'ici pour finalement[ENTER]abandonner? Comme vous voudrez ... Passez une[ENTER]bonne journ\233e... "
gameforge.subquest_32._360_say = "Tr\232s bien. Nous nous entraidons finalement. Merci[ENTER]et bonne chance ! "
gameforge.subquest_32._370_npcChat = "Puis avoir ma pi\232ce de joaillerie ? "
gameforge.subquest_32._380_say = "Laissez-moi voir \231a ... 100 foies de tigres et[ENTER]les herbes m\233dicinales, tout est l\224. Merci ![ENTER]Tenez, vous l'avez bien m\233rit\233 cette pi\232ce de[ENTER]joaillerie. \192 bient\244t ! "
gameforge.subquest_32._390_qSetTitle = "Retournez voir le marchand ambulant "
gameforge.subquest_32._400_targetVid = "Retournez voir le marchand ambulant "
gameforge.subquest_32._40_say = "En ce moment il y a une r\233elle demande concernant[ENTER]les colliers fabriqu\233s \224 partir de dents[ENTER]d'Unggyi. Ces dents sont solides, grosses et[ENTER]parfaites pour fabriquer certaines pi\232ces de[ENTER]joaillerie. Certains soldats pensent que ces[ENTER]souvenirs provenant d'orcs sorciers \233lites[ENTER]portent bonheur. Pouvez-vous m'en trouver ? Il[ENTER]m'en faudrait 100 pour bien commencer mon[ENTER]commerce. "
gameforge.subquest_32._410_sayReward = "Retournez voir le marchand ambulant "
gameforge.subquest_32._420_sayReward = "Vous avez trouv\233 les mat\233riaux pour le collier.[ENTER]Apportez-les au marchand ambulant. "
gameforge.subquest_32._430_npcChat = "J'ai tous les mat\233riaux "
gameforge.subquest_32._440_sayTitle = "Marchand ambulant: "
gameforge.subquest_32._450_say = "Vous avez tout ? Laissez-moi regarder ... Oh oui,[ENTER]tout y est ! Merci beaucoup, je vais pouvoir en[ENTER]stocker un peu. Voici votre r\233compense. Bonne[ENTER]continuation.[ENTER][ENTER]Allez venez ! Il y en aura pour tout le monde ! "
gameforge.subquest_32._460_sayReward = "Vous avez re\231u 1.100.000 points d'exp\233rience. "
gameforge.subquest_32._470_sayReward = "Vous avez re\231u un bracelet d'or, un collier d'or[ENTER]et des boucles d'oreille en or. "
gameforge.subquest_32._480_say = "Hum, je suis d\233sol\233 mais il manque quelque chose.[ENTER]Pouvez-vous tenter \224 nouveau ? "
gameforge.subquest_32._490_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_32._500_say = "Merci de ne pas abandonner si facilement. La[ENTER]chance appartient \224 ceux qui essaient ! Je vous[ENTER]attends. "
gameforge.subquest_32._50_say = "J'ai aussi besoin d'une pi\232ce de joaillerie et de[ENTER]Fil. Vous pouvez les obtenir aupr\232s de la[ENTER]marchande et d'Ariyoung. Il n'est pas facile de[ENTER]trouver tous ces ingr\233dients mais la vente de ces[ENTER]colliers est vraiment lucrative, et vous aurez[ENTER]une bonne r\233compense. Cela vous int\233resse ? "
gameforge.subquest_32._510_say = "Cette qu\234te est trop difficile ? Bon, au moins[ENTER]vous aurez essay\233. Je vous ferai savoir si un[ENTER]jour j'ai une mission plus facile pour vous.[ENTER]Adieu ! "
gameforge.subquest_32._520_say = "Vous allez essayer \224 nouveau ? Merci. Je vous[ENTER]attends. "
gameforge.subquest_32._60_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_32._70_say = "Vous \234tes occup\233 ? Je peux comprendre cela. Mais[ENTER]s'il vous plait, revenez quand vous aurez un peu[ENTER]de temps. "
gameforge.subquest_32._80_say = "Oh mais comment vais-je faire pour terminer mes[ENTER]t\226ches ? \192 bient\244t ! "
gameforge.subquest_32._90_say = "Fantastique. Je vous attends. "
gameforge.subquest_33 = {}
gameforge.subquest_33._100_sayTitle = "Carte au tr\233sor trouv\233e "
gameforge.subquest_33._10_targetVid = "Retournez voir Soon "
gameforge.subquest_33._110_say = "Vous avez tu\233 les 4 Dieux des Animaux \224[ENTER]l'ext\233rieur du village et avez collect\233 les 4[ENTER]morceaux de la Carte au Tr\233sor. Apportez-les \224[ENTER]Soon. "
gameforge.subquest_33._120_sayTitle = "La chasse des Dieux Animaux "
gameforge.subquest_33._130_say = "Collectez les 4 morceaux de la Carte au Tr\233sor en[ENTER]tuant les 4 Dieux des Animaux : Lykos, Scrofa,[ENTER]Bera et Tigris. "
gameforge.subquest_33._140_sayReward = "(Morceau(x) de la carte trouv\233(s) : %s ) "
gameforge.subquest_33._150_sendLetter = "La carte au tr\233sor "
gameforge.subquest_33._160_sayTitle = "Les 4 morceaux sont trouv\233s ! "
gameforge.subquest_33._170_say = "Retournez voir Soon et dites-lui que vous avez[ENTER]trouv\233 tous les morceaux de la carte au tr\233sor. "
gameforge.subquest_33._175_npcChat = "J'ai tous les fragments de carte. "
gameforge.subquest_33._180_say = "Oh, fantastique ! Les 4 morceaux r\233unis ... Je[ENTER]n'osais m\234me plus en r\234ver ! \192 pr\233sent je vais[ENTER]les r\233unir pour d\233voiler la carte ... "
gameforge.subquest_33._190_say = "Hum, \233trange. La carte r\233v\232le que le tr\233sor est[ENTER]cach\233 pr\232s du Rocher ou se trouve le Vieil Homme.[ENTER]Je ne peux y croire. Et il n'aurait jamais \233t\233[ENTER]trouv\233 ! C'est un canular pour b\233b\233 ![ENTER]Voulez-vous aller jeter un \156il tout de m\234me ou[ENTER]bien je br\251le cette carte ? "
gameforge.subquest_33._200_select = "Je vais jeter un oeil. "
gameforge.subquest_33._20_npcChat = "\192 propos de la carte ... "
gameforge.subquest_33._210_select = "Br\251lez-la. "
gameforge.subquest_33._220_say = "\202tes-vous s\251r de ne pas avoir besoin de cette[ENTER]carte ? "
gameforge.subquest_33._230_say = "Quel path\233tique conte de f\233es ![ENTER]Je suis d\233sol\233 de vous avoir fait perdre votre[ENTER]temps \224 aller chercher ces morceaux de carte. Je[ENTER]vais les br\251ler, plus personne ne se fera avoir[ENTER]comme cela. Merci quand m\234me en tout cas. A[ENTER]bient\244t. "
gameforge.subquest_33._240_say = "Pourquoi h\233sitez-vous ? Vous avez les morceaux de[ENTER]la carte, et la carte. Allez donc jeter un \156il ! "
gameforge.subquest_33._250_say = "Comme vous voulez. Je serais vraiment surpris que[ENTER]vous trouviez quoi que ce soit ... Prenez la[ENTER]carte ! Bonne chance ! "
gameforge.subquest_33._260_say = "La carte a \233t\233 divis\233e en 4 parties. Il nous faut[ENTER]donc les 4 pour l'unifier. "
gameforge.subquest_33._270_select = "Essayez encore "
gameforge.subquest_33._280_say = "Vous abandonnez ? Bon ... Adieu. "
gameforge.subquest_33._290_say = "Je savais que vous iriez. Je crois en vous ! "
gameforge.subquest_33._300_targetVid = "Le Rocher du Vieil Homme "
gameforge.subquest_33._30_say = "Hey, j'ai trouv\233 des informations \233tranges dans[ENTER]de vieux textes, disant que quelque part dans ce[ENTER]village, il se pourrait qu'il y ait une carte au[ENTER]tr\233sor... Connaissez-vous les Dieux de la ville?[ENTER]Le Dieu Chien, le Dieu Ours, le Dieu Tigre et le[ENTER]Dieu Cochon. "
gameforge.subquest_33._310_sayTitle = "Cherchez le tr\233sor "
gameforge.subquest_33._320_say = "Hmmm, derri\232re le Rocher du Vieil Homme...[ENTER]Aucune id\233e. Peut-\234tre devrais-je demander au[ENTER]vieil homme. Le chemin est si long... "
gameforge.subquest_33._330_sayTitle = "Vieil Homme: "
gameforge.subquest_33._340_say = "Que cherchez-vous ? un tr\233sor ? Ah ah ah, vous[ENTER]allez chercher un moment ! Montrez-moi cette[ENTER]carte... Hum ... Je pense que c'est juste ici...[ENTER]Bonne chance ... "
gameforge.subquest_33._350_say = "Cela doit \234tre ici. Allez un effort ![ENTER]Fichtre, ce sol est extr\234mement dur. Hmm ...[ENTER][ENTER]Voil\224, je vois enfin un coffre ! "
gameforge.subquest_33._360_sendLetter = "Le tr\233sor existe vraiment! "
gameforge.subquest_33._370_sayTitle = "Retournez voir Soon "
gameforge.subquest_33._380_say = "Vous avez creus\233 \224 l'endroit indiqu\233 par la carte[ENTER]et avez r\233ellement trouv\233 un tr\233sor ![ENTER]Retournez voir Soon et racontez-lui cette[ENTER]d\233couverte inattendue. "
gameforge.subquest_33._390_npcChat = "J'ai trouv\233 le tr\233sor ! "
gameforge.subquest_33._400_say = "Oh, quelle surprise ! Voyons ... Impressionnant ![ENTER]Ce tr\233sor ressemble \224 la description qui \233tait[ENTER]faite dans les textes anciens. Il ne me reste[ENTER]plus qu'\224 trouver comment l'ouvrir. Mais ce n'est[ENTER]pas votre probl\232me. Tenez, acceptez ceci en guise[ENTER]de reconnaissance. "
gameforge.subquest_33._40_say = "Ces 4 Dieux monstres divisent la carte en 4[ENTER]morceaux, et ils les prot\232gent. C'est un vieux[ENTER]conte de f\233es, donc je ne suis pas certain...[ENTER]Pourquoi ne pas aller chercher ? S'il vous[ENTER]pla\238t... Je ne peux le faire... S'il vous pla\238t,[ENTER]aidez-moi! "
gameforge.subquest_33._410_sayReward = "Vous avez re\231u 1.400.000 points d'exp\233rience. "
gameforge.subquest_33._420_sayReward = "Vous avez re\231u 25\160000 Yangs. "
gameforge.subquest_33._430_sayReward = "Vous avez re\231u un casque masque spectre + 1 "
gameforge.subquest_33._440_sayReward = "Vous avez re\231u un heaume de ch\226teau + 1 "
gameforge.subquest_33._450_sayReward = "Vous avez re\231u un capuchon de fer + 1 "
gameforge.subquest_33._460_sayReward = "Vous avez re\231u un chapeau lumi\232re du soleil + 1 "
gameforge.subquest_33._470_say = "Alors, ou est-il ? Vous ne l'avez pas vraiment[ENTER]trouv\233 n'est-ce pas ? Vous vous moquez de moi ? "
gameforge.subquest_33._50_say = "Pas int\233ress\233 par la carte au tr\233sor? Vous \234tes[ENTER]bizarre ... Je suis en train de lire[ENTER]attentivement les vieux textes pour y trouver des[ENTER]indices.[ENTER]Revenez si vous changez d'avis. "
gameforge.subquest_33._60_say = "Vous n'aimez pas ce genre d'aventures n'est ce[ENTER]pas . Comment suis je suppos\233 regrouper les 4[ENTER]morceaux dans ce cas ?[ENTER][ENTER]Bon, h\233 bien, au revoir... "
gameforge.subquest_33._70_say = "Vous \234tes un v\233ritable ami. Je savais bien que[ENTER]vous le trouveriez. "
gameforge.subquest_33._80_sendLetter = "La carte au tr\233sor de Soon "
gameforge.subquest_33._90_targetVid = "Allez voir Soon "
gameforge.subquest_34 = {}
gameforge.subquest_34._100_say = "Le Capitaine a toujours des ennuis avec le Gang[ENTER]du Vent Noir. Si vous tuez les g\233n\233raux du Vent[ENTER]Noir, c'est \224 dire Jak-To, To-Su et Gu-Ryung, il[ENTER]arrivera peut-\234tre \224 les avoir sous contr\244le. "
gameforge.subquest_34._10_npcChat = "Que fait le Gang du Vent Noir ? "
gameforge.subquest_34._110_say = "Les G\233n\233raux sont morts ! "
gameforge.subquest_34._120_select = "Essayer encore "
gameforge.subquest_34._130_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_34._140_say = "Il n'est pas facile de gagner une bataille,[ENTER]surtout contre les g\233n\233raux. Essayez encore. "
gameforge.subquest_34._150_say = "Comme je le disais, le Gang du Vent Noir est[ENTER]r\233ellement fort. Au revoir. "
gameforge.subquest_34._160_say = "Vous \234tes vraiment courageux! Je pense que vous[ENTER]pouvez battre le Gang du Vent Noir ! "
gameforge.subquest_34._170_targetVid = "Racontez au Capitaine "
gameforge.subquest_34._180_say = "Allez voir le Capitaine et dites-lui que vous[ENTER]avez tu\233 les g\233n\233raux. "
gameforge.subquest_34._185_npcChat = "J'ai bien tu\233 les g\233n\233raux ! "
gameforge.subquest_34._190_say = "Vous avez vaincu les g\233n\233raux. De ce fait, les[ENTER]autres membres du gang seront faciles \224 vaincre,[ENTER]nous allons nous en occuper. Ils nous ont donn\233[ENTER]de belles migraines, mais nous y arriverons[ENTER]maintenant. Voici votre r\233compense. Merci[ENTER]beaucoup, j'esp\232re qu'on se reverra! "
gameforge.subquest_34._200_sayReward = "Vous avez re\231u 1.000.000 de points d'exp\233rience. "
gameforge.subquest_34._20_sayTitle = "Capitaine: "
gameforge.subquest_34._210_sayReward = "Vous avez re\231u un anneau de langage. "
gameforge.subquest_34._30_say = "Malgr\233 votre victoire face au Gang du Vent Noir,[ENTER]ils ne veulent pas abandonner. Au lieu de se[ENTER]tenir \224 carreaux, ils sont devenus comme une[ENTER]horde de b\234tes sauvages. Si nous voulons les[ENTER]vaincre, nous allons devoir tuer les g\233n\233raux du[ENTER]Vent Noir. "
gameforge.subquest_34._40_say = "Une fois que les G\233n\233raux seront vaincus, les[ENTER]autres membres tomberont aussi. Ce travail sera[ENTER]difficile, mais vous devez l'emporter face aux[ENTER]g\233n\233raux Jak-To, To-Su et Gu-Ryung du Vent Noir.[ENTER]Si vous r\233ussissez, nous n'aurons plus \224 nous[ENTER]inqui\233ter de ce Gang. Bonne chance. Je prie pour[ENTER]votre victoire. "
gameforge.subquest_34._50_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_34._60_say = "Bon, revenez quand vous serez pr\234t. Il n'y a pas[ENTER]beaucoup de monde aussi comp\233tent que vous. "
gameforge.subquest_34._70_say = "Vous ne pouvez le faire...[ENTER]Comment allons-nous d\233manteler le Gang du Vent[ENTER]Noir maintenant... "
gameforge.subquest_34._80_say = "Je savais que je pouvais compter sur vous ! Une[ENTER]fois les g\233n\233raux tu\233s, les autres membres du[ENTER]Gang du Vent Noir ne seront plus un probl\232me.[ENTER]Bonne chance ! "
gameforge.subquest_34._90_sendLetter = "Tuez les G\233n\233raux du Vent Noir "
gameforge.subquest_36 = {}
gameforge.subquest_36._100_sayTitle = "Allez voir le palefrenier "
gameforge.subquest_36._10_targetVid = "Yonah "
gameforge.subquest_36._110_say = "Vous avez rassembl\233 les 10 bottes de foin.[ENTER]Apportez-les au palefrenier afin qu'il puisse[ENTER]nourrir les chevaux. "
gameforge.subquest_36._120_sayTitle = "Du foin pour l'\233table "
gameforge.subquest_36._130_say = "Il y a p\233nurie de nourriture dans les \233tables.[ENTER]Trouvez 10 bottes de foin et apportez-les au[ENTER]palefrenier avant que les chevaux ne meurent de[ENTER]faim ! Vous pouvez en trouver en chassant. "
gameforge.subquest_36._140_npcChat = "Vous avez besoin de foin ? "
gameforge.subquest_36._150_say = "Yonah vous envoie ? Je n'ai entendu que du bien[ENTER]de vous. Tous nos chevaux sont en train de mourir[ENTER]de faim. Nous devons les sauver. Aidez-moi \224[ENTER]trouver du foin pour les chevaux ! "
gameforge.subquest_36._160_say = "Une promesse est une promesse. Et j'aimerais bien[ENTER]monter \224 cheval un jour ! Je dois absolument[ENTER]trouver du foin ! "
gameforge.subquest_36._170_say = "Je suis d\233sol\233. J'ai cherch\233 mais impossible de[ENTER]trouver du foin. "
gameforge.subquest_36._180_say = "J'attendais, en esp\233rant que vous pourriez le[ENTER]faire. Je vous l'accorde, ce n'est pas tr\232s bien[ENTER]de vous refiler le travail... Mais, pourriez-vous[ENTER]essayer encore ?[ENTER][ENTER]Je connais quelqu'un d'un autre empire, il est[ENTER]tr\232s fort. Si vous m'aidez, je lui demanderai[ENTER]s'il peut faire quelque chose pour vous. "
gameforge.subquest_36._190_select = "Essayer encore "
gameforge.subquest_36._200_say = "Bien s\251r que je vais vous aider! Je n'ai pas la[ENTER]force... "
gameforge.subquest_36._20_npcChat = "L'\233table a des ennuis "
gameforge.subquest_36._210_say = "Je n'ai pas assez de force. J'aimerais vous[ENTER]aider, mais je n'y arrive pas. Je ne suis pas[ENTER]assez fort. "
gameforge.subquest_36._220_npcChat = "J'ai le foin ! "
gameforge.subquest_36._230_say = "Vous avez le foin ? Oh, merci. Nous n'en avions[ENTER]pas assez pour nourrir tous les chevaux, donc[ENTER]j'en avais parl\233 \224 Yonah. C'est un bon ami \224 moi.[ENTER]J'avais eu cette id\233e qu'il en parle un peu[ENTER]partout autour de lui. Je n'aurais pas pens\233 que[ENTER]\231a puisse \234tre si rapide. Regardez avec quel[ENTER]enthousiasme mangent ces chevaux ! "
gameforge.subquest_36._240_sayReward = "Vous avez re\231u 1.800.000 points d'exp\233rience. "
gameforge.subquest_36._250_sendLetter = "Retournez voir Yonah "
gameforge.subquest_36._260_sayTitle = "Retournez voir Yonah "
gameforge.subquest_36._270_say = "Vous avez apport\233 les 10 bottes de foin aux[ENTER]chevaux affam\233s du palefrenier. Retournez voir[ENTER]Yonah et racontez-lui ! "
gameforge.subquest_36._280_npcChat = "Prendre soin des chevaux ! "
gameforge.subquest_36._290_say = "Hello, vous \234tes revenu ![ENTER]Cela n'a pas du \234tre facile de trouver tout ce[ENTER]foin. Merci de ne pas avoir abandonn\233 ! Voici une[ENTER]petite r\233compense. "
gameforge.subquest_36._300_sayReward = "Vous avez re\231u un livre de qu\234te. "
gameforge.subquest_36._30_say = "H\233, j'ai une question! Je sais que quelqu'un[ENTER]d'autre est responsable des \233curies, mais nous[ENTER]avons eu un tas d'ennuis r\233cemment. Pendant la[ENTER]guerre, il a \233t\233 beaucoup exig\233 des chevaux, mais[ENTER]les chevaux m\234me adultes vraiment ont leurs[ENTER]limites... "
gameforge.subquest_36._40_say = "Il y a beaucoup de chevaux, mais pas assez de[ENTER]nourriture. Beaucoup de chevaux meurent.[ENTER]Pourriez-vous trouver de la nourriture pour que[ENTER]ces chevaux puissent survivre? Vous \234tes le seul[ENTER]\224 pouvoir le faire. Trouvez 10 bottes de foin et[ENTER]ramenez-les ici. Le palefrenier comprendra si[ENTER]vous lui dites que vous venez de ma part. "
gameforge.subquest_36._50_select = "Je pars imm\233diatement ! "
gameforge.subquest_36._60_select = "Non, c'est une t\226che subalterne. "
gameforge.subquest_36._70_say = "De nos jours, de plus en plus de gens veulent un[ENTER]cheval. Mais il n'y a pas assez de cheval pour[ENTER]tout le monde, et pas assez de nourriture non[ENTER]plus. Les chevaux meurent de faim. Revenez si[ENTER]vous changez d'avis. "
gameforge.subquest_36._80_say = "Ahhh, les chevaux n'ont pas assez \224 manger... Je[ENTER]suppose que je vais devoir faire avec ... "
gameforge.subquest_36._90_say = "Je sais que vous \234tes occup\233 et j'appr\233cie[ENTER]vraiment votre aide. Les chevaux sont importants[ENTER]de nos jours. Nous avons vraiment besoin de foin. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah fait de son mieux pour fabriquer une[ENTER]nouvelle porcelaine mais n'avance plus du tout.[ENTER]Allez voir Uriel et demandez-lui ce qu'il sait de[ENTER]la Porcelaine C\233ladon. "
gameforge.subquest_37._10_targetVid = "Le secret de la porcelaine c\233ladon "
gameforge.subquest_37._110_npcChat = "Connaissez-vous la porcelaine C\233ladon ? "
gameforge.subquest_37._120_sayTitle = "Uriel: "
gameforge.subquest_37._130_say = "La porcelaine c\233ladon ? A vrai dire, je connais[ENTER]beaucoup de choses concernant l'histoire et la[ENTER]science, mais je ne suis pas vraiment int\233ress\233[ENTER]par l'art. Je ne peux rien vous dire du tout \224[ENTER]propos de cette porcelaine c\233ladon. Mais[ENTER]peut-\234tre que Soon sait quelque chose. Les gens[ENTER]ne l'aiment pas vraiment, mais il lit toutes[ENTER]sortes de livres. Il est possible qu'il sache[ENTER]quelque chose. "
gameforge.subquest_37._140_makequestbutton = "Allez voir Soon "
gameforge.subquest_37._150_targetVid = "Allez voir Soon "
gameforge.subquest_37._160_say = "Malheureusement Uriel ne sait rien concernant la[ENTER]porcelaine C\233ladon. Mais Soon lit tellement de[ENTER]livres. Allez le voir, peut-\234tre qu'il sait[ENTER]quelque chose. "
gameforge.subquest_37._170_sayTitle = "Soon: "
gameforge.subquest_37._180_say = "Que voulez-vous\160? Ne me d\233rangez pas quand je[ENTER]lis\160! Quoi\160? La porcelaine C\233ladon\160? \201videmment[ENTER]que je connais\160! J'ai lu tout un tas de livres[ENTER]sur le sujet. On ne m'appelle pas le rat de[ENTER]biblioth\232que pour rien vous savez\160! Je peux[ENTER]comprendre tout ce qui est expliqu\233 dans un[ENTER]livre\160! "
gameforge.subquest_37._190_say = "Je pourrais vous \233crire tout ce que je sais de la[ENTER]Porcelaine C\233ladon l\224, mais pourquoi le[ENTER]ferais-je\160? Hum, attendez un peu, j'ai une id\233e\160:[ENTER]j'ai command\233 au marchand ambulant du village[ENTER]voisin un livre qui manque \224 ma collection mais[ENTER]je n'ai pas le temps d'aller le chercher. Allez[ENTER]me le chercher s'il vous plait, et je vous[ENTER]parlerai de la porcelaine. Allez-y\160! "
gameforge.subquest_37._200_makequestbutton = "Allez voir le marchand ambulant "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "Allez voir le marchand ambulant "
gameforge.subquest_37._220_say = "Soon sait des choses concernant la porcelaine[ENTER]C\233ladon. Il ne veut partager son savoir qu'en[ENTER]\233change de votre aide. Allez chercher le livre[ENTER]qu'il a command\233 au marchand ambulant et[ENTER]apportez-lui. "
gameforge.subquest_37._230_npcChat = "Soon m'envoie ... "
gameforge.subquest_37._240_say = "Oh, vous venez m'aider \224 nouveau ? Ah, vous venez[ENTER]chercher le livre pour Soon. J'aurais \233t\233 amen\233 \224[ENTER]aller au village d'\224 c\244t\233, mais il est impatient[ENTER]et finit toujours par demander \224 quelqu'un d'y[ENTER]aller \224 sa place. Hum, le voici.[ENTER]Je ne comprends pas pourquoi Soon aime autant ces[ENTER]bouts de papiers. Il est tout de m\234me plus[ENTER]important de gagner de l'argent ! "
gameforge.subquest_37._250_qSetTitle = "Retournez voir Soon "
gameforge.subquest_37._260_targetVid = "Retournez voir Soon "
gameforge.subquest_37._270_say = "Le marchand ambulant vous a donn\233 le livre pour[ENTER]Soon. Apportez-lui, il vous dira alors ce qu'il[ENTER]sait concernant la porcelaine C\233ladon. "
gameforge.subquest_37._280_npcChat = "J'ai le livre "
gameforge.subquest_37._290_say = "Hey, j'ai enfin mon livre ! Merci beaucoup. Il y[ENTER]a si peu de livres que je n'ai encore lu ...[ENTER]Je vous ai \233crit ici ce que je sais de la[ENTER]porcelaine C\233ladon. Avec mes notes, vous pourrez[ENTER]fabriquer une fantastique porcelaine. Bon, je[ENTER]vais lire mon nouveau livre. Adieu. "
gameforge.subquest_37._300_makequestbutton = "Retournez voir Yonah "
gameforge.subquest_37._30_say = "Hmm... Ce n'est pas le bon. Celui-ci non plus...[ENTER]Oh, bonjour ! Regardez : je fabrique de la[ENTER]porcelaine en continue, mais chaque fois presque[ENTER]elle se casse imm\233diatement. Je pense que j'ai[ENTER]besoin d'un nouveau type de porcelaine[ENTER]r\233volutionnaire... "
gameforge.subquest_37._310_targetVid = "Apportez les notes \224 Yonah "
gameforge.subquest_37._320_say = "Soon a tenu sa promesse et a \233crit ce qu'il sait[ENTER]\224 propos de la porcelaine C\233ladon. Apportez les[ENTER]notes \224 Yonah. "
gameforge.subquest_37._330_say = "Oh ! Tout ce qui concerne la fabrication de la[ENTER]porcelaine C\233ladon est \233crit ici. Avec l'aide de[ENTER]ces notes je vais enfin entrer dans l'histoire en[ENTER]tant que ma\238tre cr\233atif. Merci pour votre aide.[ENTER]Bient\244t je vous montrerai la plus belle c\233ramique[ENTER]au monde ! Vous pouvez compter sur moi ! Ma[ENTER]porcelaine C\233ladon sera tellement exceptionnelle[ENTER]qu'elle perdurera pendant des si\232cles. "
gameforge.subquest_37._340_sayReward = "Vous avez re\231u 2.500.000 points d'exp\233rience. "
gameforge.subquest_37._350_sayReward = "Vous avez re\231u 35\160000 Yangs. "
gameforge.subquest_37._360_sayReward = "Vous recevez des chaussures de jade+3 "
gameforge.subquest_37._40_say = "J'ai essay\233 une nouvelle m\233thode... Ce n'est pas[ENTER]facile de fabriquer cette porcelaine c\233ladon.[ENTER]C'est pour cette raison que peu de gens savent[ENTER]comment le faire. Je dois savoir le faire aussi,[ENTER]pour l'accomplissement de mon art. Dans ce cas...[ENTER]Oui, Uriel doit conna\238tre des choses.[ENTER]Allez-lui demander s'il vous pla\238t, il vous[ENTER]aidera s\251rement! "
gameforge.subquest_37._50_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_37._60_say = "Hmm, je suppose que vous \234tes trop occup\233 ?[ENTER]N'oubliez pas de revenir quand vous aurez plus de[ENTER]temps. "
gameforge.subquest_37._70_say = "Je veux fabriquer la meilleure porcelaine... Je[ENTER]comprends... \192 bient\244t.... "
gameforge.subquest_37._80_say = "Merci. Uriel saura quoi faire. \192 bient\244t ! "
gameforge.subquest_37._90_targetVid = "Allez voir Uriel "
gameforge.subquest_38 = {}
gameforge.subquest_38._100_say = "L'arc ouvrag\233 du Chasseur, qui \233tait un objet[ENTER]d'h\233ritage familial, a \233t\233 vol\233. Allez au donjon[ENTER]des singes experts et reprenez l'arc ouvrag\233 des[ENTER]mains des vilains singes. "
gameforge.subquest_38._10_targetVid = "Le tr\233sor du chasseur "
gameforge.subquest_38._110_sendLetter = "Trouvez l'arc ouvrag\233 "
gameforge.subquest_38._120_targetVid = "Allez voir le chasseur Yang-Shin "
gameforge.subquest_38._125_say = "Vous avez trouv\233 l'arc ouvrag\233 du chasseur.[ENTER]Rapportez-le \224 Yang-Shin. "
gameforge.subquest_38._130_npcChat = "Voici l'arc... "
gameforge.subquest_38._140_say = "Quoi ? Oui !!! C'est lui ! Le splendide arc[ENTER]ouvrag\233 ! Ah l'honneur de mes anc\234tres est enfin[ENTER]r\233tabli ! J'ai souffert pendant si longtemps de[ENTER]me l'\234tre fait voler. Je vous suis vraiment[ENTER]reconnaissant pour votre aide. C'est un honneur[ENTER]pour moi de vous remettre ceci. Ce n'est pas[ENTER]grand chose, mais \231a vient du c\156ur. Prenez-la[ENTER]s'il vous pla\238t. Merci beaucoup, je peux vivre en[ENTER]paix \224 pr\233sent. "
gameforge.subquest_38._150_sayReward = "Vous recevez 1.500.000 points d'exp\233rience. "
gameforge.subquest_38._160_sayReward = "Vous avez re\231u 35\160000 Yangs. "
gameforge.subquest_38._170_sayReward = "Vous avez re\231u des capes de bravoure. "
gameforge.subquest_38._180_say = "Vous avez trouv\233 mon arc ? Mais ou est-il ?[ENTER]L'avez-vous \233gar\233 ? "
gameforge.subquest_38._190_select = "Je cherche encore. "
gameforge.subquest_38._200_say = "Faites comme bon vous semble.[ENTER]Occupez-vous de vos affaires. "
gameforge.subquest_38._20_say = "H\233, vous auriez deux secondes pour m'\233couter ?[ENTER]Comme vous pouvez le voir, je suis un chasseur,[ENTER]ma famille chasse depuis des g\233n\233rations. Nous[ENTER]sommes tous des chasseurs, une famille pleine de[ENTER]bravoure. Mais j'ai commis une erreur qui risque[ENTER]de me discr\233diter aupr\232s de toute ma famille... "
gameforge.subquest_38._210_say = "Pouvez-vous essayer ? Merci. Avec vos[ENTER]comp\233tences, vous devez \234tre capable de le faire. "
gameforge.subquest_38._30_say = "C'est \224 propos d'un arc ouvrag\233 qui fut vol\233 il y[ENTER]a fort longtemps par les singes alors que je ne[ENTER]faisais pas attention. Dans le donjon des singes[ENTER]alors que je me battais, ils m'ont montr\233 leur[ENTER]vrai visage, celui du mal, et me l'ont vol\233. "
gameforge.subquest_38._40_say = "Je ne suis jamais all\233 bien loin dans le donjon[ENTER]des singes, je n'y connais donc pas grand chose.[ENTER]J'ai besoin de votre aide... J'ai entendu dire[ENTER]par de nombreuses personnes que vous \233tiez plein[ENTER]de talent. C'est pourquoi je vous demande cette[ENTER]faveur. Je ne pourrais plus regarder mes anc\234tres[ENTER]en face sans cet arc ouvrag\233... "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Oh, j'en ai besoin le plus vite possible...[ENTER]S'il vous pla\238t revenez quand vous aurez le[ENTER]temps. \192 bient\244t. "
gameforge.subquest_38._70_say = "Bien dans ce cas ... Faites attention \224 vous. "
gameforge.subquest_38._80_say = "Vous le trouverez facilement car c'est un arc[ENTER]tr\232s finement ouvrag\233. Je vous r\233compenserai[ENTER]g\233n\233reusement ! "
gameforge.subquest_38._90_sayTitle = "Cherchez l'arc ouvrag\233. "
