gameforge.subquest_39._10_targetVid = "Aidez Balso le tra\238tre "
gameforge.subquest_39._110_say = "La sant\233 de Balso le Tra\238tre s'aggrave. Allez[ENTER]voir Baek-Go et demandez-lui ce qu'on peut faire[ENTER]pour aider Balso. "
gameforge.subquest_39._120_makequestbutton = "Allez voir Baek-Go "
gameforge.subquest_39._130_qSetTitle = "Allez voir Baek-Go "
gameforge.subquest_39._140_targetVid = "Allez voir Baek-Go "
gameforge.subquest_39._150_npcChat = "J'ai un patient ... "
gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Ah, c'est vous ! Comment allez-vous ? Vous vous[ENTER]occupez de la maladie d'un patient ?[ENTER]Expliquez-moi ses sympt\244mes. Hum, quels[ENTER]m\233dicaments a t-il pris jusque l\224 ? Quoi ?!? Cela[ENTER]ne m'\233tonne pas qu'il aille encore plus mal ![ENTER]Ce rem\232de est totalement inappropri\233 ! "
gameforge.subquest_39._180_say = "Il a de la chance d'\234tre encore en vie ! C'est[ENTER]tr\232s dangereux de donner un mauvais traitement \224[ENTER]un patient tr\232s malade. Mais je sais ce qui peut[ENTER]l'aider. Il existe une herbe sp\233ciale qui[ENTER]annihile le poison pr\233sent dans le corps et vous[ENTER]remet sur pieds. Cependant, aller le chercher est[ENTER]tr\232s dangereux. "
gameforge.subquest_39._190_say = "Si mes souvenirs sont bons, cette herbe pousse[ENTER]uniquement \224 Sangsun Dong.[ENTER]Elle est gard\233e par le Seigneur Singe qui aime en[ENTER]manger. Vous devrez donc le tuer pour l'obtenir.[ENTER]Je pourrais vous pr\233parer un rem\232de si vous m'en[ENTER]rapportez. "
gameforge.subquest_39._200_select = "D'accord, je le ferai. "
gameforge.subquest_39._20_npcChat = "\192 propos du rem\232de ... "
gameforge.subquest_39._210_select = "Je ne peux pas faire \231a "
gameforge.subquest_39._220_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_39._230_select = "Oui "
gameforge.subquest_39._240_say = "Bien, peut-\234tre qu'un jour tu auras un peu de[ENTER]temps libre. Beaucoup de gens sont malades, mais[ENTER]seuls quelques-uns cherchent un rem\232de... "
gameforge.subquest_39._250_say = "Hum, cela devait \234tre ainsi. C'est une honte de[ENTER]ne trouver personne d'assez courageux. Comment[ENTER]cela va t-il finir ... "
gameforge.subquest_39._260_say = "Oh, merci. Cette t\226che sera difficile mais vous[ENTER]aiderez tout un tas de gens ! "
gameforge.subquest_39._270_makequestbutton = "L'herbe du Seigneur Singe "
gameforge.subquest_39._280_targetVid = "Retournez voir Baek-Go "
gameforge.subquest_39._290_sayTitle = "Vous avez trouv\233 de l'herbe des singes (D) "
gameforge.subquest_39._300_say = "Vous avez trouv\233 l'herbe sur le Seigneur Singe.[ENTER]Apportez-la \224 Baek-Go, il pourra ainsi pr\233parer[ENTER]le rem\232de pour Balso. "
gameforge.subquest_39._30_say = "Merci de m'avoir rapport\233 un traitement la[ENTER]derni\232re fois. Mais il y a un soucis... Le rem\232de[ENTER]ne m'a pas gu\233ri... Je pense que \231a a empir\233.[ENTER](tousse) J'ai besoin d'un traitement... "
gameforge.subquest_39._310_sayTitle = "Allez chercher l'herbe au Donjon Sangsun Dong "
gameforge.subquest_39._320_say = "Baek-Go peut pr\233parer un traitement pour soigner[ENTER]Balso. Pour cela, il a besoin de l'herbe des[ENTER]singes (D). Vous la trouverez en tuant le[ENTER]Seigneur Singe dans le Donjon difficile des[ENTER]Singes. "
gameforge.subquest_39._330_npcChat = "L'herbe des singes (D) ... "
gameforge.subquest_39._340_say = "La maladie semble s'\233tendre, une \233pid\233mie[ENTER]s'installe. Et nous en ignorons la cause.[ENTER]Cependant, l'acad\233mie semble avoir trouv\233 un[ENTER]rem\232de \224 l'aide de l'herbe des singes. Quoi ?[ENTER]Avez-vous d\233j\224 trouv\233 l'herbe ? "
gameforge.subquest_39._350_select = "Pas encore, mais bient\244t ! "
gameforge.subquest_39._360_select = "Je ne peux pas avoir l'herbe... "
gameforge.subquest_39._370_say = "Oh, vous voulez vraiment abandonner....[ENTER]Bien, il n'y a rien que vous puissiez faire.[ENTER]Qu'est-ce que je peux faire sans \231a...[ENTER][ENTER]Cette herbe serait une b\233n\233diction r\233elle. "
gameforge.subquest_39._380_select = "Je ne peux pas le faire. "
gameforge.subquest_39._390_select = "Je veux aider! "
gameforge.subquest_39._400_say = "Le Singe est trop fort pour moi. Je ne peux pas[ENTER]lui arracher cette herbe, d\233sol\233. "
gameforge.subquest_39._40_say = "Je sais qu'il y a un m\233decin dans le village d'\224[ENTER]c\244t\233. Pourriez-vous lui expliquer comment je me[ENTER]sens, comme \231a il pourra vous indiquer ce qui[ENTER]peut \234tre fait. Comme vous savez, je ne peux[ENTER]quitter le village dans ces conditions. Je vous[ENTER]serez reconnaissant et je vous r\233compenserai[ENTER]comme il se doit. "
gameforge.subquest_39._410_say = "Vous refusez d'aider des tas de personnes[ENTER]souffrant d'une myst\233rieuse et terrible maladie.[ENTER]Hors de ma vue ! "
gameforge.subquest_39._420_say = "Vous avez raison. Quelqu'un doit trouver cette[ENTER]herbe sinon des tas de gens mourront de cette[ENTER]maladie. Je vais y veiller. "
gameforge.subquest_39._430_say = "Bien donc, d\233p\234chez vous! "
gameforge.subquest_39._440_say = "Vous avez vraiment r\233ussi \224 trouver l'herbe ![ENTER]J'esp\232re qu'elle nous aidera vraiment \224 combattre[ENTER]cette terrible maladie. Attendez une seconde, je[ENTER]vais pr\233parer le rem\232de... "
gameforge.subquest_39._450_sayTitle = "Baek-Go: "
gameforge.subquest_39._460_say = "Voici le rem\232de. Apportez le vite au patient. Il[ENTER]devrait aller mieux. Dites-lui aussi qu'avant de[ENTER]s'auto-m\233dicamenter, il faut toujours consulter[ENTER]un vrai m\233decin. "
gameforge.subquest_39._470_makequestbutton = "Apportez le rem\232de \224 Balso "
