gameforge.subquest_39._500_say = "Baek-Go a pr\233par\233 le rem\232de \224 partir de l'herbe[ENTER]des singes (D), qui peut soigner de nombreuses[ENTER]maladies rares.[ENTER]Apportez-le \224 Balso le tra\238tre au village voisin. "
gameforge.subquest_39._50_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_39._510_npcChat = "Voici le m\233dicament. "
gameforge.subquest_39._520_say = "M'apportez-vous un nouveau rem\232de ? Des progr\232s[ENTER]ont \233t\233 faits dans la recherche ? D\233sol\233 de vous[ENTER]emb\234ter. J'aurais mieux fait de consulter un[ENTER]m\233decin avant toute chose. Cependant, je me dois[ENTER]d'accepter ce rem\232de. "
gameforge.subquest_39._530_say = "Merci de m'aider \224 aller mieux. Je n'ai pas[ENTER]beaucoup d'amis. Tenez, c'est peu je sais, mais[ENTER]\231a vient du c\156ur. Acceptez s'il vous plait. Je ne[ENTER]vous oublierai jamais. "
