gameforge.subquest_40._220_say = "Fantastique travail ! Nous pouvons enfin nous[ENTER]pr\233parer pour l'assaut. Je vais imm\233diatement[ENTER]ordonner la fabrication d'arcs. Ce fut vraiment[ENTER]un travail formidable. J'esp\232re que nous pourrons[ENTER]\224 nouveau compter sur vous plus tard. "
gameforge.subquest_40._230_say = "Voici votre r\233compense. La prochaine fois que[ENTER]j'ai une t\226che importante, c'est \224 vous que je[ENTER]penserai en premier ! Je vous souhaite le[ENTER]meilleur, \224 bient\244t ! "
