gameforge.subquest_40._30_say = "Les archers sont un \233l\233ment strat\233gique important[ENTER]en temps de guerre. D\232s que les ennemis sont \224[ENTER]port\233e de tir de nos archers. C'est une bonne[ENTER]mani\232re de r\233duire leur nombre rapidement. Mais[ENTER]s'il y a trop d'attaques bient\244t nous serons en[ENTER]manque de fl\232ches. "
gameforge.subquest_40._40_say = "C'est pour cette raison que nous avons besoin de[ENTER]vous ! Allez au Mont Sohan, tuez des Archers[ENTER]Pestif\233r\233s et prenez leurs hauts de fl\232che. Ces[ENTER]fl\232ches sont empoisonn\233es mais elle nous aiderons[ENTER]\224 combattre nos ennemis. Nous avons besoin de[ENTER]5.000 Hauts de Fl\232che. Que dites-vous ? "
