gameforge.subquest_41._100_say = "Vous avez r\233uni les 100 \189il d'araign\233e pour la[ENTER]nouvelle recette d'Octavio. Vous devriez vite lui[ENTER]apporter. "
gameforge.subquest_41._10_targetVid = "Yeux d'araign\233e sp\233ciaux "
gameforge.subquest_41._110_sayTitle = "Trouvez les \189il d'araign\233e "
gameforge.subquest_41._120_say = "Octavio a envie de tester une nouvelle recette[ENTER]appel\233e \189il d'araign\233es sp\233ciaux. Pour la[ENTER]pr\233parer, il a besoin de 100 \189il d'araign\233es[ENTER]provenant des araign\233es du d\233sert de Yongbi. "
gameforge.subquest_41._130_targetVid = "Retournez voir Octavio "
gameforge.subquest_41._140_npcChat = "J'ai les Oeils d'araign\233e. "
gameforge.subquest_41._150_sayTitle = "Octavio: "
gameforge.subquest_41._160_say = "Montrez-moi. 100 \140ils exactement, parfait\160![ENTER]Alors, voyons voir ...[ENTER]Hum, et voil\224\160! Vous voulez go\251ter\160? Ne me[ENTER]regardez pas comme cela, je ne vais pas vous[ENTER]tuer\160! "
gameforge.subquest_41._170_say = "Humm ... Quelle exp\233rience ! Tr\232s nutritif, pas[ENTER]trop doux ... quel go\251t incroyable ! Cela en[ENTER]valait la peine ! Je n'y serais pas parvenu sans[ENTER]vous. Merci beaucoup pour votre aide ! "
gameforge.subquest_41._180_sayReward = "Vous avez re\231u 2.100.000 points d'exp\233rience. "
gameforge.subquest_41._190_say = "Que dites-vous ? Il n'y en a pas 100, m\234me pas[ENTER]besoin de compter pour le voir ! Ramenez-m'en[ENTER]d'autres s'il vous plait. "
gameforge.subquest_41._200_say = "Je voulais tellement la faire ...[ENTER][ENTER]Soit, merci, adieu. "
gameforge.subquest_41._20_say = "Bonjour, comment allez-vous ? Je suis en train de[ENTER]lire un livre de recettes que Soon m'a offert.[ENTER]J'ai trouv\233 une recette tr\232s int\233ressante appel\233e[ENTER] \189ils d'araign\233e sp\233ciaux. Je n'ai jamais[ENTER]entendu parler de \231a avant, et vous ? Il[ENTER]semblerait que ce met vienne d'un autre pays. "
gameforge.subquest_41._210_say = "Merci de ne pas me laisser en plan. Vous \234tes[ENTER]tr\232s aimable ! "
gameforge.subquest_41._30_say = "Il serait tr\232s sympathique de pouvoir tester[ENTER]cette recette, mais comment puis-je trouver ces[ENTER]\140ils d'araign\233es ? J'ai vraiment besoin de votre[ENTER]aide une fois de plus ! S'il vous plait aller me[ENTER]chercher les \156ils d'araign\233es sur les araign\233es[ENTER]au d\233sert de Yongbi. "
gameforge.subquest_41._40_say = "Pouvez-vous le faire pour moi ? Je vous en serais[ENTER]tr\232s reconnaissant. Pour tester cette recette[ENTER]j'ai besoin d'exactement 100 \140ils d'araign\233es.[ENTER]Je suis tr\232s excit\233 ... "
gameforge.subquest_41._50_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_41._60_say = "J'ai vraiment tr\232s envie de faire cette recette,[ENTER]donc si vous avez envie de me faire plaisir,[ENTER]revenez. "
gameforge.subquest_41._70_say = "Hum... Comment vais-je faire pour trouver ces[ENTER]\140ils d'araign\233es ?? Tant pis, \224 bient\244t. "
gameforge.subquest_41._80_say = "Merci, je savais que vous me feriez cette faveur.[ENTER]Je vous pr\233parerai un succulent repas. "
gameforge.subquest_41._90_sayTitle = "Retournez voir Octavio "
gameforge.subquest_42 = {}
gameforge.subquest_42._100_say = "Bien navr\233 d'entendre \231a... J'ai entendu[ENTER]tellement de voix de morts ne pouvant \234tre en[ENTER]paix. Nous devons vraiment les aider. Je vais[ENTER]demander \224 quelqu'un d'autre. Adieu. "
gameforge.subquest_42._10_targetVid = "Laissez les morts reposer en paix "
gameforge.subquest_42._110_say = "Vous \234tes tellement courageux ! Je suis convaincu[ENTER]qu'avec votre aide, nos petits guerriers en[ENTER]apprentissage vont atteindre le Nirvana ! "
gameforge.subquest_42._120_say = "De terribles guerres ont tu\233 de jeunes hommes.[ENTER]Ils ont combattu en premi\232re ligne, luttant pour[ENTER]leur vie, leur famille, leur patrie. Mais apr\232s[ENTER]leur mort, certains d'entre eux ne purent trouver[ENTER]le repos et rest\232rent bloqu\233s dans notre monde. "
gameforge.subquest_42._130_say = "J'ai entendu dire que le fier chef funeste[ENTER]d\233tient une \233charpe et une doctrine du Temple. Je[ENTER]vous en supplie, aidez-moi \224 les r\233cup\233rer afin[ENTER]que nous puissions apporter la paix aux soldats[ENTER]morts pour leur patrie. "
gameforge.subquest_42._140_sayTitle = "Retournez voir le Ma\238tre dragon "
gameforge.subquest_42._150_say = "Vous avez trouv\233 l'\233charpe et la doctrine du[ENTER]Temple. Apportez-les au Ma\238tre Dragon, afin que[ENTER]les chamanes puissent entamer leur rituel pour[ENTER]calmer les esprits des morts. "
gameforge.subquest_42._160_sayTitle = "Trouver l'\233charpe et la doctrine du temple. "
gameforge.subquest_42._170_say = "Les chamanes ont besoin d'une \233charpe et d'une[ENTER]doctrine du Temple pour effectuer une c\233r\233monie[ENTER]visant \224 calmer les esprits des soldats morts[ENTER]pendant la guerre. Tuez le fier chef funeste du[ENTER]Temple de Hwang pour obtenir ces objets. "
gameforge.subquest_42._180_npcChat = "J'ai l'\233charpe et la doctrine. "
gameforge.subquest_42._190_say = "Formidable. Nous allons pouvoir apaiser les[ENTER]esprits des soldats morts. Ils ont fait de leur[ENTER]mieux, ils peuvent reposer en paix. Laissez-moi[ENTER]vous offrir une r\233compense pour vos efforts. "
gameforge.subquest_42._200_sayReward = "Vous avez re\231u 1.700.000 points d'exp\233rience. "
gameforge.subquest_42._20_sayTitle = "Ma\238tre Dragon : "
gameforge.subquest_42._210_sayReward = "Vous avez re\231u 30\160000 Yangs. "
gameforge.subquest_42._220_sayReward = "Vous avez re\231u 3 Diamants. "
gameforge.subquest_42._230_say = "Formidable. Nous allons pouvoir apaiser les[ENTER]esprits des soldats morts. Ils ont fait de leur[ENTER]mieux, ils peuvent reposer en paix. Laissez-moi[ENTER]vous offrir une r\233compense pour vos efforts. "
gameforge.subquest_42._30_say = "De terribles guerres ont tu\233 de jeunes hommes.[ENTER]Ils ont combattu en premi\232re ligne, luttant pour[ENTER]leur vie, leur famille, leur patrie. Mais apr\232s[ENTER]leur mort, certains d'entre eux ne purent trouver[ENTER]le repos et rest\232rent bloqu\233s dans notre monde. "
gameforge.subquest_42._40_say = "On dit que depuis la guerre, ils peuvent r\233sister[ENTER]\224 la mort. Ils pensent qu'ils doivent toujours[ENTER]d\233fendre leur pays.[ENTER]Nos chamanes veulent organiser une c\233r\233monie pour[ENTER]calmer leurs esprits. Pour ce faire, nous avons[ENTER]besoin d'une \233charpe et d'une doctrine du Temple,[ENTER]qui sont assez difficiles \224 trouver de nos jours.[ENTER]Pourriez-vous aller nous les chercher\160? "
gameforge.subquest_42._50_say = "J'ai entendu dire que le fier chef funeste[ENTER]d\233tient une \233charpe et une doctrine du Temple. Je[ENTER]vous en supplie, aidez-moi \224 les r\233cup\233rer afin[ENTER]que nous puissions apporter la paix aux soldats[ENTER]morts pour leur patrie. "
gameforge.subquest_42._60_select = "Je vais vous aider "
gameforge.subquest_42._70_select = "Je suis d\233sol\233, je suis terrifi\233 "
gameforge.subquest_42._80_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_42._90_say = "Aidez nous \224 faire en sorte qu'ils reposent en[ENTER]paix. Je vous attends ici. "
gameforge.subquest_44 = {}
gameforge.subquest_44._100_sendLetter = "L'araign\233e \224 clochette "
gameforge.subquest_44._10_targetVid = "L'araign\233e "
gameforge.subquest_44._110_say = "Taurean a dit qu'il avait accroch\233 une clochette[ENTER]sur une araign\233e. \192 pr\233sent Yu-Rang veut savoir[ENTER]si son ami est vraiment courageux ou pas. Allez[ENTER]chercher cette araign\233e dans le d\233sert. "
gameforge.subquest_44._120_say = "Avez-vous trouv\233 l'araign\233e \224 clochette ? Non ?[ENTER]Vous ne la trouverez probablement jamais. Taurean[ENTER]n'est qu'un menteur qui ne cherche qu'\224 se rendre[ENTER]int\233ressant ! "
gameforge.subquest_44._130_sendLetter = "Je ne peux trouver de clochette "
gameforge.subquest_44._140_sayTitle = "Plein d'araign\233es, aucune clochette "
gameforge.subquest_44._150_say = "Vous avez tu\233 beaucoup d'araign\233es mais n'avez[ENTER]pas trouv\233 de clochette. Inutile de continuer \224[ENTER]chercher. Il est pr\233f\233rable de retourner voir[ENTER]Taurean et de lui demander de dire la v\233rit\233. "
gameforge.subquest_44._160_sendLetter = "Allez voir Taurean "
gameforge.subquest_44._170_targetVid = "Demandez \224 Taurean pour la clochette "
gameforge.subquest_44._180_say = "C'est peut-\234tre simplement que Taurean n'a pas eu[ENTER]assez de courage pour accrocher une clochette sur[ENTER]une araign\233e. Allez le voir afin qu'il vous dise[ENTER]la v\233rit\233. "
gameforge.subquest_44._190_npcChat = "Dites-moi, pour la clochette... "
gameforge.subquest_44._200_say = "Vous \234tes au courant pour le pari avec Yu-Rang ?[ENTER]Elle ne me croit pas et pense que je ne l'ai pas[ENTER]fait. Elle pense que je serais mort de peur rien[ENTER]qu'\224 l'id\233e de m'approcher d'une araign\233e. "
gameforge.subquest_44._20_npcChat = "Une araign\233e \224 clochette ? "
gameforge.subquest_44._210_say = "Honn\234tement ... elle a raison. Je n'ai pas \233t\233[ENTER]assez courageux, et j'ai \233t\233 trop orgueilleux[ENTER]pour l'avouer. "
gameforge.subquest_44._220_say = "Mais vous paraissez tr\232s courageux ! Vous[ENTER]pourriez accrocher la clochette sur une araign\233e[ENTER]\224 ma place, n'est-ce pas ? S'il vous plait je[ENTER]vous en supplie ! Sinon, ils vont tous se moquer[ENTER]de moi jusqu'\224 la fin de ma vie. "
gameforge.subquest_44._230_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_44._240_say = "Vous ne voulez pas le faire ? Mais comment[ENTER]vais-je pouvoir dire la v\233rit\233 \224 Yu-Rang ?[ENTER]S'il vous plait, aidez-moi. Revenez quand vous[ENTER]aurez du temps. "
gameforge.subquest_44._250_say = "Yu-Rang ne m'adressera plus jamais la parole. Ou[ENTER]juste pour se moquer de moi... "
gameforge.subquest_44._260_say = "Ah, j'avais raison. Je savais que vous \233tiez[ENTER]aimable et serviable. Merci pour votre aide.[ENTER]Bonne chance! "
gameforge.subquest_44._270_sendLetter = "Retournez voir Yu-Rang "
gameforge.subquest_44._280_say = "Retournez voir Yu-Rang et dites-lui les propos[ENTER]mensongers de Taurean. "
gameforge.subquest_44._290_npcChat = "Vous avez beaucoup d\233\231u Yu-Rang. "
gameforge.subquest_44._300_say = "Vous lui avez parl\233 ?[ENTER]Je peux comprendre qu'elle refuse d'\234tre mon amie[ENTER]\224 pr\233sent. Mais \231a me rend si triste.[ENTER]J'esp\232re pouvoir lui faire changer d'avis[ENTER]Peut-\234tre en lui faisant un cadeau ... "
gameforge.subquest_44._30_say = "Salut, pouvez-vous m'aider ? Mon ami Taurean est[ENTER]tr\232s en col\232re apr\232s moi parce que je l'ai trait\233[ENTER]de menteur. Il me dit qu'il est courageux et[ENTER]qu'il en a m\234me accroch\233 une clochette sur[ENTER]araign\233e. Mais je ne le crois pas. "
gameforge.subquest_44._310_npcChat = "Taurean a menti. "
gameforge.subquest_44._320_say = "Son histoire est fausse ?[ENTER]Bon, je ne lui en veux pas vraiment. Personne[ENTER]n'aime perdre la face.[ENTER]Mais il aurait au moins pu essayer ! Je n'ai pas[ENTER]envie d'\234tre amie avec un tel trouillard ! "
gameforge.subquest_44._330_sayReward = "Yu-Rang vous donnera une r\233compense pour votre[ENTER]honn\234tet\233. "
gameforge.subquest_44._340_sayReward = "Vous avez re\231u 30\160000 Yangs. "
gameforge.subquest_44._350_sayReward = "Vous avez re\231u 350.000 points d'exp\233rience. "
gameforge.subquest_44._360_sendLetter = "Clochette pour araign\233e "
gameforge.subquest_44._370_say = "Allez au d\233sert tuer de Jeunes Araign\233es et[ENTER]tentez d'accrocher la clochette de Taurean sur[ENTER]l'une d'elles. "
gameforge.subquest_44._380_npcChat = "Au sujet de la clochette ... "
gameforge.subquest_44._390_say = "Vous n'avez pas encore accroch\233 la clochette ?[ENTER]Faites-le rapidement s'il vous plait. Et[ENTER]assurez-vous que Yu-Rang ne vous voit pas ! "
gameforge.subquest_44._400_sendLetter = "C'est fait ! "
gameforge.subquest_44._40_say = "Je sais que je devrais faire confiance \224 mon ami,[ENTER]mais je veux savoir s'il l'a vraiment fait.[ENTER]C'est trop dangereux pour moi dans le d\233sert.[ENTER]Vous semblez si fort, vous pourriez le faire pour[ENTER]moi. Voulez-vous bien vous en charger ? "
gameforge.subquest_44._410_say = "C'\233tait difficile, mais vous \234tes enfin parvenu \224[ENTER]accrocher une clochette sur une araign\233e. Allez[ENTER]voir Yu-Rang et dites que Taurean l'a fait. "
gameforge.subquest_44._420_npcChat = "La clochette a \233t\233 accroch\233e "
gameforge.subquest_44._430_say = "Vous l'avez fait ? Fantastique ! Allez vite le[ENTER]dire \224 yu-Rang pour qu'elle me croit enfin ! "
gameforge.subquest_44._440_npcChat = "Taurean a dit la v\233rit\233. "
gameforge.subquest_44._450_say = "Encore vous ? Vous avez trouv\233 une araign\233e avec[ENTER]une clochette ? Taurean l'a donc fait ... Je ne[ENTER]le pensait pas capable. Peut-\234tre deviendra t-il[ENTER]un homme finalement apr\232s tout. Merci d'\234tre all\233[ENTER]v\233rifier. Une r\233compense vous attend. "
gameforge.subquest_44._460_sendLetter = "Retournez voir Taurean "
gameforge.subquest_44._470_targetVid = "Retournez voir Taurean "
gameforge.subquest_44._480_say = "Vous avez dit \224 Yu-Rang que son ami a vraiment[ENTER]accroch\233 une clochette sur une araign\233e.[ENTER]Retournez voir Taurean et expliquez lui. "
gameforge.subquest_44._490_npcChat = "Yu-Rang vous croit. "
gameforge.subquest_44._500_say = "Merci beaucoup. Yu-Rang ne doutera plus de moi \224[ENTER]pr\233sent. Nous devons garder ceci secret \224 tout[ENTER]jamais ! Promis ? \192 bient\244t ! "
gameforge.subquest_44._50_select = "Accepter "
gameforge.subquest_44._510_sayReward = "Taurean vous donne une r\233compense pour l'aide que[ENTER]vous lui avez apport\233. Vous avez re\231u 30.000[ENTER]yangs. "
gameforge.subquest_44._520_sayReward = "Vous avez re\231u 700.000 points d'exp\233rience. "
gameforge.subquest_44._60_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_44._70_say = "Pourquoi pas ? Vous avez peur ?[ENTER]Revenez quand vous aurez chang\233 d'avis. "
gameforge.subquest_44._80_say = "Ah, vous avez peur ?[ENTER]Mais vous \234tes bien plus fort et courageux que[ENTER]moi ! Vous \234tes donc un trouillard ! Je vais[ENTER]demander \224 quelqu'un d'autre alors. "
gameforge.subquest_44._90_say = "Les araign\233es vivent dans le d\233sert. Vous \234tes[ENTER]fort. Je suis s\251r que vous pouvez le faire. Bonne[ENTER]chance ! "
gameforge.subquest_45 = {}
gameforge.subquest_45._100_sayTitle = "Trouvez l'information secr\232te "
gameforge.subquest_45._10_npcChat = "\192 propos du Temple Sombre "
gameforge.subquest_45._110_say = "Vous avez la Doctrine du temple, l'\233charpe du[ENTER]temple et la traduction du livre Maudit. Prenez[ENTER]les pour Soon. "
gameforge.subquest_45._120_say = "Si vous aidez Soon, le rat de biblioth\232que, il[ENTER]pourra continuer ses recherches \224 propos du[ENTER]Temple Obscur. Cependant, il ne peut qu'en ayant[ENTER]avec lui ces objets : La doctrine du Temple,[ENTER]l'\233charpe du Temple et la traduction du Livre[ENTER]Maudit. Apportez-lui tout cela. Vous les[ENTER]trouverez dans le Temple dans la Vall\233e de[ENTER]Seungryong. "
gameforge.subquest_45._130_npcChat = "Les objets du Temple Obscur "
gameforge.subquest_45._140_say = "Ah, vous les avez ! Merci beaucoup. Le secret des[ENTER]habitants du Temple est assez simple : ils sont[ENTER]dangereux. Vous l'avez appris vous-m\234me. Il[ENTER]semblerait qu'ils soient d\233vou\233s au diable. Je[ENTER]n'ai pas plus de d\233tails, mais je suppose qu'ils[ENTER]ne pr\233parent rien de bien bon. "
gameforge.subquest_45._150_say = "Maintenant que je d\233tiens certains de leurs[ENTER]objets je vais en apprendre plus sur eux. Je vais[ENTER]commencer avec la doctrine. Voyons voir ... Hum[ENTER]... Pourquoi \234tes-vous toujours ici ? Vous n'avez[ENTER]rien de mieux \224 faire ? "
gameforge.subquest_45._160_sayReward = "Vous avez re\231u 7.000.000 de points d'exp\233rience. "
gameforge.subquest_45._170_sayReward = "Vous avez re\231u 70\160000 Yangs. "
gameforge.subquest_45._180_sayReward = "Vous avez re\231u un Livre du Chef. "
gameforge.subquest_45._190_say = "Quoi ? Vous ne les avez pas ??? Ne trainez pas si[ENTER]vous acceptez une mission ! D\233p\234chez-vous ! "
gameforge.subquest_45._200_select = "Essayer encore "
gameforge.subquest_45._20_say = "Il se passe quelque chose dans le Temple Obscur.[ENTER]Je crois que de dangereuses cr\233atures y r\233sident[ENTER]et y \233tudient une vieille magie noire.[ENTER]Les secrets du temple de Hwang sont difficiles \224[ENTER]d\233couvrir et comprendre, m\234me pour moi. Mais je[ENTER]suis s\251r que leur but est plus que douteux. Je[ENTER]dois en apprendre plus ! "
gameforge.subquest_45._210_say = "Je vais donc devoir demander \224 un h\233ros plus[ENTER]fort. Adieu. "
gameforge.subquest_45._220_say = "Merci.[ENTER]J'esp\232re que vous aurez plus de chance cette[ENTER]fois\160! "
gameforge.subquest_45._30_say = "J'ai besoin de plus de faits pour mes \233tudes. Je[ENTER]pense que la doctrine du temple, l'\233charpe du[ENTER]temple ainsi que la traduction du livre maudit[ENTER]m'aideront beaucoup. Si vous pouvez me les[ENTER]rapporter, je vous en serais tr\232s reconnaissant ![ENTER]Ne trainez pas trop en route, j'en ai besoin[ENTER]rapidement ! "
gameforge.subquest_45._40_select = "J'y vais de ce pas. "
gameforge.subquest_45._50_say = "Voulez-vous le faire? "
gameforge.subquest_45._60_say = "Je demande votre aide ! Si vous \234tes trop occup\233[ENTER]actuellement, revenez plus tard. Vous aurez[ENTER]peut-\234tre plus de temps. Je vous attends. "
gameforge.subquest_45._70_say = "J'implore votre aide et vous me tournez le dos ?[ENTER]Bien, vous pouvez partir dans ce cas, nous[ENTER]n'avons pas besoin de vous de toutes fa\231ons ! "
gameforge.subquest_45._80_say = "Merci! "
gameforge.subquest_45._90_makequestbutton = "Temple Obscur "
gameforge.subquest_46 = {}
gameforge.subquest_46._100_say = "Bonne chance. Je ne peux faire la bonne[ENTER]porcelaine que si j'ai les bons mat\233riaux. Mes[ENTER]clients attendent avec impatience. "
gameforge.subquest_46._10_targetVid = "Le secret de la porcelaine vert p\226le "
gameforge.subquest_46._110_makequestbutton = "La porcelaine c\233ladon "
gameforge.subquest_46._120_qSetTitle = "La porcelaine c\233ladon "
gameforge.subquest_46._130_say = "Vous avez tous les mat\233riaux dont Yonah a besoin[ENTER]pour fabriquer la porcelaine C\233ladon.[ENTER]Apportez-lui ! "
gameforge.subquest_46._140_say = "Pour pouvoir fabriquer une porcelaine parfaite,[ENTER]Yonah a besoin de ceci :[ENTER]Du sable du d\233sert \224 prendre sur les Hors la Loi[ENTER]du d\233sert de Yongbi, du minerai de cristal \224[ENTER]piocher ou acheter en magasin et du sang de[ENTER]primate \224 r\233cup\233rer sur les \"fort singe de[ENTER]pierre\" ou \"fort singe d'or\" au Donjon des Singes[ENTER]Experts. R\233cup\233rez le tout et amenez-le \224 Yonah. "
gameforge.subquest_46._150_targetVid = "Le secret de la porcelaine vert p\226le "
gameforge.subquest_46._160_npcChat = "J'ai tous les mat\233riaux. "
gameforge.subquest_46._170_say = "Vous l'avez fait ! Merci ! Avec la bonne[ENTER]technique et tous les mat\233riaux, je peux[ENTER]fabriquer une superbe porcelaine. Les b\233n\233fices[ENTER]que je vais en tirer seront une vraie d\233livrance.[ENTER]Tenez, votre r\233compense. Vous l'avez bien m\233rit\233.[ENTER]Je vais commencer \224 fabriquer de la porcelaine[ENTER]tout de suite ! "
gameforge.subquest_46._180_sayReward = "Vous avez re\231u 3.000.000 de points d'exp\233rience. "
gameforge.subquest_46._190_sayReward = "Vous avez re\231u 30\160000 Yangs. "
gameforge.subquest_46._20_say = "Bonjour aventurier ! C'est bien vous qui m'avez[ENTER]r\233cemment apport\233 le livre de Soon concernant la[ENTER]fabrication de la porcelaine C\233ladon ? J'ai un[ENTER]probl\232me ... Malgr\233 la technique que j'ai[ENTER]assimil\233, je n'arrive pas \224 produire une[ENTER]porcelaine solide et belle. Sans doutes parce que[ENTER]je n'ai pas les vrais ingr\233dients demand\233s dans[ENTER]la recette, ils sont difficiles \224 trouver. "
gameforge.subquest_46._30_say = "J'ai besoin de sable du d\233sert, de sang de[ENTER]primate et de minerai de cristal. En les[ENTER]m\233langeant et en les ajoutant \224 de la terre[ENTER]glaise ils se durcissent. Alors la terre prend[ENTER]une couleur vert p\226le ressemblant au jade. Cette[ENTER]couleur est tr\232s convoit\233e et il me la faut pour[ENTER]vendre encore plus ! "
gameforge.subquest_46._40_say = "Vous trouvez le sable du d\233sert sur les[ENTER]hors-la-loi du d\233sert, le minerai de cristal en[ENTER]le piochant ou l'achetant, et le sang de primate[ENTER]au donjon des singes expert. Pouvez-vous le faire[ENTER]pour moi ? Je sais que \231a sera difficile mais[ENTER]vous serez r\233compens\233 g\233n\233reusement. "
gameforge.subquest_46._50_select = "Accepter "
gameforge.subquest_46._60_select = "Refuser "
gameforge.subquest_46._70_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_46._80_say = "Si vous \234tes trop occup\233, revenez plus tard. "
gameforge.subquest_46._90_say = "Vous abandonnez? Vraiment? Donc, je suppose que[ENTER]je devrais chercher tout moi-m\234me. J'ai vraiment[ENTER]besoin de cette porcelaine. Au revoir et bonne[ENTER]chance. "
gameforge.subquest_47 = {}
