gameforge.subquest_48 = {}
gameforge.subquest_48._100_sayTitle = "Trouvez l'espion. "
gameforge.subquest_48._10_npcChat = "Trouvez l'espion "
gameforge.subquest_48._110_say = "Un des espions se fait passer pour un p\234cheur au[ENTER]village Pyungmoo de l'empire Jinno. Essayez de[ENTER]prendre contact avec lui discr\232tement et faites[ENTER]ensuite un rapport au capitaine. "
gameforge.subquest_48._120_say = "Un des espions se fait passer pour un p\234cheur au[ENTER]village Yongan de l'empire Shinsoo. Essayez de[ENTER]prendre contact avec lui discr\232tement et faites[ENTER]ensuite un rapport au capitaine. "
gameforge.subquest_48._130_say = "Un des espions se fait passer pour un p\234cheur au[ENTER]village Joan de l'empire Chunjo. Essayez de[ENTER]prendre contact avec lui discr\232tement et faites[ENTER]ensuite un rapport au capitaine. "
gameforge.subquest_48._140_npcChat = "Que faites vous? "
gameforge.subquest_48._150_say = "Chut, faites moins de bruit ! Vous faites peur[ENTER]aux poissons. Pourquoi \234tes-vous l\224 de toutes[ENTER]mani\232res? Vous \234tes bruyant et maladroit, vous[ENTER]n'\234tes pas l\224 pour p\234cher! "
gameforge.subquest_48._160_say = "Oh, je comprends. Je vous attends depuis un[ENTER]moment; vous \234tes en retard. Il n'\233tait pas[ENTER]facile d'obtenir ces informations sans \234tre[ENTER]attrap\233. Vous devez comprendre que l'ennemi est[ENTER]partout et tout ce qu'il fait pourrait[ENTER]accidentellement brouiller votre couverture. "
gameforge.subquest_48._170_say = "Bien, allons vite avant que quelqu'un nous voit.[ENTER]Voici les documents. Prenez-les et portez-les[ENTER]imm\233diatement au capitaine. "
gameforge.subquest_48._180_say = "Un moment, s'il vous pla\238t ! J'ai quelque chose[ENTER]pour nous. Un petit cadeau. Voil\224, partez. Au[ENTER]revoir ! "
gameforge.subquest_48._190_sayReward = "Vous \234tes curieux et ouvrez le colis pour savoir[ENTER]ce que l'espion vous a donn\233. "
gameforge.subquest_48._200_say = "Super ! Du gardon rouge grill\233 ! Cet espion[ENTER]connait r\233ellement des choses concernant la p\234che[ENTER]tout compte fait ! "
gameforge.subquest_48._20_say = "Du clame, soldat ![ENTER]Depuis que les contr\233es voisines sont nos[ENTER]ennemies, il est important d'avoir des amis sur[ENTER]place l\224-bas afin de nous aider \224 avoir des[ENTER]informations, afin qu'on se pr\233pare pour[ENTER]d'\233ventuelles attaques. Il est vital que leur[ENTER]couverture ne soit jamais d\233voil\233e. "
gameforge.subquest_48._210_sayReward = "Vous recevez 3 Gardons rouges grill\233s. "
gameforge.subquest_48._220_sendLetter = "Retournez voir le Capitaine. "
gameforge.subquest_48._230_targetVid = "Le capitaine "
gameforge.subquest_48._240_say = "Le dangereux voyage \224 Pyungmoo de l'empire Jinno[ENTER]fut un succ\232s ! L'espion d\233guis\233 en p\234cheur vous[ENTER]a fait son rapport. Allez voir le capitaine dans[ENTER]votre empire et remettez-lui ces informations. "
gameforge.subquest_48._250_say = "Le dangereux voyage \224 Yongan dans l'empire[ENTER]Shinsoo fut un succ\232s ! L'espion d\233guis\233 en[ENTER]p\234cheur vous a fait son rapport. Allez voir le[ENTER]capitaine dans votre empire et remettez-lui ces[ENTER]informations. "
gameforge.subquest_48._260_say = "Le dangereux voyage \224 Joan dans l'empire Chunjo[ENTER]fut un succ\232s ! L'espion d\233guis\233 en p\234cheur vous[ENTER]a fait son rapport. Allez voir le capitaine dans[ENTER]votre empire et remettez-lui ces informations. "
gameforge.subquest_48._270_npcChat = "La mission est un succ\232s ! "
gameforge.subquest_48._280_say = "Ce sont les documents ? Fantastique ! Merci, nous[ENTER]en savons plus \224 pr\233sent concernant les plans de[ENTER]nos ennemis et nous allons pouvoir nous prot\233ger.[ENTER]Vous avez rendu un grand service \224 votre empire\160! "
gameforge.subquest_48._290_sayReward = "Vous avez re\231u 5.500.000 points d'exp\233rience. "
gameforge.subquest_48._300_sayReward = "Vous recevez 50\160000 Yangs. "
gameforge.subquest_48._30_say = "Vous connaissez surement Yu-Hwan le musicien,[ENTER]n'est-ce pas ? C'est un espion et il travaille[ENTER]pour nous. Un seul espion ne suffit pas, donc[ENTER]nous en avons plusieurs partout dans le monde.[ENTER]L'un d'entre eux se trouve dans le premier[ENTER]village et pr\233tend \234tre p\234cheur. "
gameforge.subquest_48._40_say = "Je ne peux pas entrer en contact directement avec[ENTER]lui pour ne pas briser sa couverture. J'ai besoin[ENTER]d'un de mes courageux soldats. Oui, je veux dire,[ENTER]vous ![ENTER]Pouvez-vous aller voir le p\234cheur et \233couter son[ENTER]rapport ? C'est absolument vital pour la s\233curit\233[ENTER]de notre empire ! "
gameforge.subquest_48._50_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_48._60_say = "Vous voulez vous pr\233parer d'abord ? D'accord,[ENTER]revenez plus tard dans ce cas. Je vous attendrai.[ENTER]Mais je vous en supplie d\233p\234chez-vous, j'ai[ENTER]besoin de ce rapport. "
gameforge.subquest_48._70_say = "Qu'est-ce qui ne va pas chez vous\160? La derni\232re[ENTER]fois, vous aviez fait un travail fantastique pour[ENTER]nous\160! Et \224 pr\233sent, vous abandonnez votre[ENTER]empire\160? Mais je ne peux pas vous en emp\234cher...[ENTER]Adieu\160! "
gameforge.subquest_48._80_say = "Je savais que je pouvais compter sur vous ! Bonne[ENTER]chance et faites attention ! "
gameforge.subquest_48._90_makequestbutton = "Rencontrez l'espion "
gameforge.subquest_49 = {}
gameforge.subquest_49._100_sayTitle = "\192 propos du Bingsu "
gameforge.subquest_49._10_targetVid = "Bingsu\160? "
gameforge.subquest_49._110_say = "Taurean s'est disput\233 avec Harang parce qu'il ne[ENTER]croit pas que vous pouvez faire de la glace en[ENTER]plein \233t\233. Allez voir Harang et demandez-lui ce[ENTER]qu'elle connait sur le Bingsu. "
gameforge.subquest_49._120_qSetTitle = "Allez voir Harang "
gameforge.subquest_49._130_targetVid = "Allez voir Harang "
gameforge.subquest_49._140_npcChat = "Qu'est-ce que le Bingsu? "
gameforge.subquest_49._150_say = "Sacr\233 Taurean\160! Il ne sait pas ce qu'est le[ENTER]Bingsu, mais il sait se plaindre\160! Comment[ENTER]quelqu'un peut ne pas conna\238tre ce succulent[ENTER]mets\160? Quelle folie! Vous non plus ne savez pas\160?[ENTER]Allez voir Octavio au village d'\224 c\244t\233.[ENTER]C'est un fameux cuisinier, et il conna\238t toutes[ENTER]les meilleures recettes. Une fois, il m'a fait du[ENTER]Bingsu, hmm\160! Demandez lui et allez dire \224[ENTER]Taurean que j'avais raison\160! "
gameforge.subquest_49._160_makequestbutton = "Allez voir Octavio "
gameforge.subquest_49._170_say = "Taurean veut absolument savoir ce qu'est le[ENTER]Bingsu. Allez au restaurant d'Octavio. Je suis[ENTER]s\251r qu'il peut vous aider. "
gameforge.subquest_49._180_npcChat = "Savez-vous ce qu'est le Bingsu ? "
gameforge.subquest_49._190_say = "Bingsu ? Bien s\251r que je sais ! N'importe quel[ENTER]grand cuisiner sait comment pr\233parer du Bingsu ![ENTER]Tout d'abord vous avez besoin de fine glace[ENTER]pil\233e. Ajoutez du sucre, de petits morceaux de[ENTER]g\226teaux de riz et d\233corez le tout avec quelques[ENTER]fruits de saison. "
gameforge.subquest_49._200_say = "Vous me demandez cela parce que Taurean et Harang[ENTER]se chamaillent ? Ce n'est pas nouveau. Mais[ENTER]Harang a raison. Le Bingsu est un mets populaire[ENTER]dans les pays chauds. Taurean est un bon gar\231on,[ENTER]m\234me s'il est un peu mesquin. Si vous m'apportez[ENTER]les ingr\233dients, je peux vous faire du Bingsu. "
gameforge.subquest_49._20_npcChat = "Bingsu\160? "
gameforge.subquest_49._210_say = "J'aimerais bien donner une le\231on \224 Taurean et lui[ENTER]apporter du Bingsu? Qu'en pensez-vous ?[ENTER]Pouvez-vous aller chercher des gla\231ons au Mont[ENTER]Sohan ? "
gameforge.subquest_49._220_say = "Voulez-vous abandonner cette qu\234te ? "
gameforge.subquest_49._230_say = "N'aimez-vous donc pas la glace ? Ou bien[ENTER]avez-vous d\233j\224 trop mang\233 aujourd'hui ? C'est[ENTER]pour Taurean, repensez-y quand m\234me. "
gameforge.subquest_49._240_say = "Quel dommage, Taurean va \234tre bien triste ...[ENTER]Adieu. "
gameforge.subquest_49._250_say = "Parfait ! J'ai besoin de Gla\231ons qu'on peut[ENTER]trouver sur les Glaces Enchant\233es du Mont Sohan.[ENTER]Apportez m'en 50. Je pourrai alors vous faire du[ENTER]Bingsu. "
gameforge.subquest_49._260_targetVid = "Allez voir Octavio "
gameforge.subquest_49._270_say = "%s[ENTER]Vous avez les gla\231ons pour le Bingsu de Taurean.[ENTER]Apportez les \224 Octavio. "
gameforge.subquest_49._275_say = "J'ai les Gla\231ons "
gameforge.subquest_49._280_say = "Octavio veut bien pr\233parer du Bingsu pour[ENTER]Taurean, mais il a besoin de gla\231ons pour cela.[ENTER]\201liminez des glaces enchant\233es au Mont Sohan et[ENTER]collectez 50 gla\231ons. Rapportez-les ensuite \224[ENTER]Octavio. "
gameforge.subquest_49._285_say = "Trouver les gla\231ons "
gameforge.subquest_49._290_npcChat = "Tenez, j'ai apport\233 les Gla\231ons. "
gameforge.subquest_49._300_say = "Ah, superbe\160! Le plus dur est fait. \192 pr\233sent,[ENTER]j'ajoute le sucre... quelques fruits... et[ENTER]voil\224\160! Une cr\232me glac\233e pour Taurean.[ENTER]Apportez-lui, il en oubliera sa col\232re. "
gameforge.subquest_49._30_sayTitle = "Taurean: "
gameforge.subquest_49._310_say = "D\233sol\233, il en manque. Allez m'en chercher[ENTER]d'autres sinon il y aura tr\232s peu de glace ! "
gameforge.subquest_49._320_select = "Essayer encore "
gameforge.subquest_49._330_say = "Je sais que la route est longue et que les[ENTER]monstres sont tr\232s forts. Si c'est trop dur pour[ENTER]vous, on ne peut rien y faire. Adieu. "
gameforge.subquest_49._340_say = "Essayez encore. Avec courage et d\233termination,[ENTER]vous pouvez le faire ! "
gameforge.subquest_49._350_targetVid = "Bingsu! "
gameforge.subquest_49._360_say = "C'est fait : Octavio a pr\233par\233 la glace.[ENTER]Apportez-la vite \224 Taurean avant qu'elle fonde. "
gameforge.subquest_49._370_npcChat = "Voil\224 du Bingsu! "
gameforge.subquest_49._380_say = "C'est du Bingsu ? Cela a l'air bien bon ! Je[ENTER]n'avais jamais go\251t\233 auparavant, merci beaucoup[ENTER]c'est un d\233lice ! Harang avait donc raison. Il[ENTER]faut que j'aille m'excuser aupr\232s d'elle. "
gameforge.subquest_49._390_sayReward = "Vous avez re\231u 6.000.000 de points d'exp\233rience. "
gameforge.subquest_49._400_sayReward = "Vous avez re\231u 70\160000 Yangs. "
gameforge.subquest_49._40_say = "Aujourd'hui, je me suis disput\233 avec Harang...[ENTER]Elle pr\233tend qu'il existe une cr\232me glac\233e[ENTER]vraiment d\233licieuse qui s'appelle le Bingsu. "
gameforge.subquest_49._410_sayReward = "Vous avez re\231u un Parchemin de Guerre. "
gameforge.subquest_49._420_say = "Vous souvenez-vous que vous devez m'apporter du[ENTER]Bingsu ? "
gameforge.subquest_49._430_say = "Oh mon dieu, j'avais totalement oubli\233 ! Est-ce[ENTER]que je dois tenter \224 nouveau ou totalement[ENTER]abandonner ? "
gameforge.subquest_49._440_select = "Oui, je continue. "
gameforge.subquest_49._450_select = "J'abandonne. "
gameforge.subquest_49._460_say = "Je ne peux pas faire \231a, d\233sol\233. "
gameforge.subquest_49._50_say = "Quelque chose de ce genre est seulement possible[ENTER]en hiver quand il fait froid. Mais elle continue[ENTER]de me jurer que c'est vrai. Pouvez-vous trouver[ENTER]comment il est possible de pr\233parer du Bingsu en[ENTER]\233t\233 ? Si seulement c'est vraiment possible ... "
gameforge.subquest_49._60_say = "Je suis convaincu que ce Bingsu est d\233licieux ![ENTER]\202tes-vous s\251r de ne pas vouloir m'aider \224 en[ENTER]pr\233parer ? "
gameforge.subquest_49._70_say = "Si vous voulez essayer plus tard, dites le. "
gameforge.subquest_49._80_say = "J'aurais tellement aim\233 pr\233parer du Bingsu...[ENTER]Mais vous avez raison. Harang voulait surement[ENTER]juste se rendre int\233ressante et ce Bingsu[ENTER]n'existe pas ! Adieu. "
gameforge.subquest_49._90_say = "Merci pour votre aide. Faites moi savoir si vous[ENTER]avez besoin de quelque chose. Je dois une fi\232re[ENTER]chandelle \224 Harang en tout cas ! "
