gameforge.training_mount._03_say = "O\249 est votre sceau de monture\160? Sans lui, je ne[ENTER]peux pas l'am\233liorer\160! Regardez derri\232re la pi\232ce[ENTER]qui tourne, en bas \224 gauche de l'\233cran.[ENTER]Vous y trouverez des certificats que vous pourrez[ENTER]\233changer chez moi contre des sceaux de monture. "
gameforge.training_mount._04_say = "J'aimerais chevaucher une nouvelle monture\160! "
gameforge.training_mount._05_say = "H\233\160! Vous voyagez encore \224 cheval\160? Incroyable\160![ENTER]De nos jours, il est possible de dompter des[ENTER]animaux sauvages. "
gameforge.training_mount._06_say = "Cela dit, pour pouvoir entra\238ner des animaux[ENTER]sauvages apprivois\233s au combat, vous devez[ENTER]poss\233der de bonnes connaissances en \233quitation.[ENTER]De plus, vous avez besoin des objets suivants\160:[ENTER]un parchemin d'\233volution, pour transformer votre[ENTER]monture en monture sauvage, et un parchemin de[ENTER]mutation, pour en faire une monture vaillante. "
gameforge.training_mount._07_say = "Si vous avez des questions, passez me voir quand[ENTER]vous voulez. Je vous aiderai du mieux que je[ENTER]peux. "
gameforge.training_mount._08_say = "J'aimerais am\233liorer ma monture\160! "
gameforge.training_mount._09_say = "Alors comme \231a, vous d\233sirez am\233liorer votre[ENTER]monture\160? Savez-vous comment faire\160? Bien, je[ENTER]vais vous l'expliquer. "
gameforge.training_mount._10_say = "Afin de transformer votre monture en monture[ENTER]sauvage, partez \224 la recherche d'un parchemin[ENTER]d'\233volution. Trouvez \233galement un parchemin de[ENTER]mutation, qui transformera votre monture sauvage[ENTER]en monture vaillante. On dit que ces parchemins[ENTER]sont cach\233s dans une lointaine contr\233e peupl\233e de[ENTER]dangereux g\233ants\160! "
gameforge.training_mount._11_say = "Apportez-moi un de ces parchemins et[ENTER]j'am\233liorerai votre monture. \192 moins que vous ne[ENTER]les ayez d\233j\224 sur vous\160? "
gameforge.training_mount._12_say = "Oui, je voudrais am\233liorer ma monture\160! "
gameforge.training_mount._13_say = "Non, pas pour l'instant. "
gameforge.training_mount._14_say = "Ah, vous avez un parchemin sur vous. Lequel\160? Le[ENTER]parchemin d'\233volution vous permet d'entra\238ner au[ENTER]combat un jeune animal sans exp\233rience.[ENTER]Cela fait, le parchemin de mutation vous[ENTER]permettra de le transformer en monture vaillante. "
gameforge.training_mount._15_2_say = "J'ai le parchemin de mutation. "
gameforge.training_mount._15_say = "J'ai le parchemin d'\233volution. "
gameforge.training_mount._16_say = "Je n'ai aucun parchemin sur moi. "
gameforge.training_mount._17_say = "Ah, regardez, le parchemin d'\233volution\160! Dans ce[ENTER]cas, laissez-moi jeter un \156il \224 votre sceau de[ENTER]monture. Plus d'un aventurier a d\233j\224 tent\233 de me[ENTER]rouler avec un faux\160! Je vais d'abord v\233rifier[ENTER]son authenticit\233. Donnez-le-moi. [Glissez le[ENTER]sceau sur le palefrenier.] "
gameforge.training_mount._18_say = "Le parchemin de mutation\160! Jusqu'\224 aujourd'hui,[ENTER]j'en avais seulement entendu parler, je ne[ENTER]l'avais encore jamais eu en main... \192 pr\233sent,[ENTER]montrez-moi votre sceau de monture. D\232s que[ENTER]j'aurai v\233rifi\233 son authenticit\233, je vous[ENTER]l'\233changerai contre un autre, plus puissant.[ENTER][Glissez le sceau sur le palefrenier.] "
gameforge.training_mount._19_say = "Lorsque vous aurez trouv\233 un des parchemins,[ENTER]revenez me voir. Je pourrai vous \233changer votre[ENTER]sceau de monture contre un autre, plus puissant. "
gameforge.training_mount._20_say = "Votre sceau de monture commence \224 \234tre un peu[ENTER]vieux, il est grand temps d'en changer.[ENTER]Attendez, je vais vous en donner un autre.[ENTER]Tenez, le voil\224. \192 pr\233sent, vous pouvez appeler[ENTER]une monture sauvage. Revenez me voir d\232s que vous[ENTER]aurez trouv\233 un parchemin de mutation. Je vous[ENTER]donnerai un sceau de monture encore plus[ENTER]puissant. "
gameforge.training_mount._21_say = "C'est le sceau de monture que je vous ai donn\233 la[ENTER]derni\232re fois. Entre-temps, il est un peu us\233.[ENTER]Rendez-le-moi et je vous l'\233changerai contre un[ENTER]autre encore plus puissant\160! "
gameforge.training_mount._22_say = "Le pouvoir de ce sceau vous permettra d'appeler[ENTER]une monture transform\233e. Faites-y bien attention,[ENTER]il a une valeur inestimable\160! "
gameforge.training_mount._23_say = "Puis-je utiliser les aptitudes de ma monture\160? "
gameforge.training_mount._24_say = "Vous aimeriez utiliser les aptitudes de votre[ENTER]monture\160? Vous \234tes bien exigeant... mais j'avoue[ENTER]que moi aussi, j'en r\234ve. Bien, pour cela, il[ENTER]vous faudra respecter certaines r\232gles. "
gameforge.training_mount._25_say = "Tout d'abord, apprenez \224 monter \224 cheval, faute[ENTER]de quoi l'entreprise sera p\233rilleuse. De plus,[ENTER]votre monture doit \234tre apte au combat pour[ENTER]pouvoir utiliser des aptitudes. "
gameforge.training_mount._26_say = "Votre monture est-elle capable d'apprendre des[ENTER]aptitudes\160? Si ce n'est pas le cas, je ne vous[ENTER]laisserai pas commencer l'entra\238nement. Que[ENTER]voulez-vous faire\160? "
gameforge.training_mount._27_say = "Je comprends. Je vais \224 pr\233sent \233valuer votre[ENTER]force et vos talents de cavalier. Attendez un[ENTER]instant. "
gameforge.training_mount._28_say = "Hm... Des vert\232bres en bon \233tat, de solides[ENTER]connaissances en \233quitation et une monture[ENTER]particuli\232rement belliqueuse. Vous pouvez[ENTER]utiliser des aptitudes de monture. "
gameforge.training_mount._29_say = "Votre monture peut \224 pr\233sent utiliser des[ENTER]aptitudes. Cependant, si vous vous procurez une[ENTER]nouvelle monture, elle devra \224 nouveau les[ENTER]apprendre. Dans ce cas, revenez me voir. "
gameforge.training_mount._30_say = "\199a suffit. Je vous ai d\233j\224 dit que c'\233tait[ENTER]beaucoup trop dangereux tant que vous ne savez[ENTER]pas monter \224 cheval. Revenez me voir quand vous[ENTER]aurez progress\233. "
gameforge.training_mount._31_say = "Malheureusement, votre monture n'est pas pr\234te.[ENTER]Revenez me voir quand elle sera plus agressive. "
gameforge.training_mount._32_say = "Est-ce que vous pourriez descendre de votre[ENTER]monture pendant que nous parlons\160? J'ai la nuque[ENTER]un peu raide et c'est assez contraignant de[ENTER]devoir constamment lever la t\234te pour vous[ENTER]regarder. "
gameforge.training_mount._33_say = "Vous ne poss\233dez pas la licence n\233cessaire pour[ENTER]am\233liorer votre monture. Pour pouvoir entra\238ner[ENTER]une monture sauvage, il vous faut au minimum la[ENTER]licence de cheval de combat. Pour pouvoir[ENTER]entra\238ner une monture vaillante, il vous faut la[ENTER]licence de cheval militaire. "
gameforge.training_mount._34_say = "Je vois que vous avez un remontant. Cette[ENTER]pr\233cieuse plante m\233dicinale redonnera des forces[ENTER]\224 votre monture, ce qui prolongera son existence[ENTER]de quelques jours. Que dois-je faire\160?[ENTER]Voulez-vous que je prolonge l'existence de votre[ENTER]monture, ou pas\160? "
gameforge.training_mount._35_select_1 = "Prolonger "
gameforge.training_mount._35_select_2 = "Am\233liorer "
gameforge.training_mount._36_select_1 = "7 jours "
gameforge.training_mount._36_select_2 = "15 jours "
gameforge.training_mount._36_select_3 = "30 jours "
gameforge.training_mount._36_select_4 = "Parchemin de mutation + 200k Yangs "
gameforge.training_mount._37_say = "Malheureusement, vous ne disposez pas du[ENTER]remontant correspondant \224 cette dur\233e. Toutefois,[ENTER]vous pourrez le trouver en cliquant sur la pi\232ce[ENTER]en rotation\160! "
gameforge.training_mount._38_say = "Le parchemin de mutation est tr\232s puissant\160! Il[ENTER]peut prolonger l'existence de votre super monture[ENTER]d'au maximum quatre jours. Une tentative vous[ENTER]co\251tera 200\160000 Yangs. Votre monture doit \234tre[ENTER]\233puis\233e et n'avoir plus qu'un jour d'existence.[ENTER]\201videmment, il vous faudra \233galement un peu de[ENTER]chance\160! Si jamais l'op\233ration \233chouait,[ENTER]donnez-lui un remontant.[ENTER]Vous en trouverez en cliquant sur la pi\232ce en[ENTER]rotation. "
gameforge.training_mount._39_say = "Cette monture est encore en pleine forme. Le[ENTER]parchemin de mutation n'aura pas d'effet sur[ENTER]elle. Revenez quand il ne lui restera plus qu'un[ENTER]jour d'existence. "
gameforge.training_mount._40_say = "Je ne peux malheureusement rien faire pour vous.[ENTER]Soit vous n'avez pas de parchemin de mutation,[ENTER]soit vous avez moins de 200\160000 Yangs. "
gameforge.upgrade_refine_scroll = {}
gameforge.upgrade_refine_scroll._100_say = "Votre tentative de fabrication d'un Parchemin du[ENTER]Dieu Dragon a \233chou\233 parce que vous n'avez pas[ENTER]les mat\233riaux requis. "
gameforge.upgrade_refine_scroll._10_npcChat = "Fabrication du Parchemin de Guerre "
gameforge.upgrade_refine_scroll._110_npcChat = "Cr\233er Parchemin du Dieu Dragon "
gameforge.upgrade_refine_scroll._120_say = "Un parchemin du Dieu Dragon augmente la chance de[ENTER]r\233ussite d'une am\233lioration. En cas d'\233chec, seul[ENTER]le niveau baisse. C'est un item myst\233rieux qui[ENTER]peut \234tre assimil\233 \224 un parchemin de b\233n\233diction. "
gameforge.upgrade_refine_scroll._130_say = "Pour le faire, vous avez besoin de Minerai de fer[ENTER]magique "
gameforge.upgrade_refine_scroll._140_sayItem = "Minerai de fer magique "
gameforge.upgrade_refine_scroll._150_say = "Pour le fabriquer, vous avez besoin d'un[ENTER]Parchemin de B\233n\233diction "
gameforge.upgrade_refine_scroll._160_say = "Avez-vous les mat\233riaux n\233cessaires? Voulez-vous[ENTER]en fabriquer un? Si vous utilisez un Parchemin de[ENTER]B\233n\233diction et du Minerai de fer magique, vous[ENTER]pouvez fabriquer un Parchemin du Dieu Dragon. "
gameforge.upgrade_refine_scroll._170_say = "Vous avez fabriqu\233 un Parchemin du Dieu Dragon.[ENTER]C'est vraiment facile de le fabriquer avec du[ENTER]Minerai de fer magique. J'aime \231a! "
gameforge.upgrade_refine_scroll._180_say = "Votre tentative de fabrication d'un Parchemin du[ENTER]Dieu Dragon a \233chou\233 parce que vous n'avez pas[ENTER]les mat\233riaux requis. "
gameforge.upgrade_refine_scroll._190_npcChat = "Fabriquer un Manuel du forgeron "
gameforge.upgrade_refine_scroll._200_say = "Avez-vous entendu parler d'une pierre nomm\233e[ENTER]pierre du forgeron? C'est une pierre faite \224[ENTER]partir du sang et de la sueur du forgeron. Si[ENTER]vous m'apportez une pierre du forgeron et un[ENTER]parchemin de b\233n\233diction, je vous fabriquerai un[ENTER]Manuel du forgeron qui passe de g\233n\233rations en[ENTER]g\233n\233rations dans ma famille. Il a la m\234me[ENTER]fonction que le parchemin du Dieu dragon, mais la[ENTER]chance de succ\232s est sup\233rieure. "
gameforge.upgrade_refine_scroll._20_say = "Les parchemins de Guerre sont des objets[ENTER]myst\233rieux qui augmentent les objets de +0 \224 + 3[ENTER]avec un taux de succ\232s de 100%. Par contre, ils[ENTER]ne marchent pas sur les objets +4 ou sup\233rieurs. "
gameforge.upgrade_refine_scroll._210_say = "Pour le fabriquer, vous avez besoin d'une pierre[ENTER]du forgeron. "
gameforge.upgrade_refine_scroll._220_sayItem = "Pierre du forgeron "
gameforge.upgrade_refine_scroll._230_say = "Pour fabriquer cela, vous avez besoin d'un[ENTER]Parchemin de B\233n\233diction. "
gameforge.upgrade_refine_scroll._240_say = "Avez-vous tous les mat\233riaux n\233cessaires? Donc,[ENTER]vous voulez fabriquer un Manuel du forgeron qui[ENTER]se transmet dans ma famille de g\233n\233ration en[ENTER]g\233n\233ration? "
gameforge.upgrade_refine_scroll._250_say = "Vous vous \234tes fabriqu\233 un Manuel du forgeron![ENTER]Vous connaissez donc tout sur la Dynastie des[ENTER]forgerons. Utilisez-le avec sagesse ! Ah ah ah ! "
gameforge.upgrade_refine_scroll._260_sayItem = "Manuel du forgeron "
gameforge.upgrade_refine_scroll._270_say = "Vous ne pouvez pas cr\233er de Manuel du forgeron[ENTER]car vous ne portez pas sur vous tous les[ENTER]mat\233riaux n\233cessaires. "
gameforge.upgrade_refine_scroll._30_say = "Pour fabriquer cela, vous avez besoin de cuivre[ENTER]magique. "
gameforge.upgrade_refine_scroll._40_sayItem = "Cuivre magique "
gameforge.upgrade_refine_scroll._50_say = "En plus, vous avez besoin d'un parchemin de[ENTER]b\233n\233diction. "
gameforge.upgrade_refine_scroll._60_sayItem = "Parchemin de B\233n\233diction "
gameforge.upgrade_refine_scroll._70_say = "Avez-vous les mat\233riaux n\233cessaires\160?[ENTER]Vous avez aussi besoin de 200\160000 Yangs.[ENTER]Si vous avez le parchemin de b\233n\233diction, du[ENTER]cuivre magique et les 200\160000 Yangs vous pouvez[ENTER]fabriquer un parchemin de guerre.[ENTER]Voulez-vous en fabriquer un\160? "
gameforge.upgrade_refine_scroll._80_say = "Vous avez produit un Parchemin. C'est facile de[ENTER]cr\233er un parchemin de guerre si vous avez du[ENTER]Cuivre magique![ENTER]J'aime \231a! Ha, ha ha! "
gameforge.upgrade_refine_scroll._90_sayItem = "Parchemin de guerre "
gameforge.warehouse = {}
gameforge.warehouse._100_say = "Soyez le bienvenu ! Savez-vous \224 quoi servent les[ENTER]lingots ?[ENTER]Si vous vous promenez avec des masses de Yangs,[ENTER]c'est comme si vous disiez\160: Tuez-moi, s'il vous[ENTER]pla\238t\160![ENTER]C'est pourquoi j'\233change vos Yangs contre des[ENTER]lingots d'or et les conserve pour vous. "
gameforge.warehouse._10_npcChat = "Voulez-vous utiliser l'entrep\244t? "
gameforge.warehouse._110_say = "Certes, je demande beaucoup plus que le prix[ENTER]usuel d'un lingot d'or. Mais c'est justifi\233 pour[ENTER]un tel service,n'est-ce pas ? Pas de raison de[ENTER]vous sentir trahi. Comme vous le savez, c'est[ENTER]dangereux par ici. "
gameforge.warehouse._120_npcChat = "Ouvrir l'entrep\244t de la boutique "
gameforge.warehouse._130_say = "Humm...[ENTER]Les mines sont toutes \233puis\233es.[ENTER]Il est tr\232s dur de trouver de l'or ou de[ENTER]l'argent. Tant qu'on ne trouvera pas de nouveaux[ENTER]filons, il n'y aura pas de nouveaux lingots d'or[ENTER]ou d'argent. "
gameforge.warehouse._140_say = "Bienvenue ! Vous voulez probablement visiter[ENTER]votre entrep\244t de la boutique ? Pourquoi[ENTER]venez-vous donc me voir ? Regardez simplement[ENTER]dans votre inventaire, vous y trouverez un acc\232s[ENTER]direct. "
gameforge.warehouse._150_say = "Cliquez tout simplement sur ce symbole qui vous[ENTER]permet d'atteindre n'importe quand et depuis[ENTER]n'importe o\249 votre entrep\244t de la boutique. Le[ENTER]mot de passe est 000000, si vous ne l'avez pas[ENTER]encore modifi\233. "
gameforge.warehouse._20_sayTitle = "Magasinier : "
gameforge.warehouse._30_say = "Voulez-vous utiliser l'entrep\244t\160? Vous devez[ENTER]payer des Yangs pour pouvoir l'utiliser. Je suis[ENTER]de bonne Humeur aujourd'hui\160: vous pouvez[ENTER]l'utiliser pour 500 Yangs seulement.[ENTER]Allez, venez, c'est pas cher\160! "
gameforge.warehouse._40_say = "Quoi\160? Vous n'avez pas assez de Yangs\160?[ENTER]Revenez quand vous en aurez assez\160! "
gameforge.warehouse._50_say = "Votre entrep\244t est ouvert. Si vous voulez[ENTER]l'utiliser, il vous suffit de me parler.[ENTER]Le mot de passe pour votre entrep\244t est: "
gameforge.warehouse._60_sayReward = "000000 "
gameforge.warehouse._70_say = "Vous devriez le changer pour des raisons de[ENTER]s\233curit\233.[ENTER]Peut \234tre pensez vous que 45 cases ne sont pas[ENTER]assez. Mais qui sait, peut \234tre je te donnerais[ENTER]de l'espace suppl\233mentaire si notre contrat[ENTER]s'\233ternise ! "
gameforge.warehouse._80_say = "Mais je n'oblige personne. Si vous n'avez pas[ENTER]envie maintenant, revenez quand vous voudrez. "
gameforge.warehouse._90_npcChat = "Ouvrir l'entrep\244t "
